window.TOEIC = [{"word":"abandon","pos":"v.","phonetic":"[əˈbændən]","meaning":"放棄；中止；拋棄","definition":"to stop doing or supporting something before it is finished","collocations":["abandon a plan","abandon the project","abandon the idea"],"example":"The company decided to abandon the expansion plan due to rising construction costs.","exampleZh":"由於營建成本不斷上漲，公司決定放棄擴建計畫。","synonyms":["give up","discard","forsake"],"level":3,"theme":"企業經營"},{"word":"ability","pos":"n.","phonetic":"[əˈbɪlətɪ]","meaning":"能力；才能","definition":"the skill or power to do something well","collocations":["ability to communicate","leadership ability","demonstrate one's ability"],"example":"Applicants must have the ability to work independently under tight deadlines.","exampleZh":"應徵者必須具備在緊迫期限下獨立作業的能力。","synonyms":["capability","skill","competence"],"level":1,"theme":"人事與職涯"},{"word":"able","pos":"adj.","phonetic":"[ˈebḷ]","meaning":"能夠的；有能力的","definition":"having the skill, power, or opportunity to do something","collocations":["be able to attend","be able to afford","an able manager"],"example":"Ms. Chen will not be able to attend the board meeting tomorrow.","exampleZh":"陳小姐明天無法出席董事會會議。","synonyms":["capable","competent"],"level":1,"theme":"日常與一般"},{"word":"abroad","pos":"adv.","phonetic":"[əˈbrɔd]","meaning":"在國外；到國外","definition":"in or to a foreign country","collocations":["travel abroad","study abroad","work abroad","expand abroad"],"example":"Employees who travel abroad on business can claim their expenses within thirty days.","exampleZh":"因公出國的員工可在三十天內申報差旅費用。","synonyms":["overseas"],"level":2,"theme":"旅遊與交通"},{"word":"absence","pos":"n.","phonetic":"[ˈæbsns]","meaning":"缺席；不在；缺乏","definition":"the state of being away from a place, such as work or school","collocations":["leave of absence","in the absence of","absence from work"],"example":"Please notify your supervisor at least one day before any planned absence.","exampleZh":"若有預定的缺勤，請至少提前一天通知主管。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"absent","pos":"adj.","phonetic":"[ˈæbsnt]","meaning":"缺席的；不在的；缺乏的","definition":"not present in a place where you are expected to be","collocations":["absent from work","absent from the meeting","be absent without notice"],"example":"Two committee members were absent from the meeting because of flight delays.","exampleZh":"兩位委員因班機延誤而缺席會議。","synonyms":["away","missing"],"level":2,"theme":"人事與職涯"},{"word":"absolutely","pos":"adv.","phonetic":"[ˈæbsəˌlutlɪ]","meaning":"絕對地；完全地","definition":"completely or totally; used to emphasize something","collocations":["absolutely necessary","absolutely free","absolutely certain"],"example":"It is absolutely necessary to back up all files before the system upgrade.","exampleZh":"系統升級前務必備份所有檔案。","synonyms":["completely","totally","entirely"],"level":2,"theme":"日常與一般"},{"word":"accept","pos":"v.","phonetic":"[əkˈsɛpt]","meaning":"接受；同意；認可","definition":"to agree to take something that is offered to you","collocations":["accept an offer","accept credit cards","accept responsibility","accept an invitation"],"example":"We are pleased to inform you that the hotel accepts all major credit cards.","exampleZh":"我們很高興通知您，本飯店接受各大信用卡付款。","synonyms":["receive","agree to"],"level":1,"theme":"日常與一般"},{"word":"acceptable","pos":"adj.","phonetic":"[əkˈsɛptəbḷ]","meaning":"可接受的；令人滿意的","definition":"good enough to be agreed to or approved","collocations":["acceptable quality","an acceptable price","acceptable to both parties"],"example":"The revised terms of the contract were acceptable to both parties.","exampleZh":"修訂後的合約條款雙方都能接受。","synonyms":["satisfactory","adequate"],"level":2,"theme":"合約與法律"},{"word":"acceptance","pos":"n.","phonetic":"[əkˈsɛptəns]","meaning":"接受；錄取；認可","definition":"the act of agreeing to an offer, proposal, or invitation","collocations":["letter of acceptance","acceptance of the offer","gain wide acceptance"],"example":"Please sign and return the letter of acceptance by Friday, May 10.","exampleZh":"請於五月十日（星期五）前簽署並寄回錄取通知書。","synonyms":["approval","agreement"],"level":3,"theme":"人事與職涯"},{"word":"access","pos":"n./v.","phonetic":"[ˈæksɛs]","meaning":"使用權；進入；（電腦）存取","definition":"the right or opportunity to enter a place or use something","collocations":["access to the database","gain access","grant access","Internet access"],"example":"Only authorized staff members have access to the company's financial records.","exampleZh":"只有獲得授權的員工才能查閱公司的財務紀錄。","synonyms":["entry","admittance"],"level":2,"theme":"科技與通訊"},{"word":"accessible","pos":"adj.","phonetic":"[əkˈsɛsəbḷ]","meaning":"容易到達的；可使用的；易取得的","definition":"easy to reach, enter, or use","collocations":["easily accessible","accessible by public transportation","wheelchair accessible"],"example":"The new conference center is easily accessible by subway and bus.","exampleZh":"新的會議中心搭地鐵和公車都很方便到達。","synonyms":["reachable","available"],"level":3,"theme":"房產與設施"},{"word":"accident","pos":"n.","phonetic":"[ˈæksədənt]","meaning":"意外；事故","definition":"an unexpected event that causes damage or injury","collocations":["a traffic accident","by accident","accident insurance","prevent accidents"],"example":"All factory workers must wear helmets to prevent accidents on the production line.","exampleZh":"所有廠區員工都必須戴安全帽，以防止生產線上發生意外。","synonyms":["mishap","crash"],"level":2,"theme":"生產與物流"},{"word":"accidentally","pos":"adv.","phonetic":"[ˌæksəˈdɛntḷɪ]","meaning":"意外地；不小心地","definition":"by chance or without intending to","collocations":["accidentally delete","accidentally leave behind","accidentally damage"],"example":"I accidentally deleted the attachment, so could you send the file again?","exampleZh":"我不小心刪除了附件，可以請你再寄一次檔案嗎？","synonyms":["unintentionally","by mistake"],"level":3,"theme":"日常與一般"},{"word":"accommodate","pos":"v.","phonetic":"[əˈkɑməˌdet]","meaning":"容納；為…提供住宿；配合","definition":"to have enough space for a number of people or things","collocations":["accommodate up to 200 guests","accommodate special requests","accommodate your needs"],"example":"The banquet hall can accommodate up to three hundred guests for the ceremony.","exampleZh":"這間宴會廳最多可容納三百位賓客參加典禮。","synonyms":["hold","house"],"level":4,"theme":"餐飲與住宿"},{"word":"accommodation","pos":"n.","phonetic":"[əˌkɑməˈdeʃən]","meaning":"住宿；膳宿","definition":"a place to stay, such as a hotel room","collocations":["hotel accommodations","overnight accommodation","arrange accommodation"],"example":"The travel package includes airfare, accommodation, and daily breakfast for five days.","exampleZh":"這個旅遊行程包含五天的機票、住宿和每日早餐。","synonyms":["lodging","housing"],"level":3,"theme":"餐飲與住宿"},{"word":"accompany","pos":"v.","phonetic":"[əˈkʌmpənɪ]","meaning":"陪同；伴隨；附上","definition":"to go somewhere with someone, or to be included with something","collocations":["be accompanied by","accompany a client","accompanying documents"],"example":"All refund requests must be accompanied by the original sales receipt.","exampleZh":"所有退款申請都必須附上原始購買收據。","synonyms":["escort","go with"],"level":3,"theme":"購物與消費"},{"word":"accomplish","pos":"v.","phonetic":"[əˈkɑmplɪʃ]","meaning":"完成；達成；實現","definition":"to succeed in doing or finishing something","collocations":["accomplish a goal","accomplish a task","accomplish a mission"],"example":"Thanks to everyone's effort, our team accomplished all of its quarterly goals.","exampleZh":"多虧大家的努力，我們團隊達成了所有季度目標。","synonyms":["achieve","complete","fulfill"],"level":3,"theme":"企業經營"},{"word":"according","pos":"adv.","phonetic":"[əˈkɔrdɪŋ]","meaning":"依據；按照（according to 根據）","definition":"as stated by someone or shown by something (used in the phrase \"according to\")","collocations":["according to the report","according to the schedule","according to company policy"],"example":"According to the weather report, the outdoor event may be postponed until Sunday.","exampleZh":"根據氣象報導，戶外活動可能延到星期日舉行。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"accordingly","pos":"adv.","phonetic":"[əˈkɔrdɪŋlɪ]","meaning":"因此；相應地；照著","definition":"in a way that is suitable for the situation; therefore","collocations":["act accordingly","plan accordingly","adjust the budget accordingly"],"example":"The deadline has been moved up, so please adjust your schedule accordingly.","exampleZh":"截止日期提前了，請大家據此調整自己的時程。","synonyms":["therefore","consequently"],"level":4,"theme":"辦公室與行政"},{"word":"account","pos":"n./v.","phonetic":"[əˈkaʊnt]","meaning":"帳戶；帳目；客戶；說明（account for 解釋；占）","definition":"an arrangement with a bank or company to keep your money or records","collocations":["open a bank account","account number","take into account","account for"],"example":"You can open a savings account online in less than ten minutes.","exampleZh":"您只要不到十分鐘就能在線上開立儲蓄帳戶。","synonyms":[],"level":2,"theme":"財務與會計"},{"word":"accountant","pos":"n.","phonetic":"[əˈkaʊntənt]","meaning":"會計師；會計人員","definition":"a person whose job is to keep and check financial records","collocations":["a certified public accountant","hire an accountant","consult an accountant"],"example":"Our accountant will review the quarterly financial statements before the audit begins.","exampleZh":"我們的會計師會在查帳開始前審閱季度財務報表。","synonyms":["bookkeeper"],"level":2,"theme":"財務與會計"},{"word":"accounting","pos":"n.","phonetic":"[əˈkaʊntɪŋ]","meaning":"會計；會計學","definition":"the work or process of keeping financial records","collocations":["the accounting department","accounting software","accounting practices"],"example":"Please submit your travel receipts to the accounting department by Friday.","exampleZh":"請在星期五前將差旅收據交給會計部門。","synonyms":["bookkeeping"],"level":3,"theme":"財務與會計"},{"word":"accuracy","pos":"n.","phonetic":"[ˈækjərəsɪ]","meaning":"準確性；精確度","definition":"the quality of being correct and exact","collocations":["improve accuracy","check the accuracy of","with great accuracy"],"example":"Please check the accuracy of the invoice before sending it to the client.","exampleZh":"寄給客戶之前，請先確認發票內容是否正確。","synonyms":["precision","exactness"],"level":3,"theme":"財務與會計"},{"word":"accurate","pos":"adj.","phonetic":"[ˈækjərɪt]","meaning":"準確的；精確的","definition":"correct and true in every detail","collocations":["accurate information","accurate records","an accurate estimate"],"example":"Keeping accurate records will make the year-end audit much easier for everyone.","exampleZh":"保持正確的紀錄能讓年終查帳對大家來說輕鬆許多。","synonyms":["precise","exact","correct"],"level":2,"theme":"財務與會計"},{"word":"accurately","pos":"adv.","phonetic":"[ˈækjərɪtlɪ]","meaning":"準確地；精確地","definition":"in a way that is correct and exact","collocations":["accurately reflect","accurately record","accurately predict"],"example":"The monthly report accurately reflects the current condition of the overseas market.","exampleZh":"這份月報準確反映了海外市場的現況。","synonyms":["precisely","correctly"],"level":3,"theme":"辦公室與行政"},{"word":"achieve","pos":"v.","phonetic":"[əˈtʃiv]","meaning":"達成；實現；獲得","definition":"to succeed in reaching a goal, especially through effort","collocations":["achieve a goal","achieve success","achieve growth"],"example":"The sales team achieved its annual target two months ahead of schedule.","exampleZh":"業務團隊提前兩個月達成了年度目標。","synonyms":["accomplish","attain","reach"],"level":2,"theme":"企業經營"},{"word":"achievement","pos":"n.","phonetic":"[əˈtʃivmənt]","meaning":"成就；達成","definition":"something important that you succeed in doing through effort","collocations":["a remarkable achievement","a sense of achievement","recognize achievements"],"example":"The award ceremony recognizes the outstanding achievements of employees across all departments.","exampleZh":"頒獎典禮表彰各部門員工的傑出成就。","synonyms":["accomplishment","attainment"],"level":2,"theme":"人事與職涯"},{"word":"acknowledge","pos":"v.","phonetic":"[əkˈnɑlɪdʒ]","meaning":"確認收到；承認；感謝","definition":"to tell someone that you have received something they sent","collocations":["acknowledge receipt of","acknowledge an order","acknowledge one's contribution"],"example":"Please acknowledge receipt of this email by replying to the sender directly.","exampleZh":"收到這封電子郵件後，請直接回覆寄件人確認。","synonyms":["confirm","admit","recognize"],"level":4,"theme":"辦公室與行政"},{"word":"acquire","pos":"v.","phonetic":"[əˈkwaɪr]","meaning":"收購；取得；學到","definition":"to buy or gain something such as a company, property, or skill","collocations":["acquire a company","acquire new skills","acquire property"],"example":"The corporation plans to acquire two smaller firms to expand its market share.","exampleZh":"這家企業計畫收購兩家較小的公司，以擴大市占率。","synonyms":["obtain","purchase","gain"],"level":3,"theme":"企業經營"},{"word":"acquisition","pos":"n.","phonetic":"[ˌækwəˈzɪʃən]","meaning":"收購；併購；獲得","definition":"the act of buying a company or obtaining something","collocations":["mergers and acquisitions","the acquisition of","a recent acquisition"],"example":"The acquisition of the software company was completed at the end of March.","exampleZh":"對那家軟體公司的收購已於三月底完成。","synonyms":["purchase","takeover"],"level":4,"theme":"企業經營"},{"word":"across","pos":"prep./adv.","phonetic":"[əˈkrɔs]","meaning":"橫越；在…對面；遍及","definition":"from one side to the other, or on the other side of something","collocations":["across the street","across the country","across departments"],"example":"The new branch office is located directly across the street from the station.","exampleZh":"新的分公司就位在車站正對面。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"act","pos":"v./n.","phonetic":"[ækt]","meaning":"行動；擔任；法案；行為","definition":"to do something for a particular purpose or in a particular way","collocations":["act quickly","act on behalf of","act as"],"example":"Mr. Lopez will act as interim manager until a replacement is found.","exampleZh":"在找到接任人選之前，羅培茲先生將代理經理職務。","synonyms":["behave","function"],"level":1,"theme":"日常與一般"},{"word":"action","pos":"n.","phonetic":"[ˈækʃən]","meaning":"行動；措施；作用","definition":"something that you do to deal with a situation","collocations":["take action","a course of action","immediate action"],"example":"Management promised to take immediate action to resolve the customer complaints.","exampleZh":"管理階層承諾立即採取行動處理顧客的投訴。","synonyms":["measure","step","move"],"level":1,"theme":"日常與一般"},{"word":"activate","pos":"v.","phonetic":"[ˈæktəˌvet]","meaning":"啟用；啟動；使活化","definition":"to make a device, account, or system start working","collocations":["activate an account","activate a credit card","activate the alarm system"],"example":"Please call our service hotline to activate your new credit card.","exampleZh":"請撥打客服專線為您的新信用卡開卡。","synonyms":["start","turn on","enable"],"level":3,"theme":"科技與通訊"},{"word":"active","pos":"adj.","phonetic":"[ˈæktɪv]","meaning":"活躍的；積極的；有效的","definition":"busy doing things or taking part in activities","collocations":["an active role","active participation","an active member"],"example":"She plays an active role in organizing the company's annual charity event.","exampleZh":"她在籌辦公司年度慈善活動方面扮演相當積極的角色。","synonyms":["energetic","engaged"],"level":2,"theme":"日常與一般"},{"word":"activity","pos":"n.","phonetic":"[ækˈtɪvətɪ]","meaning":"活動","definition":"something that people do, especially for interest or a purpose","collocations":["outdoor activities","promotional activities","business activities"],"example":"The resort offers a variety of outdoor activities, including hiking and kayaking.","exampleZh":"這座度假村提供多種戶外活動，包括健行和獨木舟。","synonyms":["event","pursuit"],"level":1,"theme":"旅遊與交通"},{"word":"actually","pos":"adv.","phonetic":"[ˈæktʃuəlɪ]","meaning":"實際上；其實","definition":"used to say what is really true or to correct something","collocations":["actually happen","actually mean","actually cost"],"example":"The repairs actually cost less than the original estimate we received last month.","exampleZh":"維修費用其實比我們上個月拿到的原始估價還低。","synonyms":["in fact","really"],"level":1,"theme":"日常與一般"},{"word":"ad","pos":"n.","phonetic":"[æd]","meaning":"廣告（advertisement 的縮寫）","definition":"a short form of \"advertisement\"; a notice promoting a product or service","collocations":["place an ad","a classified ad","an online ad","a job ad"],"example":"We placed an ad in the local newspaper to attract more customers.","exampleZh":"我們在地方報紙上刊登廣告，以吸引更多顧客。","synonyms":["advertisement","commercial"],"level":1,"theme":"行銷與銷售"},{"word":"adapt","pos":"v.","phonetic":"[əˈdæpt]","meaning":"適應；調整；改編","definition":"to change your behavior or something else to suit a new situation","collocations":["adapt to change","adapt quickly","adapt a product for"],"example":"Successful companies adapt quickly to changes in consumer demand and technology.","exampleZh":"成功的企業能迅速適應消費者需求與科技的變化。","synonyms":["adjust","modify"],"level":3,"theme":"企業經營"},{"word":"adaptation","pos":"n.","phonetic":"[ˌædəpˈteʃən]","meaning":"適應；改編（作品）","definition":"the process of changing to suit a new situation","collocations":["adaptation to change","a film adaptation","require some adaptation"],"example":"Adaptation to the new software took the staff only a few weeks.","exampleZh":"員工只花了幾個星期就適應了新軟體。","synonyms":["adjustment","modification"],"level":4,"theme":"日常與一般"},{"word":"add","pos":"v.","phonetic":"[æd]","meaning":"增加；添加；補充說","definition":"to put something together with something else to increase it","collocations":["add to the total","add value","add an item to the order"],"example":"Would you like to add a dessert to your order for two dollars?","exampleZh":"您想加點一份甜點嗎？只要兩美元。","synonyms":["include","attach"],"level":1,"theme":"餐飲與住宿"},{"word":"addition","pos":"n.","phonetic":"[əˈdɪʃən]","meaning":"增加；增添的人或物（in addition 此外）","definition":"something or someone added, or the act of adding","collocations":["in addition to","a welcome addition","the addition of"],"example":"In addition to a competitive salary, the company offers excellent health benefits.","exampleZh":"除了具競爭力的薪資之外，公司還提供優渥的健康福利。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"additional","pos":"adj.","phonetic":"[əˈdɪʃənḷ]","meaning":"額外的；附加的","definition":"more than what was originally expected or agreed","collocations":["additional charges","additional information","at no additional cost"],"example":"Breakfast is included, but airport transfers are available at an additional charge.","exampleZh":"住宿含早餐，但機場接送需額外付費。","synonyms":["extra","further","supplementary"],"level":2,"theme":"餐飲與住宿"},{"word":"address","pos":"n./v.","phonetic":"[əˈdrɛs]","meaning":"處理（問題）；地址；向…致詞","definition":"to deal with a problem, or the details of where someone lives or works","collocations":["address the issue","a mailing address","address customer concerns","deliver an address"],"example":"The manager will address the staffing issue at next week's department meeting.","exampleZh":"經理將在下週的部門會議上處理人力問題。","synonyms":["handle","deal with","tackle"],"level":2,"theme":"辦公室與行政"},{"word":"adequate","pos":"adj.","phonetic":"[ˈædəkwɪt]","meaning":"足夠的；適當的","definition":"enough in quantity or good enough in quality for a purpose","collocations":["adequate funding","adequate training","adequate supplies"],"example":"Please make sure that all new employees receive adequate training before starting work.","exampleZh":"請確保所有新進員工在開始工作前接受足夠的訓練。","synonyms":["sufficient","enough","satisfactory"],"level":4,"theme":"人事與職涯"},{"word":"adjacent","pos":"adj.","phonetic":"[əˈdʒesnt]","meaning":"鄰近的；毗鄰的","definition":"next to or very near something else","collocations":["adjacent to the building","the adjacent room","an adjacent parking lot"],"example":"Visitor parking is available in the lot adjacent to the main building.","exampleZh":"訪客可將車輛停放在主大樓旁邊的停車場。","synonyms":["neighboring","adjoining","nearby"],"level":5,"theme":"房產與設施"},{"word":"adjust","pos":"v.","phonetic":"[əˈdʒʌst]","meaning":"調整；適應","definition":"to change something slightly to make it more suitable","collocations":["adjust the schedule","adjust prices","adjust to a new environment"],"example":"You can adjust the height of the office chair by pulling this lever.","exampleZh":"拉這個拉桿就可以調整辦公椅的高度。","synonyms":["modify","alter","adapt"],"level":2,"theme":"日常與一般"},{"word":"adjustment","pos":"n.","phonetic":"[əˈdʒʌstmənt]","meaning":"調整；調節","definition":"a small change made to make something more suitable","collocations":["make adjustments to","a price adjustment","a slight adjustment"],"example":"We made several adjustments to the production schedule to meet the deadline.","exampleZh":"為了趕上交期，我們對生產排程做了幾項調整。","synonyms":["modification","alteration"],"level":3,"theme":"生產與物流"},{"word":"administration","pos":"n.","phonetic":"[ədˌmɪnəˈstreʃən]","meaning":"行政；管理；行政部門","definition":"the management and organization of a company or institution","collocations":["business administration","the administration office","under new administration"],"example":"She earned a master's degree in business administration before joining the firm.","exampleZh":"她在加入這家公司之前取得了企業管理碩士學位。","synonyms":["management","governance"],"level":3,"theme":"辦公室與行政"},{"word":"administrative","pos":"adj.","phonetic":"[ədˈmɪnəˌstretɪv]","meaning":"行政的；管理的","definition":"relating to the organization and management of a company","collocations":["administrative assistant","administrative duties","administrative costs"],"example":"The administrative assistant handles scheduling, correspondence, and travel arrangements for the director.","exampleZh":"行政助理負責處理主管的行程安排、信件往來與差旅事宜。","synonyms":["managerial","clerical"],"level":3,"theme":"辦公室與行政"},{"word":"administrator","pos":"n.","phonetic":"[ədˈmɪnəˌstretɚ]","meaning":"管理者；行政人員；（系統）管理員","definition":"a person who manages an organization, office, or system","collocations":["a system administrator","a hospital administrator","contact the administrator"],"example":"Contact the system administrator if you cannot log in to your email account.","exampleZh":"如果無法登入電子郵件帳號，請聯絡系統管理員。","synonyms":["manager","supervisor"],"level":3,"theme":"科技與通訊"},{"word":"admire","pos":"v.","phonetic":"[ədˈmaɪr]","meaning":"欽佩；欣賞","definition":"to respect someone or find something attractive or impressive","collocations":["admire the view","admire one's work","greatly admire"],"example":"Guests can admire the ocean view from the hotel's rooftop restaurant.","exampleZh":"房客可以在飯店頂樓餐廳欣賞海景。","synonyms":["respect","appreciate"],"level":2,"theme":"餐飲與住宿"},{"word":"admission","pos":"n.","phonetic":"[ədˈmɪʃən]","meaning":"入場（費）；准許進入；承認","definition":"the money you pay or the permission you need to enter a place","collocations":["free admission","an admission fee","admission to the museum","gain admission"],"example":"Admission to the exhibition is free for children under twelve years old.","exampleZh":"十二歲以下兒童可免費入場參觀這個展覽。","synonyms":["entry","entrance"],"level":3,"theme":"媒體與活動"},{"word":"admit","pos":"v.","phonetic":"[ədˈmɪt]","meaning":"承認；准許進入","definition":"to agree that something is true, often unwillingly; to allow someone to enter","collocations":["admit a mistake","admit defeat","be admitted to the hospital"],"example":"The supplier admitted that the shipment had been delayed by a labeling error.","exampleZh":"供應商承認這批貨因標籤錯誤而延遲出貨。","synonyms":["confess","acknowledge"],"level":2,"theme":"日常與一般"},{"word":"adopt","pos":"v.","phonetic":"[əˈdɑpt]","meaning":"採用；採納；領養","definition":"to formally accept and begin to use a plan, method, or policy","collocations":["adopt a new policy","adopt a strategy","adopt new technology"],"example":"The board voted to adopt a flexible work policy starting next quarter.","exampleZh":"董事會投票通過自下一季起採用彈性工作制度。","synonyms":["embrace","implement","take up"],"level":3,"theme":"企業經營"},{"word":"advance","pos":"n./v./adj.","phonetic":"[ədˈvæns]","meaning":"預先（in advance 事先）；前進；進展；預付款","definition":"forward movement or progress; \"in advance\" means before a particular time","collocations":["in advance","advance notice","advance booking","a cash advance"],"example":"Please make your dinner reservation at least two days in advance.","exampleZh":"晚餐訂位請至少提前兩天預約。","synonyms":["progress","proceed"],"level":2,"theme":"餐飲與住宿"},{"word":"advanced","pos":"adj.","phonetic":"[ədˈvænst]","meaning":"先進的；高階的；進階的","definition":"modern and highly developed, or at a high level","collocations":["advanced technology","an advanced course","advanced equipment"],"example":"The laboratory is equipped with the most advanced testing equipment available.","exampleZh":"這間實驗室配備了目前最先進的檢測設備。","synonyms":["sophisticated","cutting-edge"],"level":3,"theme":"科技與通訊"},{"word":"advantage","pos":"n.","phonetic":"[ədˈvæntɪdʒ]","meaning":"優勢；優點；利益（take advantage of 利用）","definition":"something that helps you be more successful than others","collocations":["a competitive advantage","take advantage of","an advantage over"],"example":"Customers should take advantage of the special discount before it ends Sunday.","exampleZh":"顧客應該把握這檔特別折扣，優惠只到星期日。","synonyms":["benefit","edge"],"level":2,"theme":"購物與消費"},{"word":"advertise","pos":"v.","phonetic":"[ˈædvɚˌtaɪz]","meaning":"登廣告；宣傳；徵求","definition":"to tell the public about a product, service, or job in order to promote it","collocations":["advertise a position","advertise online","advertise a new product"],"example":"The company advertised the marketing position on several popular job websites.","exampleZh":"公司在幾個知名求職網站上刊登了行銷職缺的廣告。","synonyms":["promote","publicize"],"level":2,"theme":"行銷與銷售"},{"word":"advertisement","pos":"n.","phonetic":"[ˌædvɚˈtaɪzmənt]","meaning":"廣告；宣傳","definition":"a notice, picture, or short film that tells people about a product, service, or job","collocations":["place an advertisement","job advertisement","run an advertisement","respond to an advertisement"],"example":"The company placed an advertisement for a sales manager in the local newspaper.","exampleZh":"該公司在地方報紙上刊登了一則徵求業務經理的廣告。","synonyms":["ad","commercial"],"level":2,"theme":"行銷與銷售"},{"word":"advertising","pos":"n.","phonetic":"[ˈædvɚˌtaɪzɪŋ]","meaning":"廣告（業）；廣告活動","definition":"the business or activity of creating public notices to persuade people to buy products or services","collocations":["advertising campaign","advertising agency","advertising budget"],"example":"Our advertising campaign significantly increased sales during the holiday season.","exampleZh":"我們的廣告活動在假期期間大幅提升了銷售額。","synonyms":["promotion","publicity"],"level":2,"theme":"行銷與銷售"},{"word":"advice","pos":"n.","phonetic":"[ədˈvaɪs]","meaning":"建議；忠告","definition":"an opinion or suggestion about what someone should do in a particular situation","collocations":["give advice","seek advice","professional advice","take someone's advice"],"example":"Before signing the contract, she sought advice from a lawyer.","exampleZh":"簽約前，她先向律師尋求建議。","synonyms":["suggestion","guidance","counsel"],"level":1,"theme":"日常與一般"},{"word":"advise","pos":"v.","phonetic":"[ədˈvaɪz]","meaning":"建議；勸告；通知","definition":"to tell someone what you think they should do, especially as an expert","collocations":["advise against","strongly advise","advise someone to do something"],"example":"The consultant advised the company to reduce its operating costs.","exampleZh":"顧問建議公司降低營運成本。","synonyms":["recommend","counsel","suggest"],"level":2,"theme":"日常與一般"},{"word":"advisor","pos":"n.","phonetic":"[ədˈvaɪzɚ]","meaning":"顧問；指導者","definition":"a person whose job is to give expert guidance on a particular subject","collocations":["financial advisor","legal advisor","senior advisor"],"example":"She works as a financial advisor at a major investment firm.","exampleZh":"她在一家大型投資公司擔任財務顧問。","synonyms":["consultant","counselor"],"level":2,"theme":"人事與職涯"},{"word":"affair","pos":"n.","phonetic":"[əˈfɛr]","meaning":"事務；事件","definition":"a matter or situation, especially one connected with business or public life, that is being dealt with","collocations":["business affairs","public affairs","current affairs"],"example":"The vice president handles all public affairs for the corporation.","exampleZh":"副總裁負責公司所有的公共事務。","synonyms":["matter","business"],"level":3,"theme":"企業經營"},{"word":"affect","pos":"v.","phonetic":"[əˈfɛkt]","meaning":"影響；（疾病）侵襲","definition":"to have an influence on someone or something, or cause a change in them","collocations":["adversely affect","directly affect","affect performance"],"example":"The delayed shipment will not affect our production schedule this month.","exampleZh":"延遲的貨運不會影響我們本月的生產排程。","synonyms":["influence","impact"],"level":2,"theme":"日常與一般"},{"word":"afford","pos":"v.","phonetic":"[əˈfɔrd]","meaning":"負擔得起；承擔得起；提供","definition":"to have enough money to buy or pay for something","collocations":["can afford to","afford the cost","cannot afford to lose"],"example":"Many small businesses cannot afford to hire full-time accountants.","exampleZh":"許多小型企業請不起全職會計師。","synonyms":[],"level":2,"theme":"購物與消費"},{"word":"affordable","pos":"adj.","phonetic":"[əˈfɔrdəbḷ]","meaning":"負擔得起的；價格合理的","definition":"cheap enough for most people to be able to buy or pay for","collocations":["affordable prices","affordable housing","affordable options"],"example":"The hotel offers affordable rates for business travelers on weekdays.","exampleZh":"這家飯店平日為商務旅客提供實惠的房價。","synonyms":["inexpensive","reasonable","economical"],"level":2,"theme":"購物與消費"},{"word":"afternoon","pos":"n.","phonetic":"[ˌæftɚˈnun]","meaning":"下午","definition":"the period of the day between noon and the evening","collocations":["in the afternoon","afternoon meeting","tomorrow afternoon"],"example":"The staff meeting has been rescheduled for Thursday afternoon.","exampleZh":"員工會議已改到週四下午舉行。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"afterward","pos":"adv.","phonetic":"[ˈæftɚwɚd]","meaning":"之後；後來","definition":"after an event or time that has already been mentioned","collocations":["shortly afterward","soon afterward","immediately afterward"],"example":"The seminar ends at noon, and lunch will be served afterward.","exampleZh":"研討會中午結束，之後將供應午餐。","synonyms":["later","subsequently"],"level":2,"theme":"日常與一般"},{"word":"agency","pos":"n.","phonetic":"[ˈedʒənsɪ]","meaning":"代理商；仲介；（政府）機構","definition":"a business or organization that provides a particular service on behalf of others","collocations":["travel agency","advertising agency","government agency","employment agency"],"example":"We hired an advertising agency to promote our new product line.","exampleZh":"我們聘請廣告公司來宣傳新產品線。","synonyms":["bureau","firm"],"level":2,"theme":"企業經營"},{"word":"agenda","pos":"n.","phonetic":"[əˈdʒɛndə]","meaning":"議程；待辦事項","definition":"a list of items to be discussed at a meeting","collocations":["on the agenda","meeting agenda","set the agenda","agenda item"],"example":"Please review the agenda before tomorrow's board meeting begins.","exampleZh":"請在明天董事會開始前先看過議程。","synonyms":["schedule","program"],"level":3,"theme":"會議與簡報"},{"word":"agent","pos":"n.","phonetic":"[ˈedʒənt]","meaning":"代理人；經紀人；專員","definition":"a person who acts on behalf of another person or company in business","collocations":["travel agent","real estate agent","sales agent","customer service agent"],"example":"A travel agent helped us book flights and hotels for the conference.","exampleZh":"旅行社專員協助我們預訂了參加會議的機票和飯店。","synonyms":["representative","broker"],"level":2,"theme":"旅遊與交通"},{"word":"agile","pos":"adj.","phonetic":"[ˈædʒəl]","meaning":"敏捷的；靈活的","definition":"able to move, think, or respond quickly and easily","collocations":["agile development","agile approach","remain agile"],"example":"The startup stays agile by responding quickly to changes in the market.","exampleZh":"這家新創公司靠著快速回應市場變化保持靈活。","synonyms":["nimble","flexible"],"level":5,"theme":"企業經營"},{"word":"agree","pos":"v.","phonetic":"[əˈgri]","meaning":"同意；贊成；達成協議","definition":"to have the same opinion, or to say yes to a suggestion or proposal","collocations":["agree with","agree to the terms","agree on a price"],"example":"Both parties agreed to the terms of the new contract.","exampleZh":"雙方都同意了新合約的條款。","synonyms":["consent","concur"],"level":1,"theme":"日常與一般"},{"word":"agreement","pos":"n.","phonetic":"[əˈgrimənt]","meaning":"協議；合約；同意","definition":"an official arrangement or contract between two or more people or organizations","collocations":["reach an agreement","sign an agreement","under the agreement","mutual agreement"],"example":"The two companies signed an agreement to share research facilities.","exampleZh":"兩家公司簽署協議，共享研究設施。","synonyms":["contract","deal","arrangement"],"level":2,"theme":"合約與法律"},{"word":"agriculture","pos":"n.","phonetic":"[ˈægrɪˌkʌltʃɚ]","meaning":"農業","definition":"the practice or industry of farming, including growing crops and raising animals","collocations":["sustainable agriculture","the agriculture industry","modern agriculture"],"example":"The government offers subsidies to support local agriculture and family farms.","exampleZh":"政府提供補助以支持在地農業與家庭農場。","synonyms":["farming"],"level":3,"theme":"生產與物流"},{"word":"ahead","pos":"adv.","phonetic":"[əˈhɛd]","meaning":"提前；在前面；領先","definition":"earlier than planned or expected; in or toward the front","collocations":["ahead of schedule","go ahead","plan ahead","ahead of time"],"example":"The construction project was completed two weeks ahead of schedule.","exampleZh":"這項工程比預定進度提前兩週完工。","synonyms":["in advance"],"level":2,"theme":"日常與一般"},{"word":"aid","pos":"n./v.","phonetic":"[ed]","meaning":"援助；幫助；輔助工具","definition":"money, equipment, or help given to people or organizations in need","collocations":["financial aid","first aid","with the aid of","foreign aid"],"example":"The charity provides financial aid to families affected by the flood.","exampleZh":"該慈善機構提供財務援助給受水災影響的家庭。","synonyms":["assistance","help","support"],"level":3,"theme":"日常與一般"},{"word":"aim","pos":"n./v.","phonetic":"[em]","meaning":"目標；目的；旨在；瞄準","definition":"to have a particular goal or to intend to achieve something","collocations":["aim to do","aim at","main aim","with the aim of"],"example":"The new policy aims to improve employee satisfaction and reduce turnover.","exampleZh":"新政策旨在提升員工滿意度並降低流動率。","synonyms":["goal","objective","target"],"level":2,"theme":"企業經營"},{"word":"aircraft","pos":"n.","phonetic":"[ˈɛrˌkræft]","meaning":"飛機；航空器","definition":"a vehicle, such as an airplane or helicopter, that can fly","collocations":["board the aircraft","aircraft maintenance","commercial aircraft"],"example":"Passengers must turn off electronic devices before the aircraft takes off.","exampleZh":"飛機起飛前，乘客必須關閉電子設備。","synonyms":["airplane","plane"],"level":3,"theme":"旅遊與交通"},{"word":"airline","pos":"n.","phonetic":"[ˈɛrˌlaɪn]","meaning":"航空公司","definition":"a company that provides regular flights to carry passengers and goods","collocations":["airline ticket","budget airline","airline industry"],"example":"The airline canceled several flights because of the severe weather.","exampleZh":"由於天氣惡劣，該航空公司取消了多個航班。","synonyms":["carrier"],"level":1,"theme":"旅遊與交通"},{"word":"airport","pos":"n.","phonetic":"[ˈɛrˌpɔrt]","meaning":"機場","definition":"a place where aircraft take off and land, with buildings for passengers","collocations":["international airport","airport terminal","airport shuttle"],"example":"Please arrive at the airport two hours before your international flight.","exampleZh":"搭乘國際航班請提前兩小時抵達機場。","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"aisle","pos":"n.","phonetic":"[aɪl]","meaning":"走道；通道","definition":"a long narrow passage between rows of seats or shelves","collocations":["aisle seat","window or aisle","down the aisle","supermarket aisle"],"example":"Would you prefer a window seat or an aisle seat?","exampleZh":"您想要靠窗還是靠走道的座位？","synonyms":["passageway","walkway"],"level":3,"theme":"旅遊與交通"},{"word":"alert","pos":"v./n./adj.","phonetic":"[əˈlɝt]","meaning":"提醒；使警覺；警報；警覺的","definition":"to warn someone of a possible danger or problem so they can take action","collocations":["alert someone to","security alert","stay alert","email alert"],"example":"The system automatically alerts staff to any unusual account activity.","exampleZh":"系統會自動提醒員工注意任何異常的帳戶活動。","synonyms":["warn","notify"],"level":4,"theme":"科技與通訊"},{"word":"alliance","pos":"n.","phonetic":"[əˈlaɪəns]","meaning":"聯盟；結盟","definition":"a formal arrangement between organizations or countries to work together","collocations":["form an alliance","strategic alliance","in alliance with"],"example":"The two airlines formed a strategic alliance to expand their global networks.","exampleZh":"這兩家航空公司結成策略聯盟，以擴展全球航線。","synonyms":["partnership","coalition"],"level":5,"theme":"企業經營"},{"word":"allocate","pos":"v.","phonetic":"[ˈæləˌket]","meaning":"分配；撥出（資金、資源）","definition":"to officially give money, time, or resources to a particular person or purpose","collocations":["allocate funds","allocate resources","allocate a budget"],"example":"The board allocated additional funds to the marketing department this quarter.","exampleZh":"董事會本季撥出額外經費給行銷部門。","synonyms":["assign","distribute","apportion"],"level":5,"theme":"財務與會計"},{"word":"allow","pos":"v.","phonetic":"[əˈlaʊ]","meaning":"允許；使能夠","definition":"to give someone permission to do something, or make something possible","collocations":["allow someone to do","be allowed to","allow access to"],"example":"The new software allows employees to work remotely from any location.","exampleZh":"新軟體讓員工可以在任何地點遠距工作。","synonyms":["permit","enable","let"],"level":1,"theme":"日常與一般"},{"word":"allowance","pos":"n.","phonetic":"[əˈlaʊəns]","meaning":"津貼；補助；限額","definition":"an amount of money given regularly to someone for a particular purpose","collocations":["travel allowance","housing allowance","baggage allowance","make allowance for"],"example":"Employees receive a monthly travel allowance for client visits.","exampleZh":"員工每月可領取拜訪客戶的交通津貼。","synonyms":["subsidy","stipend"],"level":4,"theme":"財務與會計"},{"word":"almost","pos":"adv.","phonetic":"[ˈɔlmost]","meaning":"幾乎；差不多","definition":"very nearly but not completely or exactly","collocations":["almost every","almost all","almost finished"],"example":"The quarterly report is almost finished and will be submitted tomorrow.","exampleZh":"季度報告快完成了，明天就會提交。","synonyms":["nearly","virtually"],"level":1,"theme":"日常與一般"},{"word":"along","pos":"prep./adv.","phonetic":"[əˈlɔŋ]","meaning":"沿著；一起；連同（along with）","definition":"moving on or beside something in a constant direction; together with","collocations":["along the street","get along with","bring along","along with"],"example":"Please submit the application form along with two reference letters.","exampleZh":"請將申請表連同兩封推薦信一起提交。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"already","pos":"adv.","phonetic":"[ɔlˈrɛdɪ]","meaning":"已經","definition":"before now, or before a particular time in the past","collocations":["have already done","already available","already in progress"],"example":"The meeting room has already been reserved for Friday's training session.","exampleZh":"會議室已經預訂好，供週五的教育訓練使用。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"also","pos":"adv.","phonetic":"[ˈɔlso]","meaning":"也；而且","definition":"in addition; as well","collocations":["not only... but also","is also available","will also include"],"example":"The hotel also provides free shuttle service to the airport.","exampleZh":"這家飯店也提供免費機場接駁服務。","synonyms":["too","as well","additionally"],"level":1,"theme":"日常與一般"},{"word":"alter","pos":"v.","phonetic":"[ˈɔltɚ]","meaning":"更改；修改","definition":"to change something, or to make someone or something change","collocations":["alter the schedule","alter plans","significantly alter"],"example":"We had to alter our travel plans because of the flight cancellation.","exampleZh":"因為航班取消，我們不得不更改旅遊計畫。","synonyms":["change","modify","adjust"],"level":4,"theme":"日常與一般"},{"word":"alternative","pos":"n./adj.","phonetic":"[ɔlˈtɝnətɪv]","meaning":"替代方案；替代的；另類的","definition":"something that can be chosen or used instead of something else","collocations":["alternative solution","have no alternative but to","alternative energy"],"example":"If the venue is unavailable, we should consider an alternative location.","exampleZh":"如果場地無法使用，我們應該考慮替代地點。","synonyms":["option","substitute","choice"],"level":3,"theme":"日常與一般"},{"word":"although","pos":"conj.","phonetic":"[ɔlˈðo]","meaning":"雖然；儘管","definition":"despite the fact that; even though","collocations":["although sales increased","although the deadline was tight","although not required"],"example":"Although the product is expensive, it remains popular among consumers.","exampleZh":"雖然這項產品價格昂貴，卻仍深受消費者喜愛。","synonyms":["though","even though"],"level":1,"theme":"日常與一般"},{"word":"always","pos":"adv.","phonetic":"[ˈɔlwez]","meaning":"總是；一直","definition":"at all times, or every time","collocations":["as always","always available","always on time"],"example":"Our customer service team is always ready to assist you.","exampleZh":"我們的客服團隊隨時樂意為您服務。","synonyms":["constantly","invariably"],"level":1,"theme":"日常與一般"},{"word":"ambitious","pos":"adj.","phonetic":"[æmˈbɪʃəs]","meaning":"有企圖心的；野心勃勃的；（計畫）艱鉅的","definition":"having a strong desire to be successful, or needing great effort to succeed","collocations":["ambitious plan","ambitious goal","ambitious young professional"],"example":"The company set an ambitious goal of doubling revenue within three years.","exampleZh":"公司訂下三年內營收翻倍的宏大目標。","synonyms":["aspiring","determined"],"level":4,"theme":"人事與職涯"},{"word":"amend","pos":"v.","phonetic":"[əˈmɛnd]","meaning":"修訂；修正（法律、文件）","definition":"to make small changes to a document, law, or agreement to improve or correct it","collocations":["amend the contract","amend the law","amend a proposal"],"example":"The committee voted to amend the company's hiring policy.","exampleZh":"委員會投票通過修訂公司的聘僱政策。","synonyms":["revise","modify","alter"],"level":5,"theme":"合約與法律"},{"word":"amendment","pos":"n.","phonetic":"[əˈmɛndmənt]","meaning":"修正案；修訂","definition":"a change or addition made to a document, law, or agreement","collocations":["make an amendment to","propose an amendment","contract amendment"],"example":"Both parties must approve any amendment to the original agreement.","exampleZh":"任何對原合約的修訂都必須經雙方同意。","synonyms":["revision","modification"],"level":5,"theme":"合約與法律"},{"word":"amenity","pos":"n.","phonetic":"[əˈmɛnətɪ]","meaning":"便利設施；生活機能","definition":"a feature or service that makes a place pleasant or convenient to stay in","collocations":["hotel amenities","modern amenities","on-site amenities"],"example":"The apartment complex offers amenities such as a gym and a pool.","exampleZh":"這個社區提供健身房和游泳池等設施。","synonyms":["facility","convenience"],"level":5,"theme":"房產與設施"},{"word":"among","pos":"prep.","phonetic":"[əˈmʌŋ]","meaning":"在…之中；…之一","definition":"in the middle of or included in a group of people or things","collocations":["among the best","popular among","among other things"],"example":"The new smartphone is especially popular among young consumers.","exampleZh":"這款新手機特別受到年輕消費者的歡迎。","synonyms":["amid","amongst"],"level":2,"theme":"日常與一般"},{"word":"amount","pos":"n./v.","phonetic":"[əˈmaʊnt]","meaning":"金額；數量；總計達（amount to）","definition":"a quantity of something, especially money","collocations":["a large amount of","total amount","amount to","the full amount"],"example":"Please pay the full amount within thirty days of receiving the invoice.","exampleZh":"請於收到發票後三十天內支付全額款項。","synonyms":["quantity","sum"],"level":2,"theme":"財務與會計"},{"word":"analysis","pos":"n.","phonetic":"[əˈnæləsɪs]","meaning":"分析","definition":"a careful examination of something in order to understand it better","collocations":["market analysis","data analysis","conduct an analysis","in-depth analysis"],"example":"The marketing team conducted a detailed analysis of consumer trends.","exampleZh":"行銷團隊針對消費趨勢進行了詳細分析。","synonyms":["examination","study","evaluation"],"level":3,"theme":"企業經營"},{"word":"analyst","pos":"n.","phonetic":"[ˈænḷɪst]","meaning":"分析師","definition":"a person whose job is to examine data or situations and explain them","collocations":["financial analyst","market analyst","industry analysts predict"],"example":"Industry analysts predict steady growth in the technology sector next year.","exampleZh":"產業分析師預測明年科技業將穩定成長。","synonyms":["expert","specialist"],"level":3,"theme":"財務與會計"},{"word":"analyze","pos":"v.","phonetic":"[ˈænḷˌaɪz]","meaning":"分析","definition":"to examine something carefully in order to understand or explain it","collocations":["analyze data","analyze the results","analyze market trends"],"example":"We need to analyze the survey results before making a decision.","exampleZh":"我們必須先分析問卷結果，再做出決定。","synonyms":["examine","evaluate","assess"],"level":3,"theme":"企業經營"},{"word":"anniversary","pos":"n.","phonetic":"[ˌænəˈvɝsərɪ]","meaning":"週年紀念（日）","definition":"the date on which an important event happened in a previous year","collocations":["celebrate an anniversary","tenth anniversary","anniversary sale"],"example":"The store is holding a special sale to celebrate its tenth anniversary.","exampleZh":"這家店正舉辦特賣活動，慶祝開業十週年。","synonyms":[],"level":3,"theme":"媒體與活動"},{"word":"announce","pos":"v.","phonetic":"[əˈnaʊns]","meaning":"宣布；發表","definition":"to make something known officially or publicly","collocations":["announce a decision","officially announce","announce plans to"],"example":"The CEO announced plans to open three new branches overseas.","exampleZh":"執行長宣布將在海外開設三家新分公司。","synonyms":["declare","proclaim"],"level":2,"theme":"企業經營"},{"word":"announcement","pos":"n.","phonetic":"[əˈnaʊnsmənt]","meaning":"公告；宣布","definition":"an official or public statement that informs people about something","collocations":["make an announcement","official announcement","public announcement"],"example":"An important announcement about the merger will be made this afternoon.","exampleZh":"今天下午將發布一項有關合併案的重要公告。","synonyms":["statement","notice","declaration"],"level":2,"theme":"辦公室與行政"},{"word":"annual","pos":"adj.","phonetic":"[ˈænjʊəl]","meaning":"年度的；每年的","definition":"happening once a year, or calculated over a period of one year","collocations":["annual report","annual meeting","annual revenue","annual leave"],"example":"The company's annual report shows a significant increase in profits.","exampleZh":"公司年度報告顯示獲利大幅成長。","synonyms":["yearly"],"level":2,"theme":"財務與會計"},{"word":"annually","pos":"adv.","phonetic":"[ˈænjʊəlɪ]","meaning":"每年地；一年一次地","definition":"once a year, or every year","collocations":["held annually","reviewed annually","renewed annually"],"example":"Employee performance is reviewed annually by the human resources department.","exampleZh":"人資部門每年會對員工績效進行考核。","synonyms":["yearly","every year"],"level":3,"theme":"人事與職涯"},{"word":"another","pos":"det./pron.","phonetic":"[əˈnʌðɚ]","meaning":"另一個；再一個","definition":"one more of the same kind, or a different one","collocations":["another option","one after another","yet another"],"example":"Could you give us another week to complete the project?","exampleZh":"可以再給我們一週的時間完成這個專案嗎？","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"answer","pos":"n./v.","phonetic":"[ˈænsɚ]","meaning":"回答；答案；接（電話）","definition":"to speak or write as a reaction to a question, letter, or phone call","collocations":["answer the phone","answer questions","in answer to"],"example":"The receptionist answers all incoming calls in a friendly manner.","exampleZh":"接待人員總是親切地接聽每一通來電。","synonyms":["reply","respond","response"],"level":1,"theme":"辦公室與行政"},{"word":"anticipate","pos":"v.","phonetic":"[ænˈtɪsəˌpet]","meaning":"預期；預料","definition":"to expect that something will happen and prepare for it","collocations":["anticipate demand","anticipate problems","as anticipated"],"example":"We anticipate strong demand for the new model during the holidays.","exampleZh":"我們預期新機型在假期期間需求會很強勁。","synonyms":["expect","predict","foresee"],"level":5,"theme":"企業經營"},{"word":"anybody","pos":"pron.","phonetic":"[ˈɛnɪˌbɑdɪ]","meaning":"任何人","definition":"any person; used especially in questions and negative sentences","collocations":["anybody else","if anybody","hardly anybody"],"example":"Is there anybody available to cover the front desk this afternoon?","exampleZh":"今天下午有人可以支援櫃檯嗎？","synonyms":["anyone"],"level":1,"theme":"日常與一般"},{"word":"anyone","pos":"pron.","phonetic":"[ˈɛnɪˌwʌn]","meaning":"任何人","definition":"any person; used especially in questions and negative sentences","collocations":["anyone who","anyone else","anyone interested"],"example":"Anyone interested in the workshop should register by Friday.","exampleZh":"有興趣參加工作坊的人請在週五前報名。","synonyms":["anybody"],"level":1,"theme":"日常與一般"},{"word":"anything","pos":"pron.","phonetic":"[ˈɛnɪˌθɪŋ]","meaning":"任何事物","definition":"any object, event, or matter of any kind","collocations":["anything else","if anything","anything but"],"example":"Is there anything else I can help you with today?","exampleZh":"今天還有什麼我可以為您服務的嗎？","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"anywhere","pos":"adv.","phonetic":"[ˈɛnɪˌhwɛr]","meaning":"任何地方","definition":"in, at, or to any place","collocations":["anywhere in the world","anywhere else","from anywhere"],"example":"With this app, you can check your account balance from anywhere.","exampleZh":"有了這個應用程式，你可以隨時隨地查詢帳戶餘額。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"apart","pos":"adv.","phonetic":"[əˈpɑrt]","meaning":"分開地；相隔；除了…之外（apart from）","definition":"separated by a distance in space or time; except for","collocations":["apart from","fall apart","set apart","miles apart"],"example":"Apart from the price, the two laptops are almost identical.","exampleZh":"除了價格之外，這兩台筆電幾乎一模一樣。","synonyms":["separately"],"level":2,"theme":"日常與一般"},{"word":"apartment","pos":"n.","phonetic":"[əˈpɑrtmənt]","meaning":"公寓；公寓房間","definition":"a set of rooms for living in, usually on one floor of a building","collocations":["rent an apartment","apartment building","furnished apartment","apartment complex"],"example":"The company will help cover the cost of renting an apartment near the new office.","exampleZh":"公司會協助負擔在新辦公室附近租公寓的費用。","synonyms":["flat","unit"],"level":1,"theme":"房產與設施"},{"word":"apologize","pos":"v.","phonetic":"[əˈpɑləˌdʒaɪz]","meaning":"道歉；致歉","definition":"to tell someone that you are sorry for something you have done","collocations":["apologize for the delay","apologize to customers","sincerely apologize"],"example":"We apologize for the delay and will ship your order by Friday.","exampleZh":"造成延誤我們深感抱歉，您的訂單將於週五前出貨。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"apology","pos":"n.","phonetic":"[əˈpɑlədʒɪ]","meaning":"道歉；歉意","definition":"a statement in which you say you are sorry about something","collocations":["offer an apology","a formal apology","accept an apology"],"example":"The airline issued a formal apology to passengers affected by the cancellation.","exampleZh":"航空公司針對受班機取消影響的旅客發表正式道歉聲明。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"apparel","pos":"n.","phonetic":"[əˈpærəl]","meaning":"服裝；衣著（尤指店內販售或特定用途的服飾）","definition":"clothing, especially the kind sold in stores or worn for a particular purpose","collocations":["sports apparel","apparel industry","men's apparel"],"example":"The store's new line of winter apparel has been selling extremely well.","exampleZh":"這家店新推出的冬季服飾系列賣得非常好。","synonyms":["clothing","attire","garments"],"level":4,"theme":"購物與消費"},{"word":"apparent","pos":"adj.","phonetic":"[əˈpærənt]","meaning":"明顯的；顯而易見的；表面上的","definition":"easy to see or understand; obvious","collocations":["for no apparent reason","become apparent","apparent from the results"],"example":"It soon became apparent that the project would need more staff.","exampleZh":"大家很快就發現這項專案需要更多人手。","synonyms":["obvious","evident","clear"],"level":3,"theme":"日常與一般"},{"word":"apparently","pos":"adv.","phonetic":"[əˈpærəntlɪ]","meaning":"顯然地；據說；看來","definition":"according to what you have heard or read, or as it seems","collocations":["apparently unaware of","has apparently decided to","apparently due to"],"example":"The meeting was apparently moved to Thursday because of the director's schedule.","exampleZh":"因為總監行程的關係，會議顯然已改到週四。","synonyms":["evidently","seemingly"],"level":3,"theme":"日常與一般"},{"word":"appeal","pos":"n./v.","phonetic":"[əˈpil]","meaning":"吸引力；吸引；呼籲；上訴","definition":"the quality that makes something attractive or interesting, or to attract someone","collocations":["appeal to customers","broad appeal","make an appeal","file an appeal"],"example":"The new packaging is designed to appeal to younger consumers.","exampleZh":"新包裝的設計旨在吸引年輕消費者。","synonyms":["attract","attraction"],"level":3,"theme":"行銷與銷售"},{"word":"appear","pos":"v.","phonetic":"[əˈpɪr]","meaning":"似乎；出現；登場","definition":"to seem to be something, or to start to be seen","collocations":["appear to be","appear on the list","appear in court"],"example":"The error message appears whenever users try to upload large files.","exampleZh":"使用者只要上傳大型檔案，就會出現這個錯誤訊息。","synonyms":["seem","emerge","show up"],"level":1,"theme":"日常與一般"},{"word":"appliance","pos":"n.","phonetic":"[əˈplaɪəns]","meaning":"家電；電器用品","definition":"a machine such as a refrigerator or washing machine that is used in the home","collocations":["household appliances","kitchen appliance","energy-efficient appliances"],"example":"All kitchen appliances purchased this month come with a two-year warranty.","exampleZh":"本月購買的所有廚房家電均享兩年保固。","synonyms":["device","machine"],"level":3,"theme":"購物與消費"},{"word":"applicable","pos":"adj.","phonetic":"[ˈæplɪkəbḷ]","meaning":"適用的；可應用的","definition":"affecting or relating to a particular person, group, or situation","collocations":["applicable law","if applicable","applicable to all employees"],"example":"The discount is applicable only to orders placed through our official website.","exampleZh":"此折扣僅適用於透過官方網站下的訂單。","synonyms":["relevant","valid"],"level":4,"theme":"合約與法律"},{"word":"applicant","pos":"n.","phonetic":"[ˈæpləkənt]","meaning":"申請人；應徵者","definition":"a person who formally asks for a job, a place at a school, or permission to do something","collocations":["job applicant","successful applicant","screen applicants"],"example":"All applicants must submit a resume and two letters of recommendation.","exampleZh":"所有應徵者都必須繳交履歷及兩封推薦信。","synonyms":["candidate"],"level":2,"theme":"人事與職涯"},{"word":"application","pos":"n.","phonetic":"[ˌæpləˈkeʃən]","meaning":"申請；申請書；應用；應用程式","definition":"a formal, usually written, request for something such as a job or membership","collocations":["application form","submit an application","job application","application deadline"],"example":"Please complete the online application form before the June 30 deadline.","exampleZh":"請在6月30日截止日前填妥線上申請表。","synonyms":["request"],"level":2,"theme":"人事與職涯"},{"word":"apply","pos":"v.","phonetic":"[əˈplaɪ]","meaning":"申請；應徵；適用；應用；塗抹","definition":"to make a formal request for a job, permission, or membership","collocations":["apply for a position","apply online","terms and conditions apply"],"example":"Interested candidates should apply for the position by the end of this week.","exampleZh":"有意者請於本週結束前應徵這個職位。","synonyms":[],"level":1,"theme":"人事與職涯"},{"word":"appointment","pos":"n.","phonetic":"[əˈpɔɪntmənt]","meaning":"預約；約定會面；任命","definition":"an arrangement to meet someone at a particular time and place","collocations":["make an appointment","schedule an appointment","doctor's appointment","appointment with a client"],"example":"I would like to make an appointment with Dr. Chen for next Tuesday.","exampleZh":"我想預約下週二陳醫師的門診。","synonyms":["booking","engagement"],"level":2,"theme":"辦公室與行政"},{"word":"appraisal","pos":"n.","phonetic":"[əˈprezḷ]","meaning":"績效考核；評估；估價","definition":"an official judgment of the value, performance, or quality of something or someone","collocations":["performance appraisal","annual appraisal","property appraisal"],"example":"Managers will conduct annual performance appraisals for all staff in December.","exampleZh":"主管將於12月為全體員工進行年度績效考核。","synonyms":["evaluation","assessment","review"],"level":5,"theme":"人事與職涯"},{"word":"appreciate","pos":"v.","phonetic":"[əˈpriʃɪˌet]","meaning":"感謝；重視；欣賞；增值","definition":"to be grateful for something, or to recognize how good or valuable it is","collocations":["greatly appreciate","appreciate your patience","appreciate the opportunity"],"example":"We would appreciate your prompt reply regarding the revised contract terms.","exampleZh":"若您能儘快回覆修訂後的合約條款，我們將不勝感激。","synonyms":["value","treasure"],"level":2,"theme":"日常與一般"},{"word":"appreciation","pos":"n.","phonetic":"[əˌpriʃɪˈeʃən]","meaning":"感謝；欣賞；增值","definition":"a feeling of being grateful for something someone has done","collocations":["in appreciation of","show appreciation","customer appreciation event"],"example":"The company hosted a dinner in appreciation of its long-term clients.","exampleZh":"公司舉辦晚宴，感謝長期合作的客戶。","synonyms":["gratitude","recognition"],"level":3,"theme":"日常與一般"},{"word":"approach","pos":"n./v.","phonetic":"[əˈprotʃ]","meaning":"方法；途徑；接近；洽詢","definition":"a particular way of dealing with a situation or problem","collocations":["a new approach to","take a different approach","approach a potential client"],"example":"The marketing team decided to take a completely different approach this quarter.","exampleZh":"行銷團隊決定本季採取截然不同的做法。","synonyms":["method","strategy"],"level":3,"theme":"企業經營"},{"word":"appropriate","pos":"adj.","phonetic":"[əˈproprɪɪt]","meaning":"適當的；合宜的","definition":"suitable or right for a particular situation or purpose","collocations":["appropriate attire","take appropriate action","appropriate for the occasion"],"example":"Employees are expected to wear appropriate attire when meeting with clients.","exampleZh":"員工與客戶會面時應穿著合宜的服裝。","synonyms":["suitable","proper","fitting"],"level":3,"theme":"日常與一般"},{"word":"approval","pos":"n.","phonetic":"[əˈpruvḷ]","meaning":"批准；核准；贊同","definition":"official permission or agreement for something","collocations":["obtain approval","subject to approval","final approval","approval process"],"example":"The budget proposal requires final approval from the board of directors.","exampleZh":"這份預算提案還需要董事會的最終核准。","synonyms":["authorization","consent","endorsement"],"level":2,"theme":"辦公室與行政"},{"word":"approve","pos":"v.","phonetic":"[əˈpruv]","meaning":"批准；核准；贊成","definition":"to officially agree to or accept something","collocations":["approve a request","approve the budget","approve of the plan"],"example":"The manager approved my request for two additional days of leave.","exampleZh":"經理批准了我多請兩天假的申請。","synonyms":["authorize","endorse","sanction"],"level":2,"theme":"辦公室與行政"},{"word":"approximate","pos":"adj./v.","phonetic":"[əˈprɑksəmɪt]","meaning":"大約的；近似的；接近","definition":"close to a particular number or amount but not exact","collocations":["approximate cost","approximate figure","approximate arrival time"],"example":"Could you give us the approximate cost of renovating the conference room?","exampleZh":"你能告訴我們整修會議室大約要花多少錢嗎？","synonyms":["rough","estimated"],"level":4,"theme":"日常與一般"},{"word":"approximately","pos":"adv.","phonetic":"[əˈprɑksəmɪtlɪ]","meaning":"大約；將近","definition":"close to a particular number or amount but not exactly","collocations":["approximately 30 minutes","approximately 20 percent of","cost approximately $500"],"example":"The flight from Taipei to Tokyo takes approximately three and a half hours.","exampleZh":"從台北飛往東京大約需要三個半小時。","synonyms":["roughly","about","around"],"level":3,"theme":"日常與一般"},{"word":"apron","pos":"n.","phonetic":"[ˈeprən]","meaning":"圍裙","definition":"a piece of clothing worn over the front of your clothes to keep them clean while cooking or working","collocations":["wear an apron","put on an apron","kitchen apron"],"example":"All kitchen staff must wear a clean apron during their shifts.","exampleZh":"所有廚房人員值班時都必須穿著乾淨的圍裙。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"architect","pos":"n.","phonetic":"[ˈɑrkəˌtɛkt]","meaning":"建築師；設計者","definition":"a person whose job is to design buildings","collocations":["hire an architect","landscape architect","chief architect"],"example":"The firm hired a renowned architect to design its new headquarters.","exampleZh":"該公司聘請知名建築師設計新總部。","synonyms":["designer"],"level":3,"theme":"房產與設施"},{"word":"architecture","pos":"n.","phonetic":"[ˈɑrkəˌtɛktʃɚ]","meaning":"建築；建築風格；建築學；（系統）架構","definition":"the style or design of buildings, or the art and practice of designing them","collocations":["modern architecture","study architecture","software architecture"],"example":"Visitors admire the museum's blend of traditional and modern architecture.","exampleZh":"遊客們很欣賞這座博物館融合傳統與現代的建築風格。","synonyms":[],"level":3,"theme":"房產與設施"},{"word":"archive","pos":"n./v.","phonetic":"[ˈɑrkaɪv]","meaning":"檔案；檔案室；將…歸檔","definition":"a collection of historical records, or to store documents for long-term keeping","collocations":["digital archive","archive old files","company archives"],"example":"Please archive all emails older than one year to free up storage space.","exampleZh":"請將一年以上的舊郵件歸檔，以釋出儲存空間。","synonyms":["records","files"],"level":4,"theme":"辦公室與行政"},{"word":"area","pos":"n.","phonetic":"[ˈɛrɪə]","meaning":"區域；地區；領域；面積","definition":"a particular part of a place, building, city, or country","collocations":["reception area","metropolitan area","area of expertise","dining area"],"example":"Please wait in the reception area until your name is called.","exampleZh":"請在接待區稍候，直到叫到您的名字。","synonyms":["region","zone","district"],"level":1,"theme":"日常與一般"},{"word":"argue","pos":"v.","phonetic":"[ˈɑrgju]","meaning":"主張；爭論；爭吵","definition":"to give reasons to support or oppose an idea, or to disagree with someone in words","collocations":["argue that","argue for a change","argue with a colleague"],"example":"Several board members argued that the merger should be postponed until next year.","exampleZh":"幾位董事主張合併案應延到明年再進行。","synonyms":["claim","contend","dispute"],"level":2,"theme":"日常與一般"},{"word":"argument","pos":"n.","phonetic":"[ˈɑrgjəmənt]","meaning":"論點；理由；爭論；爭執","definition":"a reason or set of reasons given to support an idea, or an angry disagreement","collocations":["a strong argument for","make an argument","get into an argument"],"example":"She presented a convincing argument for expanding into the Southeast Asian market.","exampleZh":"她提出了進軍東南亞市場的有力論點。","synonyms":["reasoning","dispute","debate"],"level":2,"theme":"日常與一般"},{"word":"arise","pos":"v.","phonetic":"[əˈraɪz]","meaning":"（問題）出現；發生；產生","definition":"to happen or begin to exist, especially unexpectedly","collocations":["problems arise","should the need arise","arise from a misunderstanding"],"example":"Please contact technical support immediately if any issues arise during installation.","exampleZh":"安裝過程中若出現任何問題，請立即聯絡技術支援。","synonyms":["occur","emerge","happen"],"level":3,"theme":"日常與一般"},{"word":"arrange","pos":"v.","phonetic":"[əˈrendʒ]","meaning":"安排；籌備；排列","definition":"to plan or organize something in advance","collocations":["arrange a meeting","arrange transportation","arrange for delivery"],"example":"My assistant will arrange a meeting with the suppliers early next week.","exampleZh":"我的助理會安排下週初與供應商開會。","synonyms":["organize","schedule","coordinate"],"level":2,"theme":"辦公室與行政"},{"word":"arrangement","pos":"n.","phonetic":"[əˈrendʒmənt]","meaning":"安排；籌備；約定；排列","definition":"plans or preparations made so that something can happen","collocations":["make arrangements","travel arrangements","seating arrangement","flower arrangement"],"example":"The travel agency will handle all arrangements for the company retreat.","exampleZh":"旅行社會處理公司員工旅遊的所有安排。","synonyms":["plan","preparation"],"level":2,"theme":"辦公室與行政"},{"word":"arrival","pos":"n.","phonetic":"[əˈraɪvḷ]","meaning":"到達；抵達；到貨；新到的人（物）","definition":"the act of reaching the place you are going to","collocations":["upon arrival","arrival time","new arrivals","delayed arrival"],"example":"Upon arrival at the hotel, guests will receive a complimentary welcome drink.","exampleZh":"房客抵達飯店時，將獲得一杯免費迎賓飲料。","synonyms":[],"level":2,"theme":"旅遊與交通"},{"word":"arrive","pos":"v.","phonetic":"[əˈraɪv]","meaning":"到達；抵達；送達","definition":"to reach the place you are going to","collocations":["arrive on time","arrive at the airport","arrive in Tokyo"],"example":"The shipment is expected to arrive at the warehouse by Thursday afternoon.","exampleZh":"這批貨預計週四下午前送達倉庫。","synonyms":["reach"],"level":1,"theme":"旅遊與交通"},{"word":"article","pos":"n.","phonetic":"[ˈɑrtɪkḷ]","meaning":"文章；報導；條款；物品","definition":"a piece of writing on a particular subject in a newspaper or magazine","collocations":["publish an article","a feature article","article of clothing"],"example":"She wrote an article about emerging trends in the electric vehicle industry.","exampleZh":"她寫了一篇關於電動車產業新趨勢的文章。","synonyms":["report","piece","item"],"level":2,"theme":"媒體與活動"},{"word":"artist","pos":"n.","phonetic":"[ˈɑrtɪst]","meaning":"藝術家；畫家；表演者","definition":"a person who creates art such as paintings, or who performs music","collocations":["local artist","guest artist","artist in residence"],"example":"The gallery will feature works by several local artists this month.","exampleZh":"本月藝廊將展出多位在地藝術家的作品。","synonyms":["painter","performer"],"level":1,"theme":"媒體與活動"},{"word":"artwork","pos":"n.","phonetic":"[ˈɑrtˌwɝk]","meaning":"藝術品；美術作品；（出版品的）圖稿、美術設計","definition":"paintings, drawings, and other objects made by artists, or images prepared for printing","collocations":["original artwork","display artwork","artwork for the brochure"],"example":"Please send the final artwork for the brochure to the printer by Monday.","exampleZh":"請在週一前把手冊的完稿圖檔送交印刷廠。","synonyms":[],"level":3,"theme":"媒體與活動"},{"word":"ask","pos":"v.","phonetic":"[æsk]","meaning":"詢問；要求；邀請","definition":"to say something to someone in order to get information or help","collocations":["ask a question","ask for assistance","ask about the schedule"],"example":"Feel free to ask our staff if you need any assistance with your order.","exampleZh":"訂單方面若需要任何協助，歡迎隨時詢問我們的工作人員。","synonyms":["inquire","request"],"level":1,"theme":"日常與一般"},{"word":"aspect","pos":"n.","phonetic":"[ˈæspɛkt]","meaning":"方面；層面","definition":"one part or feature of a situation, idea, or problem","collocations":["every aspect of","an important aspect","key aspects of the job"],"example":"Customer service is the most important aspect of our business.","exampleZh":"顧客服務是我們業務中最重要的一環。","synonyms":["facet","dimension","feature"],"level":3,"theme":"日常與一般"},{"word":"assemble","pos":"v.","phonetic":"[əˈsɛmbḷ]","meaning":"組裝；裝配；集合；召集","definition":"to put the parts of something together, or to gather people in one place","collocations":["assemble furniture","easy to assemble","assemble a team"],"example":"The bookshelf comes with clear instructions and takes about twenty minutes to assemble.","exampleZh":"這座書櫃附有清楚的說明書，組裝大約只需二十分鐘。","synonyms":["construct","gather"],"level":3,"theme":"生產與物流"},{"word":"assembly","pos":"n.","phonetic":"[əˈsɛmblɪ]","meaning":"組裝；裝配；集會；議會","definition":"the process of putting the parts of something together","collocations":["assembly line","assembly instructions","some assembly required"],"example":"Workers on the assembly line inspect each unit before it is packaged.","exampleZh":"裝配線上的作業員會在每台機器包裝前逐一檢查。","synonyms":[],"level":3,"theme":"生產與物流"},{"word":"assess","pos":"v.","phonetic":"[əˈsɛs]","meaning":"評估；評定；估價","definition":"to judge the quality, importance, or value of something","collocations":["assess the damage","assess performance","assess the impact"],"example":"The consultant was hired to assess the efficiency of our production process.","exampleZh":"我們聘請顧問來評估生產流程的效率。","synonyms":["evaluate","appraise","gauge"],"level":4,"theme":"企業經營"},{"word":"assessment","pos":"n.","phonetic":"[əˈsɛsmənt]","meaning":"評估；評量；評定","definition":"the act of judging the quality, importance, or value of something","collocations":["risk assessment","needs assessment","conduct an assessment"],"example":"The safety team completed a thorough risk assessment of the new facility.","exampleZh":"安全小組已完成新廠區的完整風險評估。","synonyms":["evaluation","appraisal","analysis"],"level":4,"theme":"企業經營"},{"word":"asset","pos":"n.","phonetic":"[ˈæsɛt]","meaning":"資產；財產；有價值的人（物）","definition":"something valuable that a person or company owns, or a useful quality or person","collocations":["company assets","fixed assets","a valuable asset to the team"],"example":"Her fluency in three languages makes her a valuable asset to the company.","exampleZh":"她精通三種語言，是公司不可多得的人才。","synonyms":["property","resource"],"level":4,"theme":"財務與會計"},{"word":"assign","pos":"v.","phonetic":"[əˈsaɪn]","meaning":"指派；分配；指定","definition":"to give someone a particular job or task to do","collocations":["assign a task","assign staff to a project","assigned seating"],"example":"The supervisor assigned two technicians to repair the broken copier immediately.","exampleZh":"主管立刻指派兩名技術人員去修理故障的影印機。","synonyms":["allocate","designate","delegate"],"level":3,"theme":"辦公室與行政"},{"word":"assignment","pos":"n.","phonetic":"[əˈsaɪnmənt]","meaning":"任務；（指派的）工作；作業；派任","definition":"a piece of work that someone is given to do as part of their job or studies","collocations":["complete an assignment","overseas assignment","take on an assignment"],"example":"He accepted a six-month overseas assignment at the Singapore branch office.","exampleZh":"他接受了到新加坡分公司為期六個月的外派任務。","synonyms":["task","duty","mission"],"level":2,"theme":"辦公室與行政"},{"word":"assist","pos":"v.","phonetic":"[əˈsɪst]","meaning":"協助；幫助","definition":"to help someone do something","collocations":["assist customers","assist with the project","assist in preparing"],"example":"Our staff will be happy to assist you with any billing questions.","exampleZh":"我們的服務人員很樂意協助您處理任何帳單問題。","synonyms":["help","aid","support"],"level":2,"theme":"日常與一般"},{"word":"assistance","pos":"n.","phonetic":"[əˈsɪstəns]","meaning":"協助；幫助；援助","definition":"help or support given to someone","collocations":["technical assistance","financial assistance","require assistance"],"example":"Passengers requiring special assistance should notify the airline 48 hours in advance.","exampleZh":"需要特殊協助的旅客，請提前48小時通知航空公司。","synonyms":["help","aid","support"],"level":2,"theme":"日常與一般"},{"word":"assistant","pos":"n.","phonetic":"[əˈsɪstənt]","meaning":"助理；助手；店員","definition":"a person whose job is to help someone in their work","collocations":["administrative assistant","executive assistant","assistant manager"],"example":"The executive assistant manages the director's calendar and travel plans.","exampleZh":"這位特別助理負責管理總監的行程與差旅安排。","synonyms":["aide","helper"],"level":1,"theme":"人事與職涯"},{"word":"associate","pos":"n./v./adj.","phonetic":"[əˈsoʃɪˌet]","meaning":"同事；夥伴；（門市）店員；使有關聯；副的","definition":"a person you work with in business, or to connect people or things in your mind","collocations":["sales associate","business associate","be associated with"],"example":"A sales associate will help you find the right size in our fitting rooms.","exampleZh":"門市人員會在試衣間協助您找到合適的尺寸。","synonyms":["colleague","partner"],"level":4,"theme":"人事與職涯"},{"word":"assume","pos":"v.","phonetic":"[əˈsum]","meaning":"承擔（責任）；就任（職位）；假定；認為","definition":"to begin to have a position, responsibility, or duty, or to think something is true without proof","collocations":["assume responsibility","assume the role of","assume that"],"example":"Ms. Park will assume the role of regional director starting next month.","exampleZh":"朴女士將於下個月起接任區域總監一職。","synonyms":["undertake","presume","suppose"],"level":3,"theme":"人事與職涯"},{"word":"assumption","pos":"n.","phonetic":"[əˈsʌmpʃən]","meaning":"假設；假定；（責任的）承擔","definition":"something that you accept as true without proof","collocations":["make an assumption","based on the assumption that","a false assumption"],"example":"Our sales forecast is based on the assumption that demand will remain steady.","exampleZh":"我們的銷售預測是以需求維持穩定為前提。","synonyms":["presumption","supposition"],"level":4,"theme":"日常與一般"},{"word":"assurance","pos":"n.","phonetic":"[əˈʃʊrəns]","meaning":"保證；擔保；（品質）保證；把握","definition":"a promise that something will certainly happen or is true","collocations":["quality assurance","give an assurance","assurance of confidentiality"],"example":"The quality assurance team tests every product before it leaves the factory.","exampleZh":"品保團隊會在每項產品出廠前進行測試。","synonyms":["guarantee","pledge"],"level":4,"theme":"生產與物流"},{"word":"assure","pos":"v.","phonetic":"[əˈʃʊr]","meaning":"向…保證；使確信；確保","definition":"to tell someone confidently that something is true so that they do not worry","collocations":["assure customers that","rest assured","I can assure you"],"example":"The manager assured us that the missing shipment would be located soon.","exampleZh":"經理向我們保證，遺失的貨件很快就會找到。","synonyms":["guarantee","promise","reassure"],"level":3,"theme":"日常與一般"},{"word":"atmosphere","pos":"n.","phonetic":"[ˈætməsˌfɪr]","meaning":"氣氛；氛圍；大氣","definition":"the feeling or mood that a place or situation gives you","collocations":["a relaxed atmosphere","friendly atmosphere","the restaurant's atmosphere"],"example":"The cafe is popular for its cozy atmosphere and freshly baked pastries.","exampleZh":"這家咖啡館以溫馨的氣氛和現烤糕點深受歡迎。","synonyms":["ambience","mood"],"level":3,"theme":"餐飲與住宿"},{"word":"attach","pos":"v.","phonetic":"[əˈtætʃ]","meaning":"附上（檔案）；貼上；繫上；使附屬","definition":"to add a document or file to an email, or to fasten one thing to another","collocations":["attach a file","attached to this email","please find attached"],"example":"I have attached the updated price list for your review.","exampleZh":"隨信附上更新後的價目表，敬請過目。","synonyms":["affix","fasten","append"],"level":2,"theme":"科技與通訊"},{"word":"attachment","pos":"n.","phonetic":"[əˈtætʃmənt]","meaning":"附件；附加檔案；依戀","definition":"a computer file sent together with an email message","collocations":["email attachment","open the attachment","see the attachment for details"],"example":"Please review the attachment before our conference call tomorrow morning.","exampleZh":"請在明天早上電話會議前先看過附件。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"attempt","pos":"n./v.","phonetic":"[əˈtɛmpt]","meaning":"嘗試；企圖；試圖","definition":"an act of trying to do something, especially something difficult","collocations":["make an attempt","in an attempt to","attempt to contact"],"example":"We made several attempts to contact the client, but no one answered.","exampleZh":"我們試著聯絡客戶好幾次，但都沒有人接聽。","synonyms":["try","effort","endeavor"],"level":3,"theme":"日常與一般"},{"word":"attend","pos":"v.","phonetic":"[əˈtɛnd]","meaning":"出席；參加；照料；處理","definition":"to go to an event, meeting, or place","collocations":["attend a meeting","attend a conference","attend to a customer"],"example":"All department heads are required to attend the quarterly budget meeting.","exampleZh":"所有部門主管都必須出席季度預算會議。","synonyms":["participate in","be present at"],"level":1,"theme":"會議與簡報"},{"word":"attendance","pos":"n.","phonetic":"[əˈtɛndəns]","meaning":"出席；出席人數；出席率","definition":"the act of being present at an event, meeting, or place, or the number of people present","collocations":["take attendance","attendance record","in attendance","poor attendance"],"example":"Attendance at the annual conference reached a record high this year.","exampleZh":"今年年度大會的出席人數創下新高。","synonyms":["presence","turnout"],"level":3,"theme":"會議與簡報"},{"word":"attendee","pos":"n.","phonetic":"[əˌtɛnˈdi]","meaning":"出席者；與會者","definition":"a person who attends a meeting, conference, or other event","collocations":["conference attendees","registered attendees","attendee list"],"example":"All attendees will receive a copy of the presentation slides by email.","exampleZh":"所有與會者將透過電子郵件收到簡報投影片。","synonyms":["participant","delegate"],"level":3,"theme":"會議與簡報"},{"word":"attention","pos":"n.","phonetic":"[əˈtɛnʃən]","meaning":"注意；關注；照料","definition":"the act of watching, listening to, or thinking about something carefully","collocations":["pay attention to","attract attention","bring to one's attention","attention to detail"],"example":"Please pay close attention to the safety instructions before operating the machine.","exampleZh":"操作機器前，請仔細注意安全說明。","synonyms":["focus","notice"],"level":2,"theme":"日常與一般"},{"word":"attitude","pos":"n.","phonetic":"[ˈætətjud]","meaning":"態度；看法","definition":"the way you think and feel about someone or something, often shown in your behavior","collocations":["positive attitude","attitude toward work","change one's attitude"],"example":"Her positive attitude toward customer complaints impressed the store manager.","exampleZh":"她面對顧客抱怨的正面態度讓店長印象深刻。","synonyms":["outlook","viewpoint"],"level":2,"theme":"人事與職涯"},{"word":"attorney","pos":"n.","phonetic":"[əˈtɝnɪ]","meaning":"律師（美式用法）；法定代理人","definition":"a lawyer, especially one who represents clients in legal matters","collocations":["attorney at law","hire an attorney","power of attorney"],"example":"The company's attorney reviewed the contract before both parties signed it.","exampleZh":"雙方簽約前，公司律師先審閱了合約。","synonyms":["lawyer","counsel"],"level":4,"theme":"合約與法律"},{"word":"attract","pos":"v.","phonetic":"[əˈtrækt]","meaning":"吸引；招徠","definition":"to make someone interested in something or make them want to come to a place","collocations":["attract customers","attract attention","attract investment"],"example":"The new advertising campaign attracted thousands of customers to the store.","exampleZh":"新的廣告活動為這家店吸引了數千名顧客。","synonyms":["draw","appeal to"],"level":2,"theme":"行銷與銷售"},{"word":"attractive","pos":"adj.","phonetic":"[əˈtræktɪv]","meaning":"吸引人的；誘人的；有魅力的","definition":"pleasing or interesting in a way that makes people want something","collocations":["attractive offer","attractive price","attractive to investors"],"example":"The hotel offers attractive discounts for guests who book in advance.","exampleZh":"這家飯店為提前訂房的旅客提供誘人的折扣。","synonyms":["appealing","desirable"],"level":2,"theme":"行銷與銷售"},{"word":"auction","pos":"n./v.","phonetic":"[ˈɔkʃən]","meaning":"拍賣；拍賣會；拍賣（動詞）","definition":"a public sale in which items are sold to the person who offers the highest price","collocations":["auction house","put up for auction","online auction"],"example":"The antique painting was sold at auction for over two million dollars.","exampleZh":"那幅古董畫在拍賣會上以超過兩百萬美元售出。","synonyms":[],"level":4,"theme":"購物與消費"},{"word":"audience","pos":"n.","phonetic":"[ˈɔdɪəns]","meaning":"觀眾；聽眾；受眾","definition":"the group of people who watch or listen to a performance, speech, or program","collocations":["target audience","reach a wider audience","audience feedback"],"example":"The speaker asked the audience to turn off their mobile phones.","exampleZh":"講者請聽眾將手機關機。","synonyms":["spectators","viewers"],"level":2,"theme":"媒體與活動"},{"word":"audio","pos":"n./adj.","phonetic":"[ˈɔdɪˌo]","meaning":"音訊；聲音（的）","definition":"relating to sound, especially sound that is recorded or broadcast","collocations":["audio equipment","audio file","audio system"],"example":"Please check the audio equipment before the video conference begins.","exampleZh":"視訊會議開始前，請先檢查音訊設備。","synonyms":["sound"],"level":2,"theme":"科技與通訊"},{"word":"audit","pos":"n./v.","phonetic":"[ˈɔdɪt]","meaning":"審計；查帳；稽核","definition":"an official examination of a company's financial records to check that they are correct","collocations":["conduct an audit","annual audit","internal audit","tax audit"],"example":"The accounting firm will conduct an annual audit of our financial records.","exampleZh":"這家會計師事務所將對我們的財務紀錄進行年度審計。","synonyms":["inspection","review"],"level":4,"theme":"財務與會計"},{"word":"auditorium","pos":"n.","phonetic":"[ˌɔdəˈtorɪəm]","meaning":"禮堂；觀眾席","definition":"a large room or building where people gather to watch performances or listen to speeches","collocations":["main auditorium","school auditorium","packed auditorium"],"example":"The awards ceremony will be held in the main auditorium at seven.","exampleZh":"頒獎典禮將於七點在大禮堂舉行。","synonyms":["hall"],"level":3,"theme":"房產與設施"},{"word":"author","pos":"n.","phonetic":"[ˈɔθɚ]","meaning":"作者；作家","definition":"a person who writes books, articles, or other written works","collocations":["bestselling author","book author","author of the report"],"example":"The author will sign copies of her new book at the store.","exampleZh":"這位作家將在書店為她的新書簽名。","synonyms":["writer"],"level":2,"theme":"媒體與活動"},{"word":"authority","pos":"n.","phonetic":"[əˈθɔrətɪ]","meaning":"權力；當局；權威","definition":"the power or right to make decisions, give orders, or control something","collocations":["have the authority to","local authorities","person in authority"],"example":"Only the branch manager has the authority to approve large refunds.","exampleZh":"只有分店經理有權核准大額退款。","synonyms":["power","control"],"level":3,"theme":"企業經營"},{"word":"authorize","pos":"v.","phonetic":"[ˈɔθəˌraɪz]","meaning":"授權；批准","definition":"to give official permission for something to happen or for someone to do something","collocations":["authorize a payment","authorized personnel","authorize access"],"example":"The finance director must authorize all expenses over five thousand dollars.","exampleZh":"所有超過五千美元的支出都必須由財務長批准。","synonyms":["approve","permit"],"level":4,"theme":"企業經營"},{"word":"automatic","pos":"adj.","phonetic":"[ˌɔtəˈmætɪk]","meaning":"自動的；自動化的","definition":"working by itself without direct human control","collocations":["automatic payment","automatic doors","automatic renewal"],"example":"Customers can set up automatic payments to avoid missing their monthly bills.","exampleZh":"顧客可以設定自動扣款，以免漏繳每月帳單。","synonyms":["self-operating"],"level":2,"theme":"科技與通訊"},{"word":"automatically","pos":"adv.","phonetic":"[ˌɔtəˈmætɪklɪ]","meaning":"自動地；自然而然地","definition":"by itself, without human control or action","collocations":["automatically renew","automatically update","be automatically deducted"],"example":"Your subscription will automatically renew at the end of each month.","exampleZh":"您的訂閱將於每月月底自動續約。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"automobile","pos":"n.","phonetic":"[ˈɔtəməˌbil]","meaning":"汽車","definition":"a car; a road vehicle with an engine, used for carrying people","collocations":["automobile industry","automobile manufacturer","automobile insurance"],"example":"The automobile industry is investing heavily in electric vehicle technology.","exampleZh":"汽車產業正大力投資電動車技術。","synonyms":["car","vehicle"],"level":3,"theme":"旅遊與交通"},{"word":"availability","pos":"n.","phonetic":"[əˌveləˈbɪlətɪ]","meaning":"可得性；（房間、貨品）尚有供應；（人）有空的時間","definition":"the state of being able to be used, bought, or reached","collocations":["check availability","subject to availability","room availability"],"example":"Please call the hotel to check room availability before making travel plans.","exampleZh":"安排行程前，請先致電飯店確認是否有空房。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"available","pos":"adj.","phonetic":"[əˈveləbḷ]","meaning":"可用的；有空的；買得到的","definition":"able to be used or obtained, or (of a person) free to see or talk to someone","collocations":["available for","readily available","available in stock","available upon request"],"example":"The manager is not available now, but she can meet you tomorrow.","exampleZh":"經理現在沒空，但她明天可以和您見面。","synonyms":["accessible","obtainable"],"level":1,"theme":"辦公室與行政"},{"word":"avenue","pos":"n.","phonetic":"[ˈævəˌnju]","meaning":"大道；林蔭大道；途徑","definition":"a wide street in a town or city; a possible way of achieving something","collocations":["on Fifth Avenue","explore every avenue","tree-lined avenue"],"example":"The new office building is located on Park Avenue near the subway station.","exampleZh":"新辦公大樓位於公園大道上，鄰近地鐵站。","synonyms":["boulevard","street"],"level":2,"theme":"旅遊與交通"},{"word":"average","pos":"adj./n./v.","phonetic":"[ˈævərɪdʒ]","meaning":"平均的；一般的；平均值；平均為","definition":"the amount calculated by adding quantities together and dividing by the number of quantities; typical or usual","collocations":["on average","above average","average income","average temperature"],"example":"On average, employees spend two hours a day answering emails.","exampleZh":"員工平均每天花兩小時回覆電子郵件。","synonyms":["mean","typical"],"level":2,"theme":"日常與一般"},{"word":"avoid","pos":"v.","phonetic":"[əˈvɔɪd]","meaning":"避免；避開","definition":"to stay away from something or prevent something from happening","collocations":["avoid delays","avoid mistakes","avoid rush hour"],"example":"Book your tickets early to avoid paying higher prices during peak season.","exampleZh":"請提早訂票，以免在旺季支付較高的票價。","synonyms":["prevent","evade"],"level":1,"theme":"日常與一般"},{"word":"award","pos":"n./v.","phonetic":"[əˈwɔrd]","meaning":"獎項；獎金；頒發；授予","definition":"a prize given to someone for an achievement, or to officially give something such as a prize or contract","collocations":["win an award","award ceremony","be awarded a contract"],"example":"She received an award for outstanding customer service at the annual banquet.","exampleZh":"她在年度晚宴上獲頒傑出客戶服務獎。","synonyms":["prize","honor"],"level":2,"theme":"媒體與活動"},{"word":"aware","pos":"adj.","phonetic":"[əˈwɛr]","meaning":"知道的；察覺到的；意識到的","definition":"knowing that something exists or having knowledge of a situation","collocations":["be aware of","make someone aware","fully aware"],"example":"Please be aware that the office will be closed next Monday for maintenance.","exampleZh":"請注意，辦公室下週一將因維修而關閉。","synonyms":["conscious","informed"],"level":2,"theme":"日常與一般"},{"word":"away","pos":"adv.","phonetic":"[əˈwe]","meaning":"離開；遠離；不在","definition":"at or to a distance from a place, person, or thing","collocations":["far away","right away","away on business","give away"],"example":"Mr. Chen is away on business and will return next Thursday.","exampleZh":"陳先生出差不在，下週四才會回來。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"background","pos":"n.","phonetic":"[ˈbækˌgraʊnd]","meaning":"背景；學經歷；出身","definition":"a person's education, experience, and family history","collocations":["educational background","background check","background in finance"],"example":"Applicants should have a strong background in marketing and data analysis.","exampleZh":"應徵者應具備行銷與資料分析的深厚背景。","synonyms":["experience"],"level":2,"theme":"人事與職涯"},{"word":"backpack","pos":"n.","phonetic":"[ˈbækˌpæk]","meaning":"背包；後背包","definition":"a bag carried on the back, used for carrying things when walking or traveling","collocations":["carry a backpack","laptop backpack","pack a backpack"],"example":"Please store your backpack in the overhead compartment during the flight.","exampleZh":"飛行期間請將背包放置於頭頂置物櫃內。","synonyms":["knapsack","rucksack"],"level":1,"theme":"旅遊與交通"},{"word":"backup","pos":"n./adj.","phonetic":"[ˈbækˌʌp]","meaning":"備份；後備（的）；支援","definition":"a copy of computer data kept in case the original is lost or damaged; extra support","collocations":["backup copy","backup plan","data backup","make a backup"],"example":"Remember to make a backup of all important files before updating the system.","exampleZh":"更新系統前，記得先備份所有重要檔案。","synonyms":["copy","reserve"],"level":3,"theme":"科技與通訊"},{"word":"badge","pos":"n.","phonetic":"[bædʒ]","meaning":"識別證；徽章；名牌","definition":"a small piece of metal or plastic worn to show who you are or what you do","collocations":["ID badge","name badge","wear a badge","security badge"],"example":"All visitors must wear an identification badge while inside the building.","exampleZh":"所有訪客在大樓內都必須配戴識別證。","synonyms":[],"level":2,"theme":"辦公室與行政"},{"word":"baggage","pos":"n.","phonetic":"[ˈbægɪdʒ]","meaning":"行李","definition":"the bags and suitcases that a person carries when traveling","collocations":["baggage claim","checked baggage","excess baggage","carry-on baggage"],"example":"Passengers can pick up their baggage at carousel number six.","exampleZh":"旅客可在六號行李轉盤領取行李。","synonyms":["luggage"],"level":2,"theme":"旅遊與交通"},{"word":"bake","pos":"v.","phonetic":"[bek]","meaning":"烘焙；烤","definition":"to cook food in an oven using dry heat","collocations":["bake bread","freshly baked","bake a cake"],"example":"The coffee shop bakes fresh bread and pastries every morning before opening.","exampleZh":"這家咖啡店每天早上開門前都會現烤麵包和糕點。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"bakery","pos":"n.","phonetic":"[ˈbekərɪ]","meaning":"麵包店；烘焙坊","definition":"a shop where bread, cakes, and pastries are made or sold","collocations":["local bakery","bakery products","open a bakery"],"example":"The bakery on Main Street is famous for its chocolate croissants.","exampleZh":"大街上那家麵包店以巧克力可頌聞名。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"balance","pos":"n./v.","phonetic":"[ˈbæləns]","meaning":"餘額；結餘；平衡；使平衡","definition":"the amount of money in a bank account, or a state in which different things are equal","collocations":["account balance","check your balance","work-life balance","balance the budget"],"example":"You can check your account balance anytime through our mobile banking app.","exampleZh":"您可以隨時透過我們的行動銀行應用程式查詢帳戶餘額。","synonyms":["remainder"],"level":2,"theme":"財務與會計"},{"word":"balcony","pos":"n.","phonetic":"[ˈbælkənɪ]","meaning":"陽台；（劇院的）樓座","definition":"a platform on the outside of a building, above ground level, enclosed by a wall or rail","collocations":["private balcony","balcony view","room with a balcony"],"example":"Our deluxe rooms feature a private balcony overlooking the ocean.","exampleZh":"我們的豪華客房設有可眺望海景的私人陽台。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"ballroom","pos":"n.","phonetic":"[ˈbɔlˌrum]","meaning":"宴會廳；舞廳","definition":"a large room used for formal dances, banquets, or other events","collocations":["hotel ballroom","grand ballroom","ballroom dancing"],"example":"The company banquet will take place in the hotel's grand ballroom.","exampleZh":"公司晚宴將在飯店的大宴會廳舉行。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"ban","pos":"v./n.","phonetic":"[bæn]","meaning":"禁止；禁令","definition":"to officially say that something must not be done, or an official rule that forbids something","collocations":["impose a ban","smoking ban","ban on parking","lift a ban"],"example":"The city council voted to ban smoking in all public parks.","exampleZh":"市議會投票通過禁止在所有公園內吸菸。","synonyms":["prohibit","forbid"],"level":3,"theme":"合約與法律"},{"word":"bank","pos":"n./v.","phonetic":"[bæŋk]","meaning":"銀行；河岸；把錢存入銀行","definition":"an organization that keeps and lends money and provides financial services","collocations":["bank account","bank loan","bank transfer","go to the bank"],"example":"You will need to open a bank account before receiving your salary.","exampleZh":"領薪水之前，你必須先開立銀行帳戶。","synonyms":[],"level":1,"theme":"財務與會計"},{"word":"banking","pos":"n.","phonetic":"[ˈbæŋkɪŋ]","meaning":"銀行業；銀行業務","definition":"the business activity of banks and similar financial institutions","collocations":["online banking","banking services","mobile banking","banking industry"],"example":"Online banking allows customers to transfer money without visiting a branch.","exampleZh":"網路銀行讓顧客不必親臨分行就能轉帳。","synonyms":[],"level":2,"theme":"財務與會計"},{"word":"bankrupt","pos":"adj./v.","phonetic":"[ˈbæŋkrʌpt]","meaning":"破產的；使破產","definition":"unable to pay your debts and officially declared to have no money","collocations":["go bankrupt","be declared bankrupt","bankrupt company"],"example":"The retail chain went bankrupt after years of declining sales.","exampleZh":"這家連鎖零售商在銷售連年下滑後宣告破產。","synonyms":["insolvent"],"level":4,"theme":"財務與會計"},{"word":"banner","pos":"n.","phonetic":"[ˈbænɚ]","meaning":"橫幅；布條；橫幅廣告","definition":"a long piece of cloth or a digital image displaying a message or advertisement","collocations":["banner ad","hang a banner","welcome banner"],"example":"Volunteers hung a colorful banner above the entrance to welcome conference guests.","exampleZh":"志工在入口上方掛起色彩繽紛的橫幅，歡迎與會嘉賓。","synonyms":[],"level":3,"theme":"行銷與銷售"},{"word":"banquet","pos":"n.","phonetic":"[ˈbæŋkwɪt]","meaning":"宴會；晚宴；盛宴","definition":"a formal dinner for many people held on a special occasion","collocations":["banquet hall","awards banquet","hold a banquet","annual banquet"],"example":"Tickets for the retirement banquet must be purchased by Friday afternoon.","exampleZh":"退休晚宴的餐券必須在週五下午前購買。","synonyms":["feast"],"level":3,"theme":"餐飲與住宿"},{"word":"bargain","pos":"n./v.","phonetic":"[ˈbɑrgɪn]","meaning":"特價品；划算的交易；討價還價","definition":"something bought for less than its usual price, or to negotiate the price of something","collocations":["bargain price","get a bargain","bargain hunting","bargain with"],"example":"Shoppers found great bargains during the store's year-end clearance sale.","exampleZh":"顧客在這家店的年終清倉特賣中找到許多超值好物。","synonyms":["deal"],"level":3,"theme":"購物與消費"},{"word":"barrier","pos":"n.","phonetic":"[ˈbærɪɚ]","meaning":"障礙；阻礙；柵欄","definition":"something that blocks the way or prevents progress or communication","collocations":["trade barrier","language barrier","remove barriers","safety barrier"],"example":"The language barrier made it difficult to negotiate with the overseas supplier.","exampleZh":"語言障礙使得與海外供應商的談判變得困難。","synonyms":["obstacle","obstruction"],"level":3,"theme":"企業經營"},{"word":"base","pos":"n./v.","phonetic":"[bes]","meaning":"基礎；總部；基地；以…為據點","definition":"the main place where a company or activity is managed, or to have something as a foundation","collocations":["customer base","based in","base salary","home base"],"example":"The software company is based in Taipei but serves clients worldwide.","exampleZh":"這家軟體公司總部設於台北，但服務全球客戶。","synonyms":["foundation","headquarters"],"level":2,"theme":"企業經營"},{"word":"basement","pos":"n.","phonetic":"[ˈbesmənt]","meaning":"地下室","definition":"a room or floor of a building that is below ground level","collocations":["basement parking","in the basement","basement floor"],"example":"Extra office supplies are stored in the basement next to the parking garage.","exampleZh":"多餘的辦公用品存放在停車場旁的地下室。","synonyms":["cellar"],"level":2,"theme":"房產與設施"},{"word":"basic","pos":"adj.","phonetic":"[ˈbesɪk]","meaning":"基本的；基礎的","definition":"forming the simplest or most important part of something","collocations":["basic skills","basic training","basic requirements","basic salary"],"example":"All new employees receive basic training during their first week of work.","exampleZh":"所有新進員工在到職第一週都會接受基礎訓練。","synonyms":["fundamental","essential"],"level":1,"theme":"日常與一般"},{"word":"basically","pos":"adv.","phonetic":"[ˈbesɪklɪ]","meaning":"基本上；大致上","definition":"in the most important ways, without considering small details","collocations":["basically the same","basically agree"],"example":"The two software packages are basically the same except for the price.","exampleZh":"這兩套軟體除了價格之外基本上相同。","synonyms":["essentially","fundamentally"],"level":2,"theme":"日常與一般"},{"word":"basis","pos":"n.","phonetic":"[ˈbesɪs]","meaning":"基礎；根據；（on a...basis）以…的方式","definition":"the way or frequency in which something is done, or the reason for something","collocations":["on a regular basis","on a daily basis","on a first-come basis","the basis of"],"example":"The cleaning crew inspects the equipment on a weekly basis.","exampleZh":"清潔人員每週檢查一次設備。","synonyms":["foundation","grounds"],"level":3,"theme":"辦公室與行政"},{"word":"batch","pos":"n.","phonetic":"[bætʃ]","meaning":"一批；一組；批次","definition":"a group of things or people produced or dealt with at the same time","collocations":["a batch of","batch processing","in batches","fresh batch"],"example":"The factory shipped a new batch of products to overseas distributors yesterday.","exampleZh":"工廠昨天將一批新產品運送給海外經銷商。","synonyms":["group","lot"],"level":4,"theme":"生產與物流"},{"word":"bathroom","pos":"n.","phonetic":"[ˈbæθˌrum]","meaning":"浴室；廁所","definition":"a room with a toilet and often a bath or shower","collocations":["public bathroom","bathroom facilities","remodel a bathroom"],"example":"Each hotel room has a private bathroom with a bathtub and shower.","exampleZh":"每間客房都有附浴缸和淋浴設備的獨立衛浴。","synonyms":["restroom","washroom"],"level":1,"theme":"餐飲與住宿"},{"word":"battery","pos":"n.","phonetic":"[ˈbætərɪ]","meaning":"電池","definition":"a device that stores and provides electricity for phones, cars, and other machines","collocations":["battery life","charge the battery","replace the battery","dead battery"],"example":"Please charge the laptop battery fully before the afternoon presentation.","exampleZh":"下午簡報前，請先將筆電電池充飽。","synonyms":[],"level":1,"theme":"科技與通訊"},{"word":"beach","pos":"n.","phonetic":"[bitʃ]","meaning":"海灘；沙灘","definition":"an area of sand or small stones beside the sea or a lake","collocations":["beach resort","on the beach","sandy beach"],"example":"The resort offers free shuttle service to the beach every hour.","exampleZh":"度假村每小時提供一班前往海灘的免費接駁車。","synonyms":["seashore","coast"],"level":1,"theme":"旅遊與交通"},{"word":"bear","pos":"v./n.","phonetic":"[bɛr]","meaning":"承擔；忍受；熊","definition":"to accept or be responsible for something, or to endure something difficult","collocations":["bear the cost","bear in mind","bear responsibility","can't bear"],"example":"The supplier agreed to bear the cost of shipping the replacement parts.","exampleZh":"供應商同意負擔更換零件的運費。","synonyms":["endure","tolerate"],"level":3,"theme":"企業經營"},{"word":"beautiful","pos":"adj.","phonetic":"[ˈbjutəfəl]","meaning":"美麗的；漂亮的","definition":"very pleasing to look at, hear, or experience","collocations":["beautiful scenery","beautiful view","beautiful weather"],"example":"The conference center offers a beautiful view of the harbor.","exampleZh":"會議中心可欣賞到美麗的海港景色。","synonyms":["lovely","gorgeous"],"level":1,"theme":"日常與一般"},{"word":"because","pos":"conj.","phonetic":"[bɪˈkɔz]","meaning":"因為","definition":"for the reason that","collocations":["because of","just because","simply because"],"example":"The flight was delayed because of heavy snow at the departure airport.","exampleZh":"由於出發機場下大雪，班機因此延誤。","synonyms":["since","as"],"level":1,"theme":"日常與一般"},{"word":"become","pos":"v.","phonetic":"[bɪˈkʌm]","meaning":"成為；變得","definition":"to begin to be something or to develop into something","collocations":["become available","become aware of","become popular"],"example":"The position will become available when the current manager retires in June.","exampleZh":"現任經理六月退休後，這個職位就會出缺。","synonyms":["turn into","grow"],"level":1,"theme":"日常與一般"},{"word":"before","pos":"prep./conj./adv.","phonetic":"[bɪˈfor]","meaning":"在…之前；以前","definition":"earlier than a particular time or event","collocations":["before the deadline","before long","the day before"],"example":"Please submit your expense report before the end of this month.","exampleZh":"請在本月底前提交你的費用報告。","synonyms":["prior to"],"level":1,"theme":"日常與一般"},{"word":"begin","pos":"v.","phonetic":"[bɪˈgɪn]","meaning":"開始；著手","definition":"to start doing something or to start happening","collocations":["begin with","begin a meeting","to begin with"],"example":"The orientation session will begin promptly at nine in the main conference room.","exampleZh":"新人說明會將於九點準時在大會議室開始。","synonyms":["start","commence"],"level":1,"theme":"日常與一般"},{"word":"beginner","pos":"n.","phonetic":"[bɪˈgɪnɚ]","meaning":"初學者；新手","definition":"a person who is starting to learn or do something for the first time","collocations":["beginner level","beginner course","suitable for beginners"],"example":"The gym offers yoga classes for beginners every Tuesday evening.","exampleZh":"這家健身房每週二晚上開設初學者瑜伽課程。","synonyms":["novice","newcomer"],"level":2,"theme":"日常與一般"},{"word":"beginning","pos":"n.","phonetic":"[bɪˈɡɪnɪŋ]","meaning":"開始；起初；開端","definition":"the first part or the start of something","collocations":["at the beginning of the month","from beginning to end","the beginning of the fiscal year"],"example":"Employees must submit their timesheets at the beginning of each month.","exampleZh":"員工必須在每月月初繳交工時表。","synonyms":["start","outset","commencement"],"level":1,"theme":"日常與一般"},{"word":"behalf","pos":"n.","phonetic":"[bɪˈhæf]","meaning":"代表；為了…的利益（on behalf of 代表…）","definition":"used in the phrase 'on behalf of' to mean as the representative of someone or instead of them","collocations":["on behalf of the company","sign on someone's behalf","accept an award on behalf of"],"example":"On behalf of the management team, I would like to thank all our staff.","exampleZh":"我謹代表管理團隊，感謝全體同仁。","synonyms":[],"level":3,"theme":"辦公室與行政"},{"word":"behavior","pos":"n.","phonetic":"[bɪˈhevjɚ]","meaning":"行為；舉止；表現","definition":"the way a person or animal acts or conducts themselves","collocations":["consumer behavior","professional behavior","a change in behavior"],"example":"The marketing team studies consumer behavior to improve its advertising strategies.","exampleZh":"行銷團隊研究消費者行為，以改善廣告策略。","synonyms":["conduct","manner"],"level":2,"theme":"行銷與銷售"},{"word":"behind","pos":"prep./adv.","phonetic":"[bɪˈhaɪnd]","meaning":"落後（進度）；在…後面；支持","definition":"at or toward the back of someone or something; late or slow in making progress","collocations":["behind schedule","fall behind","behind the counter"],"example":"The construction project is two weeks behind schedule due to bad weather.","exampleZh":"由於天候不佳，這項工程的進度落後了兩週。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"believe","pos":"v.","phonetic":"[bɪˈliv]","meaning":"相信；認為","definition":"to think that something is true or that someone is telling the truth","collocations":["believe in","firmly believe","have reason to believe"],"example":"We believe the new policy will increase employee satisfaction significantly.","exampleZh":"我們相信新政策將大幅提升員工滿意度。","synonyms":["trust","suppose"],"level":1,"theme":"日常與一般"},{"word":"belong","pos":"v.","phonetic":"[bəˈlɔŋ]","meaning":"屬於；是…的成員；應放在（某處）","definition":"to be the property of someone, or to be a member of a group or organization","collocations":["belong to a committee","belong to the company","belong in the cabinet"],"example":"These files belong to the accounting department and should be returned promptly.","exampleZh":"這些檔案屬於會計部門，應盡快歸還。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"below","pos":"prep./adv.","phonetic":"[bəˈlo]","meaning":"低於；在…下方；在下文","definition":"at or to a lower position, level, or amount than something","collocations":["below average","see the details below","below the market price"],"example":"Sales figures for the last quarter were well below our expectations.","exampleZh":"上一季的銷售數字遠低於我們的預期。","synonyms":["beneath","under"],"level":1,"theme":"日常與一般"},{"word":"beneficial","pos":"adj.","phonetic":"[ˌbɛnəˈfɪʃəl]","meaning":"有益的；有利的","definition":"producing good or helpful results or effects","collocations":["mutually beneficial","beneficial to both parties","a beneficial effect"],"example":"The merger proved mutually beneficial for both companies involved.","exampleZh":"這次合併對參與的兩家公司都證明是互利的。","synonyms":["advantageous","helpful","favorable"],"level":3,"theme":"企業經營"},{"word":"benefit","pos":"n./v.","phonetic":"[ˈbɛnəfɪt]","meaning":"福利；利益；獲益；有益於","definition":"an advantage or helpful effect, especially money or services provided by an employer in addition to pay","collocations":["employee benefits","a benefits package","benefit from the training"],"example":"Full-time employees receive a generous benefits package, including health insurance.","exampleZh":"正職員工享有優渥的福利制度，包括健康保險。","synonyms":["advantage","gain"],"level":2,"theme":"人事與職涯"},{"word":"beside","pos":"prep.","phonetic":"[bɪˈsaɪd]","meaning":"在…旁邊","definition":"next to or at the side of someone or something","collocations":["sit beside","right beside the entrance","park beside the building"],"example":"The printer is located beside the copy machine on the second floor.","exampleZh":"印表機位於二樓影印機的旁邊。","synonyms":["alongside"],"level":1,"theme":"日常與一般"},{"word":"besides","pos":"prep./adv.","phonetic":"[bɪˈsaɪdz]","meaning":"除…之外（還有）；此外","definition":"in addition to something; used to add another reason or fact","collocations":["besides the salary","besides that","many benefits besides"],"example":"Besides free parking, the company also offers meal allowances to staff.","exampleZh":"除了免費停車之外，公司還提供員工餐費補助。","synonyms":["in addition","moreover"],"level":2,"theme":"日常與一般"},{"word":"best","pos":"adj./adv./n.","phonetic":"[bɛst]","meaning":"最好的；最佳地；最佳者","definition":"of the highest quality, or the most suitable or effective of its kind","collocations":["best practices","best regards","do one's best"],"example":"Our hotel was voted the best in the region for customer service.","exampleZh":"本飯店的顧客服務獲選為全區最佳。","synonyms":["finest","top"],"level":1,"theme":"日常與一般"},{"word":"bestseller","pos":"n.","phonetic":"[ˈbɛstˈsɛlɚ]","meaning":"暢銷書；暢銷商品","definition":"a product, especially a book, that sells in very large numbers","collocations":["a bestseller list","become a bestseller","a national bestseller"],"example":"Her latest novel became a bestseller within two weeks of its release.","exampleZh":"她的最新小說上市短短兩週便成為暢銷書。","synonyms":[],"level":3,"theme":"行銷與銷售"},{"word":"better","pos":"adj./adv./v.","phonetic":"[ˈbɛtɚ]","meaning":"更好的；更好地；改善","definition":"of a higher quality or standard, or more suitable than something else","collocations":["better than expected","a better deal","get better"],"example":"The revised proposal is much better than the original version.","exampleZh":"修改後的提案比原本的版本好上許多。","synonyms":["superior","improved"],"level":1,"theme":"日常與一般"},{"word":"between","pos":"prep./adv.","phonetic":"[bɪˈtwin]","meaning":"在…之間","definition":"in the space or period of time separating two things, places, or people","collocations":["between meetings","choose between","the difference between"],"example":"The shuttle bus runs between the airport and the hotel every thirty minutes.","exampleZh":"接駁車每三十分鐘往返機場與飯店之間。","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"beverage","pos":"n.","phonetic":"[ˈbɛvərɪdʒ]","meaning":"飲料","definition":"a drink of any type, especially one other than water","collocations":["complimentary beverages","food and beverage","beverage service"],"example":"Complimentary beverages will be served to all passengers during the flight.","exampleZh":"機上將為所有旅客提供免費飲料。","synonyms":["drink"],"level":2,"theme":"餐飲與住宿"},{"word":"beyond","pos":"prep./adv.","phonetic":"[bɪˈjɑnd]","meaning":"超過；超出…的範圍；在…的另一邊","definition":"more than a particular amount or limit; on the farther side of something","collocations":["beyond expectations","beyond repair","go beyond"],"example":"The hotel staff went beyond our expectations to make the conference a success.","exampleZh":"飯店人員的表現超乎我們的期待，讓這場會議圓滿成功。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"bias","pos":"n./v.","phonetic":"[ˈbaɪəs]","meaning":"偏見；偏袒；使有偏見","definition":"an unfair preference for or dislike of a particular person or group","collocations":["gender bias","bias against","without bias"],"example":"The company trains its managers to avoid bias in the hiring process.","exampleZh":"公司訓練主管在招募過程中避免偏見。","synonyms":["prejudice","partiality"],"level":4,"theme":"人事與職涯"},{"word":"bid","pos":"n./v.","phonetic":"[bɪd]","meaning":"投標；出價；競標","definition":"an offer to do work or supply goods at a stated price, or the act of making such an offer","collocations":["submit a bid","the winning bid","bid on a contract"],"example":"Three construction firms submitted bids for the new office building project.","exampleZh":"三家營造公司針對新辦公大樓工程案提出投標。","synonyms":["offer","tender"],"level":4,"theme":"合約與法律"},{"word":"big","pos":"adj.","phonetic":"[bɪɡ]","meaning":"大的；重大的；重要的","definition":"large in size, amount, or degree, or important in influence","collocations":["a big decision","a big discount","a big client"],"example":"Landing this big client will greatly increase our annual revenue.","exampleZh":"拿下這個大客戶將大幅提升我們的年營收。","synonyms":["large","major"],"level":1,"theme":"日常與一般"},{"word":"bilingual","pos":"adj.","phonetic":"[baɪˈlɪŋɡwəl]","meaning":"雙語的；能說兩種語言的","definition":"able to speak two languages fluently, or written in two languages","collocations":["bilingual staff","a bilingual receptionist","bilingual education"],"example":"We are seeking a bilingual receptionist who is fluent in English and Japanese.","exampleZh":"我們正在徵求一位精通英日雙語的櫃檯接待人員。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"bill","pos":"n./v.","phonetic":"[bɪl]","meaning":"帳單；法案；鈔票；向…開立帳單","definition":"a written statement showing how much money you owe for goods or services","collocations":["pay the bill","a utility bill","bill a client"],"example":"Please review the bill carefully before making the payment.","exampleZh":"付款前請仔細核對帳單。","synonyms":["invoice","statement"],"level":2,"theme":"財務與會計"},{"word":"billboard","pos":"n.","phonetic":"[ˈbɪlˌbord]","meaning":"大型廣告看板","definition":"a large outdoor board used for displaying advertisements","collocations":["billboard advertising","put up a billboard","a highway billboard"],"example":"The company rented a huge billboard along the highway to promote its new product.","exampleZh":"該公司在公路旁租下大型廣告看板來宣傳新產品。","synonyms":["hoarding"],"level":3,"theme":"行銷與銷售"},{"word":"billing","pos":"n.","phonetic":"[ˈbɪlɪŋ]","meaning":"開立帳單；帳務處理","definition":"the process of preparing and sending bills or invoices to customers","collocations":["billing address","billing cycle","a billing error"],"example":"Please contact our billing department if you find any errors on your invoice.","exampleZh":"若發現發票上有任何錯誤，請聯絡我們的帳務部門。","synonyms":["invoicing"],"level":3,"theme":"財務與會計"},{"word":"bin","pos":"n.","phonetic":"[bɪn]","meaning":"垃圾桶；回收桶；儲物箱","definition":"a container for storing things or for throwing away waste","collocations":["a recycling bin","a storage bin","the overhead bin"],"example":"Please place all recyclable materials in the blue bins by the entrance.","exampleZh":"請將所有可回收物品放入入口旁的藍色回收桶。","synonyms":["container"],"level":2,"theme":"日常與一般"},{"word":"binding","pos":"adj./n.","phonetic":"[ˈbaɪndɪŋ]","meaning":"有（法律）約束力的；裝訂","definition":"(of an agreement or promise) that must be obeyed because it is legally accepted","collocations":["legally binding","a binding contract","a binding agreement"],"example":"Once signed, the contract becomes legally binding on both parties.","exampleZh":"合約一經簽署，即對雙方具有法律約束力。","synonyms":["obligatory","compulsory"],"level":5,"theme":"合約與法律"},{"word":"bit","pos":"n.","phonetic":"[bɪt]","meaning":"一點；少量；小片","definition":"a small amount or small piece of something","collocations":["a bit of","a little bit","quite a bit"],"example":"The meeting ran a bit longer than we had originally planned.","exampleZh":"會議進行的時間比原先預定的稍微長了一些。","synonyms":["piece","fragment"],"level":1,"theme":"日常與一般"},{"word":"blank","pos":"adj./n.","phonetic":"[blæŋk]","meaning":"空白的；空白處；表格欄位","definition":"containing no writing, marks, or information","collocations":["a blank form","fill in the blanks","leave it blank"],"example":"Please fill in all the blanks on the application form before submitting it.","exampleZh":"送出申請表之前，請填妥所有空白欄位。","synonyms":["empty"],"level":2,"theme":"辦公室與行政"},{"word":"blanket","pos":"n./adj.","phonetic":"[ˈblæŋkɪt]","meaning":"毯子；全面的；總括的","definition":"a large piece of soft material used as a covering to keep you warm","collocations":["an extra blanket","a wool blanket","a blanket policy"],"example":"The flight attendant kindly brought me an extra blanket and a pillow.","exampleZh":"空服員貼心地為我送來一條多的毯子和一個枕頭。","synonyms":["cover"],"level":2,"theme":"旅遊與交通"},{"word":"blend","pos":"n./v.","phonetic":"[blɛnd]","meaning":"混合；混合物；調和","definition":"to mix different things together to form a single substance or product","collocations":["a blend of","a special coffee blend","blend in with"],"example":"Our signature coffee is a special blend of beans from three countries.","exampleZh":"我們的招牌咖啡是以三個國家的咖啡豆特調而成。","synonyms":["mixture","combination"],"level":3,"theme":"餐飲與住宿"},{"word":"block","pos":"n./v.","phonetic":"[blɑk]","meaning":"街區；阻擋；封鎖","definition":"the distance along a city street from one crossing to the next; to stop something from moving through","collocations":["two blocks away","block the entrance","an office block"],"example":"The hotel is just two blocks away from the central train station.","exampleZh":"飯店距離中央車站只有兩個街區。","synonyms":["obstruct"],"level":2,"theme":"旅遊與交通"},{"word":"blueprint","pos":"n.","phonetic":"[ˈbluˌprɪnt]","meaning":"藍圖；設計圖；詳細計畫","definition":"a detailed technical drawing or plan for a building, machine, or project","collocations":["review the blueprints","a blueprint for success","architectural blueprints"],"example":"The architect presented the blueprints for the new headquarters at the meeting.","exampleZh":"建築師在會議上展示了新總部的設計藍圖。","synonyms":["plan","design"],"level":4,"theme":"房產與設施"},{"word":"board","pos":"n./v.","phonetic":"[bord]","meaning":"董事會；委員會；木板；登機（車、船）","definition":"a group of people who manage or direct a company; to get on a plane, ship, or train","collocations":["the board of directors","a board meeting","board a plane"],"example":"The board of directors will vote on the merger proposal next Tuesday.","exampleZh":"董事會將於下週二針對合併提案進行表決。","synonyms":["committee","council"],"level":2,"theme":"企業經營"},{"word":"boarding","pos":"n.","phonetic":"[ˈbordɪŋ]","meaning":"登機；登船；寄宿","definition":"the act of getting on a plane, ship, or train","collocations":["a boarding pass","the boarding gate","begin boarding"],"example":"Passengers should have their boarding passes ready at the gate.","exampleZh":"旅客請在登機門前備妥登機證。","synonyms":[],"level":2,"theme":"旅遊與交通"},{"word":"boardroom","pos":"n.","phonetic":"[ˈbordˌrum]","meaning":"董事會會議室","definition":"a room where the directors of a company hold their meetings","collocations":["in the boardroom","reserve the boardroom","a boardroom meeting"],"example":"The quarterly review will take place in the boardroom at ten o'clock.","exampleZh":"季度檢討會議將於十點在董事會會議室舉行。","synonyms":[],"level":3,"theme":"會議與簡報"},{"word":"boat","pos":"n.","phonetic":"[bot]","meaning":"船；小船","definition":"a small vehicle used for traveling on water","collocations":["a boat tour","by boat","a fishing boat"],"example":"The travel package includes a relaxing boat tour around the harbor.","exampleZh":"這個旅遊行程包含一趟悠閒的環港遊船之旅。","synonyms":["vessel","ship"],"level":1,"theme":"旅遊與交通"},{"word":"bold","pos":"adj.","phonetic":"[bold]","meaning":"粗體的；大膽的；醒目的","definition":"printed in thick, dark letters; brave and confident","collocations":["in bold type","a bold move","a bold decision"],"example":"Important deadlines are printed in bold type at the top of the schedule.","exampleZh":"重要期限以粗體字印在時程表的最上方。","synonyms":["daring","brave"],"level":3,"theme":"辦公室與行政"},{"word":"bond","pos":"n./v.","phonetic":"[bɑnd]","meaning":"債券；聯繫；黏合","definition":"an official document from a government or company promising to pay back borrowed money with interest","collocations":["government bonds","invest in bonds","a corporate bond"],"example":"Many investors buy government bonds because they are considered relatively safe.","exampleZh":"許多投資人購買公債，因為公債被認為相對安全。","synonyms":["tie","connection"],"level":4,"theme":"財務與會計"},{"word":"bonus","pos":"n.","phonetic":"[ˈbonəs]","meaning":"獎金；紅利；額外的好處","definition":"an extra amount of money added to someone's pay, especially as a reward for good work","collocations":["a year-end bonus","a performance bonus","a signing bonus"],"example":"All employees will receive a year-end bonus based on company performance.","exampleZh":"全體員工將依公司營運表現領取年終獎金。","synonyms":["reward","premium"],"level":2,"theme":"人事與職涯"},{"word":"book","pos":"n./v.","phonetic":"[bʊk]","meaning":"預訂；書；帳簿","definition":"to arrange to have or use something, such as a room or a ticket, at a future time","collocations":["book a flight","book a room","fully booked"],"example":"I would like to book a double room for two nights next week.","exampleZh":"我想預訂下週兩個晚上的雙人房。","synonyms":["reserve"],"level":1,"theme":"旅遊與交通"},{"word":"bookcase","pos":"n.","phonetic":"[ˈbʊkˌkes]","meaning":"書櫃","definition":"a piece of furniture with shelves for holding books","collocations":["a wooden bookcase","a built-in bookcase","assemble a bookcase"],"example":"The new bookcase in the manager's office holds all the reference manuals.","exampleZh":"經理辦公室新添的書櫃收放著所有的參考手冊。","synonyms":["bookshelf"],"level":2,"theme":"辦公室與行政"},{"word":"booking","pos":"n.","phonetic":"[ˈbʊkɪŋ]","meaning":"預訂；預約","definition":"an arrangement to have a room, ticket, or seat kept for you at a future time","collocations":["a booking confirmation","make a booking","cancel a booking"],"example":"You will receive a booking confirmation by email within ten minutes.","exampleZh":"您將在十分鐘內收到電子郵件的訂位確認信。","synonyms":["reservation"],"level":2,"theme":"旅遊與交通"},{"word":"bookkeeping","pos":"n.","phonetic":"[ˈbʊkˌkipɪŋ]","meaning":"簿記；記帳","definition":"the job or activity of keeping an accurate record of a company's financial accounts","collocations":["bookkeeping services","handle the bookkeeping","double-entry bookkeeping"],"example":"The firm outsources its bookkeeping to a local accounting company.","exampleZh":"該公司將記帳工作外包給當地的會計事務所。","synonyms":["accounting"],"level":5,"theme":"財務與會計"},{"word":"booklet","pos":"n.","phonetic":"[ˈbʊklɪt]","meaning":"小冊子","definition":"a small, thin book with paper covers that gives information about something","collocations":["an instruction booklet","an information booklet","a free booklet"],"example":"An instruction booklet is included in the box with the appliance.","exampleZh":"包裝盒內附有這台家電的使用說明手冊。","synonyms":["brochure","pamphlet"],"level":3,"theme":"行銷與銷售"},{"word":"bookshelf","pos":"n.","phonetic":"[ˈbʊkˌʃɛlf]","meaning":"書架","definition":"a shelf or a set of shelves for holding books","collocations":["on the bookshelf","the top bookshelf","install a bookshelf"],"example":"Please return the catalogs to the bookshelf when you are finished.","exampleZh":"使用完畢後，請將型錄放回書架。","synonyms":["bookcase"],"level":2,"theme":"日常與一般"},{"word":"bookstore","pos":"n.","phonetic":"[ˈbʊkˌstor]","meaning":"書店","definition":"a shop that sells books","collocations":["an online bookstore","a local bookstore","a campus bookstore"],"example":"The bookstore near the station is having a clearance sale this weekend.","exampleZh":"車站附近的那家書店本週末舉辦清倉特賣。","synonyms":["bookshop"],"level":1,"theme":"購物與消費"},{"word":"boom","pos":"n./v.","phonetic":"[bum]","meaning":"（經濟）繁榮；激增；迅速發展","definition":"a sudden increase in trade and economic activity, or a period of rapid growth","collocations":["an economic boom","a boom in tourism","a housing boom"],"example":"The region has experienced a boom in tourism over the past five years.","exampleZh":"過去五年來，該地區的觀光業蓬勃發展。","synonyms":["surge","upswing"],"level":4,"theme":"企業經營"},{"word":"boost","pos":"v./n.","phonetic":"[bust]","meaning":"提升；促進；增加","definition":"to increase or improve something and make it more successful","collocations":["boost sales","boost morale","give a boost to"],"example":"The new advertising campaign helped boost sales by twenty percent.","exampleZh":"新的廣告活動幫助銷售額成長了兩成。","synonyms":["increase","raise","enhance"],"level":3,"theme":"行銷與銷售"},{"word":"booth","pos":"n.","phonetic":"[buθ]","meaning":"攤位；展位；小隔間","definition":"a small enclosed space or stall, especially at a trade fair or market","collocations":["a trade show booth","an exhibition booth","a ticket booth"],"example":"Visit our booth at the trade show to see a live product demonstration.","exampleZh":"歡迎到我們的展覽攤位參觀產品現場示範。","synonyms":["stall","stand"],"level":3,"theme":"媒體與活動"},{"word":"border","pos":"n./v.","phonetic":"[ˈbɔrdɚ]","meaning":"邊界；國界；與…接壤","definition":"the official line that separates two countries or regions","collocations":["cross the border","border control","a border town"],"example":"Travelers must show their passports when crossing the border.","exampleZh":"旅客過境時必須出示護照。","synonyms":["boundary","frontier"],"level":2,"theme":"旅遊與交通"},{"word":"borrow","pos":"v.","phonetic":"[ˈbɑro]","meaning":"借入；借用","definition":"to take and use something that belongs to someone else and return it later","collocations":["borrow money from","borrow equipment","borrow a book"],"example":"May I borrow your laptop charger for the afternoon meeting?","exampleZh":"我可以跟你借筆電充電器，下午開會時使用嗎？","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"boss","pos":"n.","phonetic":"[bɔs]","meaning":"老闆；上司；主管","definition":"the person who is in charge of employees at a workplace","collocations":["report to the boss","ask the boss for approval","a new boss"],"example":"My boss approved my request for two weeks of vacation.","exampleZh":"我的主管批准了我兩週的休假申請。","synonyms":["supervisor","manager","employer"],"level":1,"theme":"人事與職涯"},{"word":"both","pos":"det./pron.","phonetic":"[boθ]","meaning":"兩者（都）；雙方","definition":"used to refer to two people or things together","collocations":["both parties","both sides","both of them"],"example":"Both candidates have strong qualifications for the marketing position.","exampleZh":"兩位應徵者都具備勝任行銷職位的堅強資歷。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"bottle","pos":"n./v.","phonetic":"[ˈbɑtl̩]","meaning":"瓶子；一瓶（的量）；裝瓶","definition":"a container with a narrow neck, used for holding liquids","collocations":["a bottle of water","a plastic bottle","recycle bottles"],"example":"Each conference attendee received a bottle of water at registration.","exampleZh":"每位與會者在報到時都領到一瓶水。","synonyms":["container"],"level":1,"theme":"日常與一般"},{"word":"bottled","pos":"adj.","phonetic":"[ˈbɑtld]","meaning":"瓶裝的","definition":"sold or stored in bottles","collocations":["bottled water","bottled juice","bottled drinks"],"example":"Bottled water is provided free of charge in every guest room.","exampleZh":"每間客房皆免費提供瓶裝水。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"bottom","pos":"n./adj.","phonetic":"[ˈbɑtəm]","meaning":"底部；最下面的；末端","definition":"the lowest part or point of something","collocations":["at the bottom of the page","the bottom line","the bottom shelf"],"example":"Please sign your name at the bottom of the contract.","exampleZh":"請在合約的最下方簽名。","synonyms":["base"],"level":1,"theme":"日常與一般"},{"word":"boulevard","pos":"n.","phonetic":"[ˈbʊləˌvɑrd]","meaning":"林蔭大道；大道","definition":"a wide city street, often lined with trees","collocations":["along the boulevard","the main boulevard","a tree-lined boulevard"],"example":"The new shopping mall is located on the main boulevard near the park.","exampleZh":"新開幕的購物中心位於公園附近的主要大道上。","synonyms":["avenue"],"level":4,"theme":"旅遊與交通"},{"word":"bound","pos":"adj./v./n.","phonetic":"[baʊnd]","meaning":"開往…的；必定的；受約束的；跳躍","definition":"traveling toward a particular place; certain or very likely to happen","collocations":["bound for","bound to succeed","legally bound"],"example":"The express train bound for the airport departs from platform two.","exampleZh":"開往機場的直達列車由第二月台發車。","synonyms":[],"level":4,"theme":"旅遊與交通"},{"word":"boundary","pos":"n.","phonetic":"[ˈbaʊndrɪ]","meaning":"邊界；界線；範圍","definition":"a real or imaginary line that marks the limits of an area","collocations":["a property boundary","a boundary line","set clear boundaries"],"example":"The fence clearly marks the boundary between the two properties.","exampleZh":"這道圍籬清楚標示出兩塊土地的分界線。","synonyms":["border","limit"],"level":3,"theme":"房產與設施"},{"word":"bouquet","pos":"n.","phonetic":"[buˈke]","meaning":"花束","definition":"an arranged bunch of flowers, often given as a gift","collocations":["a bouquet of roses","send a bouquet","present a bouquet"],"example":"The retiring manager was presented with a bouquet of flowers at the farewell party.","exampleZh":"歡送會上，即將退休的經理獲贈一束鮮花。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"box","pos":"n./v.","phonetic":"[bɑks]","meaning":"箱子；盒子；把…裝箱","definition":"a container with stiff sides used for storing or transporting things","collocations":["cardboard box","a box of supplies","pack items into boxes"],"example":"Please pack the brochures into boxes before the trade show tomorrow.","exampleZh":"請在明天商展前把宣傳手冊裝進箱子裡。","synonyms":["container","carton","case"],"level":1,"theme":"生產與物流"},{"word":"branch","pos":"n.","phonetic":"[bræntʃ]","meaning":"分公司；分行；分店；樹枝","definition":"a local office or shop that is part of a larger company or organization","collocations":["open a new branch","branch office","branch manager","overseas branch"],"example":"The bank plans to open three new branches in southern Taiwan next year.","exampleZh":"這家銀行計劃明年在南台灣開設三家新分行。","synonyms":["office","division","outlet"],"level":2,"theme":"企業經營"},{"word":"brand","pos":"n./v.","phonetic":"[brænd]","meaning":"品牌；商標；把…塑造為（某形象）","definition":"a type of product made by a particular company under a particular name","collocations":["brand image","leading brand","brand loyalty","build a brand"],"example":"Our marketing team is working hard to strengthen the company's brand image overseas.","exampleZh":"我們的行銷團隊正努力強化公司在海外的品牌形象。","synonyms":["trademark","label","make"],"level":2,"theme":"行銷與銷售"},{"word":"brand-new","pos":"adj.","phonetic":"[ˈbrændˈnju]","meaning":"全新的；嶄新的","definition":"completely new and never used before","collocations":["a brand-new model","brand-new equipment","a brand-new facility"],"example":"The office just installed a brand-new copier that prints twice as fast.","exampleZh":"辦公室剛安裝了一台全新的影印機，列印速度快了一倍。","synonyms":["new","unused"],"level":2,"theme":"購物與消費"},{"word":"break","pos":"n./v.","phonetic":"[brek]","meaning":"休息；中斷；打破；違反","definition":"a short period of rest when you stop working","collocations":["take a break","lunch break","coffee break","break a contract"],"example":"Let's take a short break before we review the sales figures again.","exampleZh":"我們先休息一下，再繼續檢視銷售數據吧。","synonyms":["rest","pause","recess"],"level":1,"theme":"辦公室與行政"},{"word":"breakdown","pos":"n.","phonetic":"[ˈbrekˌdaʊn]","meaning":"故障；（費用等的）明細；崩潰；破裂","definition":"an occasion when a machine or vehicle stops working","collocations":["equipment breakdown","a breakdown of costs","communication breakdown"],"example":"A sudden breakdown of the assembly line delayed shipments for two days.","exampleZh":"組裝線突然故障，導致出貨延誤了兩天。","synonyms":["failure","malfunction"],"level":3,"theme":"生產與物流"},{"word":"breakfast","pos":"n.","phonetic":"[ˈbrɛkfəst]","meaning":"早餐","definition":"the first meal of the day, eaten in the morning","collocations":["complimentary breakfast","breakfast buffet","bed and breakfast"],"example":"The hotel offers a complimentary breakfast for all guests from six to ten.","exampleZh":"這家飯店提供所有房客免費早餐，供應時間為六點到十點。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"breakthrough","pos":"n.","phonetic":"[ˈbrekˌθru]","meaning":"突破；重大進展","definition":"an important discovery or development that helps solve a problem","collocations":["a major breakthrough","technological breakthrough","achieve a breakthrough"],"example":"Researchers announced a major breakthrough in battery technology at the conference yesterday.","exampleZh":"研究人員昨天在會議上宣布電池技術的重大突破。","synonyms":["advance","discovery","progress"],"level":4,"theme":"科技與通訊"},{"word":"brick","pos":"n.","phonetic":"[brɪk]","meaning":"磚塊；磚","definition":"a rectangular block of baked clay used for building walls and houses","collocations":["brick wall","red brick building","brick and mortar"],"example":"The renovated warehouse features exposed brick walls and large modern windows.","exampleZh":"整修後的倉庫以裸露的磚牆和大片現代化窗戶為特色。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"bridge","pos":"n./v.","phonetic":"[brɪdʒ]","meaning":"橋；橋樑；彌合（差距）","definition":"a structure built over a river or road so people or vehicles can cross","collocations":["cross the bridge","build a bridge","bridge the gap"],"example":"The bridge will be closed for repairs, so please take an alternate route.","exampleZh":"這座橋將封閉維修，請改走替代道路。","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"brief","pos":"adj./v./n.","phonetic":"[brif]","meaning":"簡短的；短暫的；向…簡報；摘要","definition":"lasting only a short time or using few words","collocations":["a brief meeting","a brief summary","brief the staff"],"example":"The manager gave a brief overview of the project before the discussion began.","exampleZh":"經理在討論開始前，先簡短說明了這項專案的概況。","synonyms":["short","concise"],"level":3,"theme":"會議與簡報"},{"word":"briefcase","pos":"n.","phonetic":"[ˈbrifˌkes]","meaning":"公事包","definition":"a flat case used for carrying documents and papers to work","collocations":["carry a briefcase","leather briefcase","leave a briefcase behind"],"example":"A passenger left his briefcase on the train and reported it immediately.","exampleZh":"一位乘客把公事包遺忘在火車上，並立即通報。","synonyms":["bag","case"],"level":2,"theme":"辦公室與行政"},{"word":"briefing","pos":"n.","phonetic":"[ˈbrifɪŋ]","meaning":"簡報；情況說明會","definition":"a meeting where people are given information or instructions","collocations":["attend a briefing","press briefing","safety briefing","morning briefing"],"example":"All new employees must attend a safety briefing before entering the factory floor.","exampleZh":"所有新進員工進入工廠作業區前，都必須參加安全簡報。","synonyms":["meeting","orientation"],"level":3,"theme":"會議與簡報"},{"word":"briefly","pos":"adv.","phonetic":"[ˈbriflɪ]","meaning":"簡短地；短暫地","definition":"for a short time, or using only a few words","collocations":["speak briefly","briefly explain","pause briefly"],"example":"The CEO spoke briefly about next year's goals before answering questions.","exampleZh":"執行長先簡短談了明年的目標，接著回答提問。","synonyms":["shortly","concisely"],"level":3,"theme":"會議與簡報"},{"word":"bright","pos":"adj.","phonetic":"[braɪt]","meaning":"明亮的；鮮豔的；聰明的；有前途的","definition":"full of light, or strong and easy to see in color","collocations":["bright lighting","bright colors","a bright future"],"example":"The new office space is bright and spacious, with windows on three sides.","exampleZh":"新辦公空間明亮又寬敞，三面都有窗戶。","synonyms":["brilliant","vivid","radiant"],"level":1,"theme":"日常與一般"},{"word":"bring","pos":"v.","phonetic":"[brɪŋ]","meaning":"帶來；攜帶；造成","definition":"to take something or someone with you to a place","collocations":["bring a copy","bring about change","bring up an issue"],"example":"Please bring two copies of your résumé to the interview on Friday.","exampleZh":"請在星期五面試時攜帶兩份履歷。","synonyms":["carry","take"],"level":1,"theme":"日常與一般"},{"word":"broad","pos":"adj.","phonetic":"[brɔd]","meaning":"廣泛的；寬闊的","definition":"including a wide range of things; wide","collocations":["a broad range of","broad experience","broad appeal"],"example":"The store carries a broad range of office supplies at competitive prices.","exampleZh":"這家店販售種類廣泛的辦公用品，價格也很有競爭力。","synonyms":["wide","extensive","comprehensive"],"level":2,"theme":"日常與一般"},{"word":"broadcast","pos":"v./n.","phonetic":"[ˈbrɔdˌkæst]","meaning":"播出；廣播；播送；（廣播或電視）節目","definition":"to send out a program on television, radio, or the internet","collocations":["broadcast live","a live broadcast","broadcast the news"],"example":"The award ceremony will be broadcast live on the company's official website.","exampleZh":"頒獎典禮將在公司官方網站上現場直播。","synonyms":["air","transmit"],"level":3,"theme":"媒體與活動"},{"word":"broaden","pos":"v.","phonetic":"[ˈbrɔdn̩]","meaning":"拓展；擴大；使變寬","definition":"to increase the range of something; to make something wider","collocations":["broaden one's horizons","broaden the customer base","broaden your skills"],"example":"The firm hopes to broaden its customer base by entering overseas markets.","exampleZh":"這家公司希望透過進軍海外市場來擴大客群。","synonyms":["expand","widen","extend"],"level":4,"theme":"企業經營"},{"word":"brochure","pos":"n.","phonetic":"[broˈʃʊr]","meaning":"宣傳手冊；小冊子；簡介","definition":"a small, thin book with pictures that gives information about a product or service","collocations":["travel brochure","product brochure","request a brochure"],"example":"You can find detailed pricing information in the brochure at the front desk.","exampleZh":"您可以在櫃檯的宣傳手冊中找到詳細的價格資訊。","synonyms":["pamphlet","booklet","leaflet"],"level":2,"theme":"行銷與銷售"},{"word":"broken","pos":"adj.","phonetic":"[ˈbrokən]","meaning":"壞掉的；故障的；破碎的","definition":"damaged and no longer working or in one piece","collocations":["a broken printer","broken glass","a broken promise"],"example":"The elevator has been broken since Monday, so please use the stairs.","exampleZh":"電梯從星期一就故障了，請改走樓梯。","synonyms":["damaged","faulty"],"level":1,"theme":"日常與一般"},{"word":"broker","pos":"n./v.","phonetic":"[ˈbrokɚ]","meaning":"經紀人；仲介；居中促成（協議）","definition":"a person who buys and sells things such as shares or property for others","collocations":["real estate broker","insurance broker","stock broker"],"example":"The real estate broker showed us several office spaces in the downtown area.","exampleZh":"房仲帶我們看了市中心的幾個辦公空間。","synonyms":["agent","dealer","intermediary"],"level":4,"theme":"財務與會計"},{"word":"browse","pos":"v.","phonetic":"[braʊz]","meaning":"瀏覽；隨意翻閱；逛（商店）","definition":"to look at goods or information casually without a particular purpose","collocations":["browse the website","browse through a catalog","browse the shelves"],"example":"Customers can browse our full catalog online before visiting the showroom.","exampleZh":"顧客可以先在線上瀏覽完整型錄，再前往展示中心參觀。","synonyms":["skim","scan"],"level":3,"theme":"購物與消費"},{"word":"browser","pos":"n.","phonetic":"[ˈbraʊzɚ]","meaning":"（網頁）瀏覽器","definition":"a computer program used for finding and looking at pages on the internet","collocations":["web browser","update your browser","open a browser window"],"example":"Please update your browser to the latest version before accessing the system.","exampleZh":"存取系統前，請先將瀏覽器更新到最新版本。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"budget","pos":"n./v./adj.","phonetic":"[ˈbʌdʒɪt]","meaning":"預算；編列預算；廉價的","definition":"the amount of money available for spending in a particular period or on a particular thing","collocations":["annual budget","within budget","budget cuts","over budget"],"example":"The project was completed on time and well within the approved budget.","exampleZh":"這項專案如期完成，而且遠低於核定的預算。","synonyms":["funds","allocation"],"level":2,"theme":"財務與會計"},{"word":"buffet","pos":"n.","phonetic":"[bʌˈfe]","meaning":"自助餐；歐式自助餐","definition":"a meal where people serve themselves from a variety of dishes","collocations":["buffet lunch","breakfast buffet","all-you-can-eat buffet"],"example":"The conference fee includes a buffet lunch in the hotel's main dining room.","exampleZh":"會議費用包含飯店主餐廳的自助式午餐。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"build","pos":"v./n.","phonetic":"[bɪld]","meaning":"建造；建立；培養","definition":"to make something by putting materials or parts together","collocations":["build a factory","build relationships","build trust"],"example":"The company plans to build a new distribution center near the airport.","exampleZh":"該公司計劃在機場附近興建新的配送中心。","synonyms":["construct","establish","develop"],"level":1,"theme":"房產與設施"},{"word":"builder","pos":"n.","phonetic":"[ˈbɪldɚ]","meaning":"營造商；建築業者；建造者","definition":"a person or company that constructs buildings","collocations":["home builder","hire a builder","licensed builder"],"example":"The builder promised to finish the renovation before the end of March.","exampleZh":"營造商承諾在三月底前完成整修工程。","synonyms":["contractor","constructor"],"level":2,"theme":"房產與設施"},{"word":"building","pos":"n.","phonetic":"[ˈbɪldɪŋ]","meaning":"建築物；大樓","definition":"a structure with walls and a roof, such as a house or office block","collocations":["office building","building permit","building maintenance"],"example":"The marketing department will move to the new building next month.","exampleZh":"行銷部門下個月將搬到新大樓。","synonyms":["structure","property"],"level":1,"theme":"房產與設施"},{"word":"built-in","pos":"adj.","phonetic":"[ˈbɪltˈɪn]","meaning":"內建的；嵌入式的","definition":"included as a permanent part of something","collocations":["built-in camera","built-in storage","built-in features"],"example":"The laptop comes with a built-in camera and high-quality speakers.","exampleZh":"這台筆電配備內建攝影機和高品質喇叭。","synonyms":["integrated","internal"],"level":3,"theme":"科技與通訊"},{"word":"bulb","pos":"n.","phonetic":"[bʌlb]","meaning":"燈泡；球莖","definition":"the glass part of an electric lamp that produces light","collocations":["light bulb","replace a bulb","energy-saving bulb"],"example":"Maintenance staff replaced all the light bulbs in the conference room yesterday.","exampleZh":"維修人員昨天更換了會議室裡所有的燈泡。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"bulk","pos":"n./adj.","phonetic":"[bʌlk]","meaning":"大量；大宗；主要部分","definition":"a large amount or quantity of something","collocations":["in bulk","bulk order","bulk discount"],"example":"We offer a ten percent discount to customers who order in bulk.","exampleZh":"我們為大量訂購的客戶提供九折優惠。","synonyms":["quantity","volume","mass"],"level":4,"theme":"購物與消費"},{"word":"bulletin","pos":"n.","phonetic":"[ˈbʊlətɪn]","meaning":"公告；佈告；快報","definition":"a short official notice or news report that gives information to people","collocations":["bulletin board","news bulletin","post a bulletin"],"example":"The schedule change was posted on the bulletin board in the break room.","exampleZh":"班表異動已公告在休息室的佈告欄上。","synonyms":["notice","announcement"],"level":3,"theme":"辦公室與行政"},{"word":"bundle","pos":"n./v.","phonetic":"[ˈbʌndl̩]","meaning":"組合包；一捆；一束；捆綁搭售","definition":"a group of things sold or tied together as a unit","collocations":["a bundle of documents","software bundle","bundle deal"],"example":"Customers who buy the phone and tablet bundle save nearly a hundred dollars.","exampleZh":"購買手機平板組合包的顧客可省下將近一百美元。","synonyms":["package","set","batch"],"level":3,"theme":"購物與消費"},{"word":"burden","pos":"n./v.","phonetic":"[ˈbɝdn̩]","meaning":"負擔；重擔；使承受負擔","definition":"something difficult or worrying that you are responsible for","collocations":["financial burden","ease the burden","tax burden"],"example":"The new software greatly reduces the administrative burden on our staff.","exampleZh":"新軟體大幅減輕了員工的行政負擔。","synonyms":["load","responsibility","strain"],"level":4,"theme":"企業經營"},{"word":"bureau","pos":"n.","phonetic":"[ˈbjʊro]","meaning":"局；處；辦事處；事務所","definition":"a government department or an office that provides a particular service","collocations":["tourism bureau","credit bureau","news bureau"],"example":"Visitors can pick up free maps at the local tourism bureau downtown.","exampleZh":"遊客可以在市中心的觀光局索取免費地圖。","synonyms":["agency","office","department"],"level":4,"theme":"辦公室與行政"},{"word":"burn","pos":"v./n.","phonetic":"[bɝn]","meaning":"燃燒；燒毀；燙傷；灼傷","definition":"to be on fire, or to damage something with fire or heat","collocations":["burn down","burn calories","minor burns"],"example":"Do not leave the stove unattended, or the food may burn quickly.","exampleZh":"爐子上煮東西時別走開，不然食物很快就會燒焦。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"bus","pos":"n.","phonetic":"[bʌs]","meaning":"公車；巴士","definition":"a large road vehicle that carries many passengers along a fixed route","collocations":["take the bus","shuttle bus","bus stop","miss the bus"],"example":"A free shuttle bus runs between the airport and the hotel every thirty minutes.","exampleZh":"免費接駁巴士每三十分鐘往返機場與飯店一趟。","synonyms":["coach","shuttle"],"level":1,"theme":"旅遊與交通"},{"word":"business","pos":"n.","phonetic":"[ˈbɪznɪs]","meaning":"商業；生意；公司；業務；事務","definition":"the activity of buying and selling goods or services; a company","collocations":["do business with","business trip","run a business","business hours"],"example":"She started her own business after working in the industry for ten years.","exampleZh":"她在業界工作十年後，自行創業。","synonyms":["company","firm","trade"],"level":1,"theme":"企業經營"},{"word":"busy","pos":"adj.","phonetic":"[ˈbɪzɪ]","meaning":"忙碌的；繁忙的；（電話）佔線的","definition":"having a lot of things to do; full of activity","collocations":["busy schedule","busy season","the line is busy"],"example":"December is our busiest season, so extra staff will be hired soon.","exampleZh":"十二月是我們最忙的旺季，所以很快就會增聘人手。","synonyms":["occupied","hectic"],"level":1,"theme":"日常與一般"},{"word":"button","pos":"n./v.","phonetic":"[ˈbʌtn̩]","meaning":"按鈕；鈕扣；扣上鈕扣","definition":"a small object that you press to operate a machine or device","collocations":["press the button","click the button","power button"],"example":"Press the green button to start the machine and red to stop it.","exampleZh":"按綠色按鈕啟動機器，按紅色按鈕停止。","synonyms":["switch","key"],"level":1,"theme":"日常與一般"},{"word":"buy","pos":"v./n.","phonetic":"[baɪ]","meaning":"購買；買；划算的東西","definition":"to get something by paying money for it","collocations":["buy in bulk","buy tickets online","a good buy"],"example":"Many customers prefer to buy tickets online instead of waiting in line.","exampleZh":"許多顧客寧願在線上購票，也不想排隊等候。","synonyms":["purchase","acquire"],"level":1,"theme":"購物與消費"},{"word":"buyer","pos":"n.","phonetic":"[ˈbaɪɚ]","meaning":"買家；買主；採購人員","definition":"a person who buys something, or whose job is to choose goods for a company to sell","collocations":["potential buyer","first-time buyer","attract buyers"],"example":"Several potential buyers have already made offers on the downtown property.","exampleZh":"已有多位潛在買家對這處市中心的房產出價。","synonyms":["purchaser","customer","client"],"level":2,"theme":"購物與消費"},{"word":"bylaw","pos":"n.","phonetic":"[ˈbaɪˌlɔ]","meaning":"（公司、組織的）章程；內部規章；地方法規","definition":"an official rule made by an organization or a local government","collocations":["company bylaws","amend the bylaws","comply with bylaws"],"example":"According to the company bylaws, board members must be elected every two years.","exampleZh":"根據公司章程，董事會成員每兩年必須改選一次。","synonyms":["regulation","rule","ordinance"],"level":6,"theme":"合約與法律"},{"word":"bypass","pos":"v./n.","phonetic":"[ˈbaɪˌpæs]","meaning":"繞過；避開；繞道；外環道","definition":"to avoid a place or a step by going around it","collocations":["bypass the city center","bypass the approval process","take the bypass"],"example":"Drivers can bypass the construction zone by taking Highway 12 instead.","exampleZh":"駕駛人可改走12號公路，繞過施工路段。","synonyms":["avoid","skip","circumvent"],"level":5,"theme":"旅遊與交通"},{"word":"cabinet","pos":"n.","phonetic":"[ˈkæbənɪt]","meaning":"櫥櫃；文件櫃；內閣","definition":"a piece of furniture with shelves or drawers used for storing things","collocations":["filing cabinet","kitchen cabinet","display cabinet"],"example":"All signed contracts are stored in the filing cabinet next to the printer.","exampleZh":"所有簽署好的合約都存放在印表機旁的文件櫃裡。","synonyms":["cupboard","locker"],"level":2,"theme":"辦公室與行政"},{"word":"cable","pos":"n.","phonetic":"[ˈkebl̩]","meaning":"纜線；電纜；有線電視","definition":"a thick wire used for carrying electricity or signals","collocations":["power cable","cable TV","connect the cable"],"example":"The technician will come tomorrow to install the new network cables.","exampleZh":"技術人員明天會來安裝新的網路線。","synonyms":["wire","cord"],"level":2,"theme":"科技與通訊"},{"word":"cafeteria","pos":"n.","phonetic":"[ˌkæfəˈtɪrɪə]","meaning":"自助餐廳；員工餐廳；學生餐廳","definition":"a restaurant in a workplace or school where people serve themselves","collocations":["company cafeteria","cafeteria staff","eat in the cafeteria"],"example":"The company cafeteria serves lunch from eleven thirty to one thirty daily.","exampleZh":"公司員工餐廳每天十一點半到一點半供應午餐。","synonyms":["canteen"],"level":2,"theme":"餐飲與住宿"},{"word":"calculate","pos":"v.","phonetic":"[ˈkælkjəˌlet]","meaning":"計算；估算；預測","definition":"to find an amount or number using mathematics","collocations":["calculate the cost","calculate the total","calculate interest"],"example":"Please calculate the total shipping cost before sending the invoice to the client.","exampleZh":"請先算出運費總額，再將發票寄給客戶。","synonyms":["compute","estimate"],"level":2,"theme":"財務與會計"},{"word":"calculation","pos":"n.","phonetic":"[ˌkælkjəˈleʃən]","meaning":"計算；計算結果；估算","definition":"the process of using numbers to find an amount, or the result of this","collocations":["make a calculation","accurate calculation","according to my calculations"],"example":"According to our calculations, the new plan will cut costs by fifteen percent.","exampleZh":"根據我們的計算，新方案可以降低百分之十五的成本。","synonyms":["computation","estimation"],"level":3,"theme":"財務與會計"},{"word":"calculator","pos":"n.","phonetic":"[ˈkælkjəˌletɚ]","meaning":"計算機","definition":"a small electronic device used for doing mathematical calculations","collocations":["use a calculator","pocket calculator","online calculator"],"example":"You may use a calculator to check the figures in the expense report.","exampleZh":"你可以用計算機核對費用報告裡的數字。","synonyms":[],"level":2,"theme":"辦公室與行政"},{"word":"calendar","pos":"n.","phonetic":"[ˈkæləndɚ]","meaning":"行事曆；日曆；月曆","definition":"a chart or system showing days, weeks, and months, often used to plan events","collocations":["mark your calendar","calendar year","check the calendar"],"example":"Please mark your calendar for the annual company banquet on December tenth.","exampleZh":"請在行事曆上記下十二月十日的公司年度晚宴。","synonyms":["schedule","planner"],"level":1,"theme":"辦公室與行政"},{"word":"call","pos":"v./n.","phonetic":"[kɔl]","meaning":"打電話；通話；稱呼；召開（會議）","definition":"to telephone someone, or a conversation on the telephone","collocations":["make a call","return a call","conference call","call a meeting"],"example":"Mr. Chen is in a meeting now, but he will return your call shortly.","exampleZh":"陳先生正在開會，不過他稍後會回電給您。","synonyms":["phone","dial","contact"],"level":1,"theme":"科技與通訊"},{"word":"camera","pos":"n.","phonetic":"[ˈkæmərə]","meaning":"相機；攝影機；鏡頭","definition":"a device used for taking photographs or recording videos","collocations":["security camera","digital camera","on camera"],"example":"Security cameras have been installed at every entrance to the warehouse.","exampleZh":"倉庫的每個入口都已裝設監視攝影機。","synonyms":[],"level":1,"theme":"科技與通訊"},{"word":"campaign","pos":"n./v.","phonetic":"[kæmˈpen]","meaning":"（行銷、宣傳）活動；競選活動；發起運動","definition":"a planned series of activities intended to achieve a particular goal, such as selling a product","collocations":["advertising campaign","launch a campaign","marketing campaign"],"example":"The new advertising campaign helped increase sales by twenty percent last quarter.","exampleZh":"新的廣告活動使上一季的銷售額成長了百分之二十。","synonyms":["drive","promotion","initiative"],"level":3,"theme":"行銷與銷售"},{"word":"campus","pos":"n.","phonetic":"[ˈkæmpəs]","meaning":"校園；（企業）園區；校區","definition":"the land and buildings of a university, college, or large company","collocations":["on campus","corporate campus","campus tour"],"example":"The tech company's new campus includes a gym, cafeteria, and childcare center.","exampleZh":"這家科技公司的新園區設有健身房、餐廳和托育中心。","synonyms":["grounds","site"],"level":2,"theme":"房產與設施"},{"word":"cancel","pos":"v.","phonetic":"[ˈkænsl̩]","meaning":"取消；廢除；作廢","definition":"to decide that a planned event or arrangement will not happen","collocations":["cancel a reservation","cancel an order","cancel a flight","cancel a meeting"],"example":"The afternoon flight was canceled due to bad weather, so we rebooked for tomorrow.","exampleZh":"下午的班機因天候不佳被取消，所以我們改訂明天的航班。","synonyms":["call off","annul"],"level":2,"theme":"旅遊與交通"},{"word":"cancellation","pos":"n.","phonetic":"[ˌkænsəˈleʃən]","meaning":"取消；廢除","definition":"a decision that a planned event or arrangement will not happen","collocations":["cancellation fee","cancellation policy","flight cancellation"],"example":"Guests must notify the hotel one day in advance to avoid a cancellation fee.","exampleZh":"房客須提前一天通知飯店，以免被收取取消費用。","synonyms":["annulment","termination"],"level":3,"theme":"旅遊與交通"},{"word":"candidate","pos":"n.","phonetic":"[ˈkændədet]","meaning":"應徵者；候選人；人選","definition":"a person who applies for a job or is considered for a position","collocations":["qualified candidate","interview candidates","successful candidate","candidate for the position"],"example":"We interviewed five candidates for the marketing manager position this week.","exampleZh":"我們這星期為行銷經理一職面試了五位應徵者。","synonyms":["applicant","nominee","contender"],"level":3,"theme":"人事與職涯"},{"word":"capability","pos":"n.","phonetic":"[ˌkepəˈbɪlətɪ]","meaning":"能力；性能；才能","definition":"the ability or power to do something","collocations":["production capability","technical capabilities","beyond our capability"],"example":"The new factory will double our production capability within two years.","exampleZh":"新工廠將在兩年內使我們的產能倍增。","synonyms":["ability","capacity","competence"],"level":4,"theme":"企業經營"},{"word":"capable","pos":"adj.","phonetic":"[ˈkepəbḷ]","meaning":"有能力的；能幹的；能夠…的","definition":"having the ability or skill needed to do something well","collocations":["capable of handling","a capable manager","highly capable staff"],"example":"Ms. Lin is capable of managing multiple projects at the same time.","exampleZh":"林小姐有能力同時管理多項專案。","synonyms":["competent","able","skilled"],"level":2,"theme":"人事與職涯"},{"word":"capacity","pos":"n.","phonetic":"[kəˈpæsətɪ]","meaning":"產能；容量；能力；（正式）身分","definition":"the maximum amount that something can hold, contain, or produce","collocations":["production capacity","seating capacity","at full capacity","storage capacity"],"example":"The new factory will double our production capacity by next year.","exampleZh":"新工廠明年將使我們的產能增加一倍。","synonyms":["volume","capability"],"level":3,"theme":"生產與物流"},{"word":"capital","pos":"n./adj.","phonetic":"[ˈkæpətḷ]","meaning":"資本；資金；首都；大寫字母；資本的","definition":"money or property used to start or invest in a business","collocations":["raise capital","capital investment","working capital"],"example":"The startup raised enough capital to expand into overseas markets.","exampleZh":"這家新創公司募得足夠的資金，得以拓展海外市場。","synonyms":["funds","assets"],"level":3,"theme":"財務與會計"},{"word":"card","pos":"n.","phonetic":"[kɑrd]","meaning":"卡片；名片；信用卡；賀卡","definition":"a small piece of stiff paper or plastic used for payment, identification, or greetings","collocations":["business card","credit card","membership card","key card"],"example":"Please present your membership card at the front desk to receive a discount.","exampleZh":"請在櫃檯出示會員卡，即可享有折扣。","synonyms":[],"level":1,"theme":"購物與消費"},{"word":"care","pos":"n./v.","phonetic":"[kɛr]","meaning":"照顧；照料；小心；在乎","definition":"the process of protecting and looking after someone or something","collocations":["customer care","take care of","handle with care","health care"],"example":"Our customer care team will respond to your inquiry within 24 hours.","exampleZh":"我們的客服團隊將在二十四小時內回覆您的詢問。","synonyms":["attention","concern"],"level":1,"theme":"日常與一般"},{"word":"career","pos":"n.","phonetic":"[kəˈrɪr]","meaning":"職涯；職業；事業","definition":"a job or profession that someone does for a long period of their life","collocations":["career development","pursue a career","career opportunities","career path"],"example":"The company offers excellent career development opportunities for new employees.","exampleZh":"這家公司為新進員工提供絕佳的職涯發展機會。","synonyms":["profession","occupation","vocation"],"level":2,"theme":"人事與職涯"},{"word":"careful","pos":"adj.","phonetic":"[ˈkɛrfəl]","meaning":"小心的；仔細的；謹慎的","definition":"giving close attention to what you are doing in order to avoid mistakes or damage","collocations":["careful consideration","careful planning","be careful with"],"example":"After careful consideration, the board approved the merger proposal.","exampleZh":"經過審慎考量後，董事會通過了合併提案。","synonyms":["cautious","attentive","prudent"],"level":1,"theme":"日常與一般"},{"word":"carefully","pos":"adv.","phonetic":"[ˈkɛrfəlɪ]","meaning":"小心地；仔細地；謹慎地","definition":"in a way that shows close attention to detail and avoids mistakes","collocations":["read carefully","listen carefully","carefully review"],"example":"Please read the contract carefully before signing it.","exampleZh":"簽約前請仔細閱讀合約內容。","synonyms":["cautiously","thoroughly"],"level":1,"theme":"日常與一般"},{"word":"cargo","pos":"n.","phonetic":"[ˈkɑrgo]","meaning":"貨物；貨運","definition":"goods carried by a ship, aircraft, or other large vehicle","collocations":["cargo ship","air cargo","unload the cargo"],"example":"The cargo will be shipped from Kaohsiung to Los Angeles next Monday.","exampleZh":"這批貨物將於下週一從高雄運往洛杉磯。","synonyms":["freight","shipment","goods"],"level":3,"theme":"生產與物流"},{"word":"carrier","pos":"n.","phonetic":"[ˈkærɪɚ]","meaning":"運輸公司；航空公司；電信業者；載具","definition":"a company that transports goods or passengers, especially by air","collocations":["air carrier","low-cost carrier","common carrier"],"example":"The carrier is responsible for any damage that occurs during shipping.","exampleZh":"貨物在運送途中若有損壞，由運輸業者負責。","synonyms":["transporter","shipper"],"level":4,"theme":"生產與物流"},{"word":"carry","pos":"v.","phonetic":"[ˈkærɪ]","meaning":"攜帶；搬運；（商店）販售；承擔","definition":"to hold something and take it somewhere; to have goods available for sale","collocations":["carry out","carry luggage","carry a full line of products"],"example":"The store no longer carries that brand of office furniture.","exampleZh":"那家店已經不再販售那個品牌的辦公家具了。","synonyms":["transport","convey"],"level":1,"theme":"購物與消費"},{"word":"carry-on","pos":"n./adj.","phonetic":"[ˈkærɪˌɑn]","meaning":"隨身行李；可隨身攜帶的","definition":"a small bag that a passenger is allowed to take onto an airplane","collocations":["carry-on luggage","carry-on baggage allowance","one carry-on item"],"example":"Each passenger is allowed one carry-on bag and one personal item.","exampleZh":"每位乘客可攜帶一件隨身行李及一件個人物品。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"cart","pos":"n.","phonetic":"[kɑrt]","meaning":"購物車；手推車","definition":"a small vehicle with wheels that you push by hand to carry goods","collocations":["shopping cart","luggage cart","add to cart"],"example":"You can add items to your cart and check out later.","exampleZh":"您可以先把商品加入購物車，稍後再結帳。","synonyms":["trolley","wagon"],"level":2,"theme":"購物與消費"},{"word":"case","pos":"n.","phonetic":"[kes]","meaning":"情況；案例；案件；箱子","definition":"a particular situation or an example of something happening","collocations":["in case of","in this case","case study"],"example":"In case of an emergency, please use the stairs instead of the elevator.","exampleZh":"遇到緊急狀況時，請走樓梯，不要搭電梯。","synonyms":["instance","situation"],"level":1,"theme":"日常與一般"},{"word":"cash","pos":"n./v.","phonetic":"[kæʃ]","meaning":"現金；兌現（支票）","definition":"money in the form of coins or bills rather than checks or cards","collocations":["pay in cash","cash flow","cash a check","cash register"],"example":"Would you like to pay in cash or by credit card?","exampleZh":"請問您要付現還是刷卡？","synonyms":["currency","money"],"level":1,"theme":"購物與消費"},{"word":"cashier","pos":"n.","phonetic":"[kæˈʃɪr]","meaning":"收銀員；出納員","definition":"a person whose job is to receive and pay out money in a store or bank","collocations":["head cashier","pay at the cashier","cashier's counter"],"example":"Please take your items to the cashier at the front of the store.","exampleZh":"請把商品拿到店面前方的收銀台結帳。","synonyms":["teller","clerk"],"level":2,"theme":"購物與消費"},{"word":"casual","pos":"adj.","phonetic":"[ˈkæʒʊəl]","meaning":"休閒的；非正式的；隨意的","definition":"relaxed and informal, not suitable for official or formal occasions","collocations":["casual attire","business casual","casual Friday"],"example":"Employees may wear casual clothing on Fridays throughout the summer.","exampleZh":"整個夏季的每週五，員工都可以穿休閒服裝上班。","synonyms":["informal","relaxed"],"level":2,"theme":"辦公室與行政"},{"word":"catalog","pos":"n./v.","phonetic":"[ˈkætḷɔg]","meaning":"型錄；目錄；將…編入目錄","definition":"a book or online list showing goods for sale or items in a collection","collocations":["product catalog","online catalog","browse the catalog"],"example":"Our latest product catalog will be mailed to all registered customers.","exampleZh":"我們最新的產品型錄將寄送給所有已註冊的客戶。","synonyms":["brochure","directory"],"level":2,"theme":"行銷與銷售"},{"word":"category","pos":"n.","phonetic":"[ˈkætəˌgorɪ]","meaning":"類別；種類；範疇","definition":"a group of people or things that share the same features","collocations":["fall into a category","product category","job category"],"example":"The products on our website are organized into five main categories.","exampleZh":"我們網站上的商品分成五大類別。","synonyms":["class","type","group"],"level":2,"theme":"日常與一般"},{"word":"cater","pos":"v.","phonetic":"[ˈketɚ]","meaning":"承辦（活動）餐飲；提供外燴；迎合（需求）","definition":"to provide food and drinks for an event; to satisfy particular needs","collocations":["cater an event","cater to customers' needs","cater for a banquet"],"example":"A local restaurant will cater the company's year-end banquet next month.","exampleZh":"下個月公司尾牙的餐點將由一家當地餐廳承辦。","synonyms":["provide","serve"],"level":4,"theme":"餐飲與住宿"},{"word":"catering","pos":"n.","phonetic":"[ˈketərɪŋ]","meaning":"外燴服務；餐飲承辦","definition":"the business of providing food and drinks for meetings and events","collocations":["catering service","catering company","catering staff"],"example":"We hired a catering service for the product launch reception.","exampleZh":"我們為產品發表會的酒會聘請了外燴服務。","synonyms":[],"level":4,"theme":"餐飲與住宿"},{"word":"cause","pos":"n./v.","phonetic":"[kɔz]","meaning":"導致；造成；原因；（慈善）理念","definition":"to make something happen, especially something bad","collocations":["cause a delay","cause damage","the cause of the problem"],"example":"The heavy snowstorm caused significant delays in all outgoing flights.","exampleZh":"這場大風雪造成所有出境航班嚴重延誤。","synonyms":["reason","bring about"],"level":1,"theme":"日常與一般"},{"word":"caution","pos":"n./v.","phonetic":"[ˈkɔʃən]","meaning":"謹慎；小心；警告；告誡","definition":"great care taken in order to avoid danger or mistakes","collocations":["exercise caution","with caution","a word of caution"],"example":"Please exercise caution when operating the machinery in the warehouse.","exampleZh":"在倉庫操作機具時，請務必格外小心。","synonyms":["care","prudence","warning"],"level":4,"theme":"生產與物流"},{"word":"celebrate","pos":"v.","phonetic":"[ˈsɛləˌbret]","meaning":"慶祝；慶賀","definition":"to do something special and enjoyable to mark an important occasion","collocations":["celebrate an anniversary","celebrate the achievement","celebrate the grand opening"],"example":"The company will hold a banquet to celebrate its twentieth anniversary.","exampleZh":"公司將舉辦晚宴，慶祝成立二十週年。","synonyms":["commemorate","observe"],"level":1,"theme":"媒體與活動"},{"word":"celebration","pos":"n.","phonetic":"[ˌsɛləˈbreʃən]","meaning":"慶祝活動；慶典","definition":"a special event that people organize to mark an important occasion","collocations":["anniversary celebration","in celebration of","hold a celebration"],"example":"All staff are invited to a celebration of our record sales this quarter.","exampleZh":"誠摯邀請全體員工參加本季銷售創新高的慶祝活動。","synonyms":["festivity","party"],"level":2,"theme":"媒體與活動"},{"word":"cell","pos":"n.","phonetic":"[sɛl]","meaning":"手機（cell phone）；細胞；（表格）儲存格；小房間","definition":"a mobile phone; a very small unit or compartment","collocations":["cell phone","turn off your cell phone","cell number"],"example":"Please turn off your cell phone before the presentation begins.","exampleZh":"簡報開始前，請將手機關機。","synonyms":[],"level":1,"theme":"科技與通訊"},{"word":"cement","pos":"n./v.","phonetic":"[səˈmɛnt]","meaning":"水泥；鞏固（關係）；加強","definition":"a gray powder used in building that hardens when mixed with water; to make a relationship stronger","collocations":["cement a relationship","cement mixer","pour cement"],"example":"The joint venture helped cement the partnership between the two firms.","exampleZh":"這項合資案有助於鞏固兩家公司的合作關係。","synonyms":["strengthen","solidify"],"level":4,"theme":"房產與設施"},{"word":"center","pos":"n./v.","phonetic":"[ˈsɛntɚ]","meaning":"中心；中央；中心機構；集中於","definition":"a building or place used for a particular activity; the middle point of something","collocations":["convention center","shopping center","call center","in the center of"],"example":"The trade show will take place at the downtown convention center.","exampleZh":"這場商展將在市中心的會議中心舉行。","synonyms":["hub","core"],"level":1,"theme":"房產與設施"},{"word":"central","pos":"adj.","phonetic":"[ˈsɛntrəl]","meaning":"中央的；市中心的；主要的；核心的","definition":"in the middle of an area or city; most important","collocations":["central location","central office","play a central role"],"example":"The hotel's central location makes it convenient for business travelers.","exampleZh":"這家飯店位於市中心，對商務旅客來說非常方便。","synonyms":["main","principal"],"level":2,"theme":"房產與設施"},{"word":"ceremony","pos":"n.","phonetic":"[ˈsɛrəˌmonɪ]","meaning":"典禮；儀式","definition":"a formal public event held to mark an important occasion","collocations":["opening ceremony","awards ceremony","attend a ceremony"],"example":"The mayor will attend the opening ceremony of the new public library.","exampleZh":"市長將出席新公共圖書館的開幕典禮。","synonyms":["ritual","rite"],"level":2,"theme":"媒體與活動"},{"word":"certain","pos":"adj.","phonetic":"[ˈsɝtṇ]","meaning":"確定的；肯定的；某些；某個","definition":"sure to happen or be true; particular but not named specifically","collocations":["make certain","a certain amount of","under certain conditions"],"example":"Please make certain that all documents are signed before submission.","exampleZh":"提交前請確認所有文件都已簽名。","synonyms":["sure","definite"],"level":1,"theme":"日常與一般"},{"word":"certainly","pos":"adv.","phonetic":"[ˈsɝtṇlɪ]","meaning":"當然；一定；確實","definition":"without any doubt; used to agree politely with a request","collocations":["will certainly","certainly not","Certainly, sir"],"example":"Certainly, I will send you the revised invoice this afternoon.","exampleZh":"當然沒問題，我今天下午就把修改後的發票寄給您。","synonyms":["definitely","surely","undoubtedly"],"level":1,"theme":"日常與一般"},{"word":"certificate","pos":"n.","phonetic":"[sɚˈtɪfəkɪt]","meaning":"證書；證明書；禮券（gift certificate）","definition":"an official document that proves a fact, qualification, or achievement","collocations":["gift certificate","certificate of completion","birth certificate"],"example":"Participants will receive a certificate after completing the training course.","exampleZh":"完成訓練課程後，學員將獲得結業證書。","synonyms":["credential","diploma"],"level":3,"theme":"人事與職涯"},{"word":"certification","pos":"n.","phonetic":"[ˌsɝtəfəˈkeʃən]","meaning":"認證；檢定；證明","definition":"the process of giving official or legal approval that a standard has been met","collocations":["obtain certification","professional certification","certification exam"],"example":"All technicians must obtain safety certification before operating the equipment.","exampleZh":"所有技術人員在操作設備前，都必須先取得安全認證。","synonyms":["accreditation","credential"],"level":4,"theme":"人事與職涯"},{"word":"certify","pos":"v.","phonetic":"[ˈsɝtəˌfaɪ]","meaning":"證明；認證；核發證書給","definition":"to state officially that something is true or meets a required standard","collocations":["certified public accountant","certify compliance","be certified to operate"],"example":"An inspector will certify that the building meets all safety codes.","exampleZh":"檢查員將證明這棟建築符合所有安全法規。","synonyms":["verify","confirm","validate"],"level":4,"theme":"合約與法律"},{"word":"chain","pos":"n.","phonetic":"[tʃen]","meaning":"連鎖店；鏈條；一連串","definition":"a group of stores, hotels, or restaurants owned by the same company","collocations":["hotel chain","supply chain","restaurant chain","chain of command"],"example":"The retail chain plans to open ten new branches across Asia.","exampleZh":"這家連鎖零售商計畫在亞洲各地開設十家新分店。","synonyms":["series","franchise"],"level":2,"theme":"企業經營"},{"word":"chair","pos":"n./v.","phonetic":"[tʃɛr]","meaning":"主持（會議）；主席；椅子","definition":"to be in charge of a meeting; the person in charge of a committee","collocations":["chair a meeting","committee chair","take a chair"],"example":"Ms. Watson will chair the budget committee meeting on Thursday.","exampleZh":"華森小姐將於週四主持預算委員會會議。","synonyms":["chairperson","preside over"],"level":2,"theme":"會議與簡報"},{"word":"challenge","pos":"n./v.","phonetic":"[ˈtʃælɪndʒ]","meaning":"挑戰；難題；質疑；向…挑戰","definition":"a difficult task that tests someone's ability or determination","collocations":["face a challenge","meet the challenge","pose a challenge"],"example":"Expanding into new markets remains the biggest challenge for our company.","exampleZh":"拓展新市場仍是我們公司最大的挑戰。","synonyms":["difficulty","test"],"level":2,"theme":"企業經營"},{"word":"challenging","pos":"adj.","phonetic":"[ˈtʃælɪndʒɪŋ]","meaning":"具挑戰性的；有難度的","definition":"difficult in a way that tests your ability, often in an interesting way","collocations":["a challenging task","challenging work","find it challenging"],"example":"The new position is challenging but offers great opportunities for growth.","exampleZh":"這個新職位很有挑戰性，但也提供絕佳的成長機會。","synonyms":["demanding","difficult"],"level":3,"theme":"人事與職涯"},{"word":"chance","pos":"n.","phonetic":"[tʃæns]","meaning":"機會；可能性；機率","definition":"an opportunity to do something; the possibility that something will happen","collocations":["a chance to","by chance","there is a good chance that"],"example":"This internship gives students a chance to gain real work experience.","exampleZh":"這個實習機會讓學生能夠累積實際的工作經驗。","synonyms":["opportunity","possibility"],"level":1,"theme":"日常與一般"},{"word":"change","pos":"n./v.","phonetic":"[tʃendʒ]","meaning":"變更；改變；零錢；找零；更換","definition":"to become different or make something different; money given back after payment","collocations":["a change in schedule","change one's mind","keep the change"],"example":"Please note the recent change in our store's opening hours.","exampleZh":"請注意本店營業時間近期有所異動。","synonyms":["alter","modify"],"level":1,"theme":"日常與一般"},{"word":"channel","pos":"n.","phonetic":"[ˈtʃænḷ]","meaning":"通路；管道；頻道","definition":"a way or system through which goods or information pass","collocations":["distribution channel","communication channel","through official channels"],"example":"The company uses multiple distribution channels to reach overseas customers.","exampleZh":"該公司透過多種通路接觸海外客戶。","synonyms":["route","medium"],"level":3,"theme":"行銷與銷售"},{"word":"chapter","pos":"n.","phonetic":"[ˈtʃæptɚ]","meaning":"章節；（組織的）分會","definition":"one of the separate sections of a book or report","collocations":["the first chapter","local chapter","a new chapter in"],"example":"The final chapter of the report summarizes our key recommendations.","exampleZh":"報告的最後一章總結了我們的主要建議。","synonyms":["section"],"level":2,"theme":"媒體與活動"},{"word":"characteristic","pos":"n./adj.","phonetic":"[ˌkærəktəˈrɪstɪk]","meaning":"特色；特徵；特點；典型的","definition":"a typical quality or feature that makes someone or something recognizable","collocations":["key characteristics","characteristic of","distinguishing characteristic"],"example":"Durability is a key characteristic of our new line of luggage.","exampleZh":"耐用是我們新系列行李箱的一大特色。","synonyms":["feature","trait","quality"],"level":4,"theme":"行銷與銷售"},{"word":"charge","pos":"n./v.","phonetic":"[tʃɑrdʒ]","meaning":"收費；費用；負責（in charge of）；充電；記帳","definition":"to ask someone to pay an amount of money for goods or services","collocations":["free of charge","in charge of","charge a fee","extra charge"],"example":"The hotel provides shuttle service to the airport free of charge.","exampleZh":"這家飯店免費提供機場接駁服務。","synonyms":["fee","bill"],"level":2,"theme":"購物與消費"},{"word":"charity","pos":"n.","phonetic":"[ˈtʃærətɪ]","meaning":"慈善機構；慈善事業；善舉","definition":"an organization that collects money to help people in need","collocations":["charity event","donate to charity","charity fundraiser"],"example":"All proceeds from the concert will be donated to local charities.","exampleZh":"這場音樂會的所有收益將捐給當地的慈善機構。","synonyms":["foundation","philanthropy"],"level":3,"theme":"媒體與活動"},{"word":"chart","pos":"n./v.","phonetic":"[tʃɑrt]","meaning":"圖表；曲線圖；記錄；繪製圖表","definition":"a drawing that shows information in the form of a graph or diagram","collocations":["bar chart","sales chart","as shown in the chart"],"example":"The chart on page five shows our quarterly sales figures.","exampleZh":"第五頁的圖表顯示了我們的季度銷售數字。","synonyms":["graph","diagram","table"],"level":2,"theme":"會議與簡報"},{"word":"charter","pos":"n./v.","phonetic":"[ˈtʃɑrtɚ]","meaning":"包租（飛機、巴士、船）；包機；特許狀；章程","definition":"to rent a plane, bus, or boat for the private use of a group","collocations":["charter flight","charter a bus","charter member"],"example":"The company chartered a bus to take employees to the training retreat.","exampleZh":"公司包了一輛巴士，載員工前往教育訓練營。","synonyms":["hire","rent","lease"],"level":5,"theme":"旅遊與交通"},{"word":"check","pos":"n./v.","phonetic":"[tʃɛk]","meaning":"檢查；確認；支票；帳單","definition":"to examine something in order to make sure it is correct or in good condition","collocations":["check the schedule","double-check","pay by check"],"example":"Please check your reservation details before confirming the booking.","exampleZh":"確認訂位之前，請先檢查您的預約資料。","synonyms":["examine","inspect","verify"],"level":1,"theme":"日常與一般"},{"word":"check-in","pos":"n./adj.","phonetic":"[ˈtʃɛkˌɪn]","meaning":"報到；登機手續；登記入住","definition":"the act of registering your arrival at an airport or hotel","collocations":["check-in counter","check-in time","online check-in"],"example":"The check-in counter opens three hours before the scheduled departure.","exampleZh":"報到櫃檯於預定起飛時間前三小時開放。","synonyms":["registration"],"level":2,"theme":"旅遊與交通"},{"word":"checklist","pos":"n.","phonetic":"[ˈtʃɛkˌlɪst]","meaning":"檢查清單；核對清單","definition":"a list of items or tasks that you check off as each one is done","collocations":["safety checklist","go through a checklist","complete the checklist"],"example":"Use the checklist to make sure every step has been completed.","exampleZh":"請利用核對清單，確認每個步驟都已完成。","synonyms":["list"],"level":3,"theme":"辦公室與行政"},{"word":"checkout","pos":"n.","phonetic":"[ˈtʃɛkˌaʊt]","meaning":"退房；結帳（櫃檯）","definition":"the time when you leave a hotel; the place where you pay in a store","collocations":["checkout time","checkout counter","express checkout"],"example":"Checkout time at the hotel is eleven o'clock in the morning.","exampleZh":"這家飯店的退房時間是上午十一點。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"checkup","pos":"n.","phonetic":"[ˈtʃɛkˌʌp]","meaning":"健康檢查；體檢","definition":"a general medical examination to make sure that you are healthy","collocations":["annual checkup","regular checkup","schedule a checkup","dental checkup"],"example":"All employees are required to have an annual health checkup.","exampleZh":"所有員工每年都必須接受健康檢查。","synonyms":["examination","physical"],"level":3,"theme":"醫療與保險"},{"word":"chef","pos":"n.","phonetic":"[ʃɛf]","meaning":"主廚；廚師","definition":"a skilled professional cook, especially the head cook in a restaurant","collocations":["head chef","executive chef","chef's special"],"example":"The head chef has designed a new seasonal menu for the restaurant.","exampleZh":"主廚為餐廳設計了一份全新的季節菜單。","synonyms":["cook"],"level":2,"theme":"餐飲與住宿"},{"word":"chemical","pos":"n./adj.","phonetic":"[ˈkɛmɪkḷ]","meaning":"化學物質；化學藥品；化學的","definition":"a substance produced by or used in a chemical process","collocations":["hazardous chemicals","chemical plant","chemical products"],"example":"Workers must wear protective gloves when handling hazardous chemicals.","exampleZh":"工作人員處理危險化學物質時，必須戴上防護手套。","synonyms":["substance","compound"],"level":3,"theme":"生產與物流"},{"word":"chief","pos":"adj./n.","phonetic":"[tʃif]","meaning":"首席的；最高階的；主要的；首長","definition":"highest in rank or authority; most important","collocations":["chief executive officer","chief financial officer","chief concern"],"example":"The chief executive officer will announce the restructuring plan tomorrow.","exampleZh":"執行長明天將宣布組織重整計畫。","synonyms":["main","principal","head"],"level":3,"theme":"企業經營"},{"word":"choice","pos":"n.","phonetic":"[tʃɔɪs]","meaning":"選擇；選項；可選擇的範圍","definition":"the act of choosing between two or more possibilities; a range of things to choose from","collocations":["a wide choice of","make a choice","have no choice but to"],"example":"The menu offers a wide choice of vegetarian dishes.","exampleZh":"這份菜單提供多樣的素食餐點可供選擇。","synonyms":["option","selection","alternative"],"level":1,"theme":"日常與一般"},{"word":"choose","pos":"v.","phonetic":"[tʃuz]","meaning":"選擇；挑選；決定","definition":"to decide which one you want from a number of possibilities","collocations":["choose from","choose between","choose to do"],"example":"Customers can choose from three different subscription plans.","exampleZh":"顧客可以從三種不同的訂閱方案中選擇。","synonyms":["select","pick"],"level":1,"theme":"日常與一般"},{"word":"chronological","pos":"adj.","phonetic":"[ˌkrɑnəˈlɑdʒɪkḷ]","meaning":"按時間順序的；依年代排列的","definition":"arranged in the order in which events actually happened","collocations":["in chronological order","reverse chronological order","a chronological list"],"example":"Please list your work experience in reverse chronological order on your resume.","exampleZh":"請在履歷上依時間由近到遠列出工作經歷。","synonyms":["sequential"],"level":5,"theme":"人事與職涯"},{"word":"circulate","pos":"v.","phonetic":"[ˈsɝkjəˌlet]","meaning":"傳閱；分發；流通；（消息）流傳；循環","definition":"to send something such as a document around to a group of people","collocations":["circulate a memo","circulate the agenda","circulate among the guests"],"example":"Please circulate the meeting agenda to all department heads by Friday.","exampleZh":"請在週五前將會議議程傳給各部門主管傳閱。","synonyms":["distribute","disseminate","spread"],"level":4,"theme":"辦公室與行政"},{"word":"circumstance","pos":"n.","phonetic":"[ˈsɝkəmˌstæns]","meaning":"情況；情勢；環境","definition":"a condition or fact that affects a situation","collocations":["under no circumstances","due to unforeseen circumstances","under the circumstances"],"example":"Due to unforeseen circumstances, the annual conference has been postponed until next month.","exampleZh":"由於突發狀況，年度會議已延期至下個月舉行。","synonyms":["situation","condition"],"level":3,"theme":"日常與一般"},{"word":"cite","pos":"v.","phonetic":"[saɪt]","meaning":"引用；引述；舉出（理由、例子）","definition":"to mention something as an example, proof, or reason","collocations":["cite an example","cite a source","cite reasons for"],"example":"The manager cited rising material costs as the main reason for the price increase.","exampleZh":"經理指出原物料成本上漲是這次漲價的主要原因。","synonyms":["quote","mention","reference"],"level":4,"theme":"企業經營"},{"word":"city","pos":"n.","phonetic":"[ˈsɪtɪ]","meaning":"城市；都市","definition":"a large town where many people live and work","collocations":["city center","city hall","capital city"],"example":"The new branch office is located in the heart of the city.","exampleZh":"新的分公司就位於市中心。","synonyms":["metropolis"],"level":1,"theme":"旅遊與交通"},{"word":"claim","pos":"v./n.","phonetic":"[klem]","meaning":"索賠；申請（理賠）；聲稱；領取（行李）","definition":"to officially ask for money or something you have a right to","collocations":["file a claim","claim compensation","an insurance claim","baggage claim"],"example":"Passengers can claim compensation if their flight is delayed more than three hours.","exampleZh":"航班若延誤超過三小時，乘客可以申請賠償。","synonyms":["demand","assert"],"level":3,"theme":"醫療與保險"},{"word":"clarify","pos":"v.","phonetic":"[ˈklærəˌfaɪ]","meaning":"澄清；說明；闡明","definition":"to make something easier to understand by explaining it in more detail","collocations":["clarify a point","clarify the details","clarify a misunderstanding"],"example":"Could you clarify the payment terms before we sign the contract?","exampleZh":"在簽約之前，能否請您說明一下付款條件？","synonyms":["explain","elucidate"],"level":4,"theme":"會議與簡報"},{"word":"class","pos":"n.","phonetic":"[klæs]","meaning":"課程；班級；等級；（交通工具的）艙等","definition":"a series of lessons, or a group or category of a particular standard","collocations":["business class","take a class","first-class service","world-class"],"example":"All employees are encouraged to take an evening class in business English.","exampleZh":"公司鼓勵所有員工參加商用英語的夜間課程。","synonyms":["course","category"],"level":1,"theme":"日常與一般"},{"word":"classify","pos":"v.","phonetic":"[ˈklæsəˌfaɪ]","meaning":"分類；歸類","definition":"to divide things into groups according to their type or features","collocations":["classify documents","classify data by category","be classified as"],"example":"Please classify all incoming documents by department before filing them.","exampleZh":"請先將所有收到的文件依部門分類，再進行歸檔。","synonyms":["categorize","sort","group"],"level":4,"theme":"辦公室與行政"},{"word":"clause","pos":"n.","phonetic":"[klɔz]","meaning":"（合約的）條款；（文法）子句","definition":"a separate part of a legal document or contract","collocations":["a confidentiality clause","a penalty clause","under clause five of the contract"],"example":"The contract includes a clause allowing either party to cancel with thirty days' notice.","exampleZh":"合約中有一項條款，允許任一方在提前三十天通知後解約。","synonyms":["provision","stipulation","term"],"level":5,"theme":"合約與法律"},{"word":"clean","pos":"adj./v.","phonetic":"[klin]","meaning":"乾淨的；清潔的；打掃；清理","definition":"free from dirt; to remove dirt from something","collocations":["keep the workplace clean","clean energy","clean the office"],"example":"Hotel staff clean each room thoroughly before new guests arrive.","exampleZh":"飯店人員會在新房客入住前徹底打掃每間客房。","synonyms":["spotless","tidy"],"level":1,"theme":"餐飲與住宿"},{"word":"cleaner","pos":"n.","phonetic":"[ˈklinɚ]","meaning":"清潔人員；清潔劑；乾洗店","definition":"a person whose job is to clean, or a substance used for cleaning","collocations":["a vacuum cleaner","an office cleaner","take a suit to the cleaner's"],"example":"The office cleaner comes every evening after the staff have left.","exampleZh":"辦公室的清潔人員每天傍晚在員工下班後前來打掃。","synonyms":["janitor"],"level":2,"theme":"房產與設施"},{"word":"cleaning","pos":"n.","phonetic":"[ˈklinɪŋ]","meaning":"清潔；打掃；清洗","definition":"the activity or process of making something clean","collocations":["dry cleaning","a cleaning service","cleaning supplies"],"example":"The building's cleaning service operates daily between six and nine in the evening.","exampleZh":"這棟大樓的清潔服務每天傍晚六點到九點進行。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"clear","pos":"adj./v.","phonetic":"[klɪr]","meaning":"清楚的；明確的；清除；（貨物）通關","definition":"easy to understand or see; to remove things that are not wanted","collocations":["clear instructions","make it clear","clear customs","clear the table"],"example":"The manual provides clear instructions on how to install the new software.","exampleZh":"這本手冊清楚說明了新軟體的安裝步驟。","synonyms":["obvious","evident","plain"],"level":2,"theme":"日常與一般"},{"word":"clearance","pos":"n.","phonetic":"[ˈklɪrəns]","meaning":"清倉（拍賣）；許可；清關","definition":"the sale of goods at reduced prices to get rid of stock, or official permission","collocations":["a clearance sale","customs clearance","security clearance"],"example":"The store is holding a clearance sale to make room for new inventory.","exampleZh":"這家店正在舉辦清倉特賣，為新進商品騰出空間。","synonyms":["authorization","permission"],"level":4,"theme":"購物與消費"},{"word":"clearly","pos":"adv.","phonetic":"[ˈklɪrlɪ]","meaning":"清楚地；明顯地","definition":"in a way that is easy to see, hear, or understand","collocations":["clearly stated","speak clearly","clearly marked"],"example":"All prices are clearly marked on the shelves for customers' convenience.","exampleZh":"所有價格都清楚標示在貨架上，方便顧客查看。","synonyms":["plainly","obviously"],"level":2,"theme":"日常與一般"},{"word":"clerical","pos":"adj.","phonetic":"[ˈklɛrɪkḷ]","meaning":"文書的；辦公室事務的","definition":"relating to routine office work such as filing and keeping records","collocations":["clerical work","clerical staff","a clerical error"],"example":"The invoice was delayed because of a clerical error in the billing department.","exampleZh":"由於帳務部門的文書疏失，發票延遲寄出了。","synonyms":["administrative","secretarial"],"level":5,"theme":"辦公室與行政"},{"word":"clerk","pos":"n.","phonetic":"[klɝk]","meaning":"職員；辦事員；（旅館、商店）櫃檯人員","definition":"a person who works in an office, store, or hotel keeping records or serving customers","collocations":["a front desk clerk","a sales clerk","a filing clerk"],"example":"The hotel clerk helped us check in and stored our luggage.","exampleZh":"飯店櫃檯人員協助我們辦理入住，並幫忙寄放行李。","synonyms":["receptionist","office worker"],"level":2,"theme":"辦公室與行政"},{"word":"client","pos":"n.","phonetic":"[ˈklaɪənt]","meaning":"客戶；委託人","definition":"a person or company that pays for professional services","collocations":["meet with a client","a major client","client satisfaction"],"example":"Our law firm has represented this client for more than ten years.","exampleZh":"我們律師事務所為這位客戶服務已超過十年。","synonyms":["customer","patron"],"level":2,"theme":"行銷與銷售"},{"word":"clientele","pos":"n.","phonetic":"[ˌklaɪənˈtɛl]","meaning":"（總稱）客戶群；顧客群","definition":"all the customers of a business considered as a group","collocations":["a loyal clientele","an international clientele","attract a wealthy clientele"],"example":"The boutique has built a loyal clientele through excellent personal service.","exampleZh":"這家精品店憑藉出色的貼心服務，培養出一群忠實顧客。","synonyms":["customers","patrons"],"level":6,"theme":"行銷與銷售"},{"word":"climate","pos":"n.","phonetic":"[ˈklaɪmɪt]","meaning":"（經濟、商業）情勢；氣候；風氣","definition":"the general situation or atmosphere in a place, or the typical weather conditions of an area","collocations":["the economic climate","climate change","a favorable business climate"],"example":"Many companies are cutting costs in the current economic climate.","exampleZh":"在目前的經濟情勢下，許多公司都在削減成本。","synonyms":["environment","atmosphere"],"level":3,"theme":"企業經營"},{"word":"clinic","pos":"n.","phonetic":"[ˈklɪnɪk]","meaning":"診所；門診","definition":"a place where people receive medical treatment or advice","collocations":["a dental clinic","an outpatient clinic","visit a clinic"],"example":"Employees can receive free flu shots at the company clinic this week.","exampleZh":"員工本週可在公司附設診所免費接種流感疫苗。","synonyms":["medical center"],"level":2,"theme":"醫療與保險"},{"word":"close","pos":"v./adj./adv.","phonetic":"[kloz]","meaning":"關閉；結束；打烊；接近的；密切的","definition":"to shut something or stop it from operating for a period of time","collocations":["close a deal","close down a branch","close of business","a close relationship"],"example":"The store closes at nine on weekdays and at six on weekends.","exampleZh":"這家店平日晚上九點打烊，週末則是六點。","synonyms":["shut"],"level":1,"theme":"購物與消費"},{"word":"closely","pos":"adv.","phonetic":"[ˈkloslɪ]","meaning":"密切地；緊密地；仔細地","definition":"carefully and with great attention; in a way that involves a strong connection","collocations":["work closely with","monitor closely","closely related"],"example":"Our team works closely with suppliers to ensure timely delivery.","exampleZh":"我們的團隊與供應商密切合作，確保準時交貨。","synonyms":["carefully","intimately"],"level":3,"theme":"企業經營"},{"word":"closet","pos":"n.","phonetic":"[ˈklɑzɪt]","meaning":"衣櫥；壁櫥；儲藏室","definition":"a small room or piece of furniture for storing clothes or other things","collocations":["a walk-in closet","a supply closet","closet space"],"example":"Extra office supplies are kept in the closet next to the copy room.","exampleZh":"備用的辦公用品放在影印室旁邊的儲藏室裡。","synonyms":["cupboard","wardrobe"],"level":2,"theme":"房產與設施"},{"word":"closure","pos":"n.","phonetic":"[ˈkloʒɚ]","meaning":"關閉；歇業；（道路）封閉","definition":"the permanent or temporary closing of a business, road, or facility","collocations":["a factory closure","a road closure","temporary closure"],"example":"The road closure caused significant delays for commuters this morning.","exampleZh":"今天早上道路封閉，造成通勤族嚴重延誤。","synonyms":["shutdown"],"level":4,"theme":"旅遊與交通"},{"word":"clothing","pos":"n.","phonetic":"[ˈkloðɪŋ]","meaning":"衣服；服裝（總稱）","definition":"clothes in general, especially of a particular type","collocations":["protective clothing","a clothing store","an item of clothing"],"example":"All factory visitors must wear protective clothing at all times.","exampleZh":"所有到工廠參觀的訪客必須全程穿著防護服。","synonyms":["apparel","garments","attire"],"level":2,"theme":"購物與消費"},{"word":"coach","pos":"n./v.","phonetic":"[kotʃ]","meaning":"教練；長途巴士；（客機）經濟艙；指導","definition":"a person who trains and instructs people, or a comfortable bus for long journeys","collocations":["travel by coach","fly coach","a business coach","coach new employees"],"example":"The company hired a professional coach to train its sales team.","exampleZh":"公司聘請了一位專業教練來訓練業務團隊。","synonyms":["trainer","instructor","mentor"],"level":2,"theme":"人事與職涯"},{"word":"code","pos":"n.","phonetic":"[kod]","meaning":"代碼；密碼；規範；法規","definition":"a system of numbers or letters used for identification, or a set of rules","collocations":["a dress code","an area code","a discount code","a building code"],"example":"Enter the discount code at checkout to receive ten percent off.","exampleZh":"結帳時輸入折扣碼，即可享有九折優惠。","synonyms":["regulations"],"level":2,"theme":"購物與消費"},{"word":"coffee","pos":"n.","phonetic":"[ˈkɔfɪ]","meaning":"咖啡","definition":"a hot drink made from the roasted seeds of a tropical plant","collocations":["a coffee break","a cup of coffee","a coffee maker"],"example":"Complimentary coffee is available in the hotel lobby every morning.","exampleZh":"每天早上飯店大廳都提供免費咖啡。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"coincide","pos":"v.","phonetic":"[ˌkoɪnˈsaɪd]","meaning":"同時發生；恰巧碰上；（意見）一致","definition":"to happen at the same time as something else","collocations":["coincide with the anniversary","the dates coincide","opinions coincide"],"example":"The product launch was scheduled to coincide with the international trade show.","exampleZh":"產品發表會特地安排在國際商展同期舉行。","synonyms":["concur","overlap"],"level":5,"theme":"媒體與活動"},{"word":"collaborate","pos":"v.","phonetic":"[kəˈlæbəˌret]","meaning":"合作；協作","definition":"to work together with another person or group on a project","collocations":["collaborate with partners","collaborate on a project","collaborate closely"],"example":"The two firms will collaborate on developing new medical equipment.","exampleZh":"這兩家公司將合作開發新型醫療設備。","synonyms":["cooperate","team up"],"level":4,"theme":"企業經營"},{"word":"collaboration","pos":"n.","phonetic":"[kəˌlæbəˈreʃən]","meaning":"合作；協作","definition":"the act of working together with others to produce or achieve something","collocations":["in collaboration with","close collaboration","a collaboration between departments"],"example":"The new software was developed in collaboration with a local university.","exampleZh":"這套新軟體是與當地一所大學合作開發的。","synonyms":["cooperation","partnership","teamwork"],"level":4,"theme":"企業經營"},{"word":"colleague","pos":"n.","phonetic":"[ˈkɑlig]","meaning":"同事","definition":"a person you work with, especially in a profession or business","collocations":["a former colleague","colleagues and clients","a trusted colleague"],"example":"Please welcome our new colleague, who joins the marketing team today.","exampleZh":"請大家歡迎今天加入行銷團隊的新同事。","synonyms":["coworker","associate","peer"],"level":2,"theme":"人事與職涯"},{"word":"collect","pos":"v.","phonetic":"[kəˈlɛkt]","meaning":"領取；收集；收取（款項）","definition":"to go and get something, or to gather things together","collocations":["collect your baggage","collect data","collect payment"],"example":"Passengers may collect their baggage at carousel number five.","exampleZh":"旅客可在五號行李轉盤領取行李。","synonyms":["gather","pick up"],"level":2,"theme":"旅遊與交通"},{"word":"collection","pos":"n.","phonetic":"[kəˈlɛkʃən]","meaning":"收藏（品）；（服裝）系列；收取；蒐集","definition":"a group of objects gathered together, often for display or study","collocations":["a permanent collection","the new spring collection","data collection","garbage collection"],"example":"The museum's permanent collection features over two thousand works of art.","exampleZh":"這座美術館的常設館藏包含兩千多件藝術作品。","synonyms":["assortment","compilation"],"level":3,"theme":"媒體與活動"},{"word":"collector","pos":"n.","phonetic":"[kəˈlɛktɚ]","meaning":"收藏家；收款員；收集者","definition":"a person who collects things as a hobby or as part of their job","collocations":["an art collector","a ticket collector","a collector's item"],"example":"The rare painting was sold to a private collector at auction.","exampleZh":"這幅珍稀畫作在拍賣會上售予一位私人收藏家。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"column","pos":"n.","phonetic":"[ˈkɑləm]","meaning":"（報章雜誌）專欄；欄位；圓柱","definition":"a regular article in a newspaper or magazine, or a vertical section of a page or building","collocations":["a weekly column","a column of figures","the left-hand column"],"example":"She writes a weekly column on personal finance for the local newspaper.","exampleZh":"她為當地報紙撰寫每週一篇的個人理財專欄。","synonyms":["article","pillar"],"level":3,"theme":"媒體與活動"},{"word":"combination","pos":"n.","phonetic":"[ˌkɑmbəˈneʃən]","meaning":"結合；組合","definition":"a mixture of two or more things used or considered together","collocations":["a combination of factors","in combination with","a winning combination"],"example":"The restaurant's success comes from a combination of good food and friendly service.","exampleZh":"這家餐廳的成功來自美味餐點與親切服務的完美結合。","synonyms":["mixture","blend"],"level":3,"theme":"日常與一般"},{"word":"combine","pos":"v.","phonetic":"[kəmˈbaɪn]","meaning":"結合；合併；兼具","definition":"to join two or more things together to form a single unit","collocations":["combine efforts","combine work with travel","combine A with B"],"example":"The tour combines sightseeing with plenty of free time for shopping.","exampleZh":"這個行程結合了觀光行程與充裕的自由購物時間。","synonyms":["merge","unite","integrate"],"level":3,"theme":"日常與一般"},{"word":"comfort","pos":"n./v.","phonetic":"[ˈkʌmfɚt]","meaning":"舒適；安慰；使舒服","definition":"a pleasant state of being physically relaxed, or to make someone feel better","collocations":["travel in comfort","passenger comfort","comfort and convenience"],"example":"The airline's new seats were designed with passenger comfort in mind.","exampleZh":"這家航空公司的新座椅是以乘客的舒適度為設計考量。","synonyms":["ease","coziness"],"level":3,"theme":"旅遊與交通"},{"word":"comfortable","pos":"adj.","phonetic":"[ˈkʌmfɚtəbḷ]","meaning":"舒適的；自在的","definition":"making you feel physically relaxed and free from pain","collocations":["a comfortable room","feel comfortable with","comfortable seating"],"example":"Our hotel rooms are spacious, comfortable, and equipped with modern amenities.","exampleZh":"本飯店客房寬敞舒適，並配備現代化設施。","synonyms":["cozy","relaxing"],"level":2,"theme":"餐飲與住宿"},{"word":"commemorate","pos":"v.","phonetic":"[kəˈmɛməˌret]","meaning":"紀念；慶祝（週年、事件）","definition":"to do something special to show respect for an important event or person","collocations":["commemorate an anniversary","a ceremony to commemorate","commemorate the founding"],"example":"A special dinner will be held to commemorate the company's fiftieth anniversary.","exampleZh":"公司將舉辦特別晚宴，紀念創立五十週年。","synonyms":["celebrate","honor"],"level":6,"theme":"媒體與活動"},{"word":"comment","pos":"n./v.","phonetic":"[ˈkɑmɛnt]","meaning":"評論；意見；發表意見","definition":"a written or spoken opinion or remark about something","collocations":["make a comment","comment on the proposal","customer comments"],"example":"Customers are invited to leave comments about their shopping experience online.","exampleZh":"我們邀請顧客上網留言，分享他們的購物體驗。","synonyms":["remark","observation","feedback"],"level":2,"theme":"行銷與銷售"},{"word":"commercial","pos":"adj./n.","phonetic":"[kəˈmɝʃəl]","meaning":"商業的；商用的；（電視、廣播）廣告","definition":"related to buying and selling goods and services, or an advertisement on TV or radio","collocations":["a commercial district","commercial use","a TV commercial"],"example":"The company aired its first television commercial during the holiday season.","exampleZh":"這家公司在節慶期間播出了第一支電視廣告。","synonyms":["advertisement"],"level":3,"theme":"行銷與銷售"},{"word":"commission","pos":"n./v.","phonetic":"[kəˈmɪʃən]","meaning":"佣金；委員會；委託（製作、進行）","definition":"money paid to someone based on the amount they sell, or an official group with a duty","collocations":["earn a commission","work on commission","commission a study","a planning commission"],"example":"Sales representatives earn a ten percent commission on every unit sold.","exampleZh":"業務代表每售出一件商品，可獲得百分之十的佣金。","synonyms":["fee"],"level":4,"theme":"行銷與銷售"},{"word":"commit","pos":"v.","phonetic":"[kəˈmɪt]","meaning":"承諾；投入（資金、時間）；犯（錯、罪）","definition":"to promise to do something, or to devote money or time to a purpose","collocations":["commit to a deadline","commit resources","commit an error"],"example":"The firm has committed significant funds to renewable energy research.","exampleZh":"這家公司已投入大量資金於再生能源研究。","synonyms":["pledge","dedicate","devote"],"level":4,"theme":"企業經營"},{"word":"commitment","pos":"n.","phonetic":"[kəˈmɪtmənt]","meaning":"承諾；投入；（已排定的）事務","definition":"a promise or firm decision to do something, or dedication to a cause","collocations":["a commitment to quality","make a commitment","prior commitments"],"example":"Our commitment to customer satisfaction has made us an industry leader.","exampleZh":"我們對顧客滿意度的堅持，使我們成為業界的領導者。","synonyms":["dedication","pledge","devotion"],"level":4,"theme":"企業經營"},{"word":"committee","pos":"n.","phonetic":"[kəˈmɪtɪ]","meaning":"委員會","definition":"a group of people chosen to make decisions or deal with a particular subject","collocations":["a planning committee","committee members","form a committee","sit on a committee"],"example":"The hiring committee will interview five candidates for the manager position.","exampleZh":"招聘委員會將面試五位應徵經理職位的人選。","synonyms":["board","panel"],"level":3,"theme":"辦公室與行政"},{"word":"commodity","pos":"n.","phonetic":"[kəˈmɑdətɪ]","meaning":"商品；原物料；日用品","definition":"a product or raw material that can be bought and sold, especially in large quantities","collocations":["commodity prices","a valuable commodity","agricultural commodities"],"example":"Rising commodity prices have increased production costs across the industry.","exampleZh":"原物料價格上漲，使整個產業的生產成本增加。","synonyms":["goods","product"],"level":5,"theme":"財務與會計"},{"word":"common","pos":"adj.","phonetic":"[ˈkɑmən]","meaning":"常見的；共同的；普通的","definition":"happening often or existing in large numbers; shared by two or more people","collocations":["a common problem","common practice","have something in common","common sense"],"example":"Flight delays are common during the busy holiday travel season.","exampleZh":"在繁忙的節慶旅遊旺季，航班延誤是常有的事。","synonyms":["usual","frequent","widespread"],"level":1,"theme":"日常與一般"},{"word":"commonly","pos":"adv.","phonetic":"[ˈkɑmənlɪ]","meaning":"通常；普遍地；常常","definition":"usually or very often","collocations":["commonly used","commonly known as","most commonly"],"example":"This software is commonly used for managing customer databases.","exampleZh":"這套軟體常被用來管理客戶資料庫。","synonyms":["frequently","generally","widely"],"level":2,"theme":"日常與一般"},{"word":"communicate","pos":"v.","phonetic":"[kəˈmjunəˌket]","meaning":"溝通；傳達；聯繫","definition":"to share information, ideas, or feelings with other people","collocations":["communicate effectively","communicate with clients","communicate a message"],"example":"Managers should communicate any schedule changes to their teams promptly.","exampleZh":"主管應立即將任何行程異動告知團隊成員。","synonyms":["convey","correspond"],"level":3,"theme":"科技與通訊"},{"word":"communication","pos":"n.","phonetic":"[kəˌmjunəˈkeʃən]","meaning":"溝通；通訊；聯絡","definition":"the process of sharing information, ideas, or feelings with others","collocations":["communication skills","a breakdown in communication","internal communication"],"example":"Strong communication skills are essential for this customer service position.","exampleZh":"良好的溝通能力是這個客服職位的必備條件。","synonyms":["correspondence","interaction"],"level":3,"theme":"科技與通訊"},{"word":"community","pos":"n.","phonetic":"[kəˈmjunətɪ]","meaning":"社區；社群；界","definition":"the people living in one area, or a group of people with shared interests","collocations":["the local community","a community center","the business community","community service"],"example":"The company sponsors several events for the local community each year.","exampleZh":"這家公司每年贊助多場地方社區活動。","synonyms":["neighborhood","public"],"level":2,"theme":"日常與一般"},{"word":"commute","pos":"v./n.","phonetic":"[kəˈmjut]","meaning":"通勤；通勤路程","definition":"to travel regularly between your home and your workplace","collocations":["commute to work","a long commute","the daily commute"],"example":"Many employees commute to the office by train every day.","exampleZh":"許多員工每天搭火車通勤上班。","synonyms":["travel"],"level":3,"theme":"旅遊與交通"},{"word":"commuter","pos":"n.","phonetic":"[kəˈmjutɚ]","meaning":"通勤者；通勤族","definition":"a person who travels regularly between home and work","collocations":["a commuter train","rush-hour commuters","commuter traffic"],"example":"The new subway line will benefit thousands of daily commuters.","exampleZh":"新的地鐵路線將造福數千名每日通勤族。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"company","pos":"n.","phonetic":"[ˈkʌmpənɪ]","meaning":"公司；同伴；陪伴","definition":"a business organization that makes money by producing or selling goods or services","collocations":["company policy","run a company","a company car","keep someone company"],"example":"The company plans to open three new branches next year.","exampleZh":"這家公司計畫明年開設三家新分店。","synonyms":["firm","corporation","enterprise"],"level":1,"theme":"企業經營"},{"word":"comparable","pos":"adj.","phonetic":"[ˈkɑmpərəbḷ]","meaning":"可比較的；相當的；類似的","definition":"similar to something else in size, quality, or amount","collocations":["comparable to","of comparable quality","comparable products"],"example":"Our prices are lower than those of comparable products on the market.","exampleZh":"我們的價格比市面上同類產品更低。","synonyms":["similar","equivalent"],"level":5,"theme":"行銷與銷售"},{"word":"compare","pos":"v.","phonetic":"[kəmˈpɛr]","meaning":"比較；相比","definition":"to examine how people or things are similar or different","collocations":["compare prices","compared with last year","compare A with B"],"example":"Customers can compare prices from several airlines on our website.","exampleZh":"顧客可以在我們的網站上比較多家航空公司的票價。","synonyms":["contrast"],"level":2,"theme":"購物與消費"},{"word":"comparison","pos":"n.","phonetic":"[kəmˈpærəsṇ]","meaning":"比較；對照","definition":"the act of considering how things are similar or different","collocations":["in comparison with","make a comparison","by comparison","a price comparison"],"example":"The report includes a comparison of sales figures from the past three years.","exampleZh":"這份報告比較了過去三年的銷售數字。","synonyms":["contrast"],"level":3,"theme":"財務與會計"},{"word":"compartment","pos":"n.","phonetic":"[kəmˈpɑrtmənt]","meaning":"置物櫃；隔間；（火車）車廂","definition":"a separate section inside a container, piece of furniture, or vehicle","collocations":["an overhead compartment","a luggage compartment","a glove compartment"],"example":"Please place your carry-on luggage in the overhead compartment before takeoff.","exampleZh":"起飛前請將隨身行李放入座位上方的置物櫃。","synonyms":["section","cubicle"],"level":3,"theme":"旅遊與交通"},{"word":"compatible","pos":"adj.","phonetic":"[kəmˈpætəbḷ]","meaning":"相容的；可並存的；合得來的","definition":"able to be used together with something else without causing problems","collocations":["compatible with","backward compatible","compatible devices"],"example":"The new software is fully compatible with all major operating systems.","exampleZh":"這套新軟體與所有主要作業系統完全相容。","synonyms":["consistent","harmonious"],"level":4,"theme":"科技與通訊"},{"word":"compensate","pos":"v.","phonetic":"[ˈkɑmpənˌset]","meaning":"賠償；補償；彌補","definition":"to pay someone money because they have suffered loss, damage, or inconvenience","collocations":["compensate for the loss","compensate passengers","fully compensate"],"example":"The airline will compensate passengers for the cancelled evening flight.","exampleZh":"航空公司將賠償乘客晚間班機取消的損失。","synonyms":["reimburse","repay"],"level":4,"theme":"財務與會計"},{"word":"compensation","pos":"n.","phonetic":"[ˌkɑmpənˈseʃən]","meaning":"薪酬；補償金；賠償","definition":"money paid to someone as salary and benefits, or for loss or damage","collocations":["compensation package","workers' compensation","seek compensation"],"example":"Employees receive a generous compensation package including health insurance and bonuses.","exampleZh":"員工享有優渥的薪酬福利，包含健康保險與獎金。","synonyms":["remuneration","reimbursement"],"level":4,"theme":"人事與職涯"},{"word":"compete","pos":"v.","phonetic":"[kəmˈpit]","meaning":"競爭；比賽","definition":"to try to be more successful than other people or companies","collocations":["compete with rivals","compete for market share","compete in the global market"],"example":"Small businesses find it hard to compete with large retail chains.","exampleZh":"小型企業很難與大型連鎖零售商競爭。","synonyms":["contend","rival"],"level":2,"theme":"企業經營"},{"word":"competent","pos":"adj.","phonetic":"[ˈkɑmpətənt]","meaning":"能幹的；勝任的；稱職的","definition":"having enough skill or knowledge to do something well","collocations":["a competent manager","competent in accounting","highly competent staff"],"example":"We are looking for a competent accountant to manage our payroll.","exampleZh":"我們正在徵求一位能勝任薪資管理的會計人員。","synonyms":["capable","qualified","skilled"],"level":4,"theme":"人事與職涯"},{"word":"competition","pos":"n.","phonetic":"[ˌkɑmpəˈtɪʃən]","meaning":"競爭；比賽；競賽","definition":"a situation in which people or companies try to be more successful than others","collocations":["fierce competition","face competition","enter a competition"],"example":"The company faces intense competition from overseas manufacturers.","exampleZh":"該公司面臨來自海外製造商的激烈競爭。","synonyms":["rivalry","contest"],"level":2,"theme":"企業經營"},{"word":"competitive","pos":"adj.","phonetic":"[kəmˈpɛtətɪv]","meaning":"有競爭力的；競爭激烈的；好勝的","definition":"as good as or better than others of the same type, especially in price","collocations":["competitive prices","competitive advantage","competitive salary"],"example":"We offer competitive prices on all office supplies and free delivery.","exampleZh":"我們所有辦公用品均以具競爭力的價格供應，並提供免費送貨。","synonyms":[],"level":3,"theme":"行銷與銷售"},{"word":"competitor","pos":"n.","phonetic":"[kəmˈpɛtətɚ]","meaning":"競爭者；競爭對手","definition":"a company or person that tries to win business or success from others","collocations":["main competitor","outperform competitors","a strong competitor"],"example":"Our main competitor recently lowered its prices to gain market share.","exampleZh":"我們的主要競爭對手最近降價以搶攻市占率。","synonyms":["rival","opponent"],"level":3,"theme":"企業經營"},{"word":"compile","pos":"v.","phonetic":"[kəmˈpaɪl]","meaning":"彙整；編纂；編譯","definition":"to collect information from different places and arrange it in a list, report, or book","collocations":["compile a report","compile data","compile a list"],"example":"The assistant compiled a list of potential clients for the sales team.","exampleZh":"助理為業務團隊彙整了一份潛在客戶名單。","synonyms":["assemble","gather"],"level":4,"theme":"辦公室與行政"},{"word":"complain","pos":"v.","phonetic":"[kəmˈplen]","meaning":"抱怨；投訴","definition":"to say that you are annoyed or not satisfied with something","collocations":["complain about the service","complain to the manager","complain constantly"],"example":"Several customers complained about the slow service at the checkout counter.","exampleZh":"好幾位顧客抱怨結帳櫃檯的服務速度太慢。","synonyms":["grumble","protest"],"level":2,"theme":"購物與消費"},{"word":"complaint","pos":"n.","phonetic":"[kəmˈplent]","meaning":"投訴；客訴；抱怨","definition":"a statement saying that something is wrong or not satisfactory","collocations":["file a complaint","customer complaints","handle complaints"],"example":"The customer service department handles complaints within twenty-four hours.","exampleZh":"客服部門會在二十四小時內處理客訴。","synonyms":["grievance","objection"],"level":2,"theme":"購物與消費"},{"word":"complement","pos":"v./n.","phonetic":"[ˈkɑmpləˌmɛnt]","meaning":"與…相配；使更完善；互補；補充物","definition":"to combine well with something and make it better or more complete","collocations":["complement each other","complement the design","a perfect complement to"],"example":"The new dessert menu perfectly complements the restaurant's main dishes.","exampleZh":"新的甜點菜單與餐廳的主菜相得益彰。","synonyms":["supplement","enhance"],"level":5,"theme":"餐飲與住宿"},{"word":"complete","pos":"v./adj.","phonetic":"[kəmˈplit]","meaning":"完成；填寫（表格）；完整的","definition":"to finish doing or making something, or to fill in a form","collocations":["complete a form","complete the project","complete a survey"],"example":"Please complete the attached form and return it by Friday.","exampleZh":"請填妥附件表格並於週五前繳回。","synonyms":["finish","finalize"],"level":1,"theme":"辦公室與行政"},{"word":"completely","pos":"adv.","phonetic":"[kəmˈplitlɪ]","meaning":"完全地；徹底地","definition":"in every way or as much as possible; totally","collocations":["completely different","completely satisfied","completely sold out"],"example":"The hotel lobby was completely renovated last spring.","exampleZh":"飯店大廳去年春天全面翻新。","synonyms":["totally","entirely","fully"],"level":1,"theme":"日常與一般"},{"word":"completion","pos":"n.","phonetic":"[kəmˈpliʃən]","meaning":"完成；完工","definition":"the state of being finished, or the act of finishing something","collocations":["upon completion of","completion date","near completion"],"example":"The construction project is scheduled for completion by the end of December.","exampleZh":"這項工程預計於十二月底完工。","synonyms":["conclusion","fulfillment"],"level":3,"theme":"房產與設施"},{"word":"complex","pos":"adj./n.","phonetic":"[ˈkɑmplɛks]","meaning":"複雜的；綜合大樓；建築群","definition":"consisting of many different parts and often difficult to understand","collocations":["a complex issue","an apartment complex","complex procedures"],"example":"The new apartment complex includes a gym and a swimming pool.","exampleZh":"新落成的公寓社區設有健身房和游泳池。","synonyms":["complicated","intricate"],"level":3,"theme":"房產與設施"},{"word":"compliance","pos":"n.","phonetic":"[kəmˈplaɪəns]","meaning":"遵守（法規）；合規；順從","definition":"the act of obeying a law, rule, or request","collocations":["in compliance with","compliance with regulations","ensure compliance"],"example":"All factories must operate in compliance with local safety regulations.","exampleZh":"所有工廠都必須遵守當地的安全法規營運。","synonyms":["conformity","adherence","obedience"],"level":5,"theme":"合約與法律"},{"word":"complicated","pos":"adj.","phonetic":"[ˈkɑmpləˌketɪd]","meaning":"複雜的；難懂的","definition":"involving many parts and difficult to understand or deal with","collocations":["a complicated process","complicated instructions","become complicated"],"example":"The visa application process is more complicated than we expected.","exampleZh":"簽證申請流程比我們預期的還要複雜。","synonyms":["complex","intricate"],"level":2,"theme":"日常與一般"},{"word":"compliment","pos":"n./v.","phonetic":"[ˈkɑmpləmənt]","meaning":"讚美；恭維；稱讚","definition":"a polite remark that expresses praise or admiration","collocations":["pay someone a compliment","receive compliments","compliment the chef"],"example":"The manager complimented the staff on their excellent customer service.","exampleZh":"經理稱讚員工出色的顧客服務。","synonyms":["praise","flattery"],"level":4,"theme":"日常與一般"},{"word":"complimentary","pos":"adj.","phonetic":"[ˌkɑmpləˈmɛntərɪ]","meaning":"免費贈送的；讚美的","definition":"given free of charge, especially as a courtesy to customers","collocations":["complimentary breakfast","complimentary shuttle service","complimentary tickets"],"example":"All guests receive a complimentary breakfast and free airport shuttle service.","exampleZh":"所有房客均可享有免費早餐及免費機場接駁服務。","synonyms":["free","courtesy"],"level":4,"theme":"餐飲與住宿"},{"word":"comply","pos":"v.","phonetic":"[kəmˈplaɪ]","meaning":"遵守；依從；服從","definition":"to act according to a rule, law, or request","collocations":["comply with regulations","fail to comply","comply fully with"],"example":"All employees must comply with the company's new security policies.","exampleZh":"全體員工都必須遵守公司新的資安政策。","synonyms":["obey","conform","adhere"],"level":5,"theme":"合約與法律"},{"word":"component","pos":"n.","phonetic":"[kəmˈponənt]","meaning":"零件；組成部分；元件","definition":"one of the parts that make up a machine, system, or product","collocations":["electronic components","a key component","component parts"],"example":"The factory imports electronic components from several countries in Asia.","exampleZh":"這家工廠從亞洲多個國家進口電子零件。","synonyms":["part","element"],"level":4,"theme":"生產與物流"},{"word":"comprehensive","pos":"adj.","phonetic":"[ˌkɑmprɪˈhɛnsɪv]","meaning":"全面的；完整的；綜合的","definition":"including everything or nearly everything that is needed","collocations":["comprehensive training","a comprehensive report","comprehensive insurance"],"example":"New employees receive comprehensive training during their first month.","exampleZh":"新進員工在到職第一個月會接受完整的訓練。","synonyms":["thorough","complete","extensive"],"level":4,"theme":"人事與職涯"},{"word":"compromise","pos":"n./v.","phonetic":"[ˈkɑmprəˌmaɪz]","meaning":"妥協；折衷方案；讓步","definition":"an agreement reached when each side gives up part of its demands","collocations":["reach a compromise","compromise on price","a fair compromise"],"example":"After lengthy negotiations, both parties finally reached a compromise on the contract terms.","exampleZh":"經過漫長的協商，雙方終於就合約條款達成妥協。","synonyms":["concession","settlement"],"level":4,"theme":"合約與法律"},{"word":"computer","pos":"n.","phonetic":"[kəmˈpjutɚ]","meaning":"電腦","definition":"an electronic machine that stores and processes information","collocations":["computer software","personal computer","computer skills"],"example":"Please shut down your computer before leaving the office each day.","exampleZh":"每天下班前請關閉您的電腦。","synonyms":[],"level":1,"theme":"科技與通訊"},{"word":"concentrate","pos":"v.","phonetic":"[ˈkɑnsṇˌtret]","meaning":"專心；集中（注意力）","definition":"to give all your attention to one thing","collocations":["concentrate on work","concentrate efforts on","concentrate fully"],"example":"It is hard to concentrate on work in a noisy office.","exampleZh":"在吵雜的辦公室裡很難專心工作。","synonyms":["focus"],"level":2,"theme":"辦公室與行政"},{"word":"concentration","pos":"n.","phonetic":"[ˌkɑnsṇˈtreʃən]","meaning":"專注力；專心；集中","definition":"the ability to give all your attention to something","collocations":["require concentration","lose concentration","a high level of concentration"],"example":"Finishing the detailed report required hours of intense concentration.","exampleZh":"完成這份詳盡的報告需要數小時的高度專注。","synonyms":["focus","attention"],"level":3,"theme":"辦公室與行政"},{"word":"concept","pos":"n.","phonetic":"[ˈkɑnsɛpt]","meaning":"概念；觀念；構想","definition":"an idea of what something is or how something should be done","collocations":["a marketing concept","a new concept","the concept of"],"example":"The design team presented a new concept for the product packaging.","exampleZh":"設計團隊提出了產品包裝的全新概念。","synonyms":["idea","notion"],"level":3,"theme":"行銷與銷售"},{"word":"concern","pos":"n./v.","phonetic":"[kənˈsɝn]","meaning":"擔憂；關切的事；與…有關","definition":"a feeling of worry, or something that worries you","collocations":["raise concerns","growing concern","address concerns"],"example":"The manager addressed employees' concerns about the upcoming restructuring.","exampleZh":"經理回應了員工對即將展開的組織重整的疑慮。","synonyms":["worry","anxiety"],"level":3,"theme":"企業經營"},{"word":"concerning","pos":"prep.","phonetic":"[kənˈsɝnɪŋ]","meaning":"關於；有關","definition":"about or relating to something","collocations":["inquiries concerning","concerning the new policy","information concerning the schedule"],"example":"Please contact human resources concerning any questions about your benefits.","exampleZh":"如有任何福利相關問題，請洽人力資源部。","synonyms":["regarding","about","respecting"],"level":4,"theme":"辦公室與行政"},{"word":"concert","pos":"n.","phonetic":"[ˈkɑnsɚt]","meaning":"音樂會；演唱會","definition":"a performance of music given in public","collocations":["attend a concert","concert hall","a live concert"],"example":"Tickets for the outdoor concert go on sale next Monday morning.","exampleZh":"戶外音樂會的門票將於下週一上午開賣。","synonyms":["performance","recital"],"level":1,"theme":"媒體與活動"},{"word":"concierge","pos":"n.","phonetic":"[ˌkɑnsɪˈɛrʒ]","meaning":"（飯店）禮賓人員；門房","definition":"a hotel employee who helps guests with services such as booking tours or taxis","collocations":["concierge desk","hotel concierge","concierge service"],"example":"The concierge can arrange airport transportation and restaurant reservations for guests.","exampleZh":"禮賓人員可為房客安排機場接送和餐廳訂位。","synonyms":[],"level":5,"theme":"餐飲與住宿"},{"word":"conclude","pos":"v.","phonetic":"[kənˈklud]","meaning":"結束；下結論；締結（協議）","definition":"to end something, or to decide something after considering all the information","collocations":["conclude a meeting","conclude an agreement","conclude that"],"example":"The chairman concluded the meeting with a summary of key decisions.","exampleZh":"主席以重點決議摘要為會議作結。","synonyms":["finish","end","close"],"level":3,"theme":"會議與簡報"},{"word":"conclusion","pos":"n.","phonetic":"[kənˈkluʒən]","meaning":"結論；結尾；締結","definition":"a decision or judgment reached after considering all the information","collocations":["draw a conclusion","in conclusion","reach a conclusion"],"example":"After reviewing the data, the committee reached a clear conclusion.","exampleZh":"在審閱數據之後，委員會得出了明確的結論。","synonyms":["deduction","ending"],"level":3,"theme":"會議與簡報"},{"word":"concrete","pos":"adj./n.","phonetic":"[ˈkɑnkrit]","meaning":"具體的；確實的；混凝土","definition":"based on facts and details; definite and specific","collocations":["concrete evidence","a concrete plan","concrete steps"],"example":"The consultant proposed concrete steps to reduce operating costs.","exampleZh":"顧問提出了降低營運成本的具體措施。","synonyms":["specific","tangible","definite"],"level":4,"theme":"企業經營"},{"word":"condition","pos":"n.","phonetic":"[kənˈdɪʃən]","meaning":"狀況；條件；（複數）環境","definition":"the state that something or someone is in","collocations":["in good condition","terms and conditions","working conditions"],"example":"The used equipment is still in excellent condition despite years of service.","exampleZh":"這批二手設備使用多年，狀況依然良好。","synonyms":["state","situation"],"level":2,"theme":"日常與一般"},{"word":"condominium","pos":"n.","phonetic":"[ˌkɑndəˈmɪnɪəm]","meaning":"（產權自有的）公寓大樓；公寓","definition":"an apartment in a large building that is owned by the person living in it","collocations":["a luxury condominium","condominium units","purchase a condominium"],"example":"The new condominium near the station sold out within two weeks.","exampleZh":"車站附近的新建公寓兩週內即銷售一空。","synonyms":["condo","apartment"],"level":4,"theme":"房產與設施"},{"word":"conduct","pos":"v./n.","phonetic":"[kənˈdʌkt]","meaning":"進行；執行；行為；指揮","definition":"to organize and carry out an activity such as a survey or research","collocations":["conduct a survey","conduct research","code of conduct"],"example":"The marketing team will conduct a survey to measure customer satisfaction.","exampleZh":"行銷團隊將進行問卷調查以評估顧客滿意度。","synonyms":["carry out","perform"],"level":3,"theme":"行銷與銷售"},{"word":"conference","pos":"n.","phonetic":"[ˈkɑnfərəns]","meaning":"會議；研討會；大會","definition":"a large formal meeting where people discuss shared interests or work topics","collocations":["attend a conference","conference room","press conference","annual conference"],"example":"The annual sales conference will be held in Chicago this October.","exampleZh":"年度業務大會將於今年十月在芝加哥舉行。","synonyms":["convention","meeting"],"level":2,"theme":"會議與簡報"},{"word":"confidence","pos":"n.","phonetic":"[ˈkɑnfədəns]","meaning":"信心；自信；信任","definition":"the feeling that you can trust or be sure about something or someone","collocations":["have confidence in","consumer confidence","build confidence"],"example":"Strong quarterly results boosted investors' confidence in the company.","exampleZh":"亮眼的季度業績提升了投資人對公司的信心。","synonyms":["trust","assurance","faith"],"level":3,"theme":"財務與會計"},{"word":"confident","pos":"adj.","phonetic":"[ˈkɑnfədənt]","meaning":"有信心的；確信的；自信的","definition":"sure that something will happen or that you can do something well","collocations":["confident in","feel confident","confident that"],"example":"The director is confident that the new branch will succeed.","exampleZh":"總監深具信心，認為新分店一定會成功。","synonyms":["assured","certain","positive"],"level":2,"theme":"日常與一般"},{"word":"confidential","pos":"adj.","phonetic":"[ˌkɑnfəˈdɛnʃəl]","meaning":"機密的；保密的","definition":"meant to be kept secret and not told to other people","collocations":["confidential information","strictly confidential","confidential documents"],"example":"Please keep all client records strictly confidential at all times.","exampleZh":"請務必隨時將所有客戶資料嚴格保密。","synonyms":["secret","private","classified"],"level":4,"theme":"辦公室與行政"},{"word":"confirm","pos":"v.","phonetic":"[kənˈfɝm]","meaning":"確認；證實","definition":"to state or show that something is definitely true or arranged","collocations":["confirm a reservation","confirm receipt","confirm the appointment"],"example":"Please call the hotel to confirm your reservation before arrival.","exampleZh":"抵達前請致電飯店確認您的訂房。","synonyms":["verify","validate"],"level":2,"theme":"餐飲與住宿"},{"word":"confirmation","pos":"n.","phonetic":"[ˌkɑnfɚˈmeʃən]","meaning":"確認；確認信；證實","definition":"a message or document that proves something is arranged or true","collocations":["confirmation number","booking confirmation","receive confirmation"],"example":"You will receive a confirmation email shortly after completing your booking.","exampleZh":"完成訂位後，您很快就會收到確認信。","synonyms":["verification","proof"],"level":3,"theme":"旅遊與交通"},{"word":"conflict","pos":"n./v.","phonetic":"[ˈkɑnflɪkt]","meaning":"衝突；（時間）撞期；牴觸","definition":"a serious disagreement, or a situation in which two things cannot happen together","collocations":["a scheduling conflict","conflict of interest","resolve a conflict"],"example":"Due to a scheduling conflict, the workshop has been moved to Thursday.","exampleZh":"由於時間撞期，工作坊已改到週四舉行。","synonyms":["disagreement","clash","dispute"],"level":3,"theme":"會議與簡報"},{"word":"congratulate","pos":"v.","phonetic":"[kənˈgrætʃəˌlet]","meaning":"恭喜；祝賀","definition":"to tell someone that you are happy about their success","collocations":["congratulate someone on","congratulate the winner","congratulate warmly"],"example":"The CEO congratulated the sales team on exceeding their annual targets.","exampleZh":"執行長祝賀業務團隊超越年度目標。","synonyms":["compliment","praise"],"level":2,"theme":"人事與職涯"},{"word":"congratulations","pos":"n.","phonetic":"[kənˌgrætʃəˈleʃənz]","meaning":"恭喜；祝賀（語）","definition":"an expression used to praise someone for a success or achievement","collocations":["congratulations on your promotion","offer congratulations","extend congratulations to"],"example":"Congratulations on your promotion to regional manager of the sales division.","exampleZh":"恭喜您升任業務部區域經理。","synonyms":[],"level":1,"theme":"人事與職涯"},{"word":"connect","pos":"v.","phonetic":"[kəˈnɛkt]","meaning":"連接；連線；轉接（電話）","definition":"to join two or more things together, or to link to a network or phone line","collocations":["connect to the Internet","connect the printer","a connecting flight"],"example":"I cannot connect to the office network from my laptop.","exampleZh":"我的筆電無法連上公司的網路。","synonyms":["link","join","attach"],"level":2,"theme":"科技與通訊"},{"word":"connection","pos":"n.","phonetic":"[kəˈnɛkʃən]","meaning":"連線；連接；轉乘班機；關聯","definition":"the state of being joined or linked, especially to a network or transportation service","collocations":["Internet connection","miss a connection","in connection with"],"example":"The hotel offers a stable Internet connection in every room.","exampleZh":"這家飯店每間客房都提供穩定的網路連線。","synonyms":["link","relation"],"level":2,"theme":"科技與通訊"},{"word":"consecutive","pos":"adj.","phonetic":"[kənˈsɛkjətɪv]","meaning":"連續的；不間斷的","definition":"following one after another without interruption","collocations":["three consecutive years","consecutive quarters","consecutive days"],"example":"The company has reported record profits for five consecutive quarters.","exampleZh":"該公司已連續五季創下獲利新高。","synonyms":["successive","continuous"],"level":5,"theme":"財務與會計"},{"word":"consensus","pos":"n.","phonetic":"[kənˈsɛnsəs]","meaning":"共識；一致的意見","definition":"a general agreement among all the members of a group","collocations":["reach a consensus","consensus on the issue","build consensus"],"example":"Board members finally reached a consensus on the merger proposal.","exampleZh":"董事會成員終於就合併案達成共識。","synonyms":["agreement","accord"],"level":5,"theme":"會議與簡報"},{"word":"consent","pos":"n./v.","phonetic":"[kənˈsɛnt]","meaning":"同意；准許；答應","definition":"permission or agreement to do something","collocations":["written consent","give consent","without prior consent"],"example":"Employees may not share client data without written consent from management.","exampleZh":"未經管理階層書面同意，員工不得外流客戶資料。","synonyms":["approval","permission","agreement"],"level":5,"theme":"合約與法律"},{"word":"consequently","pos":"adv.","phonetic":"[ˈkɑnsəˌkwɛntlɪ]","meaning":"因此；所以；結果","definition":"as a result of something that has just been mentioned","collocations":["consequently, the deadline was extended","and consequently increased costs"],"example":"The shipment was delayed; consequently, the product launch was postponed.","exampleZh":"貨運延誤，因此產品上市時間也順延了。","synonyms":["therefore","thus","hence"],"level":4,"theme":"日常與一般"},{"word":"consider","pos":"v.","phonetic":"[kənˈsɪdɚ]","meaning":"考慮；認為；把…視為","definition":"to think carefully about something before making a decision","collocations":["consider an offer","consider carefully","be considered for the position"],"example":"The committee will consider all applications before making a final decision.","exampleZh":"委員會將在做出最終決定前審慎考量所有申請案。","synonyms":["contemplate","weigh","regard"],"level":2,"theme":"人事與職涯"},{"word":"considerable","pos":"adj.","phonetic":"[kənˈsɪdərəbḷ]","meaning":"相當大的；可觀的","definition":"large in amount, size, or importance","collocations":["a considerable amount","considerable experience","considerable savings"],"example":"The new system saved the company a considerable amount of money.","exampleZh":"新系統為公司省下相當可觀的費用。","synonyms":["substantial","significant","sizable"],"level":4,"theme":"財務與會計"},{"word":"considerably","pos":"adv.","phonetic":"[kənˈsɪdərəblɪ]","meaning":"相當地；大幅地","definition":"by a large amount or degree","collocations":["increase considerably","considerably higher than","vary considerably"],"example":"Shipping costs have risen considerably over the past two years.","exampleZh":"過去兩年運費大幅上漲。","synonyms":["significantly","substantially","markedly"],"level":4,"theme":"日常與一般"},{"word":"considerate","pos":"adj.","phonetic":"[kənˈsɪdərɪt]","meaning":"體貼的；周到的","definition":"always thinking about other people's feelings and needs","collocations":["considerate of others","a considerate host","considerate staff"],"example":"Our considerate staff always respond quickly to guest requests.","exampleZh":"我們貼心的員工總是迅速回應房客的需求。","synonyms":["thoughtful","attentive","kind"],"level":4,"theme":"餐飲與住宿"},{"word":"consideration","pos":"n.","phonetic":"[kənˌsɪdəˈreʃən]","meaning":"考量；考慮；體貼","definition":"careful thought about something before making a decision","collocations":["take into consideration","under consideration","careful consideration"],"example":"Your proposal is currently under consideration by the management team.","exampleZh":"您的提案目前正由管理團隊審核考量中。","synonyms":["deliberation","thought"],"level":3,"theme":"企業經營"},{"word":"consist","pos":"v.","phonetic":"[kənˈsɪst]","meaning":"由…組成；在於","definition":"to be made up or formed of particular things or people","collocations":["consist of","consist mainly of","consist in"],"example":"The selection committee consists of five senior managers from different departments.","exampleZh":"遴選委員會由五位來自不同部門的資深主管組成。","synonyms":["comprise","be composed of"],"level":3,"theme":"企業經營"},{"word":"consistent","pos":"adj.","phonetic":"[kənˈsɪstənt]","meaning":"一致的；穩定的；始終如一的","definition":"always behaving, happening, or performing in the same way","collocations":["consistent with","consistent quality","consistent growth"],"example":"The factory maintains consistent quality across all its production lines.","exampleZh":"這座工廠所有生產線都維持一致的品質。","synonyms":["steady","constant","unchanging"],"level":4,"theme":"生產與物流"},{"word":"consistently","pos":"adv.","phonetic":"[kənˈsɪstəntlɪ]","meaning":"一貫地；持續地；始終如一地","definition":"in a way that does not change and stays the same over time","collocations":["consistently high quality","perform consistently","consistently ranked among the best"],"example":"The hotel has consistently received excellent reviews from business travelers.","exampleZh":"這家飯店一直獲得商務旅客的極佳評價。","synonyms":["steadily","invariably"],"level":3,"theme":"企業經營"},{"word":"consolidate","pos":"v.","phonetic":"[kənˈsɑləˌdet]","meaning":"整合；合併；鞏固","definition":"to combine several things into one in order to become more effective","collocations":["consolidate operations","consolidate debt","consolidate its market position"],"example":"The company plans to consolidate its regional offices into one headquarters.","exampleZh":"公司計劃將各地區辦公室整合為單一總部。","synonyms":["merge","combine","unify"],"level":5,"theme":"企業經營"},{"word":"constant","pos":"adj./n.","phonetic":"[ˈkɑnstənt]","meaning":"持續的；不斷的；固定不變的","definition":"happening all the time or staying at the same level without changing","collocations":["constant demand","constant supervision","remain constant"],"example":"The warehouse requires constant monitoring to maintain proper temperature levels.","exampleZh":"倉庫需要持續監控，以維持適當的溫度。","synonyms":["continuous","steady"],"level":3,"theme":"生產與物流"},{"word":"constantly","pos":"adv.","phonetic":"[ˈkɑnstəntlɪ]","meaning":"不斷地；經常地","definition":"all the time or very often, without stopping","collocations":["constantly changing","constantly updated","constantly improve"],"example":"Our website is constantly updated with the latest product information.","exampleZh":"我們的網站不斷更新最新的產品資訊。","synonyms":["continually","always"],"level":2,"theme":"科技與通訊"},{"word":"construct","pos":"v.","phonetic":"[kənˈstrʌkt]","meaning":"建造；興建；建構","definition":"to build something large such as a building, road, or bridge","collocations":["construct a building","newly constructed","construct a bridge"],"example":"The city will construct a new parking garage next to the convention center.","exampleZh":"市政府將在會議中心旁興建一座新的停車場。","synonyms":["build","erect"],"level":3,"theme":"房產與設施"},{"word":"construction","pos":"n.","phonetic":"[kənˈstrʌkʃən]","meaning":"建造；建設；建築工程","definition":"the work or process of building houses, offices, roads, or other structures","collocations":["under construction","construction site","construction project","construction company"],"example":"The main road is closed this week due to ongoing construction work.","exampleZh":"由於工程持續進行，主要道路本週封閉。","synonyms":["building"],"level":2,"theme":"房產與設施"},{"word":"constructive","pos":"adj.","phonetic":"[kənˈstrʌktɪv]","meaning":"建設性的；有助益的","definition":"useful and intended to help improve something rather than criticize it","collocations":["constructive feedback","constructive criticism","constructive suggestions"],"example":"The manager offered constructive feedback on the intern's first sales presentation.","exampleZh":"經理針對實習生的第一次銷售簡報提出了建設性的意見。","synonyms":["helpful","productive"],"level":4,"theme":"人事與職涯"},{"word":"consult","pos":"v.","phonetic":"[kənˈsʌlt]","meaning":"諮詢；請教；查閱","definition":"to ask a person for advice or look at a source for information","collocations":["consult a lawyer","consult the manual","consult with colleagues"],"example":"Please consult the employee handbook before submitting your vacation request.","exampleZh":"提交休假申請前，請先查閱員工手冊。","synonyms":["refer to"],"level":3,"theme":"辦公室與行政"},{"word":"consultant","pos":"n.","phonetic":"[kənˈsʌltənt]","meaning":"顧問","definition":"a person who is paid to give expert advice on a particular subject","collocations":["management consultant","hire a consultant","financial consultant"],"example":"We hired an outside consultant to improve our customer service procedures.","exampleZh":"我們聘請了一位外部顧問來改善客服流程。","synonyms":["adviser","specialist"],"level":3,"theme":"企業經營"},{"word":"consultation","pos":"n.","phonetic":"[ˌkɑnsəlˈteʃən]","meaning":"諮詢；商議；會診","definition":"a meeting with an expert to discuss something or get advice","collocations":["free consultation","in consultation with","schedule a consultation"],"example":"The clinic offers a free consultation for all first-time patients.","exampleZh":"這家診所為所有初診病患提供免費諮詢。","synonyms":["discussion","meeting"],"level":4,"theme":"醫療與保險"},{"word":"consulting","pos":"n./adj.","phonetic":"[kənˈsʌltɪŋ]","meaning":"顧問業；諮詢服務；顧問的","definition":"the business of giving expert advice to companies for a fee","collocations":["consulting firm","consulting services","management consulting"],"example":"She left her corporate job to start her own consulting firm.","exampleZh":"她辭去了大公司的工作，自行創立顧問公司。","synonyms":["advisory"],"level":4,"theme":"企業經營"},{"word":"consume","pos":"v.","phonetic":"[kənˈsjum]","meaning":"消耗；消費；吃、喝","definition":"to use fuel, energy, or time, or to eat or drink something","collocations":["consume energy","consume less fuel","time-consuming"],"example":"The new machines consume far less electricity than the older models.","exampleZh":"新機器的耗電量遠低於舊機型。","synonyms":["use up","expend"],"level":3,"theme":"購物與消費"},{"word":"consumer","pos":"n.","phonetic":"[kənˈsjumɚ]","meaning":"消費者","definition":"a person who buys goods or services for personal use","collocations":["consumer demand","consumer goods","consumer protection"],"example":"The survey shows that consumers prefer eco-friendly packaging over plastic.","exampleZh":"調查顯示，消費者偏好環保包裝勝過塑膠包裝。","synonyms":["buyer","customer","purchaser"],"level":2,"theme":"購物與消費"},{"word":"consumption","pos":"n.","phonetic":"[kənˈsʌmpʃən]","meaning":"消耗量；消費；食用","definition":"the amount of something that is used, or the act of using it","collocations":["energy consumption","fuel consumption","reduce consumption"],"example":"The factory reduced its energy consumption by twenty percent last year.","exampleZh":"這座工廠去年將能源消耗量降低了百分之二十。","synonyms":["use","usage"],"level":4,"theme":"生產與物流"},{"word":"contact","pos":"n./v.","phonetic":"[ˈkɑntækt]","meaning":"聯絡；聯繫；接觸","definition":"to communicate with someone by phone, email, or letter","collocations":["contact information","contact customer service","stay in contact with"],"example":"Please contact our customer service department if you have any questions.","exampleZh":"如有任何問題，請與我們的客服部門聯絡。","synonyms":["reach","get in touch with"],"level":1,"theme":"辦公室與行政"},{"word":"contain","pos":"v.","phonetic":"[kənˈten]","meaning":"包含；含有；容納","definition":"to have something inside or to include something as a part","collocations":["contain ingredients","contain important information","contain errors"],"example":"The package contains all the parts needed to assemble the bookshelf.","exampleZh":"包裹內含組裝書架所需的所有零件。","synonyms":["include","hold"],"level":2,"theme":"日常與一般"},{"word":"container","pos":"n.","phonetic":"[kənˈtenɚ]","meaning":"貨櫃；容器","definition":"a large metal box for transporting goods, or any object used for holding things","collocations":["shipping container","storage container","plastic container"],"example":"The shipping containers will arrive at the port on Thursday morning.","exampleZh":"貨櫃將於週四上午抵達港口。","synonyms":["receptacle"],"level":2,"theme":"生產與物流"},{"word":"contemporary","pos":"adj./n.","phonetic":"[kənˈtɛmpəˌrɛrɪ]","meaning":"當代的；現代的；同時代的人","definition":"belonging to the present time or existing now","collocations":["contemporary art","contemporary design","contemporary furniture"],"example":"The gallery is hosting an exhibition of contemporary art next month.","exampleZh":"美術館下個月將舉辦當代藝術展。","synonyms":["modern","current"],"level":5,"theme":"媒體與活動"},{"word":"content","pos":"n./adj.","phonetic":"[ˈkɑntɛnt]","meaning":"內容；目錄；（形）滿意的","definition":"the information or material contained in a document, website, or program","collocations":["table of contents","digital content","the content of the report"],"example":"The marketing team creates digital content for the company's social media pages.","exampleZh":"行銷團隊為公司的社群媒體頁面製作數位內容。","synonyms":["material","substance"],"level":3,"theme":"媒體與活動"},{"word":"contest","pos":"n./v.","phonetic":"[ˈkɑntɛst]","meaning":"比賽；競賽；（動）質疑、角逐","definition":"a competition in which people try to win a prize","collocations":["enter a contest","photo contest","win a contest"],"example":"Employees are invited to enter the annual photography contest by Friday.","exampleZh":"誠邀員工在週五前報名參加年度攝影比賽。","synonyms":["competition"],"level":2,"theme":"媒體與活動"},{"word":"continue","pos":"v.","phonetic":"[kənˈtɪnju]","meaning":"繼續；持續","definition":"to keep doing something or keep happening without stopping","collocations":["continue to grow","continue working","continue the discussion"],"example":"The meeting will continue after a short lunch break at noon.","exampleZh":"會議將在中午短暫的午餐休息後繼續進行。","synonyms":["proceed","carry on"],"level":1,"theme":"會議與簡報"},{"word":"contract","pos":"n./v.","phonetic":"[ˈkɑntrækt]","meaning":"合約；契約；（動）簽約、收縮","definition":"a legal written agreement between two people or companies","collocations":["sign a contract","contract terms","renew a contract","under contract"],"example":"Both parties signed the contract after reviewing the payment terms carefully.","exampleZh":"雙方在仔細審閱付款條件後簽署了合約。","synonyms":["agreement","deal"],"level":2,"theme":"合約與法律"},{"word":"contractor","pos":"n.","phonetic":"[ˈkɑntræktɚ]","meaning":"承包商；包商","definition":"a person or company hired to do work, especially building work","collocations":["general contractor","independent contractor","hire a contractor"],"example":"The contractor promised to finish the office renovation by the end of May.","exampleZh":"承包商承諾在五月底前完成辦公室整修。","synonyms":["builder"],"level":4,"theme":"房產與設施"},{"word":"contrast","pos":"n./v.","phonetic":"[ˈkɑntræst]","meaning":"對比；對照；（動）形成對比","definition":"an obvious difference between two or more things","collocations":["in contrast to","by contrast","a sharp contrast"],"example":"In contrast to last year, sales in the Asian market rose sharply.","exampleZh":"與去年相比，亞洲市場的銷售額大幅成長。","synonyms":["difference","distinction"],"level":4,"theme":"日常與一般"},{"word":"contribute","pos":"v.","phonetic":"[kənˈtrɪbjut]","meaning":"貢獻；捐助；促成；投稿","definition":"to give money, ideas, or help in order to achieve something together","collocations":["contribute to the success","contribute funds","contribute ideas"],"example":"Every team member contributed valuable ideas to the new marketing campaign.","exampleZh":"每位團隊成員都為新的行銷活動貢獻了寶貴的想法。","synonyms":["donate","give"],"level":3,"theme":"人事與職涯"},{"word":"contribution","pos":"n.","phonetic":"[ˌkɑntrəˈbjuʃən]","meaning":"貢獻；捐款；投稿","definition":"something you give or do to help make something successful","collocations":["make a contribution","significant contribution","charitable contribution"],"example":"She received an award for her outstanding contribution to the company.","exampleZh":"她因對公司的傑出貢獻而獲頒獎項。","synonyms":["donation"],"level":3,"theme":"人事與職涯"},{"word":"control","pos":"n./v.","phonetic":"[kənˈtrol]","meaning":"控制；管理；管制","definition":"the power to direct or manage something, or the act of doing so","collocations":["quality control","under control","control costs"],"example":"The quality control team inspects every product before it leaves the factory.","exampleZh":"品管團隊會在每項產品出廠前進行檢驗。","synonyms":["manage","regulate"],"level":1,"theme":"生產與物流"},{"word":"convenience","pos":"n.","phonetic":"[kənˈvinjəns]","meaning":"方便；便利；便利設施","definition":"the quality of being easy to use or suitable for your needs","collocations":["at your earliest convenience","convenience store","for your convenience"],"example":"Please reply at your earliest convenience so we can confirm the booking.","exampleZh":"請盡早回覆，以便我們確認訂位。","synonyms":["ease"],"level":3,"theme":"辦公室與行政"},{"word":"convenient","pos":"adj.","phonetic":"[kənˈvinjənt]","meaning":"方便的；便利的","definition":"suitable for your needs and easy to use, do, or reach","collocations":["convenient location","convenient time","convenient for commuters"],"example":"The hotel is convenient for guests attending events at the convention center.","exampleZh":"這家飯店對參加會議中心活動的旅客來說十分方便。","synonyms":["handy","accessible"],"level":2,"theme":"旅遊與交通"},{"word":"conveniently","pos":"adv.","phonetic":"[kənˈvinjəntlɪ]","meaning":"方便地；便利地","definition":"in a way that is easy, useful, or suitable","collocations":["conveniently located","conveniently situated","conveniently close to"],"example":"Our new branch is conveniently located near the central train station.","exampleZh":"我們的新分店位置便利，鄰近中央車站。","synonyms":["handily"],"level":3,"theme":"房產與設施"},{"word":"convention","pos":"n.","phonetic":"[kənˈvɛnʃən]","meaning":"大會；會議；慣例；公約","definition":"a large formal meeting of people who share the same profession or interest","collocations":["convention center","attend a convention","annual convention"],"example":"Thousands of dealers will attend the auto convention in Chicago next week.","exampleZh":"數千名經銷商下週將參加在芝加哥舉行的汽車大會。","synonyms":["conference","assembly"],"level":3,"theme":"會議與簡報"},{"word":"conventional","pos":"adj.","phonetic":"[kənˈvɛnʃənl]","meaning":"傳統的；慣例的；常規的","definition":"following the usual or traditional way of doing things","collocations":["conventional methods","conventional wisdom","conventional oven"],"example":"The startup abandoned conventional advertising in favor of social media campaigns.","exampleZh":"這家新創公司放棄傳統廣告，改採社群媒體宣傳。","synonyms":["traditional","standard"],"level":4,"theme":"企業經營"},{"word":"conversation","pos":"n.","phonetic":"[ˌkɑnvɚˈseʃən]","meaning":"對話；交談","definition":"an informal talk between two or more people","collocations":["have a conversation","phone conversation","a conversation with a client"],"example":"I had a brief conversation with the manager about the schedule change.","exampleZh":"我和經理針對班表調整簡短談了一下。","synonyms":["talk","discussion"],"level":1,"theme":"日常與一般"},{"word":"conversion","pos":"n.","phonetic":"[kənˈvɝʒən]","meaning":"轉換；改建；改變信仰","definition":"the process of changing something from one form or use to another","collocations":["currency conversion","conversion rate","the conversion of the building"],"example":"The conversion of the old factory into offices will take eight months.","exampleZh":"將舊工廠改建為辦公室的工程需要八個月。","synonyms":["transformation","change"],"level":5,"theme":"房產與設施"},{"word":"convert","pos":"v./n.","phonetic":"[kənˈvɝt]","meaning":"轉換；改變；改建","definition":"to change something into a different form or use it for a different purpose","collocations":["convert currency","convert a file","convert the space into"],"example":"You can convert the document into a PDF before sending it out.","exampleZh":"你可以先將文件轉成 PDF 檔再寄出。","synonyms":["transform","change"],"level":4,"theme":"科技與通訊"},{"word":"convey","pos":"v.","phonetic":"[kənˈve]","meaning":"傳達；表達；運送","definition":"to communicate ideas or feelings to someone, or to transport something","collocations":["convey a message","convey information","convey one's thanks"],"example":"Please convey my sincere thanks to everyone who organized the farewell party.","exampleZh":"請代我向籌辦歡送會的每位同仁致上誠摯的謝意。","synonyms":["communicate","express","transmit"],"level":5,"theme":"辦公室與行政"},{"word":"convince","pos":"v.","phonetic":"[kənˈvɪns]","meaning":"說服；使相信","definition":"to make someone believe something is true or persuade them to do something","collocations":["convince customers","convince the board","convince someone to buy"],"example":"The sales team convinced the client to extend the service agreement.","exampleZh":"銷售團隊說服客戶延長服務合約。","synonyms":["persuade"],"level":3,"theme":"行銷與銷售"},{"word":"cook","pos":"v./n.","phonetic":"[kʊk]","meaning":"烹調；煮；廚師","definition":"to prepare food by heating it, or a person who prepares food","collocations":["cook a meal","head cook","cook dinner for guests"],"example":"The chef will cook a special menu for the company banquet.","exampleZh":"主廚將為公司晚宴烹調特製菜單。","synonyms":["prepare"],"level":1,"theme":"餐飲與住宿"},{"word":"cooperate","pos":"v.","phonetic":"[koˈɑpəˌret]","meaning":"合作；配合","definition":"to work together with other people or organizations to achieve a shared goal","collocations":["cooperate with","cooperate closely","cooperate fully"],"example":"The two firms agreed to cooperate on developing new battery technology.","exampleZh":"這兩家公司同意合作開發新的電池技術。","synonyms":["collaborate"],"level":3,"theme":"企業經營"},{"word":"cooperation","pos":"n.","phonetic":"[koˌɑpəˈreʃən]","meaning":"合作；配合","definition":"the act of working together with others to achieve something","collocations":["in cooperation with","close cooperation","thank you for your cooperation"],"example":"We appreciate your cooperation while the elevators are under repair.","exampleZh":"電梯維修期間，感謝您的配合。","synonyms":["collaboration","teamwork"],"level":2,"theme":"辦公室與行政"},{"word":"cooperative","pos":"adj./n.","phonetic":"[koˈɑpəˌretɪv]","meaning":"配合的；合作的；合作社","definition":"willing to work with others in a helpful way","collocations":["cooperative effort","cooperative agreement","remain cooperative"],"example":"The staff were extremely cooperative during the office relocation last month.","exampleZh":"上個月辦公室搬遷期間，員工們都非常配合。","synonyms":["helpful","collaborative"],"level":4,"theme":"人事與職涯"},{"word":"coordinate","pos":"v./n.","phonetic":"[koˈɔrdnˌet]","meaning":"協調；統籌；（名）座標","definition":"to organize the different parts of an activity so that they work well together","collocations":["coordinate schedules","coordinate efforts","coordinate with vendors"],"example":"She will coordinate travel arrangements for everyone attending the trade show.","exampleZh":"她將為所有參加商展的人員統籌差旅安排。","synonyms":["organize","arrange"],"level":4,"theme":"辦公室與行政"},{"word":"coordination","pos":"n.","phonetic":"[koˌɔrdnˈeʃən]","meaning":"協調；統籌","definition":"the organization of people or things so that they work together effectively","collocations":["in coordination with","close coordination","coordination between departments"],"example":"Good coordination between departments helped the product launch go smoothly.","exampleZh":"部門之間的良好協調讓產品上市進行得很順利。","synonyms":["organization"],"level":4,"theme":"企業經營"},{"word":"coordinator","pos":"n.","phonetic":"[koˈɔrdnˌetɚ]","meaning":"協調人；統籌者；專員","definition":"a person whose job is to organize activities and the people involved in them","collocations":["event coordinator","project coordinator","marketing coordinator"],"example":"The event coordinator confirmed the catering order for Friday's reception.","exampleZh":"活動統籌人員已確認週五酒會的餐飲訂單。","synonyms":["organizer"],"level":3,"theme":"人事與職涯"},{"word":"copier","pos":"n.","phonetic":"[ˈkɑpɪɚ]","meaning":"影印機","definition":"a machine that makes paper copies of documents","collocations":["color copier","copier paper","the copier is jammed"],"example":"The copier on the third floor is out of order again.","exampleZh":"三樓的影印機又故障了。","synonyms":["photocopier","copy machine"],"level":2,"theme":"辦公室與行政"},{"word":"copy","pos":"n./v.","phonetic":"[ˈkɑpɪ]","meaning":"副本；影本；一份（書刊）；複製","definition":"a thing made to be exactly like another, or to make such a thing","collocations":["make a copy","a copy of the contract","copy and paste"],"example":"Please make three copies of the agenda before the board meeting.","exampleZh":"請在董事會議前將議程影印三份。","synonyms":["duplicate","reproduction"],"level":1,"theme":"辦公室與行政"},{"word":"cordially","pos":"adv.","phonetic":"[ˈkɔrdʒəlɪ]","meaning":"誠摯地；熱誠地","definition":"in a friendly, polite, and sincere way","collocations":["be cordially invited","cordially welcome","cordially greet"],"example":"You are cordially invited to attend our annual awards banquet.","exampleZh":"誠摯邀請您參加我們的年度頒獎晚宴。","synonyms":["warmly","graciously"],"level":5,"theme":"媒體與活動"},{"word":"corner","pos":"n./v.","phonetic":"[ˈkɔrnɚ]","meaning":"轉角；角落；（動）壟斷（市場）","definition":"the place where two roads, walls, or edges meet","collocations":["on the corner of","around the corner","corner office"],"example":"The new coffee shop is on the corner of Fifth Avenue and Main Street.","exampleZh":"新開的咖啡店位於第五大道與主街的轉角。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"cornerstone","pos":"n.","phonetic":"[ˈkɔrnɚˌston]","meaning":"基石；基礎；奠基石","definition":"the most important part that something else depends on","collocations":["the cornerstone of the strategy","lay the cornerstone","a cornerstone of success"],"example":"Excellent customer service remains the cornerstone of our business philosophy.","exampleZh":"卓越的顧客服務始終是我們經營理念的基石。","synonyms":["foundation","basis"],"level":6,"theme":"企業經營"},{"word":"corporate","pos":"adj.","phonetic":"[ˈkɔrpərɪt]","meaning":"公司的；企業的；法人的","definition":"relating to a large company or to companies in general","collocations":["corporate culture","corporate headquarters","corporate clients"],"example":"All corporate clients receive a discount on bulk orders over five hundred dollars.","exampleZh":"所有企業客戶大量訂購滿五百美元即可享折扣。","synonyms":[],"level":3,"theme":"企業經營"},{"word":"corporation","pos":"n.","phonetic":"[ˌkɔrpəˈreʃən]","meaning":"公司；企業；法人","definition":"a large company or business organization recognized by law as a single unit","collocations":["multinational corporation","large corporation","form a corporation"],"example":"The corporation announced plans to open ten new branches overseas.","exampleZh":"該公司宣布計劃在海外開設十家新分店。","synonyms":["company","firm","enterprise"],"level":3,"theme":"企業經營"},{"word":"correct","pos":"adj./v.","phonetic":"[kəˈrɛkt]","meaning":"正確的；（動）改正、糾正","definition":"accurate and without mistakes, or to make something right","collocations":["the correct answer","correct an error","correct information"],"example":"Please make sure your contact information is correct before submitting the form.","exampleZh":"送出表單前，請確認您的聯絡資訊正確無誤。","synonyms":["accurate","right"],"level":1,"theme":"日常與一般"},{"word":"correctly","pos":"adv.","phonetic":"[kəˈrɛktlɪ]","meaning":"正確地","definition":"in a way that is accurate and without mistakes","collocations":["fill out the form correctly","function correctly","correctly installed"],"example":"Make sure the printer driver is installed correctly before printing the reports.","exampleZh":"列印報表前，請確認印表機驅動程式已正確安裝。","synonyms":["accurately","properly"],"level":2,"theme":"日常與一般"},{"word":"correspond","pos":"v.","phonetic":"[ˌkɔrəˈspɑnd]","meaning":"相符；一致；通信","definition":"to match or be the same as something else, or to exchange letters or emails","collocations":["correspond to the records","correspond with clients","correspond exactly"],"example":"The invoice numbers should correspond to the entries in the shipping records.","exampleZh":"發票號碼應與出貨紀錄中的項目相符。","synonyms":["match","agree"],"level":5,"theme":"財務與會計"},{"word":"correspondence","pos":"n.","phonetic":"[ˌkɔrəˈspɑndəns]","meaning":"往來信件；通信；一致","definition":"letters or emails exchanged between people, or the activity of writing them","collocations":["business correspondence","handle correspondence","email correspondence"],"example":"The assistant handles all correspondence between the firm and its overseas clients.","exampleZh":"這位助理負責處理公司與海外客戶之間的所有往來信件。","synonyms":["letters","mail"],"level":5,"theme":"辦公室與行政"},{"word":"corridor","pos":"n.","phonetic":"[ˈkɔrədɚ]","meaning":"走廊；通道","definition":"a long passage in a building with doors and rooms on both sides","collocations":["along the corridor","at the end of the corridor","hotel corridor"],"example":"The meeting room is at the end of the corridor on your left.","exampleZh":"會議室在走廊盡頭，就在您的左手邊。","synonyms":["hallway","passage"],"level":3,"theme":"房產與設施"},{"word":"cost","pos":"n./v.","phonetic":"[kɔst]","meaning":"成本；費用；（動）花費","definition":"the amount of money needed to buy, do, or make something","collocations":["cut costs","production costs","at no extra cost","shipping costs"],"example":"The airline raised ticket prices to cover rising fuel costs.","exampleZh":"這家航空公司調漲票價，以因應不斷上升的燃油成本。","synonyms":["expense","price"],"level":1,"theme":"財務與會計"},{"word":"cost-effective","pos":"adj.","phonetic":"[ˌkɔstɪˈfɛktɪv]","meaning":"具成本效益的；划算的","definition":"giving good value or profit compared with the money spent","collocations":["cost-effective solution","a cost-effective way","highly cost-effective"],"example":"Shipping by rail is a more cost-effective option for heavy goods.","exampleZh":"對於重型貨物而言，鐵路運輸是更具成本效益的選擇。","synonyms":["economical"],"level":5,"theme":"財務與會計"},{"word":"costly","pos":"adj.","phonetic":"[ˈkɔstlɪ]","meaning":"昂貴的；代價高的","definition":"costing a lot of money or causing serious loss","collocations":["costly mistake","costly repairs","costly delays"],"example":"Regular equipment maintenance helps the factory avoid costly repairs later.","exampleZh":"定期保養設備有助於工廠日後避免昂貴的維修費用。","synonyms":["expensive","pricey"],"level":4,"theme":"財務與會計"},{"word":"council","pos":"n.","phonetic":"[ˈkaʊnsl]","meaning":"議會；委員會；理事會","definition":"a group of people elected or chosen to make decisions or give advice","collocations":["city council","council meeting","council member"],"example":"The city council approved funding for the new public library.","exampleZh":"市議會通過了新公立圖書館的經費。","synonyms":["committee","board"],"level":3,"theme":"日常與一般"},{"word":"counseling","pos":"n.","phonetic":"[ˈkaʊnsəlɪŋ]","meaning":"諮商；輔導","definition":"professional advice given to someone to help them deal with problems","collocations":["career counseling","counseling services","financial counseling"],"example":"The company offers free career counseling to all full-time employees.","exampleZh":"公司為所有正職員工提供免費職涯諮商。","synonyms":["guidance","advising"],"level":4,"theme":"人事與職涯"},{"word":"counselor","pos":"n.","phonetic":"[ˈkaʊnsəlɚ]","meaning":"顧問；諮商師","definition":"a person trained to give advice on personal or professional problems","collocations":["career counselor","legal counselor","school counselor"],"example":"Please make an appointment with the career counselor before Friday.","exampleZh":"請在週五前與職涯顧問預約。","synonyms":["adviser","consultant"],"level":4,"theme":"人事與職涯"},{"word":"count","pos":"v./n.","phonetic":"[kaʊnt]","meaning":"計算；數；總數","definition":"to calculate the total number of things or people in a group","collocations":["count the votes","head count","count on"],"example":"Please count the boxes before signing the delivery receipt.","exampleZh":"簽收前請先清點箱子的數量。","synonyms":["calculate","tally"],"level":1,"theme":"日常與一般"},{"word":"counter","pos":"n./v.","phonetic":"[ˈkaʊntɚ]","meaning":"櫃檯；計數器；反駁","definition":"a long flat surface where customers are served in a shop, bank, or restaurant","collocations":["check-in counter","ticket counter","over the counter"],"example":"Please pick up your boarding pass at the check-in counter.","exampleZh":"請到報到櫃檯領取您的登機證。","synonyms":["desk"],"level":2,"theme":"旅遊與交通"},{"word":"counterpart","pos":"n.","phonetic":"[ˈkaʊntɚˌpɑrt]","meaning":"對應的人（或物）；相對職位者","definition":"a person or thing that has the same position or function as another in a different place","collocations":["overseas counterpart","meet with one's counterpart"],"example":"Our sales director will meet her Japanese counterpart next week.","exampleZh":"我們的業務總監下週將會見她的日本對口主管。","synonyms":["equivalent","peer"],"level":5,"theme":"企業經營"},{"word":"country","pos":"n.","phonetic":"[ˈkʌntrɪ]","meaning":"國家；鄉村","definition":"an area of land that has its own government and borders","collocations":["foreign country","across the country","country of origin"],"example":"The company exports its products to more than thirty countries.","exampleZh":"這家公司將產品外銷到三十多個國家。","synonyms":["nation"],"level":1,"theme":"日常與一般"},{"word":"couple","pos":"n.","phonetic":"[ˈkʌpl]","meaning":"一對；夫妻；幾個","definition":"two people or things together, or a small number of something","collocations":["a couple of days","married couple"],"example":"The report will be ready in a couple of days.","exampleZh":"報告再過幾天就會完成。","synonyms":["pair"],"level":1,"theme":"日常與一般"},{"word":"coupon","pos":"n.","phonetic":"[ˈkupɑn]","meaning":"折價券；優惠券","definition":"a printed ticket that gives you a discount or free item when you buy something","collocations":["discount coupon","redeem a coupon","coupon code"],"example":"Customers can redeem this coupon for ten percent off any purchase.","exampleZh":"顧客可使用這張折價券享任何消費九折優惠。","synonyms":["voucher"],"level":2,"theme":"購物與消費"},{"word":"courier","pos":"n.","phonetic":"[ˈkɝɪɚ]","meaning":"快遞員；快遞公司","definition":"a person or company that delivers documents or packages quickly","collocations":["courier service","send by courier","overnight courier"],"example":"The contract was sent by courier to arrive before the deadline.","exampleZh":"合約以快遞寄出，以便在期限前送達。","synonyms":["messenger"],"level":4,"theme":"生產與物流"},{"word":"course","pos":"n.","phonetic":"[kors]","meaning":"課程；過程；一道菜","definition":"a series of lessons on a subject, or the way something develops over time","collocations":["training course","of course","in the course of"],"example":"All new hires must complete an online safety training course.","exampleZh":"所有新進員工都必須完成線上安全訓練課程。","synonyms":["class","program"],"level":1,"theme":"人事與職涯"},{"word":"court","pos":"n.","phonetic":"[kort]","meaning":"法院；法庭；球場","definition":"the place where legal cases are heard and decided","collocations":["go to court","court order","tennis court"],"example":"The two companies settled the dispute before going to court.","exampleZh":"兩家公司在上法院前就爭議達成和解。","synonyms":["tribunal"],"level":2,"theme":"合約與法律"},{"word":"courteous","pos":"adj.","phonetic":"[ˈkɝtɪəs]","meaning":"有禮貌的；殷勤的","definition":"polite and showing respect for other people","collocations":["courteous service","courteous staff"],"example":"Our hotel staff are trained to be courteous to every guest.","exampleZh":"我們的飯店員工受過訓練，對每位房客都彬彬有禮。","synonyms":["polite","respectful"],"level":5,"theme":"餐飲與住宿"},{"word":"courtesy","pos":"n.","phonetic":"[ˈkɝtəsɪ]","meaning":"禮貌；殷勤；免費招待","definition":"polite behavior, or something provided free as a polite gesture","collocations":["courtesy shuttle","as a courtesy","courtesy call"],"example":"The hotel provides a courtesy shuttle to the airport every hour.","exampleZh":"飯店每小時提供一班免費機場接駁車。","synonyms":["politeness"],"level":4,"theme":"餐飲與住宿"},{"word":"cover","pos":"v./n.","phonetic":"[ˈkʌvɚ]","meaning":"涵蓋；支付；封面；掩蓋","definition":"to include or deal with something, or to pay for a cost","collocations":["cover the cost","insurance covers","cover letter"],"example":"The company will cover all travel expenses for the conference.","exampleZh":"公司將支付這次會議的所有差旅費用。","synonyms":["include","pay for"],"level":1,"theme":"日常與一般"},{"word":"coverage","pos":"n.","phonetic":"[ˈkʌvərɪdʒ]","meaning":"保險範圍；報導；涵蓋範圍","definition":"the protection an insurance policy provides, or the reporting of news","collocations":["insurance coverage","media coverage","full coverage"],"example":"This policy provides full coverage for medical expenses abroad.","exampleZh":"這份保單提供海外醫療費用的全額保障。","synonyms":["protection"],"level":4,"theme":"醫療與保險"},{"word":"coworker","pos":"n.","phonetic":"[ˈkoˌwɝkɚ]","meaning":"同事","definition":"a person who works with you at the same company","collocations":["helpful coworker","get along with coworkers"],"example":"My coworkers organized a farewell party for the retiring manager.","exampleZh":"我的同事們為即將退休的經理辦了歡送會。","synonyms":["colleague"],"level":2,"theme":"辦公室與行政"},{"word":"craft","pos":"n. / v.","phonetic":"[kræft]","meaning":"工藝；技藝；精心製作","definition":"an activity involving skill in making things by hand","collocations":["arts and crafts","craft a plan","traditional craft"],"example":"She learned the craft of pottery from her grandmother.","exampleZh":"她向祖母學習製陶的技藝。","synonyms":["skill","art"],"level":3,"theme":"媒體與活動"},{"word":"create","pos":"v.","phonetic":"[krɪˈet]","meaning":"創造；創作；引起","definition":"to make something new to exist","collocations":["create a problem","create jobs","create art"],"example":"The artist created a beautiful painting.","exampleZh":"這位藝術家創作了一幅美麗的畫。","synonyms":["make","produce"],"level":2,"theme":"媒體與活動"},{"word":"creative","pos":"adj.","phonetic":"[krɪˈetɪv]","meaning":"有創意的；創造性的","definition":"having or showing an ability to make new things or think of new ideas","collocations":["creative writing","creative thinking","a creative solution"],"example":"She is very creative when it comes to solving problems.","exampleZh":"在解決問題方面她非常有創意。","synonyms":["imaginative","inventive"],"level":3,"theme":"日常與一般"},{"word":"credential","pos":"n.","phonetic":"[krɪˈdɛnʃəl]","meaning":"資格證明；憑證","definition":"a qualification or achievement that shows a person is suitable for a job","collocations":["professional credentials","verify credentials","login credentials"],"example":"Applicants should list their credentials at the top of the resume.","exampleZh":"應徵者應將資格證明列在履歷的最上方。","synonyms":["qualification"],"level":5,"theme":"人事與職涯"},{"word":"credit","pos":"n. / v.","phonetic":"[ˈkrɛdɪt]","meaning":"信用；學分；歸功於","definition":"the ability to buy something now and pay later; recognition for an achievement","collocations":["credit card","take credit for","school credit"],"example":"He paid for the trip with a credit card.","exampleZh":"他用信用卡支付了這趟旅行的費用。","synonyms":[],"level":3,"theme":"財務與會計"},{"word":"crew","pos":"n.","phonetic":"[kru]","meaning":"全體船員；工作團隊","definition":"a group of people who work together, especially on a ship, plane, or film","collocations":["ship's crew","film crew","flight crew"],"example":"The plane's crew welcomed the passengers on board.","exampleZh":"飛機的機組人員歡迎乘客登機。","synonyms":["team","staff"],"level":3,"theme":"人事與職涯"},{"word":"criterion","pos":"n.","phonetic":"[kraɪˈtɪrɪən]","meaning":"標準；準則（複數 criteria）","definition":"a standard used for judging or deciding something","collocations":["meet the criteria","selection criteria","evaluation criterion"],"example":"Candidates must meet all the criteria listed in the job posting.","exampleZh":"應徵者必須符合職缺公告中列出的所有條件。","synonyms":["standard","benchmark"],"level":5,"theme":"人事與職涯"},{"word":"critic","pos":"n.","phonetic":"[ˈkrɪtɪk]","meaning":"評論家；批評者","definition":"a person who gives opinions about the good and bad qualities of something","collocations":["film critic","harsh critic","art critic"],"example":"The food critic praised the new restaurant.","exampleZh":"這位美食評論家稱讚了這家新餐廳。","synonyms":["reviewer"],"level":4,"theme":"媒體與活動"},{"word":"critical","pos":"adj.","phonetic":"[ˈkrɪtɪkl̩]","meaning":"批評的；關鍵的；危急的","definition":"expressing disapproval, or extremely important, or very serious","collocations":["critical thinking","critical condition","a critical moment"],"example":"The patient is in critical condition.","exampleZh":"這位病人情況危急。","synonyms":["crucial","vital"],"level":4,"theme":"日常與一般"},{"word":"criticize","pos":"v.","phonetic":"[ˈkrɪtəˌsaɪz]","meaning":"批評；指責","definition":"to express disapproval of someone or something","collocations":["criticize harshly","criticize a decision"],"example":"The teacher criticized his careless mistakes.","exampleZh":"老師批評了他的粗心錯誤。","synonyms":["condemn","blame"],"level":4,"theme":"溝通與語言"},{"word":"crop","pos":"n. / v.","phonetic":"[krɑp]","meaning":"農作物；收成；剪裁","definition":"a plant grown in large amounts, especially for food","collocations":["harvest a crop","crop rotation","crop failure"],"example":"Farmers harvested the rice crop in autumn.","exampleZh":"農夫在秋天收割了稻米。","synonyms":["harvest"],"level":3,"theme":"日常與一般"},{"word":"cross","pos":"v. / adj. / n.","phonetic":"[krɔs]","meaning":"穿越；生氣的；十字架","definition":"to go from one side to the other, or angry, or a mark shaped like a plus sign","collocations":["cross the street","cross one's arms","get cross with"],"example":"Look both ways before you cross the street.","exampleZh":"過馬路前要看清左右來車。","synonyms":["angry"],"level":1,"theme":"旅遊與交通"},{"word":"crowded","pos":"adj.","phonetic":"[ˈkraʊdɪd]","meaning":"擁擠的","definition":"completely filled with people or things","collocations":["crowded street","crowded bus"],"example":"The train was too crowded to find a seat.","exampleZh":"火車太擁擠了，找不到座位。","synonyms":["packed"],"level":2,"theme":"日常與一般"},{"word":"crucial","pos":"adj.","phonetic":"[ˈkruʃəl]","meaning":"關鍵的；決定性的","definition":"extremely important because it will affect other things","collocations":["crucial role","crucial decision","crucial moment"],"example":"Teamwork played a crucial role in our success.","exampleZh":"團隊合作在我們的成功中扮演了關鍵角色。","synonyms":["critical","vital"],"level":5,"theme":"日常與一般"},{"word":"cruise","pos":"n. / v.","phonetic":"[kruz]","meaning":"郵輪旅行；巡航","definition":"a voyage on a ship taken for pleasure, or to travel at a steady speed","collocations":["go on a cruise","cruise ship","cruise around"],"example":"They took a cruise around the Caribbean islands.","exampleZh":"他們搭乘郵輪遊覽加勒比海群島。","synonyms":["voyage"],"level":3,"theme":"旅遊與交通"},{"word":"cubicle","pos":"n.","phonetic":"[ˈkjubɪkl]","meaning":"（辦公室）隔間；小隔間","definition":"a small divided space in an office where one person works","collocations":["office cubicle","cubicle wall"],"example":"Each employee's cubicle is equipped with a monitor and docking station.","exampleZh":"每位員工的隔間都配有螢幕和擴充底座。","synonyms":["workstation"],"level":4,"theme":"辦公室與行政"},{"word":"cuisine","pos":"n.","phonetic":"[kwɪˈzin]","meaning":"烹飪；菜系","definition":"a style or method of cooking, especially of a particular country","collocations":["French cuisine","local cuisine","fine cuisine"],"example":"The restaurant serves authentic Italian cuisine.","exampleZh":"這家餐廳提供道地的義大利菜。","synonyms":["cooking"],"level":5,"theme":"餐飲與住宿"},{"word":"culinary","pos":"adj.","phonetic":"[ˈkjulɪˌnɛrɪ]","meaning":"烹飪的；廚藝的","definition":"relating to cooking or the kitchen","collocations":["culinary skills","culinary school","culinary arts"],"example":"She studied culinary arts in Paris.","exampleZh":"她在巴黎學習烹飪藝術。","synonyms":[],"level":6,"theme":"餐飲與住宿"},{"word":"cultural","pos":"adj.","phonetic":"[ˈkʌltʃərəl]","meaning":"文化的","definition":"relating to the customs and beliefs of a society","collocations":["cultural heritage","cultural difference","cultural exchange"],"example":"The festival celebrates the region's cultural heritage.","exampleZh":"這個節慶慶祝該地區的文化遺產。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"culture","pos":"n.","phonetic":"[ˈkʌltʃɚ]","meaning":"文化","definition":"the customs, arts, and beliefs of a particular society","collocations":["pop culture","culture shock","traditional culture"],"example":"Taiwan has a rich and diverse culture.","exampleZh":"台灣擁有豐富多元的文化。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"curator","pos":"n.","phonetic":"[kjʊˈretɚ]","meaning":"（博物館等的）館長；策展人","definition":"a person in charge of the objects in a museum or gallery","collocations":["museum curator","exhibition curator"],"example":"The curator will lead a guided tour of the new exhibition.","exampleZh":"策展人將帶領參觀新展覽的導覽行程。","synonyms":["keeper"],"level":5,"theme":"媒體與活動"},{"word":"curb","pos":"n. / v.","phonetic":"[kɝb]","meaning":"路緣；抑制","definition":"the edge of a sidewalk, or to control or limit something","collocations":["curb one's appetite","park by the curb","curb inflation"],"example":"The government tried to curb rising prices.","exampleZh":"政府試圖抑制物價上漲。","synonyms":["control","limit"],"level":5,"theme":"日常與一般"},{"word":"currency","pos":"n.","phonetic":"[ˈkɝənsɪ]","meaning":"貨幣；通貨","definition":"the money used in a particular country","collocations":["foreign currency","exchange currency","local currency"],"example":"You need to exchange your currency before traveling.","exampleZh":"旅行前你需要兌換貨幣。","synonyms":["money"],"level":4,"theme":"財務與會計"},{"word":"current","pos":"adj. / n.","phonetic":"[ˈkɝənt]","meaning":"目前的；水流；電流","definition":"belonging to the present time, or a flow of water, air, or electricity","collocations":["current situation","ocean current","electric current"],"example":"The current situation requires immediate action.","exampleZh":"目前的情況需要立即採取行動。","synonyms":["present"],"level":3,"theme":"日常與一般"},{"word":"currently","pos":"adv.","phonetic":"[ˈkɝəntlɪ]","meaning":"目前；現在","definition":"at the present time","collocations":["currently available","currently under review"],"example":"The position is currently open, and interviews begin next week.","exampleZh":"該職缺目前開放中，下週開始面試。","synonyms":["presently","now"],"level":2,"theme":"日常與一般"},{"word":"curriculum","pos":"n.","phonetic":"[kəˈrɪkjələm]","meaning":"課程；課程表","definition":"the subjects that are studied or taught in a school or course","collocations":["school curriculum","curriculum design"],"example":"The school revised its curriculum this year.","exampleZh":"這所學校今年修訂了課程。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"custom","pos":"n. / adj.","phonetic":"[ˈkʌstəm]","meaning":"習俗；慣例；訂製的","definition":"a traditional way of behaving in a society, or made specially to order","collocations":["local custom","custom-made","follow a custom"],"example":"It is a local custom to remove shoes before entering.","exampleZh":"進門前脫鞋是當地的習俗。","synonyms":["tradition"],"level":3,"theme":"日常與一般"},{"word":"customary","pos":"adj.","phonetic":"[ˈkʌstəmˌɛrɪ]","meaning":"習慣上的；慣例的","definition":"usual or traditional in a particular situation or place","collocations":["customary practice","it is customary to"],"example":"It is customary to leave a fifteen percent tip in this country.","exampleZh":"在這個國家，習慣上要給百分之十五的小費。","synonyms":["traditional","usual"],"level":5,"theme":"日常與一般"},{"word":"customer","pos":"n.","phonetic":"[ˈkʌstəmɚ]","meaning":"顧客","definition":"a person who buys goods or services from a business","collocations":["customer service","satisfied customer","regular customer"],"example":"The shop offers great customer service.","exampleZh":"這家店提供優質的顧客服務。","synonyms":["client"],"level":2,"theme":"財務與會計"},{"word":"customize","pos":"v.","phonetic":"[ˈkʌstəˌmaɪz]","meaning":"客製化；訂做","definition":"to modify something according to a person's individual requirements","collocations":["customize a phone","customize settings"],"example":"You can customize the settings on your phone.","exampleZh":"你可以在手機上客製化設定。","synonyms":["personalize"],"level":5,"theme":"科技與通訊"},{"word":"customs","pos":"n.","phonetic":"[ˈkʌstəmz]","meaning":"海關","definition":"the place at a border where officials check goods entering a country","collocations":["pass through customs","customs officer","customs declaration"],"example":"We had to wait in line at customs.","exampleZh":"我們得在海關排隊等候。","synonyms":[],"level":4,"theme":"旅遊與交通"},{"word":"cut","pos":"v. / n.","phonetic":"[kʌt]","meaning":"切；剪；傷口","definition":"to use a sharp tool to divide or remove something","collocations":["cut down","cut in line","a paper cut"],"example":"She cut the cake into eight pieces.","exampleZh":"她把蛋糕切成八塊。","synonyms":["slice"],"level":1,"theme":"日常與一般"},{"word":"cutting-edge","pos":"adj.","phonetic":"[ˈkʌtɪŋˈɛdʒ]","meaning":"最先進的；尖端的","definition":"using the newest and most advanced technology or methods","collocations":["cutting-edge technology","cutting-edge design"],"example":"The lab is equipped with cutting-edge technology for product testing.","exampleZh":"這間實驗室配備最先進的產品測試技術。","synonyms":["state-of-the-art","advanced"],"level":5,"theme":"科技與通訊"},{"word":"daily","pos":"adj. / adv.","phonetic":"[ˈdelɪ]","meaning":"每日的；每天","definition":"happening or done every day","collocations":["daily life","daily routine","daily newspaper"],"example":"She goes jogging on a daily basis.","exampleZh":"她每天都去慢跑。","synonyms":["everyday"],"level":2,"theme":"日常與一般"},{"word":"dairy","pos":"n./adj.","phonetic":"[ˈdɛrɪ]","meaning":"乳製品；乳品的","definition":"foods made from milk, such as cheese and butter","collocations":["dairy products","dairy farm","dairy section"],"example":"The dairy section is located at the back of the supermarket.","exampleZh":"乳製品區位於超市的後方。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"damage","pos":"n. / v.","phonetic":"[ˈdæmɪdʒ]","meaning":"損害；損傷","definition":"harm that reduces value or usefulness","collocations":["cause damage","serious damage","damage property"],"example":"The storm caused severe damage to the roof.","exampleZh":"這場暴風雨對屋頂造成嚴重損害。","synonyms":["harm","destruction"],"level":3,"theme":"日常與一般"},{"word":"danger","pos":"n.","phonetic":"[ˈdendʒɚ]","meaning":"危險","definition":"the possibility of harm or death","collocations":["in danger","face danger","danger zone"],"example":"Firefighters risk their lives to save people in danger.","exampleZh":"消防員冒著生命危險拯救身處危險中的人。","synonyms":["risk","peril"],"level":2,"theme":"日常與一般"},{"word":"dangerous","pos":"adj.","phonetic":"[ˈdendʒərəs]","meaning":"危險的","definition":"likely to cause harm","collocations":["dangerous sport","dangerous road","extremely dangerous"],"example":"Riding a motorcycle without a helmet is dangerous.","exampleZh":"騎機車不戴安全帽是很危險的。","synonyms":["risky","hazardous"],"level":2,"theme":"日常與一般"},{"word":"dark","pos":"adj.","phonetic":"[dɑrk]","meaning":"黑暗的；深色的","definition":"having little or no light","collocations":["dark room","dark night","dark color"],"example":"It was too dark to see the road ahead.","exampleZh":"天太黑了看不清前方的路。","synonyms":["dim","gloomy"],"level":1,"theme":"日常與一般"},{"word":"data","pos":"n.","phonetic":"[ˈdetə]","meaning":"資料；數據","definition":"facts and information used for analysis","collocations":["collect data","data analysis","personal data"],"example":"Researchers analyzed the data from the survey.","exampleZh":"研究人員分析了這項調查的數據。","synonyms":["information"],"level":4,"theme":"科技與通訊"},{"word":"database","pos":"n.","phonetic":"[ˈdetəˌbes]","meaning":"資料庫","definition":"an organized collection of data stored electronically","collocations":["build a database","search a database","update the database"],"example":"The company stores customer information in a database.","exampleZh":"這家公司把客戶資訊儲存在資料庫中。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"date","pos":"n. / v.","phonetic":"[det]","meaning":"日期；約會","definition":"a specific day, or a romantic meeting","collocations":["due date","go on a date","set a date"],"example":"They went on their first date to the movies.","exampleZh":"他們第一次約會去看電影。","synonyms":["appointment"],"level":2,"theme":"日常與一般"},{"word":"day","pos":"n.","phonetic":"[de]","meaning":"天；日子","definition":"a period of twenty-four hours","collocations":["all day","one day","school day"],"example":"I had a very busy day at work.","exampleZh":"我今天工作非常忙碌。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"deactivate","pos":"v.","phonetic":"[diˈæktəˌvet]","meaning":"停用；使失效","definition":"to turn off a device or stop a system from working","collocations":["deactivate an account","deactivate the alarm"],"example":"Your card will be deactivated if it is reported lost or stolen.","exampleZh":"若掛失或遭竊，您的卡片將被停用。","synonyms":["disable"],"level":4,"theme":"科技與通訊"},{"word":"deadline","pos":"n.","phonetic":"[ˈdɛdˌlaɪn]","meaning":"截止日期","definition":"a time by which something must be finished","collocations":["meet a deadline","miss a deadline","tight deadline"],"example":"We have to submit the report before the deadline.","exampleZh":"我們必須在截止日期前繳交報告。","synonyms":["due date"],"level":4,"theme":"人事與職涯"},{"word":"deal","pos":"n. / v.","phonetic":"[dil]","meaning":"交易；處理","definition":"an agreement, or to handle a situation","collocations":["make a deal","deal with","a good deal"],"example":"We need to deal with this problem quickly.","exampleZh":"我們需要盡快處理這個問題。","synonyms":["handle","agreement"],"level":2,"theme":"財務與會計"},{"word":"debate","pos":"n. / v.","phonetic":"[dɪˈbet]","meaning":"辯論","definition":"a formal discussion of opposing views","collocations":["hold a debate","debate over","join a debate"],"example":"The students had a heated debate about the new policy.","exampleZh":"學生們針對新政策展開激烈辯論。","synonyms":["argument","discussion"],"level":4,"theme":"溝通與語言"},{"word":"debit","pos":"n./v.","phonetic":"[ˈdɛbɪt]","meaning":"借記；扣款；記入借方","definition":"an amount of money taken out of a bank account","collocations":["debit card","direct debit","debit an account"],"example":"The monthly fee will be debited from your account automatically.","exampleZh":"月費將自動從您的帳戶中扣除。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"debt","pos":"n.","phonetic":"[dɛt]","meaning":"債務","definition":"money owed to someone","collocations":["pay off debt","in debt","national debt"],"example":"He worked hard to pay off his debt.","exampleZh":"他努力工作來還清債務。","synonyms":["liability"],"level":4,"theme":"財務與會計"},{"word":"decade","pos":"n.","phonetic":"[ˈdɛked]","meaning":"十年","definition":"a period of ten years","collocations":["over the past decade","last decade","for decades"],"example":"The city has changed a lot over the past decade.","exampleZh":"這座城市在過去十年間變化很大。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"decide","pos":"v.","phonetic":"[dɪˈsaɪd]","meaning":"決定","definition":"to make a choice after consideration","collocations":["decide to do","decide on","decide against"],"example":"She decided to study abroad next year.","exampleZh":"她決定明年出國留學。","synonyms":["determine","choose"],"level":2,"theme":"日常與一般"},{"word":"decision","pos":"n.","phonetic":"[dɪˈsɪʒən]","meaning":"決定","definition":"a choice made after consideration","collocations":["make a decision","final decision","difficult decision"],"example":"Moving to a new city was a hard decision.","exampleZh":"搬到新城市是一個困難的決定。","synonyms":["choice"],"level":2,"theme":"日常與一般"},{"word":"deck","pos":"n.","phonetic":"[dɛk]","meaning":"甲板；（建築的）露臺；一副（牌）","definition":"a flat outdoor floor attached to a building, or a floor of a ship","collocations":["observation deck","upper deck","wooden deck"],"example":"Guests can enjoy the sunset from the hotel's rooftop deck.","exampleZh":"房客可以在飯店的頂樓露臺欣賞夕陽。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"declare","pos":"v.","phonetic":"[dɪˈklɛr]","meaning":"宣布；聲明","definition":"to state something officially or firmly","collocations":["declare war","declare independence","declare openly"],"example":"The government declared a state of emergency.","exampleZh":"政府宣布進入緊急狀態。","synonyms":["announce","proclaim"],"level":5,"theme":"合約與法律"},{"word":"decline","pos":"v. / n.","phonetic":"[dɪˈklaɪn]","meaning":"下降；婉拒","definition":"to become smaller or worse, or to refuse politely","collocations":["decline an offer","decline in sales","sharp decline"],"example":"Sales have declined sharply this quarter.","exampleZh":"本季銷售大幅下滑。","synonyms":["refuse","decrease"],"level":5,"theme":"財務與會計"},{"word":"decorate","pos":"v.","phonetic":"[ˈdɛkəˌret]","meaning":"裝飾；佈置","definition":"to make something look more attractive by adding things to it","collocations":["decorate the office","decorate with flowers"],"example":"The staff decorated the conference room for the year-end party.","exampleZh":"員工們為尾牙佈置了會議室。","synonyms":["adorn"],"level":2,"theme":"房產與設施"},{"word":"decoration","pos":"n.","phonetic":"[ˌdɛkəˈreʃən]","meaning":"裝飾；裝飾品","definition":"something added to make a place or object more attractive","collocations":["holiday decorations","interior decoration"],"example":"The holiday decorations in the lobby attracted many visitors.","exampleZh":"大廳的節慶裝飾吸引了許多訪客。","synonyms":["ornament"],"level":2,"theme":"房產與設施"},{"word":"decrease","pos":"v. / n.","phonetic":"[dɪˈkris]","meaning":"減少","definition":"to become or make smaller in size or amount","collocations":["decrease in number","sharp decrease","gradually decrease"],"example":"The population of the village has decreased over the years.","exampleZh":"這個村莊的人口這些年來逐漸減少。","synonyms":["reduce","decline"],"level":4,"theme":"日常與一般"},{"word":"dedicate","pos":"v.","phonetic":"[ˈdɛdɪˌket]","meaning":"奉獻；致力於","definition":"to devote time or effort to a particular purpose","collocations":["dedicate one's life to","dedicate a book to"],"example":"She dedicated her life to helping the poor.","exampleZh":"她將一生奉獻於幫助窮人。","synonyms":["devote","commit"],"level":5,"theme":"日常與一般"},{"word":"dedication","pos":"n.","phonetic":"[ˌdɛdəˈkeʃən]","meaning":"奉獻；投入；落成典禮","definition":"the willingness to give a lot of time and energy to something","collocations":["dedication to work","show dedication"],"example":"She was praised for her dedication to customer service excellence.","exampleZh":"她因致力於卓越的顧客服務而受到讚揚。","synonyms":["commitment","devotion"],"level":4,"theme":"人事與職涯"},{"word":"deduct","pos":"v.","phonetic":"[dɪˈdʌkt]","meaning":"扣除；減除","definition":"to take an amount of money away from a total","collocations":["deduct from salary","deduct taxes","deduct expenses"],"example":"Insurance premiums are deducted from your paycheck each month.","exampleZh":"保險費每個月會從你的薪資中扣除。","synonyms":["subtract"],"level":4,"theme":"財務與會計"},{"word":"deduction","pos":"n.","phonetic":"[dɪˈdʌkʃən]","meaning":"扣除額；推論","definition":"an amount taken away from a total, or a conclusion reached by reasoning","collocations":["tax deduction","payroll deduction","make a deduction"],"example":"Employees can claim a tax deduction for work-related travel.","exampleZh":"員工可就與工作相關的差旅申報稅務扣除額。","synonyms":["subtraction"],"level":5,"theme":"財務與會計"},{"word":"defect","pos":"n./v.","phonetic":"[ˈdifɛkt]","meaning":"瑕疵；缺陷；叛逃","definition":"a fault or problem in something that makes it imperfect","collocations":["manufacturing defect","product defect","free of defects"],"example":"All items are inspected twice to catch any manufacturing defects.","exampleZh":"所有商品都經過兩次檢驗，以找出任何製造瑕疵。","synonyms":["flaw","fault"],"level":4,"theme":"生產與物流"},{"word":"defective","pos":"adj.","phonetic":"[dɪˈfɛktɪv]","meaning":"有瑕疵的；有缺陷的","definition":"having a fault and not working correctly","collocations":["defective product","defective parts","replace defective items"],"example":"Customers may return defective products within thirty days for a refund.","exampleZh":"顧客可在三十天內退回瑕疵商品並取得退款。","synonyms":["faulty","flawed"],"level":4,"theme":"購物與消費"},{"word":"defend","pos":"v.","phonetic":"[dɪˈfɛnd]","meaning":"防禦；辯護","definition":"to protect from attack or criticism","collocations":["defend against","defend a decision","defend one's rights"],"example":"Soldiers were sent to defend the border.","exampleZh":"士兵被派去防守邊境。","synonyms":["protect","guard"],"level":3,"theme":"合約與法律"},{"word":"define","pos":"v.","phonetic":"[dɪˈfaɪn]","meaning":"下定義；界定","definition":"to state the exact meaning of something","collocations":["define a term","clearly defined","define success"],"example":"The dictionary defines the word clearly.","exampleZh":"這本字典清楚地為這個字下定義。","synonyms":["explain","specify"],"level":4,"theme":"人事與職涯"},{"word":"definitely","pos":"adv.","phonetic":"[ˈdɛfənɪtlɪ]","meaning":"確實地；肯定地","definition":"without doubt; certainly","collocations":["definitely true","will definitely come","definitely not"],"example":"I will definitely attend your birthday party.","exampleZh":"我一定會參加你的生日派對。","synonyms":["certainly"],"level":3,"theme":"溝通與語言"},{"word":"definition","pos":"n.","phonetic":"[ˌdɛfəˈnɪʃən]","meaning":"定義；清晰度","definition":"a statement explaining what a word or idea means","collocations":["clear definition","high definition","by definition"],"example":"The contract includes a clear definition of each party's responsibilities.","exampleZh":"合約中對各方的責任有明確的定義。","synonyms":["explanation"],"level":2,"theme":"日常與一般"},{"word":"degree","pos":"n.","phonetic":"[dɪˈgri]","meaning":"程度；學位；度數","definition":"a unit of measurement, or an academic qualification","collocations":["bachelor's degree","to some degree","30 degrees"],"example":"She earned a degree in economics.","exampleZh":"她獲得經濟學學位。","synonyms":["extent"],"level":3,"theme":"人事與職涯"},{"word":"delay","pos":"v. / n.","phonetic":"[dɪˈle]","meaning":"延遲；耽擱","definition":"to make something happen later than planned","collocations":["delay a flight","without delay","delay the meeting"],"example":"The flight was delayed due to bad weather.","exampleZh":"班機因天候不佳而延誤。","synonyms":["postpone"],"level":3,"theme":"旅遊與交通"},{"word":"delegate","pos":"n. / v.","phonetic":"[ˈdɛlɪˌɡet]","meaning":"代表；代表團成員；委派","definition":"a person sent to represent others; to assign responsibility to someone else","collocations":["delegate a task","conference delegate","delegate authority"],"example":"The manager decided to delegate some tasks to her team.","exampleZh":"經理決定將一些任務委派給她的團隊。","synonyms":["representative","assign"],"level":6,"theme":"人事與職涯"},{"word":"delete","pos":"v.","phonetic":"[dɪˈlit]","meaning":"刪除","definition":"to remove something, especially from a computer or document","collocations":["delete a file","delete an email","accidentally delete"],"example":"Please do not delete any files from the shared folder without permission.","exampleZh":"未經許可，請勿刪除共用資料夾中的任何檔案。","synonyms":["remove","erase"],"level":2,"theme":"科技與通訊"},{"word":"delicious","pos":"adj.","phonetic":"[dɪˈlɪʃəs]","meaning":"美味的","definition":"having a very pleasant taste","collocations":["delicious meal","smell delicious","absolutely delicious"],"example":"The cake she baked was absolutely delicious.","exampleZh":"她烤的蛋糕非常美味。","synonyms":["tasty","yummy"],"level":2,"theme":"餐飲與住宿"},{"word":"delight","pos":"n./v.","phonetic":"[dɪˈlaɪt]","meaning":"高興；使欣喜","definition":"great pleasure, or to give someone great pleasure","collocations":["take delight in","to one's delight"],"example":"To our delight, the new product sold out within a week.","exampleZh":"令我們欣喜的是，新產品一週內就銷售一空。","synonyms":["please","joy"],"level":3,"theme":"日常與一般"},{"word":"delighted","pos":"adj.","phonetic":"[dɪˈlaɪtɪd]","meaning":"高興的；欣喜的","definition":"very pleased and happy about something","collocations":["delighted to announce","delighted with the results"],"example":"We are delighted to announce the opening of our newest branch.","exampleZh":"我們很高興宣布最新分店開幕。","synonyms":["pleased","thrilled"],"level":3,"theme":"日常與一般"},{"word":"deliver","pos":"v.","phonetic":"[dɪˈlɪvɚ]","meaning":"遞送；發表","definition":"to bring goods or a message to a place, or give a speech","collocations":["deliver a package","deliver a speech","deliver on time"],"example":"The mailman delivers letters every morning.","exampleZh":"郵差每天早上送信。","synonyms":["bring","carry"],"level":3,"theme":"人事與職涯"},{"word":"delivery","pos":"n.","phonetic":"[dɪˈlɪvərɪ]","meaning":"交付；送貨；投遞","definition":"the act of bringing goods or letters to a person or place","collocations":["free delivery","delivery date","on-time delivery"],"example":"We offer free delivery on all orders over fifty dollars.","exampleZh":"訂單滿五十美元即享免費送貨。","synonyms":["shipment"],"level":2,"theme":"生產與物流"},{"word":"demand","pos":"n. / v.","phonetic":"[dɪˈmænd]","meaning":"需求；要求","definition":"an insistent request, or the desire for goods or services","collocations":["in high demand","demand payment","meet demand"],"example":"There is a high demand for skilled workers.","exampleZh":"目前對熟練工人的需求很高。","synonyms":["request","require"],"level":4,"theme":"財務與會計"},{"word":"demanding","pos":"adj.","phonetic":"[dɪˈmændɪŋ]","meaning":"要求高的；費力的","definition":"needing a lot of time, attention, or effort","collocations":["demanding job","demanding customer","physically demanding"],"example":"Working in the emergency department is demanding but rewarding.","exampleZh":"在急診部門工作雖然辛苦，但很有成就感。","synonyms":["challenging","tough"],"level":4,"theme":"人事與職涯"},{"word":"demonstrate","pos":"v.","phonetic":"[ˈdɛmənˌstret]","meaning":"示範；證明；展示","definition":"to show clearly by giving proof or evidence","collocations":["demonstrate a skill","demonstrate how to","demonstrate against"],"example":"The teacher demonstrated how to solve the equation.","exampleZh":"老師示範了如何解這道方程式。","synonyms":["show","prove"],"level":4,"theme":"人事與職涯"},{"word":"demonstration","pos":"n.","phonetic":"[ˌdɛmənˈstreʃən]","meaning":"示範；展示；示威","definition":"an act of showing how something works or is done","collocations":["product demonstration","give a demonstration","live demonstration"],"example":"The sales team will give a live demonstration of the new software.","exampleZh":"業務團隊將現場示範新軟體的操作。","synonyms":["presentation","display"],"level":4,"theme":"行銷與銷售"},{"word":"dental","pos":"adj.","phonetic":"[ˈdɛntl]","meaning":"牙齒的；牙科的","definition":"relating to the teeth or dentistry","collocations":["dental care","dental appointment","dental insurance"],"example":"The company's health plan includes full dental coverage.","exampleZh":"公司的健康保險方案包含完整的牙科給付。","synonyms":[],"level":3,"theme":"醫療與保險"},{"word":"dentist","pos":"n.","phonetic":"[ˈdɛntɪst]","meaning":"牙醫","definition":"a doctor who treats teeth","collocations":["visit the dentist","see a dentist","dentist appointment"],"example":"I have an appointment with the dentist tomorrow.","exampleZh":"我明天跟牙醫有約。","synonyms":[],"level":2,"theme":"醫療與保險"},{"word":"deny","pos":"v.","phonetic":"[dɪˈnaɪ]","meaning":"否認","definition":"to state that something is not true","collocations":["deny the charge","deny doing something","flatly deny"],"example":"He denied stealing the money.","exampleZh":"他否認偷了那筆錢。","synonyms":["refute"],"level":4,"theme":"溝通與語言"},{"word":"depart","pos":"v.","phonetic":"[dɪˈpɑrt]","meaning":"出發；離開","definition":"to leave, especially to start a journey","collocations":["depart from","flight departs","depart for"],"example":"The train departs from platform three.","exampleZh":"火車從第三月台出發。","synonyms":["leave"],"level":4,"theme":"旅遊與交通"},{"word":"department","pos":"n.","phonetic":"[dɪˈpɑrtmənt]","meaning":"部門；系","definition":"a division within an organization or institution","collocations":["sales department","department store","history department"],"example":"She works in the marketing department.","exampleZh":"她在行銷部門工作。","synonyms":["division"],"level":2,"theme":"人事與職涯"},{"word":"departure","pos":"n.","phonetic":"[dɪˈpɑrtʃɚ]","meaning":"出發；離開；離職","definition":"the act of leaving a place, especially at the start of a journey","collocations":["departure time","departure gate","upon departure"],"example":"Passengers should arrive two hours before the scheduled departure time.","exampleZh":"乘客應在預定起飛時間前兩小時抵達。","synonyms":["exit","leaving"],"level":3,"theme":"旅遊與交通"},{"word":"depend","pos":"v.","phonetic":"[dɪˈpɛnd]","meaning":"依賴；視情況而定","definition":"to rely on someone or something","collocations":["depend on","it depends","depend heavily"],"example":"Children depend on their parents for support.","exampleZh":"孩子依賴父母的支持。","synonyms":["rely"],"level":2,"theme":"日常與一般"},{"word":"dependent","pos":"adj./n.","phonetic":"[dɪˈpɛndənt]","meaning":"依賴的；取決於…的；受扶養人","definition":"needing someone or something for support, or a family member you support financially","collocations":["dependent on","insurance for dependents"],"example":"Employees may add dependents to their health insurance plan.","exampleZh":"員工可將受扶養親屬加入健康保險方案。","synonyms":["reliant"],"level":4,"theme":"醫療與保險"},{"word":"deposit","pos":"n. / v.","phonetic":"[dɪˈpɑzɪt]","meaning":"存款；訂金；存放","definition":"a sum of money placed in a bank or as a partial payment; to place something somewhere","collocations":["make a deposit","pay a deposit","deposit money"],"example":"You need to pay a deposit before renting the apartment.","exampleZh":"租這間公寓之前你需要先付訂金。","synonyms":["down payment"],"level":4,"theme":"財務與會計"},{"word":"deputy","pos":"n.","phonetic":"[ˈdɛpjəti]","meaning":"副手；代理人","definition":"a person appointed to act on behalf of another","collocations":["deputy mayor","deputy manager"],"example":"The deputy manager ran the meeting in the boss's absence.","exampleZh":"老闆不在時，副理主持了這場會議。","synonyms":["assistant","substitute"],"level":5,"theme":"人事與職涯"},{"word":"descend","pos":"v.","phonetic":"[dɪˈsɛnd]","meaning":"下降；下來","definition":"to move downward from a higher place","collocations":["descend the stairs","descend into chaos"],"example":"The plane began to descend as it approached the airport.","exampleZh":"飛機在接近機場時開始下降。","synonyms":["descend","go down"],"level":4,"theme":"日常與一般"},{"word":"describe","pos":"v.","phonetic":"[dɪˈskraɪb]","meaning":"描述","definition":"to give a detailed account of something","collocations":["describe in detail","describe as","hard to describe"],"example":"Can you describe what happened last night?","exampleZh":"你能描述一下昨晚發生了什麼事嗎？","synonyms":["depict"],"level":2,"theme":"溝通與語言"},{"word":"description","pos":"n.","phonetic":"[dɪˈskrɪpʃən]","meaning":"描述；說明","definition":"a statement that tells what someone or something is like","collocations":["job description","detailed description","match the description"],"example":"The job description lists all required qualifications and duties.","exampleZh":"職務說明列出了所有必備資格與職責。","synonyms":["account"],"level":2,"theme":"人事與職涯"},{"word":"deserve","pos":"v.","phonetic":"[dɪˈzɝv]","meaning":"應得；值得","definition":"to have earned or be worthy of something","collocations":["deserve credit","deserve a break","richly deserve"],"example":"You deserve a reward for your hard work.","exampleZh":"你的努力值得獲得獎勵。","synonyms":["merit"],"level":4,"theme":"日常與一般"},{"word":"design","pos":"n. / v.","phonetic":"[dɪˈzaɪn]","meaning":"設計","definition":"a plan or drawing showing how something will look or work","collocations":["design a building","fashion design","graphic design"],"example":"She designed the poster for the school festival.","exampleZh":"她為校慶設計了海報。","synonyms":["plan","create"],"level":3,"theme":"媒體與活動"},{"word":"designate","pos":"v.","phonetic":"[ˈdɛzɪgˌnet]","meaning":"指定；指派","definition":"to officially choose someone or something for a particular purpose","collocations":["designated area","designate a successor","designated driver"],"example":"Please park only in the designated visitor parking area.","exampleZh":"請僅停放在指定的訪客停車區。","synonyms":["appoint","assign"],"level":5,"theme":"辦公室與行政"},{"word":"designer","pos":"n.","phonetic":"[dɪˈzaɪnɚ]","meaning":"設計師","definition":"a person whose job is to plan how things will look or work","collocations":["graphic designer","fashion designer","interior designer"],"example":"The graphic designer created three logo options for the client.","exampleZh":"平面設計師為客戶設計了三種標誌方案。","synonyms":[],"level":2,"theme":"媒體與活動"},{"word":"desirable","pos":"adj.","phonetic":"[dɪˈzaɪrəbl]","meaning":"值得嚮往的；理想的","definition":"worth having or wanted by many people","collocations":["desirable location","highly desirable","desirable qualities"],"example":"Experience with data analysis is desirable but not required.","exampleZh":"具備資料分析經驗尤佳，但非必要條件。","synonyms":["attractive","preferable"],"level":4,"theme":"人事與職涯"},{"word":"desire","pos":"n. / v.","phonetic":"[dɪˈzaɪr]","meaning":"渴望；欲望","definition":"a strong wish for something","collocations":["desire to succeed","strong desire","fulfill a desire"],"example":"She has a strong desire to travel the world.","exampleZh":"她非常渴望環遊世界。","synonyms":["wish","longing"],"level":4,"theme":"日常與一般"},{"word":"desk","pos":"n.","phonetic":"[dɛsk]","meaning":"書桌；辦公桌","definition":"a piece of furniture with a flat top for writing or working","collocations":["office desk","clean up the desk","front desk"],"example":"He keeps his desk very tidy.","exampleZh":"他把書桌整理得很整齊。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"desktop","pos":"n./adj.","phonetic":"[ˈdɛskˌtɑp]","meaning":"桌上型電腦；桌面（的）","definition":"a computer that stays on a desk, or the main screen of a computer","collocations":["desktop computer","desktop icon","on the desktop"],"example":"Save the report to your desktop so you can find it quickly.","exampleZh":"把報告存到桌面，這樣你可以很快找到它。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"despite","pos":"prep.","phonetic":"[dɪˈspaɪt]","meaning":"儘管","definition":"without being affected by; in spite of","collocations":["despite the rain","despite his efforts","despite all odds"],"example":"Despite the heavy rain, the game continued.","exampleZh":"儘管下著大雨，比賽仍繼續進行。","synonyms":["in spite of"],"level":4,"theme":"日常與一般"},{"word":"dessert","pos":"n.","phonetic":"[dɪˈzɝt]","meaning":"甜點","definition":"a sweet course eaten at the end of a meal","collocations":["order dessert","favorite dessert","dessert menu"],"example":"We ordered chocolate cake for dessert.","exampleZh":"我們點了巧克力蛋糕當甜點。","synonyms":["sweet"],"level":2,"theme":"餐飲與住宿"},{"word":"destination","pos":"n.","phonetic":"[ˌdɛstəˈneʃən]","meaning":"目的地；終點","definition":"the place that someone or something is going to","collocations":["final destination","popular tourist destination","reach one's destination"],"example":"Please check that your luggage tags show the correct destination before boarding.","exampleZh":"登機前請確認行李吊牌上的目的地是否正確。","synonyms":["stop","terminus"],"level":2,"theme":"旅遊與交通"},{"word":"destroy","pos":"v.","phonetic":"[dɪˈstrɔɪ]","meaning":"銷毀；破壞；摧毀","definition":"to damage something so badly that it no longer exists or cannot be used","collocations":["destroy confidential documents","completely destroyed","destroy evidence"],"example":"Confidential files must be destroyed once the retention period has expired.","exampleZh":"機密文件一旦超過保存期限就必須銷毀。","synonyms":["ruin","demolish","wreck"],"level":2,"theme":"辦公室與行政"},{"word":"detail","pos":"n./v.","phonetic":"[ˈditel]","meaning":"細節；詳情；詳述","definition":"a single piece of information or fact about something","collocations":["in detail","further details","contact details","attention to detail"],"example":"Please refer to the attached file for further details about the workshop schedule.","exampleZh":"有關研習營行程的詳細資訊，請參閱附件檔案。","synonyms":["particular","specifics"],"level":2,"theme":"辦公室與行政"},{"word":"detailed","pos":"adj.","phonetic":"[ˈditeld]","meaning":"詳細的；細節的","definition":"giving many facts and a lot of information","collocations":["detailed report","detailed instructions","detailed description"],"example":"The consultant submitted a detailed report on the company's current marketing strategy.","exampleZh":"顧問針對公司目前的行銷策略提交了一份詳細報告。","synonyms":["thorough","comprehensive"],"level":2,"theme":"辦公室與行政"},{"word":"detect","pos":"v.","phonetic":"[dɪˈtɛkt]","meaning":"偵測；察覺；發現","definition":"to discover or notice something, especially something that is not easy to see","collocations":["detect errors","detect a problem","detect smoke"],"example":"The new security system can detect unauthorized entry within a few seconds.","exampleZh":"新的保全系統能在幾秒內偵測到未經授權的闖入。","synonyms":["discover","notice","identify"],"level":3,"theme":"科技與通訊"},{"word":"detector","pos":"n.","phonetic":"[dɪˈtɛktɚ]","meaning":"偵測器；探測器","definition":"a device that finds or measures the presence of something such as smoke or metal","collocations":["smoke detector","metal detector","install a detector"],"example":"Smoke detectors must be installed in every guest room of the hotel.","exampleZh":"飯店的每間客房都必須安裝煙霧偵測器。","synonyms":["sensor"],"level":3,"theme":"房產與設施"},{"word":"determine","pos":"v.","phonetic":"[dɪˈtɝmɪn]","meaning":"確定；查明；決定","definition":"to discover the facts about something, or to officially decide something","collocations":["determine the cause","determine whether","determine the price"],"example":"An inspection will be conducted to determine the cause of the equipment failure.","exampleZh":"將會進行檢查，以查明設備故障的原因。","synonyms":["decide","establish","ascertain"],"level":3,"theme":"企業經營"},{"word":"detour","pos":"n./v.","phonetic":"[ˈditʊr]","meaning":"繞道；繞行路線","definition":"a longer, different route taken to avoid a road that is blocked or closed","collocations":["take a detour","make a detour","follow the detour signs"],"example":"Drivers should take a detour because the main bridge is closed for repairs.","exampleZh":"由於主橋封閉維修，駕駛人應改道繞行。","synonyms":["diversion","bypass"],"level":4,"theme":"旅遊與交通"},{"word":"develop","pos":"v.","phonetic":"[dɪˈvɛləp]","meaning":"開發；研發；發展","definition":"to create something new, or to make something grow or improve over time","collocations":["develop a new product","develop skills","develop a marketing plan"],"example":"Our research team is developing a new product line for younger consumers.","exampleZh":"我們的研發團隊正在為年輕消費者開發新的產品線。","synonyms":["create","expand","cultivate"],"level":2,"theme":"企業經營"},{"word":"developer","pos":"n.","phonetic":"[dɪˈvɛləpɚ]","meaning":"開發人員；開發商；建商","definition":"a person or company that creates software or builds new houses and buildings","collocations":["software developer","property developer","web developer"],"example":"The company is hiring experienced software developers for its mobile application team.","exampleZh":"該公司正在為行動應用程式團隊招募資深軟體開發人員。","synonyms":["programmer","builder"],"level":3,"theme":"科技與通訊"},{"word":"development","pos":"n.","phonetic":"[dɪˈvɛləpmənt]","meaning":"發展；開發；研發","definition":"the process of creating something new or making something grow and improve","collocations":["research and development","career development","product development"],"example":"The firm invests nearly ten percent of its revenue in research and development.","exampleZh":"這家公司將近一成的營收投入研發。","synonyms":["growth","progress","advancement"],"level":2,"theme":"企業經營"},{"word":"device","pos":"n.","phonetic":"[dɪˈvaɪs]","meaning":"裝置；設備；儀器","definition":"a piece of equipment, especially an electronic one, made for a particular purpose","collocations":["mobile device","electronic device","storage device"],"example":"Passengers must switch off all electronic devices before the plane takes off.","exampleZh":"飛機起飛前，乘客必須關閉所有電子裝置。","synonyms":["gadget","appliance","instrument"],"level":2,"theme":"科技與通訊"},{"word":"devote","pos":"v.","phonetic":"[dɪˈvot]","meaning":"投入（時間、心力）；奉獻；致力於","definition":"to give your time, effort, or attention completely to something","collocations":["devote time to","devote oneself to","devote resources to"],"example":"The manager devotes most of her time to improving customer service quality.","exampleZh":"這位經理把大部分時間都投入在提升客服品質上。","synonyms":["dedicate","commit"],"level":3,"theme":"人事與職涯"},{"word":"diagram","pos":"n.","phonetic":"[ˈdaɪəˌgræm]","meaning":"圖表；圖解；示意圖","definition":"a simple drawing that shows how something works or how parts are related","collocations":["as shown in the diagram","draw a diagram","flow diagram"],"example":"The diagram on page five shows how the assembly line operates.","exampleZh":"第五頁的示意圖說明了組裝線的運作方式。","synonyms":["chart","illustration","figure"],"level":3,"theme":"會議與簡報"},{"word":"dial","pos":"v./n.","phonetic":"[ˈdaɪəl]","meaning":"撥（電話號碼）；撥號盤；儀表盤","definition":"to press the buttons or turn the dial on a phone to make a call","collocations":["dial a number","dial an extension","dial the wrong number"],"example":"To reach the sales department, please dial extension two zero five.","exampleZh":"如需聯絡業務部，請撥分機二〇五。","synonyms":["call","phone"],"level":2,"theme":"科技與通訊"},{"word":"diet","pos":"n.","phonetic":"[ˈdaɪət]","meaning":"飲食；日常食物；節食","definition":"the kind of food that a person usually eats","collocations":["balanced diet","go on a diet","vegetarian diet"],"example":"The hotel restaurant offers special menus for guests on a vegetarian diet.","exampleZh":"飯店餐廳為吃素的房客提供特製菜單。","synonyms":["eating habits"],"level":2,"theme":"餐飲與住宿"},{"word":"differ","pos":"v.","phonetic":"[ˈdɪfɚ]","meaning":"不同；相異；意見不合","definition":"to be not the same as something or someone else","collocations":["differ from","differ in","opinions differ"],"example":"Delivery times may differ depending on the shipping method you choose.","exampleZh":"配送時間可能因您選擇的寄送方式而有所不同。","synonyms":["vary","diverge"],"level":3,"theme":"日常與一般"},{"word":"difference","pos":"n.","phonetic":"[ˈdɪfərəns]","meaning":"差異；差別；差額","definition":"the way in which two things are not the same","collocations":["make a difference","price difference","tell the difference"],"example":"There is a significant price difference between the two laptop models.","exampleZh":"這兩款筆電的價格差距相當大。","synonyms":["distinction","gap","variation"],"level":1,"theme":"日常與一般"},{"word":"different","pos":"adj.","phonetic":"[ˈdɪfərənt]","meaning":"不同的；各種的","definition":"not the same as another person or thing","collocations":["different from","a different approach","different types of"],"example":"The new manager has a completely different approach to team communication.","exampleZh":"新任經理在團隊溝通上採取截然不同的做法。","synonyms":["distinct","dissimilar","various"],"level":1,"theme":"日常與一般"},{"word":"difficult","pos":"adj.","phonetic":"[ˈdɪfəˌkʌlt]","meaning":"困難的；難處理的","definition":"not easy to do, deal with, or understand","collocations":["a difficult decision","difficult to understand","a difficult task"],"example":"It is difficult to find parking near the office during rush hour.","exampleZh":"尖峰時段很難在辦公室附近找到停車位。","synonyms":["hard","challenging","tough"],"level":1,"theme":"日常與一般"},{"word":"difficulty","pos":"n.","phonetic":"[ˈdɪfəˌkʌltɪ]","meaning":"困難；難處；麻煩","definition":"a problem, or the state of something being hard to do","collocations":["have difficulty doing something","financial difficulty","without difficulty"],"example":"Some customers had difficulty accessing the website during the holiday promotion.","exampleZh":"促銷檔期期間，有些顧客無法順利進入網站。","synonyms":["trouble","problem","obstacle"],"level":2,"theme":"日常與一般"},{"word":"digital","pos":"adj.","phonetic":"[ˈdɪdʒɪtḷ]","meaning":"數位的；數字顯示的","definition":"using an electronic system that stores information as a series of numbers","collocations":["digital marketing","digital camera","digital transformation"],"example":"The company plans to increase its digital marketing budget next year.","exampleZh":"該公司計劃明年提高數位行銷預算。","synonyms":["electronic"],"level":2,"theme":"科技與通訊"},{"word":"dine","pos":"v.","phonetic":"[daɪn]","meaning":"用餐；進餐","definition":"to eat a meal, especially the main meal of the day, in a formal way","collocations":["dine out","dine in","wine and dine clients"],"example":"Guests can dine on the terrace while enjoying a view of the harbor.","exampleZh":"房客可以一邊在露臺用餐，一邊欣賞港灣景色。","synonyms":["eat","feast"],"level":3,"theme":"餐飲與住宿"},{"word":"dining","pos":"n./adj.","phonetic":"[ˈdaɪnɪŋ]","meaning":"用餐；餐飲；用餐的","definition":"the activity of eating a meal, especially in a restaurant","collocations":["dining room","dining area","fine dining"],"example":"The hotel's main dining room serves breakfast from six to ten daily.","exampleZh":"飯店的主餐廳每天六點到十點供應早餐。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"dinner","pos":"n.","phonetic":"[ˈdɪnɚ]","meaning":"晚餐；晚宴；正餐","definition":"the main meal of the day, usually eaten in the evening","collocations":["business dinner","dinner party","have dinner with"],"example":"The company will host a farewell dinner for the retiring sales director.","exampleZh":"公司將為即將退休的業務總監舉辦歡送晚宴。","synonyms":["supper","banquet"],"level":1,"theme":"餐飲與住宿"},{"word":"diploma","pos":"n.","phonetic":"[dɪˈplomə]","meaning":"文憑；畢業證書","definition":"an official document showing that someone has completed a course of study","collocations":["high school diploma","earn a diploma","a diploma in accounting"],"example":"Applicants must hold a diploma in accounting or a related field.","exampleZh":"應徵者必須具備會計或相關領域的文憑。","synonyms":["certificate","credential"],"level":3,"theme":"人事與職涯"},{"word":"direct","pos":"adj./v.","phonetic":"[dəˈrɛkt]","meaning":"直接的；直達的；將…轉給；指引","definition":"going straight to a place or person without stopping or changing","collocations":["direct flight","direct deposit","direct all inquiries to"],"example":"Please direct all questions about the merger to the public relations office.","exampleZh":"有關合併案的所有問題，請洽公關部門。","synonyms":["straight","guide","route"],"level":2,"theme":"辦公室與行政"},{"word":"direction","pos":"n.","phonetic":"[dəˈrɛkʃən]","meaning":"方向；指示；（複數）使用說明","definition":"the path along which someone or something moves, or instructions on how to do something","collocations":["follow the directions","ask for directions","in the direction of"],"example":"Carefully follow the directions on the package before assembling the shelf.","exampleZh":"組裝層架前，請仔細依照包裝上的說明操作。","synonyms":["instruction","guidance","course"],"level":2,"theme":"日常與一般"},{"word":"directly","pos":"adv.","phonetic":"[dəˈrɛktlɪ]","meaning":"直接地；正好地","definition":"without anyone or anything else being involved or in between","collocations":["report directly to","speak directly with","directly responsible for"],"example":"All regional managers report directly to the vice president of sales.","exampleZh":"所有區域經理都直接向業務副總報告。","synonyms":["straight","immediately"],"level":2,"theme":"辦公室與行政"},{"word":"director","pos":"n.","phonetic":"[dəˈrɛktɚ]","meaning":"主管；總監；董事；導演","definition":"a senior manager in charge of a department or an entire company","collocations":["board of directors","managing director","marketing director"],"example":"The board of directors will meet on Friday to approve next year's budget.","exampleZh":"董事會將於週五開會，審核明年度的預算。","synonyms":["executive","manager","head"],"level":2,"theme":"人事與職涯"},{"word":"directory","pos":"n.","phonetic":"[dəˈrɛktərɪ]","meaning":"名錄；通訊錄；電話簿；目錄","definition":"a book or list containing names, addresses, and phone numbers of people or companies","collocations":["staff directory","telephone directory","business directory"],"example":"You can find every employee's extension number in the online staff directory.","exampleZh":"你可以在線上員工通訊錄中查到每位員工的分機號碼。","synonyms":["listing","register"],"level":3,"theme":"辦公室與行政"},{"word":"disability","pos":"n.","phonetic":"[ˌdɪsəˈbɪlətɪ]","meaning":"身心障礙；失能；殘疾","definition":"a physical or mental condition that limits a person's movements, senses, or activities","collocations":["disability insurance","people with disabilities","physical disability"],"example":"The building was renovated to improve access for people with disabilities.","exampleZh":"這棟大樓經過整修，方便身心障礙人士進出。","synonyms":["impairment","handicap"],"level":4,"theme":"醫療與保險"},{"word":"disabled","pos":"adj.","phonetic":"[dɪsˈebḷd]","meaning":"身心障礙的；殘障的；（功能）停用的","definition":"having an illness or condition that makes it difficult to do everyday activities","collocations":["disabled access","disabled parking space","physically disabled"],"example":"Parking spaces near the main entrance are reserved for disabled visitors.","exampleZh":"靠近大門的停車位保留給身心障礙訪客使用。","synonyms":["handicapped","impaired"],"level":4,"theme":"房產與設施"},{"word":"disadvantage","pos":"n.","phonetic":"[ˌdɪsədˈvæntɪdʒ]","meaning":"缺點；不利條件；劣勢","definition":"something that makes a situation more difficult or less likely to succeed","collocations":["at a disadvantage","advantages and disadvantages","competitive disadvantage"],"example":"The main disadvantage of the proposal is its high initial cost.","exampleZh":"這項提案最大的缺點是初期成本過高。","synonyms":["drawback","weakness","downside"],"level":3,"theme":"企業經營"},{"word":"disagree","pos":"v.","phonetic":"[ˌdɪsəˈgri]","meaning":"不同意；意見不合","definition":"to have a different opinion from someone else","collocations":["disagree with someone","strongly disagree","disagree about the issue"],"example":"Several board members disagreed with the plan to reduce the training budget.","exampleZh":"幾位董事不同意刪減教育訓練預算的計畫。","synonyms":["differ","object","dispute"],"level":2,"theme":"會議與簡報"},{"word":"disappoint","pos":"v.","phonetic":"[ˌdɪsəˈpɔɪnt]","meaning":"使失望；辜負","definition":"to make someone feel unhappy because something was not as good as expected","collocations":["disappoint customers","sorry to disappoint you","refuse to disappoint"],"example":"We are sorry to disappoint customers whose orders were delayed by the storm.","exampleZh":"訂單因暴風雨延誤，讓顧客失望，我們深感抱歉。","synonyms":["let down","dissatisfy"],"level":2,"theme":"購物與消費"},{"word":"disappointed","pos":"adj.","phonetic":"[ˌdɪsəˈpɔɪntɪd]","meaning":"失望的；沮喪的","definition":"unhappy because someone or something was not as good as you hoped","collocations":["deeply disappointed","disappointed with the results","disappointed to learn"],"example":"Many customers were disappointed with the repeated delays in the product launch.","exampleZh":"許多顧客對產品上市一再延期感到失望。","synonyms":["dissatisfied","let down"],"level":2,"theme":"日常與一般"},{"word":"disaster","pos":"n.","phonetic":"[dɪˈzæstɚ]","meaning":"災難；災害；重大失敗","definition":"a sudden event such as a flood or storm that causes great damage or harm","collocations":["natural disaster","disaster relief","disaster recovery plan"],"example":"The corporation donated one million dollars to the disaster relief fund.","exampleZh":"該企業捐了一百萬美元給賑災基金。","synonyms":["catastrophe","calamity"],"level":3,"theme":"日常與一般"},{"word":"disclosure","pos":"n.","phonetic":"[dɪsˈkloʒɚ]","meaning":"揭露；公開；披露","definition":"the act of making secret or private information known","collocations":["full disclosure","financial disclosure","disclosure of information"],"example":"The contract requires full disclosure of any potential conflicts of interest.","exampleZh":"合約要求充分揭露任何潛在的利益衝突。","synonyms":["revelation","announcement"],"level":5,"theme":"合約與法律"},{"word":"discontinue","pos":"v.","phonetic":"[ˌdɪskənˈtɪnjʊ]","meaning":"停產；停止；中止","definition":"to stop producing, providing, or doing something permanently","collocations":["discontinue a product","discontinue production","a discontinued model"],"example":"The manufacturer will discontinue this printer model at the end of the year.","exampleZh":"製造商將在年底停產這款印表機。","synonyms":["stop","terminate","cease"],"level":4,"theme":"生產與物流"},{"word":"discount","pos":"n./v.","phonetic":"[ˈdɪskaʊnt]","meaning":"折扣；打折","definition":"a reduction in the usual price of something","collocations":["offer a discount","at a discount","discount coupon"],"example":"Members receive a ten percent discount on all purchases this weekend.","exampleZh":"本週末會員消費一律享有九折優惠。","synonyms":["reduction","markdown"],"level":1,"theme":"購物與消費"},{"word":"discover","pos":"v.","phonetic":"[dɪˈskʌvɚ]","meaning":"發現；發覺；找到","definition":"to find something for the first time, or to learn something you did not know","collocations":["discover a problem","discover that","discover new markets"],"example":"During the audit, the accountant discovered several errors in the invoices.","exampleZh":"查帳期間，會計師發現發票上有好幾處錯誤。","synonyms":["find","uncover","detect"],"level":2,"theme":"日常與一般"},{"word":"discovery","pos":"n.","phonetic":"[dɪˈskʌvərɪ]","meaning":"發現；發覺","definition":"the act of finding something new, or the thing that is found","collocations":["make a discovery","scientific discovery","the discovery of"],"example":"The discovery of a design flaw forced the company to recall the product.","exampleZh":"由於發現設計瑕疵，公司被迫回收該產品。","synonyms":["finding","breakthrough"],"level":3,"theme":"日常與一般"},{"word":"discuss","pos":"v.","phonetic":"[dɪˈskʌs]","meaning":"討論；商討","definition":"to talk about something with other people in order to exchange ideas or make a decision","collocations":["discuss the issue","meet to discuss","discuss in detail"],"example":"The committee will meet on Monday to discuss the new marketing plan.","exampleZh":"委員會將在週一開會討論新的行銷計畫。","synonyms":["talk about","debate","deliberate"],"level":1,"theme":"會議與簡報"},{"word":"discussion","pos":"n.","phonetic":"[dɪˈskʌʃən]","meaning":"討論；商討；談論","definition":"a conversation in which people talk about a subject and share their opinions","collocations":["panel discussion","under discussion","have a discussion about"],"example":"After a lengthy discussion, the team finally agreed on the launch date.","exampleZh":"經過漫長的討論，團隊終於敲定了上市日期。","synonyms":["debate","conversation","talk"],"level":2,"theme":"會議與簡報"},{"word":"dish","pos":"n.","phonetic":"[dɪʃ]","meaning":"菜餚；一道菜；盤子","definition":"food prepared in a particular way as part of a meal, or a container for serving food","collocations":["signature dish","main dish","wash the dishes"],"example":"The chef's signature dish is grilled salmon served with lemon sauce.","exampleZh":"主廚的招牌菜是佐檸檬醬的烤鮭魚。","synonyms":["plate","course"],"level":1,"theme":"餐飲與住宿"},{"word":"dishwasher","pos":"n.","phonetic":"[ˈdɪʃˌwɑʃɚ]","meaning":"洗碗機；洗碗工","definition":"a machine that washes dirty plates, cups, and other kitchen items","collocations":["built-in dishwasher","load the dishwasher","run the dishwasher"],"example":"Every apartment in the new building comes with a built-in dishwasher.","exampleZh":"新大樓的每戶公寓都附有嵌入式洗碗機。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"disk","pos":"n.","phonetic":"[dɪsk]","meaning":"磁碟；碟片；圓盤","definition":"a flat, round object used for storing computer information","collocations":["hard disk","disk space","disk drive"],"example":"Please back up your files because the hard disk is almost full.","exampleZh":"硬碟空間快滿了，請先備份你的檔案。","synonyms":["disc"],"level":2,"theme":"科技與通訊"},{"word":"display","pos":"v./n.","phonetic":"[dɪˈsple]","meaning":"展示；陳列；顯示；顯示器","definition":"to put something where people can see it easily, or an arrangement of things for people to see","collocations":["on display","display window","display the merchandise"],"example":"The latest smartphone models are on display near the store entrance.","exampleZh":"最新款的智慧型手機就陳列在賣場入口附近。","synonyms":["exhibit","show","present"],"level":2,"theme":"購物與消費"},{"word":"distance","pos":"n.","phonetic":"[ˈdɪstəns]","meaning":"距離；路程","definition":"the amount of space between two places or things","collocations":["within walking distance","long-distance call","keep a safe distance"],"example":"The hotel is within walking distance of the international convention center.","exampleZh":"這家飯店距離國際會議中心只有步行可達的路程。","synonyms":["range","span"],"level":2,"theme":"旅遊與交通"},{"word":"distant","pos":"adj.","phonetic":"[ˈdɪstənt]","meaning":"遙遠的；久遠的；疏遠的","definition":"far away in space or time","collocations":["a distant location","in the distant future","distant markets"],"example":"The airline plans to add routes to more distant destinations next year.","exampleZh":"這家航空公司計劃明年增闢飛往更遠目的地的航線。","synonyms":["remote","faraway"],"level":3,"theme":"旅遊與交通"},{"word":"distinctive","pos":"adj.","phonetic":"[dɪˈstɪŋktɪv]","meaning":"獨特的；有特色的；與眾不同的","definition":"having a special quality that makes something easy to recognize","collocations":["distinctive design","distinctive feature","distinctive style"],"example":"The brand's distinctive logo makes its products easy to recognize on shelves.","exampleZh":"這個品牌獨特的標誌讓消費者在貨架上一眼就能認出其產品。","synonyms":["unique","characteristic"],"level":5,"theme":"行銷與銷售"},{"word":"distinguish","pos":"v.","phonetic":"[dɪˈstɪŋgwɪʃ]","meaning":"區別；辨別；使有別於","definition":"to notice or recognize the difference between two things or people","collocations":["distinguish between","distinguish A from B","distinguish oneself"],"example":"Customers often find it hard to distinguish between the two software versions.","exampleZh":"顧客常常難以分辨這兩個軟體版本的差異。","synonyms":["differentiate","discriminate","tell apart"],"level":4,"theme":"日常與一般"},{"word":"distribute","pos":"v.","phonetic":"[dɪˈstrɪbjut]","meaning":"分發；配送；經銷","definition":"to give or send things to a number of people or places","collocations":["distribute the handouts","distribute products","evenly distributed"],"example":"The assistant will distribute copies of the agenda before the meeting begins.","exampleZh":"會議開始前，助理會發放議程資料給大家。","synonyms":["hand out","deliver","dispense"],"level":3,"theme":"生產與物流"},{"word":"distribution","pos":"n.","phonetic":"[ˌdɪstrəˈbjuʃən]","meaning":"配送；經銷；分配","definition":"the process of delivering goods to stores or customers over an area","collocations":["distribution center","distribution channel","distribution network"],"example":"The company opened a new distribution center to speed up regional deliveries.","exampleZh":"公司新設了一座物流中心，以加快區域配送速度。","synonyms":["delivery","allocation"],"level":3,"theme":"生產與物流"},{"word":"distributor","pos":"n.","phonetic":"[dɪˈstrɪbjətɚ]","meaning":"經銷商；配銷商；批發商","definition":"a company or person that supplies goods to stores or other businesses","collocations":["authorized distributor","exclusive distributor","local distributor"],"example":"We recently signed a contract with an authorized distributor in Southeast Asia.","exampleZh":"我們最近和東南亞的一家授權經銷商簽了約。","synonyms":["wholesaler","supplier"],"level":4,"theme":"生產與物流"},{"word":"district","pos":"n.","phonetic":"[ˈdɪstrɪkt]","meaning":"地區；區域；行政區","definition":"an area of a town or country with a particular feature or official boundary","collocations":["business district","shopping district","financial district"],"example":"Our new headquarters is located in the city's main business district.","exampleZh":"我們的新總部位於市內主要的商業區。","synonyms":["area","zone","region"],"level":3,"theme":"房產與設施"},{"word":"disturb","pos":"v.","phonetic":"[dɪˈstɝb]","meaning":"打擾；妨礙；擾亂","definition":"to interrupt someone and stop them from continuing what they are doing","collocations":["do not disturb","sorry to disturb you","disturb the neighbors"],"example":"Please do not disturb the staff while they are counting the inventory.","exampleZh":"工作人員盤點庫存時，請勿打擾他們。","synonyms":["interrupt","bother","distract"],"level":3,"theme":"辦公室與行政"},{"word":"diverse","pos":"adj.","phonetic":"[daɪˈvɝs]","meaning":"多元的；多樣的；不同的","definition":"including many different types of people or things","collocations":["diverse workforce","diverse backgrounds","culturally diverse"],"example":"The firm is committed to building a diverse and inclusive workforce.","exampleZh":"這家公司致力於打造多元且具包容性的工作團隊。","synonyms":["varied","assorted"],"level":4,"theme":"人事與職涯"},{"word":"diversity","pos":"n.","phonetic":"[daɪˈvɝsətɪ]","meaning":"多元性；多樣性","definition":"the fact of including many different types of people or things","collocations":["cultural diversity","promote diversity","diversity training"],"example":"All new employees must attend a workshop on diversity in the workplace.","exampleZh":"所有新進員工都必須參加職場多元化研習課程。","synonyms":["variety","multiplicity"],"level":4,"theme":"人事與職涯"},{"word":"divide","pos":"v.","phonetic":"[dəˈvaɪd]","meaning":"劃分；分配；除","definition":"to separate something into parts or share it among people","collocations":["divide into groups","divide the work","divide equally"],"example":"The manager divided the project into four smaller tasks.","exampleZh":"經理將專案劃分為四個較小的任務。","synonyms":["split","separate"],"level":2,"theme":"日常與一般"},{"word":"division","pos":"n.","phonetic":"[dəˈvɪʒən]","meaning":"部門；劃分；除法","definition":"a separate part of a large company or organization","collocations":["sales division","overseas division","division manager"],"example":"She was promoted to head of the marketing division last month.","exampleZh":"她上個月升任行銷部門的主管。","synonyms":["department","branch"],"level":3,"theme":"企業經營"},{"word":"do","pos":"v./aux.","phonetic":"[du]","meaning":"做；進行；（助動詞）","definition":"to perform an action or activity","collocations":["do business","do research","do one's best"],"example":"Our firm has done business with that supplier for ten years.","exampleZh":"我們公司與那家供應商已有十年的生意往來。","synonyms":["perform","carry out"],"level":1,"theme":"日常與一般"},{"word":"dock","pos":"n. / v.","phonetic":"[dɑk]","meaning":"碼頭；船塢","definition":"a place where ships load and unload","collocations":["fishing dock","dock a ship","loading dock"],"example":"The ship stopped at the dock to unload cargo.","exampleZh":"這艘船停靠在碼頭卸貨。","synonyms":["pier","wharf"],"level":4,"theme":"旅遊與交通"},{"word":"doctor","pos":"n.","phonetic":"[ˈdɑktɚ]","meaning":"醫生；博士","definition":"a person qualified to treat illness","collocations":["see a doctor","family doctor","doctor's appointment"],"example":"I need to see a doctor about my cough.","exampleZh":"我需要去看醫生治療我的咳嗽。","synonyms":["physician"],"level":1,"theme":"醫療與保險"},{"word":"document","pos":"n. / v.","phonetic":"[ˈdɑkjəmənt]","meaning":"文件；記錄","definition":"a piece of written material providing information","collocations":["legal document","sign a document","document a process"],"example":"Please sign this document before you leave.","exampleZh":"離開前請簽署這份文件。","synonyms":["file","record"],"level":3,"theme":"人事與職涯"},{"word":"documentary","pos":"n./adj.","phonetic":"[ˌdɑkjəˈmɛntərɪ]","meaning":"紀錄片；文件的","definition":"a film or program that gives facts about real events or people","collocations":["documentary film","watch a documentary"],"example":"The museum is screening a documentary about local craftsmen.","exampleZh":"博物館正在放映一部關於當地工匠的紀錄片。","synonyms":[],"level":3,"theme":"媒體與活動"},{"word":"documentation","pos":"n.","phonetic":"[ˌdɑkjəmɛnˈteʃən]","meaning":"文件；證明文件；文件記錄","definition":"official documents that prove or record something","collocations":["supporting documentation","provide documentation","complete documentation"],"example":"Please submit all required documentation with your visa application.","exampleZh":"請隨簽證申請一併繳交所有必要文件。","synonyms":["paperwork","records"],"level":4,"theme":"辦公室與行政"},{"word":"dollar","pos":"n.","phonetic":"[ˈdɑlɚ]","meaning":"美元","definition":"the basic unit of money in the United States","collocations":["US dollar","dollar bill","spend a dollar"],"example":"The toy costs about five dollars.","exampleZh":"這個玩具大約要五美元。","synonyms":[],"level":1,"theme":"財務與會計"},{"word":"domestic","pos":"adj.","phonetic":"[dəˈmɛstɪk]","meaning":"家庭的；國內的","definition":"relating to the home, or not foreign","collocations":["domestic flight","domestic animal","domestic affairs"],"example":"The airline offers many domestic flights every day.","exampleZh":"這家航空公司每天提供許多國內航班。","synonyms":["household","national"],"level":5,"theme":"合約與法律"},{"word":"donate","pos":"v.","phonetic":"[ˈdonet]","meaning":"捐贈","definition":"to give something as a gift to charity","collocations":["donate money","donate blood","donate to charity"],"example":"They donated a large sum of money to the school.","exampleZh":"他們捐了一大筆錢給學校。","synonyms":["contribute","give"],"level":4,"theme":"財務與會計"},{"word":"donation","pos":"n.","phonetic":"[doˈneʃən]","meaning":"捐款；捐贈","definition":"money or goods given to help a person or organization","collocations":["make a donation","charitable donation","blood donation"],"example":"The company made a generous donation to the local food bank.","exampleZh":"該公司向當地食物銀行慷慨捐款。","synonyms":["contribution","gift"],"level":3,"theme":"媒體與活動"},{"word":"donor","pos":"n.","phonetic":"[ˈdonɚ]","meaning":"捐贈者；捐獻者","definition":"a person who gives something, especially blood or an organ","collocations":["blood donor","organ donor","generous donor"],"example":"He became a blood donor after college.","exampleZh":"他大學畢業後成為一名捐血者。","synonyms":["contributor","giver"],"level":5,"theme":"醫療與保險"},{"word":"door","pos":"n.","phonetic":"[dor]","meaning":"門","definition":"a hinged barrier used to open and close an entrance","collocations":["open the door","front door","knock on the door"],"example":"Please close the door when you leave.","exampleZh":"你離開時請把門關上。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"dose","pos":"n. / v.","phonetic":"[dos]","meaning":"劑量","definition":"a measured quantity of medicine","collocations":["daily dose","dose of medicine","overdose"],"example":"Take one dose of this medicine every morning.","exampleZh":"每天早上服用一劑這種藥。","synonyms":["dosage"],"level":4,"theme":"醫療與保險"},{"word":"double","pos":"adj. / v. / n.","phonetic":"[ˈdʌbl̩]","meaning":"雙倍的；使加倍","definition":"twice as much or as many","collocations":["double the amount","double room","double-check"],"example":"The price of the ticket has doubled since last year.","exampleZh":"這張票的價格自去年以來已經翻倍了。","synonyms":["twofold"],"level":2,"theme":"科技與通訊"},{"word":"doubt","pos":"n. / v.","phonetic":"[daʊt]","meaning":"懷疑","definition":"a feeling of uncertainty","collocations":["have doubts","without a doubt","doubt someone's word"],"example":"I have no doubt that she will succeed.","exampleZh":"我毫不懷疑她會成功。","synonyms":["uncertainty","suspicion"],"level":2,"theme":"日常與一般"},{"word":"down","pos":"adv. / prep. / adj.","phonetic":"[daʊn]","meaning":"向下；沮喪的","definition":"toward a lower place","collocations":["sit down","feel down","down the street"],"example":"He walked down the street toward the station.","exampleZh":"他沿著街道走向車站。","synonyms":["downward"],"level":1,"theme":"日常與一般"},{"word":"download","pos":"v. / n.","phonetic":"[ˈdaʊnˌlod]","meaning":"下載","definition":"to copy data from the internet to a device","collocations":["download a file","download speed","free download"],"example":"You can download the app for free.","exampleZh":"你可以免費下載這個應用程式。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"downstairs","pos":"adv. / adj.","phonetic":"[ˈdaʊnˈstɛrz]","meaning":"樓下","definition":"on or to a lower floor","collocations":["go downstairs","downstairs neighbor"],"example":"The kitchen is downstairs, next to the living room.","exampleZh":"廚房在樓下，就在客廳旁邊。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"downtown","pos":"n. / adv.","phonetic":"[ˈdaʊnˈtaʊn]","meaning":"市中心","definition":"the central business part of a city","collocations":["go downtown","downtown area","downtown traffic"],"example":"We went downtown to watch a movie.","exampleZh":"我們去市中心看電影。","synonyms":["city center"],"level":3,"theme":"旅遊與交通"},{"word":"dozen","pos":"n.","phonetic":"[ˈdʌzn̩]","meaning":"一打；十二個","definition":"a group of twelve","collocations":["a dozen eggs","dozens of times","half a dozen"],"example":"She bought a dozen eggs at the market.","exampleZh":"她在市場買了一打雞蛋。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"draft","pos":"n. / v.","phonetic":"[dræft]","meaning":"草稿；徵兵；匯票","definition":"a preliminary version of a piece of writing, or to write such a version","collocations":["draft a letter","rough draft","draft a proposal"],"example":"She wrote a draft of her essay before the final version.","exampleZh":"她在寫最終版本之前先寫了一份草稿。","synonyms":["outline","sketch"],"level":4,"theme":"人事與職涯"},{"word":"dramatic","pos":"adj.","phonetic":"[drəˈmætɪk]","meaning":"戲劇性的；引人注目的","definition":"striking in appearance or effect","collocations":["dramatic change","dramatic increase","dramatic effect"],"example":"There was a dramatic increase in sales last month.","exampleZh":"上個月銷售額有戲劇性的成長。","synonyms":["striking","sudden"],"level":4,"theme":"日常與一般"},{"word":"dramatically","pos":"adv.","phonetic":"[drəˈmætɪklɪ]","meaning":"大幅地；戲劇性地","definition":"in a sudden and very noticeable way","collocations":["increase dramatically","change dramatically","drop dramatically"],"example":"Online sales have increased dramatically over the past two years.","exampleZh":"過去兩年線上銷售額大幅成長。","synonyms":["significantly","sharply"],"level":4,"theme":"日常與一般"},{"word":"draw","pos":"v. / n.","phonetic":"[drɔ]","meaning":"畫；拉；抽籤；平局","definition":"to produce a picture by making lines","collocations":["draw a picture","draw conclusions","draw attention"],"example":"The little girl loves to draw pictures of animals.","exampleZh":"小女孩喜歡畫動物的圖畫。","synonyms":["sketch","pull"],"level":2,"theme":"媒體與活動"},{"word":"drawer","pos":"n.","phonetic":"[drɔr]","meaning":"抽屜","definition":"a box-shaped storage compartment","collocations":["open a drawer","top drawer","desk drawer"],"example":"She keeps her socks in the top drawer.","exampleZh":"她把襪子放在最上層的抽屜裡。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"dress","pos":"n. / v.","phonetic":"[drɛs]","meaning":"洋裝；穿衣","definition":"a one-piece garment for women, or to put on clothes","collocations":["wear a dress","dress up","get dressed"],"example":"She wore a beautiful red dress to the party.","exampleZh":"她穿了一件漂亮的紅色洋裝去參加派對。","synonyms":["gown","attire"],"level":1,"theme":"購物與消費"},{"word":"drink","pos":"v. / n.","phonetic":"[drɪŋk]","meaning":"喝；飲料","definition":"to take liquid into the mouth and swallow","collocations":["drink water","soft drink","drink alcohol"],"example":"You should drink more water every day.","exampleZh":"你每天應該多喝水。","synonyms":["beverage","sip"],"level":1,"theme":"餐飲與住宿"},{"word":"drive","pos":"v. / n.","phonetic":"[draɪv]","meaning":"駕駛；開車；驅動力","definition":"to operate and control a vehicle","collocations":["drive a car","driving license","drive someone crazy"],"example":"My father drives me to school every day.","exampleZh":"我爸爸每天開車送我上學。","synonyms":["operate","motivate"],"level":1,"theme":"旅遊與交通"},{"word":"driver","pos":"n.","phonetic":"[ˈdraɪvɚ]","meaning":"駕駛員；司機","definition":"a person who drives a vehicle","collocations":["bus driver","careful driver","taxi driver"],"example":"The bus driver stopped to let the passengers on.","exampleZh":"公車司機停下來讓乘客上車。","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"drop","pos":"v. / n.","phonetic":"[drɑp]","meaning":"掉落；滴；下降","definition":"to fall or let fall","collocations":["drop a hint","drop by","price drop"],"example":"Please don't drop the glass; it will break.","exampleZh":"請不要摔破玻璃杯，它會破掉。","synonyms":["fall","decline"],"level":2,"theme":"日常與一般"},{"word":"drug","pos":"n.","phonetic":"[drʌg]","meaning":"藥物；毒品","definition":"a medicine or an illegal substance","collocations":["take drugs","drug abuse","prescription drug"],"example":"The doctor prescribed a new drug for his illness.","exampleZh":"醫生為他的病開了一種新藥。","synonyms":["medicine","narcotic"],"level":3,"theme":"醫療與保險"},{"word":"drugstore","pos":"n.","phonetic":"[ˈdrʌgˌstor]","meaning":"藥妝店","definition":"a store that sells medicine and other goods","collocations":["local drugstore","buy at the drugstore"],"example":"I bought some shampoo at the drugstore.","exampleZh":"我在藥妝店買了一些洗髮精。","synonyms":["pharmacy"],"level":3,"theme":"財務與會計"},{"word":"dry","pos":"adj. / v.","phonetic":"[draɪ]","meaning":"乾燥的；使乾燥","definition":"free from moisture","collocations":["dry weather","dry clothes","dry season"],"example":"The towel felt completely dry.","exampleZh":"那條毛巾摸起來完全乾了。","synonyms":["arid","dehydrated"],"level":1,"theme":"日常與一般"},{"word":"dryer","pos":"n.","phonetic":"[ˈdraɪɚ]","meaning":"烘乾機","definition":"a machine for drying clothes or hair","collocations":["hair dryer","clothes dryer","use a dryer"],"example":"She put the wet clothes in the dryer.","exampleZh":"她把濕衣服放進烘乾機裡。","synonyms":[],"level":3,"theme":"房產與設施"},{"word":"due","pos":"adj.","phonetic":"[dju]","meaning":"到期的；應得的；由於","definition":"expected at a certain time; owed","collocations":["due date","due to","payment due"],"example":"The report is due next Monday.","exampleZh":"這份報告下週一到期。","synonyms":["owed","expected"],"level":3,"theme":"日常與一般"},{"word":"duplicate","pos":"v. / n. / adj.","phonetic":"[ˈdjupləˌket]","meaning":"複製；副本","definition":"to make an exact copy of something","collocations":["duplicate a document","duplicate key","exact duplicate"],"example":"Please duplicate this file and send a copy to me.","exampleZh":"請複製這份文件並寄一份副本給我。","synonyms":["copy","replicate"],"level":5,"theme":"科技與通訊"},{"word":"durable","pos":"adj.","phonetic":"[ˈdjʊrəbl̩]","meaning":"耐用的","definition":"able to withstand wear; long-lasting","collocations":["durable material","durable goods","durable friendship"],"example":"This backpack is made of durable material.","exampleZh":"這個背包是用耐用的材質製成的。","synonyms":["sturdy","long-lasting"],"level":5,"theme":"日常與一般"},{"word":"duration","pos":"n.","phonetic":"[djʊˈreʃən]","meaning":"期間；持續時間","definition":"the time during which something continues","collocations":["duration of the flight","short duration","entire duration"],"example":"The duration of the flight is about three hours.","exampleZh":"這趟飛行的時間大約是三個小時。","synonyms":["length","period"],"level":5,"theme":"日常與一般"},{"word":"during","pos":"prep.","phonetic":"[ˈdjʊrɪŋ]","meaning":"在……期間","definition":"throughout the course of","collocations":["during the day","during vacation","during class"],"example":"Please turn off your phone during class.","exampleZh":"上課期間請把手機關機。","synonyms":["throughout"],"level":1,"theme":"日常與一般"},{"word":"dust","pos":"n. / v.","phonetic":"[dʌst]","meaning":"灰塵；撢灰塵","definition":"fine dry powder of dirt","collocations":["dust off","layer of dust","dust the shelves"],"example":"There was a thick layer of dust on the shelf.","exampleZh":"架子上有一層厚厚的灰塵。","synonyms":["dirt","grime"],"level":2,"theme":"房產與設施"},{"word":"duty","pos":"n.","phonetic":"[ˈdjuti]","meaning":"責任；職責；關稅","definition":"a moral or legal obligation","collocations":["sense of duty","on duty","duty-free"],"example":"It is our duty to protect the environment.","exampleZh":"保護環境是我們的責任。","synonyms":["obligation","responsibility"],"level":3,"theme":"日常與一般"},{"word":"duty-free","pos":"adj./adv.","phonetic":"[ˈdutɪˈfri]","meaning":"免稅的；免稅地","definition":"describing goods that can be bought without paying import tax","collocations":["duty-free shop","duty-free goods","shop duty-free"],"example":"Passengers can buy perfume at the duty-free shop before boarding.","exampleZh":"乘客登機前可在免稅店購買香水。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"dwelling","pos":"n.","phonetic":"[ˈdwɛlɪŋ]","meaning":"住所；住宅","definition":"a house or place to live in","collocations":["human dwelling","modest dwelling"],"example":"The old farmhouse was their family dwelling for generations.","exampleZh":"那間老農舍是他們家族世代居住的地方。","synonyms":["residence","house"],"level":6,"theme":"房產與設施"},{"word":"each","pos":"adj. / pron.","phonetic":"[itʃ]","meaning":"每一個","definition":"used to refer to every individual thing or person in a group separately","collocations":["each one","each other","each of us"],"example":"Each student must bring a pencil.","exampleZh":"每個學生都必須帶一支鉛筆。","synonyms":["every"],"level":1,"theme":"日常與一般"},{"word":"early","pos":"adj. / adv.","phonetic":"[ˈɝlɪ]","meaning":"早的；提早地","definition":"before the usual or expected time","collocations":["early morning","get up early","early stage"],"example":"We arrived early to get good seats.","exampleZh":"我們提早到場以佔到好位子。","synonyms":["ahead of time"],"level":1,"theme":"日常與一般"},{"word":"earn","pos":"v.","phonetic":"[ɝn]","meaning":"賺得；獲得","definition":"to receive money or a reward for work done","collocations":["earn money","earn a living","earn respect"],"example":"He earns a good salary as an engineer.","exampleZh":"他當工程師賺取不錯的薪水。","synonyms":["gain","obtain"],"level":2,"theme":"財務與會計"},{"word":"earnings","pos":"n.","phonetic":"[ˈɝnɪŋz]","meaning":"收益；盈餘；所得","definition":"the money a person or company receives for work or business","collocations":["quarterly earnings","earnings report","annual earnings"],"example":"The company's quarterly earnings exceeded analysts' expectations.","exampleZh":"該公司的季度盈餘超出分析師的預期。","synonyms":["income","profits"],"level":5,"theme":"財務與會計"},{"word":"ease","pos":"n. / v.","phonetic":"[iz]","meaning":"輕鬆；容易；減輕","definition":"the state of being comfortable or without difficulty; to make less severe","collocations":["with ease","ease the pain","at ease"],"example":"She solved the puzzle with ease.","exampleZh":"她輕鬆地解開了這個謎題。","synonyms":["comfort","relieve"],"level":3,"theme":"日常與一般"},{"word":"easily","pos":"adv.","phonetic":"[ˈizlɪ]","meaning":"容易地；輕易地","definition":"without difficulty","collocations":["win easily","easily accessible","easily forgotten"],"example":"He easily passed the exam.","exampleZh":"他輕鬆地通過了考試。","synonyms":["effortlessly"],"level":2,"theme":"日常與一般"},{"word":"east","pos":"n. / adj. / adv.","phonetic":"[ist]","meaning":"東方；東方的","definition":"the direction from which the sun rises","collocations":["the Far East","face east","east coast"],"example":"The sun rises in the east.","exampleZh":"太陽從東方升起。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"easy","pos":"adj.","phonetic":"[ˈizɪ]","meaning":"容易的；輕鬆的","definition":"not difficult; requiring little effort","collocations":["an easy task","take it easy","easy to understand"],"example":"This math problem is easy for me.","exampleZh":"這道數學題對我來說很簡單。","synonyms":["simple"],"level":1,"theme":"日常與一般"},{"word":"economic","pos":"adj.","phonetic":"[ˌikəˈnɑmɪk]","meaning":"經濟的","definition":"relating to trade, industry, and money","collocations":["economic growth","economic crisis","economic policy"],"example":"The country is facing an economic crisis.","exampleZh":"這個國家正面臨經濟危機。","synonyms":["financial"],"level":4,"theme":"財務與會計"},{"word":"economical","pos":"adj.","phonetic":"[ˌikəˈnɑmɪkl]","meaning":"節約的；經濟實惠的","definition":"giving good value for the amount of money spent","collocations":["an economical car","economical use of resources","economical way"],"example":"This car is very economical to run.","exampleZh":"這輛車開起來很省油。","synonyms":["thrifty","efficient"],"level":5,"theme":"財務與會計"},{"word":"economy","pos":"n.","phonetic":"[ɪˈkɑnəmɪ]","meaning":"經濟；經濟體系","definition":"the wealth and resources of a country or region","collocations":["a strong economy","global economy","economy grows"],"example":"The nation's economy is growing rapidly.","exampleZh":"這個國家的經濟正快速成長。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"edit","pos":"v.","phonetic":"[ˈɛdɪt]","meaning":"編輯；校訂","definition":"to prepare written material for publication by correcting errors","collocations":["edit a document","edit a video","edit carefully"],"example":"She edited the article before it was published.","exampleZh":"她在文章發表前先進行了編輯。","synonyms":["revise"],"level":4,"theme":"科技與通訊"},{"word":"edition","pos":"n.","phonetic":"[ɪˈdɪʃən]","meaning":"版本；版次","definition":"a particular version of a printed text","collocations":["first edition","special edition","the latest edition"],"example":"This is the second edition of the textbook.","exampleZh":"這是這本教科書的第二版。","synonyms":["version"],"level":4,"theme":"科技與通訊"},{"word":"editor","pos":"n.","phonetic":"[ˈɛdɪtɚ]","meaning":"編輯；編輯者","definition":"a person who edits texts, films, or newspapers","collocations":["chief editor","newspaper editor","video editor"],"example":"She works as an editor for a magazine.","exampleZh":"她在一本雜誌擔任編輯。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"education","pos":"n.","phonetic":"[ˌɛdʒʊˈkeʃən]","meaning":"教育","definition":"the process of teaching or learning","collocations":["higher education","receive education","education system"],"example":"Education is important for everyone.","exampleZh":"教育對每個人都很重要。","synonyms":["schooling"],"level":2,"theme":"人事與職涯"},{"word":"educational","pos":"adj.","phonetic":"[ˌɛdʒʊˈkeʃənḷ]","meaning":"教育的；有教育意義的","definition":"relating to education, or providing knowledge","collocations":["educational program","educational toy","educational background"],"example":"The museum offers many educational activities.","exampleZh":"這間博物館提供許多具教育意義的活動。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"effect","pos":"n.","phonetic":"[ɪˈfɛkt]","meaning":"效果；影響","definition":"a change that is a result of an action","collocations":["side effect","have an effect on","take effect"],"example":"The medicine had an immediate effect.","exampleZh":"這藥立刻產生了效果。","synonyms":["result","impact"],"level":3,"theme":"日常與一般"},{"word":"effective","pos":"adj.","phonetic":"[ɪˈfɛktɪv]","meaning":"有效的","definition":"successful in producing a desired result","collocations":["effective method","cost-effective","highly effective"],"example":"This is an effective way to learn vocabulary.","exampleZh":"這是一個學習單字的有效方法。","synonyms":["efficient"],"level":4,"theme":"日常與一般"},{"word":"effectively","pos":"adv.","phonetic":"[ɪˈfɛktɪvlɪ]","meaning":"有效地；實際上","definition":"in a way that produces the intended result","collocations":["communicate effectively","work effectively","manage time effectively"],"example":"The training helps new managers communicate more effectively with staff.","exampleZh":"這項訓練幫助新任主管更有效地與員工溝通。","synonyms":["efficiently"],"level":3,"theme":"日常與一般"},{"word":"efficiency","pos":"n.","phonetic":"[ɪˈfɪʃənsɪ]","meaning":"效率","definition":"the ability to do something well without wasting time or energy","collocations":["increase efficiency","work efficiency","energy efficiency"],"example":"The new system improved office efficiency.","exampleZh":"新系統提升了辦公室的效率。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"efficient","pos":"adj.","phonetic":"[ɪˈfɪʃənt]","meaning":"有效率的","definition":"achieving maximum productivity with minimum wasted effort","collocations":["an efficient worker","efficient use of time","fuel efficient"],"example":"She is an efficient manager.","exampleZh":"她是一位有效率的經理。","synonyms":["productive"],"level":5,"theme":"日常與一般"},{"word":"efficiently","pos":"adv.","phonetic":"[ɪˈfɪʃəntlɪ]","meaning":"有效率地","definition":"in a way that works well without wasting time or resources","collocations":["run efficiently","work efficiently","operate efficiently"],"example":"The new system allows us to process orders more efficiently.","exampleZh":"新系統讓我們能更有效率地處理訂單。","synonyms":["productively"],"level":3,"theme":"日常與一般"},{"word":"effort","pos":"n.","phonetic":"[ˈɛfɚt]","meaning":"努力","definition":"a vigorous or determined attempt","collocations":["make an effort","great effort","effort to improve"],"example":"He made a great effort to finish the project.","exampleZh":"他非常努力完成了這個專案。","synonyms":["endeavor"],"level":2,"theme":"日常與一般"},{"word":"either","pos":"pron. / adj. / conj. / adv.","phonetic":"[ˈiðɚ]","meaning":"（兩者中）任一；也（不）","definition":"used to refer to one of two possibilities","collocations":["either way","either...or","not either"],"example":"You can choose either color.","exampleZh":"你可以選擇任一顏色。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"elect","pos":"v.","phonetic":"[ɪˈlɛkt]","meaning":"選舉；選出","definition":"to choose someone by voting","collocations":["elect a president","newly elected","elect officials"],"example":"The citizens elected a new mayor.","exampleZh":"市民們選出了新市長。","synonyms":["vote for"],"level":4,"theme":"合約與法律"},{"word":"election","pos":"n.","phonetic":"[ɪˈlɛkʃən]","meaning":"選舉","definition":"a formal process of choosing a person for a position by voting","collocations":["win an election","presidential election","hold an election"],"example":"The presidential election will be held next month.","exampleZh":"總統選舉將於下個月舉行。","synonyms":["vote"],"level":4,"theme":"合約與法律"},{"word":"electric","pos":"adj.","phonetic":"[ɪˈlɛktrɪk]","meaning":"電動的；電的","definition":"powered by electricity","collocations":["electric car","electric guitar","electric shock"],"example":"They bought a new electric car.","exampleZh":"他們買了一輛新的電動車。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"electrical","pos":"adj.","phonetic":"[ɪˈlɛktrɪkl]","meaning":"電的；用電的","definition":"relating to electricity or using electricity","collocations":["electrical equipment","electrical outlet","electrical engineer"],"example":"All electrical equipment must be inspected once a year.","exampleZh":"所有電氣設備每年必須檢查一次。","synonyms":["electric"],"level":3,"theme":"生產與物流"},{"word":"electricity","pos":"n.","phonetic":"[ɪˌlɛkˈtrɪsətɪ]","meaning":"電力","definition":"a form of energy used for lighting and power","collocations":["generate electricity","electricity bill","supply electricity"],"example":"The storm cut off the electricity in the village.","exampleZh":"暴風雨切斷了村莊的電力。","synonyms":["power"],"level":3,"theme":"科技與通訊"},{"word":"electronic","pos":"adj.","phonetic":"[ɪˌlɛkˈtrɑnɪk]","meaning":"電子的","definition":"having many small parts that control an electrical current, such as a computer","collocations":["electronic device","electronic mail","electronic music"],"example":"She sells electronic devices online.","exampleZh":"她在網路上販售電子產品。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"electronically","pos":"adv.","phonetic":"[ɪˌlɛkˈtrɑnɪklɪ]","meaning":"以電子方式","definition":"using a computer or other electronic device","collocations":["submit electronically","pay electronically","sign electronically"],"example":"All invoices should be submitted electronically through the portal.","exampleZh":"所有請款單都應透過入口網站以電子方式提交。","synonyms":["digitally"],"level":4,"theme":"科技與通訊"},{"word":"electronics","pos":"n.","phonetic":"[ɪˌlɛkˈtrɑnɪks]","meaning":"電子產品；電子學","definition":"electronic devices, or the science of electronic technology","collocations":["consumer electronics","electronics store","electronics manufacturer"],"example":"The electronics store is having a clearance sale this weekend.","exampleZh":"這家電子產品店本週末舉行清倉特賣。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"elevator","pos":"n.","phonetic":"[ˈɛləˌvetɚ]","meaning":"電梯","definition":"a machine that carries people or goods between floors of a building","collocations":["take the elevator","elevator door","elevator button"],"example":"We took the elevator to the tenth floor.","exampleZh":"我們搭電梯到十樓。","synonyms":["lift"],"level":2,"theme":"房產與設施"},{"word":"eligible","pos":"adj.","phonetic":"[ˈɛlɪdʒəbl]","meaning":"有資格的；合格的","definition":"having the right qualifications to do or receive something","collocations":["eligible for a refund","eligible employees","eligible to vote"],"example":"Employees who work full-time are eligible for the annual bonus.","exampleZh":"全職員工有資格領取年終獎金。","synonyms":["qualified","entitled"],"level":4,"theme":"人事與職涯"},{"word":"eliminate","pos":"v.","phonetic":"[ɪˈlɪməˌnet]","meaning":"消除；淘汰","definition":"to completely remove or get rid of something","collocations":["eliminate errors","eliminate poverty","be eliminated from"],"example":"The team was eliminated in the first round.","exampleZh":"這支隊伍在第一輪就被淘汰了。","synonyms":["remove","get rid of"],"level":5,"theme":"日常與一般"},{"word":"else","pos":"adv.","phonetic":"[ɛls]","meaning":"其他；別的","definition":"in addition; other than someone or something already mentioned","collocations":["something else","or else","anyone else"],"example":"Is there anything else you need?","exampleZh":"你還需要其他東西嗎？","synonyms":["other"],"level":2,"theme":"日常與一般"},{"word":"elsewhere","pos":"adv.","phonetic":"[ˈɛlsˌhwɛr]","meaning":"在別處；到別處","definition":"in, at, or to another place","collocations":["move elsewhere","look elsewhere","found elsewhere"],"example":"If this shop is closed, we can shop elsewhere.","exampleZh":"如果這家店關了，我們可以去別的地方購物。","synonyms":["somewhere else"],"level":4,"theme":"日常與一般"},{"word":"email","pos":"n./v.","phonetic":"[ˈiˌmel]","meaning":"電子郵件；寄電子郵件","definition":"a message sent electronically from one computer to another","collocations":["send an email","email address","reply to an email"],"example":"Please email the final report to the entire project team.","exampleZh":"請將最終報告以電子郵件寄給整個專案團隊。","synonyms":[],"level":1,"theme":"科技與通訊"},{"word":"emerge","pos":"v.","phonetic":"[ɪˈmɝdʒ]","meaning":"出現；浮現","definition":"to come out from somewhere or come into existence","collocations":["emerge from","new evidence emerges","emerge victorious"],"example":"The sun emerged from behind the clouds.","exampleZh":"太陽從雲後面出現了。","synonyms":["appear"],"level":5,"theme":"日常與一般"},{"word":"emergency","pos":"n.","phonetic":"[ɪˈmɝdʒənsɪ]","meaning":"緊急情況","definition":"a serious, unexpected situation requiring immediate action","collocations":["emergency room","in case of emergency","emergency exit"],"example":"Call 911 in case of an emergency.","exampleZh":"遇到緊急情況時，請撥打911。","synonyms":["crisis"],"level":3,"theme":"醫療與保險"},{"word":"emphasize","pos":"v.","phonetic":"[ˈɛmfəˌsaɪz]","meaning":"強調","definition":"to give special importance to something","collocations":["emphasize the importance","strongly emphasize","emphasize a point"],"example":"The teacher emphasized the importance of practice.","exampleZh":"老師強調練習的重要性。","synonyms":["stress","highlight"],"level":5,"theme":"溝通與語言"},{"word":"employ","pos":"v.","phonetic":"[ɪmˈplɔɪ]","meaning":"雇用；使用","definition":"to give work to someone in exchange for payment","collocations":["employ workers","employ a method","fully employed"],"example":"The factory employs over 500 workers.","exampleZh":"這間工廠雇用了超過五百名員工。","synonyms":["hire"],"level":4,"theme":"人事與職涯"},{"word":"employee","pos":"n.","phonetic":"[ˌɛmplɔɪˈi]","meaning":"員工","definition":"a person who works for another person or company for pay","collocations":["hire an employee","loyal employee","employee benefits"],"example":"The company treats its employees well.","exampleZh":"這間公司善待員工。","synonyms":["worker","staff"],"level":3,"theme":"人事與職涯"},{"word":"employer","pos":"n.","phonetic":"[ɪmˈplɔɪɚ]","meaning":"雇主","definition":"a person or organization that employs people","collocations":["good employer","employer and employee","potential employer"],"example":"Her employer gave her a raise.","exampleZh":"她的雇主給她加薪了。","synonyms":["boss"],"level":3,"theme":"人事與職涯"},{"word":"employment","pos":"n.","phonetic":"[ɪmˈplɔɪmənt]","meaning":"就業；雇用","definition":"the state of having paid work","collocations":["find employment","full employment","employment rate"],"example":"The new factory created many employment opportunities.","exampleZh":"這間新工廠創造了許多就業機會。","synonyms":["job","work"],"level":4,"theme":"人事與職涯"},{"word":"empty","pos":"adj./v.","phonetic":"[ˈɛmptɪ]","meaning":"空的；清空","definition":"containing nothing, or to remove everything from a container","collocations":["empty seat","empty the trash","empty box"],"example":"Please empty your desk drawers before the office relocation.","exampleZh":"辦公室搬遷前，請清空你的書桌抽屜。","synonyms":["vacant","clear"],"level":1,"theme":"日常與一般"},{"word":"enable","pos":"v.","phonetic":"[ɪnˈebl]","meaning":"使能夠；賦予權力","definition":"to make someone able to do something, or make something possible","collocations":["enable someone to do","enable access","technology that enables"],"example":"The new software enables users to edit videos easily.","exampleZh":"這套新軟體讓使用者能輕鬆剪輯影片。","synonyms":["allow","permit"],"level":3,"theme":"科技與通訊"},{"word":"enclose","pos":"v.","phonetic":"[ɪnˈkloz]","meaning":"圍住；附上（文件等）","definition":"to surround an area completely, or to put something inside an envelope with a letter","collocations":["enclose a garden","enclose a check","enclosed area"],"example":"Please find the documents enclosed with this letter.","exampleZh":"請查收隨信附上的文件。","synonyms":["surround","attach"],"level":4,"theme":"溝通與語言"},{"word":"enclosure","pos":"n.","phonetic":"[ɪnˈkloʒɚ]","meaning":"附件；圍場；圈地","definition":"something included with a letter, or an area surrounded by a fence","collocations":["see enclosure","letter enclosure"],"example":"The enclosure with this letter contains your updated insurance policy.","exampleZh":"隨函附件為您更新後的保險契約。","synonyms":["attachment"],"level":5,"theme":"辦公室與行政"},{"word":"encounter","pos":"v. / n.","phonetic":"[ɪnˈkaʊntɚ]","meaning":"遭遇；邂逅；相遇","definition":"to meet or experience something, especially something unexpected","collocations":["encounter difficulty","a chance encounter","encounter a problem"],"example":"We encountered many difficulties during the trip.","exampleZh":"我們在旅途中遇到了許多困難。","synonyms":["meet","face"],"level":4,"theme":"日常與一般"},{"word":"encourage","pos":"v.","phonetic":"[ɪnˈkɝɪdʒ]","meaning":"鼓勵；激勵","definition":"to give someone support, confidence, or hope","collocations":["encourage someone to","encourage growth","words of encouragement"],"example":"Her parents always encourage her to follow her dreams.","exampleZh":"她的父母總是鼓勵她追求夢想。","synonyms":["motivate","inspire"],"level":2,"theme":"日常與一般"},{"word":"end","pos":"n./v.","phonetic":"[ɛnd]","meaning":"結束；末端；終止","definition":"the final part of something, or to finish","collocations":["end of the month","end a meeting","year-end"],"example":"The promotion will end at the close of business on Friday.","exampleZh":"促銷活動將於週五營業結束時截止。","synonyms":["finish","conclude"],"level":1,"theme":"日常與一般"},{"word":"endure","pos":"v.","phonetic":"[ɪnˈdʊr]","meaning":"忍受；持續；耐久","definition":"to suffer something difficult, painful, or unpleasant patiently","collocations":["endure pain","endure hardship","hard to endure"],"example":"Soldiers had to endure freezing temperatures during the war.","exampleZh":"士兵們在戰爭期間得忍受酷寒的氣溫。","synonyms":["bear","withstand"],"level":5,"theme":"日常與一般"},{"word":"energy","pos":"n.","phonetic":"[ˈɛnɚdʒi]","meaning":"能量；精力；能源","definition":"the strength and vitality needed for activity, or power from fuel sources","collocations":["solar energy","full of energy","save energy"],"example":"We should try to save energy at home.","exampleZh":"我們在家裡應該試著節省能源。","synonyms":["power","vigor"],"level":2,"theme":"科技與通訊"},{"word":"engage","pos":"v.","phonetic":"[ɪnˈgedʒ]","meaning":"從事；使參與；訂婚","definition":"to participate or become involved in an activity, or to attract someone's interest","collocations":["engage in conversation","engage the audience","get engaged"],"example":"Students actively engaged in the class discussion.","exampleZh":"學生們積極參與了課堂討論。","synonyms":["participate","involve"],"level":4,"theme":"人事與職涯"},{"word":"engagement","pos":"n.","phonetic":"[ɪnˈgedʒmənt]","meaning":"約定；婚約；參與；交戰","definition":"an arrangement to do something, or involvement in an activity","collocations":["prior engagement","customer engagement","speaking engagement"],"example":"The director declined the invitation due to a prior engagement.","exampleZh":"由於已有約在先，總監婉拒了邀請。","synonyms":["appointment","commitment"],"level":5,"theme":"辦公室與行政"},{"word":"engine","pos":"n.","phonetic":"[ˈɛndʒən]","meaning":"引擎；發動機","definition":"a machine that converts energy into mechanical motion","collocations":["car engine","start the engine","engine trouble"],"example":"The mechanic checked the car's engine before the trip.","exampleZh":"技師在出發前檢查了汽車的引擎。","synonyms":["motor"],"level":2,"theme":"旅遊與交通"},{"word":"engineer","pos":"n.","phonetic":"[ˌɛndʒəˈnɪr]","meaning":"工程師","definition":"a person who designs, builds, or maintains engines, machines, or structures","collocations":["civil engineer","software engineer","become an engineer"],"example":"She works as a software engineer at a tech company.","exampleZh":"她在一家科技公司擔任軟體工程師。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"engineering","pos":"n.","phonetic":"[ˌɛndʒəˈnɪrɪŋ]","meaning":"工程；工程學","definition":"the work of designing and building machines, structures, or systems","collocations":["engineering department","civil engineering","engineering degree"],"example":"The engineering team resolved the design flaw within two days.","exampleZh":"工程團隊在兩天內解決了設計上的缺陷。","synonyms":[],"level":3,"theme":"生產與物流"},{"word":"enhance","pos":"v.","phonetic":"[ɪnˈhæns]","meaning":"提升；增強；提高","definition":"to improve the quality, value, or extent of something","collocations":["enhance performance","enhance the flavor","enhance one's image"],"example":"Regular exercise can enhance your overall health.","exampleZh":"規律運動能提升你整體的健康。","synonyms":["improve","boost"],"level":5,"theme":"日常與一般"},{"word":"enjoy","pos":"v.","phonetic":"[ɪnˈdʒɔɪ]","meaning":"享受；喜歡","definition":"to take pleasure in an activity or occasion","collocations":["enjoy oneself","enjoy the movie","enjoy life"],"example":"They enjoyed the concert last night.","exampleZh":"他們昨晚很享受那場演唱會。","synonyms":["like","appreciate"],"level":1,"theme":"日常與一般"},{"word":"enough","pos":"adj. / adv. / pron.","phonetic":"[ɪˈnʌf]","meaning":"足夠的；充分地","definition":"as much or as many as required","collocations":["enough time","enough money","good enough"],"example":"We don't have enough time to finish this today.","exampleZh":"我們沒有足夠的時間今天完成這個。","synonyms":["sufficient","adequate"],"level":1,"theme":"日常與一般"},{"word":"enroll","pos":"v.","phonetic":"[ɪnˈrol]","meaning":"註冊；入學；加入","definition":"to officially register as a member, student, or participant","collocations":["enroll in a course","enroll at school","enrollment fee"],"example":"She enrolled in a painting class last month.","exampleZh":"她上個月報名了一堂繪畫課。","synonyms":["register","sign up"],"level":4,"theme":"人事與職涯"},{"word":"enrollment","pos":"n.","phonetic":"[ɪnˈrolmənt]","meaning":"註冊；報名；入學","definition":"the act of officially joining a course, program, or organization","collocations":["open enrollment","enrollment form","enrollment period"],"example":"Open enrollment for health benefits begins on November first.","exampleZh":"健康保險的開放投保期自十一月一日開始。","synonyms":["registration"],"level":4,"theme":"人事與職涯"},{"word":"ensure","pos":"v.","phonetic":"[ɪnˈʃʊr]","meaning":"確保；保證","definition":"to make certain that something will happen or be the case","collocations":["ensure safety","ensure quality","ensure that"],"example":"The teacher checked twice to ensure everyone understood.","exampleZh":"老師檢查了兩次以確保每個人都理解了。","synonyms":["guarantee","assure"],"level":4,"theme":"日常與一般"},{"word":"enter","pos":"v.","phonetic":"[ˈɛntɚ]","meaning":"進入；參加","definition":"to come or go into a place, or to become involved in an activity","collocations":["enter a room","enter a contest","enter data"],"example":"He knocked before entering the office.","exampleZh":"他進辦公室前先敲了門。","synonyms":["go in","join"],"level":1,"theme":"日常與一般"},{"word":"enterprise","pos":"n.","phonetic":"[ˈɛntɚˌpraɪz]","meaning":"企業；事業；進取心","definition":"a company or business, or a large project","collocations":["private enterprise","small enterprise","enterprise software"],"example":"The bank offers special loans for small and medium enterprises.","exampleZh":"這家銀行為中小企業提供特別貸款。","synonyms":["company","venture"],"level":5,"theme":"企業經營"},{"word":"entertain","pos":"v.","phonetic":"[ˌɛntɚˈten]","meaning":"娛樂；招待；款待","definition":"to provide amusement or enjoyment, or to receive guests","collocations":["entertain guests","entertain an idea","entertain the audience"],"example":"The clown entertained the children at the party.","exampleZh":"那位小丑在派對上逗樂了孩子們。","synonyms":["amuse","host"],"level":3,"theme":"媒體與活動"},{"word":"entertainment","pos":"n.","phonetic":"[ˌɛntɚˈtenmənt]","meaning":"娛樂；餘興節目","definition":"shows, performances, or activities that people enjoy","collocations":["live entertainment","entertainment industry","evening entertainment"],"example":"The hotel provides live entertainment in the lounge every evening.","exampleZh":"飯店每晚在酒廊提供現場表演。","synonyms":["amusement"],"level":3,"theme":"媒體與活動"},{"word":"enthusiastic","pos":"adj.","phonetic":"[ɪnˌθjuziˈæstɪk]","meaning":"熱情的；熱心的","definition":"showing intense enjoyment, interest, or approval","collocations":["enthusiastic about","enthusiastic supporter","become enthusiastic"],"example":"He is very enthusiastic about learning new languages.","exampleZh":"他對學習新語言非常熱衷。","synonyms":["eager","passionate"],"level":4,"theme":"日常與一般"},{"word":"entire","pos":"adj.","phonetic":"[ɪnˈtaɪr]","meaning":"整個的；全部的","definition":"whole or complete, with no part left out","collocations":["the entire family","entire life","entire process"],"example":"The entire class passed the final exam.","exampleZh":"全班同學都通過了期末考試。","synonyms":["whole","complete"],"level":3,"theme":"日常與一般"},{"word":"entirely","pos":"adv.","phonetic":"[ɪnˈtaɪrlɪ]","meaning":"完全地；全然","definition":"completely and in every way","collocations":["entirely different","entirely possible","agree entirely"],"example":"The new office building is powered entirely by solar energy.","exampleZh":"新辦公大樓完全以太陽能供電。","synonyms":["completely","totally"],"level":3,"theme":"日常與一般"},{"word":"entitle","pos":"v.","phonetic":"[ɪnˈtaɪtl]","meaning":"給予權利；命名","definition":"to give someone a right to do or have something, or to give a title to a work","collocations":["be entitled to","entitle a book","entitled to vote"],"example":"Every citizen is entitled to a fair trial.","exampleZh":"每位公民都享有公平審判的權利。","synonyms":["qualify","authorize"],"level":5,"theme":"合約與法律"},{"word":"entrance","pos":"n.","phonetic":"[ˈɛntrəns]","meaning":"入口；進入；入學","definition":"a way into a place, or the act of entering","collocations":["main entrance","entrance exam","entrance fee"],"example":"Meet me at the entrance of the museum.","exampleZh":"在博物館入口處等我。","synonyms":["entry","doorway"],"level":2,"theme":"人事與職涯"},{"word":"entrepreneur","pos":"n.","phonetic":"[ˌɑntrəprəˈnɝ]","meaning":"創業家；企業家","definition":"a person who starts and runs their own business","collocations":["successful entrepreneur","young entrepreneur","serial entrepreneur"],"example":"The forum invites successful entrepreneurs to share their startup experiences.","exampleZh":"論壇邀請成功的創業家分享他們的創業經驗。","synonyms":["founder"],"level":5,"theme":"企業經營"},{"word":"entry","pos":"n.","phonetic":"[ˈɛntri]","meaning":"進入；入口；條目","definition":"the act of coming or going in, or an item recorded in a list","collocations":["entry fee","diary entry","gain entry"],"example":"She wrote a new entry in her diary every night.","exampleZh":"她每晚都在日記裡寫一篇新的紀錄。","synonyms":["entrance","admission"],"level":2,"theme":"人事與職涯"},{"word":"envelope","pos":"n.","phonetic":"[ˈɛnvəˌlop]","meaning":"信封","definition":"a flat paper container used to enclose a letter or document","collocations":["seal an envelope","stamp an envelope","a padded envelope"],"example":"He put the letter in an envelope and mailed it.","exampleZh":"他把信放進信封裡然後寄出去。","synonyms":[],"level":2,"theme":"溝通與語言"},{"word":"environment","pos":"n.","phonetic":"[ɪnˈvaɪrənmənt]","meaning":"環境；周遭事物","definition":"the surroundings or conditions in which a person, animal, or plant lives","collocations":["protect the environment","working environment","natural environment"],"example":"We must protect the environment for future generations.","exampleZh":"我們必須為了後代子孫保護環境。","synonyms":["surroundings"],"level":2,"theme":"日常與一般"},{"word":"environmental","pos":"adj.","phonetic":"[ɪnˌvaɪrənˈmɛntl]","meaning":"環境的；環保的","definition":"relating to the natural world and its protection","collocations":["environmental impact","environmental regulations","environmental protection"],"example":"The factory passed its annual environmental impact inspection.","exampleZh":"該工廠通過了年度環境影響檢查。","synonyms":["ecological"],"level":4,"theme":"企業經營"},{"word":"equal","pos":"adj. / v.","phonetic":"[ˈikwəl]","meaning":"平等的；相等的；等於","definition":"being the same in status, rights, or amount","collocations":["equal rights","equal opportunity","equal to"],"example":"Everyone should have equal rights before the law.","exampleZh":"每個人在法律面前都應享有平等的權利。","synonyms":["identical","equivalent"],"level":2,"theme":"日常與一般"},{"word":"equally","pos":"adv.","phonetic":"[ˈikwəlɪ]","meaning":"平等地；同樣地","definition":"in the same way or to the same degree","collocations":["equally important","divide equally","treat equally"],"example":"The bonus will be divided equally among all team members.","exampleZh":"獎金將由所有團隊成員平分。","synonyms":["evenly"],"level":2,"theme":"日常與一般"},{"word":"equip","pos":"v.","phonetic":"[ɪˈkwɪp]","meaning":"裝備；配備","definition":"to supply someone or something with necessary items for a task","collocations":["equip a kitchen","fully equipped","equip students with"],"example":"The lab is equipped with the latest technology.","exampleZh":"這間實驗室配備了最新的科技設備。","synonyms":["furnish","supply"],"level":4,"theme":"科技與通訊"},{"word":"equipment","pos":"n.","phonetic":"[ɪˈkwɪpmənt]","meaning":"設備；裝備","definition":"the necessary items for a particular purpose","collocations":["sports equipment","camping equipment","piece of equipment"],"example":"They bought new equipment for the gym.","exampleZh":"他們為健身房買了新的設備。","synonyms":["gear","apparatus"],"level":2,"theme":"科技與通訊"},{"word":"equivalent","pos":"adj./n.","phonetic":"[ɪˈkwɪvələnt]","meaning":"相等的；等值物","definition":"equal in value, amount, or meaning, or something that is equal","collocations":["equivalent to","the equivalent of","or equivalent experience"],"example":"Applicants need a degree in finance or equivalent work experience.","exampleZh":"應徵者需具備財務學位或同等的工作經驗。","synonyms":["equal","comparable"],"level":5,"theme":"日常與一般"},{"word":"error","pos":"n.","phonetic":"[ˈɛrɚ]","meaning":"錯誤；過失","definition":"a mistake, especially one that causes problems","collocations":["make an error","human error","error message"],"example":"The report contained several spelling errors.","exampleZh":"這份報告有好幾個拼字錯誤。","synonyms":["mistake","fault"],"level":2,"theme":"人事與職涯"},{"word":"escalator","pos":"n.","phonetic":"[ˈɛskəˌletɚ]","meaning":"電扶梯","definition":"a moving staircase that carries people between floors","collocations":["take the escalator","ride an escalator","broken escalator"],"example":"We took the escalator up to the second floor.","exampleZh":"我們搭電扶梯上到二樓。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"escort","pos":"v./n.","phonetic":"[ˈɛskɔrt]","meaning":"護送；陪同；護衛者","definition":"to go with someone to guide or protect them","collocations":["escort visitors","security escort","escort to the door"],"example":"All visitors must be escorted by an employee while in the building.","exampleZh":"所有訪客在大樓內都必須由員工陪同。","synonyms":["accompany"],"level":4,"theme":"辦公室與行政"},{"word":"especially","pos":"adv.","phonetic":"[ɪˈspɛʃəli]","meaning":"尤其；特別是","definition":"used to single out one person, thing, or situation over others","collocations":["especially important","especially when","especially for"],"example":"I love all seasons, especially autumn.","exampleZh":"我喜歡所有季節，尤其是秋天。","synonyms":["particularly","specifically"],"level":2,"theme":"日常與一般"},{"word":"essential","pos":"adj.","phonetic":"[ɪˈsɛnʃəl]","meaning":"必要的；基本的","definition":"absolutely necessary or extremely important","collocations":["essential skills","essential for","play an essential role"],"example":"Water is essential to all forms of life.","exampleZh":"水對所有生命形式來說都是不可或缺的。","synonyms":["necessary","vital"],"level":4,"theme":"日常與一般"},{"word":"essentially","pos":"adv.","phonetic":"[ɪˈsɛnʃəlɪ]","meaning":"本質上；基本上","definition":"in the most basic or important way","collocations":["essentially the same","essentially complete"],"example":"The two proposals are essentially the same except for the budget.","exampleZh":"這兩份提案除了預算之外，本質上是一樣的。","synonyms":["basically","fundamentally"],"level":4,"theme":"日常與一般"},{"word":"establish","pos":"v.","phonetic":"[ɪˈstæblɪʃ]","meaning":"建立；設立；確立","definition":"to set up an organization or system, or to show something is true","collocations":["establish a company","establish a relationship","establish facts"],"example":"The company was established in 1990.","exampleZh":"這間公司成立於1990年。","synonyms":["found","set up"],"level":4,"theme":"財務與會計"},{"word":"estate","pos":"n.","phonetic":"[ɪˈstet]","meaning":"地產；財產；莊園","definition":"a large area of land with a house, or all a person's property","collocations":["real estate","country estate","family estate"],"example":"He inherited a large estate from his grandfather.","exampleZh":"他從祖父那裡繼承了一大片地產。","synonyms":["property","land"],"level":5,"theme":"財務與會計"},{"word":"estimate","pos":"v. / n.","phonetic":"[ˈɛstəˌmet]","meaning":"估計；估算","definition":"to roughly calculate the value, number, or extent of something","collocations":["rough estimate","estimate the cost","give an estimate"],"example":"The builder gave us an estimate for the repairs.","exampleZh":"工人給了我們一份維修費用的估價。","synonyms":["calculate","guess"],"level":4,"theme":"財務與會計"},{"word":"evaluate","pos":"v.","phonetic":"[ɪˈvæljuˌet]","meaning":"評估；評鑑","definition":"to judge or determine the significance, worth, or quality of something","collocations":["evaluate performance","evaluate the results","carefully evaluated"],"example":"Teachers evaluate students' progress every semester.","exampleZh":"老師每學期都會評估學生的學習進度。","synonyms":["assess","judge"],"level":5,"theme":"人事與職涯"},{"word":"evaluation","pos":"n.","phonetic":"[ɪˌvæljʊˈeʃən]","meaning":"評估；評鑑；考核","definition":"the process of judging the quality, value, or performance of something","collocations":["performance evaluation","annual evaluation","evaluation form"],"example":"Annual performance evaluations will be conducted in December.","exampleZh":"年度績效考核將於十二月進行。","synonyms":["assessment","appraisal"],"level":4,"theme":"人事與職涯"},{"word":"even","pos":"adj. / adv.","phonetic":"[ˈivən]","meaning":"甚至；平坦的；偶數的","definition":"used to emphasize something surprising, or level and smooth","collocations":["even so","even number","even surface"],"example":"Even the teacher was surprised by his answer.","exampleZh":"甚至連老師都對他的答案感到驚訝。","synonyms":["level","flat"],"level":1,"theme":"日常與一般"},{"word":"evening","pos":"n.","phonetic":"[ˈivnɪŋ]","meaning":"傍晚；晚上","definition":"the period of time at the end of the day before night","collocations":["this evening","evening gown","every evening"],"example":"We usually watch TV together in the evening.","exampleZh":"我們通常在晚上一起看電視。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"event","pos":"n.","phonetic":"[ɪˈvɛnt]","meaning":"事件；活動；賽事","definition":"a thing that happens, especially one of importance","collocations":["a special event","sporting event","in any event"],"example":"The school held a special event to celebrate the anniversary.","exampleZh":"學校舉辦了一場特別活動來慶祝周年紀念。","synonyms":["occasion","happening"],"level":2,"theme":"日常與一般"},{"word":"eventually","pos":"adv.","phonetic":"[ɪˈvɛntʃuəli]","meaning":"最終；終於","definition":"in the end, especially after a long delay or series of events","collocations":["eventually succeed","eventually decided","will eventually"],"example":"After years of hard work, she eventually became a doctor.","exampleZh":"經過多年努力，她最終成為了一名醫生。","synonyms":["finally","ultimately"],"level":3,"theme":"日常與一般"},{"word":"every","pos":"adj.","phonetic":"[ˈɛvri]","meaning":"每一個的","definition":"used to refer to all the individual members of a set without exception","collocations":["every day","every time","every single one"],"example":"She practices piano every day after school.","exampleZh":"她每天放學後都練習彈鋼琴。","synonyms":["each"],"level":1,"theme":"日常與一般"},{"word":"evidence","pos":"n.","phonetic":"[ˈɛvədəns]","meaning":"證據；跡象","definition":"facts or information that show whether something is true","collocations":["strong evidence","lack of evidence","provide evidence"],"example":"The police found no evidence of a crime.","exampleZh":"警方沒有找到犯罪的證據。","synonyms":["proof"],"level":3,"theme":"合約與法律"},{"word":"evident","pos":"adj.","phonetic":"[ˈɛvədənt]","meaning":"明顯的；顯而易見的","definition":"clear and obvious to see or understand","collocations":["evident that","become evident","clearly evident"],"example":"It was evident that she had been crying.","exampleZh":"很明顯她剛剛哭過。","synonyms":["obvious","apparent"],"level":4,"theme":"日常與一般"},{"word":"exactly","pos":"adv.","phonetic":"[ɪgˈzæktlɪ]","meaning":"確切地；正好","definition":"used to emphasize that something is completely correct or precise","collocations":["exactly the same","know exactly","at exactly noon"],"example":"The shipment arrived at exactly the time the courier promised.","exampleZh":"貨物正好在快遞承諾的時間送達。","synonyms":["precisely"],"level":2,"theme":"日常與一般"},{"word":"exam","pos":"n.","phonetic":"[ɪgˈzæm]","meaning":"考試","definition":"a formal test of knowledge or skill in a subject","collocations":["take an exam","pass an exam","final exam"],"example":"She studied hard for her math exam.","exampleZh":"她為數學考試認真讀書。","synonyms":["test","examination"],"level":1,"theme":"人事與職涯"},{"word":"examination","pos":"n.","phonetic":"[ɪgˌzæməˈneʃən]","meaning":"檢查；考試；審查","definition":"a careful look at something, or a formal test of knowledge","collocations":["medical examination","careful examination","upon examination"],"example":"A thorough examination of the accounts revealed several errors.","exampleZh":"仔細審查帳目後發現了幾處錯誤。","synonyms":["inspection","test"],"level":3,"theme":"日常與一般"},{"word":"examine","pos":"v.","phonetic":"[ɪgˈzæmɪn]","meaning":"檢查；審視；測驗","definition":"to inspect something carefully, or to test someone's knowledge","collocations":["examine closely","examine a patient","be examined on"],"example":"The doctor examined the patient's injured leg.","exampleZh":"醫生檢查了病人受傷的腿。","synonyms":["inspect","check"],"level":2,"theme":"醫療與保險"},{"word":"example","pos":"n.","phonetic":"[ɪgˈzæmpl]","meaning":"例子；榜樣","definition":"a thing that illustrates a general rule, or a model to be followed","collocations":["for example","set an example","a good example"],"example":"She always sets a good example for her younger siblings.","exampleZh":"她總是為弟妹樹立好榜樣。","synonyms":["instance","model"],"level":1,"theme":"日常與一般"},{"word":"exceed","pos":"v.","phonetic":"[ɪkˈsid]","meaning":"超過；超出","definition":"to go beyond what is allowed, expected, or possible","collocations":["exceed expectations","exceed the limit","exceed the budget"],"example":"Sales this quarter exceeded our expectations.","exampleZh":"這一季的銷售超出了我們的預期。","synonyms":["surpass","go beyond"],"level":4,"theme":"財務與會計"},{"word":"excellent","pos":"adj.","phonetic":"[ˈɛksələnt]","meaning":"優秀的；傑出的","definition":"extremely good; outstanding","collocations":["excellent performance","excellent grades","an excellent idea"],"example":"She got excellent grades in every subject.","exampleZh":"她每一科都拿到了優異的成績。","synonyms":["outstanding","superb"],"level":1,"theme":"日常與一般"},{"word":"except","pos":"prep./conj.","phonetic":"[ɪkˈsɛpt]","meaning":"除了…之外","definition":"not including someone or something","collocations":["except for","every day except Sunday"],"example":"The store is open daily except on national holidays.","exampleZh":"這家店除國定假日外每天營業。","synonyms":["excluding","apart from"],"level":2,"theme":"日常與一般"},{"word":"exception","pos":"n.","phonetic":"[ɪkˈsɛpʃən]","meaning":"例外","definition":"someone or something that is not included in a general rule","collocations":["make an exception","without exception","with the exception of"],"example":"The manager made an exception and approved the late refund request.","exampleZh":"經理破例核准了逾期的退款申請。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"exceptional","pos":"adj.","phonetic":"[ɪkˈsɛpʃənl]","meaning":"傑出的；例外的","definition":"unusually good, or very unusual","collocations":["exceptional service","exceptional quality","exceptional circumstances"],"example":"She received an award for her exceptional customer service.","exampleZh":"她因傑出的顧客服務而獲獎。","synonyms":["outstanding","remarkable"],"level":4,"theme":"人事與職涯"},{"word":"excess","pos":"n./adj.","phonetic":"[ɪkˈsɛs]","meaning":"超過；過量；額外的","definition":"an amount that is more than needed or allowed","collocations":["excess baggage","in excess of","excess inventory"],"example":"Passengers must pay an extra fee for excess baggage.","exampleZh":"乘客的行李超重必須支付額外費用。","synonyms":["surplus"],"level":4,"theme":"旅遊與交通"},{"word":"excessive","pos":"adj.","phonetic":"[ɪkˈsɛsɪv]","meaning":"過度的；過多的","definition":"much more than is reasonable or necessary","collocations":["excessive spending","excessive noise","excessive workload"],"example":"The audit flagged several cases of excessive travel spending.","exampleZh":"稽核發現了幾筆過高的差旅支出。","synonyms":["extreme","undue"],"level":5,"theme":"財務與會計"},{"word":"exchange","pos":"n./v.","phonetic":"[ɪksˈtʃendʒ]","meaning":"交換；兌換；匯兌","definition":"the act of giving something and receiving something else in return","collocations":["exchange rate","exchange for","in exchange"],"example":"You may exchange the item within fourteen days with a receipt.","exampleZh":"憑收據可在十四天內更換商品。","synonyms":["swap","trade"],"level":2,"theme":"購物與消費"},{"word":"excited","pos":"adj.","phonetic":"[ɪkˈsaɪtɪd]","meaning":"興奮的；期待的","definition":"feeling very happy and enthusiastic about something","collocations":["excited about","excited to announce"],"example":"We are excited to welcome three new members to the team.","exampleZh":"我們很興奮迎接三位新成員加入團隊。","synonyms":["thrilled","eager"],"level":1,"theme":"日常與一般"},{"word":"exciting","pos":"adj.","phonetic":"[ɪkˈsaɪtɪŋ]","meaning":"令人興奮的；刺激的","definition":"making you feel very happy and enthusiastic","collocations":["exciting opportunity","exciting news","exciting development"],"example":"This role offers an exciting opportunity to lead international projects.","exampleZh":"這個職位提供領導國際專案的絕佳機會。","synonyms":["thrilling"],"level":1,"theme":"日常與一般"},{"word":"exclusive","pos":"adj./n.","phonetic":"[ɪkˈsklusɪv]","meaning":"獨家的；專屬的；高級的","definition":"limited to one particular person, group, or place","collocations":["exclusive offer","exclusive interview","exclusive rights"],"example":"Members receive exclusive discounts on all new products.","exampleZh":"會員可享所有新品的專屬折扣。","synonyms":["sole"],"level":4,"theme":"行銷與銷售"},{"word":"exclusively","pos":"adv.","phonetic":"[ɪkˈsklusɪvlɪ]","meaning":"獨家地；僅限","definition":"only and not shared with anything or anyone else","collocations":["available exclusively","exclusively for members"],"example":"This offer is available exclusively to newsletter subscribers.","exampleZh":"此優惠僅提供給電子報訂閱者。","synonyms":["solely","only"],"level":4,"theme":"行銷與銷售"},{"word":"excuse","pos":"n./v.","phonetic":"[ɪkˈskjuz]","meaning":"藉口；原諒；免除","definition":"a reason given to explain a mistake, or to forgive someone","collocations":["make an excuse","excuse me","excuse the delay"],"example":"Please excuse the delay in responding to your inquiry.","exampleZh":"回覆您的詢問有所延遲，敬請見諒。","synonyms":["pardon","forgive"],"level":2,"theme":"日常與一般"},{"word":"executive","pos":"n./adj.","phonetic":"[ɪgˈzɛkjʊtɪv]","meaning":"主管；經營主管；行政的","definition":"a senior manager in a company, or relating to managing","collocations":["chief executive","executive board","executive decision"],"example":"The executives will meet on Monday to finalize the merger plan.","exampleZh":"主管們將於週一開會敲定合併計畫。","synonyms":["director","manager"],"level":4,"theme":"企業經營"},{"word":"exercise","pos":"n./v.","phonetic":"[ˈɛksɚˌsaɪz]","meaning":"運動；練習；行使","definition":"physical activity to stay healthy, or to use a power or right","collocations":["regular exercise","exercise caution","exercise equipment"],"example":"The fitness center offers free exercise classes for hotel guests.","exampleZh":"健身中心為飯店房客提供免費運動課程。","synonyms":["workout"],"level":1,"theme":"日常與一般"},{"word":"exhibit","pos":"v./n.","phonetic":"[ɪgˈzɪbɪt]","meaning":"展出；展示品；展現","definition":"to show something publicly, or an object shown in a museum","collocations":["exhibit artwork","new exhibit","exhibit hall"],"example":"Local artists will exhibit their paintings in the gallery next month.","exampleZh":"當地藝術家下個月將在藝廊展出他們的畫作。","synonyms":["display","show"],"level":4,"theme":"媒體與活動"},{"word":"exhibition","pos":"n.","phonetic":"[ˌɛksəˈbɪʃən]","meaning":"展覽；展示會","definition":"a public event where art or products are shown","collocations":["art exhibition","trade exhibition","exhibition center"],"example":"The trade exhibition attracted over two hundred companies this year.","exampleZh":"今年的貿易展吸引了超過兩百家公司參展。","synonyms":["show","fair"],"level":3,"theme":"媒體與活動"},{"word":"exist","pos":"v.","phonetic":"[ɪgˈzɪst]","meaning":"存在；生存","definition":"to be real or present","collocations":["continue to exist","problems exist"],"example":"Several barriers still exist to entering the overseas market.","exampleZh":"進入海外市場仍存在若干障礙。","synonyms":["be present"],"level":2,"theme":"日常與一般"},{"word":"existing","pos":"adj.","phonetic":"[ɪgˈzɪstɪŋ]","meaning":"現有的；既有的","definition":"present now and already in use","collocations":["existing customers","existing system","existing contract"],"example":"The upgrade is free for all existing customers.","exampleZh":"所有現有客戶皆可免費升級。","synonyms":["current","present"],"level":3,"theme":"企業經營"},{"word":"exit","pos":"n./v.","phonetic":"[ˈɛgzɪt]","meaning":"出口；離開；退出","definition":"a way out of a place, or the act of leaving","collocations":["emergency exit","exit the building","exit interview"],"example":"Please note the location of the emergency exits before the show.","exampleZh":"表演開始前，請留意緊急出口的位置。","synonyms":["way out"],"level":2,"theme":"房產與設施"},{"word":"expand","pos":"v.","phonetic":"[ɪkˈspænd]","meaning":"擴大；擴張；展開","definition":"to become larger or make something larger","collocations":["expand the business","expand into new markets","expand rapidly"],"example":"The retailer plans to expand into Southeast Asian markets next year.","exampleZh":"這家零售商計畫明年拓展東南亞市場。","synonyms":["grow","enlarge"],"level":3,"theme":"企業經營"},{"word":"expansion","pos":"n.","phonetic":"[ɪkˈspænʃən]","meaning":"擴張；擴充；擴展","definition":"the process of becoming larger or increasing","collocations":["business expansion","expansion plan","overseas expansion"],"example":"The expansion of the factory will create three hundred new jobs.","exampleZh":"工廠擴建將創造三百個新的工作機會。","synonyms":["growth","enlargement"],"level":4,"theme":"企業經營"},{"word":"expect","pos":"v.","phonetic":"[ɪkˈspɛkt]","meaning":"預期；期待；要求","definition":"to think that something will happen","collocations":["expect a delay","be expected to","expect an increase"],"example":"We expect the shipment to arrive by Wednesday afternoon.","exampleZh":"我們預計貨物將於週三下午前送達。","synonyms":["anticipate"],"level":1,"theme":"日常與一般"},{"word":"expectation","pos":"n.","phonetic":"[ˌɛkspɛkˈteʃən]","meaning":"期望；預期","definition":"a belief about what will or should happen","collocations":["meet expectations","exceed expectations","high expectations"],"example":"The new product's sales have exceeded all expectations.","exampleZh":"新產品的銷售超出了所有預期。","synonyms":["anticipation"],"level":3,"theme":"日常與一般"},{"word":"expedite","pos":"v.","phonetic":"[ˈɛkspɪˌdaɪt]","meaning":"加速；加快處理","definition":"to make a process happen more quickly","collocations":["expedite the process","expedite shipping","expedite approval"],"example":"We can expedite your order for an additional shipping fee.","exampleZh":"加付運費即可為您的訂單加急處理。","synonyms":["speed up","hasten"],"level":6,"theme":"生產與物流"},{"word":"expense","pos":"n.","phonetic":"[ɪkˈspɛns]","meaning":"費用；開支；代價","definition":"money spent on something","collocations":["travel expenses","at the company's expense","expense report"],"example":"Submit your expense report within five days of returning from a trip.","exampleZh":"出差返回後五天內請提交費用報告。","synonyms":["cost","expenditure"],"level":3,"theme":"財務與會計"},{"word":"expensive","pos":"adj.","phonetic":"[ɪkˈspɛnsɪv]","meaning":"昂貴的","definition":"costing a lot of money","collocations":["expensive equipment","too expensive","less expensive"],"example":"The firm chose a less expensive venue for this year's banquet.","exampleZh":"公司為今年的宴會選擇了較便宜的場地。","synonyms":["costly","pricey"],"level":1,"theme":"購物與消費"},{"word":"experience","pos":"n./v.","phonetic":"[ɪkˈspɪrɪəns]","meaning":"經驗；經歷；體驗","definition":"knowledge or skill gained from doing something, or to have something happen to you","collocations":["work experience","years of experience","experience a delay"],"example":"The position requires at least five years of management experience.","exampleZh":"這個職位需要至少五年的管理經驗。","synonyms":["background"],"level":2,"theme":"人事與職涯"},{"word":"experienced","pos":"adj.","phonetic":"[ɪkˈspɪrɪənst]","meaning":"有經驗的；熟練的","definition":"having skill or knowledge from doing something for a long time","collocations":["experienced staff","highly experienced","experienced in"],"example":"We are seeking an experienced accountant to join our finance team.","exampleZh":"我們正在尋找一位有經驗的會計師加入財務團隊。","synonyms":["skilled","seasoned"],"level":3,"theme":"人事與職涯"},{"word":"expert","pos":"n./adj.","phonetic":"[ˈɛkspɝt]","meaning":"專家；熟練的","definition":"a person with special knowledge or skill in a subject","collocations":["industry expert","expert advice","expert opinion"],"example":"An outside expert was hired to review the security system.","exampleZh":"公司聘請外部專家來檢視保全系統。","synonyms":["specialist","authority"],"level":2,"theme":"人事與職涯"},{"word":"expertise","pos":"n.","phonetic":"[ˌɛkspɚˈtiz]","meaning":"專業知識；專門技術","definition":"special skill or knowledge in a particular field","collocations":["technical expertise","area of expertise","share expertise"],"example":"Her expertise in tax law makes her invaluable to the firm.","exampleZh":"她在稅法方面的專業使她成為公司不可或缺的人才。","synonyms":["know-how","skill"],"level":5,"theme":"人事與職涯"},{"word":"expiration","pos":"n.","phonetic":"[ˌɛkspəˈreʃən]","meaning":"到期；期滿","definition":"the end of a period during which something can be used","collocations":["expiration date","upon expiration","expiration of the contract"],"example":"Check the expiration date on your membership card before booking.","exampleZh":"訂位前請先確認會員卡上的有效期限。","synonyms":["expiry"],"level":4,"theme":"合約與法律"},{"word":"expire","pos":"v.","phonetic":"[ɪkˈspaɪr]","meaning":"到期；過期；失效","definition":"to reach the end of a period of validity","collocations":["the contract expires","expire at the end of","coupon expires"],"example":"Your current lease expires at the end of September.","exampleZh":"你目前的租約於九月底到期。","synonyms":["run out","lapse"],"level":4,"theme":"合約與法律"},{"word":"explain","pos":"v.","phonetic":"[ɪkˈsplen]","meaning":"解釋；說明","definition":"to make something clear by giving details or reasons","collocations":["explain the procedure","explain in detail","explain why"],"example":"The technician explained how to install the software step by step.","exampleZh":"技術人員逐步說明如何安裝軟體。","synonyms":["clarify","describe"],"level":1,"theme":"溝通與語言"},{"word":"explanation","pos":"n.","phonetic":"[ˌɛkspləˈneʃən]","meaning":"解釋；說明；理由","definition":"a statement that makes something clear or gives reasons for it","collocations":["detailed explanation","offer an explanation","without explanation"],"example":"The airline offered no explanation for the sudden cancellation.","exampleZh":"航空公司對突然取消航班未做任何解釋。","synonyms":["clarification"],"level":2,"theme":"溝通與語言"},{"word":"explore","pos":"v.","phonetic":"[ɪkˈsplor]","meaning":"探索；探討；考察","definition":"to travel around an area to learn about it, or to examine an idea carefully","collocations":["explore options","explore the city","explore possibilities"],"example":"The committee will explore several options for reducing costs.","exampleZh":"委員會將探討幾種降低成本的方案。","synonyms":["investigate","examine"],"level":2,"theme":"日常與一般"},{"word":"export","pos":"v./n.","phonetic":"[ɪksˈport]","meaning":"出口；輸出；出口品","definition":"to send goods to another country for sale","collocations":["export goods","export market","major export"],"example":"The company exports electronic components to over forty countries.","exampleZh":"該公司將電子零件出口到四十多個國家。","synonyms":[],"level":3,"theme":"生產與物流"},{"word":"exposure","pos":"n.","phonetic":"[ɪkˈspoʒɚ]","meaning":"曝光；接觸；暴露","definition":"the state of being seen by the public, or contact with something","collocations":["media exposure","brand exposure","exposure to risk"],"example":"The sponsorship gave the brand valuable exposure at the trade show.","exampleZh":"這次贊助讓品牌在商展上獲得寶貴的曝光機會。","synonyms":["publicity"],"level":5,"theme":"行銷與銷售"},{"word":"express","pos":"v./adj.","phonetic":"[ɪkˈsprɛs]","meaning":"表達；快遞的；快速的","definition":"to show what you think or feel, or done very fast","collocations":["express concern","express delivery","express train"],"example":"Choose express delivery to receive your package within two days.","exampleZh":"選擇快遞服務，兩天內即可收到包裹。","synonyms":["convey","state"],"level":2,"theme":"生產與物流"},{"word":"extend","pos":"v.","phonetic":"[ɪkˈstɛnd]","meaning":"延長；延伸；給予","definition":"to make something longer or larger, or to offer something formally","collocations":["extend the deadline","extend an invitation","extend a warranty"],"example":"The client asked us to extend the deadline by one week.","exampleZh":"客戶要求我們將期限延長一週。","synonyms":["prolong","lengthen"],"level":3,"theme":"辦公室與行政"},{"word":"extension","pos":"n.","phonetic":"[ɪkˈstɛnʃən]","meaning":"延長；分機；擴建","definition":"extra time added, a phone line in an office, or an added part of a building","collocations":["deadline extension","phone extension","request an extension"],"example":"Please call extension two-four-five to reach the accounting office.","exampleZh":"請撥分機二四五聯絡會計室。","synonyms":[],"level":3,"theme":"辦公室與行政"},{"word":"extensive","pos":"adj.","phonetic":"[ɪkˈstɛnsɪv]","meaning":"廣泛的；大規模的","definition":"covering a large area or including many things","collocations":["extensive experience","extensive research","extensive renovations"],"example":"The hotel reopened after extensive renovations to all guest rooms.","exampleZh":"飯店在全面整修所有客房後重新開幕。","synonyms":["broad","comprehensive"],"level":4,"theme":"日常與一般"},{"word":"extent","pos":"n.","phonetic":"[ɪkˈstɛnt]","meaning":"程度；範圍","definition":"the degree or size of something","collocations":["to some extent","the extent of the damage","to a large extent"],"example":"The inspector assessed the extent of the water damage.","exampleZh":"檢查員評估了水損的程度。","synonyms":["degree","scope"],"level":4,"theme":"日常與一般"},{"word":"exterior","pos":"n./adj.","phonetic":"[ɪkˈstɪrɪɚ]","meaning":"外部；外觀；外部的","definition":"the outside of something, especially a building","collocations":["building exterior","exterior walls","exterior design"],"example":"The exterior of the office building will be repainted this summer.","exampleZh":"辦公大樓的外牆將於今年夏天重新粉刷。","synonyms":["outside"],"level":4,"theme":"房產與設施"},{"word":"external","pos":"adj.","phonetic":"[ɪkˈstɝnl]","meaning":"外部的；對外的","definition":"coming from or relating to the outside","collocations":["external audit","external factors","external hard drive"],"example":"An external auditor will review the financial statements next month.","exampleZh":"外部稽核員下個月將審查財務報表。","synonyms":["outside"],"level":4,"theme":"企業經營"},{"word":"extra","pos":"adj./n./adv.","phonetic":"[ˈɛkstrə]","meaning":"額外的；外加的；額外之物","definition":"more than is usual or necessary","collocations":["extra charge","extra copies","at no extra cost"],"example":"Breakfast is included at no extra charge for all guests.","exampleZh":"所有房客均含早餐，不另外收費。","synonyms":["additional"],"level":1,"theme":"購物與消費"},{"word":"extremely","pos":"adv.","phonetic":"[ɪkˈstrimlɪ]","meaning":"極度地；非常","definition":"to a very high degree","collocations":["extremely important","extremely helpful","extremely busy"],"example":"The support team has been extremely helpful throughout the setup process.","exampleZh":"客服團隊在整個安裝過程中提供了極大的協助。","synonyms":["exceedingly","very"],"level":2,"theme":"日常與一般"},{"word":"fabric","pos":"n.","phonetic":"[ˈfæbrɪk]","meaning":"布料；織物；結構","definition":"cloth material made by weaving or knitting fibers","collocations":["cotton fabric","fabric softener","the fabric of society"],"example":"This dress is made of soft cotton fabric.","exampleZh":"這件洋裝是用柔軟的棉布做的。","synonyms":["cloth","textile"],"level":3,"theme":"購物與消費"},{"word":"face","pos":"n. / v.","phonetic":"[fes]","meaning":"臉；面對；正視","definition":"the front part of the head; to confront a situation","collocations":["face to face","face the truth","face a challenge"],"example":"You have to face your problems, not avoid them.","exampleZh":"你必須面對你的問題，而不是逃避。","synonyms":["confront","countenance"],"level":1,"theme":"醫療與保險"},{"word":"facilitate","pos":"v.","phonetic":"[fəˈsɪləˌtet]","meaning":"促進；使便利","definition":"to make an action or process easier","collocations":["facilitate communication","facilitate learning","facilitate trade"],"example":"The new software facilitates cooperation among team members.","exampleZh":"這套新軟體促進了團隊成員之間的合作。","synonyms":["ease","enable"],"level":6,"theme":"日常與一般"},{"word":"facility","pos":"n.","phonetic":"[fəˈsɪlətɪ]","meaning":"設施；才能","definition":"a building or equipment provided for a purpose","collocations":["sports facility","medical facility","storage facility"],"example":"The school built a new sports facility for students.","exampleZh":"學校為學生蓋了一座新的運動設施。","synonyms":["amenity","installation"],"level":4,"theme":"房產與設施"},{"word":"fact","pos":"n.","phonetic":"[fækt]","meaning":"事實；實情","definition":"a thing that is known or proved to be true","collocations":["in fact","a known fact","fact and fiction"],"example":"It is a fact that the earth revolves around the sun.","exampleZh":"地球繞著太陽運轉是個事實。","synonyms":["truth","reality"],"level":1,"theme":"日常與一般"},{"word":"factor","pos":"n.","phonetic":"[ˈfæktɚ]","meaning":"因素；要素","definition":"a circumstance that contributes to a result","collocations":["key factor","risk factor","contributing factor"],"example":"Price is an important factor when buying a car.","exampleZh":"價格是買車時的重要因素。","synonyms":["element","component"],"level":3,"theme":"日常與一般"},{"word":"factory","pos":"n.","phonetic":"[ˈfæktərɪ]","meaning":"工廠","definition":"a building where goods are manufactured","collocations":["car factory","factory worker","run a factory"],"example":"My father works in a shoe factory.","exampleZh":"我爸爸在一家製鞋工廠工作。","synonyms":["plant","mill"],"level":2,"theme":"人事與職涯"},{"word":"fail","pos":"v.","phonetic":"[fel]","meaning":"失敗；不及格","definition":"to be unsuccessful in achieving a goal","collocations":["fail an exam","fail to do something","fail miserably"],"example":"He failed the math test and had to retake it.","exampleZh":"他數學考試不及格，必須重考。","synonyms":["flunk","lose"],"level":2,"theme":"人事與職涯"},{"word":"failure","pos":"n.","phonetic":"[ˈfeljɚ]","meaning":"失敗；故障","definition":"lack of success; the state of not functioning","collocations":["heart failure","failure to comply","end in failure"],"example":"Fear of failure stopped her from trying new things.","exampleZh":"害怕失敗使她不敢嘗試新事物。","synonyms":["defeat","breakdown"],"level":3,"theme":"日常與一般"},{"word":"fair","pos":"adj. / n.","phonetic":"[fɛr]","meaning":"公平的；園遊會","definition":"treating people equally; a public event with entertainment","collocations":["fair play","science fair","fair chance"],"example":"The teacher tried to be fair to all the students.","exampleZh":"老師努力對所有學生都公平。","synonyms":["just","impartial"],"level":2,"theme":"日常與一般"},{"word":"fall","pos":"v. / n.","phonetic":"[fɔl]","meaning":"落下；跌倒；秋天","definition":"to drop down; the season of autumn","collocations":["fall down","fall in love","fall asleep"],"example":"The leaves fall from the trees in autumn.","exampleZh":"秋天樹葉會從樹上掉落。","synonyms":["drop","tumble"],"level":1,"theme":"日常與一般"},{"word":"familiar","pos":"adj.","phonetic":"[fəˈmɪljɚ]","meaning":"熟悉的","definition":"well known from frequent exposure","collocations":["familiar face","familiar with","sound familiar"],"example":"This song sounds familiar to me.","exampleZh":"這首歌聽起來很耳熟。","synonyms":["known","acquainted"],"level":3,"theme":"日常與一般"},{"word":"familiarize","pos":"v.","phonetic":"[fəˈmɪljəˌraɪz]","meaning":"使熟悉","definition":"to learn about something so that you understand it well","collocations":["familiarize yourself with","familiarize new employees"],"example":"Please familiarize yourself with the safety procedures before starting work.","exampleZh":"開始工作前，請先熟悉安全程序。","synonyms":["acquaint"],"level":5,"theme":"人事與職涯"},{"word":"family","pos":"n.","phonetic":"[ˈfæməlɪ]","meaning":"家庭；家人","definition":"a group of parents and children living together","collocations":["family member","family gathering","immediate family"],"example":"We have a big family reunion every Chinese New Year.","exampleZh":"我們每年農曆新年都有一場盛大的家庭聚會。","synonyms":["household","kin"],"level":1,"theme":"日常與一般"},{"word":"fancy","pos":"adj. / v.","phonetic":"[ˈfænsɪ]","meaning":"花俏的；喜歡；想要","definition":"elaborate or expensive in style; to feel a liking for","collocations":["fancy restaurant","fancy dress","fancy that"],"example":"We went to a fancy restaurant for our anniversary.","exampleZh":"我們去一家高級餐廳慶祝結婚紀念日。","synonyms":["elaborate","stylish"],"level":3,"theme":"日常與一般"},{"word":"fantastic","pos":"adj.","phonetic":"[fænˈtæstɪk]","meaning":"極好的；奇異的","definition":"extremely good or attractive; imaginative and strange","collocations":["fantastic idea","look fantastic","fantastic news"],"example":"We had a fantastic time at the beach.","exampleZh":"我們在海灘玩得非常愉快。","synonyms":["wonderful","amazing"],"level":2,"theme":"日常與一般"},{"word":"fare","pos":"n.","phonetic":"[fɛr]","meaning":"車資；票價","definition":"the money you pay to travel by bus, train, taxi, or plane","collocations":["bus fare","round-trip fare","reduced fare"],"example":"Train fares will increase by five percent starting next month.","exampleZh":"火車票價下個月起將調漲百分之五。","synonyms":["fee"],"level":3,"theme":"旅遊與交通"},{"word":"farm","pos":"n. / v.","phonetic":"[fɑrm]","meaning":"農場；耕種","definition":"land used for growing crops or raising animals","collocations":["farm animal","farm crops","organic farm"],"example":"My grandparents own a small farm in the countryside.","exampleZh":"我祖父母在鄉下擁有一座小農場。","synonyms":["ranch","cultivate"],"level":1,"theme":"日常與一般"},{"word":"farmer","pos":"n.","phonetic":"[ˈfɑrmɚ]","meaning":"農夫","definition":"a person who owns or manages a farm","collocations":["local farmer","farmer's market","hardworking farmer"],"example":"The farmer harvested the rice in early autumn.","exampleZh":"農夫在初秋時收割稻米。","synonyms":["grower","cultivator"],"level":1,"theme":"人事與職涯"},{"word":"fascinating","pos":"adj.","phonetic":"[ˈfæsnˌetɪŋ]","meaning":"迷人的；極有趣的","definition":"extremely interesting and attractive","collocations":["fascinating story","fascinating exhibition"],"example":"The keynote speaker gave a fascinating talk on future technology.","exampleZh":"主講人發表了一場關於未來科技的精彩演說。","synonyms":["captivating","intriguing"],"level":3,"theme":"媒體與活動"},{"word":"fashion","pos":"n.","phonetic":"[ˈfæʃən]","meaning":"流行；時尚","definition":"a popular trend in clothing or style","collocations":["fashion show","in fashion","fashion designer"],"example":"She works as a fashion designer in Paris.","exampleZh":"她在巴黎擔任時裝設計師。","synonyms":["trend","style"],"level":3,"theme":"購物與消費"},{"word":"fast","pos":"adj. / adv. / v.","phonetic":"[fæst]","meaning":"快的；快速地；禁食","definition":"moving or capable of moving quickly; to abstain from food","collocations":["fast food","fast asleep","run fast"],"example":"He can run very fast for his age.","exampleZh":"以他的年紀來說，他跑得非常快。","synonyms":["quick","rapid"],"level":1,"theme":"日常與一般"},{"word":"fasten","pos":"v.","phonetic":"[ˈfæsn̩]","meaning":"繫緊；固定","definition":"to close or attach something firmly","collocations":["fasten a seatbelt","fasten a button","fasten together"],"example":"Please fasten your seatbelt before takeoff.","exampleZh":"起飛前請繫好安全帶。","synonyms":["secure","attach"],"level":3,"theme":"日常與一般"},{"word":"fatigue","pos":"n.","phonetic":"[fəˈtiɡ]","meaning":"疲勞；疲乏","definition":"extreme tiredness resulting from physical or mental effort","collocations":["suffer from fatigue","mental fatigue","fatigue sets in"],"example":"Long hours at the computer left him with severe eye fatigue.","exampleZh":"長時間使用電腦讓他的眼睛非常疲勞。","synonyms":["exhaustion","tiredness"],"level":5,"theme":"醫療與保險"},{"word":"faucet","pos":"n.","phonetic":"[ˈfɔsɪt]","meaning":"水龍頭","definition":"a device that controls the flow of water from a pipe","collocations":["turn on the faucet","a leaky faucet","fix the faucet"],"example":"Please remember to turn off the faucet after washing dishes.","exampleZh":"洗完碗後請記得把水龍頭關上。","synonyms":["tap"],"level":3,"theme":"房產與設施"},{"word":"fault","pos":"n.","phonetic":"[fɔlt]","meaning":"過錯；缺點","definition":"responsibility for a mistake; a flaw or defect","collocations":["my fault","find fault","fault line"],"example":"It's not your fault that the plan failed.","exampleZh":"計畫失敗不是你的錯。","synonyms":["blame","flaw"],"level":3,"theme":"日常與一般"},{"word":"faulty","pos":"adj.","phonetic":"[ˈfɔltɪ]","meaning":"有故障的；有缺陷的","definition":"not working correctly or made incorrectly","collocations":["faulty wiring","faulty equipment","faulty goods"],"example":"The recall was issued because of faulty wiring in some units.","exampleZh":"由於部分機組電線瑕疵，廠商發布了召回令。","synonyms":["defective","broken"],"level":4,"theme":"生產與物流"},{"word":"favor","pos":"n. / v.","phonetic":"[ˈfevɚ]","meaning":"恩惠；偏愛","definition":"an act of kindness; to prefer one thing over another","collocations":["do a favor","in favor of","favor one option"],"example":"Could you do me a favor and open the door?","exampleZh":"你可以幫我一個忙，把門打開嗎？","synonyms":["kindness","preference"],"level":3,"theme":"溝通與語言"},{"word":"favorable","pos":"adj.","phonetic":"[ˈfevərəbḷ]","meaning":"有利的；贊同的","definition":"advantageous or showing approval","collocations":["favorable conditions","a favorable impression","favorable terms"],"example":"The weather forecast is favorable for our weekend trip.","exampleZh":"天氣預報顯示這個週末很適合出遊。","synonyms":["positive","advantageous"],"level":4,"theme":"日常與一般"},{"word":"favorite","pos":"adj. / n.","phonetic":"[ˈfevərɪt]","meaning":"最喜愛的","definition":"preferred above all others","collocations":["favorite color","favorite food","personal favorite"],"example":"Pizza is my favorite food.","exampleZh":"披薩是我最喜歡的食物。","synonyms":["preferred","beloved"],"level":1,"theme":"餐飲與住宿"},{"word":"fax","pos":"n./v.","phonetic":"[fæks]","meaning":"傳真；傳真機；發傳真","definition":"a document sent through a phone line, or the machine that sends it","collocations":["send a fax","fax machine","fax number"],"example":"Please fax the signed contract to our head office by noon.","exampleZh":"請於中午前將簽好的合約傳真到總公司。","synonyms":[],"level":2,"theme":"辦公室與行政"},{"word":"feasibility","pos":"n.","phonetic":"[ˌfizəˈbɪlətɪ]","meaning":"可行性","definition":"the possibility that something can be done or achieved","collocations":["feasibility study","assess the feasibility"],"example":"The board ordered a feasibility study before approving the new plant.","exampleZh":"董事會在核准新廠前，要求先進行可行性研究。","synonyms":["viability","practicality"],"level":6,"theme":"企業經營"},{"word":"feasible","pos":"adj.","phonetic":"[ˈfizəbḷ]","meaning":"可行的；行得通的","definition":"capable of being done or carried out","collocations":["a feasible plan","economically feasible","feasible solution"],"example":"Is it feasible to finish the project by Friday?","exampleZh":"這個計畫有可能在星期五前完成嗎？","synonyms":["practical","viable"],"level":5,"theme":"日常與一般"},{"word":"feature","pos":"n. / v.","phonetic":"[ˈfitʃɚ]","meaning":"特徵；特色；以...為特色","definition":"a distinctive attribute or aspect of something","collocations":["key feature","facial feature","feature a guest"],"example":"The phone's best feature is its camera.","exampleZh":"這支手機最棒的特色是它的相機。","synonyms":["characteristic","trait"],"level":3,"theme":"日常與一般"},{"word":"federal","pos":"adj.","phonetic":"[ˈfɛdərəl]","meaning":"聯邦的","definition":"relating to a system of national government","collocations":["federal government","federal law","federal agency"],"example":"The federal government passed a new law on education.","exampleZh":"聯邦政府通過了一項有關教育的新法律。","synonyms":["national"],"level":5,"theme":"合約與法律"},{"word":"fee","pos":"n.","phonetic":"[fi]","meaning":"費用","definition":"a payment made for professional services or entry","collocations":["entrance fee","tuition fee","pay a fee"],"example":"There is an entrance fee for the museum.","exampleZh":"參觀這座博物館需要付入場費。","synonyms":["charge","payment"],"level":3,"theme":"財務與會計"},{"word":"feedback","pos":"n.","phonetic":"[ˈfidˌbæk]","meaning":"回饋；意見","definition":"information given about performance for improvement","collocations":["give feedback","positive feedback","feedback form"],"example":"The teacher gave useful feedback on my essay.","exampleZh":"老師對我的作文給了有用的回饋。","synonyms":["response","comment"],"level":4,"theme":"人事與職涯"},{"word":"fellow","pos":"n./adj.","phonetic":"[ˈfɛlo]","meaning":"同伴；同事的；研究員","definition":"a person in the same situation as you, or a member of an academic society","collocations":["fellow workers","fellow passengers","research fellow"],"example":"She thanked her fellow employees for their support during the project.","exampleZh":"她感謝同事們在專案期間的支持。","synonyms":["colleague","peer"],"level":3,"theme":"人事與職涯"},{"word":"fence","pos":"n.","phonetic":"[fɛns]","meaning":"籬笆；圍欄","definition":"a barrier enclosing an area, made of posts and wire","collocations":["wooden fence","climb a fence","build a fence"],"example":"The dog jumped over the fence.","exampleZh":"那隻狗跳過了圍欄。","synonyms":["barrier","railing"],"level":2,"theme":"房產與設施"},{"word":"festival","pos":"n.","phonetic":"[ˈfɛstəvl̩]","meaning":"節慶；慶典","definition":"a day or period of celebration","collocations":["film festival","music festival","traditional festival"],"example":"The Dragon Boat Festival is celebrated in early summer.","exampleZh":"端午節在初夏時節慶祝。","synonyms":["celebration","carnival"],"level":2,"theme":"日常與一般"},{"word":"fever","pos":"n.","phonetic":"[ˈfivɚ]","meaning":"發燒","definition":"an abnormally high body temperature","collocations":["high fever","run a fever","fever reducer"],"example":"The child had a high fever and stayed home from school.","exampleZh":"這個孩子發高燒，因此沒去上學。","synonyms":["temperature"],"level":2,"theme":"醫療與保險"},{"word":"few","pos":"adj./pron.","phonetic":"[fju]","meaning":"很少的；少數的；一些","definition":"a small number of people or things","collocations":["a few days","few options","quite a few"],"example":"We have a few openings left for the morning workshop.","exampleZh":"上午的工作坊還剩下少數幾個名額。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"field","pos":"n.","phonetic":"[fild]","meaning":"田野；領域；球場","definition":"an open area of land; an area of study or activity","collocations":["rice field","field trip","field of study"],"example":"We went on a field trip to the science museum.","exampleZh":"我們去科學博物館校外教學。","synonyms":["meadow","domain"],"level":2,"theme":"日常與一般"},{"word":"fierce","pos":"adj.","phonetic":"[fɪrs]","meaning":"兇猛的；激烈的","definition":"showing intense and often violent behavior","collocations":["fierce competition","fierce animal","fierce battle"],"example":"The two teams were in fierce competition for the title.","exampleZh":"這兩隊為了冠軍展開激烈的競爭。","synonyms":["ferocious","intense"],"level":4,"theme":"日常與一般"},{"word":"figure","pos":"n. / v.","phonetic":"[ˈfɪɡjɚ]","meaning":"數字；身材；理解","definition":"a number; a shape or form; to work out an answer","collocations":["figure out","public figure","keep one's figure"],"example":"I couldn't figure out how to solve the puzzle.","exampleZh":"我想不出該怎麼解開這個謎題。","synonyms":["number","shape"],"level":2,"theme":"科技與通訊"},{"word":"file","pos":"n. / v.","phonetic":"[faɪl]","meaning":"檔案；歸檔","definition":"a collection of data stored under one name","collocations":["computer file","file a complaint","delete a file"],"example":"Please save the document as a PDF file.","exampleZh":"請把這份文件存成PDF檔案。","synonyms":["document","record"],"level":2,"theme":"科技與通訊"},{"word":"filing","pos":"n.","phonetic":"[ˈfaɪlɪŋ]","meaning":"歸檔；文件整理；申報","definition":"the act of putting documents in order, or officially submitting documents","collocations":["filing cabinet","filing system","tax filing"],"example":"The new digital filing system saves hours of paperwork each week.","exampleZh":"新的數位歸檔系統每週省下數小時的文書作業。","synonyms":[],"level":3,"theme":"辦公室與行政"},{"word":"fill","pos":"v.","phonetic":"[fɪl]","meaning":"填滿；裝滿","definition":"to make something full by putting things in it","collocations":["fill up","fill in the blank","fill a form"],"example":"She filled the glass with water.","exampleZh":"她把杯子裝滿了水。","synonyms":["stuff","load"],"level":1,"theme":"日常與一般"},{"word":"film","pos":"n. / v.","phonetic":"[fɪlm]","meaning":"電影；影片；拍攝","definition":"a motion picture; to record moving images","collocations":["watch a film","film director","film a scene"],"example":"We watched a great film about space travel last night.","exampleZh":"我們昨晚看了一部關於太空旅行的精彩電影。","synonyms":["movie","motion picture"],"level":2,"theme":"媒體與活動"},{"word":"filter","pos":"n. / v.","phonetic":"[ˈfɪltɚ]","meaning":"濾器；過濾","definition":"a device that removes unwanted substances, or to pass through such a device","collocations":["water filter","filter out impurities","air filter"],"example":"This machine filters the coffee to remove the grounds.","exampleZh":"這台機器會過濾咖啡以去除咖啡渣。","synonyms":["strain","sieve"],"level":3,"theme":"科技與通訊"},{"word":"final","pos":"adj. / n.","phonetic":"[ˈfaɪnl̩]","meaning":"最後的；決賽","definition":"coming last in a series; the last game of a competition","collocations":["final exam","final decision","reach the final"],"example":"Our team made it to the final of the tournament.","exampleZh":"我們隊伍打進了這場錦標賽的決賽。","synonyms":["last","concluding"],"level":2,"theme":"人事與職涯"},{"word":"finalize","pos":"v.","phonetic":"[ˈfaɪnlˌaɪz]","meaning":"定案；完成最後細節","definition":"to complete the last details of a plan or agreement","collocations":["finalize the details","finalize a contract","finalize the schedule"],"example":"We need to finalize the conference agenda by the end of the week.","exampleZh":"我們需要在本週結束前敲定會議議程。","synonyms":["complete","settle"],"level":4,"theme":"辦公室與行政"},{"word":"finally","pos":"adv.","phonetic":"[ˈfaɪnlɪ]","meaning":"最後；終於","definition":"after a long time or at the end of a series of events","collocations":["finally agree","finally arrive"],"example":"After months of negotiation, the two firms finally signed the deal.","exampleZh":"經過數月談判，兩家公司終於簽約。","synonyms":["eventually","at last"],"level":1,"theme":"日常與一般"},{"word":"finance","pos":"n. / v.","phonetic":"[ˈfaɪnæns]","meaning":"財務；金融；資助","definition":"the management of money; to provide funds for something","collocations":["personal finance","finance a project","finance minister"],"example":"The bank agreed to finance the new building project.","exampleZh":"銀行同意資助這個新建案。","synonyms":["funding","budget"],"level":5,"theme":"財務與會計"},{"word":"financial","pos":"adj.","phonetic":"[faɪˈnænʃəl]","meaning":"財務的；金融的","definition":"relating to money or how money is managed","collocations":["financial statement","financial support","financial services"],"example":"The financial report shows steady growth in the third quarter.","exampleZh":"財務報告顯示第三季穩定成長。","synonyms":["monetary","fiscal"],"level":3,"theme":"財務與會計"},{"word":"financing","pos":"n.","phonetic":"[fəˈnænsɪŋ]","meaning":"融資；資金籌措","definition":"money provided to fund a business or project, or the act of providing it","collocations":["secure financing","financing options","low-interest financing"],"example":"The dealership offers zero-interest financing on all new vehicles.","exampleZh":"這家經銷商為所有新車提供零利率分期方案。","synonyms":["funding"],"level":5,"theme":"財務與會計"},{"word":"findings","pos":"n.","phonetic":"[ˈfaɪndɪŋz]","meaning":"調查結果；研究發現","definition":"the information discovered as a result of research or an investigation","collocations":["research findings","present the findings","key findings"],"example":"The consultant will present her findings at Friday's board meeting.","exampleZh":"顧問將在週五的董事會上報告她的調查結果。","synonyms":["results","conclusions"],"level":4,"theme":"企業經營"},{"word":"fine","pos":"adj. / n.","phonetic":"[faɪn]","meaning":"好的；晴朗的；罰款","definition":"of good quality; a sum of money paid as punishment","collocations":["fine weather","traffic fine","feel fine"],"example":"He had to pay a fine for parking illegally.","exampleZh":"他因為違規停車而必須繳罰款。","synonyms":["good","penalty"],"level":1,"theme":"日常與一般"},{"word":"finish","pos":"v. / n.","phonetic":"[ˈfɪnɪʃ]","meaning":"完成；結束","definition":"to bring a task or activity to an end","collocations":["finish homework","finish line","finish up"],"example":"She finished her homework before dinner.","exampleZh":"她在晚餐前完成了作業。","synonyms":["complete","end"],"level":1,"theme":"日常與一般"},{"word":"firm","pos":"adj. / n.","phonetic":"[fɝm]","meaning":"堅定的；公司","definition":"solid and steady; a business organization","collocations":["law firm","firm grip","stand firm"],"example":"He gave a firm handshake to the manager.","exampleZh":"他和經理堅定地握了手。","synonyms":["solid","company"],"level":3,"theme":"財務與會計"},{"word":"firmly","pos":"adv.","phonetic":"[ˈfɝmlɪ]","meaning":"堅定地；牢固地","definition":"in a strong and determined way","collocations":["firmly believe","hold firmly","firmly attached"],"example":"Make sure the shelf brackets are firmly attached to the wall.","exampleZh":"請確認層架托架已牢牢固定在牆上。","synonyms":["securely","steadfastly"],"level":3,"theme":"日常與一般"},{"word":"first","pos":"adj./adv./n.","phonetic":"[fɝst]","meaning":"第一的；首先；最初","definition":"before all others in order, time, or importance","collocations":["first quarter","first impression","at first"],"example":"Profits rose sharply in the first quarter of this year.","exampleZh":"今年第一季獲利大幅上升。","synonyms":["initial"],"level":1,"theme":"日常與一般"},{"word":"first-class","pos":"adj./adv.","phonetic":"[ˈfɝstˈklæs]","meaning":"頭等的；一流的","definition":"of the highest quality or most expensive category","collocations":["first-class ticket","first-class service","fly first-class"],"example":"The consultant always flies first-class on international trips.","exampleZh":"這位顧問國際出差時總是搭頭等艙。","synonyms":["top-quality"],"level":3,"theme":"旅遊與交通"},{"word":"fiscal","pos":"adj.","phonetic":"[ˈfɪskl]","meaning":"財政的；會計的","definition":"relating to government money or a company's financial year","collocations":["fiscal year","fiscal policy","fiscal quarter"],"example":"The company's fiscal year begins on April first.","exampleZh":"該公司的會計年度自四月一日開始。","synonyms":["financial"],"level":6,"theme":"財務與會計"},{"word":"fit","pos":"adj. / v.","phonetic":"[fɪt]","meaning":"健康的；合適；適合","definition":"in good physical condition; to be the right size or shape","collocations":["fit in","keep fit","fit for purpose"],"example":"You need to exercise regularly to stay fit.","exampleZh":"你需要規律運動才能保持健康。","synonyms":["healthy","suitable"],"level":2,"theme":"醫療與保險"},{"word":"fitness","pos":"n.","phonetic":"[ˈfɪtnɪs]","meaning":"健身；健康；適合","definition":"the state of being physically healthy and strong","collocations":["fitness center","physical fitness","fitness program"],"example":"Hotel guests have free access to the fitness center on the second floor.","exampleZh":"飯店房客可免費使用二樓的健身中心。","synonyms":["health"],"level":2,"theme":"日常與一般"},{"word":"fitting","pos":"n./adj.","phonetic":"[ˈfɪtɪŋ]","meaning":"試穿；配件；合適的","definition":"an act of trying on clothes, a part attached to something, or suitable","collocations":["fitting room","light fittings","a fitting tribute"],"example":"The fitting rooms are located next to the customer service desk.","exampleZh":"試衣間位於顧客服務台旁。","synonyms":["appropriate"],"level":4,"theme":"購物與消費"},{"word":"fix","pos":"v.","phonetic":"[fɪks]","meaning":"修理；固定；解決","definition":"to repair or mend something","collocations":["fix a problem","fix up","fix a date"],"example":"The mechanic fixed my car in an hour.","exampleZh":"技師在一小時內修好了我的車。","synonyms":["repair","mend"],"level":2,"theme":"日常與一般"},{"word":"fixture","pos":"n.","phonetic":"[ˈfɪkstʃɚ]","meaning":"固定裝置；設備","definition":"a piece of equipment fixed in a building, such as a light","collocations":["light fixture","bathroom fixtures","install fixtures"],"example":"The electrician will replace the light fixtures in the hallway.","exampleZh":"電工將更換走廊的照明設備。","synonyms":[],"level":5,"theme":"房產與設施"},{"word":"flagship","pos":"n./adj.","phonetic":"[ˈflægˌʃɪp]","meaning":"旗艦；旗艦的","definition":"the most important product, store, or service of a company","collocations":["flagship store","flagship product","flagship model"],"example":"The brand opened its flagship store in the downtown shopping district.","exampleZh":"該品牌在市中心商圈開設了旗艦店。","synonyms":[],"level":5,"theme":"行銷與銷售"},{"word":"flat","pos":"adj. / n.","phonetic":"[flæt]","meaning":"平坦的；公寓","definition":"having a level surface; a set of rooms for living","collocations":["flat surface","flat tire","rent a flat"],"example":"They live in a small flat in the city center.","exampleZh":"他們住在市中心的一間小公寓。","synonyms":["level","apartment"],"level":2,"theme":"房產與設施"},{"word":"flavor","pos":"n. / v.","phonetic":"[ˈflevɚ]","meaning":"味道；風味","definition":"the distinctive taste of a food or drink","collocations":["flavor of the month","add flavor","chocolate flavor"],"example":"This ice cream comes in many different flavors.","exampleZh":"這款冰淇淋有許多不同的口味。","synonyms":["taste","seasoning"],"level":3,"theme":"餐飲與住宿"},{"word":"flaw","pos":"n.","phonetic":"[flɔ]","meaning":"缺陷；瑕疵","definition":"a fault or weakness that makes something imperfect","collocations":["design flaw","fatal flaw","minor flaw"],"example":"Engineers discovered a flaw in the braking system during testing.","exampleZh":"工程師在測試期間發現煞車系統有缺陷。","synonyms":["defect","fault"],"level":4,"theme":"生產與物流"},{"word":"fleet","pos":"n.","phonetic":"[flit]","meaning":"艦隊；（同一機構的）車隊","definition":"a group of ships, vehicles, or aircraft operated together","collocations":["a fishing fleet","a fleet of taxis","naval fleet"],"example":"The company owns a large fleet of delivery trucks.","exampleZh":"這家公司擁有一大批送貨卡車。","synonyms":["armada","convoy"],"level":5,"theme":"旅遊與交通"},{"word":"flexibility","pos":"n.","phonetic":"[ˌflɛksəˈbɪlətɪ]","meaning":"彈性；靈活性","definition":"the ability to change or be changed easily to suit a situation","collocations":["scheduling flexibility","offer flexibility","flexibility in"],"example":"Remote work gives employees greater flexibility in their schedules.","exampleZh":"遠距工作讓員工的時間安排更有彈性。","synonyms":["adaptability"],"level":4,"theme":"人事與職涯"},{"word":"flexible","pos":"adj.","phonetic":"[ˈflɛksəbl̩]","meaning":"有彈性的；靈活的","definition":"capable of bending easily or adapting to change","collocations":["flexible schedule","flexible material","stay flexible"],"example":"My job offers flexible working hours.","exampleZh":"我的工作提供彈性的工作時間。","synonyms":["adaptable","elastic"],"level":4,"theme":"日常與一般"},{"word":"flight","pos":"n.","phonetic":"[flaɪt]","meaning":"飛行；班機","definition":"an act of traveling through the air","collocations":["book a flight","flight attendant","domestic flight"],"example":"Our flight to Tokyo was delayed by two hours.","exampleZh":"我們飛往東京的班機延誤了兩個小時。","synonyms":["journey","trip"],"level":2,"theme":"旅遊與交通"},{"word":"float","pos":"v.","phonetic":"[flot]","meaning":"漂浮","definition":"to rest on the surface of a liquid without sinking","collocations":["float on water","float in the air","float around"],"example":"The leaves floated gently on the pond.","exampleZh":"樹葉輕輕地漂浮在池塘上。","synonyms":["drift","hover"],"level":3,"theme":"日常與一般"},{"word":"flood","pos":"n. / v.","phonetic":"[flʌd]","meaning":"洪水；淹沒","definition":"an overflow of water onto normally dry land","collocations":["flash flood","flood control","flood the streets"],"example":"Heavy rain caused a flood in the low-lying areas.","exampleZh":"豪雨造成低窪地區淹水。","synonyms":["deluge","overflow"],"level":3,"theme":"日常與一般"},{"word":"floor","pos":"n.","phonetic":"[flor]","meaning":"地板；樓層","definition":"the lower surface of a room; a level of a building","collocations":["ground floor","sweep the floor","second floor"],"example":"The office is on the third floor.","exampleZh":"辦公室在三樓。","synonyms":["ground","level"],"level":1,"theme":"房產與設施"},{"word":"flourish","pos":"v./n.","phonetic":"[ˈflɝɪʃ]","meaning":"繁榮；茁壯成長","definition":"to grow or develop successfully","collocations":["business flourishes","flourish in the market"],"example":"Small cafes have flourished in the renovated warehouse district.","exampleZh":"小咖啡館在翻新後的倉庫區蓬勃發展。","synonyms":["thrive","prosper"],"level":5,"theme":"企業經營"},{"word":"flow","pos":"v. / n.","phonetic":"[flo]","meaning":"流動；流暢","definition":"to move steadily and continuously in a current","collocations":["flow smoothly","cash flow","flow into"],"example":"The river flows through several small towns.","exampleZh":"這條河流經好幾個小鎮。","synonyms":["stream","run"],"level":3,"theme":"日常與一般"},{"word":"fluctuate","pos":"v.","phonetic":"[ˈflʌktʃʊˌet]","meaning":"波動；起伏不定","definition":"to change frequently between higher and lower levels","collocations":["prices fluctuate","fluctuate widely","fluctuate seasonally"],"example":"Fuel prices fluctuate depending on global supply and demand.","exampleZh":"燃料價格隨全球供需而波動。","synonyms":["vary","swing"],"level":6,"theme":"財務與會計"},{"word":"fluctuation","pos":"n.","phonetic":"[ˌflʌktʃʊˈeʃən]","meaning":"波動；變動","definition":"a frequent change in amount or level","collocations":["price fluctuations","currency fluctuations","seasonal fluctuation"],"example":"The budget accounts for fluctuations in raw material costs.","exampleZh":"預算已將原物料成本的波動納入考量。","synonyms":["variation"],"level":6,"theme":"財務與會計"},{"word":"flyer","pos":"n.","phonetic":"[ˈflaɪɚ]","meaning":"傳單；廣告單","definition":"a small printed sheet advertising something","collocations":["distribute flyers","promotional flyer","hand out flyers"],"example":"Staff handed out flyers announcing the store's grand opening.","exampleZh":"工作人員發送宣傳開幕活動的傳單。","synonyms":["leaflet","handout"],"level":3,"theme":"行銷與銷售"},{"word":"focus","pos":"v. / n.","phonetic":"[ˈfokəs]","meaning":"專注；焦點","definition":"to concentrate attention or effort on something","collocations":["focus on","in focus","lose focus"],"example":"You need to focus on your studies this semester.","exampleZh":"這學期你需要專注在學業上。","synonyms":["concentrate","center"],"level":3,"theme":"人事與職涯"},{"word":"fold","pos":"v.","phonetic":"[fold]","meaning":"摺疊","definition":"to bend something over on itself","collocations":["fold clothes","fold paper","fold up"],"example":"She folded the laundry neatly.","exampleZh":"她把洗好的衣服摺得整整齊齊。","synonyms":["crease","bend"],"level":3,"theme":"日常與一般"},{"word":"folder","pos":"n.","phonetic":"[ˈfoldɚ]","meaning":"文件夾；資料夾","definition":"a cover for holding papers, or a place for storing computer files","collocations":["shared folder","file folder","create a folder"],"example":"Save all meeting minutes in the shared folder on the server.","exampleZh":"請將所有會議紀錄存到伺服器上的共用資料夾。","synonyms":[],"level":2,"theme":"辦公室與行政"},{"word":"follow","pos":"v.","phonetic":"[ˈfɑlo]","meaning":"跟隨；遵循","definition":"to go or come after a person or thing","collocations":["follow instructions","follow up","follow someone"],"example":"Please follow the instructions carefully.","exampleZh":"請仔細遵循指示。","synonyms":["pursue","obey"],"level":1,"theme":"日常與一般"},{"word":"following","pos":"adj./prep./n.","phonetic":"[ˈfɑləwɪŋ]","meaning":"接下來的；下列的；在…之後","definition":"coming next, or listed below","collocations":["the following day","following the meeting","the following items"],"example":"Following the presentation, there will be a question-and-answer session.","exampleZh":"簡報結束後將有問答時間。","synonyms":["next","subsequent"],"level":2,"theme":"日常與一般"},{"word":"food","pos":"n.","phonetic":"[fud]","meaning":"食物","definition":"any nutritious substance eaten to maintain life","collocations":["fast food","healthy food","food chain"],"example":"Vietnamese food is popular in Taiwan.","exampleZh":"越南料理在台灣很受歡迎。","synonyms":["nourishment","meal"],"level":1,"theme":"餐飲與住宿"},{"word":"footage","pos":"n.","phonetic":"[ˈfʊtɪdʒ]","meaning":"影片片段；錄影畫面","definition":"film or video showing a particular event","collocations":["video footage","security footage","raw footage"],"example":"Security footage helped identify the cause of the warehouse accident.","exampleZh":"監視器畫面協助釐清了倉庫事故的原因。","synonyms":[],"level":5,"theme":"媒體與活動"},{"word":"footwear","pos":"n.","phonetic":"[ˈfʊtˌwɛr]","meaning":"鞋類","definition":"shoes, boots, and other things worn on the feet","collocations":["protective footwear","footwear department","athletic footwear"],"example":"Protective footwear is required at all times on the factory floor.","exampleZh":"在工廠作業區必須全程穿著防護鞋。","synonyms":["shoes"],"level":4,"theme":"購物與消費"},{"word":"forbid","pos":"v.","phonetic":"[fɚˈbɪd]","meaning":"禁止","definition":"to refuse to allow something","collocations":["forbid smoking","strictly forbidden","forbid someone to do"],"example":"Smoking is forbidden inside the building.","exampleZh":"建築物內禁止吸菸。","synonyms":["prohibit","ban"],"level":4,"theme":"合約與法律"},{"word":"force","pos":"n. / v.","phonetic":"[fors]","meaning":"力量；強迫","definition":"physical strength or power; to compel someone to act","collocations":["by force","force someone to","police force"],"example":"The wind's force knocked down several trees.","exampleZh":"強風的力量吹倒了好幾棵樹。","synonyms":["power","compel"],"level":2,"theme":"科技與通訊"},{"word":"forecast","pos":"n. / v.","phonetic":"[ˈforˌkæst]","meaning":"預報；預測","definition":"a prediction of future events, especially weather","collocations":["weather forecast","forecast rain","economic forecast"],"example":"The weather forecast predicts rain tomorrow.","exampleZh":"天氣預報預測明天會下雨。","synonyms":["prediction","projection"],"level":4,"theme":"日常與一般"},{"word":"foresee","pos":"v.","phonetic":"[forˈsi]","meaning":"預見；預料","definition":"to know or realize something will happen before it happens","collocations":["foresee a problem","hard to foresee"],"example":"No one could foresee the sudden change in the market.","exampleZh":"沒有人能預見市場的突然變化。","synonyms":["predict","anticipate"],"level":5,"theme":"日常與一般"},{"word":"forklift","pos":"n.","phonetic":"[ˈfɔrkˌlɪft]","meaning":"堆高機；叉車","definition":"a vehicle with two metal arms used for lifting and moving heavy loads","collocations":["forklift operator","drive a forklift","forklift training"],"example":"Only certified operators may drive the forklifts in the warehouse.","exampleZh":"只有持證照的操作員才能在倉庫駕駛堆高機。","synonyms":[],"level":4,"theme":"生產與物流"},{"word":"form","pos":"n. / v.","phonetic":"[form]","meaning":"形式；表格；形成","definition":"the shape of something; a document to fill in; to create","collocations":["fill out a form","in the form of","form a group"],"example":"Please fill out this application form.","exampleZh":"請填寫這張申請表。","synonyms":["shape","document"],"level":2,"theme":"日常與一般"},{"word":"formal","pos":"adj.","phonetic":"[ˈfɔrml̩]","meaning":"正式的","definition":"following established rules or conventions","collocations":["formal dress","formal education","formal event"],"example":"You should wear formal clothes to the interview.","exampleZh":"你應該穿正式服裝去面試。","synonyms":["official","proper"],"level":3,"theme":"購物與消費"},{"word":"formally","pos":"adv.","phonetic":"[ˈfɔrmlɪ]","meaning":"正式地","definition":"in an official or serious way","collocations":["formally announce","formally approve","formally introduce"],"example":"The merger will be formally announced at tomorrow's press conference.","exampleZh":"合併案將在明天的記者會上正式宣布。","synonyms":["officially"],"level":4,"theme":"企業經營"},{"word":"format","pos":"n. / v.","phonetic":"[ˈfɔrmæt]","meaning":"格式；使成形式","definition":"the way something is arranged or presented","collocations":["file format","in this format","format a document"],"example":"Please save the file in PDF format.","exampleZh":"請將檔案存成PDF格式。","synonyms":["layout","structure"],"level":4,"theme":"科技與通訊"},{"word":"formation","pos":"n.","phonetic":"[fɔrˈmeʃən]","meaning":"形成；隊形","definition":"the process of forming something, or an arrangement of things","collocations":["rock formation","in formation","cloud formation"],"example":"The formation of the new team took several months.","exampleZh":"新團隊的組成花了好幾個月。","synonyms":["creation"],"level":5,"theme":"日常與一般"},{"word":"former","pos":"adj.","phonetic":"[ˈfɔrmɚ]","meaning":"以前的；前者的","definition":"having been previously; the first of two mentioned","collocations":["former president","former student","the former and the latter"],"example":"The former president gave a speech at the university.","exampleZh":"前任總統在這所大學發表演說。","synonyms":["previous","past"],"level":4,"theme":"日常與一般"},{"word":"formula","pos":"n.","phonetic":"[ˈfɔrmjələ]","meaning":"公式；配方","definition":"a mathematical rule expressed in symbols, or a fixed method","collocations":["chemical formula","secret formula","math formula"],"example":"Students must memorize the formula for the exam.","exampleZh":"學生必須為考試背誦這個公式。","synonyms":["equation"],"level":4,"theme":"科技與通訊"},{"word":"formulate","pos":"v.","phonetic":"[ˈfɔrmjəˌlet]","meaning":"制定；規劃；配製","definition":"to develop a plan or idea carefully and in detail","collocations":["formulate a strategy","formulate a plan","formulate a policy"],"example":"The team met to formulate a strategy for entering the new market.","exampleZh":"團隊開會制定進軍新市場的策略。","synonyms":["devise","develop"],"level":6,"theme":"企業經營"},{"word":"forthcoming","pos":"adj.","phonetic":"[ˌforθˈkʌmɪŋ]","meaning":"即將到來的；即將出版的；樂於提供的","definition":"happening or appearing soon, or willing to give information","collocations":["forthcoming book","forthcoming event","forthcoming election"],"example":"Details about the forthcoming product launch will be shared next week.","exampleZh":"即將舉行的產品發表會細節將於下週公布。","synonyms":["upcoming"],"level":6,"theme":"媒體與活動"},{"word":"fortunate","pos":"adj.","phonetic":"[ˈfɔrtʃənɪt]","meaning":"幸運的","definition":"having good luck; lucky","collocations":["fortunate enough","a fortunate event"],"example":"We were fortunate enough to find a good seat.","exampleZh":"我們很幸運找到了好座位。","synonyms":["lucky"],"level":4,"theme":"日常與一般"},{"word":"fortunately","pos":"adv.","phonetic":"[ˈfɔrtʃənɪtlɪ]","meaning":"幸運地；幸好","definition":"used to say that something good happened by luck","collocations":["fortunately for us"],"example":"Fortunately, the backup files were saved before the system crashed.","exampleZh":"幸好在系統當機前備份檔案已經儲存。","synonyms":["luckily"],"level":3,"theme":"日常與一般"},{"word":"forum","pos":"n.","phonetic":"[ˈforəm]","meaning":"論壇；討論會","definition":"a meeting or online place where people discuss a topic","collocations":["online forum","public forum","economic forum"],"example":"The city will hold a public forum on the proposed transit line.","exampleZh":"市府將就擬議的捷運路線舉行公開論壇。","synonyms":["discussion","conference"],"level":4,"theme":"媒體與活動"},{"word":"forward","pos":"adv. / adj. / v.","phonetic":"[ˈfɔrwɚd]","meaning":"向前；期待；轉發","definition":"toward the front or ahead; to send onward","collocations":["look forward to","move forward","forward an email"],"example":"I look forward to seeing you this weekend.","exampleZh":"我很期待這週末見到你。","synonyms":["ahead","onward"],"level":2,"theme":"日常與一般"},{"word":"foster","pos":"v. / adj.","phonetic":"[ˈfɔstɚ]","meaning":"養育；培養；寄養的","definition":"to encourage development, or to bring up a child not one's own","collocations":["foster family","foster a relationship","foster child"],"example":"The program aims to foster creativity in young children.","exampleZh":"這項計畫旨在培養幼兒的創造力。","synonyms":["nurture","promote"],"level":5,"theme":"日常與一般"},{"word":"found","pos":"v.","phonetic":"[faʊnd]","meaning":"建立；創立","definition":"to establish an organization or institution","collocations":["found a company","newly founded","found a school"],"example":"The company was founded in 1990.","exampleZh":"這家公司成立於1990年。","synonyms":["establish","create"],"level":3,"theme":"財務與會計"},{"word":"foundation","pos":"n.","phonetic":"[faʊnˈdeʃən]","meaning":"基礎；地基；基金會","definition":"the base of a building; an underlying basis; a charitable organization","collocations":["lay the foundation","charity foundation","foundation course"],"example":"A strong foundation is essential for a tall building.","exampleZh":"堅固的地基對高樓來說是必要的。","synonyms":["base","basis"],"level":5,"theme":"日常與一般"},{"word":"founder","pos":"n.","phonetic":"[ˈfaʊndɚ]","meaning":"創辦人","definition":"a person who establishes an organization or institution","collocations":["company founder","co-founder"],"example":"The founder of the company started with almost no money.","exampleZh":"這家公司的創辦人幾乎是白手起家。","synonyms":["creator","originator"],"level":5,"theme":"人事與職涯"},{"word":"fountain","pos":"n.","phonetic":"[ˈfaʊntn̩]","meaning":"噴泉","definition":"a structure that shoots water into the air decoratively","collocations":["water fountain","fountain pen","public fountain"],"example":"Tourists gathered around the fountain to take photos.","exampleZh":"遊客們聚集在噴泉旁拍照。","synonyms":[],"level":3,"theme":"房產與設施"},{"word":"fraction","pos":"n.","phonetic":"[ˈfrækʃən]","meaning":"一小部分；分數","definition":"a small part of something, or a number like one half","collocations":["a fraction of the cost","a small fraction"],"example":"The refurbished laptops sell for a fraction of the original price.","exampleZh":"整新筆電的售價只有原價的一小部分。","synonyms":["portion"],"level":4,"theme":"購物與消費"},{"word":"fragile","pos":"adj.","phonetic":"[ˈfrædʒəl]","meaning":"易碎的；脆弱的","definition":"easily broken or damaged","collocations":["fragile glass","fragile relationship","extremely fragile"],"example":"Please be careful, the vase is very fragile.","exampleZh":"請小心，這個花瓶很容易破。","synonyms":["delicate","weak"],"level":5,"theme":"日常與一般"},{"word":"fragrance","pos":"n.","phonetic":"[ˈfregrəns]","meaning":"香味；芳香","definition":"a pleasant, sweet smell","collocations":["sweet fragrance","the fragrance of flowers"],"example":"The fragrance of roses filled the garden.","exampleZh":"玫瑰的香味瀰漫了整個花園。","synonyms":["scent","aroma"],"level":4,"theme":"日常與一般"},{"word":"frame","pos":"n. / v.","phonetic":"[frem]","meaning":"框架；相框","definition":"a rigid structure surrounding something; to enclose in a border","collocations":["picture frame","frame of mind","window frame"],"example":"She put the photo in a wooden frame.","exampleZh":"她把照片放進木製相框裡。","synonyms":["border","structure"],"level":3,"theme":"房產與設施"},{"word":"framework","pos":"n.","phonetic":"[ˈfrem͵wɝk]","meaning":"架構；框架","definition":"a basic structure supporting a system or concept","collocations":["legal framework","within a framework","conceptual framework"],"example":"The government set up a new legal framework for businesses.","exampleZh":"政府為企業設立了新的法律架構。","synonyms":["structure"],"level":6,"theme":"日常與一般"},{"word":"franchise","pos":"n./v.","phonetic":"[ˈfrænˌtʃaɪz]","meaning":"加盟權；特許經營；加盟店","definition":"the right to sell a company's products in a particular area","collocations":["franchise owner","fast-food franchise","buy a franchise"],"example":"He bought a coffee shop franchise after ten years in banking.","exampleZh":"他在銀行業工作十年後，買下了一家咖啡連鎖加盟店。","synonyms":[],"level":5,"theme":"企業經營"},{"word":"free","pos":"adj. / v.","phonetic":"[fri]","meaning":"自由的；免費的；釋放","definition":"not under control; costing nothing; to release","collocations":["free time","for free","set free"],"example":"Admission to the museum is free on Sundays.","exampleZh":"星期天參觀博物館免費入場。","synonyms":["liberated","gratis"],"level":1,"theme":"日常與一般"},{"word":"freelance","pos":"adj./adv./v.","phonetic":"[ˈfriˌlæns]","meaning":"自由接案的；自由業","definition":"working independently for different companies rather than being employed by one","collocations":["freelance writer","work freelance","freelance designer"],"example":"She left the agency to work as a freelance translator.","exampleZh":"她離開公司，成為自由接案的譯者。","synonyms":["self-employed"],"level":5,"theme":"人事與職涯"},{"word":"freeze","pos":"v.","phonetic":"[friz]","meaning":"結冰；冷凍","definition":"to become solid due to extreme cold","collocations":["freeze to death","freeze food","freezing cold"],"example":"The lake froze completely during the harsh winter.","exampleZh":"湖水在嚴冬中完全結冰了。","synonyms":["ice over"],"level":2,"theme":"日常與一般"},{"word":"freezer","pos":"n.","phonetic":"[ˈfrizɚ]","meaning":"冷凍庫","definition":"an appliance for freezing and storing food","collocations":["put in the freezer","freezer bag"],"example":"She put the ice cream in the freezer.","exampleZh":"她把冰淇淋放進冷凍庫。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"freight","pos":"n.","phonetic":"[fret]","meaning":"貨運；貨物","definition":"goods transported by truck, train, ship, or aircraft","collocations":["freight train","air freight","freight charges"],"example":"The goods were shipped by freight train.","exampleZh":"這些貨物是用貨運火車運送的。","synonyms":["cargo"],"level":6,"theme":"旅遊與交通"},{"word":"frequency","pos":"n.","phonetic":"[ˈfrikwənsɪ]","meaning":"頻率","definition":"the rate at which something occurs over time","collocations":["radio frequency","high frequency","increase in frequency"],"example":"The frequency of earthquakes has increased this year.","exampleZh":"今年地震發生的頻率增加了。","synonyms":["rate"],"level":5,"theme":"科技與通訊"},{"word":"frequent","pos":"adj.","phonetic":"[ˈfrikwənt]","meaning":"頻繁的","definition":"occurring often or at close intervals","collocations":["frequent visitor","frequent flyer","frequent trips"],"example":"He is a frequent traveler between Taipei and Tokyo.","exampleZh":"他經常往返台北和東京之間。","synonyms":["regular","common"],"level":4,"theme":"日常與一般"},{"word":"frequently","pos":"adv.","phonetic":"[ˈfrikwəntlɪ]","meaning":"經常地；頻繁地","definition":"often or many times","collocations":["frequently asked questions","travel frequently"],"example":"Answers to frequently asked questions are posted on our website.","exampleZh":"常見問題的解答已公布在我們的網站上。","synonyms":["often","regularly"],"level":2,"theme":"日常與一般"},{"word":"fresh","pos":"adj.","phonetic":"[frɛʃ]","meaning":"新鮮的","definition":"recently made or obtained; not stale","collocations":["fresh air","fresh fruit","fresh start"],"example":"We bought fresh vegetables at the market this morning.","exampleZh":"我們今早在市場買了新鮮蔬菜。","synonyms":["new","crisp"],"level":2,"theme":"餐飲與住宿"},{"word":"friendly","pos":"adj.","phonetic":"[ˈfrɛndlɪ]","meaning":"友善的","definition":"kind and pleasant toward others","collocations":["friendly smile","user-friendly","friendly relationship"],"example":"Our new neighbors are very friendly.","exampleZh":"我們的新鄰居非常友善。","synonyms":["kind","amiable"],"level":1,"theme":"日常與一般"},{"word":"fringe","pos":"n.","phonetic":"[frɪndʒ]","meaning":"邊緣；瀏海","definition":"the outer edge of an area, or hair cut across the forehead","collocations":["fringe benefit","on the fringe of"],"example":"The village lies on the fringe of the forest.","exampleZh":"這個村莊位於森林的邊緣。","synonyms":["edge","border"],"level":6,"theme":"日常與一般"},{"word":"front","pos":"n. / adj.","phonetic":"[frʌnt]","meaning":"前面；前方的","definition":"the foremost part or side of something","collocations":["in front of","front door","front page"],"example":"There is a big garden in front of the house.","exampleZh":"房子前面有一個大花園。","synonyms":["forefront"],"level":1,"theme":"日常與一般"},{"word":"fuel","pos":"n. / v.","phonetic":"[ˈfjuəl]","meaning":"燃料；加油","definition":"material burned to produce heat or power","collocations":["fossil fuel","fuel efficiency","fuel tank"],"example":"The rising cost of fuel affects transportation prices.","exampleZh":"燃料成本上漲影響了運輸價格。","synonyms":["gasoline","energy"],"level":4,"theme":"日常與一般"},{"word":"fulfill","pos":"v.","phonetic":"[fʊlˈfɪl]","meaning":"實現；完成","definition":"to achieve or bring to completion a goal or duty","collocations":["fulfill a dream","fulfill a promise","fulfill a role"],"example":"She worked hard to fulfill her dream of becoming a doctor.","exampleZh":"她努力實現成為醫生的夢想。","synonyms":["achieve","accomplish"],"level":5,"theme":"日常與一般"},{"word":"full","pos":"adj.","phonetic":"[fʊl]","meaning":"滿的；飽的","definition":"containing as much as possible; not hungry","collocations":["full moon","full of","feel full"],"example":"I feel full after eating that huge meal.","exampleZh":"吃完那頓大餐後我覺得很飽。","synonyms":["complete","packed"],"level":1,"theme":"日常與一般"},{"word":"full-time","pos":"adj./adv.","phonetic":"[ˈfʊlˈtaɪm]","meaning":"全職的；全職地","definition":"working the standard number of hours in a week","collocations":["full-time position","full-time employee","work full-time"],"example":"The internship may lead to a full-time position after graduation.","exampleZh":"這份實習在畢業後可能轉為正職。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"function","pos":"n. / v.","phonetic":"[ˈfʌŋkʃən]","meaning":"功能；作用","definition":"the purpose or role of something; to operate","collocations":["function properly","main function","body function"],"example":"This app has many useful functions.","exampleZh":"這個應用程式有許多實用的功能。","synonyms":["purpose","role"],"level":4,"theme":"科技與通訊"},{"word":"fund","pos":"n. / v.","phonetic":"[fʌnd]","meaning":"資金；資助","definition":"a sum of money for a specific purpose","collocations":["raise funds","fund a project","emergency fund"],"example":"The school raised funds for the new library.","exampleZh":"學校為新圖書館募款。","synonyms":["finance","capital"],"level":4,"theme":"財務與會計"},{"word":"funding","pos":"n.","phonetic":"[ˈfʌndɪŋ]","meaning":"資金；經費；資助","definition":"money provided for a particular purpose","collocations":["secure funding","government funding","research funding"],"example":"The startup secured funding from two major venture capital firms.","exampleZh":"這家新創公司獲得兩家大型創投的資金。","synonyms":["financing","backing"],"level":4,"theme":"財務與會計"},{"word":"furniture","pos":"n.","phonetic":"[ˈfɝnɪtʃɚ]","meaning":"傢俱","definition":"movable objects such as tables and chairs used in a room","collocations":["office furniture","buy furniture","wooden furniture"],"example":"They bought new furniture for their living room.","exampleZh":"他們為客廳買了新的傢俱。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"further","pos":"adv. / adj.","phonetic":"[ˈfɝðɚ]","meaning":"更遠地；進一步的","definition":"to a greater extent or degree; additional","collocations":["further information","further study","look further"],"example":"Please contact us for further information.","exampleZh":"如需進一步資訊請與我們聯絡。","synonyms":["additional","extra"],"level":3,"theme":"日常與一般"},{"word":"future","pos":"n. / adj.","phonetic":"[ˈfjutʃɚ]","meaning":"未來","definition":"the time that is to come","collocations":["in the future","future plans","near future"],"example":"She has big plans for her future career.","exampleZh":"她對未來的職涯有很大的計畫。","synonyms":["tomorrow","prospect"],"level":1,"theme":"日常與一般"},{"word":"gadget","pos":"n.","phonetic":"[ˈɡædʒɪt]","meaning":"小裝置；小工具","definition":"a small tool or device that does something useful","collocations":["a new gadget","electronic gadget","handy gadget"],"example":"He loves buying the latest kitchen gadgets.","exampleZh":"他喜歡購買最新的廚房小工具。","synonyms":["device","tool"],"level":3,"theme":"科技與通訊"},{"word":"gain","pos":"v. / n.","phonetic":"[gen]","meaning":"獲得；增加","definition":"to obtain or increase something, especially something beneficial","collocations":["gain weight","gain experience","gain confidence"],"example":"She gained a lot of experience from the internship.","exampleZh":"她從實習中獲得了很多經驗。","synonyms":["obtain","acquire"],"level":2,"theme":"日常與一般"},{"word":"gala","pos":"n.","phonetic":"[ˈgelə]","meaning":"盛會；慶祝晚會","definition":"a special public celebration or entertainment event","collocations":["gala dinner","charity gala","annual gala"],"example":"The charity gala raised over one million dollars for the hospital.","exampleZh":"慈善晚會為醫院募得超過一百萬美元。","synonyms":["celebration","banquet"],"level":5,"theme":"媒體與活動"},{"word":"gallery","pos":"n.","phonetic":"[ˈgælərɪ]","meaning":"美術館；畫廊","definition":"a room or building where works of art are shown to the public","collocations":["art gallery","visit a gallery","gallery owner"],"example":"We spent the afternoon at an art gallery downtown.","exampleZh":"我們下午在市區的一家美術館度過。","synonyms":["museum","exhibition hall"],"level":3,"theme":"媒體與活動"},{"word":"gallon","pos":"n.","phonetic":"[ˈɡælən]","meaning":"加侖（容量單位）","definition":"a unit for measuring liquid","collocations":["a gallon of milk","miles per gallon","ten gallons of gas"],"example":"The car uses one gallon of gasoline every twenty miles.","exampleZh":"這輛車每二十英里耗用一加侖汽油。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"gap","pos":"n.","phonetic":"[ɡæp]","meaning":"缺口；差距；空隙","definition":"a space between two things or a difference between two situations","collocations":["fill the gap","a wide gap","generation gap"],"example":"There is a big gap between the rich and the poor.","exampleZh":"貧富之間存在很大的差距。","synonyms":["gulf","space"],"level":2,"theme":"日常與一般"},{"word":"garage","pos":"n.","phonetic":"[gəˈrɑʒ]","meaning":"車庫；修車廠","definition":"a building where a car is kept or repaired","collocations":["park in the garage","garage sale","car garage"],"example":"He parked his car in the garage overnight.","exampleZh":"他把車停在車庫過夜。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"garden","pos":"n. / v.","phonetic":"[ˈgɑrdn̩]","meaning":"花園;菜園;園藝","definition":"a piece of land used for growing flowers, vegetables, or fruit","collocations":["water the garden","vegetable garden","garden design"],"example":"My grandmother loves working in her garden every morning.","exampleZh":"我祖母每天早上都喜歡在她的花園裡忙碌。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"garment","pos":"n.","phonetic":"[ˈɡɑrmənt]","meaning":"衣服；服裝","definition":"a piece of clothing","collocations":["a fine garment","garment industry","wool garments"],"example":"The garment was made of soft silk.","exampleZh":"這件衣服是用柔軟的絲綢做成的。","synonyms":["clothing","apparel"],"level":4,"theme":"購物與消費"},{"word":"gas","pos":"n.","phonetic":"[gæs]","meaning":"氣體；瓦斯；汽油","definition":"a substance like air that has no fixed shape, or fuel used in vehicles","collocations":["natural gas","gas station","run out of gas"],"example":"We stopped at a gas station to fill up the tank.","exampleZh":"我們在加油站停下來加油。","synonyms":["fuel"],"level":2,"theme":"科技與通訊"},{"word":"gate","pos":"n.","phonetic":"[get]","meaning":"大門；閘門；登機門","definition":"a barrier used to close an opening in a fence or wall, or an airport boarding entrance","collocations":["open the gate","boarding gate","front gate"],"example":"Passengers should proceed to gate twelve for boarding.","exampleZh":"旅客請前往十二號登機門登機。","synonyms":["entrance"],"level":1,"theme":"旅遊與交通"},{"word":"gateway","pos":"n.","phonetic":"[ˈgetˌwe]","meaning":"入口；門戶；途徑","definition":"an entrance, or a way of reaching or achieving something","collocations":["gateway to the city","payment gateway"],"example":"The port city serves as a gateway to the country's northern region.","exampleZh":"這座港口城市是通往該國北部的門戶。","synonyms":["entrance"],"level":4,"theme":"旅遊與交通"},{"word":"gather","pos":"v.","phonetic":"[ˈgæðɚ]","meaning":"聚集；收集","definition":"to come together in a group, or to collect things","collocations":["gather information","gather around","gather data"],"example":"The students gathered around the teacher to hear the story.","exampleZh":"學生們聚集在老師身邊聽故事。","synonyms":["collect","assemble"],"level":2,"theme":"日常與一般"},{"word":"gathering","pos":"n.","phonetic":"[ˈgæðərɪŋ]","meaning":"聚會；集會","definition":"a group of people meeting together","collocations":["social gathering","family gathering","informal gathering"],"example":"The rooftop lounge is ideal for small social gatherings.","exampleZh":"頂樓酒廊很適合小型社交聚會。","synonyms":["meeting","assembly"],"level":3,"theme":"媒體與活動"},{"word":"gauge","pos":"n. / v.","phonetic":"[gedʒ]","meaning":"測量儀器；判斷；估計","definition":"an instrument for measuring something, or to estimate or judge something","collocations":["fuel gauge","gauge the reaction","pressure gauge"],"example":"The driver checked the fuel gauge before the trip.","exampleZh":"司機在出發前檢查了油量表。","synonyms":["measure","estimate"],"level":5,"theme":"科技與通訊"},{"word":"gear","pos":"n.","phonetic":"[gɪr]","meaning":"齒輪；排檔；裝備","definition":"a toothed wheel in a machine, or equipment needed for an activity","collocations":["change gear","camping gear","gear up"],"example":"He packed all his camping gear into the car.","exampleZh":"他把所有的露營裝備都裝進車裡。","synonyms":["equipment"],"level":3,"theme":"科技與通訊"},{"word":"general","pos":"adj. / n.","phonetic":"[ˈdʒɛnərəl]","meaning":"一般的；普遍的；將軍","definition":"affecting or including most people or things; a senior military officer","collocations":["in general","general public","general knowledge"],"example":"In general, the students did well on the test.","exampleZh":"整體來說，學生們這次考試考得不錯。","synonyms":["common","overall"],"level":2,"theme":"日常與一般"},{"word":"generally","pos":"adv.","phonetic":"[ˈdʒɛnərəlɪ]","meaning":"一般而言；通常","definition":"usually or in most situations","collocations":["generally speaking","generally accepted"],"example":"Deliveries generally take three to five business days.","exampleZh":"送貨通常需要三到五個工作天。","synonyms":["usually","typically"],"level":2,"theme":"日常與一般"},{"word":"generate","pos":"v.","phonetic":"[ˈdʒɛnəˌret]","meaning":"產生；引起","definition":"to produce or create something","collocations":["generate income","generate ideas","generate electricity"],"example":"Wind turbines generate electricity without pollution.","exampleZh":"風力渦輪機在不造成污染的情況下發電。","synonyms":["produce","create"],"level":4,"theme":"科技與通訊"},{"word":"generation","pos":"n.","phonetic":"[ˌdʒɛnəˈreʃən]","meaning":"世代；一代人","definition":"all the people born and living at about the same time","collocations":["younger generation","generation gap","future generations"],"example":"There is often a generation gap between parents and children.","exampleZh":"父母和孩子之間常常存在代溝。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"generator","pos":"n.","phonetic":"[ˈdʒɛnəˌretɚ]","meaning":"發電機；產生器","definition":"a machine that produces electricity","collocations":["backup generator","power generator","emergency generator"],"example":"The hospital's backup generator started immediately during the outage.","exampleZh":"停電時醫院的備用發電機立即啟動。","synonyms":[],"level":4,"theme":"房產與設施"},{"word":"generous","pos":"adj.","phonetic":"[ˈdʒɛnərəs]","meaning":"慷慨的；大方的","definition":"willing to give more of something, such as money or time, than is necessary","collocations":["generous donation","generous with","a generous offer"],"example":"He is generous with his time and always helps others.","exampleZh":"他很慷慨地付出時間，總是樂於幫助別人。","synonyms":["kind","giving"],"level":3,"theme":"日常與一般"},{"word":"genuine","pos":"adj.","phonetic":"[ˈdʒɛnjuɪn]","meaning":"真正的；真誠的","definition":"truly what it is said to be; sincere and honest","collocations":["genuine leather","genuine concern","genuine interest"],"example":"She showed genuine concern for her friend's health.","exampleZh":"她對朋友的健康表現出真誠的關心。","synonyms":["authentic","sincere"],"level":4,"theme":"日常與一般"},{"word":"gesture","pos":"n. / v.","phonetic":"[ˈdʒɛstʃɚ]","meaning":"手勢；姿態；表示","definition":"a movement of the body, especially the hands, to express meaning or feeling","collocations":["make a gesture","a kind gesture","gesture toward"],"example":"He made a friendly gesture by waving hello.","exampleZh":"他友善地揮手打招呼。","synonyms":["motion","signal"],"level":4,"theme":"溝通與語言"},{"word":"get-together","pos":"n.","phonetic":"[ˈgɛttəˌgɛðɚ]","meaning":"（非正式）聚會","definition":"an informal meeting or party","collocations":["casual get-together","staff get-together"],"example":"The department is planning a casual get-together on Friday evening.","exampleZh":"部門正計畫在週五晚上辦一場輕鬆的聚會。","synonyms":["gathering","party"],"level":4,"theme":"媒體與活動"},{"word":"gift","pos":"n.","phonetic":"[gɪft]","meaning":"禮物；天賦","definition":"something given to someone without payment; a natural talent","collocations":["birthday gift","gift for music","wrap a gift"],"example":"She gave her mother a beautiful gift on her birthday.","exampleZh":"她在媽媽生日時送了一份美麗的禮物。","synonyms":["present","talent"],"level":1,"theme":"日常與一般"},{"word":"give","pos":"v.","phonetic":"[gɪv]","meaning":"給予；提供；舉行","definition":"to provide someone with something","collocations":["give a presentation","give a discount","give notice"],"example":"The sales director will give a presentation on next year's targets.","exampleZh":"業務總監將就明年的目標進行簡報。","synonyms":["provide","offer"],"level":1,"theme":"日常與一般"},{"word":"giveaway","pos":"n.","phonetic":"[ˈgɪvəˌwe]","meaning":"贈品；免費贈送活動","definition":"something given free, especially to promote a product","collocations":["free giveaway","prize giveaway","giveaway items"],"example":"The booth attracted crowds with free giveaways and product samples.","exampleZh":"攤位以免費贈品和產品試用品吸引人潮。","synonyms":["freebie"],"level":4,"theme":"行銷與銷售"},{"word":"glad","pos":"adj.","phonetic":"[glæd]","meaning":"高興的；樂意的","definition":"feeling pleasure or happiness","collocations":["glad to hear","be glad of","glad tidings"],"example":"I'm glad you could come to the party.","exampleZh":"我很高興你能來參加派對。","synonyms":["happy","pleased"],"level":1,"theme":"日常與一般"},{"word":"glance","pos":"v. / n.","phonetic":"[glæns]","meaning":"瞥一眼；匆匆一看","definition":"to look at something quickly and briefly","collocations":["glance at","at a glance","quick glance"],"example":"She glanced at her watch during the meeting.","exampleZh":"她在開會時瞥了一眼手錶。","synonyms":["look","peek"],"level":3,"theme":"日常與一般"},{"word":"glass","pos":"n.","phonetic":"[glæs]","meaning":"玻璃；玻璃杯","definition":"a hard, transparent material, or a container made of it used for drinking","collocations":["a glass of water","broken glass","glass window"],"example":"He poured a glass of milk for his little brother.","exampleZh":"他為弟弟倒了一杯牛奶。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"global","pos":"adj.","phonetic":"[ˈglobl̩]","meaning":"全球的；全世界的","definition":"relating to the whole world","collocations":["global warming","global economy","global market"],"example":"Global warming is affecting weather patterns worldwide.","exampleZh":"全球暖化正影響著世界各地的氣候型態。","synonyms":["worldwide","international"],"level":3,"theme":"日常與一般"},{"word":"globe","pos":"n.","phonetic":"[glob]","meaning":"地球儀；地球；全球","definition":"a model of the earth shaped like a ball, or the earth itself","collocations":["around the globe","spin the globe","the globe"],"example":"News of the discovery spread around the globe.","exampleZh":"這項發現的消息傳遍了全世界。","synonyms":["earth","world"],"level":3,"theme":"日常與一般"},{"word":"glove","pos":"n.","phonetic":"[glʌv]","meaning":"手套","definition":"a covering for the hand, with separate parts for each finger","collocations":["a pair of gloves","wear gloves","boxing gloves"],"example":"She put on her gloves before going out into the cold.","exampleZh":"她在出門到寒冷的戶外前戴上了手套。","synonyms":[],"level":1,"theme":"購物與消費"},{"word":"glow","pos":"v. / n.","phonetic":"[glo]","meaning":"發光；容光煥發","definition":"to produce a steady, soft light, or such a light","collocations":["glow in the dark","healthy glow","the fire glowed"],"example":"The fireflies glowed in the dark garden.","exampleZh":"螢火蟲在黑暗的花園裡發著光。","synonyms":["shine","gleam"],"level":3,"theme":"日常與一般"},{"word":"go-ahead","pos":"n./adj.","phonetic":"[ˈgoəˌhɛd]","meaning":"批准；許可；進取的","definition":"official permission to start doing something","collocations":["give the go-ahead","get the go-ahead"],"example":"The city council gave the go-ahead for the new shopping complex.","exampleZh":"市議會批准了新購物中心的興建案。","synonyms":["approval","green light"],"level":5,"theme":"企業經營"},{"word":"goal","pos":"n.","phonetic":"[gol]","meaning":"目標；(足球)進球","definition":"an aim or desired result; a point scored in soccer or hockey","collocations":["set a goal","score a goal","achieve a goal"],"example":"Her goal is to become a doctor someday.","exampleZh":"她的目標是有一天成為一名醫生。","synonyms":["aim","objective"],"level":2,"theme":"日常與一般"},{"word":"gold","pos":"n. / adj.","phonetic":"[gold]","meaning":"黃金；金色的","definition":"a valuable yellow precious metal, or the color of it","collocations":["pure gold","gold medal","gold ring"],"example":"The athlete won a gold medal at the Olympics.","exampleZh":"這位運動員在奧運會上贏得了金牌。","synonyms":[],"level":1,"theme":"財務與會計"},{"word":"golden","pos":"adj.","phonetic":"[ˈgoldn̩]","meaning":"金色的；黃金的；極好的","definition":"made of gold, or having a bright, attractive yellow color; excellent","collocations":["golden opportunity","golden hair","golden age"],"example":"This is a golden opportunity you shouldn't miss.","exampleZh":"這是一個你不該錯過的絕佳機會。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"golf","pos":"n.","phonetic":"[gɑlf]","meaning":"高爾夫球","definition":"a game played by hitting a small ball into a series of holes with clubs","collocations":["play golf","golf course","golf club"],"example":"My father plays golf every weekend.","exampleZh":"我爸爸每個週末都打高爾夫球。","synonyms":[],"level":2,"theme":"媒體與活動"},{"word":"goods","pos":"n.","phonetic":"[gʊdz]","meaning":"商品；貨物","definition":"things that are made to be sold","collocations":["consumer goods","deliver goods","household goods"],"example":"The truck was loaded with goods for the market.","exampleZh":"卡車裝滿了要運到市場的貨物。","synonyms":["merchandise","products"],"level":3,"theme":"財務與會計"},{"word":"goodwill","pos":"n.","phonetic":"[ˈgʊdˈwɪl]","meaning":"善意；商譽","definition":"friendly and helpful feelings, or the good reputation of a business","collocations":["a gesture of goodwill","build goodwill","customer goodwill"],"example":"As a gesture of goodwill, the airline upgraded the delayed passengers.","exampleZh":"作為善意的表示，航空公司為延誤的乘客升等。","synonyms":["kindness"],"level":5,"theme":"企業經營"},{"word":"gourmet","pos":"n. / adj.","phonetic":"[ɡʊrˈme]","meaning":"美食家；精緻美食的","definition":"a person who enjoys fine food, or relating to high-quality food","collocations":["gourmet food","gourmet restaurant","a true gourmet"],"example":"The hotel is famous for its gourmet restaurant.","exampleZh":"這家飯店以其精緻美食餐廳聞名。","synonyms":["connoisseur"],"level":5,"theme":"餐飲與住宿"},{"word":"govern","pos":"v.","phonetic":"[ˈgʌvɚn]","meaning":"統治；管理","definition":"to officially control and lead a country or organization","collocations":["govern a country","govern effectively","govern by law"],"example":"The president promised to govern fairly and honestly.","exampleZh":"總統承諾要公正誠實地治理國家。","synonyms":["rule","control"],"level":4,"theme":"合約與法律"},{"word":"government","pos":"n.","phonetic":"[ˈgʌvɚnmənt]","meaning":"政府","definition":"the group of people who officially govern a country or state","collocations":["local government","government policy","run for government"],"example":"The government announced a new education policy.","exampleZh":"政府宣布了一項新的教育政策。","synonyms":[],"level":2,"theme":"合約與法律"},{"word":"governor","pos":"n.","phonetic":"[ˈgʌvɚnɚ]","meaning":"州長；總督","definition":"a person who officially governs a state or region","collocations":["state governor","elect a governor","governor's office"],"example":"The governor signed the new law yesterday.","exampleZh":"州長昨天簽署了這項新法律。","synonyms":[],"level":4,"theme":"合約與法律"},{"word":"gown","pos":"n.","phonetic":"[gaʊn]","meaning":"長袍；禮服","definition":"a long formal dress or robe","collocations":["evening gown","wedding gown","graduation gown"],"example":"She wore a beautiful blue gown to the ball.","exampleZh":"她穿著一件漂亮的藍色禮服去參加舞會。","synonyms":["dress","robe"],"level":3,"theme":"購物與消費"},{"word":"grab","pos":"v.","phonetic":"[græb]","meaning":"抓住；奪取","definition":"to take hold of something suddenly and roughly","collocations":["grab a chance","grab hold of","grab lunch"],"example":"He grabbed his bag and ran out the door.","exampleZh":"他抓起書包就跑出門去。","synonyms":["seize","snatch"],"level":2,"theme":"日常與一般"},{"word":"grade","pos":"n. / v.","phonetic":"[gred]","meaning":"年級；成績；等級","definition":"a level of school, a mark given for work, or a level of quality","collocations":["get good grades","fifth grade","grade papers"],"example":"She got good grades on her final exams.","exampleZh":"她在期末考試中拿到了好成績。","synonyms":["score","rank"],"level":1,"theme":"人事與職涯"},{"word":"gradually","pos":"adv.","phonetic":"[ˈgrædʒʊəli]","meaning":"逐漸地","definition":"slowly over a period of time","collocations":["gradually increase","gradually change","gradually improve"],"example":"The weather gradually became warmer as spring arrived.","exampleZh":"隨著春天到來，天氣逐漸變暖。","synonyms":["slowly","steadily"],"level":3,"theme":"日常與一般"},{"word":"graduate","pos":"v. / n.","phonetic":"[ˈgrædʒʊˌet]","meaning":"畢業；畢業生","definition":"to complete a course of study successfully, or a person who has done so","collocations":["graduate from college","college graduate","graduate school"],"example":"She will graduate from high school next June.","exampleZh":"她將於明年六月從高中畢業。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"graduation","pos":"n.","phonetic":"[ˌgrædʒʊˈeʃən]","meaning":"畢業；畢業典禮","definition":"the act of graduating, or the ceremony for this","collocations":["graduation ceremony","graduation day","attend graduation"],"example":"Her parents were proud at her graduation ceremony.","exampleZh":"她的父母在畢業典禮上感到非常驕傲。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"grain","pos":"n.","phonetic":"[gren]","meaning":"穀物；顆粒","definition":"the seeds of cereal plants, or a small hard particle","collocations":["whole grain","grain of sand","grain of rice"],"example":"Whole grain bread is healthier than white bread.","exampleZh":"全穀麵包比白麵包更健康。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"grand","pos":"adj.","phonetic":"[grænd]","meaning":"宏偉的；盛大的","definition":"large, impressive, and splendid in appearance or style","collocations":["grand opening","grand piano","grand plan"],"example":"The hotel held a grand opening ceremony last night.","exampleZh":"這家飯店昨晚舉行了盛大的開幕儀式。","synonyms":["magnificent","impressive"],"level":3,"theme":"日常與一般"},{"word":"grant","pos":"v. / n.","phonetic":"[grænt]","meaning":"同意給予；補助金","definition":"to agree to give or allow something requested; a sum of money given for a purpose","collocations":["grant permission","research grant","take for granted"],"example":"The university granted her a scholarship to study abroad.","exampleZh":"大學授予她一筆獎學金以出國留學。","synonyms":["allow","award"],"level":4,"theme":"財務與會計"},{"word":"graph","pos":"n.","phonetic":"[græf]","meaning":"圖表；曲線圖","definition":"a diagram showing the relationship between numbers or quantities","collocations":["bar graph","draw a graph","read a graph"],"example":"The report includes a graph showing sales over the past year.","exampleZh":"這份報告包含一張顯示去年銷售額的圖表。","synonyms":["chart"],"level":2,"theme":"科技與通訊"},{"word":"graphic","pos":"adj. / n.","phonetic":"[ˈɡræfɪk]","meaning":"圖表的；生動的；（複數）圖像","definition":"relating to visual images, or described in vivid detail","collocations":["graphic design","graphic novel","computer graphics"],"example":"The report included several graphic charts to explain the data.","exampleZh":"這份報告附有幾張圖表來說明數據。","synonyms":["visual","vivid"],"level":4,"theme":"科技與通訊"},{"word":"grasp","pos":"v. / n.","phonetic":"[græsp]","meaning":"抓住；理解","definition":"to hold firmly, or to understand something completely","collocations":["grasp the concept","grasp an opportunity","firm grasp"],"example":"It took him a while to grasp the new concept.","exampleZh":"他花了一段時間才理解這個新概念。","synonyms":["understand","seize"],"level":4,"theme":"人事與職涯"},{"word":"grateful","pos":"adj.","phonetic":"[ˈgretfəl]","meaning":"感激的；感謝的","definition":"feeling or showing thanks","collocations":["grateful for","feel grateful","grateful heart"],"example":"I am truly grateful for your help and support.","exampleZh":"我真心感謝你的幫助與支持。","synonyms":["thankful","appreciative"],"level":3,"theme":"日常與一般"},{"word":"gratitude","pos":"n.","phonetic":"[ˈɡrætəˌtud]","meaning":"感激；感謝","definition":"the feeling of being thankful","collocations":["show gratitude","express gratitude","a sense of gratitude"],"example":"She wrote a letter to express her gratitude to her teacher.","exampleZh":"她寫了一封信向老師表達她的感激之情。","synonyms":["thankfulness","appreciation"],"level":4,"theme":"日常與一般"},{"word":"gratuity","pos":"n.","phonetic":"[grəˈtuətɪ]","meaning":"小費；賞金","definition":"money given to someone for their service, especially in a restaurant","collocations":["add a gratuity","gratuity included","15% gratuity"],"example":"A fifteen percent gratuity is automatically added for large groups.","exampleZh":"大型團體用餐將自動加收百分之十五的服務費。","synonyms":["tip"],"level":6,"theme":"餐飲與住宿"},{"word":"great","pos":"adj.","phonetic":"[gret]","meaning":"偉大的；很棒的；巨大的","definition":"very good, important, or large in amount","collocations":["a great idea","great deal","great success"],"example":"That was a great movie we watched last night.","exampleZh":"我們昨晚看的那部電影很棒。","synonyms":["excellent","huge"],"level":1,"theme":"日常與一般"},{"word":"greatly","pos":"adv.","phonetic":"[ˈgretlɪ]","meaning":"大大地；非常","definition":"very much","collocations":["greatly appreciated","greatly improved","greatly reduced"],"example":"Your prompt response would be greatly appreciated.","exampleZh":"若蒙迅速回覆，將不勝感激。","synonyms":["considerably","significantly"],"level":3,"theme":"日常與一般"},{"word":"green","pos":"adj. / n.","phonetic":"[grin]","meaning":"綠色的；環保的","definition":"the color of grass and leaves; environmentally friendly","collocations":["green energy","dark green","go green"],"example":"The company is trying to go green by using less plastic.","exampleZh":"這家公司試圖透過減少塑膠使用來實現環保。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"greenhouse","pos":"n.","phonetic":"[ˈgrinˌhaʊs]","meaning":"溫室","definition":"a glass building for growing plants","collocations":["greenhouse effect","greenhouse gas","grow in a greenhouse"],"example":"The greenhouse effect is a major cause of global warming.","exampleZh":"溫室效應是全球暖化的主要原因之一。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"greet","pos":"v.","phonetic":"[grit]","meaning":"問候；迎接","definition":"to say hello to someone or welcome them","collocations":["greet a guest","greet each other","greet warmly"],"example":"She greeted her guests with a warm smile.","exampleZh":"她用溫暖的笑容迎接客人。","synonyms":["welcome"],"level":2,"theme":"溝通與語言"},{"word":"greeting","pos":"n.","phonetic":"[ˈgritɪŋ]","meaning":"問候；問候語","definition":"a word or gesture used to welcome someone","collocations":["greeting card","warm greeting","exchange greetings"],"example":"They exchanged friendly greetings at the door.","exampleZh":"他們在門口互相友善地問候。","synonyms":["welcome"],"level":2,"theme":"溝通與語言"},{"word":"grill","pos":"n. / v.","phonetic":"[grɪl]","meaning":"烤架；烤肉；燒烤","definition":"a frame for cooking food over fire, or to cook food this way","collocations":["grill meat","charcoal grill","grill vegetables"],"example":"We grilled some chicken and vegetables for dinner.","exampleZh":"我們烤了一些雞肉和蔬菜當晚餐。","synonyms":["barbecue"],"level":3,"theme":"餐飲與住宿"},{"word":"grip","pos":"n. / v.","phonetic":"[grɪp]","meaning":"緊握；掌控","definition":"a firm hold, or to hold something tightly","collocations":["grip the wheel","lose grip","tight grip"],"example":"He gripped the steering wheel tightly during the storm.","exampleZh":"暴風雨中他緊緊握住方向盤。","synonyms":["hold","clutch"],"level":4,"theme":"日常與一般"},{"word":"grocery","pos":"n.","phonetic":"[ˈgrosəri]","meaning":"雜貨店；食品雜貨","definition":"a store that sells food and household items","collocations":["grocery store","grocery shopping","grocery bag"],"example":"I need to go to the grocery store to buy milk.","exampleZh":"我需要去雜貨店買牛奶。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"groom","pos":"n. / v.","phonetic":"[grum]","meaning":"新郎；打理；照料","definition":"a man about to be married, or to clean and care for an animal","collocations":["bride and groom","groom a horse","well-groomed"],"example":"The groom looked nervous before the wedding ceremony.","exampleZh":"婚禮之前新郎看起來很緊張。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"gross","pos":"adj.","phonetic":"[gros]","meaning":"噁心的；總計的；粗俗的","definition":"very unpleasant; total before deductions","collocations":["gross income","gross domestic product","that's gross"],"example":"The gross income of the company increased this year.","exampleZh":"這家公司今年的總收入增加了。","synonyms":["total","disgusting"],"level":5,"theme":"財務與會計"},{"word":"ground","pos":"n. / v.","phonetic":"[graʊnd]","meaning":"地面；根據；使停飛","definition":"the surface of the earth; a reason; to prevent aircraft from flying","collocations":["on the ground","ground floor","stand your ground"],"example":"The leaves fell and covered the ground.","exampleZh":"樹葉掉落並覆蓋了地面。","synonyms":["earth","land"],"level":2,"theme":"日常與一般"},{"word":"groundbreaking","pos":"adj./n.","phonetic":"[ˈgraʊndˌbrekɪŋ]","meaning":"開創性的；動土典禮","definition":"very new and original, or the ceremony that starts a construction project","collocations":["groundbreaking research","groundbreaking ceremony"],"example":"The mayor attended the groundbreaking ceremony for the convention center.","exampleZh":"市長出席了會議中心的動土典禮。","synonyms":["innovative","pioneering"],"level":5,"theme":"房產與設施"},{"word":"group","pos":"n. / v.","phonetic":"[grup]","meaning":"團體；小組；分組","definition":"a number of people or things gathered together","collocations":["work in groups","a group of friends","group project"],"example":"We were divided into small groups for the project.","exampleZh":"我們被分成小組進行這項專題。","synonyms":["team","set"],"level":1,"theme":"日常與一般"},{"word":"grow","pos":"v.","phonetic":"[gro]","meaning":"成長；種植；增加","definition":"to increase in size or develop; to cultivate plants","collocations":["grow up","grow vegetables","grow rapidly"],"example":"Children grow so quickly in just a few years.","exampleZh":"孩子在短短幾年內就長得很快。","synonyms":["develop","increase"],"level":1,"theme":"日常與一般"},{"word":"growth","pos":"n.","phonetic":"[groθ]","meaning":"成長；增長；發育","definition":"the process of increasing in size or amount","collocations":["economic growth","population growth","rapid growth"],"example":"The country has experienced rapid economic growth this decade.","exampleZh":"這個國家在這十年間經歷了快速的經濟成長。","synonyms":["development","increase"],"level":3,"theme":"財務與會計"},{"word":"guarantee","pos":"v. / n.","phonetic":"[ˌgærənˈti]","meaning":"保證；擔保","definition":"a promise that something will happen or be done","collocations":["guarantee success","money-back guarantee","under guarantee"],"example":"The company offers a one-year guarantee on all products.","exampleZh":"這家公司對所有產品提供一年保固。","synonyms":["promise","assurance"],"level":4,"theme":"財務與會計"},{"word":"guard","pos":"n. / v.","phonetic":"[gɑrd]","meaning":"守衛；警衛；防衛","definition":"a person who protects a place or people; to protect","collocations":["security guard","guard against","stand guard"],"example":"A security guard stands at the entrance of the building.","exampleZh":"一名保全人員站在大樓入口處。","synonyms":["protect","watch"],"level":2,"theme":"人事與職涯"},{"word":"guardian","pos":"n.","phonetic":"[ˈgɑrdiən]","meaning":"監護人；守護者","definition":"a person who is legally responsible for someone unable to care for themselves","collocations":["legal guardian","act as guardian","parent or guardian"],"example":"Her uncle became her legal guardian after her parents passed away.","exampleZh":"她父母過世後，叔叔成了她的法定監護人。","synonyms":["protector"],"level":4,"theme":"日常與一般"},{"word":"guess","pos":"v. / n.","phonetic":"[gɛs]","meaning":"猜測；猜想","definition":"to give an answer without being sure it is correct","collocations":["take a guess","guess the answer","best guess"],"example":"Can you guess how old I am?","exampleZh":"你能猜出我幾歲嗎？","synonyms":["estimate","suppose"],"level":1,"theme":"日常與一般"},{"word":"guest","pos":"n.","phonetic":"[gɛst]","meaning":"客人；房客；來賓","definition":"a person invited somewhere or staying at a hotel","collocations":["hotel guest","guest speaker","guest of honor"],"example":"All hotel guests receive a complimentary breakfast voucher.","exampleZh":"所有飯店房客都能獲得免費早餐券。","synonyms":["visitor"],"level":1,"theme":"餐飲與住宿"},{"word":"guesthouse","pos":"n.","phonetic":"[ˈgɛstˌhaʊs]","meaning":"民宿；招待所","definition":"a small hotel or a private house offering rooms to travelers","collocations":["stay at a guesthouse","family-run guesthouse"],"example":"We stayed at a family-run guesthouse near the old town.","exampleZh":"我們住在老城區附近一間家庭經營的民宿。","synonyms":["inn","lodge"],"level":4,"theme":"餐飲與住宿"},{"word":"guidance","pos":"n.","phonetic":"[ˈgaɪdns]","meaning":"指導；引導","definition":"help and advice about how to do something","collocations":["provide guidance","under the guidance of","career guidance"],"example":"New employees receive guidance from a mentor during their first month.","exampleZh":"新進員工在第一個月會有導師從旁指導。","synonyms":["direction","advice"],"level":4,"theme":"人事與職涯"},{"word":"guide","pos":"n./v.","phonetic":"[gaɪd]","meaning":"導遊；指南；引導","definition":"a person who shows others around, a book of information, or to lead","collocations":["tour guide","user guide","guide visitors"],"example":"The tour guide explained the history of each landmark building.","exampleZh":"導遊講解了每棟地標建築的歷史。","synonyms":["lead","direct"],"level":1,"theme":"旅遊與交通"},{"word":"guidebook","pos":"n.","phonetic":"[ˈgaɪdˌbʊk]","meaning":"旅遊指南；手冊","definition":"a book with information for tourists or users","collocations":["travel guidebook","city guidebook"],"example":"The guidebook recommends visiting the market early in the morning.","exampleZh":"旅遊指南建議一大早去逛市場。","synonyms":["handbook"],"level":3,"theme":"旅遊與交通"},{"word":"guideline","pos":"n.","phonetic":"[ˈgaɪdˌlaɪn]","meaning":"指導方針；準則","definition":"an official rule or piece of advice about how to do something","collocations":["safety guidelines","follow the guidelines","issue guidelines"],"example":"All staff must follow the new data privacy guidelines.","exampleZh":"所有員工都必須遵守新的資料隱私準則。","synonyms":["rule","standard"],"level":4,"theme":"辦公室與行政"},{"word":"gym","pos":"n.","phonetic":"[dʒɪm]","meaning":"健身房；體育館","definition":"a place with equipment for physical exercise","collocations":["go to the gym","gym membership","hotel gym"],"example":"The office building includes a gym for employee use.","exampleZh":"辦公大樓內設有供員工使用的健身房。","synonyms":["fitness center"],"level":1,"theme":"日常與一般"},{"word":"habit","pos":"n.","phonetic":"[ˈhæbɪt]","meaning":"習慣；癖好","definition":"a thing that you do often and regularly","collocations":["form a habit","bad habit","habit of doing something","break a habit"],"example":"Reading before bed is a good habit.","exampleZh":"睡前閱讀是個好習慣。","synonyms":["custom","routine"],"level":2,"theme":"日常與一般"},{"word":"half","pos":"n. / adj.","phonetic":"[hæf]","meaning":"一半；半數的","definition":"one of two equal parts of something","collocations":["half an hour","cut in half","half price"],"example":"He ate half of the sandwich.","exampleZh":"他吃了三明治的一半。","synonyms":[],"level":1,"theme":"科技與通訊"},{"word":"hall","pos":"n.","phonetic":"[hɔl]","meaning":"大廳；會堂；走廊","definition":"a large room for events, or the entrance area of a building","collocations":["conference hall","city hall","exhibition hall"],"example":"The awards ceremony will be held in the main conference hall.","exampleZh":"頒獎典禮將在主會議廳舉行。","synonyms":["auditorium"],"level":1,"theme":"房產與設施"},{"word":"hallway","pos":"n.","phonetic":"[ˈhɔlˌwe]","meaning":"走廊；門廳","definition":"a passage in a building that connects rooms","collocations":["walk down the hallway","narrow hallway","school hallway"],"example":"Students were talking loudly in the hallway.","exampleZh":"學生們在走廊上大聲談話。","synonyms":["corridor"],"level":2,"theme":"房產與設施"},{"word":"halt","pos":"v. / n.","phonetic":"[hɔlt]","meaning":"停止；中止","definition":"to stop moving or doing something","collocations":["come to a halt","halt production","grind to a halt"],"example":"The train came to a sudden halt.","exampleZh":"火車突然停了下來。","synonyms":["stop"],"level":3,"theme":"日常與一般"},{"word":"hand","pos":"n./v.","phonetic":"[hænd]","meaning":"手；交付；遞交","definition":"the part of the body at the end of the arm, or to give something to someone","collocations":["hand in a report","on hand","hand out"],"example":"Please hand in your timesheets by the end of the day.","exampleZh":"請在今天下班前繳交工時表。","synonyms":["submit","pass"],"level":1,"theme":"日常與一般"},{"word":"handbook","pos":"n.","phonetic":"[ˈhændˌbʊk]","meaning":"手冊；指南","definition":"a book with instructions or information about a subject","collocations":["employee handbook","refer to the handbook"],"example":"The dress code policy is explained in the employee handbook.","exampleZh":"服裝規定在員工手冊中有詳細說明。","synonyms":["manual","guide"],"level":3,"theme":"辦公室與行政"},{"word":"handful","pos":"n.","phonetic":"['hændfʊl]","meaning":"一把；少數","definition":"a small quantity or number of something","collocations":["a handful of people","a handful of sand","only a handful"],"example":"Only a handful of students showed up early.","exampleZh":"只有少數幾個學生提早到場。","synonyms":["few"],"level":3,"theme":"日常與一般"},{"word":"handle","pos":"v. / n.","phonetic":"[ˈhændl]","meaning":"處理；把手","definition":"to deal with a problem or situation, or the part of an object held by hand","collocations":["handle a problem","door handle","handle with care"],"example":"She knows how to handle difficult customers.","exampleZh":"她知道如何應付難纏的顧客。","synonyms":["manage","deal with"],"level":3,"theme":"日常與一般"},{"word":"handling","pos":"n.","phonetic":"[ˈhændlɪŋ]","meaning":"處理；搬運；手續","definition":"the way something is dealt with or moved","collocations":["shipping and handling","careful handling","handling fee"],"example":"Shipping and handling charges are added at checkout.","exampleZh":"運費及手續費將於結帳時計入。","synonyms":["management"],"level":3,"theme":"生產與物流"},{"word":"handout","pos":"n.","phonetic":"['hændˌaʊt]","meaning":"講義；施捨物","definition":"a printed sheet given out; something given free to those in need","collocations":["distribute handouts","a class handout","live on handouts"],"example":"The teacher gave each student a handout before class.","exampleZh":"老師上課前發給每位學生一份講義。","synonyms":["leaflet"],"level":4,"theme":"人事與職涯"},{"word":"hands-on","pos":"adj.","phonetic":"[ˈhændzˈɑn]","meaning":"實作的；親自動手的","definition":"involving direct practical experience rather than theory","collocations":["hands-on training","hands-on experience","hands-on workshop"],"example":"The workshop provides hands-on training with the new equipment.","exampleZh":"工作坊提供新設備的實作訓練。","synonyms":["practical"],"level":5,"theme":"人事與職涯"},{"word":"handy","pos":"adj.","phonetic":"[ˈhændi]","meaning":"方便的；手巧的","definition":"useful or convenient, or skillful with one's hands","collocations":["come in handy","handy tool","handy with tools"],"example":"A smartphone is handy for checking directions.","exampleZh":"智慧型手機在查路線時很方便。","synonyms":["convenient","useful"],"level":3,"theme":"日常與一般"},{"word":"hang","pos":"v.","phonetic":"[hæŋ]","meaning":"懸掛；吊掛","definition":"to attach or suspend something so it does not touch the ground","collocations":["hang a picture","hang out","hang up the phone"],"example":"She hung the painting on the wall.","exampleZh":"她把那幅畫掛在牆上。","synonyms":["suspend"],"level":2,"theme":"日常與一般"},{"word":"happen","pos":"v.","phonetic":"[ˈhæpən]","meaning":"發生；碰巧","definition":"to take place, especially without being planned","collocations":["happen to someone","what happened","happen by chance"],"example":"Nobody knows what happened to the missing keys.","exampleZh":"沒有人知道那把不見的鑰匙發生了什麼事。","synonyms":["occur","take place"],"level":1,"theme":"日常與一般"},{"word":"harbor","pos":"n. / v.","phonetic":"[ˈhɑrbɚ]","meaning":"港口；懷有（情感）","definition":"a place where ships can shelter, or to keep a feeling in mind","collocations":["fishing harbor","harbor a grudge","safe harbor"],"example":"The fishing boats returned to the harbor before the storm.","exampleZh":"漁船在暴風雨來臨前返回了港口。","synonyms":["port"],"level":4,"theme":"旅遊與交通"},{"word":"hard","pos":"adj./adv.","phonetic":"[hɑrd]","meaning":"困難的；硬的；努力地","definition":"difficult, firm, or with a lot of effort","collocations":["work hard","hard copy","hard work"],"example":"Please bring a hard copy of the contract to the signing.","exampleZh":"簽約時請攜帶合約的紙本。","synonyms":["difficult","tough"],"level":1,"theme":"日常與一般"},{"word":"hardly","pos":"adv.","phonetic":"[ˈhɑrdlɪ]","meaning":"幾乎不；簡直不","definition":"almost not at all","collocations":["hardly ever","hardly any","can hardly"],"example":"There were hardly any seats left when we arrived at the seminar.","exampleZh":"我們抵達研討會時，幾乎沒有剩下的座位了。","synonyms":["barely","scarcely"],"level":3,"theme":"日常與一般"},{"word":"hardware","pos":"n.","phonetic":"[ˈhɑrdˌwɛr]","meaning":"硬體；五金器具","definition":"the physical parts of a computer, or metal tools and equipment","collocations":["computer hardware","hardware store","hardware upgrade"],"example":"The new hardware made the computer run much faster.","exampleZh":"新硬體讓這台電腦運作得快多了。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"harm","pos":"n. / v.","phonetic":"[hɑrm]","meaning":"傷害；損害","definition":"physical or other damage, or to cause such damage","collocations":["cause harm","do no harm","harm the environment"],"example":"Too much sun can harm your skin.","exampleZh":"過度曬太陽會傷害你的皮膚。","synonyms":["damage","hurt"],"level":3,"theme":"日常與一般"},{"word":"harmful","pos":"adj.","phonetic":"[ˈhɑrmfəl]","meaning":"有害的","definition":"causing damage or injury","collocations":["harmful effects","harmful substances","harmful to health"],"example":"The packaging is free of chemicals harmful to the environment.","exampleZh":"這種包裝不含對環境有害的化學物質。","synonyms":["damaging","hazardous"],"level":3,"theme":"日常與一般"},{"word":"harvest","pos":"n. / v.","phonetic":"[ˈhɑrvɪst]","meaning":"收穫；收割","definition":"the gathering of crops, or to gather crops","collocations":["harvest crops","rice harvest","autumn harvest"],"example":"Farmers harvest rice in the autumn.","exampleZh":"農夫在秋天收割稻米。","synonyms":["reap","gather"],"level":3,"theme":"日常與一般"},{"word":"hazard","pos":"n.","phonetic":"[ˈhæzɚd]","meaning":"危險；危害","definition":"a danger or risk","collocations":["safety hazard","health hazard","fire hazard"],"example":"Wet floors are a safety hazard.","exampleZh":"濕滑的地板是一種安全危害。","synonyms":["danger","risk"],"level":5,"theme":"日常與一般"},{"word":"hazardous","pos":"adj.","phonetic":"['hæzɚdəs]","meaning":"危險的；有害的","definition":"risky or dangerous, especially to health or safety","collocations":["hazardous waste","hazardous conditions","hazardous materials"],"example":"Workers must wear gloves when handling hazardous chemicals.","exampleZh":"工人在處理危險化學品時必須戴手套。","synonyms":["dangerous","risky"],"level":4,"theme":"日常與一般"},{"word":"head","pos":"n./v.","phonetic":"[hɛd]","meaning":"頭；主管；率領；前往","definition":"the top part of the body, the leader of a group, or to go in a direction","collocations":["head of the department","head a team","head to"],"example":"She heads the research division at the pharmaceutical company.","exampleZh":"她在這家製藥公司主管研究部門。","synonyms":["lead","chief"],"level":1,"theme":"企業經營"},{"word":"headache","pos":"n.","phonetic":"[ˈhɛdˌek]","meaning":"頭痛；令人頭痛的事","definition":"a pain in the head, or a difficult problem","collocations":["get a headache","severe headache","cause a headache"],"example":"I have a terrible headache today.","exampleZh":"我今天頭痛得很厲害。","synonyms":[],"level":2,"theme":"醫療與保險"},{"word":"headcount","pos":"n.","phonetic":"[ˈhɛdˌkaʊnt]","meaning":"人數；員工總數","definition":"the total number of people in a group or company","collocations":["increase headcount","headcount freeze","do a headcount"],"example":"The department plans to increase its headcount by ten next quarter.","exampleZh":"該部門計畫下一季增加十名員工。","synonyms":["staff size"],"level":5,"theme":"人事與職涯"},{"word":"headline","pos":"n.","phonetic":"[ˈhɛdˌlaɪn]","meaning":"標題；頭條新聞","definition":"the title at the top of a newspaper article","collocations":["news headline","make headlines","front-page headline"],"example":"The scandal made headlines around the world.","exampleZh":"這起醜聞成為全球頭條新聞。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"headquarters","pos":"n.","phonetic":"['hɛd'kwɔrtɚz]","meaning":"總部；總公司","definition":"the main office of an organization","collocations":["company headquarters","military headquarters","move headquarters"],"example":"The company's headquarters is located in Taipei.","exampleZh":"這家公司的總部位於台北。","synonyms":["main office"],"level":3,"theme":"人事與職涯"},{"word":"health","pos":"n.","phonetic":"[hɛlθ]","meaning":"健康；衛生","definition":"the condition of a person's body or mind","collocations":["health insurance","health benefits","health and safety"],"example":"The company offers comprehensive health insurance to all employees.","exampleZh":"公司為所有員工提供完善的健康保險。","synonyms":["well-being"],"level":1,"theme":"醫療與保險"},{"word":"healthcare","pos":"n.","phonetic":"[ˈhɛlθˌkɛr]","meaning":"醫療保健；醫療服務","definition":"the service of providing medical care","collocations":["healthcare provider","healthcare costs","healthcare industry"],"example":"Rising healthcare costs are a major concern for many employers.","exampleZh":"醫療成本上漲是許多雇主關切的重大議題。","synonyms":[],"level":4,"theme":"醫療與保險"},{"word":"healthy","pos":"adj.","phonetic":"[ˈhɛlθɪ]","meaning":"健康的；有益健康的","definition":"in good physical or mental condition, or good for health","collocations":["healthy diet","stay healthy","healthy lifestyle"],"example":"Eating vegetables is part of a healthy diet.","exampleZh":"吃蔬菜是健康飲食的一部分。","synonyms":["fit","well"],"level":1,"theme":"醫療與保險"},{"word":"hear","pos":"v.","phonetic":"[hɪr]","meaning":"聽到；聽說；審理","definition":"to receive sounds with your ears, or to be told about something","collocations":["hear from","hear about","hear a case"],"example":"We look forward to hearing from you regarding the proposal.","exampleZh":"我們期待收到您對提案的回覆。","synonyms":["listen"],"level":1,"theme":"溝通與語言"},{"word":"hearing","pos":"n.","phonetic":"[ˈhɪrɪŋ]","meaning":"聽力；聽證會","definition":"the ability to hear, or an official meeting to listen to facts","collocations":["public hearing","court hearing","hearing loss"],"example":"A public hearing on the zoning change is scheduled for Tuesday.","exampleZh":"關於土地使用分區變更的公聽會訂於週二舉行。","synonyms":[],"level":4,"theme":"合約與法律"},{"word":"heat","pos":"n./v.","phonetic":"[hit]","meaning":"熱；暖氣；加熱","definition":"the quality of being hot, or to make something warm","collocations":["heat up","central heating","extreme heat"],"example":"Please do not heat food in containers not labeled microwave-safe.","exampleZh":"請勿用未標示可微波的容器加熱食物。","synonyms":["warm"],"level":1,"theme":"日常與一般"},{"word":"heating","pos":"n.","phonetic":"[ˈhitɪŋ]","meaning":"暖氣（系統）","definition":"a system that keeps a building warm","collocations":["central heating","heating system","heating costs"],"example":"The building's heating system will be serviced over the weekend.","exampleZh":"大樓的暖氣系統將於週末進行保養。","synonyms":[],"level":3,"theme":"房產與設施"},{"word":"heavily","pos":"adv.","phonetic":"[ˈhɛvɪlɪ]","meaning":"大量地；沉重地","definition":"to a great degree or in large amounts","collocations":["invest heavily","rely heavily on","heavily discounted"],"example":"The company has invested heavily in renewable energy technology.","exampleZh":"該公司大量投資於再生能源技術。","synonyms":["greatly"],"level":3,"theme":"日常與一般"},{"word":"heavy","pos":"adj.","phonetic":"[ˈhɛvɪ]","meaning":"重的；大量的；繁忙的","definition":"weighing a lot, or great in amount or degree","collocations":["heavy traffic","heavy workload","heavy machinery"],"example":"Expect heavy traffic on the highway during the holiday weekend.","exampleZh":"連假週末期間，高速公路預計會嚴重塞車。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"hectic","pos":"adj.","phonetic":"['hɛktɪk]","meaning":"忙碌的；繁忙的","definition":"full of activity and difficult to manage","collocations":["a hectic schedule","a hectic day","hectic pace"],"example":"She had a hectic week preparing for the exam.","exampleZh":"她為了準備考試度過忙碌的一週。","synonyms":["busy","frantic"],"level":4,"theme":"人事與職涯"},{"word":"height","pos":"n.","phonetic":"[haɪt]","meaning":"高度；身高","definition":"the measurement of how tall someone or something is","collocations":["average height","height and weight","gain height"],"example":"He is about 180 centimeters in height.","exampleZh":"他的身高大約一百八十公分。","synonyms":["tallness"],"level":2,"theme":"科技與通訊"},{"word":"help","pos":"v./n.","phonetic":"[hɛlp]","meaning":"幫助；協助","definition":"to make it easier for someone to do something","collocations":["help desk","help with","ask for help"],"example":"Contact the IT help desk if you cannot access your email.","exampleZh":"若無法登入電子郵件，請聯絡資訊服務台。","synonyms":["assist","aid"],"level":1,"theme":"日常與一般"},{"word":"helpful","pos":"adj.","phonetic":"[ˈhɛlpfəl]","meaning":"有幫助的；樂於助人的","definition":"useful, or willing to help","collocations":["helpful advice","helpful staff","extremely helpful"],"example":"The concierge was very helpful in arranging our airport transfer.","exampleZh":"禮賓人員非常熱心地為我們安排了機場接送。","synonyms":["useful","supportive"],"level":2,"theme":"餐飲與住宿"},{"word":"hence","pos":"adv.","phonetic":"[hɛns]","meaning":"因此；由此","definition":"for this reason","collocations":["hence the delay","hence the name"],"example":"The factory is closed for repairs; hence, all orders are delayed.","exampleZh":"工廠停工維修，因此所有訂單都延後了。","synonyms":["therefore","thus"],"level":5,"theme":"溝通與語言"},{"word":"herbal","pos":"adj.","phonetic":"[ˈɝbl]","meaning":"草本的；藥草的","definition":"made from plants used in cooking or medicine","collocations":["herbal tea","herbal remedy","herbal supplement"],"example":"The cafe serves a selection of herbal teas and fresh juices.","exampleZh":"這家咖啡館供應多種草本茶和新鮮果汁。","synonyms":[],"level":4,"theme":"餐飲與住宿"},{"word":"heritage","pos":"n.","phonetic":"[ˈhɛrətɪdʒ]","meaning":"遺產；傳統文化","definition":"features belonging to the culture of a particular society passed down over generations","collocations":["cultural heritage","world heritage site","family heritage"],"example":"The temple is part of the city's cultural heritage.","exampleZh":"這座寺廟是這座城市文化遺產的一部分。","synonyms":["legacy","tradition"],"level":5,"theme":"日常與一般"},{"word":"hesitant","pos":"adj.","phonetic":"['hɛzətənt]","meaning":"猶豫的；躊躇的","definition":"slow to act or speak because of feeling unsure","collocations":["hesitant to speak","feel hesitant","a hesitant smile"],"example":"He was hesitant to share his opinion in front of everyone.","exampleZh":"他猶豫著不敢在大家面前發表意見。","synonyms":["reluctant","uncertain"],"level":4,"theme":"日常與一般"},{"word":"hesitate","pos":"v.","phonetic":"[ˈhɛzəˌtet]","meaning":"猶豫；躊躇","definition":"to pause before doing or saying something because of uncertainty","collocations":["hesitate to ask","without hesitation","hesitate before answering"],"example":"Don't hesitate to ask if you have any questions.","exampleZh":"如果你有任何問題，不要猶豫儘管問。","synonyms":["waver","pause"],"level":4,"theme":"日常與一般"},{"word":"hidden","pos":"adj.","phonetic":"[ˈhɪdn]","meaning":"隱藏的；隱含的","definition":"not easy to see or find","collocations":["hidden fees","hidden costs","hidden camera"],"example":"Read the contract carefully to avoid any hidden fees.","exampleZh":"請仔細閱讀合約，以免有隱藏費用。","synonyms":["concealed"],"level":3,"theme":"購物與消費"},{"word":"hide","pos":"v.","phonetic":"[haɪd]","meaning":"隱藏；躲藏","definition":"to put or keep something out of sight","collocations":["hide something","hide from someone","play hide and seek"],"example":"The children hid behind the curtains.","exampleZh":"孩子們躲在窗簾後面。","synonyms":["conceal"],"level":1,"theme":"日常與一般"},{"word":"high","pos":"adj./adv.","phonetic":"[haɪ]","meaning":"高的；高度地","definition":"a long way above the ground, or great in amount or level","collocations":["high demand","high quality","high season"],"example":"Hotel rates are much higher during the high season.","exampleZh":"旺季期間飯店房價高出許多。","synonyms":["tall","elevated"],"level":1,"theme":"日常與一般"},{"word":"high-end","pos":"adj.","phonetic":"[ˈhaɪˈɛnd]","meaning":"高檔的；高階的","definition":"expensive and of high quality","collocations":["high-end products","high-end market","high-end brand"],"example":"The boutique specializes in high-end leather goods.","exampleZh":"這家精品店專營高檔皮件。","synonyms":["upscale","luxury"],"level":5,"theme":"購物與消費"},{"word":"high-tech","pos":"adj.","phonetic":"[ˈhaɪˈtɛk]","meaning":"高科技的","definition":"using the most advanced technology","collocations":["high-tech industry","high-tech equipment","high-tech company"],"example":"The region has attracted many high-tech companies in recent years.","exampleZh":"近年來這個地區吸引了許多高科技公司進駐。","synonyms":["advanced"],"level":4,"theme":"科技與通訊"},{"word":"highlight","pos":"v. / n.","phonetic":"[ˈhaɪˌlaɪt]","meaning":"強調；精彩部分","definition":"to draw special attention to something, or the most memorable part","collocations":["highlight a point","highlight of the trip","highlight reel"],"example":"The concert was the highlight of my summer.","exampleZh":"那場演唱會是我這個夏天最精彩的事。","synonyms":["emphasize"],"level":4,"theme":"日常與一般"},{"word":"highly","pos":"adv.","phonetic":"[ˈhaɪlɪ]","meaning":"高度地；非常","definition":"very or to a large degree","collocations":["highly recommended","highly skilled","highly qualified"],"example":"This restaurant is highly recommended by local food critics.","exampleZh":"這家餐廳深受當地美食評論家的推薦。","synonyms":["very","extremely"],"level":2,"theme":"日常與一般"},{"word":"hire","pos":"v.","phonetic":"[haɪr]","meaning":"雇用；租用","definition":"to employ someone, or to pay to use something temporarily","collocations":["hire an employee","hire a car","newly hired"],"example":"The company decided to hire two new engineers.","exampleZh":"這家公司決定雇用兩名新工程師。","synonyms":["employ","rent"],"level":3,"theme":"人事與職涯"},{"word":"hiring","pos":"n.","phonetic":"[ˈhaɪrɪŋ]","meaning":"招聘；僱用","definition":"the activity of employing new people","collocations":["hiring process","hiring manager","hiring freeze"],"example":"The hiring process usually takes about four weeks from application to offer.","exampleZh":"從申請到錄取，招聘流程通常需要約四週。","synonyms":["recruitment"],"level":3,"theme":"人事與職涯"},{"word":"historic","pos":"adj.","phonetic":"[hɪsˈtɔrɪk]","meaning":"具歷史意義的；歷史性的","definition":"important in history or likely to be remembered","collocations":["historic building","historic district","historic agreement"],"example":"The walking tour passes through the city's historic district.","exampleZh":"徒步導覽會經過該市的歷史街區。","synonyms":["momentous"],"level":4,"theme":"旅遊與交通"},{"word":"historical","pos":"adj.","phonetic":"[hɪsˈtɔrɪkl]","meaning":"歷史的；有關歷史的","definition":"connected with the past or the study of history","collocations":["historical data","historical records","historical site"],"example":"The report compares current sales with historical data from past years.","exampleZh":"報告將目前的銷售與歷年資料進行比較。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"history","pos":"n.","phonetic":"[ˈhɪstərɪ]","meaning":"歷史；經歷；紀錄","definition":"past events, or a record of past events","collocations":["credit history","company history","order history"],"example":"You can view your complete order history in your account settings.","exampleZh":"你可以在帳戶設定中查看完整的訂購紀錄。","synonyms":["record"],"level":1,"theme":"日常與一般"},{"word":"hold","pos":"v. / n.","phonetic":"[hold]","meaning":"拿著；握住；持有","definition":"to have or keep something in one's hand or arms","collocations":["hold hands","hold a meeting","get hold of"],"example":"She held the baby gently in her arms.","exampleZh":"她輕輕地抱著寶寶。","synonyms":["grasp","grip"],"level":1,"theme":"日常與一般"},{"word":"holder","pos":"n.","phonetic":"[ˈholdɚ]","meaning":"持有人；支架","definition":"a person who possesses something, or an object that holds something","collocations":["record holder","cup holder","ticket holder"],"example":"He is the current holder of the world record.","exampleZh":"他是目前的世界紀錄保持人。","synonyms":["owner"],"level":3,"theme":"日常與一般"},{"word":"holiday","pos":"n.","phonetic":"[ˈhɑləˌde]","meaning":"假日；假期","definition":"a day or period of rest from work or school","collocations":["national holiday","go on holiday","summer holiday"],"example":"We are planning a family holiday to the beach.","exampleZh":"我們正在計劃一次全家的海灘假期。","synonyms":["vacation","break"],"level":1,"theme":"旅遊與交通"},{"word":"home","pos":"n. / adv.","phonetic":"[hom]","meaning":"家；家鄉","definition":"the place where one lives","collocations":["at home","go home","home cooking"],"example":"There is no place like home.","exampleZh":"沒有一個地方比得上家。","synonyms":["house","residence"],"level":1,"theme":"房產與設施"},{"word":"homemade","pos":"adj.","phonetic":"[ˈhomˈmed]","meaning":"自製的；手工的","definition":"made at home rather than bought from a shop","collocations":["homemade bread","homemade dessert"],"example":"The bakery is famous for its homemade pies and pastries.","exampleZh":"這家烘焙坊以自製派餅和糕點聞名。","synonyms":["handmade"],"level":2,"theme":"餐飲與住宿"},{"word":"homepage","pos":"n.","phonetic":"[ˈhomˌpedʒ]","meaning":"（網站）首頁","definition":"the main page of a website","collocations":["visit the homepage","on the homepage"],"example":"The special offer is announced on the company homepage.","exampleZh":"特別優惠已公告在公司網站首頁。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"hometown","pos":"n.","phonetic":"[ˈhomˈtaʊn]","meaning":"家鄉；故鄉","definition":"the town where a person was born or grew up","collocations":["return to one's hometown","hometown pride"],"example":"After twenty years abroad, he returned to his hometown to open a restaurant.","exampleZh":"旅居國外二十年後，他回到家鄉開了一家餐廳。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"honor","pos":"n. / v.","phonetic":"[ˈɑnɚ]","meaning":"榮譽；尊敬","definition":"great respect, or to show respect for someone","collocations":["great honor","honor a promise","in honor of"],"example":"It was a great honor to receive the award.","exampleZh":"獲得這個獎項是莫大的榮譽。","synonyms":["respect","glory"],"level":4,"theme":"日常與一般"},{"word":"hope","pos":"v. / n.","phonetic":"[hop]","meaning":"希望；期望","definition":"to want something to happen or be true","collocations":["hope for the best","give up hope","hope so"],"example":"I hope you feel better soon.","exampleZh":"我希望你早點康復。","synonyms":["wish","expect"],"level":1,"theme":"日常與一般"},{"word":"hopefully","pos":"adv.","phonetic":"[ˈhopfəlɪ]","meaning":"但願；有希望地","definition":"used to say what you hope will happen","collocations":["hopefully by Friday"],"example":"Hopefully, the replacement parts will arrive before the weekend.","exampleZh":"但願更換零件能在週末前送達。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"horizontal","pos":"adj.","phonetic":"[ˌhɔrəˈzɑntl]","meaning":"水平的；橫的","definition":"parallel to the ground, flat and level","collocations":["horizontal line","horizontal position","horizontal axis"],"example":"Draw a horizontal line across the page.","exampleZh":"在頁面上畫一條水平線。","synonyms":[],"level":5,"theme":"科技與通訊"},{"word":"hospitable","pos":"adj.","phonetic":"[ˈhɑspɪtəbl]","meaning":"好客的；殷勤的","definition":"friendly and welcoming to guests and visitors","collocations":["hospitable staff","hospitable environment"],"example":"The islanders are known for being warm and hospitable to tourists.","exampleZh":"島上居民以熱情好客聞名。","synonyms":["welcoming","friendly"],"level":6,"theme":"餐飲與住宿"},{"word":"hospital","pos":"n.","phonetic":"[ˈhɑspɪtl]","meaning":"醫院","definition":"a place where sick or injured people are treated","collocations":["go to the hospital","hospital bed","admit to hospital"],"example":"He was taken to the hospital after the accident.","exampleZh":"意外發生後他被送到醫院。","synonyms":[],"level":1,"theme":"醫療與保險"},{"word":"hospitality","pos":"n.","phonetic":"[ˌhɑspɪˈtælətɪ]","meaning":"好客；款待","definition":"friendly and generous treatment of guests","collocations":["show hospitality","thank for the hospitality","hospitality industry"],"example":"We were grateful for the warm hospitality of our hosts.","exampleZh":"我們很感激主人熱情的款待。","synonyms":["warmth"],"level":5,"theme":"日常與一般"},{"word":"host","pos":"n. / v.","phonetic":"[host]","meaning":"主人；主持人；主辦","definition":"a person who receives guests, or to organize an event","collocations":["host a party","talk show host","host country"],"example":"Taiwan hosted an international sports event last year.","exampleZh":"台灣去年主辦了一場國際運動賽事。","synonyms":["organizer"],"level":3,"theme":"日常與一般"},{"word":"hotel","pos":"n.","phonetic":"[hoˈtɛl]","meaning":"旅館；飯店","definition":"a building where travelers pay to stay overnight","collocations":["check into a hotel","five-star hotel","book a hotel"],"example":"We stayed at a small hotel near the beach.","exampleZh":"我們住在海邊附近的一家小旅館。","synonyms":["inn"],"level":1,"theme":"旅遊與交通"},{"word":"hour","pos":"n.","phonetic":"[aʊr]","meaning":"小時","definition":"a period of sixty minutes","collocations":["an hour later","rush hour","office hours"],"example":"The meeting lasted for almost two hours.","exampleZh":"這場會議持續了將近兩個小時。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"hourly","pos":"adj. / adv.","phonetic":"[ˈaʊrlɪ]","meaning":"每小時的；按時計算的","definition":"happening or done every hour, or calculated by the hour","collocations":["hourly wage","hourly rate","update hourly"],"example":"The part-time job pays an hourly wage of 180 dollars.","exampleZh":"這份兼職工作的時薪是一百八十元。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"house","pos":"n.","phonetic":"[haʊs]","meaning":"房子；住宅","definition":"a building where people live","collocations":["build a house","move house","house rent"],"example":"They bought a house near the park.","exampleZh":"他們在公園附近買了一棟房子。","synonyms":["home","residence"],"level":1,"theme":"房產與設施"},{"word":"household","pos":"n. / adj.","phonetic":"[ˈhaʊsˌhold]","meaning":"家庭；家戶的","definition":"a house and its occupants regarded as a unit","collocations":["household chores","household income","average household"],"example":"Every household in the neighborhood received a notice.","exampleZh":"社區裡每一戶都收到了通知。","synonyms":["family"],"level":4,"theme":"日常與一般"},{"word":"housekeeping","pos":"n.","phonetic":"[ˈhaʊsˌkipɪŋ]","meaning":"（飯店）房務；家務管理","definition":"the department in a hotel that cleans rooms, or the management of a home","collocations":["housekeeping staff","call housekeeping","housekeeping service"],"example":"Call housekeeping if you need extra towels or pillows.","exampleZh":"如需額外的毛巾或枕頭，請聯絡房務部。","synonyms":[],"level":4,"theme":"餐飲與住宿"},{"word":"housing","pos":"n.","phonetic":"[ˈhaʊzɪŋ]","meaning":"住宅；住房供給","definition":"buildings for people to live in","collocations":["housing market","affordable housing","housing prices"],"example":"The city plans to build more affordable housing near the transit line.","exampleZh":"市府計畫在捷運沿線興建更多平價住宅。","synonyms":["accommodation"],"level":4,"theme":"房產與設施"},{"word":"however","pos":"adv. / conj.","phonetic":"[haʊˈɛvɚ]","meaning":"然而；不過","definition":"used to introduce a statement that contrasts with what came before","collocations":["however hard","however, it is","no matter how"],"example":"The weather was cold; however, we still went hiking.","exampleZh":"天氣很冷,然而我們還是去健行了。","synonyms":["nevertheless"],"level":2,"theme":"溝通與語言"},{"word":"hub","pos":"n.","phonetic":"[hʌb]","meaning":"中心；樞紐","definition":"the central or most important place for an activity","collocations":["transportation hub","business hub","regional hub"],"example":"The airport serves as a major hub for flights to Southeast Asia.","exampleZh":"這座機場是飛往東南亞航班的主要樞紐。","synonyms":["center"],"level":5,"theme":"旅遊與交通"},{"word":"huge","pos":"adj.","phonetic":"[hjudʒ]","meaning":"巨大的；龐大的","definition":"extremely large in size or amount","collocations":["huge success","huge amount","huge crowd"],"example":"The concert attracted a huge crowd of fans.","exampleZh":"這場演唱會吸引了一大群粉絲。","synonyms":["enormous","massive"],"level":2,"theme":"日常與一般"},{"word":"human","pos":"adj. / n.","phonetic":"[ˈhjumən]","meaning":"人類的；人類","definition":"relating to or being a person","collocations":["human being","human rights","human nature"],"example":"Human beings depend on nature for survival.","exampleZh":"人類依賴大自然才能生存。","synonyms":["person"],"level":2,"theme":"日常與一般"},{"word":"humid","pos":"adj.","phonetic":"[ˈhjumɪd]","meaning":"潮濕的；濕熱的","definition":"marked by a high level of water vapor in the air","collocations":["humid weather","hot and humid","humid climate"],"example":"Summers in Taiwan are hot and humid.","exampleZh":"台灣的夏天既悶熱又潮濕。","synonyms":["damp","moist"],"level":3,"theme":"日常與一般"},{"word":"humidity","pos":"n.","phonetic":"[hjuˈmɪdətɪ]","meaning":"濕度","definition":"the amount of moisture in the air","collocations":["high humidity","humidity level","relative humidity"],"example":"The high humidity made the day feel even hotter.","exampleZh":"高濕度讓這一天感覺更加悶熱。","synonyms":["dampness"],"level":4,"theme":"日常與一般"},{"word":"hurry","pos":"v. / n.","phonetic":"[ˈhɝɪ]","meaning":"匆忙；趕緊","definition":"to move or act quickly","collocations":["hurry up","in a hurry","hurry home"],"example":"We need to hurry, or we'll miss the train.","exampleZh":"我們得快點,不然會錯過火車。","synonyms":["rush"],"level":1,"theme":"日常與一般"},{"word":"hurt","pos":"v. / adj.","phonetic":"[hɝt]","meaning":"傷害；受傷的","definition":"to cause pain or injury, or feeling pain or emotional distress","collocations":["get hurt","hurt someone's feelings","hurt badly"],"example":"She hurt her ankle while playing basketball.","exampleZh":"她打籃球時傷到了腳踝。","synonyms":["injure","wound"],"level":1,"theme":"醫療與保險"},{"word":"hygiene","pos":"n.","phonetic":"[ˈhaɪdʒin]","meaning":"衛生；保健","definition":"practices that keep people and places clean and healthy","collocations":["personal hygiene","dental hygiene","hygiene standards"],"example":"Good personal hygiene helps prevent illness.","exampleZh":"良好的個人衛生有助於預防疾病。","synonyms":["cleanliness"],"level":5,"theme":"醫療與保險"},{"word":"icon","pos":"n.","phonetic":"[ˈaɪkɑn]","meaning":"圖示；偶像；聖像","definition":"a symbol or image, especially one shown on a computer screen","collocations":["click an icon","a cultural icon","fashion icon"],"example":"Click the icon to open the app.","exampleZh":"點擊圖示以開啟應用程式。","synonyms":["symbol","idol"],"level":4,"theme":"科技與通訊"},{"word":"idea","pos":"n.","phonetic":"[aɪˈdiə]","meaning":"想法；主意；概念","definition":"a thought, plan, or suggestion","collocations":["have an idea","a good idea","share ideas"],"example":"She had a great idea for the project.","exampleZh":"她對這個專案有個好主意。","synonyms":["thought","notion"],"level":1,"theme":"人事與職涯"},{"word":"ideal","pos":"adj. / n.","phonetic":"[aɪˈdiəl]","meaning":"理想的；理想","definition":"most suitable; a perfect example of something","collocations":["ideal solution","ideal for","an ideal world"],"example":"This job is ideal for a recent graduate.","exampleZh":"這份工作非常適合應屆畢業生。","synonyms":["perfect","best"],"level":3,"theme":"日常與一般"},{"word":"identification","pos":"n.","phonetic":"[aɪˌdɛntəfəˈkeʃən]","meaning":"身分證明；識別","definition":"an official document that proves who you are, or the act of recognizing something","collocations":["photo identification","identification card","proof of identification"],"example":"Please present photo identification when picking up your tickets.","exampleZh":"領取票券時請出示附照片的身分證件。","synonyms":["ID"],"level":4,"theme":"辦公室與行政"},{"word":"identify","pos":"v.","phonetic":"[aɪˈdɛntəˌfaɪ]","meaning":"識別；確認身份","definition":"to recognize or establish who or what someone or something is","collocations":["identify a problem","identify oneself","identify with"],"example":"Police asked him to identify the suspect.","exampleZh":"警方要求他指認嫌犯。","synonyms":["recognize","distinguish"],"level":4,"theme":"溝通與語言"},{"word":"identity","pos":"n.","phonetic":"[aɪˈdɛntəti]","meaning":"身份；特性","definition":"who a person is, or the characteristics that define someone","collocations":["national identity","prove one's identity","identity card"],"example":"He had to show ID to prove his identity.","exampleZh":"他必須出示證件證明身份。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"if","pos":"conj.","phonetic":"[ɪf]","meaning":"如果；假如","definition":"on the condition that; supposing that","collocations":["if possible","even if","as if"],"example":"If it rains, we will stay home.","exampleZh":"如果下雨，我們就待在家裡。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"ignore","pos":"v.","phonetic":"[ɪgˈnɔr]","meaning":"忽視；不理睬","definition":"to pay no attention to something or someone","collocations":["ignore advice","ignore a warning","ignore the rules"],"example":"He ignored the warning sign.","exampleZh":"他忽視了警告標誌。","synonyms":["overlook","disregard"],"level":2,"theme":"日常與一般"},{"word":"ill","pos":"adj.","phonetic":"[ɪl]","meaning":"生病的","definition":"not in good health; sick","collocations":["fall ill","seriously ill","feel ill"],"example":"She felt ill after eating the fish.","exampleZh":"她吃了魚之後覺得不舒服。","synonyms":["sick","unwell"],"level":1,"theme":"醫療與保險"},{"word":"illegal","pos":"adj.","phonetic":"[ɪˈligl̩]","meaning":"非法的","definition":"not allowed by law","collocations":["illegal parking","illegal drugs","illegal immigrant"],"example":"It is illegal to drive without a license.","exampleZh":"無照駕駛是違法的。","synonyms":["unlawful"],"level":3,"theme":"合約與法律"},{"word":"illness","pos":"n.","phonetic":"[ˈɪlnɪs]","meaning":"疾病","definition":"a disease or period of poor health","collocations":["serious illness","recover from illness","mental illness"],"example":"He missed school due to illness.","exampleZh":"他因生病而沒去上學。","synonyms":["sickness","disease"],"level":2,"theme":"醫療與保險"},{"word":"illustrate","pos":"v.","phonetic":"[ˈɪləˌstret]","meaning":"說明；圖解","definition":"to explain or make clear by using examples, pictures, or diagrams","collocations":["illustrate a point","illustrate a book","clearly illustrate"],"example":"The teacher used a diagram to illustrate the process.","exampleZh":"老師用圖表來說明這個過程。","synonyms":["demonstrate","depict"],"level":4,"theme":"人事與職涯"},{"word":"illustration","pos":"n.","phonetic":"[ˌɪləˈstreʃən]","meaning":"插圖；例證","definition":"a picture in a book, or an example that makes something clear","collocations":["colorful illustrations","a clear illustration","book illustrations"],"example":"The book is full of beautiful illustrations.","exampleZh":"這本書裡滿是精美的插圖。","synonyms":["picture","example"],"level":4,"theme":"媒體與活動"},{"word":"image","pos":"n.","phonetic":"[ˈɪmɪdʒ]","meaning":"影像；形象","definition":"a picture or representation of something; the impression people have of someone","collocations":["public image","mirror image","a clear image"],"example":"The company wants to improve its public image.","exampleZh":"這家公司想改善其公眾形象。","synonyms":["picture","impression"],"level":3,"theme":"科技與通訊"},{"word":"imagine","pos":"v.","phonetic":"[ɪˈmædʒɪn]","meaning":"想像","definition":"to form a picture or idea of something in the mind","collocations":["imagine a scene","can't imagine","just imagine"],"example":"Try to imagine life without electricity.","exampleZh":"試著想像沒有電的生活。","synonyms":["picture","envision"],"level":2,"theme":"人事與職涯"},{"word":"immediate","pos":"adj.","phonetic":"[ɪˈmidiɪt]","meaning":"立即的","definition":"happening or done right away","collocations":["immediate action","immediate response","in the immediate future"],"example":"The situation requires immediate attention.","exampleZh":"這個情況需要立即處理。","synonyms":["instant","prompt"],"level":4,"theme":"日常與一般"},{"word":"immediately","pos":"adv.","phonetic":"[ɪˈmidɪɪtlɪ]","meaning":"立即；馬上","definition":"without any delay","collocations":["respond immediately","effective immediately","report immediately"],"example":"Please report any safety hazards to your supervisor immediately.","exampleZh":"發現任何安全隱患，請立即向主管回報。","synonyms":["instantly","at once"],"level":2,"theme":"辦公室與行政"},{"word":"immigration","pos":"n.","phonetic":"[ˌɪməˈgreʃən]","meaning":"移民；入境審查","definition":"the process of coming to live in another country, or the airport control area","collocations":["immigration office","go through immigration","immigration policy"],"example":"Have your passport ready when you go through immigration.","exampleZh":"通過入境審查時，請備妥護照。","synonyms":[],"level":4,"theme":"旅遊與交通"},{"word":"impact","pos":"n. / v.","phonetic":"[ˈɪmpækt]","meaning":"衝擊；影響","definition":"a strong effect or influence on something","collocations":["have an impact on","environmental impact","make an impact"],"example":"The new policy will have a big impact on farmers.","exampleZh":"這項新政策將對農民造成重大影響。","synonyms":["effect","influence"],"level":4,"theme":"日常與一般"},{"word":"impatient","pos":"adj.","phonetic":"[ɪmˈpeʃənt]","meaning":"不耐煩的","definition":"not willing to wait calmly or tolerate delay","collocations":["get impatient","impatient with","grow impatient"],"example":"He became impatient waiting in line.","exampleZh":"他排隊等候時變得不耐煩。","synonyms":["restless"],"level":3,"theme":"日常與一般"},{"word":"implement","pos":"v. / n.","phonetic":"[ˈɪmpləˌmɛnt]","meaning":"實施；工具","definition":"to put a plan into action, or a tool used for a task","collocations":["implement a policy","farm implements"],"example":"The school will implement the new rules next semester.","exampleZh":"學校下學期將實施新規定。","synonyms":["execute","carry out"],"level":5,"theme":"人事與職涯"},{"word":"implementation","pos":"n.","phonetic":"[ˌɪmpləmɛnˈteʃən]","meaning":"實施；執行","definition":"the act of putting a plan or system into action","collocations":["implementation plan","successful implementation","implementation phase"],"example":"The implementation of the new payroll system begins next month.","exampleZh":"新的薪資系統將於下個月開始上線實施。","synonyms":["execution"],"level":5,"theme":"企業經營"},{"word":"imply","pos":"v.","phonetic":"[ɪmˈplaɪ]","meaning":"暗示；意味著","definition":"to suggest something without saying it directly","collocations":["imply that","strongly imply"],"example":"The report implies that demand will keep rising next year.","exampleZh":"這份報告暗示明年需求將持續上升。","synonyms":["suggest","indicate"],"level":4,"theme":"溝通與語言"},{"word":"import","pos":"v./n.","phonetic":"[ɪmˈport]","meaning":"進口；輸入；進口品","definition":"to bring goods into a country from abroad","collocations":["import goods","import duties","imported products"],"example":"The store imports olive oil directly from small farms in Italy.","exampleZh":"這家店直接從義大利小農場進口橄欖油。","synonyms":[],"level":3,"theme":"生產與物流"},{"word":"importance","pos":"n.","phonetic":"[ɪmˈpɔrtns̩]","meaning":"重要性","definition":"the state or quality of being important","collocations":["of great importance","stress the importance","realize the importance"],"example":"Teachers stress the importance of reading.","exampleZh":"老師們強調閱讀的重要性。","synonyms":["significance"],"level":3,"theme":"日常與一般"},{"word":"important","pos":"adj.","phonetic":"[ɪmˈpɔrtnt]","meaning":"重要的","definition":"of great value, significance, or effect","collocations":["important decision","important role","important information"],"example":"Education is important for the future.","exampleZh":"教育對未來很重要。","synonyms":["significant","essential"],"level":1,"theme":"日常與一般"},{"word":"impose","pos":"v.","phonetic":"[ɪmˈpoz]","meaning":"強加；施加","definition":"to force a rule, tax, or punishment to be accepted","collocations":["impose a fine","impose rules","impose a tax"],"example":"The government imposed a new tax.","exampleZh":"政府課徵了一項新稅。","synonyms":["enforce"],"level":5,"theme":"合約與法律"},{"word":"impress","pos":"v.","phonetic":"[ɪmˈprɛs]","meaning":"使印象深刻","definition":"to make someone feel admiration or respect","collocations":["impress the judges","try to impress","easily impressed"],"example":"She impressed everyone with her speech.","exampleZh":"她的演講讓每個人都印象深刻。","synonyms":["amaze"],"level":3,"theme":"日常與一般"},{"word":"impression","pos":"n.","phonetic":"[ɪmˈprɛʃən]","meaning":"印象","definition":"an idea, feeling, or opinion about something formed without careful thought","collocations":["first impression","make an impression","under the impression"],"example":"He made a good first impression at the interview.","exampleZh":"他在面試時給人留下良好的第一印象。","synonyms":["feeling"],"level":3,"theme":"日常與一般"},{"word":"impressive","pos":"adj.","phonetic":"[ɪmˈprɛsɪv]","meaning":"令人印象深刻的","definition":"deserving admiration because of size, quality, or skill","collocations":["impressive performance","impressive results","truly impressive"],"example":"The building has an impressive design.","exampleZh":"這棟建築有著令人印象深刻的設計。","synonyms":["remarkable"],"level":3,"theme":"日常與一般"},{"word":"improve","pos":"v.","phonetic":"[ɪmˈpruv]","meaning":"改善；進步","definition":"to make or become better","collocations":["improve skills","improve health","improve gradually"],"example":"Her English has improved a lot.","exampleZh":"她的英文進步很多。","synonyms":["enhance","better"],"level":2,"theme":"日常與一般"},{"word":"improvement","pos":"n.","phonetic":"[ɪmˈpruvmənt]","meaning":"改善；進步","definition":"the process of improving something, or the result of it","collocations":["room for improvement","make improvements","show improvement"],"example":"There has been a great improvement in his grades.","exampleZh":"他的成績有很大的進步。","synonyms":["progress"],"level":3,"theme":"人事與職涯"},{"word":"in-house","pos":"adj./adv.","phonetic":"[ˈɪnˈhaʊs]","meaning":"內部的；公司自營的","definition":"done within a company rather than by outside workers","collocations":["in-house training","in-house team","develop in-house"],"example":"All design work is done by our in-house creative team.","exampleZh":"所有設計工作都由我們公司內部的創意團隊完成。","synonyms":["internal"],"level":5,"theme":"企業經營"},{"word":"inaccurate","pos":"adj.","phonetic":"[ɪnˈækjərɪt]","meaning":"不準確的；有誤的","definition":"not correct or exact","collocations":["inaccurate information","inaccurate data","inaccurate figures"],"example":"The invoice was returned because it contained inaccurate figures.","exampleZh":"由於數字有誤，請款單被退回。","synonyms":["incorrect","wrong"],"level":4,"theme":"辦公室與行政"},{"word":"inadequate","pos":"adj.","phonetic":"[ɪnˈædəkwɪt]","meaning":"不足的；不適當的","definition":"not enough or not good enough for a purpose","collocations":["inadequate funding","inadequate supply","inadequate training"],"example":"The project fell behind schedule due to inadequate staffing.","exampleZh":"由於人力不足，專案進度落後。","synonyms":["insufficient"],"level":5,"theme":"企業經營"},{"word":"incentive","pos":"n.","phonetic":"[ɪnˈsɛntɪv]","meaning":"誘因；獎勵","definition":"something that encourages a person to do something","collocations":["a strong incentive","financial incentive"],"example":"The company offers incentives to boost sales performance.","exampleZh":"公司提供獎勵以提升銷售業績。","synonyms":["motivation","reward"],"level":5,"theme":"財務與會計"},{"word":"incident","pos":"n.","phonetic":"[ˈɪnsədənt]","meaning":"事件；事故","definition":"an event or occurrence, especially one that is unpleasant or unusual","collocations":["a strange incident","report an incident","an isolated incident"],"example":"The police were called to investigate the incident.","exampleZh":"警方被叫去調查這起事件。","synonyms":["event","occurrence"],"level":4,"theme":"日常與一般"},{"word":"include","pos":"v.","phonetic":"[ɪnˈklud]","meaning":"包括；包含","definition":"to have something as a part","collocations":["include tax","include breakfast","prices include"],"example":"The registration fee includes lunch and workshop materials.","exampleZh":"報名費包含午餐及工作坊教材。","synonyms":["contain","cover"],"level":1,"theme":"日常與一般"},{"word":"including","pos":"prep.","phonetic":"[ɪnˈkludɪŋ]","meaning":"包括；包含","definition":"used to show that something is part of a group being mentioned","collocations":["including tax","including but not limited to"],"example":"The package costs ninety dollars, including shipping and tax.","exampleZh":"此套組售價九十美元，含運費及稅金。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"inclusive","pos":"adj.","phonetic":"[ɪnˈklusɪv]","meaning":"包容的；包含在內的","definition":"including everyone or everything, not leaving anyone out","collocations":["an inclusive society","all-inclusive package"],"example":"The school promotes an inclusive environment for all students.","exampleZh":"這所學校推廣讓所有學生都能融入的環境。","synonyms":["comprehensive","all-embracing"],"level":5,"theme":"日常與一般"},{"word":"income","pos":"n.","phonetic":"[ˈɪnˌkʌm]","meaning":"收入","definition":"money that a person or organization receives regularly","collocations":["monthly income","low income","annual income"],"example":"His income has increased this year.","exampleZh":"他今年的收入增加了。","synonyms":["earnings"],"level":3,"theme":"財務與會計"},{"word":"incoming","pos":"adj.","phonetic":"[ˈɪnˌkʌmɪŋ]","meaning":"進來的；新任的","definition":"arriving or coming in, or recently elected or appointed","collocations":["incoming calls","incoming mail","incoming president"],"example":"The receptionist directs all incoming calls to the right department.","exampleZh":"總機會將所有來電轉接到正確的部門。","synonyms":[],"level":4,"theme":"辦公室與行政"},{"word":"incomplete","pos":"adj.","phonetic":"[ˌɪnkəmˈplit]","meaning":"不完整的；未完成的","definition":"not finished or missing some parts","collocations":["incomplete application","incomplete form","incomplete information"],"example":"Incomplete applications will not be considered for the position.","exampleZh":"資料不完整的申請將不予考慮。","synonyms":["unfinished","partial"],"level":3,"theme":"辦公室與行政"},{"word":"inconvenience","pos":"n./v.","phonetic":"[ˌɪnkənˈvinjəns]","meaning":"不便；麻煩；造成不便","definition":"a state of difficulty or trouble, or to cause someone trouble","collocations":["apologize for the inconvenience","cause inconvenience"],"example":"We apologize for any inconvenience caused by the elevator maintenance.","exampleZh":"電梯保養造成任何不便，敬請見諒。","synonyms":["trouble","bother"],"level":4,"theme":"溝通與語言"},{"word":"inconvenient","pos":"adj.","phonetic":"[ˌɪnkənˈvinjənt]","meaning":"不方便的","definition":"causing difficulty or trouble","collocations":["inconvenient time","inconvenient location"],"example":"If this time is inconvenient, we can reschedule the meeting.","exampleZh":"如果這個時間不方便，我們可以改約會議時間。","synonyms":["awkward"],"level":4,"theme":"日常與一般"},{"word":"incorporate","pos":"v.","phonetic":"[ɪnˈkɔrpəˌret]","meaning":"納入；合併","definition":"to include something as part of a whole","collocations":["incorporate ideas","incorporate feedback"],"example":"The designer incorporated traditional patterns into the new dress.","exampleZh":"設計師把傳統圖案融入了這件新洋裝。","synonyms":["integrate","include"],"level":6,"theme":"日常與一般"},{"word":"incorrect","pos":"adj.","phonetic":"[ˌɪnkəˈrɛkt]","meaning":"不正確的；錯誤的","definition":"not right or true","collocations":["incorrect address","incorrect password","incorrect amount"],"example":"The package was delayed because of an incorrect shipping address.","exampleZh":"由於寄送地址錯誤，包裹延遲送達。","synonyms":["wrong","inaccurate"],"level":3,"theme":"日常與一般"},{"word":"increase","pos":"v. / n.","phonetic":"[ɪnˈkris]","meaning":"增加","definition":"to become or make greater in size, amount, or degree","collocations":["increase in price","sharp increase","increase steadily"],"example":"Prices increased sharply last month.","exampleZh":"上個月物價大幅上漲。","synonyms":["rise","grow"],"level":2,"theme":"財務與會計"},{"word":"increasingly","pos":"adv.","phonetic":"[ɪnˈkrisɪŋlɪ]","meaning":"越來越；日益","definition":"more and more over time","collocations":["increasingly popular","increasingly important","increasingly difficult"],"example":"Online meetings have become increasingly common since the pandemic.","exampleZh":"疫情以來，線上會議變得越來越普遍。","synonyms":["progressively"],"level":4,"theme":"日常與一般"},{"word":"incur","pos":"v.","phonetic":"[ɪnˈkɜr]","meaning":"招致；蒙受","definition":"to experience something unpleasant, such as a cost or loss, as a result of one's actions","collocations":["incur a loss","incur debt","incur costs"],"example":"Late payments will incur an extra fee.","exampleZh":"逾期付款將產生額外費用。","synonyms":["suffer","sustain"],"level":6,"theme":"財務與會計"},{"word":"indeed","pos":"adv.","phonetic":"[ɪnˈdid]","meaning":"的確；確實","definition":"used to emphasize a statement or answer","collocations":["yes, indeed","indeed true","very good indeed"],"example":"It was indeed a difficult decision.","exampleZh":"這的確是個困難的決定。","synonyms":["truly","really"],"level":3,"theme":"日常與一般"},{"word":"independent","pos":"adj.","phonetic":"[ˌɪndɪˈpɛndənt]","meaning":"獨立的；自主的","definition":"not controlled or helped by others","collocations":["independent audit","independent contractor","independent research"],"example":"An independent auditor reviews the accounts every year.","exampleZh":"每年都由獨立稽核員審查帳目。","synonyms":["autonomous","self-reliant"],"level":3,"theme":"企業經營"},{"word":"independently","pos":"adv.","phonetic":"[ˌɪndɪˈpɛndəntlɪ]","meaning":"獨立地；自主地","definition":"without help or control from others","collocations":["work independently","operate independently"],"example":"The ideal candidate can work independently with minimal supervision.","exampleZh":"理想的人選能在最少監督下獨立作業。","synonyms":["autonomously"],"level":4,"theme":"人事與職涯"},{"word":"index","pos":"n.","phonetic":"[ˈɪndɛks]","meaning":"索引；指數","definition":"an alphabetical list of names or topics; a measure of change in something","collocations":["stock index","index finger","an index of prices"],"example":"You can find the topic quickly by checking the index.","exampleZh":"你可以查看索引來快速找到這個主題。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"indicate","pos":"v.","phonetic":"[ˈɪndəˌket]","meaning":"指出；顯示","definition":"to point out or show something clearly","collocations":["indicate a direction","research indicates","clearly indicate"],"example":"Studies indicate that exercise improves health.","exampleZh":"研究顯示運動能改善健康。","synonyms":["show","suggest"],"level":4,"theme":"溝通與語言"},{"word":"indication","pos":"n.","phonetic":"[ˌɪndəˈkeʃən]","meaning":"跡象；指示；表明","definition":"a sign that shows something exists or is likely to happen","collocations":["clear indication","give an indication","early indication"],"example":"Early sales figures give a good indication of the product's popularity.","exampleZh":"初期銷售數字清楚顯示了這項產品的受歡迎程度。","synonyms":["sign","signal"],"level":5,"theme":"企業經營"},{"word":"indicator","pos":"n.","phonetic":"[ˈɪndəˌketɚ]","meaning":"指標；指示器","definition":"something that shows the condition or level of something","collocations":["economic indicator","key performance indicator","leading indicator"],"example":"Customer retention is a key indicator of service quality.","exampleZh":"顧客留存率是服務品質的重要指標。","synonyms":["measure","index"],"level":5,"theme":"企業經營"},{"word":"individual","pos":"n. / adj.","phonetic":"[ˌɪndəˈvɪdʒuəl]","meaning":"個人；個別的","definition":"a single person; considered separately rather than as part of a group","collocations":["an individual right","individual needs","each individual"],"example":"Each individual has unique talents.","exampleZh":"每個人都有獨特的才能。","synonyms":["person"],"level":3,"theme":"日常與一般"},{"word":"individually","pos":"adv.","phonetic":"[ˌɪndəˈvɪdʒʊəlɪ]","meaning":"個別地；單獨地","definition":"separately, one by one","collocations":["individually wrapped","individually packaged","meet individually"],"example":"Each pastry is individually wrapped to stay fresh.","exampleZh":"每個糕點都個別包裝以保持新鮮。","synonyms":["separately"],"level":4,"theme":"生產與物流"},{"word":"indoor","pos":"adj.","phonetic":"[ˈɪnˌdɔr]","meaning":"室內的","definition":"located, used, or done inside a building","collocations":["indoor swimming pool","indoor activities","indoor stadium"],"example":"We played basketball at the indoor stadium.","exampleZh":"我們在室內體育館打籃球。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"indoors","pos":"adv.","phonetic":"[ˈɪnˈdorz]","meaning":"在室內","definition":"inside a building","collocations":["move indoors","stay indoors"],"example":"Due to the rain, the reception will be moved indoors.","exampleZh":"由於下雨，接待會將改在室內舉行。","synonyms":["inside"],"level":2,"theme":"日常與一般"},{"word":"industrial","pos":"adj.","phonetic":"[ɪnˈdʌstrɪəl]","meaning":"工業的","definition":"relating to industry or manufacturing","collocations":["industrial area","industrial waste","industrial revolution"],"example":"The city has many industrial zones.","exampleZh":"這座城市有許多工業區。","synonyms":["manufacturing"],"level":3,"theme":"人事與職涯"},{"word":"industry","pos":"n.","phonetic":"[ˈɪndəstri]","meaning":"產業；工業","definition":"economic activity concerned with producing goods or services","collocations":["heavy industry","the tourism industry","a growing industry"],"example":"Taiwan's tech industry is booming.","exampleZh":"台灣的科技產業正蓬勃發展。","synonyms":["manufacturing"],"level":3,"theme":"人事與職涯"},{"word":"inevitable","pos":"adj.","phonetic":"[ɪnˈɛvɪtəbəl]","meaning":"不可避免的","definition":"certain to happen; unavoidable","collocations":["an inevitable outcome","seem inevitable"],"example":"Change is inevitable as technology keeps advancing.","exampleZh":"隨著科技不斷進步，改變是不可避免的。","synonyms":["unavoidable","certain"],"level":5,"theme":"日常與一般"},{"word":"inexpensive","pos":"adj.","phonetic":"[ˌɪnɪkˈspɛnsɪv]","meaning":"便宜的；不貴的","definition":"low in price but usually of reasonable quality","collocations":["inexpensive option","relatively inexpensive"],"example":"The bistro offers inexpensive lunch specials on weekdays.","exampleZh":"這家小餐館平日提供價格實惠的午間特餐。","synonyms":["affordable","cheap"],"level":3,"theme":"購物與消費"},{"word":"infer","pos":"v.","phonetic":"[ɪnˈfɝ]","meaning":"推論；推斷","definition":"to reach a conclusion based on evidence and reasoning","collocations":["infer from","can be inferred"],"example":"What can be inferred about the company from the announcement?","exampleZh":"從這則公告可以推斷出這家公司什麼訊息？","synonyms":["deduce","conclude"],"level":5,"theme":"溝通與語言"},{"word":"inflation","pos":"n.","phonetic":"[ɪnˈfleʃən]","meaning":"通貨膨脹","definition":"a general rise in prices and fall in the value of money","collocations":["rising inflation","control inflation"],"example":"High inflation has made daily goods more expensive.","exampleZh":"高通貨膨脹使日常用品變得更貴。","synonyms":["price rise"],"level":4,"theme":"財務與會計"},{"word":"influence","pos":"n. / v.","phonetic":"[ˈɪnfluəns]","meaning":"影響","definition":"the power to affect someone's or something's behavior or development","collocations":["have influence on","under the influence","a bad influence"],"example":"Parents have a strong influence on children.","exampleZh":"父母對孩子有很大的影響。","synonyms":["effect","impact"],"level":3,"theme":"日常與一般"},{"word":"influential","pos":"adj.","phonetic":"[ˌɪnfluˈɛnʃəl]","meaning":"有影響力的","definition":"having great influence on someone or something","collocations":["an influential leader","highly influential"],"example":"She is one of the most influential scientists of her time.","exampleZh":"她是當代最具影響力的科學家之一。","synonyms":["powerful","significant"],"level":5,"theme":"日常與一般"},{"word":"inform","pos":"v.","phonetic":"[ɪnˈfɔrm]","meaning":"通知","definition":"to give information to someone","collocations":["inform someone of","keep informed","inform the police"],"example":"Please inform us of any changes.","exampleZh":"有任何變動請通知我們。","synonyms":["notify"],"level":4,"theme":"溝通與語言"},{"word":"informal","pos":"adj.","phonetic":"[ɪnˈfɔrml]","meaning":"非正式的；輕鬆的","definition":"relaxed and casual rather than official","collocations":["informal meeting","informal dress","informal discussion"],"example":"The team holds an informal meeting over coffee every Monday morning.","exampleZh":"團隊每週一早上邊喝咖啡邊舉行非正式會議。","synonyms":["casual"],"level":3,"theme":"辦公室與行政"},{"word":"information","pos":"n.","phonetic":"[ˌɪnfɚˈmeʃən]","meaning":"資訊；消息","definition":"facts or details about something","collocations":["gather information","useful information","personal information"],"example":"The website provides useful information.","exampleZh":"這個網站提供了有用的資訊。","synonyms":["data"],"level":1,"theme":"科技與通訊"},{"word":"informative","pos":"adj.","phonetic":"[ɪnˈfɔrmətɪv]","meaning":"資訊豐富的；有教育意義的","definition":"providing a lot of useful information","collocations":["informative session","highly informative","informative brochure"],"example":"Attendees found the workshop both informative and engaging.","exampleZh":"與會者認為這場工作坊既充實又有趣。","synonyms":["educational","instructive"],"level":4,"theme":"媒體與活動"},{"word":"infrastructure","pos":"n.","phonetic":"[ˈɪnfrəˌstrʌktʃɚ]","meaning":"基礎建設；基礎架構","definition":"the basic systems such as roads, power, and communication that a country or organization needs","collocations":["transportation infrastructure","IT infrastructure","invest in infrastructure"],"example":"The government announced a major investment in transportation infrastructure.","exampleZh":"政府宣布對交通基礎建設進行重大投資。","synonyms":[],"level":5,"theme":"企業經營"},{"word":"ingredient","pos":"n.","phonetic":"[ɪnˈgridiənt]","meaning":"原料；成分","definition":"a food item that is combined with others to make a dish","collocations":["main ingredient","mix ingredients","fresh ingredients"],"example":"Flour is the main ingredient of bread.","exampleZh":"麵粉是麵包的主要原料。","synonyms":["component"],"level":4,"theme":"餐飲與住宿"},{"word":"initial","pos":"adj. / n.","phonetic":"[ɪˈnɪʃəl]","meaning":"最初的；首字母","definition":"happening at the beginning; the first letter of a name","collocations":["initial stage","initial reaction","initial cost"],"example":"His initial reaction was surprise.","exampleZh":"他最初的反應是驚訝。","synonyms":["first","original"],"level":4,"theme":"日常與一般"},{"word":"initially","pos":"adv.","phonetic":"[ɪˈnɪʃəlɪ]","meaning":"起初；最初","definition":"at the beginning","collocations":["initially planned","initially expected"],"example":"The project was initially budgeted at two million dollars.","exampleZh":"這項專案最初編列的預算為兩百萬美元。","synonyms":["originally","at first"],"level":4,"theme":"日常與一般"},{"word":"initiate","pos":"v.","phonetic":"[ɪˈnɪʃiˌet]","meaning":"發起；創始","definition":"to cause a process or action to begin","collocations":["initiate a project","initiate talks"],"example":"The government initiated a new recycling program.","exampleZh":"政府發起了一項新的回收計畫。","synonyms":["begin","launch"],"level":6,"theme":"日常與一般"},{"word":"initiative","pos":"n.","phonetic":"[ɪˈnɪʃətɪv]","meaning":"主動性；倡議","definition":"the ability to act independently, or a new plan to solve a problem","collocations":["take the initiative","a new initiative"],"example":"She showed great initiative by starting the recycling club.","exampleZh":"她發起回收社團，展現了極大的主動精神。","synonyms":["enterprise","proactivity"],"level":5,"theme":"人事與職涯"},{"word":"injure","pos":"v.","phonetic":"[ˈɪndʒɚ]","meaning":"傷害","definition":"to cause physical harm to a person or animal","collocations":["injure a leg","seriously injured","injure oneself"],"example":"He injured his knee during the game.","exampleZh":"他在比賽中傷了膝蓋。","synonyms":["hurt","wound"],"level":3,"theme":"醫療與保險"},{"word":"injury","pos":"n.","phonetic":"[ˈɪndʒəri]","meaning":"受傷；傷害","definition":"physical harm or damage done to the body","collocations":["suffer an injury","sports injury","minor injury"],"example":"She recovered quickly from her injury.","exampleZh":"她的傷勢很快就痊癒了。","synonyms":["wound","harm"],"level":3,"theme":"醫療與保險"},{"word":"innovation","pos":"n.","phonetic":"[ˌɪnəˈveʃən]","meaning":"創新；新方法","definition":"a new idea, method, or product","collocations":["technological innovation","drive innovation"],"example":"The smartphone was a major innovation in communication.","exampleZh":"智慧型手機是通訊上的一大創新。","synonyms":["invention","breakthrough"],"level":4,"theme":"科技與通訊"},{"word":"innovative","pos":"adj.","phonetic":"[ˈɪnəˌvetɪv]","meaning":"創新的；新穎的","definition":"using new ideas or methods","collocations":["innovative solutions","innovative design","innovative approach"],"example":"The firm won an award for its innovative packaging design.","exampleZh":"該公司以創新的包裝設計獲獎。","synonyms":["creative","original"],"level":5,"theme":"企業經營"},{"word":"input","pos":"n. / v.","phonetic":"[ˈɪnˌpʊt]","meaning":"輸入；投入","definition":"information or data put into a computer or system","collocations":["input data","provide input","input device"],"example":"Please input your password to continue.","exampleZh":"請輸入你的密碼以繼續。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"inquire","pos":"v.","phonetic":"[ɪnˈkwaɪr]","meaning":"詢問；查詢","definition":"to ask for information from someone","collocations":["inquire about","inquire into","inquire politely"],"example":"She called the office to inquire about the job opening.","exampleZh":"她打電話到辦公室詢問職缺的事。","synonyms":["ask","question"],"level":4,"theme":"溝通與語言"},{"word":"inquiry","pos":"n.","phonetic":"[ɪnˈkwaɪrɪ]","meaning":"詢問；調查","definition":"a question asking for information, or an official investigation","collocations":["make an inquiry","customer inquiry","respond to inquiries"],"example":"Our support team responds to customer inquiries within one business day.","exampleZh":"我們的客服團隊會在一個工作天內回覆顧客詢問。","synonyms":["question","query"],"level":4,"theme":"溝通與語言"},{"word":"insert","pos":"v.","phonetic":"[ɪnˈsɝt]","meaning":"插入；嵌入","definition":"to place or fit something into something else","collocations":["insert a coin","insert a card","insert a comment"],"example":"Insert the key into the lock and turn it.","exampleZh":"把鑰匙插入鎖裡然後轉動。","synonyms":["put in"],"level":4,"theme":"日常與一般"},{"word":"inside","pos":"prep. / adv. / n.","phonetic":"[ɪnˈsaɪd]","meaning":"在...裡面；內部","definition":"within a place, container, or space","collocations":["inside out","go inside","inside the box"],"example":"Let's go inside; it's cold outside.","exampleZh":"我們進去吧，外面很冷。","synonyms":["within"],"level":1,"theme":"日常與一般"},{"word":"insight","pos":"n.","phonetic":"[ˈɪnˌsaɪt]","meaning":"洞察力；深入了解","definition":"a deep and clear understanding of something","collocations":["gain insight into","valuable insights","provide insight"],"example":"The survey provided valuable insights into customer preferences.","exampleZh":"這份調查提供了對顧客偏好的寶貴洞察。","synonyms":["understanding","perception"],"level":5,"theme":"行銷與銷售"},{"word":"insist","pos":"v.","phonetic":"[ɪnˈsɪst]","meaning":"堅持","definition":"to demand something firmly, refusing to accept a refusal","collocations":["insist on","insist that","insist firmly"],"example":"She insisted on paying the bill.","exampleZh":"她堅持要付帳。","synonyms":["demand"],"level":4,"theme":"溝通與語言"},{"word":"inspect","pos":"v.","phonetic":"[ɪnˈspɛkt]","meaning":"檢查；視察","definition":"to look at someone or something closely to assess condition or quality","collocations":["inspect the building","carefully inspect","inspect goods"],"example":"The officer inspected the car before approving it.","exampleZh":"官員在核准前仔細檢查了那輛車。","synonyms":["examine","check"],"level":4,"theme":"人事與職涯"},{"word":"inspection","pos":"n.","phonetic":"[ɪnˈspɛkʃən]","meaning":"檢查；檢驗；視察","definition":"a careful official examination of something","collocations":["safety inspection","pass inspection","annual inspection"],"example":"The restaurant passed its health inspection with a perfect score.","exampleZh":"這家餐廳以滿分通過衛生檢查。","synonyms":["examination","check"],"level":4,"theme":"生產與物流"},{"word":"inspector","pos":"n.","phonetic":"[ɪnˈspɛktɚ]","meaning":"檢查員；稽查員","definition":"a person whose job is to check that things are correct or legal","collocations":["safety inspector","building inspector","quality inspector"],"example":"The building inspector will visit the construction site on Thursday.","exampleZh":"建築檢查員將於週四視察工地。","synonyms":["examiner"],"level":4,"theme":"生產與物流"},{"word":"inspire","pos":"v.","phonetic":"[ɪnˈspaɪr]","meaning":"激勵；啟發","definition":"to fill someone with the desire or ability to do something","collocations":["inspire confidence","inspire others","feel inspired"],"example":"The teacher inspired her students to dream big.","exampleZh":"這位老師激勵學生們懷抱遠大的夢想。","synonyms":["motivate","encourage"],"level":4,"theme":"日常與一般"},{"word":"install","pos":"v.","phonetic":"[ɪnˈstɔl]","meaning":"安裝；設置","definition":"to put equipment or software in place so it is ready to use","collocations":["install software","install equipment","newly installed"],"example":"A technician will install the new printers on Friday morning.","exampleZh":"技術人員將於週五上午安裝新印表機。","synonyms":["set up"],"level":3,"theme":"科技與通訊"},{"word":"installation","pos":"n.","phonetic":"[ˌɪnstəˈleʃən]","meaning":"安裝；裝置；設施","definition":"the act of putting equipment in place, or the equipment itself","collocations":["free installation","installation fee","installation process"],"example":"The price includes free installation and a one-year warranty.","exampleZh":"價格包含免費安裝及一年保固。","synonyms":["setup"],"level":4,"theme":"科技與通訊"},{"word":"installment","pos":"n.","phonetic":"[ɪnˈstɔlmənt]","meaning":"分期付款；（連載的）一期","definition":"one of several payments made over time, or one part of a series","collocations":["monthly installments","pay in installments","first installment"],"example":"You can pay for the furniture in twelve monthly installments.","exampleZh":"這套家具可以分十二期按月付款。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"instance","pos":"n.","phonetic":"[ˈɪnstəns]","meaning":"例子；實例","definition":"an example or single occurrence of something","collocations":["for instance","in this instance","a rare instance"],"example":"For instance, many students struggle with time management.","exampleZh":"舉例來說，許多學生都在時間管理上遇到困難。","synonyms":["example","case"],"level":4,"theme":"日常與一般"},{"word":"instant","pos":"adj. / n.","phonetic":"[ˈɪnstənt]","meaning":"立即的；瞬間","definition":"happening or done immediately; a very short moment","collocations":["instant noodles","instant coffee","an instant later"],"example":"He felt an instant connection with her.","exampleZh":"他對她感到一見如故。","synonyms":["immediate"],"level":3,"theme":"日常與一般"},{"word":"instantly","pos":"adv.","phonetic":"[ˈɪnstəntlɪ]","meaning":"立即地；即刻","definition":"immediately, without delay","collocations":["instantly recognizable","respond instantly"],"example":"Payments made online are instantly reflected in your account.","exampleZh":"線上付款會立即顯示在您的帳戶中。","synonyms":["immediately"],"level":3,"theme":"日常與一般"},{"word":"instead","pos":"adv.","phonetic":"[ɪnˈstɛd]","meaning":"取而代之；反而","definition":"as an alternative or substitute","collocations":["instead of","go instead","choose this instead"],"example":"Let's take the bus instead of driving.","exampleZh":"我們搭公車吧，不要開車了。","synonyms":["rather"],"level":2,"theme":"日常與一般"},{"word":"institute","pos":"n.","phonetic":"[ˈɪnstəˌtjut]","meaning":"機構；學院；研究所","definition":"an organization founded for a particular purpose, especially research or education","collocations":["research institute","technology institute","institute of art"],"example":"He works at a scientific research institute.","exampleZh":"他在一間科學研究機構工作。","synonyms":["organization","institution"],"level":5,"theme":"人事與職涯"},{"word":"institution","pos":"n.","phonetic":"[ˌɪnstəˈtjuʃən]","meaning":"機構；制度","definition":"a large organization such as a bank, university, or hospital","collocations":["financial institution","educational institution","public institution"],"example":"Several financial institutions are offering lower mortgage rates.","exampleZh":"多家金融機構正在提供更低的房貸利率。","synonyms":["organization"],"level":4,"theme":"企業經營"},{"word":"instruct","pos":"v.","phonetic":"[ɪnˈstrʌkt]","meaning":"指示；教導","definition":"to teach someone a skill or give them an order","collocations":["instruct students","instruct someone to do","clearly instruct"],"example":"The coach instructed the players to warm up first.","exampleZh":"教練指示球員先熱身。","synonyms":["teach","direct"],"level":4,"theme":"人事與職涯"},{"word":"instruction","pos":"n.","phonetic":"[ɪnˈstrʌkʃən]","meaning":"指示；說明；教學","definition":"information about how to do or use something","collocations":["follow the instructions","instruction manual","detailed instructions"],"example":"Follow the assembly instructions carefully to avoid damaging the parts.","exampleZh":"請仔細遵照組裝說明，以免損壞零件。","synonyms":["direction","guideline"],"level":3,"theme":"日常與一般"},{"word":"instructor","pos":"n.","phonetic":"[ɪnˈstrʌktɚ]","meaning":"教練；講師","definition":"a person who teaches a skill or subject","collocations":["fitness instructor","driving instructor","course instructor"],"example":"The fitness instructor offers beginner classes twice a week.","exampleZh":"健身教練每週開設兩次初學者課程。","synonyms":["trainer","teacher"],"level":3,"theme":"人事與職涯"},{"word":"instrument","pos":"n.","phonetic":"[ˈɪnstrəmənt]","meaning":"工具；樂器","definition":"a tool used for delicate or scientific work, or a device for making music","collocations":["play an instrument","musical instrument","precision instrument"],"example":"The violin is a beautiful instrument.","exampleZh":"小提琴是一種美妙的樂器。","synonyms":["tool","device"],"level":3,"theme":"媒體與活動"},{"word":"insufficient","pos":"adj.","phonetic":"[ˌɪnsəˈfɪʃənt]","meaning":"不足的；不夠的","definition":"not enough for a particular purpose","collocations":["insufficient funds","insufficient time","insufficient evidence"],"example":"The transaction was declined due to insufficient funds.","exampleZh":"由於餘額不足，交易遭到拒絕。","synonyms":["inadequate","lacking"],"level":5,"theme":"財務與會計"},{"word":"insurance","pos":"n.","phonetic":"[ɪnˈʃʊrəns]","meaning":"保險","definition":"a system of protection against financial loss","collocations":["health insurance","buy insurance","insurance company"],"example":"Every driver in the country must have car insurance.","exampleZh":"這個國家的每位駕駛都必須有汽車保險。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"insure","pos":"v.","phonetic":"[ɪnˈʃʊr]","meaning":"投保；為…保險","definition":"to buy insurance to protect against loss or damage","collocations":["insure a car","fully insured","insure against"],"example":"All packages are insured against loss or damage during shipping.","exampleZh":"所有包裹在運送期間都投保了遺失及損壞險。","synonyms":[],"level":4,"theme":"醫療與保險"},{"word":"integrate","pos":"v.","phonetic":"[ˈɪntəˌgret]","meaning":"整合；融入","definition":"to combine things so they work together as a whole","collocations":["integrate systems","integrate into","fully integrated"],"example":"The new software integrates smoothly with our existing accounting system.","exampleZh":"新軟體能與我們現有的會計系統順利整合。","synonyms":["combine","merge"],"level":5,"theme":"科技與通訊"},{"word":"integration","pos":"n.","phonetic":"[ˌɪntəˈgreʃən]","meaning":"整合；融合","definition":"the process of combining things into a whole","collocations":["system integration","seamless integration","data integration"],"example":"The integration of the two databases will take about a month.","exampleZh":"兩個資料庫的整合工作大約需要一個月。","synonyms":["unification"],"level":5,"theme":"科技與通訊"},{"word":"intelligence","pos":"n.","phonetic":"[ɪnˈtɛlədʒəns]","meaning":"智力；情報","definition":"the ability to learn and understand, or secret information","collocations":["artificial intelligence","market intelligence","business intelligence"],"example":"The firm uses artificial intelligence to analyze customer behavior.","exampleZh":"該公司運用人工智慧分析顧客行為。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"intelligent","pos":"adj.","phonetic":"[ɪnˈtɛlədʒənt]","meaning":"聰明的；有智慧的","definition":"having or showing a high level of mental capability","collocations":["highly intelligent","intelligent design","intelligent student"],"example":"Dolphins are known to be highly intelligent animals.","exampleZh":"海豚以高智商聞名。","synonyms":["smart","clever"],"level":3,"theme":"日常與一般"},{"word":"intend","pos":"v.","phonetic":"[ɪnˈtɛnd]","meaning":"打算；意圖","definition":"to have a plan or purpose in mind; to want to do something","collocations":["intend to do","what is intended","fully intend"],"example":"I intend to finish the project by Friday.","exampleZh":"我打算在星期五前完成這個專案。","synonyms":["plan","mean"],"level":4,"theme":"日常與一般"},{"word":"intense","pos":"adj.","phonetic":"[ɪnˈtɛns]","meaning":"強烈的；緊張的","definition":"of extreme force, degree, or strength","collocations":["intense heat","intense competition","intense emotion"],"example":"The competition between the two teams was intense.","exampleZh":"這兩隊之間的競爭非常激烈。","synonyms":["extreme","fierce"],"level":4,"theme":"日常與一般"},{"word":"intensive","pos":"adj.","phonetic":"[ɪnˈtɛnsɪv]","meaning":"密集的；集中的","definition":"involving a lot of effort or activity in a short time","collocations":["intensive training","intensive course","labor-intensive"],"example":"New hires complete an intensive two-week training program.","exampleZh":"新進人員需完成為期兩週的密集訓練課程。","synonyms":["concentrated"],"level":5,"theme":"人事與職涯"},{"word":"intent","pos":"n./adj.","phonetic":"[ɪnˈtɛnt]","meaning":"意圖；目的；專注的","definition":"a plan or purpose, or showing strong attention","collocations":["letter of intent","with the intent of","intent on"],"example":"Both parties signed a letter of intent to form a partnership.","exampleZh":"雙方簽署了建立合作關係的意向書。","synonyms":["intention","purpose"],"level":6,"theme":"合約與法律"},{"word":"intention","pos":"n.","phonetic":"[ɪnˈtɛnʃən]","meaning":"意圖；打算","definition":"something you plan to do","collocations":["have no intention of","announce one's intention","good intentions"],"example":"The CEO announced her intention to retire at the end of the year.","exampleZh":"執行長宣布她打算在年底退休。","synonyms":["aim","plan"],"level":3,"theme":"日常與一般"},{"word":"interact","pos":"v.","phonetic":"[ˌɪntɚˈækt]","meaning":"互動；交流","definition":"to communicate with or react to someone or something","collocations":["interact with customers","interact directly"],"example":"Sales staff should interact with customers in a friendly, professional manner.","exampleZh":"銷售人員應以親切專業的態度與顧客互動。","synonyms":["communicate"],"level":4,"theme":"溝通與語言"},{"word":"interaction","pos":"n.","phonetic":"[ˌɪntɚˈækʃən]","meaning":"互動；交互作用","definition":"the activity of communicating or reacting with others","collocations":["customer interaction","social interaction","face-to-face interaction"],"example":"The training focuses on improving customer interactions at the front desk.","exampleZh":"這項訓練著重於改善櫃檯的顧客互動。","synonyms":["communication"],"level":4,"theme":"溝通與語言"},{"word":"interactive","pos":"adj.","phonetic":"[ˌɪntɚˈæktɪv]","meaning":"互動的；互動式的","definition":"involving communication between people or between a person and a machine","collocations":["interactive display","interactive session","interactive map"],"example":"The museum features interactive displays that visitors can touch.","exampleZh":"博物館設有可供訪客觸摸操作的互動式展示。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"interest","pos":"n. / v.","phonetic":"[ˈɪntərɪst]","meaning":"興趣；利息；利益","definition":"a feeling of wanting to know or be involved in something; money paid for the use of money","collocations":["take interest in","interest rate","lose interest"],"example":"She has always shown a great interest in astronomy.","exampleZh":"她一直對天文學展現濃厚的興趣。","synonyms":["curiosity"],"level":2,"theme":"人事與職涯"},{"word":"interested","pos":"adj.","phonetic":"[ˈɪntərɪstɪd]","meaning":"感興趣的；有意願的","definition":"wanting to know more about something or take part in it","collocations":["interested in","interested parties","interested candidates"],"example":"Interested candidates should submit a resume by March fifteenth.","exampleZh":"有意應徵者請於三月十五日前提交履歷。","synonyms":["keen"],"level":1,"theme":"日常與一般"},{"word":"interesting","pos":"adj.","phonetic":"[ˈɪntərɪstɪŋ]","meaning":"有趣的；引人入勝的","definition":"holding your attention because it is unusual or exciting","collocations":["interesting article","interesting findings"],"example":"The report contains several interesting findings about consumer trends.","exampleZh":"這份報告包含幾項關於消費趨勢的有趣發現。","synonyms":["engaging","intriguing"],"level":1,"theme":"日常與一般"},{"word":"interfere","pos":"v.","phonetic":"[ˌɪntɚˈfɪr]","meaning":"干涉；干擾","definition":"to intervene in a situation without invitation or excuse","collocations":["interfere with","interfere in","don't interfere"],"example":"Please don't interfere in our private matters.","exampleZh":"請不要干涉我們的私人事務。","synonyms":["meddle","intervene"],"level":5,"theme":"日常與一般"},{"word":"interim","pos":"adj./n.","phonetic":"[ˈɪntərɪm]","meaning":"臨時的；過渡期間","definition":"temporary and intended to be used until something permanent exists","collocations":["interim manager","interim report","in the interim"],"example":"She will serve as interim director until a replacement is found.","exampleZh":"在找到接任人選之前，她將擔任代理主任。","synonyms":["temporary","provisional"],"level":6,"theme":"人事與職涯"},{"word":"interior","pos":"n. / adj.","phonetic":"[ɪnˈtɪriɚ]","meaning":"內部；室內的","definition":"the inner part of something, especially a building","collocations":["interior design","car interior","interior wall"],"example":"The interior of the house was recently renovated.","exampleZh":"這棟房子的內部最近重新裝修過。","synonyms":["inside"],"level":4,"theme":"房產與設施"},{"word":"intermediate","pos":"adj./n.","phonetic":"[ˌɪntɚˈmidɪɪt]","meaning":"中級的；中間的","definition":"between beginner and advanced levels","collocations":["intermediate level","intermediate course"],"example":"This language course is designed for intermediate learners.","exampleZh":"這門語言課程是為中級學習者設計的。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"intermission","pos":"n.","phonetic":"[ˌɪntɚˈmɪʃən]","meaning":"中場休息","definition":"a short break between parts of a performance","collocations":["during intermission","fifteen-minute intermission"],"example":"Refreshments will be available in the lobby during intermission.","exampleZh":"中場休息時間大廳將供應茶點。","synonyms":["interval","break"],"level":5,"theme":"媒體與活動"},{"word":"intern","pos":"n./v.","phonetic":"[ˈɪntɝn]","meaning":"實習生；實習","definition":"a student or recent graduate gaining work experience","collocations":["summer intern","hire interns","intern at a company"],"example":"The marketing department hires two interns every summer.","exampleZh":"行銷部門每年夏天都會聘用兩名實習生。","synonyms":["trainee"],"level":3,"theme":"人事與職涯"},{"word":"internal","pos":"adj.","phonetic":"[ɪnˈtɝnl̩]","meaning":"內部的；體內的","definition":"existing or occurring inside a body, organization, or country","collocations":["internal organs","internal affairs","internal conflict"],"example":"The doctor checked for any internal injuries.","exampleZh":"醫生檢查了是否有任何內傷。","synonyms":["inner","interior"],"level":4,"theme":"醫療與保險"},{"word":"international","pos":"adj.","phonetic":"[ˌɪntɚˈnæʃənl̩]","meaning":"國際的","definition":"involving more than one country","collocations":["international trade","international flight","international students"],"example":"The company does international business.","exampleZh":"這家公司從事國際貿易。","synonyms":["global"],"level":3,"theme":"合約與法律"},{"word":"internet","pos":"n.","phonetic":"[ˈɪntɚˌnɛt]","meaning":"網際網路","definition":"a global computer network providing information and communication facilities","collocations":["surf the internet","internet connection","access the internet"],"example":"Most students today do research on the internet.","exampleZh":"現今大多數學生都在網路上做研究。","synonyms":["web"],"level":2,"theme":"科技與通訊"},{"word":"internship","pos":"n.","phonetic":"[ˈɪntɝnˌʃɪp]","meaning":"實習；實習期","definition":"a period of work experience for a student or graduate","collocations":["paid internship","summer internship","complete an internship"],"example":"She completed a six-month internship at an advertising agency.","exampleZh":"她在一家廣告公司完成了六個月的實習。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"interpret","pos":"v.","phonetic":"[ɪnˈtɝprɪt]","meaning":"詮釋；口譯","definition":"to explain the meaning of something or translate speech orally","collocations":["interpret a poem","interpret data","interpret for someone"],"example":"It's not easy to interpret his strange behavior.","exampleZh":"要解讀他奇怪的行為並不容易。","synonyms":["explain","translate"],"level":5,"theme":"溝通與語言"},{"word":"interpreter","pos":"n.","phonetic":"[ɪnˈtɝprɪtɚ]","meaning":"口譯員","definition":"a person who translates spoken words from one language to another","collocations":["hire an interpreter","simultaneous interpreter"],"example":"An interpreter will be provided for the meeting with overseas clients.","exampleZh":"與海外客戶的會議將安排口譯員。","synonyms":["translator"],"level":4,"theme":"溝通與語言"},{"word":"interrupt","pos":"v.","phonetic":"[ˌɪntəˈrʌpt]","meaning":"打斷；打擾","definition":"to stop the continuous progress of an activity or a person speaking","collocations":["interrupt a conversation","sorry to interrupt","interrupt class"],"example":"Sorry to interrupt, but there's an urgent phone call for you.","exampleZh":"抱歉打擾了，有一通緊急電話找你。","synonyms":["disturb","cut in"],"level":4,"theme":"溝通與語言"},{"word":"intersection","pos":"n.","phonetic":"[ˌɪntɚˈsɛkʃən]","meaning":"十字路口；交叉點","definition":"a place where two or more roads cross","collocations":["busy intersection","at the intersection of"],"example":"The new coffee shop is at the intersection of Main and Fifth Street.","exampleZh":"新開的咖啡店位於主街與第五街的十字路口。","synonyms":["crossroads","junction"],"level":4,"theme":"旅遊與交通"},{"word":"interval","pos":"n.","phonetic":"[ˈɪntɚvl̩]","meaning":"間隔；(節目)中場休息","definition":"an intervening period of time between two events","collocations":["at regular intervals","short interval","interval between shows"],"example":"The buses arrive at ten-minute intervals.","exampleZh":"公車每隔十分鐘來一班。","synonyms":["gap","break"],"level":5,"theme":"日常與一般"},{"word":"interview","pos":"n. / v.","phonetic":"[ˈɪntɚˌvju]","meaning":"面試；訪談","definition":"a meeting at which someone is asked questions, for a job or by the media","collocations":["job interview","conduct an interview","interview candidates"],"example":"She was very nervous before her job interview.","exampleZh":"她在面試前非常緊張。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"interviewer","pos":"n.","phonetic":"[ˈɪntɚˌvjuɚ]","meaning":"面試官；採訪者","definition":"a person who asks questions in an interview","collocations":["panel of interviewers","impress the interviewer"],"example":"Arrive early and greet each interviewer with a firm handshake.","exampleZh":"請提早抵達，並以堅定的握手向每位面試官致意。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"introduce","pos":"v.","phonetic":"[ˌɪntrəˈdjus]","meaning":"介紹；引進","definition":"to present someone by name to another; to bring something into use for the first time","collocations":["introduce oneself","introduce a new policy","introduce a friend"],"example":"Let me introduce you to my colleague, Sarah.","exampleZh":"讓我把你介紹給我的同事莎拉。","synonyms":["present"],"level":2,"theme":"溝通與語言"},{"word":"introduction","pos":"n.","phonetic":"[ˌɪntrəˈdʌkʃən]","meaning":"介紹；引進；序言","definition":"the act of presenting something new, or the beginning of a book or speech","collocations":["brief introduction","letter of introduction","the introduction of"],"example":"The introduction of self-checkout machines shortened waiting times.","exampleZh":"自助結帳機的引進縮短了等候時間。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"introductory","pos":"adj.","phonetic":"[ˌɪntrəˈdʌktərɪ]","meaning":"介紹性的；入門的；初次優惠的","definition":"intended as an introduction, or offered at a special price for new customers","collocations":["introductory offer","introductory price","introductory course"],"example":"New members enjoy an introductory rate for the first three months.","exampleZh":"新會員前三個月可享優惠價格。","synonyms":["initial"],"level":5,"theme":"行銷與銷售"},{"word":"invaluable","pos":"adj.","phonetic":"[ɪnˈvæljəbl]","meaning":"無價的；極寶貴的","definition":"extremely useful and important","collocations":["invaluable experience","invaluable advice","prove invaluable"],"example":"Her fluency in three languages proved invaluable during the negotiations.","exampleZh":"她精通三種語言，在談判中發揮了無比珍貴的作用。","synonyms":["priceless","precious"],"level":6,"theme":"人事與職涯"},{"word":"invent","pos":"v.","phonetic":"[ɪnˈvɛnt]","meaning":"發明；捏造","definition":"to create or design something that has not existed before","collocations":["invent a machine","invent an excuse","who invented"],"example":"Thomas Edison invented the light bulb.","exampleZh":"湯瑪斯·愛迪生發明了電燈泡。","synonyms":["create","devise"],"level":3,"theme":"科技與通訊"},{"word":"invention","pos":"n.","phonetic":"[ɪnˈvɛnʃən]","meaning":"發明；發明物","definition":"the action of inventing something, or a device created for the first time","collocations":["a useful invention","modern invention","the invention of"],"example":"The smartphone is one of the greatest inventions of our time.","exampleZh":"智慧型手機是我們這個時代最偉大的發明之一。","synonyms":["creation","innovation"],"level":3,"theme":"科技與通訊"},{"word":"inventory","pos":"n.","phonetic":"[ˈɪnvənˌtorɪ]","meaning":"存貨；庫存；盤點","definition":"all the goods available in a store or warehouse, or a list of them","collocations":["take inventory","inventory management","excess inventory"],"example":"The store closes early on Mondays to take inventory.","exampleZh":"這家店每週一提早打烊進行盤點。","synonyms":["stock"],"level":4,"theme":"生產與物流"},{"word":"invest","pos":"v.","phonetic":"[ɪnˈvɛst]","meaning":"投資","definition":"to put money into something in order to gain a profit","collocations":["invest in stocks","invest money","invest time"],"example":"He decided to invest in the stock market.","exampleZh":"他決定投資股票市場。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"investigate","pos":"v.","phonetic":"[ɪnˈvɛstəˌget]","meaning":"調查；研究","definition":"to carry out research or an official inquiry into something","collocations":["investigate a crime","investigate the cause","thoroughly investigate"],"example":"The police are investigating the cause of the fire.","exampleZh":"警方正在調查這場火災的起因。","synonyms":["examine","explore"],"level":4,"theme":"合約與法律"},{"word":"investigation","pos":"n.","phonetic":"[ɪnˌvɛstəˈgeʃən]","meaning":"調查；偵查","definition":"an official attempt to find out the truth about something","collocations":["under investigation","conduct an investigation","thorough investigation"],"example":"The cause of the shipping error is still under investigation.","exampleZh":"出貨錯誤的原因仍在調查中。","synonyms":["inquiry","probe"],"level":4,"theme":"合約與法律"},{"word":"investment","pos":"n.","phonetic":"[ɪnˈvɛstmənt]","meaning":"投資；投資額","definition":"the act of putting money into something to make a profit","collocations":["return on investment","make an investment","long-term investment"],"example":"The new equipment is a worthwhile investment for the factory.","exampleZh":"新設備對工廠而言是值得的投資。","synonyms":[],"level":3,"theme":"財務與會計"},{"word":"investor","pos":"n.","phonetic":"[ɪnˈvɛstɚ]","meaning":"投資人；投資者","definition":"a person or organization that puts money into something to make a profit","collocations":["potential investors","attract investors","foreign investor"],"example":"The startup presented its business plan to a group of potential investors.","exampleZh":"這家新創公司向一群潛在投資人簡報其商業計畫。","synonyms":["backer","shareholder"],"level":4,"theme":"財務與會計"},{"word":"invitation","pos":"n.","phonetic":"[ˌɪnvəˈteʃən]","meaning":"邀請；請帖","definition":"a written or spoken request to attend an event","collocations":["send an invitation","accept an invitation","by invitation only"],"example":"Invitations to the product launch were sent to major media outlets.","exampleZh":"產品發表會的邀請函已寄給各大媒體。","synonyms":[],"level":2,"theme":"媒體與活動"},{"word":"invite","pos":"v.","phonetic":"[ɪnˈvaɪt]","meaning":"邀請","definition":"to ask someone to attend an event or come somewhere","collocations":["invite friends","invite someone over","kindly invite"],"example":"We invited all our relatives to the wedding.","exampleZh":"我們邀請了所有的親戚來參加婚禮。","synonyms":["ask","request"],"level":2,"theme":"日常與一般"},{"word":"invoice","pos":"n./v.","phonetic":"[ˈɪnvɔɪs]","meaning":"發票；請款單；開立請款單","definition":"a document listing goods or services provided and the amount owed","collocations":["issue an invoice","pay an invoice","invoice number"],"example":"Please include the invoice number when making your payment.","exampleZh":"付款時請註明請款單編號。","synonyms":["bill"],"level":3,"theme":"財務與會計"},{"word":"involve","pos":"v.","phonetic":"[ɪnˈvɑlv]","meaning":"涉及；使參與","definition":"to include or affect something or someone as a necessary part","collocations":["involve risk","get involved in","involve many people"],"example":"The project will involve a lot of teamwork.","exampleZh":"這個專案將需要大量的團隊合作。","synonyms":["include","entail"],"level":3,"theme":"日常與一般"},{"word":"involvement","pos":"n.","phonetic":"[ɪnˈvɑlvmənt]","meaning":"參與；涉入","definition":"the act of taking part in something","collocations":["community involvement","active involvement","involvement in"],"example":"The company encourages employee involvement in local charity events.","exampleZh":"公司鼓勵員工參與當地慈善活動。","synonyms":["participation"],"level":4,"theme":"企業經營"},{"word":"iron","pos":"n. / v.","phonetic":"[ˈaɪɚn]","meaning":"鐵；熨斗；熨燙","definition":"a strong, hard metal; a device used to smooth clothes","collocations":["iron a shirt","made of iron","iron will"],"example":"She ironed her shirt before the interview.","exampleZh":"她在面試前熨了她的襯衫。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"island","pos":"n.","phonetic":"[ˈaɪlənd]","meaning":"島嶼","definition":"a piece of land surrounded by water","collocations":["a tropical island","live on an island","island nation"],"example":"Taiwan is an island located in East Asia.","exampleZh":"台灣是位於東亞的一座島嶼。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"issue","pos":"n. / v.","phonetic":"[ˈɪʃu]","meaning":"議題；問題；發行","definition":"an important topic for debate; to formally supply or distribute something","collocations":["a major issue","issue a statement","environmental issues"],"example":"Climate change is a major issue facing the world today.","exampleZh":"氣候變遷是當今世界面臨的重大議題。","synonyms":["topic","matter"],"level":3,"theme":"日常與一般"},{"word":"it","pos":"pron.","phonetic":"[ɪt]","meaning":"它；這件事","definition":"used to refer to a thing, situation, or idea already mentioned","collocations":["it depends","it seems that","make it"],"example":"The printer is out of toner, so please replace it today.","exampleZh":"印表機的碳粉用完了，請今天更換。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"item","pos":"n.","phonetic":"[ˈaɪtəm]","meaning":"項目；物品","definition":"an individual article or object, especially one included in a list","collocations":["an item on the list","expensive item","a news item"],"example":"Please check each item on the shopping list.","exampleZh":"請檢查購物清單上的每一項物品。","synonyms":["article","object"],"level":2,"theme":"財務與會計"},{"word":"itinerary","pos":"n.","phonetic":"[aɪˈtɪnəˌrɛrɪ]","meaning":"行程表；旅行路線","definition":"a detailed plan of a journey, including places and times","collocations":["travel itinerary","confirm the itinerary","detailed itinerary"],"example":"The assistant emailed the sales team a detailed itinerary for the trip.","exampleZh":"助理將詳細的出差行程表寄給業務團隊。","synonyms":["schedule"],"level":5,"theme":"旅遊與交通"},{"word":"its","pos":"det.","phonetic":"[ɪts]","meaning":"它的","definition":"belonging to a thing, animal, or organization already mentioned","collocations":["its own","its headquarters"],"example":"The company moved its headquarters to a larger building downtown.","exampleZh":"該公司將總部遷至市中心一棟更大的大樓。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"itself","pos":"pron.","phonetic":"[ɪtˈsɛlf]","meaning":"它自己；本身","definition":"used to refer back to the thing already mentioned as the subject","collocations":["by itself","in itself","the building itself"],"example":"The hotel itself is small, but the service is outstanding.","exampleZh":"飯店本身不大，但服務非常出色。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"jacket","pos":"n.","phonetic":"[ˈdʒækɪt]","meaning":"夾克；外套","definition":"a short coat, usually with sleeves","collocations":["put on a jacket","leather jacket","life jacket"],"example":"She wore a warm jacket to school this morning.","exampleZh":"她今天早上穿著一件保暖的夾克去上學。","synonyms":["coat"],"level":1,"theme":"購物與消費"},{"word":"janitor","pos":"n.","phonetic":"[ˈdʒænɪtɚ]","meaning":"工友；清潔管理員","definition":"a person who cleans and takes care of a building","collocations":["school janitor","building janitor"],"example":"The janitor locks all the office doors at ten each night.","exampleZh":"工友每晚十點會鎖上所有辦公室的門。","synonyms":["custodian","caretaker"],"level":4,"theme":"房產與設施"},{"word":"jet","pos":"n.","phonetic":"[dʒɛt]","meaning":"噴射機；噴射流","definition":"an aircraft powered by jet engines","collocations":["jet plane","jet engine","jet lag"],"example":"The jet took off smoothly from the runway.","exampleZh":"噴射機平穩地從跑道起飛。","synonyms":["airplane"],"level":3,"theme":"旅遊與交通"},{"word":"jeweler","pos":"n.","phonetic":"[ˈdʒuəlɚ]","meaning":"珠寶商；珠寶匠","definition":"a person who makes, repairs, or sells jewelry","collocations":["local jeweler","visit the jeweler"],"example":"The jeweler resized the ring while the customer waited.","exampleZh":"珠寶師傅當場為顧客修改戒圍。","synonyms":[],"level":4,"theme":"購物與消費"},{"word":"jewelry","pos":"n.","phonetic":"[ˈdʒuəlrɪ]","meaning":"珠寶；首飾","definition":"decorative items such as rings and necklaces worn on the body","collocations":["jewelry store","wear jewelry","gold jewelry"],"example":"She bought some jewelry for her mother's birthday.","exampleZh":"她買了一些珠寶送給媽媽當生日禮物。","synonyms":["accessories"],"level":3,"theme":"購物與消費"},{"word":"job","pos":"n.","phonetic":"[dʒɑb]","meaning":"工作；職業","definition":"the regular work a person does to earn money","collocations":["find a job","part-time job","do a good job"],"example":"He got a job at a local bakery.","exampleZh":"他在當地一家麵包店找到了工作。","synonyms":["occupation","work"],"level":1,"theme":"人事與職涯"},{"word":"join","pos":"v.","phonetic":"[dʒɔɪn]","meaning":"加入；參加；連接","definition":"to become a member of a group, or to connect things together","collocations":["join a club","join hands","join forces"],"example":"Would you like to join our basketball team?","exampleZh":"你想加入我們的籃球隊嗎？","synonyms":["participate","connect"],"level":1,"theme":"日常與一般"},{"word":"joint","pos":"n. / adj.","phonetic":"[dʒɔɪnt]","meaning":"關節；接合處；聯合的","definition":"a point where two bones meet, or shared by two or more people","collocations":["knee joint","joint effort","joint account"],"example":"The two companies made a joint decision to merge.","exampleZh":"這兩家公司做出了合併的共同決定。","synonyms":["shared","combined"],"level":4,"theme":"醫療與保險"},{"word":"jointly","pos":"adv.","phonetic":"[ˈdʒɔɪntlɪ]","meaning":"共同地；聯合地","definition":"done together by two or more people or organizations","collocations":["jointly owned","jointly developed","jointly organized"],"example":"The research project is jointly funded by two universities.","exampleZh":"這項研究計畫由兩所大學共同出資。","synonyms":["together"],"level":5,"theme":"企業經營"},{"word":"journal","pos":"n.","phonetic":"[ˈdʒɝnl]","meaning":"日誌；期刊","definition":"a regular written record of events, or a magazine on a special subject","collocations":["keep a journal","scientific journal","write in a journal"],"example":"She writes in her journal every night before bed.","exampleZh":"她每晚睡前都會在日誌上寫東西。","synonyms":["diary","magazine"],"level":4,"theme":"人事與職涯"},{"word":"journalist","pos":"n.","phonetic":"[ˈdʒɝnəlɪst]","meaning":"新聞記者","definition":"a person who writes news for newspapers, magazines, or broadcasts","collocations":["a young journalist","work as a journalist","investigative journalist"],"example":"The journalist interviewed the mayor about the new policy.","exampleZh":"那位記者就新政策採訪了市長。","synonyms":["reporter"],"level":4,"theme":"人事與職涯"},{"word":"journey","pos":"n. / v.","phonetic":"[ˈdʒɝnɪ]","meaning":"旅程；旅行","definition":"an act of traveling from one place to another, often a long one","collocations":["a long journey","go on a journey","journey home"],"example":"They went on a long journey across Europe.","exampleZh":"他們展開了一趟橫越歐洲的長途旅程。","synonyms":["trip","voyage"],"level":3,"theme":"旅遊與交通"},{"word":"judge","pos":"n. / v.","phonetic":"[dʒʌdʒ]","meaning":"法官；裁判；判斷","definition":"a public official who decides cases in a court of law, or to form an opinion","collocations":["a fair judge","judge a competition","judge by appearance"],"example":"The judge listened carefully before making a decision.","exampleZh":"法官在做出判決前仔細地聆聽。","synonyms":["evaluate"],"level":3,"theme":"合約與法律"},{"word":"judgment","pos":"n.","phonetic":"[ˈdʒʌdʒmənt]","meaning":"判斷；判決；評價","definition":"the ability to make sensible decisions, or an official decision of a court","collocations":["good judgment","make a judgment","court judgment"],"example":"You should trust your own judgment.","exampleZh":"你應該相信自己的判斷。","synonyms":["verdict","opinion"],"level":5,"theme":"日常與一般"},{"word":"juice","pos":"n.","phonetic":"[dʒus]","meaning":"果汁","definition":"the liquid contained in fruit or vegetables","collocations":["orange juice","fresh juice","a glass of juice"],"example":"She drank a glass of orange juice for breakfast.","exampleZh":"她早餐喝了一杯柳橙汁。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"jump","pos":"v. / n.","phonetic":"[dʒʌmp]","meaning":"跳；跳躍","definition":"to push oneself off the ground using the legs","collocations":["jump up","jump rope","jump for joy"],"example":"The dog jumped over the fence.","exampleZh":"那隻狗跳過了圍籬。","synonyms":["leap","hop"],"level":1,"theme":"日常與一般"},{"word":"junior","pos":"adj. / n.","phonetic":"[ˈdʒunjɚ]","meaning":"資淺的；年少的；晚輩","definition":"younger in age or lower in rank","collocations":["junior high school","junior staff","junior partner"],"example":"My sister is a junior high school student.","exampleZh":"我妹妹是國中生。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"jury","pos":"n.","phonetic":"[ˈdʒʊrɪ]","meaning":"陪審團；評審團","definition":"a group of people who decide a court case or judge a competition","collocations":["jury duty","serve on a jury","the jury's decision"],"example":"He requested a day off to report for jury duty.","exampleZh":"他請了一天假去履行陪審義務。","synonyms":["panel"],"level":4,"theme":"合約與法律"},{"word":"just","pos":"adv. / adj.","phonetic":"[dʒʌst]","meaning":"剛剛；只是；公正的","definition":"exactly, or fair and reasonable","collocations":["just now","just in time","a just decision"],"example":"The judge made a just decision for both sides.","exampleZh":"法官為雙方做出了公正的裁決。","synonyms":["fair"],"level":1,"theme":"日常與一般"},{"word":"justification","pos":"n.","phonetic":"[ˌdʒʌstəfəˈkeʃən]","meaning":"正當理由；辯護","definition":"a good reason for doing something","collocations":["justification for","provide justification","without justification"],"example":"Managers must provide written justification for any budget overruns.","exampleZh":"任何預算超支，主管都必須提出書面理由。","synonyms":["grounds","reason"],"level":6,"theme":"財務與會計"},{"word":"justify","pos":"v.","phonetic":"[ˈdʒʌstəˌfaɪ]","meaning":"證明…是正當的；為…辯護","definition":"to show or prove that something is right or reasonable","collocations":["justify a decision","justify one's actions","hard to justify"],"example":"He couldn't justify spending so much money on a watch.","exampleZh":"他無法證明花這麼多錢買手錶是合理的。","synonyms":["defend","explain"],"level":5,"theme":"日常與一般"},{"word":"keen","pos":"adj.","phonetic":"[kin]","meaning":"熱衷的；敏銳的；渴望的","definition":"having a strong interest or enthusiasm for something","collocations":["keen interest","keen sense of smell","be keen on something"],"example":"She is keen on learning new languages.","exampleZh":"她熱衷於學習新語言。","synonyms":["eager","sharp"],"level":4,"theme":"日常與一般"},{"word":"keep","pos":"v.","phonetic":"[kip]","meaning":"保持；保留；飼養","definition":"to have or retain possession of something, or to continue in a specified condition","collocations":["keep a promise","keep in touch","keep a diary"],"example":"Please keep in touch after you move abroad.","exampleZh":"你搬到國外後請保持聯絡。","synonyms":["retain","maintain"],"level":1,"theme":"日常與一般"},{"word":"key","pos":"n. / adj.","phonetic":"[ki]","meaning":"鑰匙；關鍵的","definition":"a small metal device for locking, or something essential and crucial","collocations":["a key issue","the key to success","spare key"],"example":"Hard work is the key to success.","exampleZh":"努力是成功的關鍵。","synonyms":["crucial","essential"],"level":1,"theme":"日常與一般"},{"word":"keyboard","pos":"n.","phonetic":"[ˈkiˌbord]","meaning":"鍵盤","definition":"a set of keys on a computer or musical instrument","collocations":["computer keyboard","type on a keyboard","piano keyboard"],"example":"She types very fast on the keyboard.","exampleZh":"她在鍵盤上打字打得很快。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"keynote","pos":"n./adj.","phonetic":"[ˈkiˌnot]","meaning":"主題演講；基調","definition":"the most important speech at a conference","collocations":["keynote speaker","keynote address","deliver the keynote"],"example":"The CEO will deliver the keynote address at the technology summit.","exampleZh":"執行長將在科技高峰會上發表主題演講。","synonyms":[],"level":5,"theme":"會議與簡報"},{"word":"kilometer","pos":"n.","phonetic":"[ˈkɪləˌmitɚ]","meaning":"公里","definition":"a unit of length equal to 1,000 meters","collocations":["ten kilometers away","kilometers per hour","run a kilometer"],"example":"The school is two kilometers from my house.","exampleZh":"學校離我家兩公里遠。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"kind","pos":"adj. / n.","phonetic":"[kaɪnd]","meaning":"親切的；種類","definition":"friendly and considerate, or a category of things","collocations":["be kind to someone","kind of person","different kinds"],"example":"It was very kind of you to help me.","exampleZh":"你能幫我真是太好心了。","synonyms":["gentle","type"],"level":1,"theme":"日常與一般"},{"word":"kindly","pos":"adv./adj.","phonetic":"[ˈkaɪndlɪ]","meaning":"請；親切地","definition":"used to make a polite request, or in a kind way","collocations":["kindly note","kindly refrain from","kindly reply"],"example":"Kindly note that the office will be closed on Monday.","exampleZh":"敬請留意，辦公室週一將休息。","synonyms":["please"],"level":4,"theme":"溝通與語言"},{"word":"kiosk","pos":"n.","phonetic":"[ˈkiɑsk]","meaning":"小亭；自助服務機","definition":"a small booth selling things, or a self-service machine","collocations":["information kiosk","self-service kiosk","check-in kiosk"],"example":"Passengers can print boarding passes at the self-service kiosks.","exampleZh":"乘客可在自助服務機列印登機證。","synonyms":["booth","stand"],"level":5,"theme":"旅遊與交通"},{"word":"kit","pos":"n.","phonetic":"[kɪt]","meaning":"工具組；用具箱","definition":"a set of tools or equipment for a particular purpose","collocations":["first-aid kit","tool kit","repair kit"],"example":"Every car should carry a first-aid kit.","exampleZh":"每輛車都應該備有急救箱。","synonyms":["set","equipment"],"level":3,"theme":"房產與設施"},{"word":"kitchen","pos":"n.","phonetic":"[ˈkɪtʃɪn]","meaning":"廚房","definition":"a room where food is prepared and cooked","collocations":["kitchen table","clean the kitchen","kitchen sink"],"example":"My mom is cooking dinner in the kitchen.","exampleZh":"我媽媽正在廚房裡煮晚餐。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"knob","pos":"n.","phonetic":"[nɑb]","meaning":"把手；旋鈕","definition":"a round handle or control switch on a door or device","collocations":["door knob","turn the knob","volume knob"],"example":"Turn the knob to open the door.","exampleZh":"轉動門把來開門。","synonyms":["handle"],"level":4,"theme":"房產與設施"},{"word":"knock","pos":"v. / n.","phonetic":"[nɑk]","meaning":"敲；敲擊","definition":"to hit a surface, especially a door, to attract attention","collocations":["knock on the door","knock over","knock someone out"],"example":"Someone knocked on the door late at night.","exampleZh":"深夜有人敲門。","synonyms":["rap","tap"],"level":2,"theme":"日常與一般"},{"word":"know","pos":"v.","phonetic":"[no]","meaning":"知道；認識","definition":"to be aware of or familiar with information or a person","collocations":["know for sure","get to know","know how to"],"example":"I don't know the answer to this question.","exampleZh":"我不知道這個問題的答案。","synonyms":["understand","recognize"],"level":1,"theme":"人事與職涯"},{"word":"knowledge","pos":"n.","phonetic":"[ˈnɑlɪdʒ]","meaning":"知識","definition":"facts, information, and skills acquired through experience or education","collocations":["general knowledge","gain knowledge","knowledge of"],"example":"Reading widely can broaden your knowledge of the world.","exampleZh":"廣泛閱讀能增廣你對世界的知識。","synonyms":["understanding","learning"],"level":2,"theme":"人事與職涯"},{"word":"knowledgeable","pos":"adj.","phonetic":"[ˈnɑlɪdʒəbl̩]","meaning":"博學的；有見識的","definition":"having or showing knowledge or intelligence about a subject","collocations":["knowledgeable about","highly knowledgeable","knowledgeable staff"],"example":"The tour guide was very knowledgeable about local history.","exampleZh":"這位導遊對當地歷史非常了解。","synonyms":["informed","learned"],"level":5,"theme":"人事與職涯"},{"word":"known","pos":"adj.","phonetic":"[non]","meaning":"已知的；著名的","definition":"recognized, familiar, or identified","collocations":["well-known","known for","known fact"],"example":"The city is well-known for its delicious street food.","exampleZh":"這座城市以美味的街頭小吃聞名。","synonyms":["recognized","famous"],"level":3,"theme":"日常與一般"},{"word":"label","pos":"n. / v.","phonetic":"[ˈlebl̩]","meaning":"標籤；標示","definition":"a piece of paper or material attached to something giving information about it, or to attach such information","collocations":["label a product","warning label","price label"],"example":"The label shows all the ingredients used in the food.","exampleZh":"標籤上列出了這食品所使用的所有成分。","synonyms":["tag","mark"],"level":3,"theme":"財務與會計"},{"word":"labor","pos":"n. / v.","phonetic":"[ˈlebɚ]","meaning":"勞動；勞工；努力工作","definition":"hard physical or mental work, or the workers who provide it","collocations":["manual labor","labor force","labor market"],"example":"Farming requires a lot of manual labor.","exampleZh":"務農需要大量的體力勞動。","synonyms":["work","toil"],"level":4,"theme":"人事與職涯"},{"word":"laboratory","pos":"n.","phonetic":"[ˈlæbrəˌtɔri]","meaning":"實驗室","definition":"a room or building equipped for scientific experiments","collocations":["chemistry laboratory","laboratory test","laboratory equipment"],"example":"The scientists conducted the experiment in the laboratory.","exampleZh":"科學家們在實驗室裡進行了這項實驗。","synonyms":["lab"],"level":5,"theme":"科技與通訊"},{"word":"lack","pos":"n. / v.","phonetic":"[læk]","meaning":"缺乏；不足","definition":"the state of not having enough of something","collocations":["lack of confidence","lack of sleep","lack money"],"example":"He failed the exam due to a lack of preparation.","exampleZh":"他因為準備不足而考試不及格。","synonyms":["shortage","absence"],"level":3,"theme":"日常與一般"},{"word":"ladder","pos":"n.","phonetic":"[ˈlædɚ]","meaning":"梯子；階梯","definition":"a structure with steps used for climbing up or down","collocations":["climb a ladder","career ladder","wooden ladder"],"example":"He climbed the ladder to fix the roof.","exampleZh":"他爬上梯子去修理屋頂。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"landlord","pos":"n.","phonetic":"[ˈlændˌlɔrd]","meaning":"房東；地主","definition":"a person who rents out a building or land to others","collocations":["notify the landlord","landlord and tenant"],"example":"Tenants must notify the landlord thirty days before moving out.","exampleZh":"房客必須在搬離前三十天通知房東。","synonyms":["property owner"],"level":4,"theme":"房產與設施"},{"word":"landscape","pos":"n.","phonetic":"[ˈlændˌskep]","meaning":"風景；景觀","definition":"all the visible features of an area of land","collocations":["rural landscape","landscape painting","urban landscape"],"example":"The artist painted a beautiful mountain landscape.","exampleZh":"這位畫家畫了一幅美麗的山景畫。","synonyms":["scenery"],"level":4,"theme":"日常與一般"},{"word":"lane","pos":"n.","phonetic":"[len]","meaning":"小巷；車道","definition":"a narrow road, or a strip of a wider road","collocations":["bike lane","country lane","fast lane"],"example":"Cyclists should stay in the bike lane.","exampleZh":"騎自行車的人應該待在自行車道上。","synonyms":[],"level":2,"theme":"旅遊與交通"},{"word":"language","pos":"n.","phonetic":"[ˈlæŋgwɪdʒ]","meaning":"語言","definition":"a system of communication used by people of a particular country or area","collocations":["foreign language","body language","native language"],"example":"Learning a new language takes time and practice.","exampleZh":"學習一種新語言需要時間和練習。","synonyms":["speech","tongue"],"level":2,"theme":"溝通與語言"},{"word":"laptop","pos":"n.","phonetic":"[ˈlæpˌtɑp]","meaning":"筆記型電腦","definition":"a small portable computer","collocations":["laptop computer","open a laptop","laptop screen"],"example":"She works on her laptop at the coffee shop.","exampleZh":"她在咖啡店用筆電工作。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"large","pos":"adj.","phonetic":"[lɑrdʒ]","meaning":"大的；巨大的","definition":"big in size, amount, or extent","collocations":["large amount","large scale","extra large"],"example":"They bought a large house near the sea.","exampleZh":"他們在海邊買了一棟大房子。","synonyms":["big","huge"],"level":1,"theme":"日常與一般"},{"word":"last","pos":"adj. / v.","phonetic":"[læst]","meaning":"最後的；持續","definition":"coming after all others in time or order; to continue for a period","collocations":["last chance","last long","at last"],"example":"The concert lasted for three hours.","exampleZh":"這場演唱會持續了三個小時。","synonyms":["final","continue"],"level":1,"theme":"日常與一般"},{"word":"late","pos":"adj. / adv.","phonetic":"[let]","meaning":"遲的；晚的","definition":"after the expected or usual time","collocations":["be late for","late night","arrive late"],"example":"He was late for school again this morning.","exampleZh":"他今天早上上學又遲到了。","synonyms":["overdue"],"level":1,"theme":"日常與一般"},{"word":"lately","pos":"adv.","phonetic":"[ˈletlɪ]","meaning":"最近；近來","definition":"recently or in the recent past","collocations":["until lately","busy lately"],"example":"Sales of the older model have slowed down lately.","exampleZh":"舊款產品的銷售最近趨緩。","synonyms":["recently"],"level":2,"theme":"日常與一般"},{"word":"latest","pos":"adj./n.","phonetic":"[ˈletɪst]","meaning":"最新的；最遲的","definition":"the most recent or newest","collocations":["latest model","latest news","at the latest"],"example":"Submit your application by Friday at the latest.","exampleZh":"最遲請於週五前提交申請。","synonyms":["newest","most recent"],"level":2,"theme":"日常與一般"},{"word":"launch","pos":"v. / n.","phonetic":"[lɔntʃ]","meaning":"發射；發起；推出","definition":"to send something into space, or to start something new such as a product","collocations":["launch a rocket","launch a product","product launch"],"example":"The company will launch a new smartphone next month.","exampleZh":"這家公司下個月將推出一款新手機。","synonyms":["start","introduce"],"level":4,"theme":"科技與通訊"},{"word":"laundry","pos":"n.","phonetic":"[ˈlɔndri]","meaning":"待洗衣物；洗衣店","definition":"clothes and other items that need to be washed, or the place where washing is done","collocations":["do the laundry","laundry basket","laundry service"],"example":"She does the laundry every Sunday morning.","exampleZh":"她每個星期天早上洗衣服。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"law","pos":"n.","phonetic":"[lɔ]","meaning":"法律；法規","definition":"a rule established by a government that must be obeyed","collocations":["break the law","obey the law","law school"],"example":"It is against the law to drive without a license.","exampleZh":"無照駕駛是違法的。","synonyms":["rule","regulation"],"level":2,"theme":"合約與法律"},{"word":"lawn","pos":"n.","phonetic":"[lɔn]","meaning":"草坪","definition":"an area of short, regularly cut grass","collocations":["mow the lawn","front lawn","lawn mower"],"example":"My father mows the lawn every weekend.","exampleZh":"我爸爸每個週末都會修剪草坪。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"lawsuit","pos":"n.","phonetic":"[ˈlɔˌsut]","meaning":"訴訟；官司","definition":"a legal case brought to a court by one party against another","collocations":["file a lawsuit","settle a lawsuit","face a lawsuit"],"example":"The supplier filed a lawsuit over the canceled contract.","exampleZh":"供應商就遭取消的合約提起訴訟。","synonyms":["litigation","legal action"],"level":5,"theme":"合約與法律"},{"word":"lawyer","pos":"n.","phonetic":"[ˈlɔjɚ]","meaning":"律師","definition":"a person who is qualified to practice law","collocations":["hire a lawyer","become a lawyer","defense lawyer"],"example":"She hired a lawyer to handle the case.","exampleZh":"她請了一位律師來處理這個案子。","synonyms":["attorney"],"level":3,"theme":"人事與職涯"},{"word":"layer","pos":"n.","phonetic":"[ˈleɚ]","meaning":"層；層次","definition":"a level, sheet, or thickness of material covering a surface","collocations":["a layer of","ozone layer","layer cake"],"example":"There is a thick layer of snow on the ground.","exampleZh":"地上有一層厚厚的雪。","synonyms":["level","coat"],"level":3,"theme":"日常與一般"},{"word":"layoff","pos":"n.","phonetic":"[ˈleˌɔf]","meaning":"裁員；解僱","definition":"the act of ending workers' jobs because there is not enough work or money","collocations":["mass layoffs","announce layoffs","avoid layoffs"],"example":"The company avoided layoffs by reducing everyone's hours slightly.","exampleZh":"公司透過小幅縮減所有人的工時來避免裁員。","synonyms":["dismissal"],"level":5,"theme":"人事與職涯"},{"word":"layout","pos":"n.","phonetic":"[ˈleˌaʊt]","meaning":"版面配置；佈局","definition":"the way things are arranged in a space or on a page","collocations":["office layout","page layout","store layout"],"example":"The new office layout includes more meeting rooms and open space.","exampleZh":"新的辦公室佈局包含更多會議室和開放空間。","synonyms":["arrangement","design"],"level":4,"theme":"辦公室與行政"},{"word":"layover","pos":"n.","phonetic":"[ˈleˌovɚ]","meaning":"中途停留；轉機停留","definition":"a short stay between parts of a journey, especially between flights","collocations":["long layover","three-hour layover","layover in"],"example":"The flight includes a two-hour layover in Singapore.","exampleZh":"這班航程包含在新加坡停留兩小時轉機。","synonyms":["stopover"],"level":5,"theme":"旅遊與交通"},{"word":"lead","pos":"v. / n.","phonetic":"[lid]","meaning":"帶領；領先","definition":"to guide a group of people, or to be in first place","collocations":["lead the way","take the lead","lead a team"],"example":"She will lead the team in the competition.","exampleZh":"她將在比賽中帶領這個團隊。","synonyms":["guide","direct"],"level":3,"theme":"人事與職涯"},{"word":"leader","pos":"n.","phonetic":"[ˈlidɚ]","meaning":"領導者","definition":"a person who leads or commands a group","collocations":["team leader","become a leader","world leader"],"example":"A good leader listens to others' opinions.","exampleZh":"一位好的領導者會傾聽他人的意見。","synonyms":["head","chief"],"level":2,"theme":"人事與職涯"},{"word":"leadership","pos":"n.","phonetic":"[ˈlidɚˌʃɪp]","meaning":"領導能力；領導階層","definition":"the ability to lead, or the people in charge of an organization","collocations":["leadership skills","under the leadership of","leadership training"],"example":"The program helps managers develop strong leadership skills.","exampleZh":"這項課程幫助主管培養優秀的領導能力。","synonyms":["guidance","management"],"level":4,"theme":"人事與職涯"},{"word":"leaflet","pos":"n.","phonetic":"[ˈliflɪt]","meaning":"傳單；小冊子","definition":"a small printed sheet giving information or advertising something","collocations":["hand out leaflets","promotional leaflet"],"example":"Staff distributed leaflets about the upcoming clearance sale.","exampleZh":"工作人員發送即將舉行的清倉特賣傳單。","synonyms":["flyer","pamphlet"],"level":4,"theme":"行銷與銷售"},{"word":"leak","pos":"v. / n.","phonetic":"[lik]","meaning":"漏；洩漏","definition":"to let liquid or gas escape through a hole or crack","collocations":["leak information","water leak","gas leak"],"example":"The roof leaks whenever it rains heavily.","exampleZh":"每次下大雨屋頂就會漏水。","synonyms":["drip","seep"],"level":4,"theme":"房產與設施"},{"word":"learn","pos":"v.","phonetic":"[lɝn]","meaning":"學習；得知","definition":"to gain knowledge or skill, or to find out information","collocations":["learn a skill","learn about","learn quickly"],"example":"New staff learn the booking system during their first week.","exampleZh":"新進員工在第一週學習訂位系統。","synonyms":["study","master"],"level":1,"theme":"人事與職涯"},{"word":"lease","pos":"n./v.","phonetic":"[lis]","meaning":"租約；租賃；出租","definition":"a legal agreement to use a building or equipment for a period in return for rent","collocations":["sign a lease","lease agreement","renew the lease"],"example":"The company signed a five-year lease on the downtown office space.","exampleZh":"公司簽下市中心辦公空間的五年租約。","synonyms":["rent"],"level":4,"theme":"房產與設施"},{"word":"leave","pos":"v. / n.","phonetic":"[liv]","meaning":"離開；留下；假期","definition":"to go away from a place, or a period of permitted absence from work","collocations":["leave home","leave a message","sick leave"],"example":"She will leave for Taipei tomorrow morning.","exampleZh":"她明天早上將前往台北。","synonyms":["depart","go"],"level":1,"theme":"日常與一般"},{"word":"lecture","pos":"n. / v.","phonetic":"[ˈlɛktʃɚ]","meaning":"講課；演講","definition":"a talk given to a group of people to teach them about a subject","collocations":["attend a lecture","give a lecture","lecture hall"],"example":"The professor gave an interesting lecture on history.","exampleZh":"這位教授做了一場有趣的歷史演講。","synonyms":["speech","talk"],"level":3,"theme":"人事與職涯"},{"word":"lecturer","pos":"n.","phonetic":"[ˈlɛktʃərɚ]","meaning":"講師；演講者","definition":"a person who gives talks to teach people, especially at a university","collocations":["guest lecturer","university lecturer"],"example":"A guest lecturer from the industry will speak at Thursday's seminar.","exampleZh":"一位業界客座講師將在週四的研討會上演講。","synonyms":["speaker","instructor"],"level":4,"theme":"人事與職涯"},{"word":"legal","pos":"adj.","phonetic":"[ˈligl̩]","meaning":"合法的；法律的","definition":"relating to the law, or allowed by law","collocations":["legal action","legal advice","legal system"],"example":"Smoking is legal but restricted in public places.","exampleZh":"吸菸是合法的，但在公共場所受到限制。","synonyms":["lawful"],"level":4,"theme":"合約與法律"},{"word":"legislation","pos":"n.","phonetic":"[ˌlɛdʒɪsˈleʃən]","meaning":"立法；法規","definition":"a law or set of laws made by a government","collocations":["pass legislation","new legislation","environmental legislation"],"example":"New legislation requires all factories to reduce emissions by 2030.","exampleZh":"新法規要求所有工廠在2030年前減少排放。","synonyms":["law","regulation"],"level":6,"theme":"合約與法律"},{"word":"leisure","pos":"n.","phonetic":"[ˈliʒɚ]","meaning":"休閒；閒暇","definition":"free time available for relaxation or enjoyment","collocations":["leisure time","leisure activities","at leisure"],"example":"He spends his leisure time playing golf.","exampleZh":"他利用休閒時間打高爾夫球。","synonyms":["free time"],"level":4,"theme":"媒體與活動"},{"word":"lend","pos":"v.","phonetic":"[lɛnd]","meaning":"借出","definition":"to give something to someone for a period of time, expecting it back","collocations":["lend money","lend a hand","lend a book"],"example":"Could you lend me your pen for a minute?","exampleZh":"你可以借我你的筆一下嗎？","synonyms":["loan"],"level":2,"theme":"財務與會計"},{"word":"length","pos":"n.","phonetic":"[lɛŋθ]","meaning":"長度","definition":"the measurement of how long something is from end to end","collocations":["full length","at length","length of time"],"example":"The length of the river is over 500 kilometers.","exampleZh":"這條河的長度超過五百公里。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"lessee","pos":"n.","phonetic":"[lɛˈsi]","meaning":"承租人；租戶","definition":"a person who rents a building or land from an owner","collocations":["lessee and lessor","rights of the lessee"],"example":"The lessee is responsible for minor repairs under this agreement.","exampleZh":"依本合約，承租人須負責小型修繕。","synonyms":["tenant","renter"],"level":6,"theme":"房產與設施"},{"word":"lesson","pos":"n.","phonetic":"[ˈlɛsn̩]","meaning":"課程；教訓","definition":"a period of learning, or something learned from experience","collocations":["take lessons","learn a lesson","piano lesson"],"example":"We had an English lesson this morning.","exampleZh":"我們今天早上上了一堂英文課。","synonyms":["class"],"level":1,"theme":"人事與職涯"},{"word":"letter","pos":"n.","phonetic":"[ˈlɛtɚ]","meaning":"信；字母","definition":"a written message sent to someone, or a symbol of the alphabet","collocations":["write a letter","capital letter","love letter"],"example":"She wrote a letter to her grandmother.","exampleZh":"她寫了一封信給她的祖母。","synonyms":[],"level":1,"theme":"溝通與語言"},{"word":"level","pos":"n. / adj.","phonetic":"[ˈlɛvl̩]","meaning":"水平；程度；等級的","definition":"a standard, amount, or position on a scale; flat and even","collocations":["high level","sea level","level ground"],"example":"The water level rose after the heavy rain.","exampleZh":"大雨過後水位上升了。","synonyms":["standard","degree"],"level":2,"theme":"日常與一般"},{"word":"liability","pos":"n.","phonetic":"[ˌlaɪəˈbɪlətɪ]","meaning":"責任；負債；不利因素","definition":"legal responsibility for something, or debts owed by a business","collocations":["liability insurance","assume liability","limited liability"],"example":"The contractor carries liability insurance for workplace accidents.","exampleZh":"承包商投保了工安事故責任險。","synonyms":["responsibility","obligation"],"level":6,"theme":"合約與法律"},{"word":"librarian","pos":"n.","phonetic":"[laɪˈbrɛrɪən]","meaning":"圖書館員","definition":"a person who works in a library","collocations":["reference librarian","ask the librarian"],"example":"The librarian can help you locate industry reports and journals.","exampleZh":"圖書館員可以協助你查找產業報告和期刊。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"library","pos":"n.","phonetic":"[ˈlaɪˌbrɛri]","meaning":"圖書館","definition":"a place containing books for reading or borrowing","collocations":["school library","public library","library card"],"example":"I borrowed three books from the library.","exampleZh":"我從圖書館借了三本書。","synonyms":[],"level":1,"theme":"人事與職涯"},{"word":"license","pos":"n. / v.","phonetic":"[ˈlaɪsn̩s]","meaning":"執照；許可證","definition":"an official document giving permission to do or own something","collocations":["driver's license","business license","license plate"],"example":"You need a license to drive a car legally.","exampleZh":"你需要有駕照才能合法開車。","synonyms":["permit"],"level":4,"theme":"合約與法律"},{"word":"lifetime","pos":"n./adj.","phonetic":"[ˈlaɪfˌtaɪm]","meaning":"一生；終身的","definition":"the period during which someone is alive or something lasts","collocations":["lifetime warranty","lifetime membership","once in a lifetime"],"example":"The cookware comes with a lifetime warranty against defects.","exampleZh":"這組鍋具提供終身瑕疵保固。","synonyms":[],"level":3,"theme":"購物與消費"},{"word":"light","pos":"n. / adj. / v.","phonetic":"[laɪt]","meaning":"光；輕的；點燃","definition":"brightness that comes from the sun or a lamp; not heavy; to set something on fire","collocations":["turn on the light","light rain","light a candle"],"example":"She turned on the light in the dark room.","exampleZh":"她打開了昏暗房間裡的燈。","synonyms":["bright"],"level":1,"theme":"日常與一般"},{"word":"likely","pos":"adj. / adv.","phonetic":"[ˈlaɪkli]","meaning":"可能的","definition":"probable or expected to happen","collocations":["likely to happen","more likely","most likely"],"example":"It is likely to rain this afternoon.","exampleZh":"今天下午很可能會下雨。","synonyms":["probable"],"level":3,"theme":"日常與一般"},{"word":"likewise","pos":"adv.","phonetic":"[ˈlaɪkˌwaɪz]","meaning":"同樣地；也","definition":"in the same way, or also","collocations":["do likewise"],"example":"The Tokyo branch cut costs, and the Seoul office did likewise.","exampleZh":"東京分公司削減了成本，首爾辦公室也照做。","synonyms":["similarly","equally"],"level":5,"theme":"溝通與語言"},{"word":"limit","pos":"n. / v.","phonetic":"[ˈlɪmɪt]","meaning":"限制；界限","definition":"the greatest or smallest amount allowed, or to restrict something","collocations":["speed limit","set a limit","age limit"],"example":"Please obey the speed limit while driving.","exampleZh":"開車時請遵守速限。","synonyms":["restrict","boundary"],"level":3,"theme":"日常與一般"},{"word":"limitation","pos":"n.","phonetic":"[ˌlɪməˈteʃən]","meaning":"限制；侷限","definition":"a rule that limits something, or a weakness","collocations":["budget limitations","limitations of the study","impose limitations"],"example":"Due to budget limitations, the team postponed the software upgrade.","exampleZh":"由於預算限制，團隊延後了軟體升級。","synonyms":["restriction","constraint"],"level":5,"theme":"企業經營"},{"word":"limited","pos":"adj.","phonetic":"[ˈlɪmɪtɪd]","meaning":"有限的","definition":"small in amount, number, or range","collocations":["limited time","limited seating","limited edition"],"example":"The discount is available for a limited time only.","exampleZh":"此折扣僅限時提供。","synonyms":["restricted"],"level":3,"theme":"行銷與銷售"},{"word":"line","pos":"n. / v.","phonetic":"[laɪn]","meaning":"線；排隊","definition":"a long thin mark, or a row of people or things","collocations":["wait in line","draw a line","phone line"],"example":"Please stand in line and wait for your turn.","exampleZh":"請排隊並等待輪到你。","synonyms":["row","queue"],"level":1,"theme":"日常與一般"},{"word":"link","pos":"n. / v.","phonetic":"[lɪŋk]","meaning":"連結；關聯","definition":"a connection between two things, or to connect them","collocations":["click a link","link together","weak link"],"example":"Click the link to visit our website.","exampleZh":"點擊這個連結來造訪我們的網站。","synonyms":["connection","join"],"level":3,"theme":"科技與通訊"},{"word":"liquid","pos":"n. / adj.","phonetic":"[ˈlɪkwɪd]","meaning":"液體；液態的","definition":"a substance, such as water, that flows freely and is neither solid nor gas","collocations":["liquid form","clear liquid","liquid diet"],"example":"Water is a liquid at room temperature.","exampleZh":"水在室溫下是液體。","synonyms":["fluid"],"level":3,"theme":"科技與通訊"},{"word":"list","pos":"n./v.","phonetic":"[lɪst]","meaning":"清單；列表；列出","definition":"a series of names or items written one below another, or to write them down","collocations":["waiting list","price list","list the items"],"example":"Please list all attendees who require vegetarian meals.","exampleZh":"請列出所有需要素食餐點的與會者。","synonyms":[],"level":1,"theme":"辦公室與行政"},{"word":"listen","pos":"v.","phonetic":"[ˈlɪsn]","meaning":"聽；聆聽","definition":"to pay attention to sounds or what someone says","collocations":["listen carefully","listen to feedback"],"example":"Managers should listen carefully to feedback from frontline staff.","exampleZh":"主管應仔細聆聽第一線員工的意見回饋。","synonyms":[],"level":1,"theme":"溝通與語言"},{"word":"literature","pos":"n.","phonetic":"[ˈlɪtərətʃɚ]","meaning":"文學；（宣傳）印刷品；文獻","definition":"written works, or printed information about a product or subject","collocations":["promotional literature","product literature","scientific literature"],"example":"Product literature and samples are available at the front counter.","exampleZh":"產品簡介與樣品可在前檯索取。","synonyms":[],"level":4,"theme":"行銷與銷售"},{"word":"live","pos":"v./adj./adv.","phonetic":"[lɪv]","meaning":"居住；現場的；直播地","definition":"to have your home somewhere, or happening now and broadcast as it happens","collocations":["live nearby","live broadcast","live music"],"example":"The restaurant features live music every Friday and Saturday night.","exampleZh":"這家餐廳每週五、六晚上有現場音樂表演。","synonyms":[],"level":1,"theme":"媒體與活動"},{"word":"living","pos":"n./adj.","phonetic":"[ˈlɪvɪŋ]","meaning":"生計；生活的；活的","definition":"the money you earn to live, or relating to life","collocations":["make a living","cost of living","living expenses"],"example":"The cost of living in the capital has risen sharply this year.","exampleZh":"首都的生活成本今年大幅上升。","synonyms":["livelihood"],"level":2,"theme":"日常與一般"},{"word":"load","pos":"n./v.","phonetic":"[lod]","meaning":"負載；貨物；裝載","definition":"an amount carried, or to put goods onto a vehicle","collocations":["load the truck","full load","workload"],"example":"Workers loaded the trucks with the morning's deliveries.","exampleZh":"工人將上午要配送的貨物裝上卡車。","synonyms":["cargo","freight"],"level":2,"theme":"生產與物流"},{"word":"loan","pos":"n. / v.","phonetic":"[lon]","meaning":"貸款；借出","definition":"money that is borrowed and repaid with interest; to lend something","collocations":["bank loan","take out a loan","loan money"],"example":"They took out a loan to buy their first house.","exampleZh":"他們貸款買了第一間房子。","synonyms":["credit","lend"],"level":3,"theme":"財務與會計"},{"word":"lobby","pos":"n. / v.","phonetic":"[ˈlɑbi]","meaning":"大廳；遊說","definition":"an entrance hall; to try to influence officials on an issue","collocations":["hotel lobby","lobby for change","lobby group"],"example":"We met in the hotel lobby before dinner.","exampleZh":"我們晚餐前在飯店大廳碰面。","synonyms":["hall","foyer"],"level":4,"theme":"合約與法律"},{"word":"local","pos":"adj.","phonetic":"[ˈlokl̩]","meaning":"當地的；地方性的","definition":"relating to a particular area or neighborhood","collocations":["local news","local government","local resident","local market"],"example":"She shops at the local market every weekend.","exampleZh":"她每個週末都在當地市場購物。","synonyms":["regional","nearby"],"level":2,"theme":"房產與設施"},{"word":"locate","pos":"v.","phonetic":"[ˈloket]","meaning":"找出...的位置；設置在","definition":"to find the exact position of something","collocations":["locate a store","locate the source","easily located"],"example":"We used GPS to locate the nearest hospital.","exampleZh":"我們用GPS定位最近的醫院。","synonyms":["find","pinpoint"],"level":3,"theme":"日常與一般"},{"word":"location","pos":"n.","phonetic":"[loˈkeʃən]","meaning":"位置；地點","definition":"a particular place or position","collocations":["perfect location","filming location","current location"],"example":"The hotel's location is very convenient for tourists.","exampleZh":"這間飯店的位置對遊客來說非常方便。","synonyms":["place","site"],"level":3,"theme":"日常與一般"},{"word":"lock","pos":"n. / v.","phonetic":"[lɑk]","meaning":"鎖；鎖上","definition":"a device for fastening a door or container; to fasten with a lock","collocations":["lock the door","under lock and key","lock in place"],"example":"Please remember to lock the door before you leave.","exampleZh":"離開前請記得鎖門。","synonyms":["fasten","secure"],"level":1,"theme":"房產與設施"},{"word":"lodging","pos":"n.","phonetic":"[ˈlɑdʒɪŋ]","meaning":"住宿；租屋處","definition":"a place to stay temporarily","collocations":["find lodging","lodging expenses"],"example":"The company provides lodging for new employees.","exampleZh":"這家公司為新員工提供住宿。","synonyms":["accommodation"],"level":5,"theme":"房產與設施"},{"word":"logistics","pos":"n.","phonetic":"[loˈdʒɪstɪks]","meaning":"物流；後勤","definition":"the organization of moving goods, or the practical arrangement of an activity","collocations":["logistics company","handle the logistics","supply chain logistics"],"example":"A third-party logistics company manages all our overseas shipments.","exampleZh":"我們所有海外貨運都由第三方物流公司負責。","synonyms":[],"level":5,"theme":"生產與物流"},{"word":"logo","pos":"n.","phonetic":"[ˈlogo]","meaning":"標誌；商標","definition":"a symbol used to identify a company or product","collocations":["company logo","brand logo","design a logo"],"example":"The company changed its logo last year.","exampleZh":"這家公司去年更換了商標。","synonyms":["emblem","symbol"],"level":3,"theme":"財務與會計"},{"word":"long-term","pos":"adj.","phonetic":"[ˈlɔŋˈtɝm]","meaning":"長期的","definition":"continuing or having an effect over a long period","collocations":["long-term plan","long-term investment","long-term contract"],"example":"The firm signed a long-term contract with its main supplier.","exampleZh":"公司與主要供應商簽訂了長期合約。","synonyms":[],"level":3,"theme":"企業經營"},{"word":"look","pos":"v. / n.","phonetic":"[lʊk]","meaning":"看；看起來；外表","definition":"to direct one's eyes toward something; appearance","collocations":["look at","look like","take a look"],"example":"Take a look at this photo I found.","exampleZh":"看看我找到的這張照片。","synonyms":["glance","appearance"],"level":1,"theme":"日常與一般"},{"word":"lose","pos":"v.","phonetic":"[luz]","meaning":"失去；輸掉；迷失","definition":"to fail to keep, win, or find something","collocations":["lose weight","lose a game","lose one's way"],"example":"Try not to lose your temper during the discussion.","exampleZh":"討論時盡量別發脾氣。","synonyms":["misplace","forfeit"],"level":1,"theme":"日常與一般"},{"word":"loss","pos":"n.","phonetic":"[lɔs]","meaning":"損失；喪失","definition":"the fact or process of losing something","collocations":["weight loss","suffer a loss","sense of loss"],"example":"The company reported a huge financial loss last year.","exampleZh":"這家公司去年通報了巨大的財務損失。","synonyms":["deficit"],"level":3,"theme":"財務與會計"},{"word":"lounge","pos":"n. / v.","phonetic":"[laʊndʒ]","meaning":"休息室；躺臥","definition":"a room for relaxing or waiting; to sit or lie comfortably","collocations":["airport lounge","lounge chair","lounge around"],"example":"Passengers were waiting in the departure lounge.","exampleZh":"乘客們在候機室等待。","synonyms":["relax","sitting room"],"level":4,"theme":"旅遊與交通"},{"word":"low","pos":"adj. / adv.","phonetic":"[lo]","meaning":"低的；矮的","definition":"not high or tall; below the usual level","collocations":["low price","low voice","low temperature"],"example":"Prices are lower during the off-season.","exampleZh":"淡季時價格較低。","synonyms":["reduced"],"level":1,"theme":"日常與一般"},{"word":"lower","pos":"v. / adj.","phonetic":"[ˈloɚ]","meaning":"降低；放低","definition":"to move something down; less high","collocations":["lower prices","lower your voice","lower the flag"],"example":"The government decided to lower the tax rate.","exampleZh":"政府決定調降稅率。","synonyms":["reduce","decrease"],"level":2,"theme":"財務與會計"},{"word":"loyal","pos":"adj.","phonetic":"[ˈlɔɪəl]","meaning":"忠誠的；忠實的","definition":"giving firm and constant support to someone or something","collocations":["loyal customer","loyal friend","stay loyal"],"example":"He has always been loyal to his friends.","exampleZh":"他一直對朋友非常忠誠。","synonyms":["faithful","devoted"],"level":3,"theme":"日常與一般"},{"word":"loyalty","pos":"n.","phonetic":"[ˈlɔɪəlti]","meaning":"忠誠；忠心","definition":"the quality of being loyal","collocations":["brand loyalty","show loyalty","loyalty program"],"example":"The company rewards customer loyalty with discounts.","exampleZh":"這家公司以折扣回饋顧客的忠誠度。","synonyms":["faithfulness","devotion"],"level":4,"theme":"財務與會計"},{"word":"lucrative","pos":"adj.","phonetic":"[ˈlukrətɪv]","meaning":"賺錢的；獲利豐厚的","definition":"producing a lot of money or profit","collocations":["lucrative market","lucrative deal","highly lucrative"],"example":"The Asian market has proven highly lucrative for the brand.","exampleZh":"事實證明，亞洲市場為該品牌帶來豐厚獲利。","synonyms":["profitable"],"level":6,"theme":"企業經營"},{"word":"luggage","pos":"n.","phonetic":"[ˈlʌgɪdʒ]","meaning":"行李","definition":"bags and suitcases used for traveling","collocations":["carry luggage","luggage claim","pack luggage"],"example":"Please make sure your luggage is properly labeled.","exampleZh":"請確認你的行李有貼好標籤。","synonyms":["baggage"],"level":2,"theme":"旅遊與交通"},{"word":"lunch","pos":"n.","phonetic":"[lʌntʃ]","meaning":"午餐","definition":"a meal eaten in the middle of the day","collocations":["have lunch","pack a lunch","lunch break"],"example":"We usually have lunch together at noon.","exampleZh":"我們通常中午一起吃午餐。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"luncheon","pos":"n.","phonetic":"[ˈlʌntʃən]","meaning":"午餐會；正式午宴","definition":"a formal lunch event","collocations":["awards luncheon","business luncheon","annual luncheon"],"example":"The chamber of commerce hosts a networking luncheon each quarter.","exampleZh":"商會每季舉辦一次人脈交流午餐會。","synonyms":[],"level":5,"theme":"媒體與活動"},{"word":"luxury","pos":"n./adj.","phonetic":"[ˈlʌkʃərɪ]","meaning":"奢華；奢侈品；豪華的","definition":"great comfort and expensive things, or something expensive but not necessary","collocations":["luxury hotel","luxury goods","luxury brand"],"example":"The luxury hotel offers a private butler for every suite.","exampleZh":"這家豪華飯店為每間套房提供私人管家服務。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"machine","pos":"n.","phonetic":"[məˈʃin]","meaning":"機器；機械","definition":"a piece of equipment with moving parts used to do a particular kind of work","collocations":["washing machine","machine gun","operate a machine"],"example":"The factory bought a new machine to speed up production.","exampleZh":"工廠購買了一台新機器以加快生產速度。","synonyms":["device","apparatus"],"level":2,"theme":"科技與通訊"},{"word":"machinery","pos":"n.","phonetic":"[məˈʃinərɪ]","meaning":"機械；機器（總稱）","definition":"machines, especially large ones, as a group","collocations":["heavy machinery","operate machinery","farm machinery"],"example":"Only trained staff may operate the heavy machinery in the plant.","exampleZh":"只有受過訓練的員工才能操作廠內的重型機械。","synonyms":["equipment"],"level":4,"theme":"生產與物流"},{"word":"magazine","pos":"n.","phonetic":"[ˌmægəˈzin]","meaning":"雜誌","definition":"a thin publication with articles and photographs published regularly","collocations":["fashion magazine","read a magazine","subscribe to a magazine"],"example":"She reads a fashion magazine every month.","exampleZh":"她每個月都會看一本時尚雜誌。","synonyms":["journal","periodical"],"level":2,"theme":"科技與通訊"},{"word":"mail","pos":"n. / v.","phonetic":"[mel]","meaning":"郵件；郵寄","definition":"letters and packages sent by post, or to send them","collocations":["send mail","mail a letter","junk mail"],"example":"Please mail this package to my sister.","exampleZh":"請把這個包裹寄給我姊姊。","synonyms":["post"],"level":1,"theme":"溝通與語言"},{"word":"mailing","pos":"n.","phonetic":"[ˈmelɪŋ]","meaning":"郵寄；郵寄品","definition":"the act of sending things by mail, or the items sent","collocations":["mailing list","mailing address","mass mailing"],"example":"Join our mailing list to receive monthly updates and offers.","exampleZh":"加入我們的郵寄名單，即可收到每月最新消息與優惠。","synonyms":[],"level":3,"theme":"行銷與銷售"},{"word":"mailroom","pos":"n.","phonetic":"[ˈmelˌrum]","meaning":"收發室","definition":"the room in a company where mail is received and sorted","collocations":["mailroom staff","pick up from the mailroom"],"example":"All incoming packages are sorted in the mailroom before delivery.","exampleZh":"所有寄來的包裹會先在收發室分類再配送。","synonyms":[],"level":4,"theme":"辦公室與行政"},{"word":"main","pos":"adj.","phonetic":"[men]","meaning":"主要的","definition":"most important; principal","collocations":["main reason","main course","main road"],"example":"The main reason for his success is hard work.","exampleZh":"他成功的主要原因是努力工作。","synonyms":["primary","principal"],"level":2,"theme":"日常與一般"},{"word":"mainly","pos":"adv.","phonetic":"[ˈmenlɪ]","meaning":"主要地；大部分","definition":"mostly or for the most part","collocations":["mainly because","mainly due to"],"example":"The delay was mainly due to bad weather at the port.","exampleZh":"延誤主要是因為港口的惡劣天氣。","synonyms":["mostly","primarily"],"level":2,"theme":"日常與一般"},{"word":"maintain","pos":"v.","phonetic":"[menˈten]","meaning":"維持；維修","definition":"to make something continue at the same level, or to keep something in good condition","collocations":["maintain a relationship","maintain order","maintain equipment"],"example":"It is important to maintain a healthy diet.","exampleZh":"維持健康的飲食很重要。","synonyms":["sustain","preserve"],"level":4,"theme":"日常與一般"},{"word":"maintenance","pos":"n.","phonetic":"[ˈmentənəns]","meaning":"維護；保養","definition":"the process of keeping something in good condition","collocations":["regular maintenance","car maintenance","maintenance cost"],"example":"The car needs regular maintenance to run smoothly.","exampleZh":"這輛車需要定期保養才能順暢運作。","synonyms":["upkeep"],"level":5,"theme":"人事與職涯"},{"word":"major","pos":"adj. / v. / n.","phonetic":"[ˈmedʒɚ]","meaning":"主要的；主修","definition":"greater in importance, size, or amount; to study as a main subject","collocations":["major problem","major in","major role"],"example":"She decided to major in economics.","exampleZh":"她決定主修經濟學。","synonyms":["primary","main"],"level":3,"theme":"人事與職涯"},{"word":"majority","pos":"n.","phonetic":"[məˈdʒɔrətɪ]","meaning":"大多數","definition":"the larger part of a group of people or things","collocations":["vast majority","majority vote","majority of people"],"example":"The majority of students passed the exam.","exampleZh":"大多數學生都通過了考試。","synonyms":["most"],"level":4,"theme":"日常與一般"},{"word":"make","pos":"v.","phonetic":"[mek]","meaning":"製造；使得","definition":"to produce or create something","collocations":["make a decision","make a mistake","make money"],"example":"She made a delicious cake for the party.","exampleZh":"她為派對做了一個美味的蛋糕。","synonyms":["create","produce"],"level":1,"theme":"日常與一般"},{"word":"malfunction","pos":"n./v.","phonetic":"[mælˈfʌŋkʃən]","meaning":"故障；失靈","definition":"a failure to work correctly, or to fail in this way","collocations":["equipment malfunction","system malfunction","malfunctioning printer"],"example":"A software malfunction caused the checkout system to shut down.","exampleZh":"軟體故障導致結帳系統停擺。","synonyms":["failure","breakdown"],"level":5,"theme":"科技與通訊"},{"word":"mall","pos":"n.","phonetic":"[mɔl]","meaning":"購物中心","definition":"a large building or group of buildings containing many stores","collocations":["shopping mall","go to the mall","mall parking lot"],"example":"We spent the afternoon shopping at the mall.","exampleZh":"我們整個下午都在購物中心逛街。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"manage","pos":"v.","phonetic":"[ˈmænɪdʒ]","meaning":"管理；設法做到","definition":"to be in charge of something, or to succeed in doing something difficult","collocations":["manage a company","manage time","manage to survive"],"example":"She manages a small restaurant downtown.","exampleZh":"她在市中心經營一家小餐廳。","synonyms":["handle","run"],"level":3,"theme":"人事與職涯"},{"word":"management","pos":"n.","phonetic":"[ˈmænɪdʒmənt]","meaning":"管理","definition":"the control and organization of something","collocations":["time management","management team","business management"],"example":"Good time management can reduce stress.","exampleZh":"良好的時間管理可以減輕壓力。","synonyms":["administration"],"level":4,"theme":"財務與會計"},{"word":"manager","pos":"n.","phonetic":"[ˈmænɪdʒɚ]","meaning":"經理","definition":"a person responsible for controlling a business or department","collocations":["sales manager","hire a manager","manager's office"],"example":"The manager approved my vacation request.","exampleZh":"經理批准了我的休假申請。","synonyms":["supervisor"],"level":2,"theme":"人事與職涯"},{"word":"managerial","pos":"adj.","phonetic":"[ˌmænəˈdʒɪrɪəl]","meaning":"管理的；經理的","definition":"relating to the job of a manager","collocations":["managerial position","managerial experience","managerial skills"],"example":"The role requires at least three years of managerial experience.","exampleZh":"此職位需要至少三年的管理經驗。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"mandatory","pos":"adj.","phonetic":"[ˈmændəˌtorɪ]","meaning":"強制的；義務的","definition":"required by law or rules","collocations":["mandatory training","mandatory meeting","mandatory retirement"],"example":"Attendance at the safety briefing is mandatory for all staff.","exampleZh":"所有員工都必須參加安全簡報。","synonyms":["compulsory","required"],"level":5,"theme":"辦公室與行政"},{"word":"manner","pos":"n.","phonetic":"[ˈmænɚ]","meaning":"方式；態度","definition":"the way in which something is done or happens","collocations":["in a gentle manner","good manners","table manners"],"example":"He spoke to the children in a gentle manner.","exampleZh":"他用溫和的方式對孩子們說話。","synonyms":["way","style"],"level":3,"theme":"溝通與語言"},{"word":"manual","pos":"adj. / n.","phonetic":"[ˈmænjuəl]","meaning":"手動的；手冊","definition":"done with the hands; a book of instructions","collocations":["manual labor","instruction manual","manual transmission"],"example":"Please read the manual before using the machine.","exampleZh":"使用機器前請先閱讀說明書。","synonyms":["handbook"],"level":4,"theme":"科技與通訊"},{"word":"manually","pos":"adv.","phonetic":"[ˈmænjʊəlɪ]","meaning":"手動地；人工地","definition":"by hand rather than automatically","collocations":["enter manually","manually operated"],"example":"If the import fails, you can enter the data manually.","exampleZh":"如果匯入失敗，可以手動輸入資料。","synonyms":["by hand"],"level":4,"theme":"科技與通訊"},{"word":"manufacture","pos":"v. / n.","phonetic":"[ˌmænjəˈfæktʃɚ]","meaning":"製造","definition":"to make goods in large quantities using machinery","collocations":["manufacture cars","manufacturing process","locally manufactured"],"example":"The company manufactures electronic devices.","exampleZh":"這家公司製造電子產品。","synonyms":["produce"],"level":5,"theme":"人事與職涯"},{"word":"manufacturer","pos":"n.","phonetic":"[ˌmænjəˈfæktʃərɚ]","meaning":"製造商；廠商","definition":"a company that makes goods in large quantities","collocations":["car manufacturer","leading manufacturer","manufacturer's warranty"],"example":"The manufacturer will replace any parts that fail within two years.","exampleZh":"製造商將更換兩年內故障的任何零件。","synonyms":["maker","producer"],"level":3,"theme":"生產與物流"},{"word":"manufacturing","pos":"n./adj.","phonetic":"[ˌmænjəˈfæktʃərɪŋ]","meaning":"製造業；製造的","definition":"the business of producing goods in large numbers","collocations":["manufacturing plant","manufacturing costs","manufacturing process"],"example":"The company moved its manufacturing operations closer to its suppliers.","exampleZh":"公司將製造部門遷至更靠近供應商的地方。","synonyms":["production"],"level":4,"theme":"生產與物流"},{"word":"many","pos":"adj. / pron.","phonetic":"[ˈmɛnɪ]","meaning":"許多的","definition":"a large number of people or things","collocations":["many people","how many","so many"],"example":"Many students joined the club this year.","exampleZh":"今年有許多學生加入了這個社團。","synonyms":["numerous"],"level":1,"theme":"日常與一般"},{"word":"map","pos":"n.","phonetic":"[mæp]","meaning":"地圖","definition":"a drawing that shows the features of an area of land","collocations":["read a map","road map","map out a plan"],"example":"Use the map to find the fastest route.","exampleZh":"使用地圖找出最快的路線。","synonyms":["chart"],"level":1,"theme":"旅遊與交通"},{"word":"margin","pos":"n.","phonetic":"[ˈmɑrdʒɪn]","meaning":"頁邊空白；差額","definition":"the empty space at the edge of a page, or a difference in amount","collocations":["profit margin","in the margin","narrow margin"],"example":"He won the election by a narrow margin.","exampleZh":"他以些微差距贏得選舉。","synonyms":["edge","border"],"level":5,"theme":"財務與會計"},{"word":"market","pos":"n.","phonetic":"[ˈmɑrkɪt]","meaning":"市場","definition":"a place where goods are bought and sold","collocations":["farmers' market","stock market","market price"],"example":"We buy fresh vegetables at the market every Saturday.","exampleZh":"我們每週六都在市場買新鮮蔬菜。","synonyms":[],"level":2,"theme":"財務與會計"},{"word":"marketing","pos":"n.","phonetic":"[ˈmɑrkɪtɪŋ]","meaning":"行銷；市場行銷","definition":"the activity of promoting and selling products","collocations":["marketing campaign","marketing strategy","marketing department"],"example":"The marketing campaign doubled traffic to the online store.","exampleZh":"這波行銷活動讓網路商店的流量翻倍。","synonyms":["promotion"],"level":3,"theme":"行銷與銷售"},{"word":"marketplace","pos":"n.","phonetic":"[ˈmɑrkɪtˌples]","meaning":"市場；交易平台","definition":"the world of business and trade, or a place where goods are sold","collocations":["global marketplace","online marketplace","competitive marketplace"],"example":"Small brands can now reach customers through online marketplaces.","exampleZh":"小品牌現在可以透過線上交易平台接觸顧客。","synonyms":["market"],"level":4,"theme":"行銷與銷售"},{"word":"mass","pos":"n. / adj.","phonetic":"[mæs]","meaning":"大量；質量","definition":"a large amount or number of something; the quantity of matter in an object","collocations":["mass production","mass media","a mass of people"],"example":"The mass media influences public opinion.","exampleZh":"大眾媒體影響著公眾輿論。","synonyms":["bulk"],"level":4,"theme":"科技與通訊"},{"word":"massive","pos":"adj.","phonetic":"[ˈmæsɪv]","meaning":"巨大的","definition":"large and heavy or solid","collocations":["massive amount","massive building","massive success"],"example":"The company suffered massive losses last year.","exampleZh":"這家公司去年遭受巨大的損失。","synonyms":["huge","enormous"],"level":5,"theme":"日常與一般"},{"word":"master","pos":"n. / v.","phonetic":"[ˈmæstɚ]","meaning":"主人；精通","definition":"a person with control over something; to become skilled at something","collocations":["master a skill","master's degree","master the art"],"example":"It takes years to master a foreign language.","exampleZh":"要精通一門外語需要多年時間。","synonyms":["expert"],"level":3,"theme":"人事與職涯"},{"word":"match","pos":"n. / v.","phonetic":"[mætʃ]","meaning":"比賽；配對","definition":"a game between two teams or players; to be similar or suitable","collocations":["tennis match","match colors","perfect match"],"example":"The two teams will play a match tomorrow.","exampleZh":"這兩隊明天將進行一場比賽。","synonyms":["game","contest"],"level":2,"theme":"媒體與活動"},{"word":"material","pos":"n. / adj.","phonetic":"[məˈtɪrɪəl]","meaning":"材料；物質的","definition":"the substance from which something is made","collocations":["raw material","building material","material world"],"example":"Cotton is a common material for clothing.","exampleZh":"棉花是製作衣服的常見材料。","synonyms":["substance","fabric"],"level":3,"theme":"科技與通訊"},{"word":"matter","pos":"n. / v.","phonetic":"[ˈmætɚ]","meaning":"事情；重要","definition":"a subject or situation being discussed; to be important","collocations":["as a matter of fact","no matter what","matter of time"],"example":"It doesn't matter what others think of you.","exampleZh":"別人怎麼看你並不重要。","synonyms":["issue","affair"],"level":2,"theme":"日常與一般"},{"word":"mature","pos":"adj. / v.","phonetic":"[məˈtjʊr]","meaning":"成熟的","definition":"fully grown or developed, physically or mentally","collocations":["mature attitude","mature tree","grow mature"],"example":"She behaves in a mature way for her age.","exampleZh":"以她的年紀來說，她的行為相當成熟。","synonyms":["grown-up"],"level":4,"theme":"日常與一般"},{"word":"maximize","pos":"v.","phonetic":"[ˈmæksəˌmaɪz]","meaning":"最大化；充分利用","definition":"to increase something as much as possible","collocations":["maximize profits","maximize efficiency","maximize space"],"example":"The new shelving layout maximizes storage space in the warehouse.","exampleZh":"新的層架配置讓倉庫的儲存空間發揮到最大。","synonyms":["optimize"],"level":5,"theme":"企業經營"},{"word":"maximum","pos":"adj. / n.","phonetic":"[ˈmæksəməm]","meaning":"最大的；最大量","definition":"the greatest amount or number possible","collocations":["maximum speed","maximum capacity","reach a maximum"],"example":"The elevator has a maximum capacity of ten people.","exampleZh":"這台電梯的最大載重量為十人。","synonyms":["peak"],"level":4,"theme":"科技與通訊"},{"word":"may","pos":"v.","phonetic":"[me]","meaning":"可能；可以","definition":"used to express possibility or to ask for permission","collocations":["may I","it may rain","may as well"],"example":"It may rain later this afternoon.","exampleZh":"今天下午稍晚可能會下雨。","synonyms":["might"],"level":1,"theme":"日常與一般"},{"word":"maybe","pos":"adv.","phonetic":"[ˈmebɪ]","meaning":"也許","definition":"perhaps; possibly","collocations":["maybe later","maybe not","maybe so"],"example":"Maybe we should leave earlier tomorrow.","exampleZh":"也許我們明天應該早點出發。","synonyms":["perhaps"],"level":1,"theme":"日常與一般"},{"word":"mayor","pos":"n.","phonetic":"[ˈmeɚ]","meaning":"市長","definition":"the head of a city or town government","collocations":["elect a mayor","city mayor","mayor's office"],"example":"The mayor gave a speech at the ceremony.","exampleZh":"市長在典禮上發表了演說。","synonyms":[],"level":3,"theme":"合約與法律"},{"word":"meal","pos":"n.","phonetic":"[mil]","meaning":"一餐","definition":"the food eaten at one particular time","collocations":["have a meal","skip a meal","home-cooked meal"],"example":"We had a big meal to celebrate the holiday.","exampleZh":"我們吃了一頓豐盛的大餐來慶祝節日。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"mean","pos":"v. / adj.","phonetic":"[min]","meaning":"意指；小氣的","definition":"to intend to express or convey something; unkind or unwilling to spend","collocations":["mean well","what do you mean","mean to someone"],"example":"What do you mean by that comment?","exampleZh":"你那句話是什麼意思？","synonyms":["signify","unkind"],"level":2,"theme":"溝通與語言"},{"word":"meaning","pos":"n.","phonetic":"[ˈminɪŋ]","meaning":"意義","definition":"what is meant by a word, action, or concept","collocations":["true meaning","hidden meaning","meaning of life"],"example":"The teacher explained the meaning of the poem.","exampleZh":"老師解釋了這首詩的意義。","synonyms":["sense"],"level":2,"theme":"溝通與語言"},{"word":"means","pos":"n.","phonetic":"[minz]","meaning":"方法；手段；財力","definition":"a way of doing something, or the money someone has","collocations":["by means of","a means of transportation","within one's means"],"example":"Email remains the primary means of communication with clients.","exampleZh":"電子郵件仍是與客戶溝通的主要方式。","synonyms":["method","way"],"level":4,"theme":"日常與一般"},{"word":"meantime","pos":"n./adv.","phonetic":"[ˈminˌtaɪm]","meaning":"其間；同時","definition":"the time between two events","collocations":["in the meantime"],"example":"The elevator is being repaired; in the meantime, please use the stairs.","exampleZh":"電梯維修中，這段期間請走樓梯。","synonyms":["meanwhile"],"level":3,"theme":"日常與一般"},{"word":"meanwhile","pos":"adv.","phonetic":"[ˈminˌhwaɪl]","meaning":"同時；與此同時","definition":"at the same time, or during the intervening period","collocations":["in the meanwhile","meanwhile, elsewhere","meanwhile, at home"],"example":"Meanwhile, the rest of us waited outside.","exampleZh":"與此同時，我們其他人在外面等待。","synonyms":["simultaneously"],"level":4,"theme":"日常與一般"},{"word":"measure","pos":"v. / n.","phonetic":"[ˈmɛʒɚ]","meaning":"測量；措施","definition":"to find the size or amount of something; a plan of action","collocations":["measure length","take measures","safety measure"],"example":"The tailor measured my waist carefully.","exampleZh":"裁縫師仔細地量了我的腰圍。","synonyms":["gauge"],"level":3,"theme":"科技與通訊"},{"word":"measurement","pos":"n.","phonetic":"[ˈmɛʒɚmənt]","meaning":"測量；尺寸","definition":"the size, length, or amount of something found by measuring","collocations":["take measurements","accurate measurement","body measurements"],"example":"The tailor took his measurements for the suit.","exampleZh":"裁縫師量了他的尺寸來做西裝。","synonyms":["dimension"],"level":4,"theme":"科技與通訊"},{"word":"mechanic","pos":"n.","phonetic":"[məˈkænɪk]","meaning":"技工；機械工","definition":"a person who repairs and maintains machines, especially vehicles","collocations":["car mechanic","skilled mechanic","auto mechanic"],"example":"The mechanic fixed the car's engine in an hour.","exampleZh":"技工在一小時內修好了汽車引擎。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"mechanical","pos":"adj.","phonetic":"[məˈkænɪkl]","meaning":"機械的；機械故障的","definition":"relating to machines or produced by machines","collocations":["mechanical problem","mechanical failure","mechanical engineer"],"example":"The flight was delayed because of a minor mechanical problem.","exampleZh":"班機因輕微的機械問題而延誤。","synonyms":[],"level":4,"theme":"生產與物流"},{"word":"mechanism","pos":"n.","phonetic":"[ˈmɛkəˌnɪzəm]","meaning":"機制；機械裝置","definition":"a part of a machine, or a system for achieving something","collocations":["locking mechanism","feedback mechanism","safety mechanism"],"example":"The door's locking mechanism needs to be replaced.","exampleZh":"這扇門的鎖定裝置需要更換。","synonyms":["device","system"],"level":5,"theme":"科技與通訊"},{"word":"media","pos":"n.","phonetic":"[ˈmidɪə]","meaning":"媒體","definition":"the main means of mass communication, such as TV and the internet","collocations":["social media","news media","media coverage"],"example":"Social media has changed how we communicate.","exampleZh":"社群媒體改變了我們的溝通方式。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"mediate","pos":"v.","phonetic":"[ˈmidɪˌet]","meaning":"調解；斡旋","definition":"to help two sides in a disagreement reach an agreement","collocations":["mediate a dispute","mediate between"],"example":"An outside consultant was brought in to mediate the contract dispute.","exampleZh":"公司請來外部顧問調解合約糾紛。","synonyms":["arbitrate"],"level":6,"theme":"合約與法律"},{"word":"medical","pos":"adj.","phonetic":"[ˈmɛdɪkəl]","meaning":"醫學的；醫療的","definition":"relating to the treatment of illness and injuries","collocations":["medical care","medical treatment","medical school"],"example":"He needs immediate medical attention.","exampleZh":"他需要立即的醫療照護。","synonyms":[],"level":3,"theme":"醫療與保險"},{"word":"medication","pos":"n.","phonetic":"[ˌmɛdɪˈkeʃən]","meaning":"藥物；藥物治療","definition":"medicine used to treat an illness","collocations":["take medication","prescription medication","on medication"],"example":"Take this medication twice daily with food.","exampleZh":"此藥每日兩次，隨餐服用。","synonyms":["medicine","drug"],"level":4,"theme":"醫療與保險"},{"word":"medicine","pos":"n.","phonetic":"[ˈmɛdəsən]","meaning":"藥；醫學","definition":"a substance used to treat illness; the science of treating disease","collocations":["take medicine","cold medicine","study medicine"],"example":"Take this medicine twice a day after meals.","exampleZh":"請在飯後每天服用兩次這種藥。","synonyms":["drug"],"level":2,"theme":"醫療與保險"},{"word":"medium","pos":"adj. / n.","phonetic":"[ˈmidɪəm]","meaning":"中等的；媒介","definition":"middle in size or amount; a means by which something is communicated","collocations":["medium size","medium heat","communication medium"],"example":"I'd like a medium coffee, please.","exampleZh":"我要一杯中杯咖啡，謝謝。","synonyms":["average"],"level":3,"theme":"日常與一般"},{"word":"meet","pos":"v.","phonetic":"[mit]","meaning":"遇見；會面","definition":"to come together with someone by chance or arrangement","collocations":["meet a deadline","meet friends","nice to meet you"],"example":"Nice to meet you! I've heard so much about you.","exampleZh":"很高興認識你！久仰大名。","synonyms":["encounter"],"level":1,"theme":"日常與一般"},{"word":"meeting","pos":"n.","phonetic":"[ˈmitɪŋ]","meaning":"會議","definition":"a gathering of people for discussion","collocations":["attend a meeting","hold a meeting","business meeting"],"example":"The manager scheduled a meeting for Monday morning.","exampleZh":"經理安排了週一早上的會議。","synonyms":["conference"],"level":2,"theme":"人事與職涯"},{"word":"member","pos":"n.","phonetic":"[ˈmɛmbɚ]","meaning":"成員","definition":"a person who belongs to a group or organization","collocations":["family member","club member","become a member"],"example":"Every family member helped clean the house.","exampleZh":"每位家庭成員都幫忙打掃房子。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"membership","pos":"n.","phonetic":"[ˈmɛmbɚˌʃɪp]","meaning":"會員資格","definition":"the state of being a member of a group or club","collocations":["gym membership","apply for membership","annual membership"],"example":"She bought a gym membership for the new year.","exampleZh":"她為新的一年買了健身房會員資格。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"memo","pos":"n.","phonetic":"[ˈmɛmo]","meaning":"備忘錄；內部通知","definition":"a short written message sent within a company","collocations":["send a memo","internal memo","memo regarding"],"example":"A memo about the new parking policy was sent to all staff.","exampleZh":"關於新停車規定的內部通知已發送給全體員工。","synonyms":["memorandum","note"],"level":3,"theme":"辦公室與行政"},{"word":"memorable","pos":"adj.","phonetic":"[ˈmɛmərəbl]","meaning":"難忘的；值得紀念的","definition":"worth remembering or easy to remember","collocations":["memorable experience","memorable event","truly memorable"],"example":"The resort staff made our anniversary trip truly memorable.","exampleZh":"度假村的員工讓我們的週年旅行永生難忘。","synonyms":["unforgettable"],"level":4,"theme":"餐飲與住宿"},{"word":"memorandum","pos":"n.","phonetic":"[ˌmɛməˈrændəm]","meaning":"備忘錄；便箋","definition":"a formal written message within an organization, or a record of an agreement","collocations":["memorandum of understanding","issue a memorandum"],"example":"The two firms signed a memorandum of understanding on joint research.","exampleZh":"兩家公司就共同研究簽署了合作備忘錄。","synonyms":["memo"],"level":6,"theme":"合約與法律"},{"word":"memory","pos":"n.","phonetic":"[ˈmɛmərɪ]","meaning":"記憶；回憶","definition":"the ability to remember things, or something remembered","collocations":["good memory","childhood memory","memory loss"],"example":"She has fond memories of her childhood.","exampleZh":"她對童年有美好的回憶。","synonyms":["recollection"],"level":2,"theme":"日常與一般"},{"word":"mention","pos":"v. / n.","phonetic":"[ˈmɛnʃən]","meaning":"提及","definition":"to speak or write about something briefly","collocations":["mention a name","not to mention","mention in passing"],"example":"She didn't mention the accident to anyone.","exampleZh":"她沒有向任何人提及這場意外。","synonyms":["refer to"],"level":2,"theme":"溝通與語言"},{"word":"mentor","pos":"n./v.","phonetic":"[ˈmɛntɔr]","meaning":"導師；指導者；指導","definition":"an experienced person who helps someone less experienced","collocations":["assign a mentor","mentor program","mentor new employees"],"example":"Each new hire is paired with a mentor from their department.","exampleZh":"每位新進員工都會與部門內的一位導師配對。","synonyms":["adviser","coach"],"level":5,"theme":"人事與職涯"},{"word":"menu","pos":"n.","phonetic":"[ˈmɛnju]","meaning":"菜單","definition":"a list of dishes available in a restaurant","collocations":["order from the menu","dinner menu","menu item"],"example":"Could I see the menu, please?","exampleZh":"請問我可以看一下菜單嗎？","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"merchandise","pos":"n./v.","phonetic":"[ˈmɝtʃənˌdaɪz]","meaning":"商品；銷售商品","definition":"goods that are bought and sold","collocations":["general merchandise","display merchandise","official merchandise"],"example":"Damaged merchandise should be reported to the supplier immediately.","exampleZh":"商品若有損壞，應立即通報供應商。","synonyms":["goods","products"],"level":4,"theme":"購物與消費"},{"word":"merchant","pos":"n.","phonetic":"[ˈmɝtʃənt]","meaning":"商人","definition":"a person involved in buying and selling goods, especially on a large scale","collocations":["wealthy merchant","merchant ship","local merchant"],"example":"The merchant sold silk and spices from the East.","exampleZh":"這位商人販賣來自東方的絲綢和香料。","synonyms":["trader"],"level":4,"theme":"財務與會計"},{"word":"merely","pos":"adv.","phonetic":"[ˈmɪrlɪ]","meaning":"僅僅","definition":"just; only","collocations":["merely a suggestion","not merely","merely by chance"],"example":"I merely wanted to help, not to criticize.","exampleZh":"我只是想幫忙，並不是想批評。","synonyms":["simply","only"],"level":5,"theme":"日常與一般"},{"word":"merge","pos":"v.","phonetic":"[mɝdʒ]","meaning":"合併","definition":"to combine or join together to form one thing","collocations":["merge companies","merge lanes","merge into one"],"example":"The two companies decided to merge.","exampleZh":"這兩家公司決定合併。","synonyms":["combine","unite"],"level":5,"theme":"財務與會計"},{"word":"merger","pos":"n.","phonetic":"[ˈmɝdʒɚ]","meaning":"（公司）合併","definition":"the joining of two companies into one","collocations":["merger and acquisition","announce a merger","merger talks"],"example":"The merger created the largest retail chain in the region.","exampleZh":"這次合併造就了該地區最大的零售連鎖集團。","synonyms":["consolidation"],"level":5,"theme":"企業經營"},{"word":"merit","pos":"n.","phonetic":"[ˈmɛrɪt]","meaning":"優點；價值","definition":"the quality of being good or deserving praise","collocations":["merit system","on its own merits","artistic merit"],"example":"The proposal has some merit but needs revision.","exampleZh":"這項提案有一些優點，但需要修改。","synonyms":["worth","value"],"level":5,"theme":"日常與一般"},{"word":"message","pos":"n.","phonetic":"[ˈmɛsɪdʒ]","meaning":"訊息","definition":"a piece of information sent to or given to someone","collocations":["leave a message","text message","send a message"],"example":"I sent him a message about the meeting time.","exampleZh":"我傳了一則訊息告訴他會議時間。","synonyms":["note"],"level":2,"theme":"溝通與語言"},{"word":"messenger","pos":"n.","phonetic":"[ˈmɛsndʒɚ]","meaning":"信差；送信人","definition":"a person who delivers messages or documents","collocations":["bike messenger","send by messenger"],"example":"The signed documents were sent by messenger to the law firm.","exampleZh":"簽署好的文件由專人送往律師事務所。","synonyms":["courier"],"level":3,"theme":"辦公室與行政"},{"word":"metal","pos":"n.","phonetic":"[ˈmɛtəl]","meaning":"金屬","definition":"a solid material that is typically hard, shiny, and conducts electricity","collocations":["heavy metal","metal detector","made of metal"],"example":"The bridge is made of strong metal.","exampleZh":"這座橋是用堅固的金屬建造的。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"method","pos":"n.","phonetic":"[ˈmɛθəd]","meaning":"方法","definition":"a particular procedure for accomplishing something","collocations":["teaching method","scientific method","effective method"],"example":"This new method makes learning easier.","exampleZh":"這種新方法讓學習變得更容易。","synonyms":["approach","technique"],"level":3,"theme":"人事與職涯"},{"word":"metropolitan","pos":"adj.","phonetic":"[ˌmɛtrəˈpɑlətən]","meaning":"大都市的","definition":"relating to a large city or urban area","collocations":["metropolitan area","metropolitan life","metropolitan population"],"example":"The metropolitan area has a population of five million.","exampleZh":"這個大都會區的人口有五百萬。","synonyms":["urban"],"level":6,"theme":"日常與一般"},{"word":"microphone","pos":"n.","phonetic":"[ˈmaɪkrəˌfon]","meaning":"麥克風","definition":"a device used to make sound louder or record it","collocations":["speak into a microphone","wireless microphone","test the microphone"],"example":"The singer held the microphone close to her mouth.","exampleZh":"歌手把麥克風靠近嘴邊。","synonyms":["mic"],"level":3,"theme":"科技與通訊"},{"word":"microwave","pos":"n. / v.","phonetic":"[ˈmaɪkrəˌwev]","meaning":"微波爐；微波加熱","definition":"an oven that cooks or heats food using electromagnetic waves","collocations":["microwave oven","microwave dinner","heat in the microwave"],"example":"He heated the leftovers in the microwave.","exampleZh":"他用微波爐加熱剩菜。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"middle","pos":"n. / adj.","phonetic":"[ˈmɪdəl]","meaning":"中間的","definition":"the point or part equally distant from the edges or ends","collocations":["middle school","in the middle of","middle age"],"example":"She sat in the middle of the room.","exampleZh":"她坐在房間的中間。","synonyms":["center"],"level":1,"theme":"日常與一般"},{"word":"might","pos":"v. / n.","phonetic":"[maɪt]","meaning":"可能；力量","definition":"used to express possibility; great strength or power","collocations":["might as well","with all one's might","might rain"],"example":"It might rain tomorrow, so bring an umbrella.","exampleZh":"明天可能會下雨，所以帶把傘吧。","synonyms":["power","force"],"level":2,"theme":"日常與一般"},{"word":"mild","pos":"adj.","phonetic":"[maɪld]","meaning":"溫和的","definition":"not severe, harsh, or extreme","collocations":["mild weather","mild flavor","mild reaction"],"example":"The weather has been mild this winter.","exampleZh":"今年冬天天氣一直很溫和。","synonyms":["gentle"],"level":4,"theme":"日常與一般"},{"word":"mile","pos":"n.","phonetic":"[maɪl]","meaning":"英里","definition":"a unit of distance equal to about 1.6 kilometers","collocations":["run a mile","miles away","mile marker"],"example":"The store is about two miles from here.","exampleZh":"那家店距離這裡大約兩英里。","synonyms":[],"level":2,"theme":"旅遊與交通"},{"word":"mileage","pos":"n.","phonetic":"[ˈmaɪlɪdʒ]","meaning":"里程數；油耗；哩程","definition":"the distance a vehicle has traveled or can travel per unit of fuel","collocations":["low mileage","gas mileage","mileage allowance"],"example":"Employees receive a mileage allowance for using personal cars on business.","exampleZh":"員工因公使用私人車輛可領取里程補貼。","synonyms":[],"level":5,"theme":"旅遊與交通"},{"word":"milestone","pos":"n.","phonetic":"[ˈmaɪlˌston]","meaning":"里程碑；重要階段","definition":"an important event in the development of something","collocations":["reach a milestone","major milestone","project milestone"],"example":"Reaching one million users was a major milestone for the app.","exampleZh":"用戶數突破百萬是這款應用程式的重要里程碑。","synonyms":["landmark"],"level":5,"theme":"企業經營"},{"word":"million","pos":"n./num.","phonetic":"[ˈmɪljən]","meaning":"百萬","definition":"the number 1,000,000","collocations":["millions of dollars","a million users"],"example":"The company invested two million dollars in new equipment.","exampleZh":"公司投資兩百萬美元購置新設備。","synonyms":[],"level":1,"theme":"財務與會計"},{"word":"mind","pos":"n./v.","phonetic":"[maɪnd]","meaning":"心智；介意；注意","definition":"the part of you that thinks, or to be annoyed by something","collocations":["keep in mind","would you mind","change one's mind"],"example":"Please keep in mind that the deadline cannot be extended.","exampleZh":"請記住，截止期限無法延長。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"minimal","pos":"adj.","phonetic":"[ˈmɪnɪmḷ]","meaning":"最小的；極少的","definition":"of a very small amount or degree","collocations":["minimal effort","minimal risk","minimal impact"],"example":"The new design requires minimal maintenance.","exampleZh":"這個新設計只需要極少的維護。","synonyms":["slight","negligible"],"level":4,"theme":"日常與一般"},{"word":"minimize","pos":"v.","phonetic":"[ˈmɪnəˌmaɪz]","meaning":"使減到最少；最小化","definition":"to reduce something to the smallest possible amount","collocations":["minimize risk","minimize damage","minimize costs"],"example":"We should minimize waste whenever possible.","exampleZh":"我們應該盡可能減少浪費。","synonyms":["reduce","lessen"],"level":4,"theme":"日常與一般"},{"word":"minimum","pos":"n./adj.","phonetic":"[ˈmɪnəməm]","meaning":"最低限度；最小的","definition":"the smallest amount possible or allowed","collocations":["minimum wage","minimum order","keep to a minimum"],"example":"There is a minimum order of fifty units for wholesale prices.","exampleZh":"批發價的最低訂購量為五十件。","synonyms":[],"level":3,"theme":"財務與會計"},{"word":"minor","pos":"adj. / n.","phonetic":"[ˈmaɪnɚ]","meaning":"較小的；未成年人","definition":"not very important, serious, or dangerous; a person under legal age","collocations":["minor injury","minor issue","protect minors"],"example":"She suffered only minor injuries in the accident.","exampleZh":"她在意外中只受了輕傷。","synonyms":["slight","insignificant"],"level":3,"theme":"日常與一般"},{"word":"minority","pos":"n.","phonetic":"[maɪˈnɔrəti]","meaning":"少數；少數族群","definition":"the smaller part of a group, or a small group different from the rest","collocations":["ethnic minority","in the minority"],"example":"Only a minority of students disagreed with the plan.","exampleZh":"只有少數學生反對這項計畫。","synonyms":["few"],"level":4,"theme":"日常與一般"},{"word":"minute","pos":"adj.","phonetic":"[maɪˈnjut]","meaning":"極小的；微小的","definition":"extremely small in size or amount","collocations":["minute detail","a minute amount"],"example":"She noticed the minute differences between the two paintings.","exampleZh":"她注意到這兩幅畫之間的細微差異。","synonyms":["tiny","microscopic"],"level":5,"theme":"日常與一般"},{"word":"mirror","pos":"n. / v.","phonetic":"[ˈmɪrɚ]","meaning":"鏡子；反映","definition":"a reflective surface; to reflect or resemble closely","collocations":["look in the mirror","rearview mirror","mirror reality"],"example":"The lake surface mirrored the mountains perfectly.","exampleZh":"湖面完美地映照出群山的倒影。","synonyms":["reflect"],"level":2,"theme":"房產與設施"},{"word":"misplace","pos":"v.","phonetic":"[mɪsˈples]","meaning":"放錯地方；遺失","definition":"to put something in the wrong place and be unable to find it","collocations":["misplace your keys","misplace trust"],"example":"I misplaced my glasses again this morning.","exampleZh":"我今天早上又把眼鏡放錯地方找不到了。","synonyms":["lose","mislay"],"level":4,"theme":"日常與一般"},{"word":"miss","pos":"v./n.","phonetic":"[mɪs]","meaning":"錯過；未趕上；想念","definition":"to fail to catch, attend, or notice something","collocations":["miss a flight","miss a deadline","miss a meeting"],"example":"Leave early so you do not miss the connecting flight.","exampleZh":"請提早出發，以免錯過轉機航班。","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"missing","pos":"adj.","phonetic":"[ˈmɪsɪŋ]","meaning":"遺失的；缺少的","definition":"lost or not present when expected","collocations":["missing documents","missing items","go missing"],"example":"Report any missing items from your shipment within seven days.","exampleZh":"貨物若有缺件，請於七天內回報。","synonyms":["lost","absent"],"level":3,"theme":"生產與物流"},{"word":"mission","pos":"n.","phonetic":"[ˈmɪʃən]","meaning":"使命；任務","definition":"an important job or purpose, especially of an organization","collocations":["mission statement","company mission","complete a mission"],"example":"The company's mission is to make clean energy affordable for everyone.","exampleZh":"該公司的使命是讓人人都負擔得起潔淨能源。","synonyms":["purpose","goal"],"level":4,"theme":"企業經營"},{"word":"mistake","pos":"n. / v.","phonetic":"[məˈstek]","meaning":"錯誤；弄錯","definition":"an action or judgment that is incorrect","collocations":["make a mistake","by mistake","mistake one for another"],"example":"It was a mistake to sign the contract without reading it.","exampleZh":"沒讀就簽約是個錯誤。","synonyms":["error","blunder"],"level":2,"theme":"日常與一般"},{"word":"mistakenly","pos":"adv.","phonetic":"[məˈstekənlɪ]","meaning":"錯誤地；誤","definition":"in a wrong way because of a misunderstanding","collocations":["mistakenly believe","mistakenly sent"],"example":"The invoice was mistakenly sent to the old billing address.","exampleZh":"請款單被誤寄到舊的帳單地址。","synonyms":["wrongly","erroneously"],"level":5,"theme":"辦公室與行政"},{"word":"misunderstand","pos":"v.","phonetic":"[ˌmɪsʌndɚˈstænd]","meaning":"誤解；誤會","definition":"to fail to understand something correctly","collocations":["misunderstand a question","easily misunderstood"],"example":"Please don't misunderstand my intentions.","exampleZh":"請不要誤會我的意圖。","synonyms":["misinterpret"],"level":3,"theme":"溝通與語言"},{"word":"misunderstanding","pos":"n.","phonetic":"[ˌmɪsʌndɚˈstændɪŋ]","meaning":"誤解；誤會","definition":"a failure to understand something correctly","collocations":["avoid misunderstandings","clear up a misunderstanding"],"example":"To avoid misunderstandings, please confirm all orders in writing.","exampleZh":"為避免誤解，請以書面確認所有訂單。","synonyms":["confusion"],"level":4,"theme":"溝通與語言"},{"word":"mix","pos":"v./n.","phonetic":"[mɪks]","meaning":"混合；結合；組合","definition":"to combine things together, or a combination","collocations":["mix of products","mix ingredients","product mix"],"example":"The store offers a good mix of local and imported goods.","exampleZh":"這家店同時販售本地與進口商品，種類豐富。","synonyms":["blend","combine"],"level":1,"theme":"日常與一般"},{"word":"mixture","pos":"n.","phonetic":"[ˈmɪkstʃɚ]","meaning":"混合物；混合","definition":"a combination of different things or substances","collocations":["a mixture of","cake mixture"],"example":"The soup is a mixture of vegetables and spices.","exampleZh":"這道湯是蔬菜和香料的混合物。","synonyms":["blend","combination"],"level":3,"theme":"餐飲與住宿"},{"word":"mobile","pos":"adj.","phonetic":"[ˈmobl̩]","meaning":"可移動的；行動的","definition":"able to move or be moved easily","collocations":["mobile phone","mobile home","highly mobile"],"example":"She uses her mobile phone to check messages all day.","exampleZh":"她整天都用手機查看訊息。","synonyms":["movable","portable"],"level":2,"theme":"科技與通訊"},{"word":"mode","pos":"n.","phonetic":"[mod]","meaning":"方式；模式","definition":"a particular way or style of doing something","collocations":["mode of transport","silent mode","in a mode"],"example":"Please switch your phone to silent mode during the meeting.","exampleZh":"開會期間請把手機切換成靜音模式。","synonyms":["manner","method"],"level":4,"theme":"科技與通訊"},{"word":"model","pos":"n. / v.","phonetic":"[ˈmɑdl̩]","meaning":"模型；模特兒；作為榜樣","definition":"a representation of something, or a person who displays clothes","collocations":["role model","fashion model","build a model"],"example":"She is a good role model for young students.","exampleZh":"她是年輕學生的好榜樣。","synonyms":["example","prototype"],"level":2,"theme":"日常與一般"},{"word":"moderate","pos":"adj. / v.","phonetic":"[ˈmɑdərɪt]","meaning":"適度的；溫和的；緩和","definition":"average in amount or degree; not extreme","collocations":["moderate exercise","moderate temperature","moderate a discussion"],"example":"Doctors recommend moderate exercise every day.","exampleZh":"醫生建議每天做適度的運動。","synonyms":["reasonable","average"],"level":5,"theme":"日常與一般"},{"word":"moderator","pos":"n.","phonetic":"[ˈmɑdəˌretɚ]","meaning":"主持人；仲裁者","definition":"a person who leads a discussion and keeps it fair","collocations":["panel moderator","serve as moderator"],"example":"The moderator will introduce each speaker and manage the question time.","exampleZh":"主持人將介紹每位講者並掌控提問時間。","synonyms":["host","chair"],"level":5,"theme":"會議與簡報"},{"word":"modern","pos":"adj.","phonetic":"[ˈmɑdɚn]","meaning":"現代的；新式的","definition":"relating to the present time, not the past","collocations":["modern technology","modern society","modern art"],"example":"Modern technology has changed the way we communicate.","exampleZh":"現代科技已經改變了我們溝通的方式。","synonyms":["contemporary","current"],"level":2,"theme":"科技與通訊"},{"word":"modernize","pos":"v.","phonetic":"[ˈmɑdɚˌnaɪz]","meaning":"使現代化","definition":"to make something more modern","collocations":["modernize a factory","modernize equipment","modernize the system"],"example":"The company plans to modernize its factories next year.","exampleZh":"這家公司計畫明年將工廠現代化。","synonyms":["update","upgrade"],"level":5,"theme":"科技與通訊"},{"word":"modest","pos":"adj.","phonetic":"[ˈmɑdɪst]","meaning":"謙虛的；適度的","definition":"not talking much about one's own abilities; not large","collocations":["stay modest","modest income","modest success"],"example":"Despite his success, he remains modest and kind.","exampleZh":"儘管他成功了，他仍然謙虛又善良。","synonyms":["humble","moderate"],"level":4,"theme":"日常與一般"},{"word":"modification","pos":"n.","phonetic":"[ˌmɑdəfəˈkeʃən]","meaning":"修改；變更","definition":"a small change made to improve something","collocations":["make modifications","minor modification","design modification"],"example":"The client requested several modifications to the original design.","exampleZh":"客戶要求對原始設計做幾處修改。","synonyms":["alteration","change"],"level":5,"theme":"企業經營"},{"word":"modify","pos":"v.","phonetic":"[ˈmɑdəˌfaɪ]","meaning":"修改；調整","definition":"to change something slightly","collocations":["modify a plan","modify behavior","modify a design"],"example":"We need to modify our plan due to the weather.","exampleZh":"由於天氣因素，我們需要修改計畫。","synonyms":["adjust","alter"],"level":4,"theme":"日常與一般"},{"word":"moment","pos":"n.","phonetic":"[ˈmomənt]","meaning":"片刻；瞬間","definition":"a very short period of time","collocations":["at the moment","for a moment","a special moment"],"example":"Please wait a moment while I check the schedule.","exampleZh":"請稍等片刻，我確認一下行程。","synonyms":["instant","second"],"level":1,"theme":"日常與一般"},{"word":"momentum","pos":"n.","phonetic":"[moˈmɛntəm]","meaning":"動力；氣勢","definition":"the force that keeps an object moving or a process developing","collocations":["gain momentum","lose momentum","build momentum"],"example":"The campaign gained momentum after the news coverage.","exampleZh":"這場活動在新聞報導後聲勢大增。","synonyms":["impetus","drive"],"level":6,"theme":"日常與一般"},{"word":"monetary","pos":"adj.","phonetic":"[ˈmɑnəˌtɛri]","meaning":"貨幣的；金錢的","definition":"relating to money","collocations":["monetary policy","monetary value","monetary system"],"example":"The bank changed its monetary policy last month.","exampleZh":"銀行上個月改變了貨幣政策。","synonyms":["financial"],"level":6,"theme":"財務與會計"},{"word":"money","pos":"n.","phonetic":"[ˈmʌni]","meaning":"金錢；錢","definition":"what is used to buy and sell things","collocations":["make money","save money","spend money"],"example":"He works hard to earn money for his family.","exampleZh":"他努力工作為家人賺錢。","synonyms":["cash","currency"],"level":1,"theme":"財務與會計"},{"word":"monitor","pos":"n. / v.","phonetic":"[ˈmɑnətɚ]","meaning":"螢幕；監視器；監控","definition":"a screen for displaying information; to watch and check something","collocations":["computer monitor","monitor progress","monitor closely"],"example":"The teacher will monitor the students' progress every week.","exampleZh":"老師每週都會監控學生的學習進度。","synonyms":["screen","observe"],"level":3,"theme":"科技與通訊"},{"word":"month","pos":"n.","phonetic":"[mʌnθ]","meaning":"月份","definition":"one of the twelve periods that a year is divided into","collocations":["last month","next month","a month ago"],"example":"We are going on vacation next month.","exampleZh":"我們下個月要去度假。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"monthly","pos":"adj. / adv.","phonetic":"[ˈmʌnθli]","meaning":"每月的；每月一次","definition":"happening or done once a month","collocations":["monthly fee","monthly report","paid monthly"],"example":"The gym charges a monthly fee for membership.","exampleZh":"健身房收取每月的會員費。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"more","pos":"adj. / adv. / pron.","phonetic":"[mɔr]","meaning":"更多的；更","definition":"a greater or additional amount or degree","collocations":["more than","much more","one more"],"example":"I need more time to finish this project.","exampleZh":"我需要更多時間完成這個專案。","synonyms":["additional"],"level":1,"theme":"日常與一般"},{"word":"moreover","pos":"adv.","phonetic":"[mɔrˈovɚ]","meaning":"此外；而且","definition":"in addition to what has just been said","collocations":["moreover, ...","moreover it is clear"],"example":"The plan is expensive; moreover, it may not even work.","exampleZh":"這個計畫很昂貴，此外還可能行不通。","synonyms":["furthermore","besides"],"level":5,"theme":"溝通與語言"},{"word":"morning","pos":"n.","phonetic":"[ˈmɔrnɪŋ]","meaning":"早晨；上午","definition":"the early part of the day","collocations":["good morning","this morning","every morning"],"example":"She goes jogging every morning before school.","exampleZh":"她每天早上上學前都去慢跑。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"mortgage","pos":"n.","phonetic":"[ˈmɔrgɪdʒ]","meaning":"房屋貸款；抵押貸款","definition":"a loan used to buy a house or land","collocations":["pay off a mortgage","mortgage payment","take out a mortgage"],"example":"They took out a mortgage to buy their first house.","exampleZh":"他們貸款買了第一間房子。","synonyms":["loan"],"level":6,"theme":"財務與會計"},{"word":"most","pos":"adj. / adv. / pron.","phonetic":"[most]","meaning":"最多的；大部分","definition":"the greatest amount or number","collocations":["most people","at most","most of all"],"example":"Most students finished the exam on time.","exampleZh":"大部分學生都準時完成了考試。","synonyms":["majority"],"level":1,"theme":"日常與一般"},{"word":"mostly","pos":"adv.","phonetic":"[ˈmostli]","meaning":"大多；主要地","definition":"mainly or generally","collocations":["mostly true","mostly sunny","mostly used"],"example":"The weather this week was mostly sunny.","exampleZh":"這週的天氣大多是晴朗的。","synonyms":["mainly","largely"],"level":3,"theme":"日常與一般"},{"word":"motel","pos":"n.","phonetic":"[moˈtɛl]","meaning":"汽車旅館","definition":"a hotel for travelers by car, usually near a road","collocations":["cheap motel","stay at a motel","roadside motel"],"example":"We stayed at a motel by the highway during our road trip.","exampleZh":"我們公路旅行時住在高速公路旁的一間汽車旅館。","synonyms":[],"level":2,"theme":"旅遊與交通"},{"word":"motion","pos":"n.","phonetic":"[ˈmoʃən]","meaning":"動作；運動；提議","definition":"the action or process of moving","collocations":["in motion","slow motion","set in motion"],"example":"The camera captured the ball's motion in slow motion.","exampleZh":"攝影機以慢動作捕捉了球的移動軌跡。","synonyms":["movement"],"level":4,"theme":"媒體與活動"},{"word":"motivate","pos":"v.","phonetic":"[ˈmotəˌvet]","meaning":"激勵；激發動機","definition":"to give someone a reason to do something","collocations":["motivate students","motivate employees","highly motivated"],"example":"Good teachers know how to motivate their students.","exampleZh":"好老師懂得如何激勵學生。","synonyms":["inspire","encourage"],"level":4,"theme":"人事與職涯"},{"word":"motivation","pos":"n.","phonetic":"[ˌmotəˈveʃən]","meaning":"動機；動力","definition":"a reason or enthusiasm for doing something","collocations":["lack of motivation","source of motivation","find motivation"],"example":"Her motivation to succeed comes from her family.","exampleZh":"她成功的動力來自她的家人。","synonyms":["drive","incentive"],"level":4,"theme":"日常與一般"},{"word":"motor","pos":"n.","phonetic":"[ˈmotɚ]","meaning":"馬達；引擎","definition":"a machine that produces motion or power","collocations":["electric motor","motor vehicle","start the motor"],"example":"The electric motor powers the small fan.","exampleZh":"這台電動馬達為小型風扇提供動力。","synonyms":["engine"],"level":3,"theme":"科技與通訊"},{"word":"move","pos":"v. / n.","phonetic":"[muv]","meaning":"移動；搬家","definition":"to change position or location","collocations":["move house","move forward","a smart move"],"example":"We plan to move to a bigger apartment next year.","exampleZh":"我們計畫明年搬到更大的公寓。","synonyms":["shift","relocate"],"level":1,"theme":"日常與一般"},{"word":"movement","pos":"n.","phonetic":"[ˈmuvmənt]","meaning":"移動；運動；動作","definition":"an act of moving; an organized group working for a cause","collocations":["social movement","free movement","sudden movement"],"example":"The civil rights movement changed history forever.","exampleZh":"民權運動永遠改變了歷史。","synonyms":["motion"],"level":3,"theme":"日常與一般"},{"word":"movie","pos":"n.","phonetic":"[ˈmuvi]","meaning":"電影","definition":"a film shown at a cinema or on television","collocations":["watch a movie","movie theater","favorite movie"],"example":"We watched a great movie together last weekend.","exampleZh":"我們上週末一起看了一部很棒的電影。","synonyms":["film"],"level":1,"theme":"媒體與活動"},{"word":"much","pos":"adj. / adv. / pron.","phonetic":"[mʌtʃ]","meaning":"許多；很","definition":"a large amount of something","collocations":["so much","too much","much better"],"example":"Thank you so much for your help.","exampleZh":"非常感謝你的幫忙。","synonyms":["a lot"],"level":1,"theme":"日常與一般"},{"word":"multiple","pos":"adj.","phonetic":"[ˈmʌltəpl̩]","meaning":"多個的；多樣的","definition":"more than one; many","collocations":["multiple choices","multiple times","multiple reasons"],"example":"There are multiple reasons why the project failed.","exampleZh":"這個專案失敗有很多原因。","synonyms":["numerous"],"level":4,"theme":"日常與一般"},{"word":"museum","pos":"n.","phonetic":"[mjuˈziəm]","meaning":"博物館","definition":"a building where art or historical objects are shown","collocations":["visit a museum","art museum","museum exhibit"],"example":"We visited the art museum during our trip to the city.","exampleZh":"我們在城市之旅中參觀了美術館。","synonyms":[],"level":2,"theme":"媒體與活動"},{"word":"must","pos":"v. / n.","phonetic":"[mʌst]","meaning":"必須；必要的事物","definition":"used to show that something is necessary","collocations":["must-have","must do","you must"],"example":"You must wear a helmet when riding a motorcycle.","exampleZh":"你騎摩托車時必須戴安全帽。","synonyms":["have to"],"level":1,"theme":"日常與一般"},{"word":"mutual","pos":"adj.","phonetic":"[ˈmjutʃuəl]","meaning":"互相的；共同的","definition":"felt or done equally by two or more people","collocations":["mutual respect","mutual friend","mutual agreement"],"example":"Their friendship is built on mutual respect and trust.","exampleZh":"他們的友誼建立在互相尊重與信任之上。","synonyms":["reciprocal","common"],"level":5,"theme":"日常與一般"},{"word":"mutually","pos":"adv.","phonetic":"[ˈmjutʃʊəlɪ]","meaning":"互相地；彼此","definition":"felt or done by two or more people toward each other","collocations":["mutually beneficial","mutually agreed","mutually exclusive"],"example":"The partnership has been mutually beneficial for both companies.","exampleZh":"這項合作對兩家公司都互蒙其利。","synonyms":[],"level":5,"theme":"企業經營"},{"word":"name","pos":"n. / v.","phonetic":"[nem]","meaning":"名字；名稱；為…命名","definition":"a word or set of words by which a person, animal, place, or thing is known","collocations":["first name","call someone names","name after"],"example":"My name is written on the first page of the book.","exampleZh":"我的名字寫在這本書的第一頁上。","synonyms":["title","label"],"level":1,"theme":"日常與一般"},{"word":"namely","pos":"adv.","phonetic":"[ˈnemlɪ]","meaning":"即；也就是","definition":"that is to say; used to introduce something specific","collocations":["namely that","two options, namely"],"example":"There is one main reason, namely, the high cost.","exampleZh":"有一個主要原因，那就是高昂的成本。","synonyms":["that is"],"level":5,"theme":"溝通與語言"},{"word":"narrow","pos":"adj. / v.","phonetic":"[ˈnæro]","meaning":"狹窄的；勉強的；使變窄","definition":"having a small distance from one side to the other","collocations":["narrow street","narrow escape","narrow down"],"example":"The car could barely fit through the narrow street.","exampleZh":"這輛車幾乎無法通過這條狹窄的街道。","synonyms":["thin","tight"],"level":2,"theme":"日常與一般"},{"word":"national","pos":"adj.","phonetic":"[ˈnæʃənl]","meaning":"國家的；全國性的","definition":"relating to or belonging to a particular nation","collocations":["national holiday","national park","national anthem"],"example":"Independence Day is a national holiday.","exampleZh":"獨立紀念日是一個全國性的假日。","synonyms":["nationwide"],"level":2,"theme":"日常與一般"},{"word":"nationwide","pos":"adj. / adv.","phonetic":"[ˈneʃənˌwaɪd]","meaning":"全國性的；全國範圍地","definition":"extending over or including a whole nation","collocations":["nationwide survey","nationwide campaign","broadcast nationwide"],"example":"The company launched a nationwide advertising campaign.","exampleZh":"這家公司發起了一場全國性的廣告活動。","synonyms":["national"],"level":4,"theme":"日常與一般"},{"word":"native","pos":"adj. / n.","phonetic":"[ˈnetɪv]","meaning":"本地的；本土的；當地人","definition":"belonging to a particular place by birth","collocations":["native speaker","native language","native to"],"example":"She is a native speaker of French.","exampleZh":"她是法語的母語人士。","synonyms":["local","indigenous"],"level":3,"theme":"日常與一般"},{"word":"natural","pos":"adj.","phonetic":"[ˈnætʃərəl]","meaning":"自然的；天生的；正常的","definition":"existing in nature and not made or caused by people","collocations":["natural resources","natural disaster","natural talent"],"example":"Earthquakes are natural disasters that can cause great damage.","exampleZh":"地震是一種能造成巨大破壞的自然災害。","synonyms":["genuine","innate"],"level":2,"theme":"日常與一般"},{"word":"naturally","pos":"adv.","phonetic":"[ˈnætʃərəlɪ]","meaning":"自然地；天生地；當然","definition":"in a natural way; of course","collocations":["naturally curly","behave naturally","naturally gifted"],"example":"Naturally, she was upset when she heard the news.","exampleZh":"她聽到這消息時當然很沮喪。","synonyms":["of course"],"level":2,"theme":"日常與一般"},{"word":"nature","pos":"n.","phonetic":"[ˈnetʃɚ]","meaning":"大自然；本性；本質","definition":"the physical world and everything in it that is not made by humans","collocations":["the nature of","human nature","love nature"],"example":"He loves spending time in nature.","exampleZh":"他喜歡花時間親近大自然。","synonyms":["environment","character"],"level":2,"theme":"日常與一般"},{"word":"navigate","pos":"v.","phonetic":"[ˈnævəˌget]","meaning":"導航；航行；探索","definition":"to plan and direct the route of a ship, aircraft, or vehicle","collocations":["navigate a ship","navigate the internet","navigate through"],"example":"The captain used a map to navigate the ship safely.","exampleZh":"船長使用地圖安全地為船隻導航。","synonyms":["steer","guide"],"level":5,"theme":"旅遊與交通"},{"word":"navigation","pos":"n.","phonetic":"[ˌnævəˈgeʃən]","meaning":"導航；航行術","definition":"the process or activity of planning a route and guiding movement","collocations":["GPS navigation","navigation system","satellite navigation"],"example":"The ship's navigation system guided it through the storm.","exampleZh":"這艘船的導航系統引導它穿過暴風雨。","synonyms":[],"level":5,"theme":"旅遊與交通"},{"word":"near","pos":"adv. / prep. / adj.","phonetic":"[nɪr]","meaning":"接近；靠近的","definition":"a short distance away in space or time","collocations":["near future","live near","draw near"],"example":"The school is near my house.","exampleZh":"學校離我家很近。","synonyms":["close","nearby"],"level":1,"theme":"日常與一般"},{"word":"nearby","pos":"adj. / adv.","phonetic":"[ˈnɪrˌbaɪ]","meaning":"附近的；在附近","definition":"not far away in distance","collocations":["nearby town","live nearby","a nearby restaurant"],"example":"We had dinner at a nearby restaurant.","exampleZh":"我們在附近的一家餐廳吃了晚餐。","synonyms":["close","near"],"level":2,"theme":"日常與一般"},{"word":"nearly","pos":"adv.","phonetic":"[ˈnɪrlɪ]","meaning":"幾乎；差不多","definition":"almost but not quite","collocations":["nearly finished","nearly every day","nearly impossible"],"example":"It's nearly midnight, so we should go to bed.","exampleZh":"現在快午夜了，我們應該去睡覺了。","synonyms":["almost"],"level":2,"theme":"日常與一般"},{"word":"neat","pos":"adj.","phonetic":"[nit]","meaning":"整潔的；乾淨俐落的","definition":"tidy and in good order","collocations":["neat and tidy","neat handwriting","keep neat"],"example":"She keeps her room neat and clean.","exampleZh":"她把房間保持得整潔乾淨。","synonyms":["tidy","orderly"],"level":2,"theme":"日常與一般"},{"word":"necessarily","pos":"adv.","phonetic":"[ˌnɛsəˈsɛrəlɪ]","meaning":"必然地；一定","definition":"as a necessary result; inevitably","collocations":["not necessarily true","necessarily mean"],"example":"Being rich doesn't necessarily mean being happy.","exampleZh":"富有並不一定代表快樂。","synonyms":["inevitably"],"level":4,"theme":"日常與一般"},{"word":"necessary","pos":"adj.","phonetic":"[ˈnɛsəˌsɛrɪ]","meaning":"必要的；必需的","definition":"needed in order to achieve a certain result","collocations":["necessary condition","if necessary","absolutely necessary"],"example":"Water is necessary for all forms of life.","exampleZh":"水對所有生命形式都是必需的。","synonyms":["essential","required"],"level":2,"theme":"日常與一般"},{"word":"necessity","pos":"n.","phonetic":"[nəˈsɛsətɪ]","meaning":"必要性；必需品","definition":"the fact of being required or indispensable","collocations":["out of necessity","basic necessity","a necessity of life"],"example":"Clean water is a basic necessity for survival.","exampleZh":"乾淨的水是生存的基本必需品。","synonyms":["requirement"],"level":4,"theme":"日常與一般"},{"word":"need","pos":"v. / n.","phonetic":"[nid]","meaning":"需要；需求","definition":"to require something because it is essential","collocations":["in need of","need help","basic needs"],"example":"Plants need sunlight and water to grow.","exampleZh":"植物需要陽光和水才能生長。","synonyms":["require","want"],"level":1,"theme":"日常與一般"},{"word":"needless","pos":"adj.","phonetic":"[ˈnidlɪs]","meaning":"不必要的","definition":"not necessary and easily avoided","collocations":["needless to say","needless expense","needless delay"],"example":"Needless to say, all travel costs will be reimbursed by the company.","exampleZh":"不用說，所有差旅費用都將由公司報銷。","synonyms":["unnecessary"],"level":5,"theme":"日常與一般"},{"word":"negative","pos":"adj. / n.","phonetic":"[ˈnɛgətɪv]","meaning":"負面的；消極的；否定的","definition":"expressing denial, refusal, or the presence of something bad","collocations":["negative effect","negative attitude","test negative"],"example":"Try not to think in such a negative way.","exampleZh":"試著不要那樣負面地思考。","synonyms":["pessimistic","unfavorable"],"level":3,"theme":"日常與一般"},{"word":"negotiable","pos":"adj.","phonetic":"[nɪˈgoʃɪəbl]","meaning":"可協商的；可談判的","definition":"able to be changed or agreed through discussion","collocations":["salary negotiable","price is negotiable","non-negotiable"],"example":"The salary for this position is negotiable based on experience.","exampleZh":"此職位的薪資可依經驗面議。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"negotiate","pos":"v.","phonetic":"[nɪˈgoʃɪˌet]","meaning":"談判；協商","definition":"to have formal discussions to reach an agreement","collocations":["negotiate a deal","negotiate with","negotiate a price"],"example":"The two companies negotiated a new contract.","exampleZh":"兩家公司協商了一份新合約。","synonyms":["bargain","discuss"],"level":4,"theme":"財務與會計"},{"word":"negotiation","pos":"n.","phonetic":"[nɪˌgoʃɪˈeʃən]","meaning":"談判；協商","definition":"discussion aimed at reaching an agreement","collocations":["peace negotiation","under negotiation","negotiation skills"],"example":"The negotiation between the two countries lasted for months.","exampleZh":"兩國之間的談判持續了好幾個月。","synonyms":["bargaining"],"level":5,"theme":"財務與會計"},{"word":"neighbor","pos":"n.","phonetic":"[ˈnebɚ]","meaning":"鄰居","definition":"a person who lives near another person","collocations":["next-door neighbor","good neighbor","noisy neighbor"],"example":"Our neighbor helped us carry the boxes.","exampleZh":"我們的鄰居幫我們搬箱子。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"neighborhood","pos":"n.","phonetic":"[ˈnebɚˌhʊd]","meaning":"鄰近地區；社區","definition":"a district or area, especially one forming a community","collocations":["quiet neighborhood","in the neighborhood","neighborhood watch"],"example":"They live in a quiet neighborhood near the park.","exampleZh":"他們住在公園附近的一個安靜社區。","synonyms":["community","area"],"level":3,"theme":"房產與設施"},{"word":"neither","pos":"pron. / conj. / adj.","phonetic":"[ˈniðɚ]","meaning":"兩者都不","definition":"not either of two people or things","collocations":["neither...nor","neither of us","neither option"],"example":"Neither of the two answers is correct.","exampleZh":"這兩個答案都不正確。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"nervous","pos":"adj.","phonetic":"[ˈnɝvəs]","meaning":"緊張的；不安的","definition":"anxious or worried about something","collocations":["nervous about","nervous breakdown","feel nervous"],"example":"She felt nervous before the exam.","exampleZh":"她考試前感到很緊張。","synonyms":["anxious","uneasy"],"level":2,"theme":"日常與一般"},{"word":"net","pos":"n. / adj.","phonetic":"[nɛt]","meaning":"網子；淨的","definition":"a material made of threads woven together with small holes","collocations":["fishing net","net income","surf the net"],"example":"The fisherman cast his net into the sea.","exampleZh":"漁夫把網子撒進海裡。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"network","pos":"n.","phonetic":"[ˈnɛtˌwɝk]","meaning":"網路；人脈；網狀系統","definition":"a group of interconnected people, computers, or things","collocations":["social network","computer network","build a network"],"example":"She has a large network of friends and colleagues.","exampleZh":"她有一個龐大的朋友和同事人際網絡。","synonyms":["system"],"level":3,"theme":"科技與通訊"},{"word":"networking","pos":"n.","phonetic":"[ˈnɛtˌwɝkɪŋ]","meaning":"建立人脈；網路連接","definition":"the activity of meeting people who might be useful for your work","collocations":["networking event","networking opportunities","professional networking"],"example":"The conference includes several networking events for young professionals.","exampleZh":"這場會議為年輕專業人士安排了多場人脈交流活動。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"nevertheless","pos":"adv.","phonetic":"[ˌnɛvɚðəˈlɛs]","meaning":"儘管如此；然而","definition":"in spite of that; nonetheless","collocations":["nevertheless, he tried","difficult nevertheless"],"example":"The task was difficult; nevertheless, she finished it.","exampleZh":"這項任務很困難，儘管如此她還是完成了。","synonyms":["however","nonetheless"],"level":5,"theme":"溝通與語言"},{"word":"new","pos":"adj.","phonetic":"[nju]","meaning":"新的；新鮮的","definition":"not existing before; recently made or discovered","collocations":["brand new","new year","new idea"],"example":"He bought a new car last week.","exampleZh":"他上週買了一輛新車。","synonyms":["fresh","recent"],"level":1,"theme":"日常與一般"},{"word":"newly","pos":"adv.","phonetic":"[ˈnjulɪ]","meaning":"新近；最近","definition":"recently or just now","collocations":["newly opened","newly appointed","newly renovated"],"example":"The newly renovated lobby features a coffee bar and lounge area.","exampleZh":"新裝修的大廳設有咖啡吧和休息區。","synonyms":["recently","freshly"],"level":3,"theme":"日常與一般"},{"word":"news","pos":"n.","phonetic":"[njuz]","meaning":"新聞；消息","definition":"information about recent events","collocations":["breaking news","good news","watch the news"],"example":"Did you watch the news last night?","exampleZh":"你昨晚看新聞了嗎？","synonyms":["information"],"level":1,"theme":"科技與通訊"},{"word":"newsletter","pos":"n.","phonetic":"[ˈnjuzˌlɛtɚ]","meaning":"電子報；通訊刊物","definition":"a regular report with news sent to members or subscribers","collocations":["monthly newsletter","subscribe to a newsletter","company newsletter"],"example":"Subscribe to our newsletter for exclusive deals and updates.","exampleZh":"訂閱我們的電子報，即可獲得獨家優惠與最新消息。","synonyms":["bulletin"],"level":3,"theme":"行銷與銷售"},{"word":"newspaper","pos":"n.","phonetic":"[ˈnjuzˌpepɚ]","meaning":"報紙","definition":"a printed publication containing news and articles","collocations":["read the newspaper","daily newspaper","local newspaper"],"example":"My grandfather reads the newspaper every morning.","exampleZh":"我祖父每天早上都看報紙。","synonyms":["paper"],"level":1,"theme":"科技與通訊"},{"word":"next","pos":"adj. / adv.","phonetic":"[nɛkst]","meaning":"下一個的；接下來","definition":"coming immediately after the present one","collocations":["next week","next to","next door"],"example":"We will meet again next Friday.","exampleZh":"我們下週五會再見面。","synonyms":["following"],"level":1,"theme":"日常與一般"},{"word":"nice","pos":"adj.","phonetic":"[naɪs]","meaning":"好的；友善的；令人愉快的","definition":"pleasant, enjoyable, or satisfactory","collocations":["nice to meet you","nice weather","be nice to"],"example":"It was nice to meet you.","exampleZh":"很高興認識你。","synonyms":["pleasant","kind"],"level":1,"theme":"日常與一般"},{"word":"night","pos":"n.","phonetic":"[naɪt]","meaning":"夜晚","definition":"the time from sunset to sunrise","collocations":["last night","good night","night shift"],"example":"The stars are bright tonight.","exampleZh":"今晚星星很明亮。","synonyms":["evening"],"level":1,"theme":"日常與一般"},{"word":"noise","pos":"n.","phonetic":"[nɔɪz]","meaning":"噪音；聲響","definition":"a sound, especially a loud or unpleasant one","collocations":["loud noise","make noise","background noise"],"example":"The construction noise woke me up early.","exampleZh":"施工的噪音把我很早就吵醒了。","synonyms":["sound","racket"],"level":1,"theme":"房產與設施"},{"word":"nominate","pos":"v.","phonetic":"[ˈnɑməˌnet]","meaning":"提名；任命","definition":"to officially suggest someone for a position or award","collocations":["nominate for an award","nominate a candidate"],"example":"Employees may nominate a colleague for the service excellence award.","exampleZh":"員工可以提名同事角逐服務卓越獎。","synonyms":["propose"],"level":5,"theme":"人事與職涯"},{"word":"nomination","pos":"n.","phonetic":"[ˌnɑməˈneʃən]","meaning":"提名","definition":"the act of proposing someone for a position or award","collocations":["receive a nomination","Oscar nomination","nomination for president"],"example":"The actress received a nomination for best actress.","exampleZh":"這位女演員獲得最佳女主角提名。","synonyms":[],"level":5,"theme":"合約與法律"},{"word":"nominee","pos":"n.","phonetic":"[ˌnɑməˈni]","meaning":"被提名人","definition":"a person who has been suggested for a position or prize","collocations":["award nominee","announce the nominees"],"example":"The nominees for employee of the year will be announced Friday.","exampleZh":"年度最佳員工的被提名人將於週五公布。","synonyms":["candidate"],"level":5,"theme":"人事與職涯"},{"word":"non-refundable","pos":"adj.","phonetic":"[ˌnɑnrɪˈfʌndəbl]","meaning":"不可退款的","definition":"describing money that cannot be returned after payment","collocations":["non-refundable deposit","non-refundable ticket"],"example":"A non-refundable deposit of one hundred dollars is required to book.","exampleZh":"預訂需支付一百美元不可退還的訂金。","synonyms":[],"level":5,"theme":"購物與消費"},{"word":"nonprofit","pos":"adj.","phonetic":"[ˌnɑnˈprɑfɪt]","meaning":"非營利的","definition":"not conducted or maintained for the purpose of making a profit","collocations":["nonprofit organization","nonprofit sector"],"example":"She works for a nonprofit organization that helps the homeless.","exampleZh":"她在一個幫助無家可歸者的非營利組織工作。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"nonstop","pos":"adj. / adv.","phonetic":"[ˈnɑnˈstɑp]","meaning":"不停的；直達的","definition":"without any stops or breaks","collocations":["nonstop flight","talk nonstop","work nonstop"],"example":"We took a nonstop flight from Taipei to New York.","exampleZh":"我們搭了從台北直飛紐約的班機。","synonyms":["continuous"],"level":4,"theme":"旅遊與交通"},{"word":"noon","pos":"n.","phonetic":"[nun]","meaning":"正午；中午","definition":"twelve o'clock in the middle of the day","collocations":["at noon","before noon","noon break"],"example":"We will meet at noon for lunch.","exampleZh":"我們中午見面吃午餐。","synonyms":["midday"],"level":1,"theme":"日常與一般"},{"word":"normal","pos":"adj.","phonetic":"[ˈnɔrml]","meaning":"正常的；普通的","definition":"usual, typical, or expected","collocations":["normal life","above normal","return to normal"],"example":"It's normal to feel nervous before a speech.","exampleZh":"在演講前感到緊張是正常的。","synonyms":["usual","typical"],"level":2,"theme":"日常與一般"},{"word":"normally","pos":"adv.","phonetic":"[ˈnɔrmlɪ]","meaning":"通常；正常地","definition":"in usual or expected circumstances","collocations":["normally wake up early","function normally","behave normally"],"example":"Normally, I wake up at seven o'clock.","exampleZh":"我通常七點起床。","synonyms":["usually"],"level":2,"theme":"日常與一般"},{"word":"north","pos":"n. / adj. / adv.","phonetic":"[nɔrθ]","meaning":"北方；北方的","definition":"the direction to the left of a person facing east","collocations":["north pole","north of","face north"],"example":"The wind is blowing from the north today.","exampleZh":"今天風從北方吹來。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"northern","pos":"adj.","phonetic":"[ˈnɔrðɚn]","meaning":"北方的；北部的","definition":"located in or coming from the north","collocations":["northern hemisphere","northern part","northern lights"],"example":"They live in the northern part of the country.","exampleZh":"他們住在這個國家的北部。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"notable","pos":"adj.","phonetic":"[ˈnotəbl]","meaning":"值得注意的；顯著的","definition":"worthy of attention or notice; remarkable","collocations":["notable exception","notable achievement","notable for"],"example":"He made a notable contribution to the field of science.","exampleZh":"他對科學領域做出了顯著的貢獻。","synonyms":["remarkable","significant"],"level":5,"theme":"日常與一般"},{"word":"notably","pos":"adv.","phonetic":"[ˈnotəblɪ]","meaning":"顯著地；尤其","definition":"especially, or in a way that deserves attention","collocations":["most notably","notably absent"],"example":"Several markets grew, most notably the online sales channel.","exampleZh":"多個市場都有成長，其中以線上銷售通路最為顯著。","synonyms":["particularly","especially"],"level":6,"theme":"溝通與語言"},{"word":"note","pos":"n. / v.","phonetic":"[not]","meaning":"筆記；紙條；注意","definition":"a short piece of writing to help someone remember something","collocations":["take notes","leave a note","note down"],"example":"Please take notes during the lecture.","exampleZh":"請在講課時做筆記。","synonyms":["memo"],"level":2,"theme":"人事與職涯"},{"word":"notebook","pos":"n.","phonetic":"[ˈnotˌbʊk]","meaning":"筆記本","definition":"a small book with blank pages for writing notes","collocations":["a new notebook","notebook computer","write in a notebook"],"example":"She wrote the vocabulary words in her notebook.","exampleZh":"她把單字寫在她的筆記本裡。","synonyms":[],"level":1,"theme":"人事與職涯"},{"word":"notice","pos":"v. / n.","phonetic":"[ˈnotɪs]","meaning":"注意到；通知","definition":"to become aware of something; a written announcement","collocations":["put up a notice","take notice of","without notice"],"example":"Did you notice the new sign on the door?","exampleZh":"你注意到門上的新標示了嗎？","synonyms":["observe"],"level":2,"theme":"溝通與語言"},{"word":"noticeable","pos":"adj.","phonetic":"[ˈnotɪsəbl]","meaning":"明顯的；顯而易見的","definition":"easy to see or notice","collocations":["noticeable improvement","noticeable difference","barely noticeable"],"example":"There has been a noticeable improvement in delivery times.","exampleZh":"配送時間有明顯的改善。","synonyms":["obvious","evident"],"level":4,"theme":"日常與一般"},{"word":"notification","pos":"n.","phonetic":"[ˌnotəfəˈkeʃən]","meaning":"通知；通知書","definition":"an official message telling someone about something","collocations":["receive a notification","email notification","prior notification"],"example":"You will receive an email notification when your order ships.","exampleZh":"訂單出貨時，您會收到電子郵件通知。","synonyms":["notice","alert"],"level":4,"theme":"辦公室與行政"},{"word":"notify","pos":"v.","phonetic":"[ˈnotəˌfaɪ]","meaning":"通知；告知","definition":"to formally inform someone of something","collocations":["notify the police","notify someone of","be notified"],"example":"Please notify us of any changes to your address.","exampleZh":"如果地址有任何變更，請通知我們。","synonyms":["inform","tell"],"level":4,"theme":"溝通與語言"},{"word":"novel","pos":"n. / adj.","phonetic":"[ˈnɑvl]","meaning":"小說；新穎的","definition":"a long fictional story in book form; new and original","collocations":["write a novel","read a novel","novel idea"],"example":"She spent the whole summer writing her first novel.","exampleZh":"她花了整個夏天寫她的第一本小說。","synonyms":["fiction"],"level":3,"theme":"媒體與活動"},{"word":"now","pos":"adv.","phonetic":"[naʊ]","meaning":"現在","definition":"at the present time or moment","collocations":["right now","from now on","by now"],"example":"I have to leave right now.","exampleZh":"我現在必須馬上離開。","synonyms":["currently"],"level":1,"theme":"日常與一般"},{"word":"nowadays","pos":"adv.","phonetic":"[ˈnaʊəˌdez]","meaning":"如今；現今","definition":"at the present time, in contrast to the past","collocations":["nowadays people","common nowadays"],"example":"Nowadays, most people use smartphones to check the news.","exampleZh":"如今，大多數人用智慧型手機看新聞。","synonyms":["today","currently"],"level":3,"theme":"日常與一般"},{"word":"number","pos":"n. / v.","phonetic":"[ˈnʌmbɚ]","meaning":"數字；號碼","definition":"a mathematical value used for counting or calculating","collocations":["phone number","a large number of","number one"],"example":"Please write down your phone number.","exampleZh":"請寫下你的電話號碼。","synonyms":["figure"],"level":1,"theme":"科技與通訊"},{"word":"numerous","pos":"adj.","phonetic":"[ˈnjumərəs]","meaning":"許多的；為數眾多的","definition":"existing in large quantities; many","collocations":["numerous times","numerous occasions","numerous studies"],"example":"He has made numerous mistakes on this project.","exampleZh":"他在這個專案上犯了許多錯誤。","synonyms":["many","countless"],"level":4,"theme":"日常與一般"},{"word":"nurse","pos":"n. / v.","phonetic":"[nɝs]","meaning":"護士；照顧","definition":"a person trained to care for sick or injured people","collocations":["registered nurse","nurse a patient","school nurse"],"example":"The nurse took care of the patient all night.","exampleZh":"這位護士整晚都在照顧病人。","synonyms":["caregiver"],"level":2,"theme":"人事與職涯"},{"word":"nutrition","pos":"n.","phonetic":"[njuˈtrɪʃən]","meaning":"營養；營養學","definition":"the process of providing or obtaining food for health and growth","collocations":["good nutrition","nutrition label","lack of nutrition"],"example":"Good nutrition is essential for children's growth.","exampleZh":"良好的營養對兒童的成長至關重要。","synonyms":[],"level":4,"theme":"醫療與保險"},{"word":"object","pos":"n. / v.","phonetic":"[ˈɑbdʒɪkt]","meaning":"物體；目標；反對","definition":"a thing that can be seen or touched; or to express disagreement","collocations":["a strange object","object to a plan","the object of study"],"example":"She found a small metal object buried in the garden.","exampleZh":"她在花園裡發現了一個埋著的小金屬物體。","synonyms":["item","thing"],"level":2,"theme":"日常與一般"},{"word":"objection","pos":"n.","phonetic":"[əbˈdʒɛkʃən]","meaning":"反對；異議","definition":"a statement expressing disagreement with something","collocations":["raise an objection","have no objection","an objection to a rule"],"example":"The lawyer raised an objection during the trial.","exampleZh":"律師在審判中提出了異議。","synonyms":["protest","opposition"],"level":5,"theme":"合約與法律"},{"word":"objective","pos":"n. / adj.","phonetic":"[əbˈdʒɛktɪv]","meaning":"目標；客觀的","definition":"a goal one aims to achieve; or based on facts rather than feelings","collocations":["achieve an objective","an objective view","the main objective"],"example":"Our main objective is to increase customer satisfaction.","exampleZh":"我們的主要目標是提升顧客滿意度。","synonyms":["goal","aim"],"level":5,"theme":"日常與一般"},{"word":"obligation","pos":"n.","phonetic":"[ˌɑbləˈgeʃən]","meaning":"義務；責任","definition":"something you must do because of a law, promise, or duty","collocations":["contractual obligation","fulfill an obligation","under no obligation"],"example":"You are under no obligation to purchase after the free trial.","exampleZh":"免費試用後您沒有購買的義務。","synonyms":["duty","responsibility"],"level":5,"theme":"合約與法律"},{"word":"observation","pos":"n.","phonetic":"[ˌɑbzɚˈveʃən]","meaning":"觀察；觀測","definition":"the act of watching something carefully","collocations":["scientific observation","keep under observation","make an observation"],"example":"The scientist recorded her observations in a notebook.","exampleZh":"科學家把她的觀察結果記錄在筆記本上。","synonyms":["watching","monitoring"],"level":4,"theme":"科技與通訊"},{"word":"observe","pos":"v.","phonetic":"[əbˈzɝv]","meaning":"觀察；注意到；遵守","definition":"to watch carefully or notice something","collocations":["observe closely","observe a custom","observe behavior"],"example":"Researchers observed the animals in their natural habitat.","exampleZh":"研究人員在自然棲息地觀察這些動物。","synonyms":["watch","notice"],"level":3,"theme":"科技與通訊"},{"word":"obsolete","pos":"adj.","phonetic":"[ˌɑbsəˈlit]","meaning":"過時的；淘汰的","definition":"no longer in use or no longer useful because something newer exists","collocations":["become obsolete","obsolete equipment"],"example":"Many old machines have become obsolete due to new technology.","exampleZh":"許多舊機器因新科技而遭到淘汰。","synonyms":["outdated","old-fashioned"],"level":5,"theme":"科技與通訊"},{"word":"obstacle","pos":"n.","phonetic":"[ˈɑbstəkl]","meaning":"障礙；阻礙","definition":"something that blocks progress or makes it difficult","collocations":["overcome an obstacle","face obstacles","a major obstacle"],"example":"Lack of money was the main obstacle to starting the business.","exampleZh":"資金不足是創業最大的障礙。","synonyms":["barrier","hurdle"],"level":4,"theme":"日常與一般"},{"word":"obtain","pos":"v.","phonetic":"[əbˈten]","meaning":"獲得；取得","definition":"to get something, especially through effort","collocations":["obtain permission","obtain information","obtain a degree"],"example":"She worked hard to obtain a scholarship for college.","exampleZh":"她努力爭取到一份大學獎學金。","synonyms":["acquire","gain"],"level":4,"theme":"日常與一般"},{"word":"obvious","pos":"adj.","phonetic":"[ˈɑbviəs]","meaning":"明顯的；顯而易見的","definition":"easy to see or understand","collocations":["an obvious mistake","for obvious reasons","make it obvious"],"example":"It was obvious that she was upset about the news.","exampleZh":"很明顯她對這個消息感到不安。","synonyms":["clear","evident"],"level":3,"theme":"日常與一般"},{"word":"obviously","pos":"adv.","phonetic":"[ˈɑbviəsli]","meaning":"顯然地；明顯地","definition":"in a way that is clear and easy to notice","collocations":["obviously wrong","obviously upset","obviously true"],"example":"Obviously, the team needs more practice before the game.","exampleZh":"顯然，這支隊伍在比賽前需要更多練習。","synonyms":["clearly","evidently"],"level":3,"theme":"溝通與語言"},{"word":"occasion","pos":"n.","phonetic":"[əˈkeʒən]","meaning":"場合；時機","definition":"a particular time or event","collocations":["a special occasion","on this occasion","rise to the occasion"],"example":"We only use the good china on special occasions.","exampleZh":"我們只有在特別的場合才會用那套好瓷器。","synonyms":["event","occurrence"],"level":3,"theme":"日常與一般"},{"word":"occasionally","pos":"adv.","phonetic":"[əˈkeʒənli]","meaning":"偶爾地","definition":"sometimes but not often","collocations":["occasionally visit","eat out occasionally","occasionally happens"],"example":"She occasionally travels abroad for work.","exampleZh":"她偶爾會因工作出國。","synonyms":["sometimes","now and then"],"level":4,"theme":"日常與一般"},{"word":"occupancy","pos":"n.","phonetic":"[ˈɑkjəpənsɪ]","meaning":"入住率；佔用","definition":"the use of a room or building, or the rate at which rooms are used","collocations":["occupancy rate","maximum occupancy","double occupancy"],"example":"The hotel's occupancy rate reaches ninety percent during summer.","exampleZh":"這家飯店夏季的入住率高達九成。","synonyms":[],"level":6,"theme":"餐飲與住宿"},{"word":"occupant","pos":"n.","phonetic":"[ˈɑkjəpənt]","meaning":"居住者；使用者","definition":"a person who occupies or lives in a particular place","collocations":["the occupant of a house","the vehicle's occupants"],"example":"The occupant of the apartment complained about the noise.","exampleZh":"那間公寓的住戶抱怨噪音問題。","synonyms":[],"level":4,"theme":"房產與設施"},{"word":"occupation","pos":"n.","phonetic":"[ˌɑkjəˈpeʃən]","meaning":"職業；佔領","definition":"a person's job or profession; the act of occupying a place","collocations":["state your occupation","a skilled occupation","military occupation"],"example":"Please state your name, age, and occupation on the form.","exampleZh":"請在表格上填寫你的姓名、年齡和職業。","synonyms":["job","profession"],"level":4,"theme":"人事與職涯"},{"word":"occupy","pos":"v.","phonetic":"[ˈɑkjəˌpaɪ]","meaning":"佔據；佔領；使忙碌","definition":"to take up space, time, or attention, or to live in a place","collocations":["occupy a seat","occupy your time","occupy a building"],"example":"The children occupied themselves with puzzles during the trip.","exampleZh":"孩子們在旅途中用拼圖打發時間。","synonyms":["inhabit","fill"],"level":4,"theme":"日常與一般"},{"word":"occur","pos":"v.","phonetic":"[əˈkɝ]","meaning":"發生；出現","definition":"to happen or take place","collocations":["occur naturally","an accident occurs","occur to someone"],"example":"The earthquake occurred late at night when most people were asleep.","exampleZh":"地震發生在深夜，大多數人都已入睡。","synonyms":["happen","take place"],"level":3,"theme":"日常與一般"},{"word":"occurrence","pos":"n.","phonetic":"[əˈkɝəns]","meaning":"發生的事；事件","definition":"something that happens; an event","collocations":["a common occurrence","a rare occurrence","daily occurrence"],"example":"Traffic jams are a common occurrence in this city.","exampleZh":"塞車在這座城市是很常見的事。","synonyms":["event","incident"],"level":5,"theme":"日常與一般"},{"word":"odd","pos":"adj.","phonetic":"[ɑd]","meaning":"奇怪的；奇數的","definition":"strange or unusual; not divisible by two evenly","collocations":["an odd number","an odd habit","act odd"],"example":"It seemed odd that no one answered the door.","exampleZh":"沒有人來應門，這感覺很奇怪。","synonyms":["strange","peculiar"],"level":3,"theme":"日常與一般"},{"word":"off","pos":"adv. / prep. / adj.","phonetic":"[ɔf]","meaning":"離開；關掉的；不新鮮的","definition":"away from a place or position; not turned on","collocations":["turn off","get off","off duty"],"example":"Please turn off the lights before you leave.","exampleZh":"離開前請把燈關掉。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"off-site","pos":"adj./adv.","phonetic":"[ˈɔfˈsaɪt]","meaning":"場外的；異地的","definition":"away from the main place of work","collocations":["off-site meeting","off-site storage","held off-site"],"example":"The strategy meeting will be held off-site at a lakeside resort.","exampleZh":"策略會議將移師湖畔度假村舉行。","synonyms":[],"level":5,"theme":"辦公室與行政"},{"word":"offer","pos":"v. / n.","phonetic":"[ˈɔfɚ]","meaning":"提供；提議；出價","definition":"to present something for someone to accept or refuse","collocations":["offer help","a job offer","offer advice"],"example":"She offered to help me carry the boxes upstairs.","exampleZh":"她主動幫我把箱子搬到樓上。","synonyms":["propose","provide"],"level":2,"theme":"溝通與語言"},{"word":"offering","pos":"n.","phonetic":"[ˈɔfərɪŋ]","meaning":"（提供的）產品／服務；提供","definition":"something offered for sale or use","collocations":["product offerings","expand offerings","new offerings"],"example":"The cafe expanded its offerings to include vegan desserts.","exampleZh":"這家咖啡館擴增了品項，加入純素甜點。","synonyms":["product"],"level":5,"theme":"行銷與銷售"},{"word":"office","pos":"n.","phonetic":"[ˈɔfɪs]","meaning":"辦公室；職位","definition":"a room or building where people work at desks","collocations":["work in an office","office hours","run for office"],"example":"My father works in an office downtown.","exampleZh":"我父親在市中心的一間辦公室工作。","synonyms":["workplace"],"level":1,"theme":"人事與職涯"},{"word":"officer","pos":"n.","phonetic":"[ˈɔfəsɚ]","meaning":"官員；警官；軍官","definition":"a person who holds a position of authority, especially in the police or military","collocations":["a police officer","a military officer","customs officer"],"example":"The police officer asked to see his driver's license.","exampleZh":"警官要求查看他的駕照。","synonyms":["official"],"level":2,"theme":"人事與職涯"},{"word":"official","pos":"adj. / n.","phonetic":"[əˈfɪʃəl]","meaning":"官方的；正式的；官員","definition":"relating to authority or government; a person holding a public position","collocations":["an official statement","government officials","make it official"],"example":"The government made an official announcement about the new policy.","exampleZh":"政府針對這項新政策發表了官方聲明。","synonyms":["formal","authorized"],"level":3,"theme":"合約與法律"},{"word":"offline","pos":"adj./adv.","phonetic":"[ˈɔfˈlaɪn]","meaning":"離線的；離線地","definition":"not connected to the internet","collocations":["go offline","offline mode","work offline"],"example":"The system will go offline briefly tonight for maintenance.","exampleZh":"系統今晚將短暫離線進行維護。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"offset","pos":"v./n.","phonetic":"[ˈɔfˌsɛt]","meaning":"抵銷；補償","definition":"to balance the effect of something so there is no overall change","collocations":["offset costs","offset losses","carbon offset"],"example":"Higher sales volumes offset the increase in shipping costs.","exampleZh":"銷售量的成長抵銷了運費的上漲。","synonyms":["counterbalance"],"level":6,"theme":"財務與會計"},{"word":"often","pos":"adv.","phonetic":"[ˈɔfən]","meaning":"常常；經常","definition":"frequently; many times","collocations":["how often","quite often","not often"],"example":"We often go hiking on the weekends.","exampleZh":"我們週末常常去健行。","synonyms":["frequently"],"level":1,"theme":"日常與一般"},{"word":"omit","pos":"v.","phonetic":"[oˈmɪt]","meaning":"省略；遺漏","definition":"to leave out or fail to include something","collocations":["omit a detail","omit a name","omit from the list"],"example":"She omitted her middle name from the application form.","exampleZh":"她在申請表上省略了她的中間名。","synonyms":["leave out","exclude"],"level":5,"theme":"溝通與語言"},{"word":"on-site","pos":"adj./adv.","phonetic":"[ˈɑnˈsaɪt]","meaning":"現場的；在現場","definition":"at the place where work happens or a service is provided","collocations":["on-site parking","on-site inspection","available on-site"],"example":"The hotel offers free on-site parking for all guests.","exampleZh":"飯店為所有房客提供免費的館內停車。","synonyms":[],"level":5,"theme":"房產與設施"},{"word":"onboard","pos":"adj./adv./v.","phonetic":"[ˈɑnˈbord]","meaning":"機上的；船上的；到職培訓","definition":"on a plane, ship, or vehicle, or to help a new employee settle in","collocations":["onboard service","onboard new staff","welcome onboard"],"example":"Meals and beverages are complimentary onboard all international flights.","exampleZh":"所有國際航班機上均免費供應餐點與飲料。","synonyms":[],"level":5,"theme":"旅遊與交通"},{"word":"once","pos":"adv. / conj.","phonetic":"[wʌns]","meaning":"一次；曾經；一旦","definition":"one time; at some time in the past; as soon as","collocations":["once a week","once upon a time","once you finish"],"example":"Once you finish your homework, you can watch TV.","exampleZh":"一旦你做完功課，就可以看電視。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"ongoing","pos":"adj.","phonetic":"[ˈɑnˌgoɪŋ]","meaning":"持續進行的","definition":"continuing to happen or develop","collocations":["an ongoing investigation","ongoing support"],"example":"The company provides ongoing training for all new employees.","exampleZh":"這家公司為所有新員工提供持續性的培訓。","synonyms":["continuing","current"],"level":4,"theme":"日常與一般"},{"word":"online","pos":"adj. / adv.","phonetic":"[ˈɑnˌlaɪn]","meaning":"線上的；上網","definition":"connected to or available through the internet","collocations":["shop online","an online course","online shopping"],"example":"More students are taking online courses these days.","exampleZh":"現在越來越多學生選修線上課程。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"only","pos":"adj. / adv.","phonetic":"[ˈonli]","meaning":"唯一的；只；僅僅","definition":"being the single one of its kind; no more than","collocations":["the only one","only if","if only"],"example":"She is the only student who finished the test early.","exampleZh":"她是唯一一位提早完成測驗的學生。","synonyms":["merely","just"],"level":1,"theme":"溝通與語言"},{"word":"onto","pos":"prep.","phonetic":"[ˈɑntu]","meaning":"到⋯⋯之上","definition":"moving to a position on top of something","collocations":["climb onto","jump onto","hold onto"],"example":"The cat jumped onto the windowsill to watch the birds.","exampleZh":"貓跳到窗台上看鳥。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"open","pos":"adj. / v.","phonetic":"[ˈopən]","meaning":"開的；打開；開放的","definition":"not closed; to make something no longer shut","collocations":["open a door","open hours","keep an open mind"],"example":"Please open the window; it's stuffy in here.","exampleZh":"請把窗戶打開，這裡很悶。","synonyms":["unlock"],"level":1,"theme":"日常與一般"},{"word":"opening","pos":"n.","phonetic":"[ˈopənɪŋ]","meaning":"開幕；開口；空缺","definition":"a hole or space; the beginning of an event; a job vacancy","collocations":["a job opening","grand opening","an opening ceremony"],"example":"The company announced a new job opening in the marketing department.","exampleZh":"這間公司宣布行銷部門有一個新的職缺。","synonyms":["gap","vacancy"],"level":3,"theme":"人事與職涯"},{"word":"operate","pos":"v.","phonetic":"[ˈɑpəˌret]","meaning":"操作；運轉；動手術","definition":"to control or run a machine or system; to perform surgery","collocations":["operate a machine","operate on a patient","operate smoothly"],"example":"The surgeon operated on the patient for six hours.","exampleZh":"外科醫生為病人動了六個小時的手術。","synonyms":["run","function"],"level":4,"theme":"科技與通訊"},{"word":"operation","pos":"n.","phonetic":"[ˌɑpəˈreʃən]","meaning":"手術；操作；運作","definition":"a surgical procedure; the process of working or functioning","collocations":["a rescue operation","a heart operation","in operation"],"example":"He is recovering well after his knee operation.","exampleZh":"他膝蓋手術後恢復得很好。","synonyms":["surgery","procedure"],"level":4,"theme":"醫療與保險"},{"word":"operational","pos":"adj.","phonetic":"[ˌɑpəˈreʃənl]","meaning":"營運的；運作中的","definition":"relating to the working of a business, or in working condition","collocations":["operational costs","fully operational","operational efficiency"],"example":"The new production line will be fully operational by March.","exampleZh":"新生產線將於三月全面投入運作。","synonyms":["functioning"],"level":5,"theme":"企業經營"},{"word":"operator","pos":"n.","phonetic":"[ˈɑpəˌretɚ]","meaning":"操作員；接線生；業者","definition":"a person who operates a machine or works a telephone service, or a company that runs a business","collocations":["machine operator","tour operator","telephone operator"],"example":"The tour operator arranged transportation and accommodations for the group.","exampleZh":"旅遊業者為團體安排了交通與住宿。","synonyms":[],"level":3,"theme":"生產與物流"},{"word":"opinion","pos":"n.","phonetic":"[əˈpɪnjən]","meaning":"意見；看法","definition":"a personal view or judgment about something","collocations":["share an opinion","in my opinion","public opinion"],"example":"In my opinion, the new policy is a step in the right direction.","exampleZh":"依我看，這項新政策是朝正確方向邁進的一步。","synonyms":["view","belief"],"level":3,"theme":"溝通與語言"},{"word":"opponent","pos":"n.","phonetic":"[əˈponənt]","meaning":"對手；反對者","definition":"a person who competes against or disagrees with another","collocations":["defeat an opponent","a tough opponent","political opponent"],"example":"She easily defeated her opponent in the final match.","exampleZh":"她在決賽中輕鬆擊敗了對手。","synonyms":["rival","adversary"],"level":4,"theme":"媒體與活動"},{"word":"opportunity","pos":"n.","phonetic":"[ˌɑpɚˈtunətɪ]","meaning":"機會","definition":"a chance to do something or achieve something","collocations":["a great opportunity","miss an opportunity","job opportunities"],"example":"Studying abroad gave her a great opportunity to learn a new language.","exampleZh":"出國留學讓她有很好的機會學習新語言。","synonyms":["chance"],"level":3,"theme":"日常與一般"},{"word":"oppose","pos":"v.","phonetic":"[əˈpoz]","meaning":"反對","definition":"to disagree with or resist a plan or idea","collocations":["oppose a plan","strongly oppose","oppose the government"],"example":"Many citizens oppose the new tax law.","exampleZh":"許多市民反對這項新稅法。","synonyms":["object to","resist"],"level":4,"theme":"合約與法律"},{"word":"opposite","pos":"adj. / n. / prep.","phonetic":"[ˈɑpəzɪt]","meaning":"相反的；對面的","definition":"completely different from something, or facing it","collocations":["opposite direction","the opposite sex","sit opposite"],"example":"He walked in the opposite direction.","exampleZh":"他朝相反的方向走去。","synonyms":["contrary","reverse"],"level":3,"theme":"日常與一般"},{"word":"opposition","pos":"n.","phonetic":"[ˌɑpəˈzɪʃən]","meaning":"反對；對手","definition":"strong disagreement, or the people you compete against","collocations":["strong opposition","in opposition to","face opposition"],"example":"The proposed parking fee met strong opposition from employees.","exampleZh":"擬議的停車收費遭到員工強烈反對。","synonyms":["resistance"],"level":4,"theme":"企業經營"},{"word":"opt","pos":"v.","phonetic":"[ɑpt]","meaning":"選擇；決定","definition":"to choose one thing instead of another","collocations":["opt for","opt out of","opt to"],"example":"Many customers opt for the extended warranty at checkout.","exampleZh":"許多顧客結帳時選擇加購延長保固。","synonyms":["choose","select"],"level":5,"theme":"購物與消費"},{"word":"optimism","pos":"n.","phonetic":"[ˈɑptəˌmɪzəm]","meaning":"樂觀","definition":"a feeling of hopefulness about the future","collocations":["a sense of optimism","cautious optimism","express optimism"],"example":"There is growing optimism about the economy.","exampleZh":"人們對經濟前景日益樂觀。","synonyms":["hopefulness"],"level":5,"theme":"日常與一般"},{"word":"optimistic","pos":"adj.","phonetic":"[ˌɑptəˈmɪstɪk]","meaning":"樂觀的","definition":"hopeful and confident about the future","collocations":["stay optimistic","optimistic about the future","remain optimistic"],"example":"She remains optimistic about her recovery.","exampleZh":"她對自己的康復保持樂觀。","synonyms":["positive","hopeful"],"level":4,"theme":"日常與一般"},{"word":"option","pos":"n.","phonetic":"[ˈɑpʃən]","meaning":"選擇","definition":"a thing that may be chosen among alternatives","collocations":["have no option","the best option","consider an option"],"example":"Buying a used car is a cheaper option.","exampleZh":"買二手車是比較便宜的選擇。","synonyms":["choice","alternative"],"level":3,"theme":"日常與一般"},{"word":"optional","pos":"adj.","phonetic":"[ˈɑpʃənḷ]","meaning":"可選擇的；非強制的","definition":"available to be chosen but not compulsory","collocations":["optional course","optional equipment","entirely optional"],"example":"Attending the workshop is optional, not required.","exampleZh":"參加這場工作坊是自由選擇的，非強制性。","synonyms":["voluntary"],"level":4,"theme":"人事與職涯"},{"word":"order","pos":"n. / v.","phonetic":"[ˈɔrdɚ]","meaning":"順序；命令；訂購","definition":"a request for goods, or an instruction to do something","collocations":["place an order","in order","give an order"],"example":"I ordered a pizza for dinner.","exampleZh":"我點了一份披薩當晚餐。","synonyms":["command","sequence"],"level":1,"theme":"財務與會計"},{"word":"ordinary","pos":"adj.","phonetic":"[ˈɔrdəˌnɛrɪ]","meaning":"普通的；平凡的","definition":"with no special or distinctive features; normal","collocations":["an ordinary day","ordinary people","out of the ordinary"],"example":"It was just an ordinary day at school.","exampleZh":"那只是學校裡平凡的一天。","synonyms":["common","normal"],"level":3,"theme":"日常與一般"},{"word":"organic","pos":"adj.","phonetic":"[ɔrˈgænɪk]","meaning":"有機的","definition":"produced without artificial chemicals or fertilizers","collocations":["organic food","organic farming","organic vegetables"],"example":"They only buy organic vegetables at the market.","exampleZh":"他們在市場只買有機蔬菜。","synonyms":[],"level":4,"theme":"餐飲與住宿"},{"word":"organization","pos":"n.","phonetic":"[ˌɔrgənəˈzeʃən]","meaning":"組織；機構","definition":"a group of people who work together for a purpose","collocations":["charitable organization","join an organization","non-profit organization"],"example":"She works for a non-profit organization.","exampleZh":"她在一個非營利組織工作。","synonyms":["institution"],"level":3,"theme":"日常與一般"},{"word":"organize","pos":"v.","phonetic":"[ˈɔrgəˌnaɪz]","meaning":"組織；籌辦","definition":"to plan and arrange an event or activity","collocations":["organize an event","organize a meeting","well organized"],"example":"The teacher organized a field trip for the class.","exampleZh":"老師為班上籌辦了一次校外教學。","synonyms":["arrange","plan"],"level":3,"theme":"人事與職涯"},{"word":"orientation","pos":"n.","phonetic":"[ˌorienˈteʃən]","meaning":"新生訓練；方向","definition":"introductory training; the direction something faces","collocations":["attend orientation","career orientation"],"example":"All new students must attend an orientation session before classes begin.","exampleZh":"所有新生在開課前都必須參加迎新說明會。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"origin","pos":"n.","phonetic":"[ˈɔrədʒɪn]","meaning":"起源；由來","definition":"the point or place where something begins","collocations":["origin of a word","country of origin","trace the origin"],"example":"The origin of this custom is unclear.","exampleZh":"這項習俗的起源並不清楚。","synonyms":["source","root"],"level":4,"theme":"日常與一般"},{"word":"original","pos":"adj. / n.","phonetic":"[əˈrɪdʒənḷ]","meaning":"最初的；原創的","definition":"existing from the beginning, or new and creative","collocations":["original idea","original copy","the original plan"],"example":"He came up with a very original idea.","exampleZh":"他想出了一個非常有創意的點子。","synonyms":["initial","creative"],"level":3,"theme":"日常與一般"},{"word":"originally","pos":"adv.","phonetic":"[əˈrɪdʒənlɪ]","meaning":"原本；最初","definition":"at first, before any changes","collocations":["originally planned","originally from","originally scheduled"],"example":"The launch was originally scheduled for May but moved to July.","exampleZh":"發表會原訂五月舉行，後來改到七月。","synonyms":["initially"],"level":3,"theme":"日常與一般"},{"word":"other","pos":"adj. / pron.","phonetic":"[ˈʌðɚ]","meaning":"其他的","definition":"used to refer to a person or thing different from one already mentioned","collocations":["each other","the other day","on the other hand"],"example":"I met an old friend the other day.","exampleZh":"前幾天我遇到一位老朋友。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"otherwise","pos":"adv. / conj.","phonetic":"[ˈʌðɚˌwaɪz]","meaning":"否則；另外","definition":"under other circumstances; or else","collocations":["or otherwise","otherwise known as","unless otherwise stated"],"example":"Hurry up, otherwise we'll miss the bus.","exampleZh":"快點，否則我們會錯過公車。","synonyms":["or else"],"level":3,"theme":"日常與一般"},{"word":"out","pos":"adv. / prep.","phonetic":"[aʊt]","meaning":"在外；出局","definition":"away from the inside of a place; not at home","collocations":["go out","out of order","run out"],"example":"We went out for dinner last night.","exampleZh":"我們昨晚出去吃晚餐。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"outcome","pos":"n.","phonetic":"[ˈaʊtˌkʌm]","meaning":"結果","definition":"the way a thing turns out; a result","collocations":["the final outcome","positive outcome","depend on the outcome"],"example":"We are waiting to hear the outcome of the election.","exampleZh":"我們正在等待選舉結果。","synonyms":["result","consequence"],"level":4,"theme":"日常與一般"},{"word":"outdated","pos":"adj.","phonetic":"[ˌaʊtˈdetɪd]","meaning":"過時的","definition":"no longer useful, fashionable, or up-to-date","collocations":["outdated technology","outdated information"],"example":"The company replaced its outdated computer systems.","exampleZh":"公司汰換了過時的電腦系統。","synonyms":["obsolete","old-fashioned"],"level":4,"theme":"科技與通訊"},{"word":"outdoor","pos":"adj.","phonetic":"[ˈaʊtˌdɔr]","meaning":"戶外的","definition":"done or used outside rather than in a building","collocations":["outdoor activities","outdoor sports","outdoor pool"],"example":"Hiking is a popular outdoor activity in Taiwan.","exampleZh":"健行是台灣熱門的戶外活動。","synonyms":[],"level":2,"theme":"媒體與活動"},{"word":"outfit","pos":"n.","phonetic":"[ˈaʊtˌfɪt]","meaning":"一套服裝","definition":"a set of clothes worn together","collocations":["a matching outfit","wear a new outfit"],"example":"She bought a new outfit for the job interview.","exampleZh":"她為了面試買了一套新服裝。","synonyms":["attire"],"level":3,"theme":"購物與消費"},{"word":"outing","pos":"n.","phonetic":"[ˈaʊtɪŋ]","meaning":"郊遊；出遊","definition":"a short trip taken for pleasure","collocations":["company outing","family outing","team outing"],"example":"The annual company outing will be a barbecue at the lake.","exampleZh":"今年的公司出遊活動是湖邊烤肉。","synonyms":["excursion","trip"],"level":4,"theme":"媒體與活動"},{"word":"outlet","pos":"n.","phonetic":"[ˈaʊtˌlɛt]","meaning":"插座；暢貨中心；宣洩管道","definition":"an electrical socket; a store; a way to express emotion","collocations":["an electrical outlet","a retail outlet","an outlet for stress"],"example":"Running is a great outlet for stress.","exampleZh":"跑步是紓解壓力的絕佳管道。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"outline","pos":"n. / v.","phonetic":"[ˈaʊtˌlaɪn]","meaning":"大綱；輪廓","definition":"a general description or summary; a rough plan","collocations":["write an outline","outline a plan","rough outline"],"example":"Please write an outline before you start the essay.","exampleZh":"開始寫作文前請先寫大綱。","synonyms":["summary","sketch"],"level":4,"theme":"人事與職涯"},{"word":"outlook","pos":"n.","phonetic":"[ˈaʊtˌlʊk]","meaning":"展望；觀點","definition":"a general view of a situation, especially the future","collocations":["economic outlook","positive outlook","future outlook"],"example":"The economic outlook for next year looks promising.","exampleZh":"明年的經濟展望看起來很樂觀。","synonyms":["perspective","prospect"],"level":5,"theme":"日常與一般"},{"word":"output","pos":"n.","phonetic":"[ˈaʊtˌpʊt]","meaning":"產量；輸出","definition":"the amount of something produced by a person, machine, or system","collocations":["increase output","factory output","energy output"],"example":"The factory increased its output by 20 percent.","exampleZh":"這家工廠將產量提高了百分之二十。","synonyms":["production"],"level":4,"theme":"財務與會計"},{"word":"outside","pos":"prep./adv./adj./n.","phonetic":"[ˈaʊtˈsaɪd]","meaning":"在外面；外部的","definition":"not inside a building or area","collocations":["outside the office","outside business hours","outside vendor"],"example":"Please call the emergency line outside regular business hours.","exampleZh":"非營業時間請撥打緊急專線。","synonyms":["exterior"],"level":1,"theme":"日常與一般"},{"word":"outstanding","pos":"adj.","phonetic":"[ˌaʊtˈstændɪŋ]","meaning":"傑出的；顯著的","definition":"exceptionally good or distinguished","collocations":["outstanding performance","outstanding student","outstanding achievement"],"example":"She received an award for her outstanding performance.","exampleZh":"她因傑出的表現獲得獎項。","synonyms":["excellent","remarkable"],"level":4,"theme":"日常與一般"},{"word":"over","pos":"prep. / adv.","phonetic":"[ˈovɚ]","meaning":"在...之上；結束","definition":"above or across; finished","collocations":["get over","all over","over there"],"example":"The movie is over now.","exampleZh":"電影現在結束了。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"overall","pos":"adj. / adv.","phonetic":"[ˌovɚˈɔl]","meaning":"整體的","definition":"taking everything into account; in general","collocations":["overall performance","overall quality","overall winner"],"example":"The team's overall performance improved this season.","exampleZh":"這支隊伍本季的整體表現進步了。","synonyms":["general","total"],"level":4,"theme":"日常與一般"},{"word":"overbook","pos":"v.","phonetic":"[ˌovɚˈbʊk]","meaning":"超額預訂","definition":"to sell more tickets or reservations than there are places available","collocations":["overbooked flight","overbook a hotel"],"example":"The flight was overbooked, so volunteers were offered travel vouchers.","exampleZh":"班機超賣，因此航空公司提供旅遊抵用券徵求自願改班者。","synonyms":[],"level":6,"theme":"旅遊與交通"},{"word":"overdue","pos":"adj.","phonetic":"[ˈovɚˈdju]","meaning":"逾期的；早該發生的","definition":"not done or paid by the expected time","collocations":["overdue payment","overdue books","long overdue"],"example":"A reminder was sent regarding the overdue invoice from March.","exampleZh":"已就三月份逾期未付的請款單發出提醒。","synonyms":["late","unpaid"],"level":5,"theme":"財務與會計"},{"word":"overnight","pos":"adj. / adv.","phonetic":"[ˌovɚˈnaɪt]","meaning":"一夜之間；過夜的","definition":"happening during the night, or very suddenly","collocations":["overnight stay","become famous overnight","overnight trip"],"example":"The singer became famous overnight.","exampleZh":"這位歌手一夜之間成名了。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"overseas","pos":"adj. / adv.","phonetic":"[ˌovɚˈsiz]","meaning":"海外的；到國外","definition":"in, to, or from a foreign country across the sea","collocations":["study overseas","overseas market","travel overseas"],"example":"Many students dream of studying overseas.","exampleZh":"許多學生夢想著到海外留學。","synonyms":["abroad"],"level":3,"theme":"旅遊與交通"},{"word":"oversee","pos":"v.","phonetic":"[ˌovɚˈsi]","meaning":"監督","definition":"to supervise a task, project, or person","collocations":["oversee a project","oversee construction","oversee staff"],"example":"He was hired to oversee the construction project.","exampleZh":"他被聘來監督這項建築工程。","synonyms":["supervise","monitor"],"level":5,"theme":"人事與職涯"},{"word":"overtime","pos":"n.","phonetic":"[ˈovɚˌtaɪm]","meaning":"加班；加班費","definition":"time worked in addition to regular hours","collocations":["work overtime","paid overtime"],"example":"He often works overtime to finish the project on schedule.","exampleZh":"他經常加班以便按時完成專案。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"overview","pos":"n.","phonetic":"[ˈovɚˌvju]","meaning":"概觀；概述","definition":"a general description of something without details","collocations":["brief overview","give an overview","overview of the project"],"example":"The first slide gives an overview of this year's marketing goals.","exampleZh":"第一張投影片概述了今年的行銷目標。","synonyms":["summary","outline"],"level":4,"theme":"會議與簡報"},{"word":"owe","pos":"v.","phonetic":"[o]","meaning":"欠（錢或情）；應給予","definition":"to be under an obligation to pay or repay something","collocations":["owe money","owe an apology","owe a debt"],"example":"I owe him fifty dollars for the concert tickets.","exampleZh":"我欠他五十美元的演唱會門票錢。","synonyms":[],"level":2,"theme":"財務與會計"},{"word":"own","pos":"v./adj.","phonetic":"[on]","meaning":"擁有；自己的","definition":"to have something that belongs to you, or belonging to yourself","collocations":["own a business","on one's own","of one's own"],"example":"She owns three restaurants in the downtown area.","exampleZh":"她在市中心擁有三家餐廳。","synonyms":["possess"],"level":1,"theme":"日常與一般"},{"word":"owner","pos":"n.","phonetic":"[ˈonɚ]","meaning":"擁有者；業主","definition":"a person who owns something","collocations":["business owner","property owner","store owner"],"example":"The owner of the bakery greets regular customers by name.","exampleZh":"麵包店老闆會叫出常客的名字打招呼。","synonyms":["proprietor"],"level":2,"theme":"企業經營"},{"word":"ownership","pos":"n.","phonetic":"[ˈonɚˌʃɪp]","meaning":"所有權","definition":"the state or fact of owning something","collocations":["take ownership","joint ownership"],"example":"The company transferred ownership of the building to a new investor.","exampleZh":"公司把這棟大樓的所有權轉讓給一位新投資者。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"pace","pos":"n. / v.","phonetic":"[pes]","meaning":"步調；速度；踱步","definition":"the speed at which someone or something moves or does something","collocations":["at a slow pace","keep pace with","pace up and down"],"example":"The teacher set a fast pace for the lesson.","exampleZh":"老師把這堂課的步調設得很快。","synonyms":["speed","tempo"],"level":3,"theme":"日常與一般"},{"word":"pack","pos":"v. / n.","phonetic":"[pæk]","meaning":"打包；裝箱；一群","definition":"to put things into a bag, box, or container","collocations":["pack a suitcase","pack up","a pack of wolves"],"example":"She packed her suitcase the night before the trip.","exampleZh":"她在出發前一晚打包好行李。","synonyms":["load","bundle"],"level":1,"theme":"房產與設施"},{"word":"package","pos":"n. / v.","phonetic":"[ˈpækɪdʒ]","meaning":"包裹；套裝；包裝","definition":"a thing or things wrapped up or packed in a box","collocations":["deliver a package","package deal","package tour"],"example":"The mailman delivered a package to my house.","exampleZh":"郵差把包裹送到我家。","synonyms":["parcel","bundle"],"level":2,"theme":"房產與設施"},{"word":"packaging","pos":"n.","phonetic":"[ˈpækɪdʒɪŋ]","meaning":"包裝；包裝材料","definition":"the materials used to wrap or protect goods","collocations":["eco-friendly packaging","packaging materials","product packaging"],"example":"The brand switched to recyclable packaging for all its products.","exampleZh":"該品牌旗下所有產品都改用可回收包裝。","synonyms":["wrapping"],"level":4,"theme":"生產與物流"},{"word":"packet","pos":"n.","phonetic":"[ˈpækɪt]","meaning":"小包；資料袋","definition":"a small package or envelope containing things","collocations":["information packet","welcome packet","a packet of"],"example":"Each attendee will receive a welcome packet at registration.","exampleZh":"每位與會者在報到時都會領到一份資料袋。","synonyms":["package"],"level":3,"theme":"會議與簡報"},{"word":"page","pos":"n.","phonetic":"[pedʒ]","meaning":"頁；頁面","definition":"one side of a sheet of paper in a book","collocations":["turn the page","front page","web page"],"example":"Please turn to page ten of the textbook.","exampleZh":"請翻到課本第十頁。","synonyms":["sheet"],"level":1,"theme":"人事與職涯"},{"word":"pair","pos":"n. / v.","phonetic":"[pɛr]","meaning":"一雙；一對；配對","definition":"two things of the same kind used together","collocations":["a pair of shoes","pair up","pair off"],"example":"I bought a new pair of shoes yesterday.","exampleZh":"我昨天買了一雙新鞋。","synonyms":["couple","duo"],"level":1,"theme":"購物與消費"},{"word":"pamphlet","pos":"n.","phonetic":"[ˈpæmflɪt]","meaning":"小冊子","definition":"a thin book with information about a subject","collocations":["informational pamphlet","distribute pamphlets"],"example":"Pamphlets about the museum's exhibits are available at the entrance.","exampleZh":"博物館展覽的簡介小冊可在入口處索取。","synonyms":["brochure","booklet"],"level":4,"theme":"行銷與銷售"},{"word":"panel","pos":"n.","phonetic":"[ˈpænl̩]","meaning":"面板；小組；委員會","definition":"a flat piece of material, or a group of people who discuss or judge something","collocations":["control panel","panel discussion","solar panel"],"example":"A panel of experts discussed the new policy.","exampleZh":"一組專家討論了這項新政策。","synonyms":["board"],"level":4,"theme":"人事與職涯"},{"word":"paper","pos":"n.","phonetic":"[ˈpepɚ]","meaning":"紙；報紙；報告","definition":"material used for writing or printing on","collocations":["a piece of paper","term paper","newspaper"],"example":"He wrote his notes on a piece of paper.","exampleZh":"他把筆記寫在一張紙上。","synonyms":["document"],"level":1,"theme":"人事與職涯"},{"word":"paperwork","pos":"n.","phonetic":"[ˈpepɚˌwɝk]","meaning":"文書工作；文件","definition":"the written work such as forms and reports that must be done for a job","collocations":["complete the paperwork","fill out paperwork","a pile of paperwork"],"example":"Please complete the enrollment paperwork before your first day.","exampleZh":"請在到職日前填妥入職文件。","synonyms":["documentation"],"level":3,"theme":"辦公室與行政"},{"word":"paragraph","pos":"n.","phonetic":"[ˈpærəˌgræf]","meaning":"段落","definition":"a section of a piece of writing","collocations":["first paragraph","write a paragraph","paragraph break"],"example":"The teacher asked us to write a short paragraph.","exampleZh":"老師要求我們寫一段短文。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"parallel","pos":"adj. / n.","phonetic":"[ˈpærəˌlɛl]","meaning":"平行的；相似之處","definition":"lines that are the same distance apart at every point","collocations":["parallel lines","run parallel to","draw a parallel"],"example":"The two roads run parallel to each other.","exampleZh":"這兩條路彼此平行。","synonyms":["equivalent"],"level":4,"theme":"科技與通訊"},{"word":"parcel","pos":"n.","phonetic":"[ˈpɑrsl̩]","meaning":"包裹","definition":"an object or objects wrapped in paper to be sent by mail","collocations":["send a parcel","wrap a parcel","parcel post"],"example":"She wrapped the gift into a neat parcel.","exampleZh":"她把禮物包成一個整齊的包裹。","synonyms":["package"],"level":4,"theme":"房產與設施"},{"word":"park","pos":"n. / v.","phonetic":"[pɑrk]","meaning":"公園；停車","definition":"a public area with grass and trees for recreation; to stop a vehicle","collocations":["national park","park a car","play in the park"],"example":"We had a picnic in the park on Sunday.","exampleZh":"我們星期天在公園野餐。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"parking","pos":"n.","phonetic":"[ˈpɑrkɪŋ]","meaning":"停車","definition":"the act of stopping a vehicle in a place for a period of time","collocations":["parking lot","free parking","no parking"],"example":"There is no parking available near the theater.","exampleZh":"戲院附近沒有停車位。","synonyms":[],"level":2,"theme":"旅遊與交通"},{"word":"part","pos":"n. / v.","phonetic":"[pɑrt]","meaning":"部分；角色","definition":"a piece or section of something larger","collocations":["take part in","spare part","play a part"],"example":"He played an important part in the project.","exampleZh":"他在這個計畫中扮演重要角色。","synonyms":["portion","section"],"level":1,"theme":"日常與一般"},{"word":"part-time","pos":"adj./adv.","phonetic":"[ˈpɑrtˈtaɪm]","meaning":"兼職的；兼職地","definition":"working fewer than the standard number of hours","collocations":["part-time job","part-time staff","work part-time"],"example":"The store hires extra part-time staff during the holiday season.","exampleZh":"這家店在節慶旺季會加聘兼職人員。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"partial","pos":"adj.","phonetic":"[ˈpɑrʃəl]","meaning":"部分的；偏袒的","definition":"not complete or total","collocations":["partial success","partial view","be partial to"],"example":"The rescue was only a partial success.","exampleZh":"這次救援只獲得部分成功。","synonyms":["incomplete"],"level":5,"theme":"日常與一般"},{"word":"partially","pos":"adv.","phonetic":"[ˈpɑrʃəlɪ]","meaning":"部分地","definition":"not completely","collocations":["partially completed","partially covered","partially responsible"],"example":"The conference fee is partially covered by the training budget.","exampleZh":"會議費用有一部分由訓練預算支應。","synonyms":["partly"],"level":4,"theme":"日常與一般"},{"word":"participant","pos":"n.","phonetic":"[pɑrˈtɪsəpənt]","meaning":"參與者","definition":"a person who takes part in something","collocations":["active participant","each participant","participant list"],"example":"Every participant received a certificate.","exampleZh":"每位參與者都獲得一張證書。","synonyms":["member"],"level":5,"theme":"人事與職涯"},{"word":"participate","pos":"v.","phonetic":"[pɑrˈtɪsəˌpet]","meaning":"參加；參與","definition":"to take part in an activity or event","collocations":["participate in a contest","actively participate","encourage to participate"],"example":"All students are encouraged to participate in the event.","exampleZh":"鼓勵所有學生參加這項活動。","synonyms":["join","take part"],"level":4,"theme":"日常與一般"},{"word":"participation","pos":"n.","phonetic":"[pɑrˌtɪsəˈpeʃən]","meaning":"參與；參加","definition":"the act of taking part in an activity","collocations":["active participation","employee participation","participation rate"],"example":"Participation in the wellness program is voluntary but encouraged.","exampleZh":"健康促進計畫採自由參加，但公司鼓勵大家響應。","synonyms":["involvement"],"level":4,"theme":"人事與職涯"},{"word":"particular","pos":"adj.","phonetic":"[pɚˈtɪkjəlɚ]","meaning":"特定的；挑剔的","definition":"specific or special; being fussy about something","collocations":["in particular","this particular case","particular about food"],"example":"He is very particular about what he eats.","exampleZh":"他對吃的東西非常挑剔。","synonyms":["specific","fussy"],"level":3,"theme":"日常與一般"},{"word":"particularly","pos":"adv.","phonetic":"[pɚˈtɪkjəlɚli]","meaning":"特別地；尤其","definition":"especially; more than usual","collocations":["particularly interested","particularly difficult","particularly true"],"example":"The exam was particularly difficult this year.","exampleZh":"今年的考試特別難。","synonyms":["especially"],"level":3,"theme":"日常與一般"},{"word":"partly","pos":"adv.","phonetic":"[ˈpɑrtli]","meaning":"部分地","definition":"to some extent, but not completely","collocations":["partly true","partly cloudy","partly due to"],"example":"The delay was partly due to bad weather.","exampleZh":"延誤部分是因為天氣不佳。","synonyms":["partially"],"level":3,"theme":"日常與一般"},{"word":"partner","pos":"n.","phonetic":"[ˈpɑrtnɚ]","meaning":"夥伴；合夥人；配偶","definition":"a person who takes part in an activity with another","collocations":["business partner","dance partner","life partner"],"example":"She started the company with her business partner.","exampleZh":"她和她的事業夥伴一起創立了這家公司。","synonyms":["colleague","associate"],"level":3,"theme":"人事與職涯"},{"word":"partnership","pos":"n.","phonetic":"[ˈpɑrtnɚˌʃɪp]","meaning":"合夥關係；合作","definition":"a business relationship between two or more people or companies","collocations":["form a partnership","strategic partnership","in partnership with"],"example":"The airline announced a partnership with a major hotel chain.","exampleZh":"這家航空公司宣布與大型連鎖飯店合作。","synonyms":["alliance","collaboration"],"level":4,"theme":"企業經營"},{"word":"party","pos":"n.","phonetic":"[ˈpɑrti]","meaning":"派對；政黨","definition":"a social gathering, or an organized political group","collocations":["birthday party","political party","throw a party"],"example":"We are throwing a surprise party for her birthday.","exampleZh":"我們正在為她的生日籌辦一場驚喜派對。","synonyms":["gathering"],"level":1,"theme":"日常與一般"},{"word":"pass","pos":"v. / n.","phonetic":"[pæs]","meaning":"通過；經過；通行證","definition":"to move past or through something; to succeed in a test","collocations":["pass an exam","pass by","boarding pass"],"example":"She worked hard to pass the final exam.","exampleZh":"她努力用功以通過期末考。","synonyms":["succeed","cross"],"level":1,"theme":"人事與職涯"},{"word":"passenger","pos":"n.","phonetic":"[ˈpæsn̩dʒɚ]","meaning":"乘客","definition":"a person traveling in a vehicle other than the driver","collocations":["airline passenger","passenger seat","carry passengers"],"example":"The bus can carry up to forty passengers.","exampleZh":"這輛公車最多可載四十名乘客。","synonyms":["traveler"],"level":2,"theme":"旅遊與交通"},{"word":"passion","pos":"n.","phonetic":"[ˈpæʃən]","meaning":"熱情；激情","definition":"a very strong feeling of enthusiasm or love","collocations":["passion for music","with passion","follow your passion"],"example":"She has a real passion for painting.","exampleZh":"她對繪畫懷有真正的熱情。","synonyms":["enthusiasm","zeal"],"level":4,"theme":"日常與一般"},{"word":"passport","pos":"n.","phonetic":"[ˈpæsˌpɔrt]","meaning":"護照","definition":"an official document used for international travel","collocations":["renew a passport","valid passport","passport control"],"example":"Don't forget to bring your passport to the airport.","exampleZh":"別忘了帶護照去機場。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"password","pos":"n.","phonetic":"[ˈpæsˌwɝd]","meaning":"密碼","definition":"a secret word or phrase used to gain access","collocations":["forget a password","strong password","change your password"],"example":"Please enter your password to log in.","exampleZh":"請輸入你的密碼登入。","synonyms":["code"],"level":3,"theme":"科技與通訊"},{"word":"past","pos":"n. / adj. / prep.","phonetic":"[pæst]","meaning":"過去；以前的","definition":"the time before the present","collocations":["in the past","past experience","walk past"],"example":"He never talks about his past.","exampleZh":"他從不談論他的過去。","synonyms":["history"],"level":1,"theme":"日常與一般"},{"word":"path","pos":"n.","phonetic":"[pæθ]","meaning":"小徑；路徑","definition":"a way or track for walking","collocations":["walking path","career path","follow a path"],"example":"They followed a narrow path through the forest.","exampleZh":"他們沿著一條狹窄的小徑穿過森林。","synonyms":["trail","route"],"level":2,"theme":"旅遊與交通"},{"word":"patience","pos":"n.","phonetic":"[ˈpeʃəns]","meaning":"耐心","definition":"the ability to wait calmly without getting upset","collocations":["have patience","lose patience","test one's patience"],"example":"Teaching young children requires great patience.","exampleZh":"教導年幼的孩子需要極大的耐心。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"patient","pos":"adj. / n.","phonetic":"[ˈpeʃənt]","meaning":"有耐心的；病人","definition":"able to wait calmly; a person receiving medical treatment","collocations":["be patient with","patient care","hospital patient"],"example":"The nurse took good care of every patient.","exampleZh":"護理師悉心照顧每一位病人。","synonyms":["tolerant"],"level":2,"theme":"醫療與保險"},{"word":"patron","pos":"n.","phonetic":"[ˈpetrən]","meaning":"顧客；贊助者","definition":"a customer of a shop or restaurant, or a person who supports the arts","collocations":["restaurant patrons","patron of the arts","regular patron"],"example":"Patrons are asked to silence their phones during the performance.","exampleZh":"演出期間請觀眾將手機調為靜音。","synonyms":["customer","supporter"],"level":5,"theme":"餐飲與住宿"},{"word":"pattern","pos":"n.","phonetic":"[ˈpætɚn]","meaning":"圖案；模式","definition":"a repeated design or a regular way something happens","collocations":["weather pattern","floral pattern","behavior pattern"],"example":"The dress has a beautiful floral pattern.","exampleZh":"這件洋裝有漂亮的花卉圖案。","synonyms":["design","model"],"level":3,"theme":"日常與一般"},{"word":"pavement","pos":"n.","phonetic":"[ˈpevmənt]","meaning":"人行道；路面","definition":"a hard-surfaced area for walking beside a road","collocations":["walk on the pavement","wet pavement","cracked pavement"],"example":"Children were playing hopscotch on the pavement.","exampleZh":"孩子們在人行道上玩跳房子。","synonyms":["sidewalk"],"level":5,"theme":"旅遊與交通"},{"word":"pay","pos":"v. / n.","phonetic":"[pe]","meaning":"支付；薪水","definition":"to give money for something; wages","collocations":["pay a bill","pay attention","monthly pay"],"example":"He always pays his bills on time.","exampleZh":"他總是準時繳付帳單。","synonyms":["compensate","wage"],"level":1,"theme":"財務與會計"},{"word":"paycheck","pos":"n.","phonetic":"[ˈpeˌtʃɛk]","meaning":"薪水；薪資支票","definition":"the money you receive for your work","collocations":["monthly paycheck","paycheck deduction","live paycheck to paycheck"],"example":"Union dues are deducted directly from each paycheck.","exampleZh":"工會會費直接從每期薪資中扣除。","synonyms":["salary","wages"],"level":4,"theme":"財務與會計"},{"word":"payment","pos":"n.","phonetic":"[ˈpemənt]","meaning":"付款；支付","definition":"an amount of money paid for something","collocations":["monthly payment","make a payment","payment method"],"example":"The store accepts payment by credit card.","exampleZh":"這家店接受信用卡付款。","synonyms":["fee"],"level":2,"theme":"財務與會計"},{"word":"payroll","pos":"n.","phonetic":"[ˈpeˌrol]","meaning":"薪資名單；薪資總額；薪資作業","definition":"the list of employees a company pays, or the total paid to them","collocations":["payroll department","on the payroll","payroll system"],"example":"The payroll department processes salaries on the twenty-fifth of each month.","exampleZh":"薪資部門於每月二十五日核發薪水。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"peak","pos":"n. / v.","phonetic":"[pik]","meaning":"山頂；頂峰；達到高峰","definition":"the pointed top of a mountain; the highest point","collocations":["mountain peak","reach a peak","peak season"],"example":"They finally reached the peak of the mountain.","exampleZh":"他們終於登上山頂。","synonyms":["summit"],"level":4,"theme":"日常與一般"},{"word":"pedestrian","pos":"n. / adj.","phonetic":"[pəˈdɛstriən]","meaning":"行人；徒步的","definition":"a person walking rather than traveling in a vehicle","collocations":["pedestrian crossing","yield to pedestrians","a pedestrian zone"],"example":"Drivers must stop for pedestrians at the crossing.","exampleZh":"駕駛人在行人穿越道必須讓行人先行。","synonyms":["walker"],"level":4,"theme":"旅遊與交通"},{"word":"penalty","pos":"n.","phonetic":"[ˈpɛnl̩ti]","meaning":"處罰；罰款；罰球","definition":"a punishment for breaking a rule or law","collocations":["death penalty","pay a penalty","penalty kick"],"example":"The player was given a penalty for the foul.","exampleZh":"這名球員因犯規被判罰。","synonyms":["punishment","fine"],"level":5,"theme":"合約與法律"},{"word":"pending","pos":"adj./prep.","phonetic":"[ˈpɛndɪŋ]","meaning":"待定的；懸而未決的；直到","definition":"waiting to be decided or completed","collocations":["pending approval","patent pending","pending review"],"example":"The promotion is pending approval from the regional director.","exampleZh":"這項升遷案尚待區域總監核准。","synonyms":["awaiting"],"level":5,"theme":"辦公室與行政"},{"word":"pension","pos":"n.","phonetic":"[ˈpɛnʃən]","meaning":"退休金；養老金","definition":"a regular payment made to someone after retirement","collocations":["retirement pension","pension plan","monthly pension"],"example":"He receives a pension after thirty years of work.","exampleZh":"他工作三十年後領取退休金。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"people","pos":"n.","phonetic":"[ˈpipl̩]","meaning":"人們；人民","definition":"human beings in general or a specific group","collocations":["young people","people say","local people"],"example":"Many people gathered to watch the fireworks.","exampleZh":"許多人聚集觀看煙火。","synonyms":["persons"],"level":1,"theme":"日常與一般"},{"word":"per","pos":"prep.","phonetic":"[pɝ]","meaning":"每；根據","definition":"for each, or according to","collocations":["per person","per hour","as per your request"],"example":"The banquet costs forty-five dollars per person, including drinks.","exampleZh":"宴席每人四十五美元，含飲料。","synonyms":["each"],"level":3,"theme":"日常與一般"},{"word":"percent","pos":"n.","phonetic":"[pɚˈsɛnt]","meaning":"百分之...","definition":"one part in every hundred","collocations":["fifty percent","percent off","percent increase"],"example":"Fifty percent of the students passed the test.","exampleZh":"百分之五十的學生通過了測驗。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"percentage","pos":"n.","phonetic":"[pɚˈsɛntɪdʒ]","meaning":"百分比","definition":"a rate or proportion per hundred","collocations":["small percentage","percentage increase","calculate a percentage"],"example":"A large percentage of the budget goes to education.","exampleZh":"預算中很大一部分用於教育。","synonyms":["proportion"],"level":4,"theme":"科技與通訊"},{"word":"perception","pos":"n.","phonetic":"[pɚˈsɛpʃən]","meaning":"知覺；看法；感知","definition":"the way something is understood or interpreted, or the ability to notice something","collocations":["public perception","change perception","perception of reality"],"example":"Public perception of the issue has changed over time.","exampleZh":"大眾對這個議題的看法已隨時間改變。","synonyms":["insight"],"level":5,"theme":"日常與一般"},{"word":"perfect","pos":"adj. / v.","phonetic":"[ˈpɝfɪkt]","meaning":"完美的；使完美","definition":"having no flaws or mistakes; complete","collocations":["perfect score","perfect day","perfect one's skills"],"example":"She got a perfect score on the math test.","exampleZh":"她在數學考試中得到滿分。","synonyms":["flawless"],"level":2,"theme":"日常與一般"},{"word":"perform","pos":"v.","phonetic":"[pɚˈfɔrm]","meaning":"表演；執行","definition":"to do an action, task, or piece of work; to entertain an audience","collocations":["perform a song","perform surgery","perform well"],"example":"The band will perform live at the concert tonight.","exampleZh":"這個樂團今晚將在演唱會上現場表演。","synonyms":["carry out","act"],"level":3,"theme":"媒體與活動"},{"word":"performance","pos":"n.","phonetic":"[pɚˈfɔrməns]","meaning":"表演；表現；績效","definition":"an act of performing, or how well someone does something","collocations":["live performance","job performance","give a performance"],"example":"The audience gave the actors a standing ovation after the performance.","exampleZh":"觀眾在表演結束後起立為演員鼓掌。","synonyms":["show"],"level":3,"theme":"媒體與活動"},{"word":"perhaps","pos":"adv.","phonetic":"[pɚˈhæps]","meaning":"也許；或許","definition":"used to express possibility; maybe","collocations":["perhaps not","perhaps because","perhaps later"],"example":"Perhaps we should wait until tomorrow to decide.","exampleZh":"或許我們應該等到明天再做決定。","synonyms":["maybe","possibly"],"level":2,"theme":"日常與一般"},{"word":"period","pos":"n.","phonetic":"[ˈpɪrɪəd]","meaning":"期間；時期；句點","definition":"a length of time","collocations":["trial period","grace period","for a period of"],"example":"New employees complete a three-month probationary period.","exampleZh":"新進員工需經過三個月的試用期。","synonyms":["duration","term"],"level":2,"theme":"日常與一般"},{"word":"periodic","pos":"adj.","phonetic":"[ˌpɪrɪˈɑdɪk]","meaning":"定期的；週期性的","definition":"happening regularly at intervals","collocations":["periodic review","periodic maintenance","periodic inspection"],"example":"All fire extinguishers undergo periodic safety inspections.","exampleZh":"所有滅火器都會定期進行安全檢查。","synonyms":["regular","recurring"],"level":5,"theme":"辦公室與行政"},{"word":"periodically","pos":"adv.","phonetic":"[ˌpɪrɪˈɑdɪklɪ]","meaning":"定期地；週期性地","definition":"at regular intervals","collocations":["check periodically","updated periodically"],"example":"Prices are reviewed periodically to stay competitive.","exampleZh":"價格會定期檢討以維持競爭力。","synonyms":["regularly"],"level":5,"theme":"日常與一般"},{"word":"permanent","pos":"adj.","phonetic":"[ˈpɚmənənt]","meaning":"永久的；固定的","definition":"lasting or intended to last forever or for a long time","collocations":["a permanent job","permanent damage","permanent resident"],"example":"The accident left a permanent scar on his arm.","exampleZh":"這場意外在他手臂上留下了永久的疤痕。","synonyms":["lasting"],"level":4,"theme":"日常與一般"},{"word":"permanently","pos":"adv.","phonetic":"[ˈpɝmənəntlɪ]","meaning":"永久地","definition":"forever or for a very long time","collocations":["permanently closed","permanently deleted","move permanently"],"example":"The downtown branch has permanently closed after forty years.","exampleZh":"市中心分店在營業四十年後永久歇業。","synonyms":["forever"],"level":4,"theme":"日常與一般"},{"word":"permission","pos":"n.","phonetic":"[pɚˈmɪʃən]","meaning":"許可；允許","definition":"the act of allowing someone to do something","collocations":["ask for permission","grant permission","without permission"],"example":"You need permission to enter this area.","exampleZh":"進入這個區域需要許可。","synonyms":["consent"],"level":3,"theme":"日常與一般"},{"word":"permit","pos":"n./v.","phonetic":"[ˈpɝmɪt]","meaning":"許可證；允許","definition":"an official document allowing you to do something, or to allow something","collocations":["work permit","building permit","parking permit"],"example":"Contractors must obtain a building permit before starting renovations.","exampleZh":"承包商必須先取得建築許可才能開始施工。","synonyms":["license","allow"],"level":4,"theme":"合約與法律"},{"word":"person","pos":"n.","phonetic":"[ˈpɝsn]","meaning":"人；個人","definition":"a human being","collocations":["in person","per person","contact person"],"example":"Applicants must submit their documents in person at the office.","exampleZh":"申請者必須親自到辦公室繳交文件。","synonyms":["individual"],"level":1,"theme":"日常與一般"},{"word":"personal","pos":"adj.","phonetic":"[ˈpɝsnl]","meaning":"個人的；私人的","definition":"belonging to or relating to one particular person","collocations":["personal belongings","personal information","personal use"],"example":"Please keep personal belongings with you at all times.","exampleZh":"請隨時保管好個人物品。","synonyms":["private"],"level":1,"theme":"日常與一般"},{"word":"personality","pos":"n.","phonetic":"[ˌpɝsnˈælətɪ]","meaning":"個性；人格；名人","definition":"the type of character a person has","collocations":["outgoing personality","personality traits","TV personality"],"example":"Her friendly personality makes her ideal for customer-facing roles.","exampleZh":"她親切的個性非常適合面對顧客的職務。","synonyms":["character"],"level":3,"theme":"人事與職涯"},{"word":"personalize","pos":"v.","phonetic":"[ˈpɝsnəˌlaɪz]","meaning":"客製化；個人化","definition":"to design or change something to suit a particular person","collocations":["personalized service","personalize a gift","personalized recommendations"],"example":"The app personalizes recommendations based on your purchase history.","exampleZh":"這款應用程式會根據你的購買紀錄提供個人化推薦。","synonyms":["customize","tailor"],"level":5,"theme":"行銷與銷售"},{"word":"personally","pos":"adv.","phonetic":"[ˈpɝsnlɪ]","meaning":"親自；就個人而言","definition":"done by yourself, or speaking for yourself","collocations":["personally responsible","thank someone personally"],"example":"The manager personally thanked each volunteer after the event.","exampleZh":"活動結束後，經理親自向每位志工道謝。","synonyms":["in person"],"level":3,"theme":"日常與一般"},{"word":"personnel","pos":"n.","phonetic":"[ˌpɚsnˈɛl]","meaning":"人員；職員","definition":"the people employed in an organization or the department that deals with them","collocations":["military personnel","personnel department","hire personnel"],"example":"All personnel must wear identification badges.","exampleZh":"所有人員都必須佩戴識別證。","synonyms":["staff"],"level":5,"theme":"人事與職涯"},{"word":"perspective","pos":"n.","phonetic":"[pɚˈspɛktɪv]","meaning":"觀點；透視","definition":"a particular way of looking at or thinking about something","collocations":["from my perspective","gain perspective","a different perspective"],"example":"Traveling abroad gave her a new perspective on life.","exampleZh":"出國旅行讓她對人生有了新的看法。","synonyms":["viewpoint"],"level":5,"theme":"日常與一般"},{"word":"persuade","pos":"v.","phonetic":"[pɚˈswed]","meaning":"說服；勸服","definition":"to make someone agree to do something by giving good reasons","collocations":["persuade customers","persuade someone to"],"example":"The presentation persuaded the board to approve the expansion.","exampleZh":"這場簡報說服了董事會核准擴張計畫。","synonyms":["convince"],"level":3,"theme":"溝通與語言"},{"word":"persuasive","pos":"adj.","phonetic":"[pɚˈswesɪv]","meaning":"有說服力的","definition":"good at making people agree or believe something","collocations":["persuasive argument","persuasive presentation"],"example":"Her persuasive proposal won over even the most cautious investors.","exampleZh":"她深具說服力的提案連最謹慎的投資人都被打動。","synonyms":["convincing","compelling"],"level":5,"theme":"溝通與語言"},{"word":"pharmacy","pos":"n.","phonetic":"[ˈfɑrməsɪ]","meaning":"藥局；藥房","definition":"a shop where medicines are prepared and sold","collocations":["24-hour pharmacy","pharmacy counter","local pharmacy"],"example":"The prescription can be picked up at any branch pharmacy.","exampleZh":"處方藥可在任何分店藥局領取。","synonyms":["drugstore"],"level":3,"theme":"醫療與保險"},{"word":"phase","pos":"n./v.","phonetic":"[fez]","meaning":"階段；分階段實施","definition":"a stage in a process of development","collocations":["first phase","phase out","phase of the project"],"example":"The first phase of construction will finish in October.","exampleZh":"第一期工程將於十月完工。","synonyms":["stage","step"],"level":4,"theme":"企業經營"},{"word":"phone","pos":"n./v.","phonetic":"[fon]","meaning":"電話；打電話","definition":"a device used to talk to someone far away, or to call someone","collocations":["phone call","answer the phone","phone number"],"example":"Please answer the phone within three rings during business hours.","exampleZh":"營業時間內，電話響三聲內請接聽。","synonyms":["telephone","call"],"level":1,"theme":"科技與通訊"},{"word":"photo","pos":"n.","phonetic":"[ˈfoto]","meaning":"照片","definition":"a picture taken with a camera","collocations":["take a photo","photo ID","photo album"],"example":"A recent photo is required for your employee badge.","exampleZh":"製作員工識別證需要一張近照。","synonyms":["photograph","picture"],"level":1,"theme":"日常與一般"},{"word":"photocopier","pos":"n.","phonetic":"[ˈfotəˌkɑpɪɚ]","meaning":"影印機","definition":"a machine that makes paper copies of documents","collocations":["use the photocopier","photocopier maintenance"],"example":"The photocopier on the third floor is out of order.","exampleZh":"三樓的影印機故障了。","synonyms":["copier"],"level":3,"theme":"辦公室與行政"},{"word":"photocopy","pos":"n./v.","phonetic":"[ˈfotəˌkɑpɪ]","meaning":"影本；影印","definition":"a paper copy of a document made by a machine, or to make one","collocations":["make a photocopy","photocopy of the receipt"],"example":"Please make ten photocopies of the agenda for the meeting.","exampleZh":"請影印十份會議議程。","synonyms":["copy"],"level":3,"theme":"辦公室與行政"},{"word":"photograph","pos":"n./v.","phonetic":"[ˈfotəˌgræf]","meaning":"照片；拍照","definition":"a picture made with a camera, or to take such a picture","collocations":["take a photograph","black-and-white photograph"],"example":"Visitors may not photograph the artwork inside the gallery.","exampleZh":"訪客不得拍攝館內的藝術品。","synonyms":["photo","picture"],"level":2,"theme":"媒體與活動"},{"word":"photographer","pos":"n.","phonetic":"[fəˈtɑgrəfɚ]","meaning":"攝影師","definition":"a person who takes photographs, especially as a job","collocations":["professional photographer","wedding photographer","hire a photographer"],"example":"A professional photographer will take headshots for the company website.","exampleZh":"專業攝影師將為公司網站拍攝形象照。","synonyms":[],"level":3,"theme":"媒體與活動"},{"word":"photography","pos":"n.","phonetic":"[fəˈtɑgrəfɪ]","meaning":"攝影；攝影術","definition":"the art or activity of taking photographs","collocations":["photography exhibition","landscape photography","photography studio"],"example":"Flash photography is not permitted inside the museum.","exampleZh":"博物館內禁止使用閃光燈拍照。","synonyms":[],"level":3,"theme":"媒體與活動"},{"word":"phrase","pos":"n./v.","phonetic":"[frez]","meaning":"片語；措辭；表達","definition":"a group of words with a particular meaning, or to express something in words","collocations":["common phrase","phrase a question","key phrase"],"example":"Try to phrase your feedback in a positive, constructive way.","exampleZh":"請盡量以正面且有建設性的方式表達你的意見。","synonyms":["expression"],"level":2,"theme":"溝通與語言"},{"word":"physical","pos":"adj./n.","phonetic":"[ˈfɪzɪkl]","meaning":"身體的；實體的；健康檢查","definition":"relating to the body or to real objects, or a medical examination","collocations":["physical examination","physical store","physical labor"],"example":"All new drivers must pass a physical examination before starting.","exampleZh":"所有新進駕駛開始工作前必須通過健康檢查。","synonyms":[],"level":3,"theme":"醫療與保險"},{"word":"physically","pos":"adv.","phonetic":"[ˈfɪzɪklɪ]","meaning":"身體上；實體上","definition":"in a way related to the body or real objects","collocations":["physically demanding","physically present","physically fit"],"example":"Warehouse work can be physically demanding, so proper training is essential.","exampleZh":"倉儲工作對體力要求高，因此適當的訓練不可或缺。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"physician","pos":"n.","phonetic":"[fɪˈzɪʃən]","meaning":"醫師；內科醫生","definition":"a medical doctor","collocations":["consult a physician","family physician","attending physician"],"example":"Consult your physician before beginning any new exercise program.","exampleZh":"開始任何新的運動計畫前，請先諮詢醫師。","synonyms":["doctor"],"level":5,"theme":"醫療與保險"},{"word":"pick","pos":"v. / n.","phonetic":"[pɪk]","meaning":"挑選；摘；採","definition":"to choose someone or something from a group of people or things","collocations":["pick a winner","pick flowers","pick a fight"],"example":"She picked the reddest apple from the tree.","exampleZh":"她從樹上摘了那顆最紅的蘋果。","synonyms":["choose","select"],"level":1,"theme":"日常與一般"},{"word":"picture","pos":"n. / v.","phonetic":"[ˈpɪktʃɚ]","meaning":"圖畫；照片；想像","definition":"a painting, drawing, or photograph","collocations":["take a picture","draw a picture","picture frame"],"example":"He hung a picture of his family on the wall.","exampleZh":"他把一張家人的照片掛在牆上。","synonyms":["photo","image"],"level":1,"theme":"媒體與活動"},{"word":"piece","pos":"n.","phonetic":"[pis]","meaning":"片；塊；件","definition":"a portion of an object or of material, produced by cutting, tearing, or breaking the whole","collocations":["a piece of cake","piece by piece","break into pieces"],"example":"Could I have a piece of that chocolate cake?","exampleZh":"我可以吃一塊那個巧克力蛋糕嗎？","synonyms":["portion","part"],"level":1,"theme":"日常與一般"},{"word":"pilot","pos":"n. / v.","phonetic":"[ˈpaɪlət]","meaning":"飛行員；駕駛員；試驗性的","definition":"a person who flies an aircraft","collocations":["airline pilot","pilot a plane","pilot program"],"example":"The pilot landed the plane safely despite the storm.","exampleZh":"儘管有暴風雨，飛行員仍安全地降落了飛機。","synonyms":["aviator"],"level":3,"theme":"人事與職涯"},{"word":"place","pos":"n. / v.","phonetic":"[ples]","meaning":"地方；場所；放置","definition":"a particular position, point, or area in space; to put something somewhere","collocations":["take place","place an order","in the first place"],"example":"This is a great place to watch the sunset.","exampleZh":"這是個欣賞日落的絕佳地點。","synonyms":["location","spot"],"level":1,"theme":"日常與一般"},{"word":"placement","pos":"n.","phonetic":"[ˈplesmənt]","meaning":"安置；職位安排；擺放位置","definition":"the act of finding a job or place for someone, or the position of something","collocations":["job placement","product placement","placement test"],"example":"The agency offers a job placement service for recent graduates.","exampleZh":"該機構為應屆畢業生提供就業媒合服務。","synonyms":["positioning"],"level":5,"theme":"人事與職涯"},{"word":"plain","pos":"adj. / n.","phonetic":"[plen]","meaning":"平坦的；樸素的；平原","definition":"simple or ordinary in character, or a large flat area of land","collocations":["plain food","plain language","vast plain"],"example":"She prefers plain clothes without any decoration.","exampleZh":"她偏好沒有裝飾的樸素衣服。","synonyms":["simple","clear"],"level":3,"theme":"日常與一般"},{"word":"plan","pos":"n. / v.","phonetic":"[plæn]","meaning":"計畫；打算","definition":"a detailed proposal for doing or achieving something","collocations":["make a plan","plan ahead","business plan"],"example":"They made a plan to travel around Europe next summer.","exampleZh":"他們計畫明年夏天環遊歐洲。","synonyms":["scheme","proposal"],"level":1,"theme":"日常與一般"},{"word":"plane","pos":"n.","phonetic":"[plen]","meaning":"飛機；平面","definition":"an aircraft with wings and one or more engines","collocations":["catch a plane","plane ticket","board the plane"],"example":"Our plane departs at seven in the morning.","exampleZh":"我們的飛機早上七點起飛。","synonyms":["airplane","aircraft"],"level":1,"theme":"旅遊與交通"},{"word":"planning","pos":"n.","phonetic":"[ˈplænɪŋ]","meaning":"規劃；計畫","definition":"the process of deciding how to do something in the future","collocations":["financial planning","urban planning","planning stage"],"example":"Careful planning helped the event run without a single problem.","exampleZh":"周密的規劃讓活動進行得毫無差錯。","synonyms":["preparation"],"level":3,"theme":"企業經營"},{"word":"plant","pos":"n. / v.","phonetic":"[plænt]","meaning":"植物；工廠；種植","definition":"a living thing that grows in the ground, or to put seeds in soil","collocations":["plant a tree","power plant","water the plants"],"example":"She waters the plants on her balcony every morning.","exampleZh":"她每天早上都會澆陽台上的植物。","synonyms":["vegetation"],"level":1,"theme":"日常與一般"},{"word":"platform","pos":"n.","phonetic":"[ˈplætˌfɔrm]","meaning":"月台；平台；講台","definition":"a raised, level surface where people stand, such as at a train station","collocations":["train platform","online platform","political platform"],"example":"The train arrived at platform three.","exampleZh":"火車抵達了第三月台。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"play","pos":"v. / n.","phonetic":"[ple]","meaning":"玩；扮演；戲劇","definition":"to engage in games or other activities for enjoyment","collocations":["play a game","play the piano","watch a play"],"example":"The children love to play in the park after school.","exampleZh":"孩子們喜歡放學後在公園玩耍。","synonyms":["perform","act"],"level":1,"theme":"媒體與活動"},{"word":"please","pos":"v. / adv.","phonetic":"[pliz]","meaning":"取悅；請","definition":"to make someone feel happy or satisfied","collocations":["please someone","hard to please","yes, please"],"example":"He always tries to please his parents.","exampleZh":"他總是努力討父母歡心。","synonyms":["satisfy","delight"],"level":1,"theme":"日常與一般"},{"word":"pleasure","pos":"n.","phonetic":"[ˈplɛʒɚ]","meaning":"愉快；樂趣","definition":"a feeling of happiness or satisfaction","collocations":["with pleasure","take pleasure in","guilty pleasure"],"example":"Reading brings her great pleasure every evening.","exampleZh":"閱讀每晚都為她帶來很大的樂趣。","synonyms":["enjoyment","delight"],"level":2,"theme":"日常與一般"},{"word":"pledge","pos":"n. / v.","phonetic":"[plɛdʒ]","meaning":"誓言；保證；發誓","definition":"a serious promise to do something","collocations":["make a pledge","pledge allegiance","pledge support"],"example":"The company pledged to reduce its carbon emissions.","exampleZh":"這家公司承諾要減少碳排放。","synonyms":["promise","vow"],"level":5,"theme":"日常與一般"},{"word":"plentiful","pos":"adj.","phonetic":"[ˈplɛntɪfəl]","meaning":"豐富的；充足的","definition":"existing in large amounts or numbers","collocations":["plentiful resources","plentiful supply","plentiful harvest"],"example":"Fish were plentiful in the river back then.","exampleZh":"當年河裡的魚非常豐富。","synonyms":["abundant","ample"],"level":5,"theme":"日常與一般"},{"word":"plenty","pos":"n. / pron. / adv.","phonetic":"[ˈplɛnti]","meaning":"許多；充足","definition":"a large amount that is more than enough","collocations":["plenty of time","plenty of money","in plenty"],"example":"There is plenty of food for everyone at the party.","exampleZh":"派對上有足夠所有人吃的食物。","synonyms":["abundance"],"level":2,"theme":"日常與一般"},{"word":"plot","pos":"n. / v.","phonetic":"[plɑt]","meaning":"情節；陰謀；策劃","definition":"the main events of a play, novel, or movie, or a secret plan","collocations":["movie plot","plot a scheme","plot against"],"example":"The plot of the novel was full of unexpected twists.","exampleZh":"這本小說的情節充滿了意想不到的轉折。","synonyms":["scheme","storyline"],"level":4,"theme":"媒體與活動"},{"word":"plumber","pos":"n.","phonetic":"[ˈplʌmɚ]","meaning":"水管工人","definition":"a person whose job is to fit and repair water pipes and other plumbing equipment","collocations":["call a plumber","local plumber","plumber fixes pipes"],"example":"We called a plumber to fix the leaking pipe.","exampleZh":"我們找了水管工人來修漏水的管子。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"plumbing","pos":"n.","phonetic":"[ˈplʌmɪŋ]","meaning":"水管系統；水電工程","definition":"the pipes that carry water in a building, or the work of fitting them","collocations":["plumbing problem","plumbing repairs","plumbing system"],"example":"The office kitchen is closed while plumbing repairs are underway.","exampleZh":"辦公室茶水間因水管維修暫停使用。","synonyms":[],"level":4,"theme":"房產與設施"},{"word":"podium","pos":"n.","phonetic":"[ˈpodɪəm]","meaning":"講台；領獎台","definition":"a raised platform for a speaker or performer","collocations":["at the podium","step up to the podium"],"example":"The keynote speaker approached the podium to loud applause.","exampleZh":"主講人在熱烈掌聲中走上講台。","synonyms":["platform","stand"],"level":5,"theme":"會議與簡報"},{"word":"point","pos":"n. / v.","phonetic":"[pɔɪnt]","meaning":"點；重點；指向","definition":"an idea or opinion expressed, or a particular position or place","collocations":["point out","make a point","point at"],"example":"She made a good point during the meeting.","exampleZh":"她在會議中提出了一個好觀點。","synonyms":["indicate","aim"],"level":1,"theme":"日常與一般"},{"word":"policy","pos":"n.","phonetic":"[ˈpɑləsi]","meaning":"政策；方針","definition":"a plan of action agreed on by a government, business, or organization","collocations":["government policy","company policy","foreign policy"],"example":"The new policy aims to reduce air pollution.","exampleZh":"這項新政策旨在減少空氣污染。","synonyms":["strategy","plan"],"level":4,"theme":"合約與法律"},{"word":"polite","pos":"adj.","phonetic":"[pəˈlaɪt]","meaning":"有禮貌的；客氣的","definition":"having or showing good manners and respect for other people","collocations":["polite manner","politely ask","stay polite"],"example":"The waiter was very polite to all the customers.","exampleZh":"這位服務生對所有顧客都非常有禮貌。","synonyms":["courteous","respectful"],"level":2,"theme":"日常與一般"},{"word":"politely","pos":"adv.","phonetic":"[pəˈlaɪtlɪ]","meaning":"有禮貌地","definition":"in a way that shows good manners","collocations":["politely decline","politely ask"],"example":"She politely declined the invitation due to a scheduling conflict.","exampleZh":"由於行程衝突，她婉拒了邀請。","synonyms":["courteously"],"level":3,"theme":"溝通與語言"},{"word":"poll","pos":"n. / v.","phonetic":"[pol]","meaning":"民意調查；投票","definition":"a survey of people's opinions on a particular subject","collocations":["opinion poll","conduct a poll","poll results"],"example":"A recent poll shows most people support the new law.","exampleZh":"最近的一項民調顯示大多數人支持這項新法。","synonyms":["survey"],"level":4,"theme":"合約與法律"},{"word":"pollution","pos":"n.","phonetic":"[pəˈluʃən]","meaning":"污染","definition":"the presence of harmful substances in the environment","collocations":["air pollution","reduce pollution","noise pollution"],"example":"Air pollution has become a serious problem in big cities.","exampleZh":"空氣污染已成為大城市的嚴重問題。","synonyms":["contamination"],"level":3,"theme":"日常與一般"},{"word":"pool","pos":"n. / v.","phonetic":"[pul]","meaning":"游泳池；水池；集中","definition":"a small area of still water, or a structure filled with water for swimming","collocations":["swimming pool","pool resources","car pool"],"example":"The kids spent the whole afternoon in the swimming pool.","exampleZh":"孩子們整個下午都待在游泳池裡。","synonyms":[],"level":1,"theme":"媒體與活動"},{"word":"poor","pos":"adj.","phonetic":"[pʊr]","meaning":"貧窮的；差的；可憐的","definition":"having very little money or resources","collocations":["poor family","poor quality","poor thing"],"example":"They grew up in a poor neighborhood.","exampleZh":"他們在一個貧窮的社區長大。","synonyms":["needy","impoverished"],"level":1,"theme":"財務與會計"},{"word":"popular","pos":"adj.","phonetic":"[ˈpɑpjəlɚ]","meaning":"受歡迎的；流行的","definition":"liked, admired, or supported by many people","collocations":["popular song","popular among students","become popular"],"example":"This restaurant is very popular with tourists.","exampleZh":"這家餐廳深受觀光客歡迎。","synonyms":["well-liked","favored"],"level":2,"theme":"日常與一般"},{"word":"popularity","pos":"n.","phonetic":"[ˌpɑpjəˈlærəti]","meaning":"受歡迎；名氣","definition":"the state of being liked or admired by many people","collocations":["gain popularity","lose popularity","rise in popularity"],"example":"The singer's popularity grew rapidly after the concert.","exampleZh":"這位歌手在演唱會後人氣迅速上升。","synonyms":["fame"],"level":4,"theme":"日常與一般"},{"word":"population","pos":"n.","phonetic":"[ˌpɑpjəˈleʃən]","meaning":"人口","definition":"all the people who live in a particular area or country","collocations":["population growth","total population","aging population"],"example":"The population of the city has doubled in ten years.","exampleZh":"這座城市的人口在十年間增加了一倍。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"port","pos":"n.","phonetic":"[pɔrt]","meaning":"港口","definition":"a town or area with a harbor where ships load and unload goods","collocations":["sea port","port city","arrive at port"],"example":"The ship docked at the port early in the morning.","exampleZh":"這艘船一大早就在港口靠岸了。","synonyms":["harbor"],"level":3,"theme":"旅遊與交通"},{"word":"portable","pos":"adj.","phonetic":"[ˈpɔrtəbl̩]","meaning":"可攜帶的；輕便的","definition":"able to be easily carried or moved","collocations":["portable device","portable speaker","portable computer"],"example":"He bought a portable speaker for his trip.","exampleZh":"他買了一個輕便喇叭準備旅行用。","synonyms":["movable"],"level":4,"theme":"科技與通訊"},{"word":"portfolio","pos":"n.","phonetic":"[portˈfolɪˌo]","meaning":"作品集；投資組合","definition":"a collection of work samples, or a group of investments","collocations":["design portfolio","investment portfolio","diversify a portfolio"],"example":"Applicants for the designer role should submit an online portfolio.","exampleZh":"應徵設計師職位者請提交線上作品集。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"portion","pos":"n.","phonetic":"[ˈpɔrʃən]","meaning":"部分；一份","definition":"a part or share of a whole","collocations":["a portion of","food portion","large portion"],"example":"He ate only a small portion of the meal.","exampleZh":"他只吃了這頓飯的一小部分。","synonyms":["part","share"],"level":4,"theme":"餐飲與住宿"},{"word":"portrait","pos":"n.","phonetic":"[ˈpɔrtrɪt]","meaning":"肖像；畫像","definition":"a painting, drawing, or photograph of a person","collocations":["family portrait","paint a portrait","self-portrait"],"example":"The artist painted a beautiful portrait of the queen.","exampleZh":"這位藝術家畫了一幅美麗的女王肖像。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"pose","pos":"v. / n.","phonetic":"[poz]","meaning":"擺姿勢；造成；姿勢","definition":"to present or cause something, such as a problem or threat","collocations":["pose a threat","pose for a photo","strike a pose"],"example":"The rising sea level poses a serious threat to coastal cities.","exampleZh":"海平面上升對沿海城市構成嚴重威脅。","synonyms":["present","cause"],"level":4,"theme":"日常與一般"},{"word":"position","pos":"n. / v.","phonetic":"[pəˈzɪʃən]","meaning":"位置；職位；立場","definition":"the place where someone or something is located, or a job or rank","collocations":["job position","current position","position oneself"],"example":"She applied for a position in the marketing department.","exampleZh":"她應徵了行銷部門的一個職位。","synonyms":["location","post"],"level":2,"theme":"人事與職涯"},{"word":"positive","pos":"adj.","phonetic":"[ˈpɑzətɪv]","meaning":"正面的；積極的；肯定的","definition":"good, favorable, or full of hope","collocations":["positive attitude","positive result","stay positive"],"example":"She always tries to stay positive even during hard times.","exampleZh":"即使在艱難的時刻，她也總是努力保持積極。","synonyms":["optimistic","favorable"],"level":2,"theme":"日常與一般"},{"word":"possess","pos":"v.","phonetic":"[pəˈzɛs]","meaning":"擁有；具有","definition":"to have or own something","collocations":["possess a skill","possess qualities","legally possess"],"example":"He possesses a remarkable talent for painting.","exampleZh":"他擁有非凡的繪畫天賦。","synonyms":["own","have"],"level":4,"theme":"日常與一般"},{"word":"possession","pos":"n.","phonetic":"[pəˈzɛʃən]","meaning":"擁有；財產；所有物","definition":"the state of owning or having something, or something that is owned","collocations":["personal possessions","take possession of","in possession"],"example":"She lost all her possessions in the fire.","exampleZh":"她在那場火災中失去了所有財產。","synonyms":["property","belongings"],"level":4,"theme":"財務與會計"},{"word":"possibility","pos":"n.","phonetic":"[ˌpɑsəˈbɪləti]","meaning":"可能性","definition":"a chance that something may happen or be true","collocations":["a real possibility","explore possibilities","rule out the possibility"],"example":"There is a possibility that the meeting will be postponed.","exampleZh":"這場會議有可能會延期。","synonyms":["chance","likelihood"],"level":3,"theme":"日常與一般"},{"word":"possible","pos":"adj.","phonetic":"[ˈpɑsəbl]","meaning":"可能的","definition":"able to happen or be done","collocations":["as soon as possible","if possible","make it possible"],"example":"Please confirm your attendance as soon as possible.","exampleZh":"請盡快確認您是否出席。","synonyms":["feasible"],"level":1,"theme":"日常與一般"},{"word":"possibly","pos":"adv.","phonetic":"[ˈpɑsəblɪ]","meaning":"可能地；或許","definition":"perhaps, or within what is possible","collocations":["quite possibly","can't possibly"],"example":"The shipment could possibly arrive a day earlier than scheduled.","exampleZh":"貨物有可能比預定時間提早一天送達。","synonyms":["perhaps","maybe"],"level":2,"theme":"日常與一般"},{"word":"post","pos":"n./v.","phonetic":"[post]","meaning":"職位；郵寄；張貼；發布","definition":"a job, to send mail, or to put up a notice or online message","collocations":["post a notice","post a job opening","post office"],"example":"The schedule for next month is posted on the staff bulletin board.","exampleZh":"下個月的班表已張貼在員工公布欄。","synonyms":["publish","position"],"level":2,"theme":"辦公室與行政"},{"word":"postage","pos":"n.","phonetic":"[ˈpostɪdʒ]","meaning":"郵資","definition":"the cost of sending something by mail","collocations":["postage stamp","postage paid","postage and handling"],"example":"Return postage is prepaid, so simply drop the package at any mailbox.","exampleZh":"回郵郵資已預付，只需將包裹投入任一郵筒即可。","synonyms":[],"level":4,"theme":"辦公室與行政"},{"word":"postal","pos":"adj.","phonetic":"[ˈpostl]","meaning":"郵政的","definition":"relating to the mail service","collocations":["postal service","postal code","postal worker"],"example":"Include the correct postal code to avoid delivery delays.","exampleZh":"請填寫正確的郵遞區號，以免延誤投遞。","synonyms":[],"level":4,"theme":"辦公室與行政"},{"word":"poster","pos":"n.","phonetic":"[ˈpostɚ]","meaning":"海報","definition":"a large printed picture or notice put on a wall","collocations":["promotional poster","put up a poster","movie poster"],"example":"Posters advertising the concert were placed around the campus.","exampleZh":"宣傳音樂會的海報張貼在校園各處。","synonyms":[],"level":2,"theme":"行銷與銷售"},{"word":"postpone","pos":"v.","phonetic":"[postˈpon]","meaning":"延期；延後","definition":"to arrange for something to happen at a later time","collocations":["postpone a meeting","postpone until","postpone indefinitely"],"example":"The outdoor ceremony was postponed until Saturday because of rain.","exampleZh":"戶外典禮因雨延至週六舉行。","synonyms":["delay","put off"],"level":4,"theme":"辦公室與行政"},{"word":"potential","pos":"adj./n.","phonetic":"[pəˈtɛnʃəl]","meaning":"潛在的；潛力","definition":"possible in the future, or the ability to develop and succeed","collocations":["potential customers","growth potential","reach one's potential"],"example":"The sales team identified fifty potential clients at the trade fair.","exampleZh":"業務團隊在商展上找到了五十個潛在客戶。","synonyms":["possible","prospective"],"level":4,"theme":"行銷與銷售"},{"word":"potentially","pos":"adv.","phonetic":"[pəˈtɛnʃəlɪ]","meaning":"潛在地；可能地","definition":"possibly, with the ability to become something in the future","collocations":["potentially dangerous","potentially profitable"],"example":"The new market is potentially worth millions in annual revenue.","exampleZh":"這個新市場每年可能帶來數百萬的營收。","synonyms":["possibly"],"level":5,"theme":"企業經營"},{"word":"pour","pos":"v.","phonetic":"[por]","meaning":"倒；傾注；湧入","definition":"to make a liquid flow from a container, or to flow in large amounts","collocations":["pour coffee","pour into","pour investment into"],"example":"The waiter poured water for everyone before taking orders.","exampleZh":"服務生在點餐前先為每位客人倒水。","synonyms":[],"level":2,"theme":"餐飲與住宿"},{"word":"power","pos":"n./v.","phonetic":"[ˈpaʊɚ]","meaning":"電力；力量；權力；供電","definition":"electricity, strength, or the ability to control","collocations":["power outage","power supply","solar power"],"example":"A power outage briefly interrupted production at the plant.","exampleZh":"停電使工廠的生產短暫中斷。","synonyms":["electricity","energy"],"level":1,"theme":"房產與設施"},{"word":"practical","pos":"adj.","phonetic":"[ˈpræktɪkl]","meaning":"實際的；實用的","definition":"concerned with actual use rather than theory","collocations":["practical solution","practical experience","practical joke"],"example":"He gave us some practical advice on saving money.","exampleZh":"他給了我們一些實用的省錢建議。","synonyms":["realistic","useful"],"level":2,"theme":"日常與一般"},{"word":"practically","pos":"adv.","phonetic":"[ˈpræktɪklɪ]","meaning":"幾乎；實際上","definition":"almost, or in a practical way","collocations":["practically impossible","practically every"],"example":"The parking lot is practically full by eight every morning.","exampleZh":"停車場每天早上八點就幾乎停滿了。","synonyms":["almost","virtually"],"level":4,"theme":"日常與一般"},{"word":"practice","pos":"n. / v.","phonetic":"[ˈpræktɪs]","meaning":"練習；實踐；慣例","definition":"repeated exercise to gain skill, or the actual application of an idea","collocations":["practice makes perfect","medical practice","practice a sport"],"example":"She practices the piano every evening.","exampleZh":"她每天晚上都會練習彈鋼琴。","synonyms":["exercise","rehearsal"],"level":1,"theme":"人事與職涯"},{"word":"practitioner","pos":"n.","phonetic":"[prækˈtɪʃənɚ]","meaning":"執業者；從業人員","definition":"a person who works in a profession such as medicine or law","collocations":["medical practitioner","general practitioner","legal practitioner"],"example":"The clinic has five licensed practitioners on staff.","exampleZh":"這家診所有五位持照執業的醫師。","synonyms":["professional"],"level":6,"theme":"醫療與保險"},{"word":"precaution","pos":"n.","phonetic":"[prɪˈkɔʃən]","meaning":"預防措施","definition":"something done to prevent problems or danger","collocations":["safety precautions","take precautions","as a precaution"],"example":"As a precaution, back up all files before the system update.","exampleZh":"為以防萬一，系統更新前請備份所有檔案。","synonyms":["safeguard"],"level":5,"theme":"辦公室與行政"},{"word":"precise","pos":"adj.","phonetic":"[prɪˈsaɪs]","meaning":"精確的；確切的","definition":"exact and accurate","collocations":["precise measurement","precise instructions","to be precise"],"example":"We need precise data before making a decision.","exampleZh":"我們需要精確的數據才能做決定。","synonyms":["exact","accurate"],"level":4,"theme":"日常與一般"},{"word":"precisely","pos":"adv.","phonetic":"[prɪˈsaɪslɪ]","meaning":"精確地；恰好","definition":"exactly and accurately","collocations":["precisely at noon","more precisely"],"example":"The tour departs precisely at nine, so please arrive early.","exampleZh":"導覽準時九點出發，請提早抵達。","synonyms":["exactly"],"level":4,"theme":"日常與一般"},{"word":"predecessor","pos":"n.","phonetic":"[ˈprɛdɪˌsɛsɚ]","meaning":"前任；前身","definition":"the person who had a job before someone else, or an earlier version of something","collocations":["immediate predecessor","succeed one's predecessor"],"example":"The new model is lighter and faster than its predecessor.","exampleZh":"新機型比前一代更輕、更快。","synonyms":["forerunner"],"level":6,"theme":"人事與職涯"},{"word":"predict","pos":"v.","phonetic":"[prɪˈdɪkt]","meaning":"預測；預言","definition":"to say that something will happen in the future","collocations":["predict the outcome","predict the weather","hard to predict"],"example":"Scientists predict that sea levels will rise.","exampleZh":"科學家預測海平面將會上升。","synonyms":["forecast","foresee"],"level":3,"theme":"科技與通訊"},{"word":"prediction","pos":"n.","phonetic":"[prɪˈdɪkʃən]","meaning":"預測；預言","definition":"a statement about what will happen in the future","collocations":["make a prediction","accurate prediction","sales prediction"],"example":"The analyst's prediction about holiday sales proved accurate.","exampleZh":"分析師對節慶買氣的預測相當準確。","synonyms":["forecast"],"level":4,"theme":"企業經營"},{"word":"prefer","pos":"v.","phonetic":"[prɪˈfɝ]","meaning":"比較喜歡；偏好","definition":"to like one thing better than another","collocations":["prefer A to B","prefer doing something","would prefer"],"example":"I prefer tea to coffee.","exampleZh":"比起咖啡，我比較喜歡茶。","synonyms":["favor"],"level":2,"theme":"日常與一般"},{"word":"preference","pos":"n.","phonetic":"[ˈprɛfərəns]","meaning":"偏好；喜好","definition":"a greater liking for one alternative over another","collocations":["personal preference","show a preference","food preference"],"example":"Do you have any preference for the color of the walls?","exampleZh":"你對牆壁的顏色有什麼偏好嗎？","synonyms":["liking"],"level":4,"theme":"日常與一般"},{"word":"preliminary","pos":"adj./n.","phonetic":"[prɪˈlɪməˌnɛrɪ]","meaning":"初步的；預備的","definition":"happening before a more important action or event","collocations":["preliminary results","preliminary report","preliminary round"],"example":"Preliminary results show strong demand for the new service.","exampleZh":"初步結果顯示新服務的需求強勁。","synonyms":["initial"],"level":6,"theme":"企業經營"},{"word":"premises","pos":"n.","phonetic":"[ˈprɛmɪsɪz]","meaning":"營業場所；房屋及土地","definition":"the buildings and land that a business uses","collocations":["on the premises","business premises","leave the premises"],"example":"Smoking is prohibited anywhere on the premises.","exampleZh":"場區內任何地方均禁止吸菸。","synonyms":["property","site"],"level":6,"theme":"房產與設施"},{"word":"premium","pos":"n./adj.","phonetic":"[ˈprimɪəm]","meaning":"保險費；額外費用；高級的","definition":"money paid for insurance, an extra charge, or of high quality","collocations":["insurance premium","premium service","at a premium"],"example":"Monthly premiums will rise slightly under the new insurance plan.","exampleZh":"在新的保險方案下，每月保費將略為調漲。","synonyms":[],"level":5,"theme":"醫療與保險"},{"word":"prepaid","pos":"adj.","phonetic":"[priˈped]","meaning":"預付的","definition":"paid for in advance","collocations":["prepaid card","prepaid envelope","prepaid shipping"],"example":"Use the prepaid envelope to return the signed documents.","exampleZh":"請使用預付郵資的信封寄回簽署好的文件。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"preparation","pos":"n.","phonetic":"[ˌprɛpəˈreʃən]","meaning":"準備；預備工作","definition":"the action of making something ready for use","collocations":["make preparations","in preparation for","careful preparation"],"example":"The preparation for the wedding took months.","exampleZh":"這場婚禮的準備工作花了好幾個月。","synonyms":["arrangement"],"level":4,"theme":"日常與一般"},{"word":"prepare","pos":"v.","phonetic":"[prɪˈpɛr]","meaning":"準備；預備","definition":"to make ready for something","collocations":["prepare for an exam","prepare a meal","prepare in advance"],"example":"She is preparing for her final exams.","exampleZh":"她正在準備期末考試。","synonyms":["arrange","get ready"],"level":2,"theme":"人事與職涯"},{"word":"prescribe","pos":"v.","phonetic":"[prɪˈskraɪb]","meaning":"開處方；規定","definition":"to say what medicine someone should take, or to state officially what must be done","collocations":["prescribe medication","prescribed by law"],"example":"The doctor prescribed antibiotics for the infection.","exampleZh":"醫生針對感染開了抗生素。","synonyms":[],"level":5,"theme":"醫療與保險"},{"word":"prescription","pos":"n.","phonetic":"[prɪˈskrɪpʃən]","meaning":"處方；處方箋","definition":"a doctor's written order for medicine","collocations":["fill a prescription","prescription drugs","by prescription only"],"example":"You can fill your prescription at the pharmacy next door.","exampleZh":"你可以在隔壁的藥局領取處方藥。","synonyms":[],"level":4,"theme":"醫療與保險"},{"word":"presence","pos":"n.","phonetic":"[ˈprɛzns]","meaning":"出席；存在","definition":"the state of being present in a place","collocations":["presence of mind","in the presence of","police presence"],"example":"Her presence at the meeting made a difference.","exampleZh":"她出席會議帶來了改變。","synonyms":["attendance"],"level":4,"theme":"日常與一般"},{"word":"present","pos":"adj. / n. / v.","phonetic":"[ˈprɛznt]","meaning":"出席的；禮物；呈現","definition":"being in a certain place; a gift; to show or give something formally","collocations":["present a gift","at present","present the results"],"example":"He gave his sister a birthday present.","exampleZh":"他送給妹妹一份生日禮物。","synonyms":["gift","introduce"],"level":1,"theme":"房產與設施"},{"word":"presentation","pos":"n.","phonetic":"[ˌprizɛnˈteʃən]","meaning":"簡報；報告；呈現","definition":"a talk giving information to a group, or the way something is shown","collocations":["give a presentation","presentation slides","sales presentation"],"example":"She gave an impressive presentation on the quarterly results.","exampleZh":"她就季度業績做了一場令人印象深刻的簡報。","synonyms":["talk","briefing"],"level":3,"theme":"會議與簡報"},{"word":"presently","pos":"adv.","phonetic":"[ˈprɛzntlɪ]","meaning":"目前；不久","definition":"now, or soon","collocations":["presently unavailable","presently under construction"],"example":"The manager is presently in a meeting but will return your call.","exampleZh":"經理目前正在開會，稍後會回電給您。","synonyms":["currently"],"level":5,"theme":"日常與一般"},{"word":"preservation","pos":"n.","phonetic":"[ˌprɛzɚˈveʃən]","meaning":"保存；維護","definition":"the act of keeping something in its original state","collocations":["historic preservation","preservation of documents","food preservation"],"example":"The society raises funds for the preservation of historic buildings.","exampleZh":"該協會為歷史建築的保存募集資金。","synonyms":["conservation"],"level":5,"theme":"媒體與活動"},{"word":"preserve","pos":"v.","phonetic":"[prɪˈzɝv]","meaning":"保存；保護","definition":"to keep something in its original state or protect it from harm","collocations":["preserve food","preserve traditions","preserve the environment"],"example":"We must preserve the rainforest for future generations.","exampleZh":"我們必須為後代保護雨林。","synonyms":["protect","conserve"],"level":4,"theme":"日常與一般"},{"word":"president","pos":"n.","phonetic":"[ˈprɛzədənt]","meaning":"總統；總裁；董事長","definition":"the leader of a country or organization","collocations":["elect a president","president of the company","vice president"],"example":"The president gave a speech about the economy.","exampleZh":"總統發表了一場關於經濟的演說。","synonyms":[],"level":2,"theme":"合約與法律"},{"word":"press","pos":"v. / n.","phonetic":"[prɛs]","meaning":"按；壓；新聞界","definition":"to push firmly against something, or the news media","collocations":["press a button","freedom of the press","press charges"],"example":"Press the button to start the machine.","exampleZh":"按下按鈕啟動機器。","synonyms":["push"],"level":2,"theme":"科技與通訊"},{"word":"pressure","pos":"n.","phonetic":"[ˈprɛʃɚ]","meaning":"壓力；壓迫","definition":"the force applied to a surface, or mental or emotional strain","collocations":["blood pressure","under pressure","peer pressure"],"example":"Students often feel a lot of pressure before exams.","exampleZh":"學生在考試前常感到很大的壓力。","synonyms":["stress","strain"],"level":3,"theme":"日常與一般"},{"word":"pretty","pos":"adj. / adv.","phonetic":"[ˈprɪti]","meaning":"漂亮的；相當地","definition":"attractive, or fairly/quite","collocations":["pretty flower","pretty good","pretty much"],"example":"She wore a pretty dress to the party.","exampleZh":"她穿了一件漂亮的洋裝去參加派對。","synonyms":["attractive","fairly"],"level":1,"theme":"購物與消費"},{"word":"prevent","pos":"v.","phonetic":"[prɪˈvɛnt]","meaning":"預防；阻止","definition":"to stop something from happening","collocations":["prevent disease","prevent an accident","prevent someone from doing"],"example":"Wearing a helmet can prevent serious injury.","exampleZh":"戴安全帽可以預防嚴重的傷害。","synonyms":["stop","avoid"],"level":3,"theme":"醫療與保險"},{"word":"prevention","pos":"n.","phonetic":"[prɪˈvɛnʃən]","meaning":"預防；防止","definition":"the act of stopping something bad from happening","collocations":["fire prevention","accident prevention","prevention measures"],"example":"The seminar covers workplace accident prevention and first aid.","exampleZh":"研討會內容涵蓋職場事故預防與急救。","synonyms":[],"level":4,"theme":"醫療與保險"},{"word":"preview","pos":"n./v.","phonetic":"[ˈpriˌvju]","meaning":"預覽；預告；試映","definition":"an early viewing of something before it is available to everyone","collocations":["sneak preview","preview the document","press preview"],"example":"Members are invited to an exclusive preview of the new collection.","exampleZh":"會員獲邀搶先預覽新系列商品。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"previous","pos":"adj.","phonetic":"[ˈprivɪəs]","meaning":"先前的；以前的","definition":"existing or occurring before something else","collocations":["previous experience","the previous day","previous owner"],"example":"He learned a lot from his previous job.","exampleZh":"他從上一份工作中學到了很多。","synonyms":["prior","earlier"],"level":3,"theme":"日常與一般"},{"word":"previously","pos":"adv.","phonetic":"[ˈprivɪəslɪ]","meaning":"先前；以前","definition":"before the present time or event","collocations":["previously mentioned","previously owned","as previously stated"],"example":"As previously announced, the office will move in September.","exampleZh":"如先前公告，辦公室將於九月搬遷。","synonyms":["formerly","earlier"],"level":4,"theme":"日常與一般"},{"word":"price","pos":"n.","phonetic":"[praɪs]","meaning":"價格；價錢","definition":"the amount of money needed to buy something","collocations":["high price","price tag","at any price"],"example":"The price of gas has gone up again.","exampleZh":"汽油的價格又漲了。","synonyms":["cost"],"level":1,"theme":"財務與會計"},{"word":"pricing","pos":"n.","phonetic":"[ˈpraɪsɪŋ]","meaning":"定價；價格策略","definition":"the act of deciding how much to charge for something","collocations":["competitive pricing","pricing strategy","pricing structure"],"example":"The team is reviewing its pricing strategy for the new fiscal year.","exampleZh":"團隊正在檢討新會計年度的定價策略。","synonyms":[],"level":5,"theme":"行銷與銷售"},{"word":"pride","pos":"n.","phonetic":"[praɪd]","meaning":"驕傲；自豪","definition":"a feeling of satisfaction from one's achievements","collocations":["take pride in","swallow one's pride","local pride"],"example":"She takes great pride in her work.","exampleZh":"她對自己的工作感到十分自豪。","synonyms":["dignity"],"level":3,"theme":"日常與一般"},{"word":"primarily","pos":"adv.","phonetic":"[praɪˈmɛrəlɪ]","meaning":"主要地；首要地","definition":"mainly or mostly","collocations":["primarily responsible","primarily focused on"],"example":"The fund is primarily intended for staff development programs.","exampleZh":"這筆經費主要用於員工發展計畫。","synonyms":["mainly","chiefly"],"level":4,"theme":"日常與一般"},{"word":"primary","pos":"adj.","phonetic":"[ˈpraɪˌmɛri]","meaning":"主要的；最初的","definition":"of chief importance; first in order","collocations":["primary school","primary reason","primary source"],"example":"Her primary goal is to finish the project on time.","exampleZh":"她的主要目標是準時完成這個計畫。","synonyms":["main","principal"],"level":3,"theme":"人事與職涯"},{"word":"principal","pos":"n. / adj.","phonetic":"[ˈprɪnsəpl]","meaning":"校長；主要的","definition":"the head of a school; most important","collocations":["school principal","principal reason","principal role"],"example":"The principal welcomed the new students on the first day.","exampleZh":"校長在開學第一天歡迎新生。","synonyms":["headmaster","main"],"level":3,"theme":"人事與職涯"},{"word":"principle","pos":"n.","phonetic":"[ˈprɪnsəpl]","meaning":"原則；原理","definition":"a fundamental rule or belief that guides behavior","collocations":["basic principle","in principle","stand by one's principles"],"example":"He refused to lie, as a matter of principle.","exampleZh":"出於原則，他拒絕說謊。","synonyms":["rule","doctrine"],"level":4,"theme":"日常與一般"},{"word":"print","pos":"v. / n.","phonetic":"[prɪnt]","meaning":"印刷；列印；印刷品","definition":"to produce text or images on paper using a machine","collocations":["print out","print a document","fine print"],"example":"Please print the report before the meeting.","exampleZh":"請在會議前把報告印出來。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"printer","pos":"n.","phonetic":"[ˈprɪntɚ]","meaning":"印表機；印刷工","definition":"a machine that prints text or images onto paper","collocations":["laser printer","printer paper","printer ink"],"example":"The printer is out of paper again.","exampleZh":"印表機的紙又用完了。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"printing","pos":"n.","phonetic":"[ˈprɪntɪŋ]","meaning":"印刷；列印","definition":"the process of producing text or images on paper","collocations":["printing services","printing costs","color printing"],"example":"The shop offers same-day printing for business cards and flyers.","exampleZh":"這家店提供名片和傳單的當日印刷服務。","synonyms":[],"level":3,"theme":"辦公室與行政"},{"word":"prior","pos":"adj.","phonetic":"[ˈpraɪɚ]","meaning":"先前的；優先的","definition":"existing or happening before something else","collocations":["prior to","prior experience","prior approval"],"example":"Prior approval is required for all purchases over five hundred dollars.","exampleZh":"超過五百美元的採購都需事先核准。","synonyms":["previous","earlier"],"level":4,"theme":"辦公室與行政"},{"word":"priority","pos":"n.","phonetic":"[praɪˈɔrətɪ]","meaning":"優先事項；優先權","definition":"something considered more important than other things","collocations":["top priority","give priority to","priority boarding"],"example":"Customer safety is our top priority at every location.","exampleZh":"顧客安全是我們每個據點的首要考量。","synonyms":["precedence"],"level":4,"theme":"企業經營"},{"word":"privacy","pos":"n.","phonetic":"[ˈpraɪvəsɪ]","meaning":"隱私；隱私權","definition":"the state of being free from public attention, or control over personal information","collocations":["privacy policy","protect privacy","invasion of privacy"],"example":"Our privacy policy explains how customer data is protected.","exampleZh":"我們的隱私權政策說明顧客資料如何受到保護。","synonyms":[],"level":4,"theme":"合約與法律"},{"word":"private","pos":"adj.","phonetic":"[ˈpraɪvɪt]","meaning":"私人的；私密的","definition":"belonging to a particular person; not public","collocations":["private property","private life","in private"],"example":"This is a private matter between us.","exampleZh":"這是我們之間的私事。","synonyms":["personal"],"level":2,"theme":"日常與一般"},{"word":"prize","pos":"n.","phonetic":"[praɪz]","meaning":"獎品；獎金","definition":"something given as a reward for winning a competition","collocations":["win a prize","first prize","prize money"],"example":"She won first prize in the science fair.","exampleZh":"她在科展中贏得了第一名的獎項。","synonyms":["award","reward"],"level":2,"theme":"人事與職涯"},{"word":"probability","pos":"n.","phonetic":"[ˌprɑbəˈbɪlətɪ]","meaning":"機率；可能性","definition":"how likely something is to happen","collocations":["high probability","in all probability"],"example":"There is a high probability that prices will rise next quarter.","exampleZh":"下一季價格上漲的可能性很高。","synonyms":["likelihood","chance"],"level":5,"theme":"日常與一般"},{"word":"probably","pos":"adv.","phonetic":"[ˈprɑbəbli]","meaning":"大概；可能地","definition":"almost certainly; very likely","collocations":["probably not","will probably","probably the best"],"example":"It will probably rain tomorrow.","exampleZh":"明天大概會下雨。","synonyms":["likely"],"level":1,"theme":"日常與一般"},{"word":"problem","pos":"n.","phonetic":"[ˈprɑbləm]","meaning":"問題；難題","definition":"a matter or situation regarded as unwelcome or harmful","collocations":["solve a problem","math problem","no problem"],"example":"We need to find a solution to this problem.","exampleZh":"我們必須找出解決這個問題的方法。","synonyms":["issue"],"level":1,"theme":"日常與一般"},{"word":"procedure","pos":"n.","phonetic":"[prəˈsidʒɚ]","meaning":"程序；手續","definition":"an established way of doing something","collocations":["standard procedure","safety procedure","follow the procedure"],"example":"Please follow the correct procedure to apply for a visa.","exampleZh":"請依照正確的程序申請簽證。","synonyms":["process"],"level":5,"theme":"日常與一般"},{"word":"proceed","pos":"v.","phonetic":"[prəˈsid]","meaning":"繼續進行；前進","definition":"to continue or move forward with an action","collocations":["proceed with caution","proceed to the next step","proceed as planned"],"example":"Please proceed to the gate for boarding.","exampleZh":"請前往登機門準備登機。","synonyms":["continue","advance"],"level":5,"theme":"日常與一般"},{"word":"process","pos":"n. / v.","phonetic":"[ˈprɑsɛs]","meaning":"過程；程序；處理","definition":"a series of actions taken to achieve a result","collocations":["learning process","process information","in the process of"],"example":"Learning a language is a slow process.","exampleZh":"學習一種語言是一個緩慢的過程。","synonyms":["procedure"],"level":3,"theme":"日常與一般"},{"word":"procurement","pos":"n.","phonetic":"[proˈkjʊrmənt]","meaning":"採購；採辦","definition":"the process of buying supplies or services for an organization","collocations":["procurement department","procurement process","procurement manager"],"example":"All orders must go through the procurement department for approval.","exampleZh":"所有訂單都必須經採購部門核准。","synonyms":["purchasing"],"level":6,"theme":"生產與物流"},{"word":"produce","pos":"v.","phonetic":"[prəˈdjus]","meaning":"生產；製造；產生","definition":"to make or create something","collocations":["produce goods","produce evidence","mass produce"],"example":"This factory produces thousands of cars every year.","exampleZh":"這家工廠每年生產數千輛汽車。","synonyms":["make","manufacture"],"level":2,"theme":"人事與職涯"},{"word":"product","pos":"n.","phonetic":"[ˈprɑdʌkt]","meaning":"產品；成果","definition":"an item that is made or grown to be sold","collocations":["new product","product design","final product"],"example":"The company launched a new product last month.","exampleZh":"這家公司上個月推出了一項新產品。","synonyms":["goods"],"level":2,"theme":"財務與會計"},{"word":"production","pos":"n.","phonetic":"[prəˈdʌkʃən]","meaning":"生產；製作","definition":"the process of making or growing goods for sale","collocations":["mass production","production line","film production"],"example":"The factory increased production to meet demand.","exampleZh":"這家工廠提高產量以滿足需求。","synonyms":["manufacturing"],"level":4,"theme":"財務與會計"},{"word":"productive","pos":"adj.","phonetic":"[prəˈdʌktɪv]","meaning":"有生產力的；富有成效的","definition":"producing a lot or achieving good results","collocations":["productive meeting","productive discussion","highly productive"],"example":"The brainstorming session was highly productive, generating twenty ideas.","exampleZh":"這場腦力激盪會議成效極佳，產出了二十個點子。","synonyms":["fruitful","effective"],"level":4,"theme":"企業經營"},{"word":"productivity","pos":"n.","phonetic":"[ˌprodʌkˈtɪvətɪ]","meaning":"生產力；生產率","definition":"the rate at which work is done or goods are produced","collocations":["increase productivity","productivity gains","employee productivity"],"example":"Flexible schedules have boosted productivity across the department.","exampleZh":"彈性工時提升了整個部門的生產力。","synonyms":["efficiency","output"],"level":5,"theme":"企業經營"},{"word":"profession","pos":"n.","phonetic":"[prəˈfɛʃən]","meaning":"職業；專業","definition":"a paid occupation that requires special training","collocations":["by profession","legal profession","choose a profession"],"example":"Teaching is a respected profession.","exampleZh":"教學是一項受人尊敬的職業。","synonyms":["occupation"],"level":4,"theme":"人事與職涯"},{"word":"professional","pos":"adj. / n.","phonetic":"[prəˈfɛʃənl]","meaning":"專業的；職業的；專業人士","definition":"relating to a profession, or a person engaged in a skilled occupation","collocations":["professional advice","professional athlete","act professionally"],"example":"She gave us some professional advice about investing.","exampleZh":"她給了我們一些關於投資的專業建議。","synonyms":["expert"],"level":3,"theme":"人事與職涯"},{"word":"professor","pos":"n.","phonetic":"[prəˈfɛsɚ]","meaning":"教授","definition":"a university teacher of the highest rank","collocations":["college professor","professor of history","associate professor"],"example":"The professor gave an interesting lecture on history.","exampleZh":"這位教授就歷史發表了一場有趣的演講。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"profile","pos":"n./v.","phonetic":"[ˈprofaɪl]","meaning":"簡介；輪廓；知名度","definition":"a short description of someone or something, or public attention","collocations":["company profile","raise one's profile","update your profile"],"example":"Update your profile in the employee directory with a recent photo.","exampleZh":"請用近照更新你在員工通訊錄的個人資料。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"profit","pos":"n. / v.","phonetic":"[ˈprɑfɪt]","meaning":"利潤；獲利","definition":"a financial gain from business activity","collocations":["make a profit","profit margin","profit from"],"example":"The company made a huge profit this year.","exampleZh":"這家公司今年獲利豐厚。","synonyms":["gain"],"level":3,"theme":"財務與會計"},{"word":"profitable","pos":"adj.","phonetic":"[ˈprɑfɪtəbl]","meaning":"有利潤的；有益的","definition":"making money or producing a benefit","collocations":["profitable business","highly profitable","profitable venture"],"example":"The airline's cargo division remains its most profitable unit.","exampleZh":"貨運部門仍是這家航空公司獲利最高的單位。","synonyms":["lucrative"],"level":4,"theme":"企業經營"},{"word":"program","pos":"n. / v.","phonetic":"[ˈprogræm]","meaning":"節目；計畫；程式；編寫程式","definition":"a planned series of activities or a set of coded instructions for a computer","collocations":["TV program","computer program","program a robot"],"example":"He learned how to program a computer in college.","exampleZh":"他在大學時學會了如何寫電腦程式。","synonyms":["schedule"],"level":2,"theme":"科技與通訊"},{"word":"progress","pos":"n. / v.","phonetic":"[ˈprɑgrɛs]","meaning":"進步；進展","definition":"forward movement toward a goal or improvement over time","collocations":["make progress","in progress","progress report"],"example":"She has made great progress in her studies.","exampleZh":"她在課業上有很大的進步。","synonyms":["advancement"],"level":3,"theme":"人事與職涯"},{"word":"prohibit","pos":"v.","phonetic":"[proˈhɪbɪt]","meaning":"禁止","definition":"to formally forbid something by law or rule","collocations":["prohibit smoking","strictly prohibited","prohibit the sale of"],"example":"Smoking is prohibited in this building.","exampleZh":"這棟大樓內禁止吸菸。","synonyms":["forbid","ban"],"level":5,"theme":"合約與法律"},{"word":"project","pos":"n. / v.","phonetic":"[ˈprɑdʒɛkt]","meaning":"計畫；專案；投射","definition":"a planned piece of work, or to estimate/forecast something","collocations":["science project","project a growth rate","group project"],"example":"Our class is working on a science project.","exampleZh":"我們班正在進行一項科學專題。","synonyms":["plan"],"level":2,"theme":"人事與職涯"},{"word":"projection","pos":"n.","phonetic":"[prəˈdʒɛkʃən]","meaning":"預測；投影；突出物","definition":"an estimate of future amounts, or an image shown on a screen","collocations":["sales projections","revenue projection","financial projections"],"example":"Sales projections for next year look very promising.","exampleZh":"明年的銷售預測看起來非常樂觀。","synonyms":["forecast","estimate"],"level":5,"theme":"財務與會計"},{"word":"projector","pos":"n.","phonetic":"[prəˈdʒɛktɚ]","meaning":"投影機","definition":"a machine that shows images or films on a screen","collocations":["set up the projector","projector screen","digital projector"],"example":"Please set up the projector before the client presentation.","exampleZh":"請在客戶簡報前架設好投影機。","synonyms":[],"level":3,"theme":"會議與簡報"},{"word":"prominent","pos":"adj.","phonetic":"[ˈprɑmənənt]","meaning":"著名的；顯眼的","definition":"famous and important, or easily seen","collocations":["prominent figure","prominent position","prominently displayed"],"example":"Several prominent business leaders attended the opening ceremony.","exampleZh":"多位知名企業領袖出席了開幕典禮。","synonyms":["notable","distinguished"],"level":5,"theme":"媒體與活動"},{"word":"promising","pos":"adj.","phonetic":"[ˈprɑmɪsɪŋ]","meaning":"有前景的；有希望的","definition":"showing signs of future success","collocations":["promising candidate","promising results","promising start"],"example":"The pilot program produced promising results in its first month.","exampleZh":"試行計畫在第一個月就有令人期待的成果。","synonyms":["encouraging"],"level":4,"theme":"企業經營"},{"word":"promote","pos":"v.","phonetic":"[prəˈmot]","meaning":"晉升；促進；宣傳","definition":"to raise someone to a higher position, or to encourage the development of something","collocations":["promote health","get promoted","promote a product"],"example":"She was promoted to manager last year.","exampleZh":"她去年被升職為經理。","synonyms":["advance","boost"],"level":4,"theme":"人事與職涯"},{"word":"promotion","pos":"n.","phonetic":"[prəˈmoʃən]","meaning":"升遷；促銷；推廣","definition":"a move to a higher position at work, or activity to increase sales","collocations":["get a promotion","sales promotion","promotion campaign"],"example":"She earned a promotion to regional manager after two strong years.","exampleZh":"表現亮眼兩年後，她升任區域經理。","synonyms":["advancement"],"level":3,"theme":"人事與職涯"},{"word":"promotional","pos":"adj.","phonetic":"[prəˈmoʃənl]","meaning":"促銷的；宣傳的","definition":"connected with advertising or special offers","collocations":["promotional materials","promotional offer","promotional video"],"example":"Promotional materials for the launch will be ready by Friday.","exampleZh":"發表會的宣傳資料將於週五前備妥。","synonyms":["advertising"],"level":4,"theme":"行銷與銷售"},{"word":"prompt","pos":"adj. / v.","phonetic":"[prɑmpt]","meaning":"迅速的；促使","definition":"done quickly and without delay; to cause someone to do something","collocations":["prompt response","prompt someone to act","prompt reply"],"example":"Thank you for your prompt reply to my email.","exampleZh":"謝謝你迅速回覆我的電子郵件。","synonyms":["quick","immediate"],"level":5,"theme":"日常與一般"},{"word":"promptly","pos":"adv.","phonetic":"[ˈprɑmptlɪ]","meaning":"迅速地；準時地","definition":"quickly and without delay, or exactly at a time","collocations":["respond promptly","promptly at nine","act promptly"],"example":"Please respond promptly to all customer complaints.","exampleZh":"請迅速回應所有顧客投訴。","synonyms":["quickly","immediately"],"level":4,"theme":"辦公室與行政"},{"word":"proof","pos":"n.","phonetic":"[pruf]","meaning":"證據；證明","definition":"evidence that establishes a fact or the truth of something","collocations":["proof of identity","provide proof","without proof"],"example":"Do you have any proof that he was there?","exampleZh":"你有任何證據證明他當時在場嗎？","synonyms":["evidence"],"level":4,"theme":"日常與一般"},{"word":"proofread","pos":"v.","phonetic":"[ˈprufˌrid]","meaning":"校對","definition":"to read and correct mistakes in a written text","collocations":["proofread a document","carefully proofread"],"example":"Always proofread the newsletter before sending it to subscribers.","exampleZh":"電子報寄給訂閱者前務必先校對。","synonyms":["review","check"],"level":5,"theme":"辦公室與行政"},{"word":"proper","pos":"adj.","phonetic":"[ˈprɑpɚ]","meaning":"適當的；正確的","definition":"correct, appropriate, or suitable","collocations":["proper way","proper training","proper behavior"],"example":"You should use the proper tools for this job.","exampleZh":"你應該使用適當的工具來做這件事。","synonyms":["appropriate","correct"],"level":3,"theme":"日常與一般"},{"word":"properly","pos":"adv.","phonetic":"[ˈprɑpɚli]","meaning":"適當地；正確地","definition":"in a correct or suitable manner","collocations":["work properly","behave properly","dress properly"],"example":"Make sure the machine is working properly.","exampleZh":"確認機器運作正常。","synonyms":["correctly"],"level":3,"theme":"日常與一般"},{"word":"property","pos":"n.","phonetic":"[ˈprɑpɚti]","meaning":"財產；房產；特性","definition":"a thing or things owned; a quality belonging to something","collocations":["private property","real property","chemical property"],"example":"The house and land are her private property.","exampleZh":"這間房子和土地是她的私人財產。","synonyms":["possession"],"level":4,"theme":"財務與會計"},{"word":"proposal","pos":"n.","phonetic":"[prəˈpozl]","meaning":"提案；企劃書；求婚","definition":"a formal plan or suggestion","collocations":["submit a proposal","business proposal","approve a proposal"],"example":"The committee will review all proposals by the end of the month.","exampleZh":"委員會將在月底前審查所有提案。","synonyms":["plan","suggestion"],"level":4,"theme":"會議與簡報"},{"word":"propose","pos":"v.","phonetic":"[prəˈpoz]","meaning":"提議；求婚","definition":"to suggest a plan or idea, or to ask someone to marry you","collocations":["propose a solution","propose marriage","propose a toast"],"example":"He proposed to his girlfriend on the beach.","exampleZh":"他在海灘上向女友求婚。","synonyms":["suggest"],"level":4,"theme":"溝通與語言"},{"word":"prospect","pos":"n.","phonetic":"[ˈprɑspɛkt]","meaning":"前景；可能性","definition":"the possibility of something happening in the future","collocations":["job prospect","future prospects","in prospect"],"example":"The company has good prospects for growth.","exampleZh":"這家公司的成長前景良好。","synonyms":["possibility","outlook"],"level":5,"theme":"日常與一般"},{"word":"prospective","pos":"adj.","phonetic":"[prəˈspɛktɪv]","meaning":"潛在的；未來的","definition":"likely to become or happen in the future","collocations":["prospective clients","prospective employees","prospective buyers"],"example":"The open house attracted dozens of prospective buyers.","exampleZh":"賞屋會吸引了數十位潛在買家。","synonyms":["potential","future"],"level":6,"theme":"行銷與銷售"},{"word":"protect","pos":"v.","phonetic":"[prəˈtɛkt]","meaning":"保護","definition":"to keep someone or something safe from harm","collocations":["protect the environment","protect against","protect one's rights"],"example":"Wear sunscreen to protect your skin from the sun.","exampleZh":"擦防曬乳來保護皮膚免受陽光傷害。","synonyms":["defend","guard"],"level":2,"theme":"日常與一般"},{"word":"protection","pos":"n.","phonetic":"[prəˈtɛkʃən]","meaning":"保護；防護","definition":"the action of keeping someone or something safe","collocations":["skin protection","under protection","legal protection"],"example":"The helmet provides protection for cyclists.","exampleZh":"安全帽能為騎士提供保護。","synonyms":["defense"],"level":3,"theme":"醫療與保險"},{"word":"protective","pos":"adj.","phonetic":"[prəˈtɛktɪv]","meaning":"保護的；防護的","definition":"intended to keep someone or something safe","collocations":["protective equipment","protective clothing","protective gear"],"example":"Workers must wear protective equipment in the assembly area.","exampleZh":"作業員在組裝區必須穿戴防護裝備。","synonyms":[],"level":4,"theme":"生產與物流"},{"word":"prototype","pos":"n.","phonetic":"[ˈprotəˌtaɪp]","meaning":"原型；樣品","definition":"the first model of a product used for testing","collocations":["build a prototype","working prototype","prototype testing"],"example":"Engineers will demonstrate the prototype at next month's expo.","exampleZh":"工程師將在下個月的博覽會上展示原型機。","synonyms":["model"],"level":5,"theme":"生產與物流"},{"word":"proud","pos":"adj.","phonetic":"[praʊd]","meaning":"驕傲的；自豪的","definition":"feeling deep pleasure or satisfaction from achievements","collocations":["proud of","proud moment","stand proud"],"example":"Her parents are very proud of her achievements.","exampleZh":"她的父母對她的成就感到十分自豪。","synonyms":["satisfied"],"level":1,"theme":"日常與一般"},{"word":"prove","pos":"v.","phonetic":"[pruv]","meaning":"證明","definition":"to demonstrate the truth of something with evidence","collocations":["prove a theory","prove wrong","prove one's innocence"],"example":"The new evidence proved his innocence.","exampleZh":"新證據證明了他的清白。","synonyms":["demonstrate","confirm"],"level":2,"theme":"日常與一般"},{"word":"provide","pos":"v.","phonetic":"[prəˈvaɪd]","meaning":"提供；供給","definition":"to give someone something they need","collocations":["provide information","provide for a family","provide support"],"example":"The school provides free lunch for students in need.","exampleZh":"學校為有需要的學生提供免費午餐。","synonyms":["supply","give"],"level":3,"theme":"日常與一般"},{"word":"provider","pos":"n.","phonetic":"[prəˈvaɪdɚ]","meaning":"供應商；提供者","definition":"a company or person that supplies a service or product","collocations":["service provider","internet provider","healthcare provider"],"example":"We switched to a new internet provider to reduce costs.","exampleZh":"為了降低成本，我們換了新的網路供應商。","synonyms":["supplier"],"level":4,"theme":"企業經營"},{"word":"provision","pos":"n.","phonetic":"[prəˈvɪʒən]","meaning":"條款；提供；準備","definition":"a condition in a legal document, or the act of supplying something","collocations":["contract provision","make provisions for","under the provisions of"],"example":"Under the provisions of the lease, tenants must give sixty days' notice.","exampleZh":"依租約條款，房客必須提前六十天通知。","synonyms":["clause","term"],"level":6,"theme":"合約與法律"},{"word":"public","pos":"adj. / n.","phonetic":"[ˈpʌblɪk]","meaning":"公共的；公眾","definition":"open to or shared by all people; the general population","collocations":["public transportation","in public","general public"],"example":"The park is open to the public every day.","exampleZh":"這座公園每天都開放給大眾。","synonyms":["communal"],"level":2,"theme":"日常與一般"},{"word":"publication","pos":"n.","phonetic":"[ˌpʌblɪˈkeʃən]","meaning":"出版；出版品","definition":"the act of printing a book or article, or something published","collocations":["trade publication","monthly publication","date of publication"],"example":"Her article appeared in a leading industry publication.","exampleZh":"她的文章刊登在一份重要的產業刊物上。","synonyms":["journal","periodical"],"level":4,"theme":"媒體與活動"},{"word":"publicity","pos":"n.","phonetic":"[pʌbˈlɪsətɪ]","meaning":"宣傳；曝光；公眾注意","definition":"attention given to something by the media","collocations":["negative publicity","publicity campaign","generate publicity"],"example":"The charity event generated positive publicity for the sponsor.","exampleZh":"這場慈善活動為贊助商帶來正面的宣傳效果。","synonyms":["exposure","attention"],"level":5,"theme":"行銷與銷售"},{"word":"publicly","pos":"adv.","phonetic":"[ˈpʌblɪklɪ]","meaning":"公開地；當眾","definition":"in a way that everyone can see or know","collocations":["publicly announce","publicly traded","publicly available"],"example":"The CEO publicly apologized for the service disruption.","exampleZh":"執行長為服務中斷公開道歉。","synonyms":["openly"],"level":4,"theme":"媒體與活動"},{"word":"publish","pos":"v.","phonetic":"[ˈpʌblɪʃ]","meaning":"出版；發表","definition":"to prepare and issue a book, journal, or article for public sale or view","collocations":["publish a book","publish research","newly published"],"example":"The author published her first novel last year.","exampleZh":"這位作者去年出版了她的第一本小說。","synonyms":["release"],"level":4,"theme":"科技與通訊"},{"word":"publisher","pos":"n.","phonetic":"[ˈpʌblɪʃɚ]","meaning":"出版社；出版者","definition":"a company or person that produces books, magazines, or newspapers","collocations":["book publisher","magazine publisher"],"example":"The publisher plans to release the travel guide in early spring.","exampleZh":"出版社計畫在初春推出這本旅遊指南。","synonyms":[],"level":3,"theme":"媒體與活動"},{"word":"publishing","pos":"n.","phonetic":"[ˈpʌblɪʃɪŋ]","meaning":"出版業；出版","definition":"the business of producing books, magazines, or digital content","collocations":["publishing industry","publishing house","digital publishing"],"example":"She spent fifteen years in publishing before starting her own firm.","exampleZh":"她在出版業工作十五年後自行創業。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"pull","pos":"v. / n.","phonetic":"[pʊl]","meaning":"拉；拖","definition":"to apply force to move something toward oneself","collocations":["pull the rope","pull over","pull a muscle"],"example":"Please pull the door instead of pushing it.","exampleZh":"請把門拉開，不要用推的。","synonyms":["drag","tug"],"level":1,"theme":"日常與一般"},{"word":"punctual","pos":"adj.","phonetic":"[ˈpʌŋktʃuəl]","meaning":"準時的","definition":"arriving or doing something at the expected time; not late","collocations":["punctual arrival","always punctual","be punctual for"],"example":"He is always punctual for meetings.","exampleZh":"他開會總是很準時。","synonyms":["on time","prompt"],"level":5,"theme":"日常與一般"},{"word":"purchase","pos":"v. / n.","phonetic":"[ˈpɝtʃəs]","meaning":"購買；購買物","definition":"to buy something","collocations":["purchase a ticket","make a purchase","online purchase"],"example":"She purchased a new laptop for school.","exampleZh":"她為了上學買了一台新筆電。","synonyms":["buy"],"level":4,"theme":"財務與會計"},{"word":"purpose","pos":"n.","phonetic":"[ˈpɝpəs]","meaning":"目的；意圖","definition":"the reason for which something is done or exists","collocations":["on purpose","serve a purpose","sense of purpose"],"example":"What is the purpose of this meeting?","exampleZh":"這次會議的目的是什麼？","synonyms":["aim","goal"],"level":2,"theme":"日常與一般"},{"word":"pursue","pos":"v.","phonetic":"[pɚˈsu]","meaning":"追求；從事","definition":"to follow or work toward achieving a goal","collocations":["pursue a career","pursue happiness","pursue a dream"],"example":"She decided to pursue a career in medicine.","exampleZh":"她決定從事醫學方面的職業。","synonyms":["chase","seek"],"level":4,"theme":"人事與職涯"},{"word":"pursuit","pos":"n.","phonetic":"[pɚˈsut]","meaning":"追求；嗜好","definition":"the act of trying to achieve something, or an activity you enjoy","collocations":["in pursuit of","leisure pursuits","the pursuit of excellence"],"example":"The company never compromises safety in pursuit of higher profits.","exampleZh":"公司絕不為追求更高利潤而犧牲安全。","synonyms":["quest"],"level":5,"theme":"日常與一般"},{"word":"push","pos":"v. / n.","phonetic":"[pʊʃ]","meaning":"推；推動","definition":"to apply force to move something away from oneself","collocations":["push the door","push forward","push someone to do"],"example":"He pushed the cart down the aisle.","exampleZh":"他推著推車走過走道。","synonyms":["shove"],"level":1,"theme":"日常與一般"},{"word":"put","pos":"v.","phonetic":"[pʊt]","meaning":"放；擺放","definition":"to move something into a particular place or position","collocations":["put away","put on","put off"],"example":"Please put the books back on the shelf.","exampleZh":"請把書放回書架上。","synonyms":["place"],"level":1,"theme":"日常與一般"},{"word":"qualification","pos":"n.","phonetic":"[͵kwɑləfəˈkeʃən]","meaning":"資格；證書；條件","definition":"a skill or achievement that makes someone suitable for a job or task","collocations":["professional qualification","meet the qualifications","academic qualification"],"example":"You need a teaching qualification to work at this school.","exampleZh":"你需要教師資格才能在這所學校任教。","synonyms":["credential","certification"],"level":4,"theme":"人事與職涯"},{"word":"qualified","pos":"adj.","phonetic":"[ˈkwɑləˌfaɪd]","meaning":"合格的；具備資格的","definition":"having the skills, knowledge, or experience needed for a job","collocations":["highly qualified","qualified candidates","fully qualified"],"example":"Only qualified electricians may service the building's wiring.","exampleZh":"只有合格的電工才能維修大樓的線路。","synonyms":["certified","eligible"],"level":4,"theme":"人事與職涯"},{"word":"qualify","pos":"v.","phonetic":"[ˈkwɑlə͵faɪ]","meaning":"取得資格；使合格；限定","definition":"to have or gain the necessary skill or knowledge to do something","collocations":["qualify for a job","qualify as a doctor","qualify for the finals"],"example":"She studied hard to qualify as a lawyer.","exampleZh":"她努力讀書以取得律師資格。","synonyms":["become eligible"],"level":3,"theme":"人事與職涯"},{"word":"quality","pos":"n. / adj.","phonetic":"[ˈkwɑlətɪ]","meaning":"品質；特質；優質的","definition":"the standard of something as measured against other things of a similar kind","collocations":["high quality","quality of life","quality control"],"example":"The company is known for the high quality of its products.","exampleZh":"這家公司以產品的高品質聞名。","synonyms":["standard","grade"],"level":2,"theme":"日常與一般"},{"word":"quantity","pos":"n.","phonetic":"[ˈkwɑntətɪ]","meaning":"數量；分量","definition":"an amount or number of something","collocations":["a large quantity","in quantity","quantity over quality"],"example":"The factory produces a huge quantity of goods every day.","exampleZh":"這家工廠每天生產大量的貨物。","synonyms":["amount","volume"],"level":2,"theme":"科技與通訊"},{"word":"quarter","pos":"n.","phonetic":"[ˈkwɔrtɚ]","meaning":"四分之一；一刻鐘；季度","definition":"one of four equal parts of something","collocations":["a quarter of an hour","the first quarter","quarter final"],"example":"The meeting will start in a quarter of an hour.","exampleZh":"會議將在十五分鐘後開始。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"quarterly","pos":"adj. / adv.","phonetic":"[ˈkwɔrtɚlɪ]","meaning":"每季的；按季度的","definition":"happening or produced four times a year","collocations":["quarterly report","quarterly meeting","paid quarterly"],"example":"The company publishes a quarterly report on its earnings.","exampleZh":"這家公司每季發布一份盈餘報告。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"question","pos":"n. / v.","phonetic":"[ˈkwɛstʃən]","meaning":"問題；疑問；質疑","definition":"a sentence used to ask for information, or to express doubt about something","collocations":["ask a question","question a decision","good question"],"example":"The teacher asked a difficult question about history.","exampleZh":"老師問了一個關於歷史的難題。","synonyms":["ask","doubt"],"level":1,"theme":"溝通與語言"},{"word":"questionnaire","pos":"n.","phonetic":"[͵kwɛstʃənˈɛr]","meaning":"問卷","definition":"a written set of questions given to people to gather information","collocations":["fill in a questionnaire","survey questionnaire","online questionnaire"],"example":"Please fill in this questionnaire about your shopping habits.","exampleZh":"請填寫這份關於購物習慣的問卷。","synonyms":["survey"],"level":4,"theme":"溝通與語言"},{"word":"quick","pos":"adj. / adv.","phonetic":"[kwɪk]","meaning":"快的；迅速的","definition":"moving or happening fast","collocations":["a quick answer","quick meal","quick to react"],"example":"She gave a quick reply to the email.","exampleZh":"她迅速回覆了那封電子郵件。","synonyms":["fast","swift"],"level":1,"theme":"日常與一般"},{"word":"quickly","pos":"adv.","phonetic":"[ˈkwɪklɪ]","meaning":"快速地；迅速地","definition":"fast or in a short time","collocations":["respond quickly","move quickly","as quickly as possible"],"example":"The support team resolved the billing issue quickly.","exampleZh":"客服團隊迅速解決了帳單問題。","synonyms":["rapidly","swiftly"],"level":1,"theme":"日常與一般"},{"word":"quotation","pos":"n.","phonetic":"[kwoˈteʃən]","meaning":"引用；引語；報價","definition":"a phrase taken from a text, or a stated price for a job or service","collocations":["famous quotation","get a quotation","quotation mark"],"example":"The teacher wrote a famous quotation on the board.","exampleZh":"老師在黑板上寫了一句名言。","synonyms":["quote","citation"],"level":5,"theme":"溝通與語言"},{"word":"quote","pos":"v. / n.","phonetic":"[kwot]","meaning":"引用；引述；報價","definition":"to repeat the exact words of someone else, or a price offered for goods or services","collocations":["quote a price","quote from a book","direct quote"],"example":"He often quotes lines from his favorite novel.","exampleZh":"他常常引用他最喜歡的小說中的句子。","synonyms":["cite"],"level":4,"theme":"溝通與語言"},{"word":"raise","pos":"v. / n.","phonetic":"[rez]","meaning":"舉起；提高；養育；加薪","definition":"to lift something up or to increase an amount","collocations":["raise a hand","raise children","raise money","get a raise"],"example":"She raised her hand to ask a question.","exampleZh":"她舉手發問。","synonyms":["lift","increase"],"level":1,"theme":"日常與一般"},{"word":"range","pos":"n. / v.","phonetic":"[rendʒ]","meaning":"範圍；山脈；種類","definition":"the area of variation between limits, or a series of mountains","collocations":["price range","a range of products","mountain range"],"example":"The store offers a wide range of products.","exampleZh":"這家店提供多樣的產品。","synonyms":["scope","variety"],"level":3,"theme":"日常與一般"},{"word":"rapidly","pos":"adv.","phonetic":"[ˈræpɪdlɪ]","meaning":"快速地；急速地","definition":"very quickly","collocations":["grow rapidly","rapidly changing","expand rapidly"],"example":"The electric vehicle market is growing rapidly worldwide.","exampleZh":"電動車市場正在全球快速成長。","synonyms":["quickly","swiftly"],"level":3,"theme":"日常與一般"},{"word":"rare","pos":"adj.","phonetic":"[rɛr]","meaning":"稀有的；罕見的；(牛排)三分熟的","definition":"not occurring very often or found in small numbers","collocations":["a rare disease","rare species","rare occasion"],"example":"Giant pandas are a rare species.","exampleZh":"大貓熊是一種稀有物種。","synonyms":["uncommon","scarce"],"level":2,"theme":"日常與一般"},{"word":"rarely","pos":"adv.","phonetic":"[ˈrɛrlɪ]","meaning":"很少；難得","definition":"not often","collocations":["rarely used","rarely seen"],"example":"The conference room on the top floor is rarely available.","exampleZh":"頂樓的會議室很少有空檔。","synonyms":["seldom"],"level":2,"theme":"日常與一般"},{"word":"rate","pos":"n. / v.","phonetic":"[ret]","meaning":"比率；速度；評價","definition":"a measure of frequency or speed","collocations":["exchange rate","heart rate"],"example":"The exchange rate changes every day.","exampleZh":"匯率每天都在變動。","synonyms":["ratio","speed"],"level":2,"theme":"財務與會計"},{"word":"rating","pos":"n.","phonetic":"[ˈretɪŋ]","meaning":"評分；等級；收視率","definition":"a measurement of how good, popular, or safe something is","collocations":["customer rating","five-star rating","credit rating"],"example":"The hotel maintains a five-star rating on most travel websites.","exampleZh":"這家飯店在多數旅遊網站上維持五星評價。","synonyms":["score","grade"],"level":4,"theme":"行銷與銷售"},{"word":"ratio","pos":"n.","phonetic":"[ˈreʃo]","meaning":"比例；比率","definition":"the relationship between two amounts showing how many times one contains another","collocations":["a ratio of","the student-teacher ratio","a high ratio"],"example":"The ratio of boys to girls in the class is two to one.","exampleZh":"班上男女生比例是二比一。","synonyms":["proportion"],"level":4,"theme":"科技與通訊"},{"word":"raw","pos":"adj.","phonetic":"[rɔ]","meaning":"生的；未加工的","definition":"uncooked or unprocessed","collocations":["raw meat","raw materials","raw data"],"example":"Never eat raw chicken; it can make you sick.","exampleZh":"千萬不要吃生雞肉，會讓你生病。","synonyms":["uncooked"],"level":2,"theme":"餐飲與住宿"},{"word":"reach","pos":"v. / n.","phonetic":"[ritʃ]","meaning":"到達；伸手拿；影響範圍","definition":"to arrive at or stretch out to touch something","collocations":["reach a goal","reach out","within reach"],"example":"We finally reached the top of the mountain.","exampleZh":"我們終於到達了山頂。","synonyms":["arrive at","attain"],"level":2,"theme":"日常與一般"},{"word":"react","pos":"v.","phonetic":"[rɪˈækt]","meaning":"反應；回應","definition":"to act in response to something","collocations":["react quickly","react to news","react negatively"],"example":"She reacted calmly to the bad news.","exampleZh":"她冷靜地應對這個壞消息。","synonyms":["respond"],"level":3,"theme":"日常與一般"},{"word":"reaction","pos":"n.","phonetic":"[rɪˈækʃən]","meaning":"反應","definition":"a response to a situation or event","collocations":["a strong reaction","chain reaction","allergic reaction"],"example":"His reaction to the surprise party was priceless.","exampleZh":"他對這場驚喜派對的反應太珍貴了。","synonyms":["response"],"level":3,"theme":"日常與一般"},{"word":"ready","pos":"adj.","phonetic":"[ˈrɛdɪ]","meaning":"準備好的","definition":"prepared for an action or situation","collocations":["get ready","ready to go","ready-made"],"example":"Are you ready for the exam tomorrow?","exampleZh":"你準備好明天的考試了嗎？","synonyms":["prepared"],"level":1,"theme":"日常與一般"},{"word":"realistic","pos":"adj.","phonetic":"[ˌriəˈlɪstɪk]","meaning":"實際的；逼真的","definition":"having a sensible view of what is possible or true to life","collocations":["realistic goal","realistic expectations","look realistic"],"example":"We need to set realistic goals for the project.","exampleZh":"我們需要為這個計畫設定實際的目標。","synonyms":["practical"],"level":4,"theme":"日常與一般"},{"word":"realize","pos":"v.","phonetic":"[ˈriəˌlaɪz]","meaning":"意識到；實現","definition":"to become fully aware of something as a fact","collocations":["realize a mistake","realize a dream","suddenly realize"],"example":"I didn't realize how late it was.","exampleZh":"我沒意識到已經這麼晚了。","synonyms":["recognize","understand"],"level":2,"theme":"日常與一般"},{"word":"reason","pos":"n. / v.","phonetic":"[ˈrizn̩]","meaning":"理由；原因；推理","definition":"a cause or explanation for something","collocations":["good reason","for this reason","reason with someone"],"example":"There is no reason to worry.","exampleZh":"沒有理由需要擔心。","synonyms":["cause","motive"],"level":2,"theme":"日常與一般"},{"word":"reasonable","pos":"adj.","phonetic":"[ˈriznəbl̩]","meaning":"合理的；合情理的","definition":"fair and sensible","collocations":["reasonable price","reasonable request","sound reasonable"],"example":"The price of the shirt seemed reasonable.","exampleZh":"這件襯衫的價格似乎很合理。","synonyms":["fair","sensible"],"level":3,"theme":"日常與一般"},{"word":"reasonably","pos":"adv.","phonetic":"[ˈriznəblɪ]","meaning":"合理地；相當","definition":"in a fair way, or to a fairly good degree","collocations":["reasonably priced","reasonably sure"],"example":"The bistro serves reasonably priced lunches near the office park.","exampleZh":"這家小餐館在辦公園區附近供應價格合理的午餐。","synonyms":["fairly"],"level":4,"theme":"購物與消費"},{"word":"reassure","pos":"v.","phonetic":"[ˌriəˈʃʊr]","meaning":"使安心；使放心","definition":"to say or do things to remove someone's doubts or fears","collocations":["reassure someone","reassure the public","feel reassured"],"example":"The doctor reassured her that the surgery would go smoothly.","exampleZh":"醫生向她保證手術會順利進行,讓她安心。","synonyms":["comfort","calm"],"level":4,"theme":"日常與一般"},{"word":"rebate","pos":"n./v.","phonetic":"[ˈribet]","meaning":"退款；回扣；折讓","definition":"money returned to you after a purchase","collocations":["mail-in rebate","tax rebate","claim a rebate"],"example":"Buyers can claim a fifty-dollar rebate on this printer model.","exampleZh":"購買這款印表機可申請五十美元的退款。","synonyms":["refund"],"level":6,"theme":"購物與消費"},{"word":"recall","pos":"v. / n.","phonetic":"[rɪˈkɔl]","meaning":"回想；召回","definition":"to remember something, or to officially call something back","collocations":["recall a memory","recall a product","total recall"],"example":"I can't quite recall where I put my keys.","exampleZh":"我想不太起來把鑰匙放在哪裡了。","synonyms":["remember","summon"],"level":4,"theme":"人事與職涯"},{"word":"receipt","pos":"n.","phonetic":"[rɪˈsit]","meaning":"收據；收到","definition":"a document proving payment, or the act of receiving something","collocations":["keep the receipt","upon receipt of","itemized receipt"],"example":"Keep your receipt in case you need to return the item.","exampleZh":"請保留收據，以便日後退貨使用。","synonyms":[],"level":3,"theme":"購物與消費"},{"word":"receive","pos":"v.","phonetic":"[rɪˈsiv]","meaning":"收到；接受","definition":"to be given, sent, or handed something","collocations":["receive a gift","receive an email","receive training"],"example":"She received a letter from her old friend.","exampleZh":"她收到一封老朋友寄來的信。","synonyms":["get","obtain"],"level":2,"theme":"日常與一般"},{"word":"recent","pos":"adj.","phonetic":"[ˈrisn̩t]","meaning":"最近的","definition":"having happened or begun not long ago","collocations":["recent years","recent events","in recent times"],"example":"In recent years, the city has changed a lot.","exampleZh":"近年來，這座城市改變了很多。","synonyms":["latest"],"level":2,"theme":"日常與一般"},{"word":"recently","pos":"adv.","phonetic":"[ˈrisn̩tlɪ]","meaning":"最近","definition":"not long ago; lately","collocations":["recently moved","have recently done","until recently"],"example":"I recently started a new job.","exampleZh":"我最近開始了一份新工作。","synonyms":["lately"],"level":2,"theme":"日常與一般"},{"word":"reception","pos":"n.","phonetic":"[rɪˈsɛpʃən]","meaning":"接待處；接待會；接收","definition":"the front desk of a building, a formal party, or the way something is received","collocations":["reception desk","wedding reception","warm reception"],"example":"Please sign in at the reception desk when you arrive.","exampleZh":"抵達時請至接待櫃檯登記。","synonyms":["front desk"],"level":3,"theme":"辦公室與行政"},{"word":"receptionist","pos":"n.","phonetic":"[rɪˈsɛpʃənɪst]","meaning":"接待員；櫃檯人員","definition":"a person who greets visitors and answers calls at a front desk","collocations":["hotel receptionist","front-desk receptionist"],"example":"The receptionist will direct you to the correct meeting room.","exampleZh":"接待人員會為您指引正確的會議室。","synonyms":[],"level":3,"theme":"辦公室與行政"},{"word":"recipe","pos":"n.","phonetic":"[ˈrɛsəpɪ]","meaning":"食譜；秘訣","definition":"a set of instructions for preparing a dish","collocations":["follow a recipe","family recipe","recipe for success"],"example":"She followed the recipe carefully to make the cake.","exampleZh":"她仔細按照食譜做蛋糕。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"recipient","pos":"n.","phonetic":"[rɪˈsɪpɪənt]","meaning":"收件人；受領者","definition":"a person who receives something","collocations":["award recipient","intended recipient","recipient's address"],"example":"Double-check the recipient's address before sending the package.","exampleZh":"寄出包裹前請再次確認收件人地址。","synonyms":["receiver"],"level":5,"theme":"辦公室與行政"},{"word":"recognition","pos":"n.","phonetic":"[ˌrɛkəgˈnɪʃən]","meaning":"表彰；認可；識別","definition":"public praise for someone's work, or the act of identifying something","collocations":["in recognition of","employee recognition","brand recognition"],"example":"She received an award in recognition of her twenty years of service.","exampleZh":"她因服務二十年而獲頒獎項表彰。","synonyms":["acknowledgment"],"level":5,"theme":"人事與職涯"},{"word":"recognize","pos":"v.","phonetic":"[ˈrɛkəgˌnaɪz]","meaning":"認出；承認","definition":"to identify someone or something from previous knowledge","collocations":["recognize a face","recognize an achievement","hardly recognize"],"example":"I almost didn't recognize you with short hair.","exampleZh":"你剪短髮後我差點認不出你。","synonyms":["identify","acknowledge"],"level":3,"theme":"日常與一般"},{"word":"recommend","pos":"v.","phonetic":"[ˌrɛkəˈmɛnd]","meaning":"推薦；建議","definition":"to suggest that something is good or suitable","collocations":["recommend a restaurant","highly recommend","recommend a book"],"example":"Can you recommend a good restaurant nearby?","exampleZh":"你能推薦附近一間不錯的餐廳嗎？","synonyms":["suggest","advise"],"level":3,"theme":"溝通與語言"},{"word":"recommendation","pos":"n.","phonetic":"[ˌrɛkəmɛnˈdeʃən]","meaning":"推薦；建議","definition":"a suggestion that something is good or should be done","collocations":["letter of recommendation","make a recommendation","strong recommendation"],"example":"Please include two letters of recommendation with your application.","exampleZh":"請隨申請文件附上兩封推薦信。","synonyms":["endorsement","suggestion"],"level":4,"theme":"人事與職涯"},{"word":"reconsider","pos":"v.","phonetic":"[ˌrikənˈsɪdɚ]","meaning":"重新考慮","definition":"to think again about a decision","collocations":["reconsider a decision","urge someone to reconsider"],"example":"The board agreed to reconsider the budget cuts after staff feedback.","exampleZh":"在員工反映意見後，董事會同意重新考慮預算刪減案。","synonyms":["rethink"],"level":5,"theme":"企業經營"},{"word":"record","pos":"n. / v.","phonetic":"[ˈrɛkɚd]","meaning":"紀錄；唱片；記錄","definition":"a piece of evidence about the past, or to set down in writing or sound","collocations":["break a record","keep a record","record a song"],"example":"He broke the world record in swimming.","exampleZh":"他打破了游泳的世界紀錄。","synonyms":["log"],"level":2,"theme":"科技與通訊"},{"word":"recover","pos":"v.","phonetic":"[rɪˈkʌvɚ]","meaning":"恢復；復原","definition":"to return to a normal state of health or strength","collocations":["recover from illness","fully recover","recover quickly"],"example":"It took him weeks to recover from the flu.","exampleZh":"他花了好幾週才從流感中康復。","synonyms":["heal","recuperate"],"level":3,"theme":"醫療與保險"},{"word":"recovery","pos":"n.","phonetic":"[rɪˈkʌvərɪ]","meaning":"復甦；恢復；復原","definition":"the process of returning to a normal state after problems or illness","collocations":["economic recovery","speedy recovery","recovery plan"],"example":"The tourism industry showed strong recovery in the second half.","exampleZh":"觀光業在下半年展現強勁復甦。","synonyms":["rebound"],"level":4,"theme":"企業經營"},{"word":"recreation","pos":"n.","phonetic":"[ˌrɛkrɪˈeʃən]","meaning":"休閒；娛樂","definition":"activities done for enjoyment when not working","collocations":["recreation center","outdoor recreation","recreation facilities"],"example":"The resort offers a wide range of recreation facilities.","exampleZh":"這座度假村提供多樣的休閒設施。","synonyms":["leisure"],"level":4,"theme":"媒體與活動"},{"word":"recruit","pos":"v./n.","phonetic":"[rɪˈkrut]","meaning":"招募；新進人員","definition":"to find new people to join a company, or a person recently hired","collocations":["recruit new staff","new recruit","recruit heavily"],"example":"The firm plans to recruit fifty engineers before year's end.","exampleZh":"公司計畫在年底前招募五十名工程師。","synonyms":["hire","enlist"],"level":4,"theme":"人事與職涯"},{"word":"recruitment","pos":"n.","phonetic":"[rɪˈkrutmənt]","meaning":"招募；招聘","definition":"the process of finding new people to work for an organization","collocations":["recruitment process","recruitment agency","recruitment drive"],"example":"The recruitment drive attracted over three hundred applicants.","exampleZh":"這波徵才活動吸引了超過三百名應徵者。","synonyms":["hiring"],"level":5,"theme":"人事與職涯"},{"word":"recycle","pos":"v.","phonetic":"[riˈsaɪkl]","meaning":"回收；再利用","definition":"to process used materials so they can be used again","collocations":["recycle paper","recycled materials","recycle bins"],"example":"Please recycle all paper and plastic in the marked bins.","exampleZh":"請將紙類和塑膠丟入標示的回收桶。","synonyms":["reuse"],"level":2,"theme":"日常與一般"},{"word":"recycling","pos":"n.","phonetic":"[riˈsaɪklɪŋ]","meaning":"資源回收","definition":"the process of treating used materials for reuse","collocations":["recycling program","recycling center","recycling bin"],"example":"The office recycling program cut waste disposal costs in half.","exampleZh":"辦公室的回收計畫讓廢棄物處理成本減半。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"reduce","pos":"v.","phonetic":"[rɪˈdjus]","meaning":"減少；降低","definition":"to make something smaller or less in amount","collocations":["reduce costs","reduce stress","reduce speed"],"example":"The company aims to reduce its carbon emissions.","exampleZh":"這家公司致力於減少碳排放。","synonyms":["decrease","lower"],"level":3,"theme":"日常與一般"},{"word":"reduction","pos":"n.","phonetic":"[rɪˈdʌkʃən]","meaning":"減少；降低；折扣","definition":"the act of making something smaller in amount or price","collocations":["cost reduction","price reduction","significant reduction"],"example":"The energy-saving upgrades led to a thirty percent reduction in bills.","exampleZh":"節能改善讓帳單金額減少了三成。","synonyms":["decrease","cut"],"level":4,"theme":"財務與會計"},{"word":"refer","pos":"v.","phonetic":"[rɪˈfɝ]","meaning":"參閱；提及；轉介","definition":"to direct someone to a source of information or help, or to mention something","collocations":["refer to the manual","refer a patient","refer to as"],"example":"Please refer to the employee handbook for the full vacation policy.","exampleZh":"完整的休假規定請參閱員工手冊。","synonyms":["consult","mention"],"level":3,"theme":"溝通與語言"},{"word":"reference","pos":"n./v.","phonetic":"[ˈrɛfərəns]","meaning":"推薦人；參考；引用","definition":"a person who confirms your abilities, or a source of information","collocations":["reference letter","for future reference","list of references"],"example":"Applicants should provide three professional references.","exampleZh":"應徵者應提供三位專業推薦人。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"referral","pos":"n.","phonetic":"[rɪˈfɝəl]","meaning":"轉介；推薦","definition":"the act of sending someone to another person or place for help or service","collocations":["referral program","customer referral","doctor's referral"],"example":"Employees earn a bonus for each successful hiring referral.","exampleZh":"員工每成功推薦一位錄取者即可獲得獎金。","synonyms":[],"level":6,"theme":"人事與職涯"},{"word":"refill","pos":"v./n.","phonetic":"[riˈfɪl]","meaning":"再裝滿；續杯；補充包","definition":"to fill something again, or a new supply of something used up","collocations":["free refills","refill a prescription","ink refill"],"example":"The cafe offers free refills on all hot coffee.","exampleZh":"這家咖啡館的熱咖啡皆可免費續杯。","synonyms":[],"level":4,"theme":"餐飲與住宿"},{"word":"reflect","pos":"v.","phonetic":"[rɪˈflɛkt]","meaning":"反映；反射；深思","definition":"to show or represent something, or to think carefully","collocations":["reflect the changes","reflect on","be reflected in"],"example":"The updated invoice reflects the agreed discount.","exampleZh":"更新後的請款單已反映議定的折扣。","synonyms":["show","mirror"],"level":3,"theme":"日常與一般"},{"word":"refreshment","pos":"n.","phonetic":"[rɪˈfrɛʃmənt]","meaning":"茶點；點心飲料","definition":"drinks and small amounts of food provided at an event","collocations":["light refreshments","refreshments will be served"],"example":"Light refreshments will be served after the seminar.","exampleZh":"研討會結束後將供應簡單茶點。","synonyms":["snacks"],"level":4,"theme":"媒體與活動"},{"word":"refrigerator","pos":"n.","phonetic":"[rɪˈfrɪdʒəˌretɚ]","meaning":"冰箱","definition":"an appliance used to keep food cold","collocations":["put in the refrigerator","open the refrigerator","empty refrigerator"],"example":"Please put the milk back in the refrigerator.","exampleZh":"請把牛奶放回冰箱。","synonyms":["fridge"],"level":2,"theme":"房產與設施"},{"word":"refund","pos":"n./v.","phonetic":"[ˈriˌfʌnd]","meaning":"退款；退還","definition":"money given back when you return something, or to give money back","collocations":["full refund","request a refund","refund policy"],"example":"Customers may request a full refund within thirty days.","exampleZh":"顧客可在三十天內申請全額退款。","synonyms":["reimbursement"],"level":3,"theme":"購物與消費"},{"word":"refundable","pos":"adj.","phonetic":"[rɪˈfʌndəbl]","meaning":"可退款的","definition":"able to be returned as money","collocations":["refundable deposit","fully refundable"],"example":"The booking deposit is fully refundable up to seven days before arrival.","exampleZh":"訂房訂金在入住前七天皆可全額退還。","synonyms":[],"level":5,"theme":"購物與消費"},{"word":"refuse","pos":"v.","phonetic":"[rɪˈfjuz]","meaning":"拒絕","definition":"to indicate unwillingness to do or accept something","collocations":["refuse an offer","refuse to answer","flatly refuse"],"example":"He refused to give up his seat.","exampleZh":"他拒絕讓出座位。","synonyms":["decline","reject"],"level":3,"theme":"日常與一般"},{"word":"regarding","pos":"prep.","phonetic":"[rɪˈgɑrdɪŋ]","meaning":"關於","definition":"about or concerning something","collocations":["regarding your inquiry","information regarding"],"example":"Please contact us regarding any billing questions.","exampleZh":"若有任何帳務問題，請與我們聯繫。","synonyms":["concerning","about"],"level":4,"theme":"溝通與語言"},{"word":"regardless","pos":"adv.","phonetic":"[rɪˈgɑrdlɪs]","meaning":"無論如何；不管","definition":"without being affected by something","collocations":["regardless of","continue regardless"],"example":"The event will proceed regardless of the weather.","exampleZh":"無論天氣如何，活動都將照常舉行。","synonyms":["anyway"],"level":5,"theme":"日常與一般"},{"word":"region","pos":"n.","phonetic":"[ˈridʒən]","meaning":"地區；區域","definition":"an area, especially part of a country","collocations":["mountain region","this region","regional differences"],"example":"This region is famous for its tea production.","exampleZh":"這個地區以生產茶葉聞名。","synonyms":["area","zone"],"level":3,"theme":"日常與一般"},{"word":"regional","pos":"adj.","phonetic":"[ˈridʒənl]","meaning":"區域的；地區性的","definition":"relating to a particular area of a country or the world","collocations":["regional office","regional manager","regional differences"],"example":"She oversees operations at all five regional offices.","exampleZh":"她負責督導五個區域辦公室的營運。","synonyms":["local"],"level":4,"theme":"企業經營"},{"word":"register","pos":"v./n.","phonetic":"[ˈrɛdʒɪstɚ]","meaning":"登記；註冊；收銀機","definition":"to put your name on an official list, or a machine for recording sales","collocations":["register for a course","cash register","register online"],"example":"Register online by Friday to receive the early-bird discount.","exampleZh":"週五前線上報名即可享早鳥優惠。","synonyms":["enroll","sign up"],"level":3,"theme":"媒體與活動"},{"word":"registration","pos":"n.","phonetic":"[ˌrɛdʒɪˈstreʃən]","meaning":"登記；報名；註冊","definition":"the act of recording a name on an official list","collocations":["registration form","registration fee","registration desk"],"example":"The registration fee includes lunch and all conference materials.","exampleZh":"報名費含午餐及所有會議資料。","synonyms":["enrollment"],"level":4,"theme":"會議與簡報"},{"word":"regret","pos":"v. / n.","phonetic":"[rɪˈgrɛt]","meaning":"後悔；遺憾","definition":"to feel sorry about something one has done or failed to do","collocations":["regret a decision","deeply regret","no regrets"],"example":"He regretted not studying harder for the test.","exampleZh":"他後悔沒有更努力準備考試。","synonyms":["remorse"],"level":4,"theme":"日常與一般"},{"word":"regular","pos":"adj.","phonetic":"[ˈrɛgjəlɚ]","meaning":"規律的；定期的；正常的","definition":"occurring at fixed intervals or following a set pattern","collocations":["regular exercise","regular basis","regular customer"],"example":"Regular exercise keeps you healthy.","exampleZh":"規律運動能讓你保持健康。","synonyms":["routine","normal"],"level":2,"theme":"日常與一般"},{"word":"regularly","pos":"adv.","phonetic":"[ˈrɛgjəlɚlɪ]","meaning":"定期地；經常地","definition":"at fixed times or often","collocations":["regularly scheduled","check regularly","meet regularly"],"example":"The machines are regularly serviced to prevent breakdowns.","exampleZh":"機器定期保養以避免故障。","synonyms":["routinely"],"level":3,"theme":"日常與一般"},{"word":"regulate","pos":"v.","phonetic":"[ˈrɛgjəˌlet]","meaning":"管制；調節","definition":"to control something by rules, or to adjust a level","collocations":["regulate the industry","strictly regulated","regulate temperature"],"example":"The thermostat regulates the temperature throughout the building.","exampleZh":"恆溫器調節整棟大樓的溫度。","synonyms":["control","govern"],"level":5,"theme":"合約與法律"},{"word":"regulation","pos":"n.","phonetic":"[ˌrɛgjəˈleʃən]","meaning":"法規；規定；管制","definition":"an official rule, or the control of an activity by rules","collocations":["safety regulations","comply with regulations","government regulation"],"example":"New safety regulations take effect at the beginning of next year.","exampleZh":"新的安全法規將於明年初生效。","synonyms":["rule","law"],"level":4,"theme":"合約與法律"},{"word":"regulatory","pos":"adj.","phonetic":"[ˈrɛgjələˌtorɪ]","meaning":"監管的；管制的","definition":"relating to the control of an activity by official rules","collocations":["regulatory approval","regulatory agency","regulatory requirements"],"example":"The drug is awaiting regulatory approval before it can be sold.","exampleZh":"這款藥物正在等待主管機關核准後才能上市。","synonyms":[],"level":6,"theme":"合約與法律"},{"word":"rehearsal","pos":"n.","phonetic":"[rɪˈhɝsl]","meaning":"排練；彩排","definition":"a practice session before a performance or event","collocations":["dress rehearsal","final rehearsal","rehearsal schedule"],"example":"The final rehearsal for the product launch is Thursday afternoon.","exampleZh":"產品發表會的最後彩排訂於週四下午。","synonyms":["practice"],"level":4,"theme":"媒體與活動"},{"word":"rehearse","pos":"v.","phonetic":"[rɪˈhɝs]","meaning":"排練；預演","definition":"to practice before a performance or presentation","collocations":["rehearse a speech","rehearse thoroughly"],"example":"She rehearsed her presentation twice before the client meeting.","exampleZh":"客戶會議前，她把簡報排練了兩次。","synonyms":["practice"],"level":4,"theme":"會議與簡報"},{"word":"reimburse","pos":"v.","phonetic":"[ˌriɪmˈbɝs]","meaning":"報銷；償還（費用）","definition":"to pay back money someone has spent for you","collocations":["reimburse expenses","fully reimbursed","reimburse for travel"],"example":"The company will reimburse employees for approved travel expenses.","exampleZh":"公司會報銷員工經核准的差旅費用。","synonyms":["repay","refund"],"level":5,"theme":"財務與會計"},{"word":"reimbursement","pos":"n.","phonetic":"[ˌriɪmˈbɝsmənt]","meaning":"報銷款；補償","definition":"money paid back to someone who spent it for you","collocations":["expense reimbursement","request reimbursement","reimbursement form"],"example":"Submit receipts with the reimbursement form within two weeks.","exampleZh":"請在兩週內連同收據繳交報銷申請單。","synonyms":["repayment"],"level":5,"theme":"財務與會計"},{"word":"reissue","pos":"v./n.","phonetic":"[riˈɪʃʊ]","meaning":"重新核發；再版","definition":"to issue something again","collocations":["reissue a ticket","reissue a card"],"example":"The bank will reissue your card within five business days.","exampleZh":"銀行將在五個工作天內重新核發您的卡片。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"reject","pos":"v.","phonetic":"[rɪˈdʒɛkt]","meaning":"拒絕；駁回","definition":"to refuse to accept, believe, or consider something","collocations":["reject an offer","reject an application","flatly reject"],"example":"The committee rejected his proposal.","exampleZh":"委員會駁回了他的提案。","synonyms":["refuse","decline"],"level":4,"theme":"日常與一般"},{"word":"relate","pos":"v.","phonetic":"[rɪˈlet]","meaning":"使有關聯；理解","definition":"to show or make a connection between things","collocations":["relate to","relate a story","closely related"],"example":"I can really relate to what you're saying.","exampleZh":"我真的能理解你所說的。","synonyms":["connect"],"level":3,"theme":"日常與一般"},{"word":"related","pos":"adj.","phonetic":"[rɪˈletɪd]","meaning":"相關的；有關聯的","definition":"connected with something","collocations":["work-related","related to","closely related"],"example":"All work-related injuries must be reported immediately.","exampleZh":"所有因公受傷都必須立即通報。","synonyms":["connected","associated"],"level":3,"theme":"日常與一般"},{"word":"relation","pos":"n.","phonetic":"[rɪˈleʃən]","meaning":"關係；關聯；親屬","definition":"a connection between things or people","collocations":["public relations","in relation to","business relations"],"example":"The public relations team handled the announcement smoothly.","exampleZh":"公關團隊順利處理了這次的對外公告。","synonyms":["relationship","connection"],"level":3,"theme":"企業經營"},{"word":"relationship","pos":"n.","phonetic":"[rɪˈleʃənˌʃɪp]","meaning":"關係","definition":"the way in which two or more people or things are connected","collocations":["build a relationship","close relationship","long-term relationship"],"example":"They have a close relationship with their neighbors.","exampleZh":"他們和鄰居關係很好。","synonyms":["connection"],"level":2,"theme":"日常與一般"},{"word":"relatively","pos":"adv.","phonetic":"[ˈrɛlətɪvlɪ]","meaning":"相對地；比較而言","definition":"compared with other things","collocations":["relatively new","relatively low","relatively simple"],"example":"The repair was relatively inexpensive compared to a full replacement.","exampleZh":"與整組更換相比，維修費用相對便宜。","synonyms":["comparatively"],"level":4,"theme":"日常與一般"},{"word":"relax","pos":"v.","phonetic":"[rɪˈlæks]","meaning":"放鬆","definition":"to become less tense or anxious","collocations":["relax at home","just relax","relax the muscles"],"example":"Just relax and enjoy the weekend.","exampleZh":"放輕鬆，好好享受週末。","synonyms":["unwind"],"level":2,"theme":"日常與一般"},{"word":"release","pos":"v. / n.","phonetic":"[rɪˈlis]","meaning":"釋放；發行","definition":"to allow to move freely, or to make available to the public","collocations":["release a movie","release a prisoner","new release"],"example":"The band will release a new album next month.","exampleZh":"這個樂團下個月將發行新專輯。","synonyms":["free","publish"],"level":3,"theme":"科技與通訊"},{"word":"relevant","pos":"adj.","phonetic":"[ˈrɛləvənt]","meaning":"相關的；切題的","definition":"closely connected or appropriate to what is being discussed","collocations":["relevant information","relevant experience","stay relevant"],"example":"Please provide relevant examples in your essay.","exampleZh":"請在你的文章中提供相關的例子。","synonyms":["pertinent"],"level":5,"theme":"日常與一般"},{"word":"reliability","pos":"n.","phonetic":"[rɪˌlaɪəˈbɪlətɪ]","meaning":"可靠性；可信度","definition":"the quality of being trusted to work well or behave correctly","collocations":["product reliability","test for reliability","proven reliability"],"example":"The brand is known for the reliability of its engines.","exampleZh":"這個品牌以引擎的可靠性著稱。","synonyms":["dependability"],"level":5,"theme":"生產與物流"},{"word":"reliable","pos":"adj.","phonetic":"[rɪˈlaɪəbl̩]","meaning":"可靠的","definition":"consistently good in quality or performance; trustworthy","collocations":["reliable source","reliable friend","highly reliable"],"example":"He is a reliable friend who always keeps his promises.","exampleZh":"他是個可靠的朋友，總是信守承諾。","synonyms":["dependable"],"level":4,"theme":"日常與一般"},{"word":"relieve","pos":"v.","phonetic":"[rɪˈliv]","meaning":"緩解；減輕；接替","definition":"to make a problem less serious, or to take over someone's duty","collocations":["relieve stress","relieve congestion","relieve pain"],"example":"The new bypass should relieve traffic congestion downtown.","exampleZh":"新的外環道應可緩解市中心的交通壅塞。","synonyms":["ease","alleviate"],"level":4,"theme":"日常與一般"},{"word":"relocate","pos":"v.","phonetic":"[riˈloket]","meaning":"搬遷；調職","definition":"to move to a new place for work or business","collocations":["relocate to","relocate the office","willing to relocate"],"example":"The company will relocate its headquarters to the new business park.","exampleZh":"公司將把總部搬遷到新的商業園區。","synonyms":["move","transfer"],"level":5,"theme":"企業經營"},{"word":"relocation","pos":"n.","phonetic":"[ˌriloˈkeʃən]","meaning":"搬遷；調職","definition":"the act of moving to a new place","collocations":["relocation package","office relocation","relocation costs"],"example":"The job offer includes a generous relocation package.","exampleZh":"這份工作提供優渥的搬遷補助。","synonyms":["move"],"level":5,"theme":"人事與職涯"},{"word":"rely","pos":"v.","phonetic":"[rɪˈlaɪ]","meaning":"依賴；信賴","definition":"to depend on with full trust or confidence","collocations":["rely on","rely heavily","cannot rely"],"example":"You can always rely on her for help.","exampleZh":"你總是可以依賴她的幫助。","synonyms":["depend"],"level":3,"theme":"日常與一般"},{"word":"remain","pos":"v.","phonetic":"[rɪˈmen]","meaning":"保持；仍然是；剩下","definition":"to continue to exist or stay in the same state","collocations":["remain calm","remain unchanged","remain silent"],"example":"Despite the chaos, she remained calm.","exampleZh":"儘管一片混亂，她仍保持冷靜。","synonyms":["stay"],"level":3,"theme":"日常與一般"},{"word":"remaining","pos":"adj.","phonetic":"[rɪˈmenɪŋ]","meaning":"剩餘的；剩下的","definition":"still existing after other parts are gone","collocations":["remaining balance","remaining seats","remaining stock"],"example":"The remaining balance is due upon delivery of the furniture.","exampleZh":"尾款於家具送達時支付。","synonyms":["leftover"],"level":4,"theme":"財務與會計"},{"word":"remark","pos":"n./v.","phonetic":"[rɪˈmɑrk]","meaning":"評論；談話；評述","definition":"something said about a subject, or to say something","collocations":["opening remarks","make a remark","closing remarks"],"example":"The chairman will give the opening remarks at the ceremony.","exampleZh":"董事長將在典禮上致開幕詞。","synonyms":["comment"],"level":4,"theme":"會議與簡報"},{"word":"remarkable","pos":"adj.","phonetic":"[rɪˈmɑrkəbl̩]","meaning":"卓越的；非凡的","definition":"worthy of attention; striking or extraordinary","collocations":["remarkable achievement","remarkable ability","truly remarkable"],"example":"She made remarkable progress in just one month.","exampleZh":"她在短短一個月內取得了驚人的進步。","synonyms":["extraordinary"],"level":5,"theme":"日常與一般"},{"word":"remind","pos":"v.","phonetic":"[rɪˈmaɪnd]","meaning":"提醒","definition":"to cause someone to remember something","collocations":["remind someone of","gentle reminder","remind to do"],"example":"This song reminds me of my childhood.","exampleZh":"這首歌讓我想起了童年。","synonyms":["prompt"],"level":2,"theme":"溝通與語言"},{"word":"reminder","pos":"n.","phonetic":"[rɪˈmaɪndɚ]","meaning":"提醒；催繳通知","definition":"a message that helps someone remember something","collocations":["friendly reminder","send a reminder","payment reminder"],"example":"This is a friendly reminder that timesheets are due tomorrow.","exampleZh":"友善提醒：工時表明天截止繳交。","synonyms":["notice"],"level":4,"theme":"辦公室與行政"},{"word":"remodel","pos":"v.","phonetic":"[riˈmɑdl]","meaning":"改建；翻修","definition":"to change the structure or style of a building or room","collocations":["remodel the kitchen","completely remodeled"],"example":"The store will stay open while the second floor is remodeled.","exampleZh":"二樓改裝期間，賣場仍照常營業。","synonyms":["renovate"],"level":5,"theme":"房產與設施"},{"word":"remote","pos":"adj. / n.","phonetic":"[rɪˈmot]","meaning":"遙遠的；偏僻的；遙控器","definition":"far away in distance; a device used to operate something from a distance","collocations":["remote area","remote control","remote work"],"example":"They live in a remote village in the mountains.","exampleZh":"他們住在山區的一個偏僻村莊。","synonyms":["distant"],"level":4,"theme":"日常與一般"},{"word":"remotely","pos":"adv.","phonetic":"[rɪˈmotlɪ]","meaning":"遠端地；遙遠地；絲毫","definition":"from a distance, especially using technology","collocations":["work remotely","access remotely","remotely located"],"example":"Half of the team works remotely three days a week.","exampleZh":"團隊半數成員每週遠距工作三天。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"removal","pos":"n.","phonetic":"[rɪˈmuvl]","meaning":"移除；搬運；免職","definition":"the act of taking something away","collocations":["stain removal","removal of debris","snow removal"],"example":"Snow removal crews cleared the parking lot before dawn.","exampleZh":"除雪人員在天亮前清理了停車場。","synonyms":["elimination"],"level":4,"theme":"房產與設施"},{"word":"remove","pos":"v.","phonetic":"[rɪˈmuv]","meaning":"移除；去除","definition":"to take something away or off","collocations":["remove a stain","remove a barrier","remove clothes"],"example":"Please remove your shoes before entering.","exampleZh":"進門前請脫鞋。","synonyms":["take away","eliminate"],"level":3,"theme":"日常與一般"},{"word":"renew","pos":"v.","phonetic":"[rɪˈnju]","meaning":"續約；更新；延長","definition":"to continue an agreement for a further period","collocations":["renew a contract","renew a subscription","renew a license"],"example":"Remember to renew your parking permit before it expires.","exampleZh":"請記得在停車證到期前辦理續期。","synonyms":["extend"],"level":4,"theme":"合約與法律"},{"word":"renewal","pos":"n.","phonetic":"[rɪˈnjuəl]","meaning":"續約；更新","definition":"the act of continuing an agreement for a further period","collocations":["contract renewal","renewal notice","membership renewal"],"example":"A renewal notice will be emailed one month before expiration.","exampleZh":"到期前一個月會以電子郵件寄送續約通知。","synonyms":["extension"],"level":5,"theme":"合約與法律"},{"word":"renovate","pos":"v.","phonetic":"[ˈrɛnəˌvet]","meaning":"翻新；整修","definition":"to repair and improve a building","collocations":["renovate the lobby","newly renovated","renovate completely"],"example":"The hotel will renovate all guest rooms over the winter.","exampleZh":"飯店將利用冬季翻新所有客房。","synonyms":["remodel","refurbish"],"level":5,"theme":"房產與設施"},{"word":"renovation","pos":"n.","phonetic":"[ˌrɛnəˈveʃən]","meaning":"翻修；整修工程","definition":"the process of repairing and improving a building","collocations":["under renovation","major renovation","renovation project"],"example":"The museum is closed for renovation until next spring.","exampleZh":"博物館整修中，將於明年春天重新開放。","synonyms":["remodeling"],"level":5,"theme":"房產與設施"},{"word":"rent","pos":"v. / n.","phonetic":"[rɛnt]","meaning":"租；租金","definition":"to pay someone for the use of something, or the payment made","collocations":["rent an apartment","pay rent","for rent"],"example":"They rent a small apartment near the university.","exampleZh":"他們在大學附近租了一間小公寓。","synonyms":["lease"],"level":2,"theme":"房產與設施"},{"word":"rental","pos":"n./adj.","phonetic":"[ˈrɛntl]","meaning":"租賃；租金；出租的","definition":"the act of renting something, or something available to rent","collocations":["car rental","rental agreement","rental fee"],"example":"The car rental counter is located on the airport's first floor.","exampleZh":"租車櫃檯位於機場一樓。","synonyms":["lease"],"level":3,"theme":"旅遊與交通"},{"word":"repair","pos":"v. / n.","phonetic":"[rɪˈpɛr]","meaning":"修理；修復","definition":"to fix something that is damaged or not working","collocations":["repair a car","under repair","repair shop"],"example":"The mechanic repaired the car in an hour.","exampleZh":"技師一小時內就修好了這輛車。","synonyms":["fix","mend"],"level":3,"theme":"人事與職涯"},{"word":"repeat","pos":"v.","phonetic":"[rɪˈpit]","meaning":"重複","definition":"to say or do something again","collocations":["repeat a word","repeat after me","repeat mistakes"],"example":"Could you repeat that, please?","exampleZh":"你可以再說一次嗎？","synonyms":["reiterate"],"level":2,"theme":"溝通與語言"},{"word":"repeatedly","pos":"adv.","phonetic":"[rɪˈpitɪdlɪ]","meaning":"重複地；再三","definition":"many times","collocations":["repeatedly asked","repeatedly warned"],"example":"Customers have repeatedly requested longer weekend hours.","exampleZh":"顧客一再要求延長週末營業時間。","synonyms":["frequently"],"level":4,"theme":"日常與一般"},{"word":"replace","pos":"v.","phonetic":"[rɪˈples]","meaning":"取代；替換","definition":"to put something new in the place of something else","collocations":["replace a battery","replace with","cannot be replaced"],"example":"We need to replace the old printer.","exampleZh":"我們需要更換舊印表機。","synonyms":["substitute"],"level":3,"theme":"日常與一般"},{"word":"replacement","pos":"n.","phonetic":"[rɪˈplesmənt]","meaning":"更換；替代品；接替者","definition":"a person or thing that takes the place of another","collocations":["replacement parts","find a replacement","free replacement"],"example":"A replacement will be shipped at no charge within three days.","exampleZh":"替換品將在三天內免費寄出。","synonyms":["substitute"],"level":4,"theme":"購物與消費"},{"word":"reply","pos":"v. / n.","phonetic":"[rɪˈplaɪ]","meaning":"回覆；回答","definition":"to say or write something in response","collocations":["reply to a letter","quick reply","in reply"],"example":"She hasn't replied to my message yet.","exampleZh":"她還沒回覆我的訊息。","synonyms":["respond","answer"],"level":2,"theme":"溝通與語言"},{"word":"report","pos":"n. / v.","phonetic":"[rɪˈport]","meaning":"報告；報導","definition":"a written or spoken account of something, or to give such an account","collocations":["news report","weather report","report a crime"],"example":"The reporter wrote a report about the accident.","exampleZh":"記者寫了一篇關於這起事故的報導。","synonyms":["account"],"level":2,"theme":"科技與通訊"},{"word":"reporter","pos":"n.","phonetic":"[rɪˈportɚ]","meaning":"記者","definition":"a person who writes news stories for media","collocations":["news reporter","field reporter"],"example":"Reporters gathered outside the headquarters for the announcement.","exampleZh":"記者們聚集在總部外等候這項宣布。","synonyms":["journalist"],"level":3,"theme":"媒體與活動"},{"word":"represent","pos":"v.","phonetic":"[ˌrɛprɪˈzɛnt]","meaning":"代表","definition":"to act or speak on behalf of someone or something","collocations":["represent a country","represent an idea","fairly represent"],"example":"She will represent our school in the debate contest.","exampleZh":"她將代表我們學校參加辯論比賽。","synonyms":["stand for"],"level":4,"theme":"日常與一般"},{"word":"representative","pos":"n./adj.","phonetic":"[ˌrɛprɪˈzɛntətɪv]","meaning":"代表；業務代表；代表性的","definition":"a person who acts or speaks for a company or group","collocations":["sales representative","customer service representative","company representative"],"example":"A customer service representative will contact you within 24 hours.","exampleZh":"客服代表將在二十四小時內與您聯繫。","synonyms":["agent","delegate"],"level":4,"theme":"人事與職涯"},{"word":"reproduce","pos":"v.","phonetic":"[ˌriprəˈdjus]","meaning":"複製；重現；繁殖","definition":"to make a copy of something","collocations":["reproduce without permission","faithfully reproduced"],"example":"This report may not be reproduced without written permission.","exampleZh":"未經書面許可，不得複製本報告。","synonyms":["copy","duplicate"],"level":5,"theme":"合約與法律"},{"word":"reputation","pos":"n.","phonetic":"[ˌrɛpjəˈteʃən]","meaning":"名聲；聲譽","definition":"the general opinion people have about someone or something","collocations":["good reputation","build a reputation","reputation for quality"],"example":"The firm has earned a reputation for outstanding customer service.","exampleZh":"這家公司以卓越的顧客服務贏得聲譽。","synonyms":["standing","name"],"level":4,"theme":"企業經營"},{"word":"request","pos":"n./v.","phonetic":"[rɪˈkwɛst]","meaning":"請求；要求；申請","definition":"the act of politely asking for something, or to ask for it","collocations":["upon request","submit a request","request form"],"example":"Vegetarian meals are available upon request.","exampleZh":"素食餐點可依需求提供。","synonyms":["ask"],"level":3,"theme":"辦公室與行政"},{"word":"require","pos":"v.","phonetic":"[rɪˈkwaɪr]","meaning":"需要；要求","definition":"to need something for a particular purpose","collocations":["require attention","require permission","as required"],"example":"This job requires a lot of patience.","exampleZh":"這份工作需要很大的耐心。","synonyms":["need"],"level":3,"theme":"日常與一般"},{"word":"requirement","pos":"n.","phonetic":"[rɪˈkwaɪrmənt]","meaning":"要求；必要條件","definition":"something that is needed or demanded","collocations":["meet the requirements","minimum requirements","entry requirements"],"example":"A bachelor's degree is a minimum requirement for this role.","exampleZh":"學士學位是這個職位的最低要求。","synonyms":["prerequisite","condition"],"level":4,"theme":"人事與職涯"},{"word":"reschedule","pos":"v.","phonetic":"[riˈskɛdʒʊl]","meaning":"改期；重新安排","definition":"to change the time of a planned event","collocations":["reschedule a meeting","reschedule for","reschedule an appointment"],"example":"Can we reschedule the interview for Thursday morning?","exampleZh":"我們可以把面試改到週四上午嗎？","synonyms":["rearrange"],"level":4,"theme":"辦公室與行政"},{"word":"research","pos":"n. / v.","phonetic":"[rɪˈsɝtʃ]","meaning":"研究","definition":"the systematic investigation into a subject","collocations":["conduct research","research shows","medical research"],"example":"Scientists are conducting research on climate change.","exampleZh":"科學家正在進行氣候變遷的研究。","synonyms":["study"],"level":3,"theme":"科技與通訊"},{"word":"researcher","pos":"n.","phonetic":"[rɪˈsɝtʃɚ]","meaning":"研究員；研究人員","definition":"a person who studies a subject carefully to discover new information","collocations":["market researcher","lead researcher","team of researchers"],"example":"Researchers found that customers prefer simpler packaging.","exampleZh":"研究人員發現顧客偏好更簡約的包裝。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"reservation","pos":"n.","phonetic":"[ˌrɛzɚˈveʃən]","meaning":"預約；訂位；保留意見","definition":"an arrangement to keep a table, room, or seat for someone","collocations":["make a reservation","confirm a reservation","dinner reservation"],"example":"I would like to make a reservation for four at seven o'clock.","exampleZh":"我想預訂七點四位的位子。","synonyms":["booking"],"level":3,"theme":"餐飲與住宿"},{"word":"reserve","pos":"v. / n.","phonetic":"[rɪˈzɝv]","meaning":"預訂；儲備","definition":"to arrange for something to be kept for a particular person","collocations":["reserve a table","natural reserve","in reserve"],"example":"I'd like to reserve a table for four tonight.","exampleZh":"我想預訂今晚四人的座位。","synonyms":["book"],"level":4,"theme":"財務與會計"},{"word":"reside","pos":"v.","phonetic":"[rɪˈzaɪd]","meaning":"居住；駐在","definition":"to live in a particular place","collocations":["reside in","currently residing"],"example":"Applicants must reside within commuting distance of the office.","exampleZh":"應徵者的居住地必須在可通勤到辦公室的範圍內。","synonyms":["live","dwell"],"level":5,"theme":"房產與設施"},{"word":"residence","pos":"n.","phonetic":"[ˈrɛzədəns]","meaning":"住所；宅邸；居住","definition":"the place where someone lives","collocations":["private residence","place of residence","official residence"],"example":"Proof of residence is required to open a bank account.","exampleZh":"開立銀行帳戶需要提供居住證明。","synonyms":["home","dwelling"],"level":5,"theme":"房產與設施"},{"word":"resident","pos":"n./adj.","phonetic":"[ˈrɛzədənt]","meaning":"居民；住戶；駐地的","definition":"a person who lives in a particular place","collocations":["local residents","residents' association","resident parking"],"example":"Local residents were invited to comment on the development plan.","exampleZh":"當地居民獲邀對開發計畫表達意見。","synonyms":["inhabitant"],"level":4,"theme":"房產與設施"},{"word":"residential","pos":"adj.","phonetic":"[ˌrɛzəˈdɛnʃəl]","meaning":"住宅的；居住的","definition":"relating to areas where people live","collocations":["residential area","residential building","residential neighborhood"],"example":"Delivery trucks must drive slowly through residential areas.","exampleZh":"貨車行經住宅區時必須減速慢行。","synonyms":[],"level":5,"theme":"房產與設施"},{"word":"resign","pos":"v.","phonetic":"[rɪˈzaɪn]","meaning":"辭職；辭去","definition":"to officially leave a job","collocations":["resign from a position","resign as director"],"example":"The marketing director resigned to start her own consultancy.","exampleZh":"行銷總監辭職去開設自己的顧問公司。","synonyms":["quit","step down"],"level":4,"theme":"人事與職涯"},{"word":"resignation","pos":"n.","phonetic":"[ˌrɛzɪgˈneʃən]","meaning":"辭職；辭呈","definition":"the act of leaving a job, or the letter announcing it","collocations":["letter of resignation","hand in one's resignation","accept a resignation"],"example":"He handed in his resignation after accepting an offer overseas.","exampleZh":"接受海外工作邀約後，他遞出了辭呈。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"resolution","pos":"n.","phonetic":"[ˌrɛzəˈluʃən]","meaning":"解決；決議；解析度","definition":"the act of solving a problem, a formal decision, or image sharpness","collocations":["conflict resolution","pass a resolution","high resolution"],"example":"The team praised her quick resolution of the shipping dispute.","exampleZh":"團隊讚賞她迅速解決了運送糾紛。","synonyms":["settlement"],"level":5,"theme":"企業經營"},{"word":"resolve","pos":"v.","phonetic":"[rɪˈzɑlv]","meaning":"解決；決心","definition":"to find a solution to a problem or difficulty","collocations":["resolve a conflict","resolve an issue","firmly resolve"],"example":"They finally resolved their differences.","exampleZh":"他們終於解決了彼此的分歧。","synonyms":["settle"],"level":5,"theme":"日常與一般"},{"word":"resort","pos":"n./v.","phonetic":"[rɪˈzɔrt]","meaning":"度假村；訴諸","definition":"a place for holidays, or to use something when other options fail","collocations":["beach resort","ski resort","as a last resort"],"example":"The seaside resort offers special packages for company retreats.","exampleZh":"這座海濱度假村為企業員工旅遊提供特別方案。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"resource","pos":"n.","phonetic":"[ˈrisɔrs]","meaning":"資源","definition":"a stock or supply of materials or assets","collocations":["natural resources","human resources","limited resources"],"example":"Taiwan lacks natural resources such as oil.","exampleZh":"臺灣缺乏石油等天然資源。","synonyms":["asset"],"level":4,"theme":"財務與會計"},{"word":"respectively","pos":"adv.","phonetic":"[rɪˈspɛktɪvlɪ]","meaning":"分別地；各自地","definition":"in the same order as the things already mentioned","collocations":["respectively priced","first and second respectively"],"example":"The gold and silver plans cost fifty and thirty dollars respectively.","exampleZh":"金級與銀級方案分別為五十美元和三十美元。","synonyms":[],"level":6,"theme":"溝通與語言"},{"word":"respond","pos":"v.","phonetic":"[rɪˈspɑnd]","meaning":"回應；回答","definition":"to say or do something as a reaction to something","collocations":["respond quickly","respond to a question","fail to respond"],"example":"He responded to my email right away.","exampleZh":"他馬上回覆了我的電子郵件。","synonyms":["reply"],"level":3,"theme":"溝通與語言"},{"word":"response","pos":"n.","phonetic":"[rɪˈspɑns]","meaning":"回應；反應","definition":"a reply or reaction to something","collocations":["in response to","positive response","quick response"],"example":"The company received hundreds of responses to the survey.","exampleZh":"這家公司收到了數百份問卷回應。","synonyms":["reply"],"level":3,"theme":"溝通與語言"},{"word":"responsibility","pos":"n.","phonetic":"[rɪˌspɑnsəˈbɪlətɪ]","meaning":"責任","definition":"a duty to deal with or take care of something","collocations":["take responsibility","sense of responsibility","job responsibility"],"example":"Taking care of the dog is my responsibility.","exampleZh":"照顧這隻狗是我的責任。","synonyms":["duty"],"level":3,"theme":"日常與一般"},{"word":"responsible","pos":"adj.","phonetic":"[rɪˈspɑnsəbl̩]","meaning":"負責任的","definition":"having a duty to deal with something or having control over someone","collocations":["responsible for","socially responsible","act responsible"],"example":"Parents are responsible for their children's safety.","exampleZh":"父母有責任確保孩子的安全。","synonyms":["accountable"],"level":3,"theme":"日常與一般"},{"word":"restaurant","pos":"n.","phonetic":"[ˈrɛstərənt]","meaning":"餐廳","definition":"a place where people pay to sit and eat meals","collocations":["eat at a restaurant","open a restaurant","fancy restaurant"],"example":"We celebrated her birthday at a fancy restaurant.","exampleZh":"我們在一家高級餐廳慶祝她的生日。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"restore","pos":"v.","phonetic":"[rɪˈstor]","meaning":"恢復；修復；復原","definition":"to bring something back to its earlier condition","collocations":["restore power","restore service","restore a building"],"example":"Technicians worked overnight to restore the network service.","exampleZh":"技術人員連夜搶修以恢復網路服務。","synonyms":["repair","revive"],"level":4,"theme":"科技與通訊"},{"word":"restrict","pos":"v.","phonetic":"[rɪˈstrɪkt]","meaning":"限制；約束","definition":"to limit something","collocations":["restrict access","restrict parking","strictly restricted"],"example":"Access to the server room is restricted to authorized staff.","exampleZh":"機房僅限授權人員進入。","synonyms":["limit","confine"],"level":4,"theme":"辦公室與行政"},{"word":"restriction","pos":"n.","phonetic":"[rɪˈstrɪkʃən]","meaning":"限制；規定","definition":"an official rule that limits something","collocations":["travel restrictions","lift restrictions","baggage restrictions"],"example":"Please review the baggage restrictions before packing.","exampleZh":"打包行李前請先查看行李限制規定。","synonyms":["limitation","constraint"],"level":4,"theme":"旅遊與交通"},{"word":"restroom","pos":"n.","phonetic":"[ˈrɛstˌrum]","meaning":"洗手間；廁所","definition":"a public toilet","collocations":["public restroom","restroom facilities"],"example":"The restrooms are located next to the elevators on each floor.","exampleZh":"每層樓的洗手間都位於電梯旁。","synonyms":["bathroom","lavatory"],"level":3,"theme":"房產與設施"},{"word":"result","pos":"n. / v.","phonetic":"[rɪˈzʌlt]","meaning":"結果","definition":"a consequence, effect, or outcome of something","collocations":["as a result","test result","result in"],"example":"As a result of hard work, she passed the exam.","exampleZh":"由於努力，她通過了考試。","synonyms":["outcome"],"level":2,"theme":"日常與一般"},{"word":"resume","pos":"n./v.","phonetic":"[ˈrɛzʊˌme]","meaning":"履歷表；恢復；重新開始","definition":"a document describing your work history, or to start again after a pause","collocations":["submit a resume","update your resume","resume operations"],"example":"Please submit your resume and cover letter through the careers page.","exampleZh":"請透過徵才網頁提交履歷與求職信。","synonyms":["CV"],"level":3,"theme":"人事與職涯"},{"word":"retail","pos":"n./adj./v.","phonetic":"[ˈritel]","meaning":"零售；零售的","definition":"the sale of goods directly to customers","collocations":["retail store","retail price","retail sales"],"example":"Retail sales rose sharply during the holiday shopping season.","exampleZh":"零售銷售額在節慶購物季大幅上升。","synonyms":[],"level":4,"theme":"購物與消費"},{"word":"retailer","pos":"n.","phonetic":"[ˈritelɚ]","meaning":"零售商","definition":"a business that sells goods directly to customers","collocations":["online retailer","major retailer","authorized retailer"],"example":"The product is available at authorized retailers nationwide.","exampleZh":"本產品於全國授權零售商均有販售。","synonyms":["merchant","seller"],"level":4,"theme":"購物與消費"},{"word":"retain","pos":"v.","phonetic":"[rɪˈten]","meaning":"保留；留住","definition":"to keep something or continue to have it","collocations":["retain customers","retain records","retain employees"],"example":"Good benefits help the company retain talented employees.","exampleZh":"優渥的福利有助於公司留住優秀人才。","synonyms":["keep","preserve"],"level":5,"theme":"人事與職涯"},{"word":"retire","pos":"v.","phonetic":"[rɪˈtaɪr]","meaning":"退休","definition":"to leave one's job and stop working, usually because of age","collocations":["retire from work","early retirement","plan to retire"],"example":"My grandfather retired at the age of sixty-five.","exampleZh":"我祖父在六十五歲時退休。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"retirement","pos":"n.","phonetic":"[rɪˈtaɪrmənt]","meaning":"退休","definition":"the time after you stop working permanently","collocations":["retirement plan","early retirement","retirement party"],"example":"The company matches employee contributions to the retirement plan.","exampleZh":"公司會相對提撥員工的退休金。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"retreat","pos":"n./v.","phonetic":"[rɪˈtrit]","meaning":"僻靜之處；共識營；撤退","definition":"a quiet place, an off-site team event, or to move back","collocations":["company retreat","weekend retreat","mountain retreat"],"example":"The annual company retreat focuses on team building activities.","exampleZh":"一年一度的公司共識營以團隊建立活動為主。","synonyms":[],"level":5,"theme":"媒體與活動"},{"word":"retrieve","pos":"v.","phonetic":"[rɪˈtriv]","meaning":"取回；檢索","definition":"to get something back, especially information or an object","collocations":["retrieve data","retrieve a file","retrieve luggage"],"example":"You can retrieve deleted files from the recycle bin within thirty days.","exampleZh":"三十天內可從資源回收筒取回刪除的檔案。","synonyms":["recover","fetch"],"level":5,"theme":"科技與通訊"},{"word":"return","pos":"v. / n.","phonetic":"[rɪˈtɝn]","meaning":"返回；歸還","definition":"to come or go back to a place, or to give something back","collocations":["return home","return a book","in return"],"example":"He returned the library book two days late.","exampleZh":"他歸還圖書館的書遲了兩天。","synonyms":["come back"],"level":1,"theme":"日常與一般"},{"word":"reveal","pos":"v.","phonetic":"[rɪˈvil]","meaning":"揭露；顯示","definition":"to make known previously secret or hidden information","collocations":["reveal a secret","reveal the truth","study reveals"],"example":"The magician revealed how the trick was done.","exampleZh":"魔術師揭露了這個把戲是怎麼做的。","synonyms":["disclose"],"level":4,"theme":"溝通與語言"},{"word":"revenue","pos":"n.","phonetic":"[ˈrɛvəˌnju]","meaning":"營收；收入","definition":"the money a company receives from its business","collocations":["annual revenue","revenue growth","generate revenue"],"example":"Subscription services now account for half of the company's revenue.","exampleZh":"訂閱服務現在占公司營收的一半。","synonyms":["income","earnings"],"level":5,"theme":"財務與會計"},{"word":"review","pos":"n. / v.","phonetic":"[rɪˈvju]","meaning":"評論；複習；審查","definition":"a formal assessment of something, or to examine again","collocations":["book review","review for a test","under review"],"example":"She wrote a positive review of the new movie.","exampleZh":"她給那部新電影寫了正面的評論。","synonyms":["evaluate"],"level":3,"theme":"人事與職涯"},{"word":"reviewer","pos":"n.","phonetic":"[rɪˈvjuɚ]","meaning":"評論者；審查者","definition":"a person who writes opinions about products, books, or performances","collocations":["book reviewer","peer reviewer","food reviewer"],"example":"Reviewers praised the restaurant's creative seasonal menu.","exampleZh":"評論家盛讚這家餐廳深具創意的季節菜單。","synonyms":["critic"],"level":4,"theme":"媒體與活動"},{"word":"revise","pos":"v.","phonetic":"[rɪˈvaɪz]","meaning":"修訂；修改","definition":"to change something to make it better or more accurate","collocations":["revise a document","revise the schedule","revised edition"],"example":"Please revise the proposal to reflect the new budget figures.","exampleZh":"請依新的預算數字修改提案。","synonyms":["amend","update"],"level":4,"theme":"辦公室與行政"},{"word":"revision","pos":"n.","phonetic":"[rɪˈvɪʒən]","meaning":"修訂；修改版本","definition":"a change made to improve something, or the changed version","collocations":["make revisions","final revision","subject to revision"],"example":"The final revision of the contract is ready for signature.","exampleZh":"合約的最終修訂版已可供簽署。","synonyms":["amendment"],"level":5,"theme":"辦公室與行政"},{"word":"reward","pos":"n. / v.","phonetic":"[rɪˈwɔrd]","meaning":"獎勵；報酬","definition":"a thing given in recognition of effort or achievement","collocations":["reward effort","offer a reward","great reward"],"example":"Hard work is often its own reward.","exampleZh":"努力工作本身往往就是一種回報。","synonyms":["prize"],"level":3,"theme":"日常與一般"},{"word":"rewarding","pos":"adj.","phonetic":"[rɪˈwɔrdɪŋ]","meaning":"有意義的；值得的","definition":"giving satisfaction or benefit","collocations":["rewarding career","rewarding experience","financially rewarding"],"example":"Volunteering at the shelter has been a rewarding experience.","exampleZh":"在收容所當志工是一段很有意義的經歷。","synonyms":["fulfilling","satisfying"],"level":4,"theme":"人事與職涯"},{"word":"rise","pos":"v. / n.","phonetic":"[raɪz]","meaning":"上升；起身；增加","definition":"to move upward or increase in level or amount","collocations":["sun rises","rise in price","give rise to"],"example":"Prices have risen sharply this year.","exampleZh":"今年物價急遽上漲。","synonyms":["increase","ascend"],"level":2,"theme":"日常與一般"},{"word":"risk","pos":"n. / v.","phonetic":"[rɪsk]","meaning":"風險；冒險","definition":"a situation involving exposure to danger","collocations":["take a risk","at risk","risk one's life"],"example":"Smoking increases the risk of lung cancer.","exampleZh":"吸菸會增加罹患肺癌的風險。","synonyms":["danger"],"level":3,"theme":"日常與一般"},{"word":"robust","pos":"adj.","phonetic":"[roˈbʌst]","meaning":"強健的；強壯的","definition":"strong and healthy; sturdy","collocations":["robust economy","robust health","robust design"],"example":"The company built a robust economy over the decade.","exampleZh":"這家公司在十年間建立了強健的經濟體系。","synonyms":["sturdy","strong"],"level":5,"theme":"日常與一般"},{"word":"role","pos":"n.","phonetic":"[rol]","meaning":"角色；作用","definition":"the function or position someone has","collocations":["play a role","leading role"],"example":"She played the leading role in the school play.","exampleZh":"她在學校話劇中飾演主角。","synonyms":["part","function"],"level":2,"theme":"媒體與活動"},{"word":"rollout","pos":"n.","phonetic":"[ˈrolˌaʊt]","meaning":"（產品／服務）推出；上線","definition":"the introduction of a new product or service","collocations":["product rollout","nationwide rollout","phased rollout"],"example":"The nationwide rollout of the app begins next quarter.","exampleZh":"這款應用程式將於下一季在全國推出。","synonyms":["launch"],"level":6,"theme":"行銷與銷售"},{"word":"roster","pos":"n.","phonetic":"[ˈrɑstɚ]","meaning":"名冊；輪值表","definition":"a list of people's names, often showing work duties","collocations":["duty roster","staff roster","on the roster"],"example":"The weekend duty roster is posted every Thursday.","exampleZh":"週末輪值表於每週四公布。","synonyms":["list","schedule"],"level":6,"theme":"辦公室與行政"},{"word":"rotate","pos":"v.","phonetic":"[ˈrotet]","meaning":"旋轉；輪流","definition":"to turn around a central point","collocations":["rotate crops","rotate the tires"],"example":"The Earth rotates on its axis once a day.","exampleZh":"地球每天繞地軸自轉一圈。","synonyms":["revolve","spin"],"level":4,"theme":"科技與通訊"},{"word":"rotation","pos":"n.","phonetic":"[roˈteʃən]","meaning":"輪調；輪換；旋轉","definition":"the practice of taking turns, or turning in a circle","collocations":["job rotation","in rotation","crop rotation"],"example":"New trainees complete a rotation through four departments.","exampleZh":"新進儲備人員需輪調四個部門完成訓練。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"roughly","pos":"adv.","phonetic":"[ˈrʌflɪ]","meaning":"大約地；粗略地","definition":"approximately; in a rough manner","collocations":["roughly estimated","treated roughly"],"example":"The trip takes roughly three hours.","exampleZh":"這趟旅程大約需要三小時。","synonyms":["approximately","about"],"level":3,"theme":"日常與一般"},{"word":"round-trip","pos":"adj./n.","phonetic":"[ˈraʊndˈtrɪp]","meaning":"來回的；來回行程","definition":"traveling to a place and back again","collocations":["round-trip ticket","round-trip fare","round-trip flight"],"example":"A round-trip ticket costs less than two one-way fares.","exampleZh":"來回票比兩張單程票便宜。","synonyms":[],"level":4,"theme":"旅遊與交通"},{"word":"route","pos":"n.","phonetic":"[rut]","meaning":"路線；路徑","definition":"a way or course taken to get somewhere","collocations":["bus route","take a different route"],"example":"We took a scenic route through the mountains.","exampleZh":"我們選了一條穿越山區的風景路線。","synonyms":["path","way"],"level":3,"theme":"旅遊與交通"},{"word":"routine","pos":"n. / adj.","phonetic":"[ruˈtin]","meaning":"例行公事；日常慣例","definition":"a regular way of doing things","collocations":["daily routine","routine checkup"],"example":"Exercise is part of my daily routine.","exampleZh":"運動是我日常生活的一部分。","synonyms":["habit","procedure"],"level":3,"theme":"房產與設施"},{"word":"row","pos":"n. / v.","phonetic":"[ro]","meaning":"排；划船","definition":"a line of things or people; to propel a boat with oars","collocations":["front row","row a boat"],"example":"We sat in the front row of the theater.","exampleZh":"我們坐在劇院的前排。","synonyms":["line","line up"],"level":2,"theme":"日常與一般"},{"word":"rule","pos":"n. / v.","phonetic":"[rul]","meaning":"規則；統治","definition":"a statement about what to do; to govern","collocations":["break a rule","rule a country"],"example":"Students must follow the school rules.","exampleZh":"學生必須遵守校規。","synonyms":["regulation","govern"],"level":1,"theme":"合約與法律"},{"word":"runway","pos":"n.","phonetic":"[ˈrʌnˌwe]","meaning":"跑道","definition":"a strip where aircraft take off and land","collocations":["airport runway","fashion runway"],"example":"The plane sped down the runway before takeoff.","exampleZh":"飛機起飛前在跑道上加速滑行。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"rural","pos":"adj.","phonetic":"[ˈrʊrəl]","meaning":"鄉村的","definition":"relating to the countryside","collocations":["rural area","rural life"],"example":"They moved to a rural area to enjoy a quiet life.","exampleZh":"他們搬到鄉村地區享受寧靜的生活。","synonyms":["countryside","agricultural"],"level":4,"theme":"房產與設施"},{"word":"rush","pos":"v. / n.","phonetic":"[rʌʃ]","meaning":"匆忙；衝","definition":"to move or act with urgent speed","collocations":["rush hour","rush to finish"],"example":"Don't rush; we still have plenty of time.","exampleZh":"別急,我們還有充裕的時間。","synonyms":["hurry","hasten"],"level":3,"theme":"日常與一般"},{"word":"safe","pos":"adj.","phonetic":"[sef]","meaning":"安全的；平安的","definition":"free from danger or harm","collocations":["safe place","safe and sound","keep safe"],"example":"Please drive safe on the icy road.","exampleZh":"請在結冰的路上小心駕駛。","synonyms":["secure"],"level":1,"theme":"日常與一般"},{"word":"safely","pos":"adv.","phonetic":"[ˈseflɪ]","meaning":"安全地","definition":"without danger or harm","collocations":["arrive safely","safely stored","drive safely"],"example":"All chemicals must be safely stored in the locked cabinet.","exampleZh":"所有化學品都必須安全存放在上鎖的櫃子裡。","synonyms":["securely"],"level":2,"theme":"日常與一般"},{"word":"safety","pos":"n.","phonetic":"[ˈsefti]","meaning":"安全","definition":"the state of being safe","collocations":["safety belt","road safety","for safety reasons"],"example":"Wear a helmet for your own safety.","exampleZh":"為了你自己的安全請戴安全帽。","synonyms":["security"],"level":2,"theme":"日常與一般"},{"word":"salary","pos":"n.","phonetic":"[ˈsæləri]","meaning":"薪水","definition":"fixed regular payment for work","collocations":["monthly salary","high salary","salary increase"],"example":"He earns a good salary as an engineer.","exampleZh":"他當工程師領著不錯的薪水。","synonyms":["wage","pay"],"level":3,"theme":"財務與會計"},{"word":"sale","pos":"n.","phonetic":"[sel]","meaning":"銷售；拍賣","definition":"the act of selling something","collocations":["for sale","on sale","sales figures"],"example":"The house is for sale.","exampleZh":"這棟房子正在出售。","synonyms":[],"level":2,"theme":"財務與會計"},{"word":"sample","pos":"n. / v.","phonetic":"[ˈsæmpəl]","meaning":"樣本；試吃","definition":"a small part representing the whole","collocations":["free sample","sample size","take a sample"],"example":"You can try a free sample at the store.","exampleZh":"你可以在店裡試吃免費樣品。","synonyms":["example"],"level":3,"theme":"日常與一般"},{"word":"satisfaction","pos":"n.","phonetic":"[ˌsætɪsˈfækʃən]","meaning":"滿意；滿足","definition":"the pleased feeling when something meets your needs or wishes","collocations":["customer satisfaction","job satisfaction","satisfaction survey"],"example":"The hotel scored highly in this year's customer satisfaction survey.","exampleZh":"這家飯店在今年的顧客滿意度調查中得分很高。","synonyms":["contentment"],"level":4,"theme":"行銷與銷售"},{"word":"satisfactory","pos":"adj.","phonetic":"[ˌsætɪsˈfæktərɪ]","meaning":"令人滿意的；合格的","definition":"good enough for a purpose","collocations":["satisfactory results","satisfactory condition","satisfactory performance"],"example":"The inspection found the equipment in satisfactory condition.","exampleZh":"檢查發現設備狀況良好。","synonyms":["acceptable","adequate"],"level":5,"theme":"生產與物流"},{"word":"satisfy","pos":"v.","phonetic":"[ˈsætɪsˌfaɪ]","meaning":"使滿意","definition":"to meet expectations or needs","collocations":["satisfy customers","hard to satisfy"],"example":"The meal satisfied everyone's hunger.","exampleZh":"這頓飯讓每個人都吃飽滿足。","synonyms":["please"],"level":3,"theme":"日常與一般"},{"word":"save","pos":"v.","phonetic":"[sev]","meaning":"拯救；儲蓄","definition":"to rescue from danger or keep money for later","collocations":["save money","save time","save a life"],"example":"He saved money to buy a new bike.","exampleZh":"他存錢買了一台新腳踏車。","synonyms":["rescue"],"level":1,"theme":"日常與一般"},{"word":"savings","pos":"n.","phonetic":"[ˈsevɪŋz]","meaning":"儲蓄；節省的金額","definition":"money kept in a bank, or an amount not spent","collocations":["savings account","cost savings","significant savings"],"example":"Buying in bulk offers significant savings for small businesses.","exampleZh":"大量採購能為小型企業省下可觀的費用。","synonyms":[],"level":3,"theme":"財務與會計"},{"word":"scale","pos":"n.","phonetic":"[skel]","meaning":"規模；刻度；磅秤","definition":"the size or extent of something, or a device for weighing","collocations":["large scale","on a small scale","bathroom scale"],"example":"The project was carried out on a large scale.","exampleZh":"這項計畫是大規模進行的。","synonyms":["extent"],"level":4,"theme":"日常與一般"},{"word":"scan","pos":"v.","phonetic":"[skæn]","meaning":"掃描；瀏覽","definition":"to look at quickly or convert into digital data","collocations":["scan a document","scan the room"],"example":"He scanned the newspaper for job ads.","exampleZh":"他瀏覽報紙找工作廣告。","synonyms":["skim"],"level":3,"theme":"科技與通訊"},{"word":"scenario","pos":"n.","phonetic":"[sɪˈnɛrɪˌo]","meaning":"情境；可能的情況","definition":"a description of a possible situation","collocations":["worst-case scenario","best-case scenario","likely scenario"],"example":"The plan covers several scenarios, including supply delays.","exampleZh":"這份計畫涵蓋多種情境，包括供貨延誤。","synonyms":["situation"],"level":5,"theme":"企業經營"},{"word":"scene","pos":"n.","phonetic":"[sin]","meaning":"場景；景象","definition":"a place where an event happens","collocations":["crime scene","behind the scenes"],"example":"Police arrived at the scene quickly.","exampleZh":"警方很快就抵達現場。","synonyms":["setting"],"level":3,"theme":"媒體與活動"},{"word":"scenery","pos":"n.","phonetic":"[ˈsinəri]","meaning":"風景","definition":"the natural features of a landscape","collocations":["beautiful scenery","mountain scenery"],"example":"We enjoyed the beautiful scenery along the coast.","exampleZh":"我們欣賞著沿海美麗的風景。","synonyms":["landscape"],"level":4,"theme":"日常與一般"},{"word":"scenic","pos":"adj.","phonetic":"[ˈsinɪk]","meaning":"風景優美的","definition":"having beautiful natural views","collocations":["scenic route","scenic view","scenic drive"],"example":"The tour follows a scenic route along the coast.","exampleZh":"這條觀光路線沿著海岸，風景優美。","synonyms":["picturesque"],"level":4,"theme":"旅遊與交通"},{"word":"schedule","pos":"n. / v.","phonetic":"[ˈskɛdʒʊl]","meaning":"時間表；排定","definition":"a plan of times for events","collocations":["busy schedule","ahead of schedule"],"example":"My schedule is full this week.","exampleZh":"我這週的行程排得很滿。","synonyms":["timetable"],"level":3,"theme":"日常與一般"},{"word":"scholar","pos":"n.","phonetic":"[ˈskɑlɚ]","meaning":"學者","definition":"a person who studies a subject deeply and thoroughly","collocations":["famous scholar","scholarly research"],"example":"The scholar spent years researching ancient history.","exampleZh":"這位學者花了數年研究古代歷史。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"scholarship","pos":"n.","phonetic":"[ˈskɑlɚˌʃɪp]","meaning":"獎學金","definition":"money given to support a student's study","collocations":["win a scholarship","apply for a scholarship"],"example":"She won a scholarship to study abroad.","exampleZh":"她獲得了出國留學的獎學金。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"science","pos":"n.","phonetic":"[ˈsaɪəns]","meaning":"科學","definition":"the study of the natural world through observation and experiment","collocations":["science class","computer science"],"example":"She loves studying science and math.","exampleZh":"她喜歡研讀科學和數學。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"scientific","pos":"adj.","phonetic":"[ˌsaɪənˈtɪfɪk]","meaning":"科學的；符合科學的","definition":"relating to science or using its methods","collocations":["scientific research","scientific evidence","scientific approach"],"example":"The claims are supported by independent scientific research.","exampleZh":"這些聲明有獨立科學研究的支持。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"scientist","pos":"n.","phonetic":"[ˈsaɪəntɪst]","meaning":"科學家","definition":"a person who studies or works in science","collocations":["become a scientist","famous scientist"],"example":"The scientist discovered a new element.","exampleZh":"這位科學家發現了一種新元素。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"scope","pos":"n.","phonetic":"[skop]","meaning":"範圍","definition":"the range covered by a subject or activity","collocations":["beyond the scope","wide scope"],"example":"This topic is beyond the scope of our discussion.","exampleZh":"這個議題超出我們討論的範圍。","synonyms":["range"],"level":5,"theme":"日常與一般"},{"word":"screen","pos":"n.","phonetic":"[skrin]","meaning":"螢幕","definition":"the flat surface of a display device","collocations":["computer screen","on screen"],"example":"Don't stare at the screen too long.","exampleZh":"不要盯著螢幕太久。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"script","pos":"n.","phonetic":"[skrɪpt]","meaning":"劇本；腳本","definition":"the written text of a play, film, or speech","collocations":["film script","follow the script"],"example":"The actors memorized the entire script.","exampleZh":"演員們把整個劇本都背下來了。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"sculpture","pos":"n.","phonetic":"[ˈskʌlptʃɚ]","meaning":"雕塑","definition":"a piece of art made by carving or shaping material","collocations":["stone sculpture","modern sculpture"],"example":"The museum displays ancient sculptures.","exampleZh":"這座博物館展示古代雕塑作品。","synonyms":["statue"],"level":5,"theme":"媒體與活動"},{"word":"seal","pos":"n. / v.","phonetic":"[sil]","meaning":"海豹；密封","definition":"a marine mammal, or to close something tightly","collocations":["seal a letter","seal an envelope"],"example":"The seal swam gracefully in the water.","exampleZh":"海豹優雅地在水中游動。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"search","pos":"v. / n.","phonetic":"[sɝtʃ]","meaning":"搜尋","definition":"to look for something carefully","collocations":["search for","search engine"],"example":"Police searched the area for clues.","exampleZh":"警方在該地區搜尋線索。","synonyms":["look for"],"level":2,"theme":"日常與一般"},{"word":"season","pos":"n.","phonetic":"[ˈsizən]","meaning":"季節","definition":"one of the four periods of the year","collocations":["rainy season","in season"],"example":"Summer is my favorite season.","exampleZh":"夏天是我最喜歡的季節。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"seasonal","pos":"adj.","phonetic":"[ˈsiznl]","meaning":"季節性的；當季的","definition":"happening or available only at certain times of the year","collocations":["seasonal menu","seasonal workers","seasonal demand"],"example":"The farm hires seasonal workers during the harvest.","exampleZh":"農場在收成期間僱用季節性工人。","synonyms":[],"level":4,"theme":"餐飲與住宿"},{"word":"seat","pos":"n.","phonetic":"[sit]","meaning":"座位","definition":"a place where one sits","collocations":["take a seat","window seat"],"example":"Please take a seat and wait.","exampleZh":"請坐下等候。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"seating","pos":"n.","phonetic":"[ˈsitɪŋ]","meaning":"座位（安排）","definition":"the seats available in a place, or how they are arranged","collocations":["seating capacity","seating arrangement","limited seating"],"example":"Seating is limited, so please arrive at least fifteen minutes early.","exampleZh":"座位有限，請至少提前十五分鐘到場。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"secondary","pos":"adj.","phonetic":"[ˈsɛkənˌdɛrɪ]","meaning":"次要的；中等的","definition":"less important than something else, or coming after primary","collocations":["secondary market","secondary concern","secondary school"],"example":"Cost is a secondary concern; reliability matters most.","exampleZh":"成本是其次，可靠性才最重要。","synonyms":["minor"],"level":4,"theme":"日常與一般"},{"word":"secondhand","pos":"adj./adv.","phonetic":"[ˈsɛkəndˈhænd]","meaning":"二手的；間接的","definition":"previously owned by someone else","collocations":["secondhand furniture","secondhand bookstore","buy secondhand"],"example":"The startup furnished its office with quality secondhand furniture.","exampleZh":"這家新創公司用品質不錯的二手家具佈置辦公室。","synonyms":["used","pre-owned"],"level":4,"theme":"購物與消費"},{"word":"secretary","pos":"n.","phonetic":"[ˈsɛkrəˌtɛri]","meaning":"秘書","definition":"a person who assists with office and administrative work","collocations":["hire a secretary","personal secretary"],"example":"The secretary scheduled all his meetings.","exampleZh":"秘書安排了他所有的會議。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"section","pos":"n.","phonetic":"[ˈsɛkʃən]","meaning":"部分；區段","definition":"a distinct part of something","collocations":["a section of","sports section"],"example":"Please read the first section of the report.","exampleZh":"請閱讀報告的第一部分。","synonyms":["part"],"level":3,"theme":"日常與一般"},{"word":"sector","pos":"n.","phonetic":"[ˈsɛktɚ]","meaning":"產業；部門；區域","definition":"a part of an economy or society","collocations":["private sector","public sector","technology sector"],"example":"Employment in the service sector grew steadily this year.","exampleZh":"服務業的就業人數今年穩定成長。","synonyms":["industry","field"],"level":5,"theme":"企業經營"},{"word":"secure","pos":"adj. / v.","phonetic":"[sɪˈkjʊr]","meaning":"安全的；確保","definition":"free from danger, or to obtain firmly","collocations":["secure a job","feel secure"],"example":"He worked hard to secure a stable job.","exampleZh":"他努力工作以確保一份穩定的工作。","synonyms":["safe"],"level":4,"theme":"日常與一般"},{"word":"securely","pos":"adv.","phonetic":"[sɪˈkjʊrlɪ]","meaning":"安全地；牢固地","definition":"in a way that is safe or firmly fixed","collocations":["securely fastened","securely stored","log in securely"],"example":"All customer data is securely stored on encrypted servers.","exampleZh":"所有顧客資料都安全地儲存在加密伺服器上。","synonyms":["safely"],"level":4,"theme":"科技與通訊"},{"word":"security","pos":"n.","phonetic":"[sɪˈkjʊrəti]","meaning":"安全；保全","definition":"protection from danger or threat","collocations":["national security","security guard"],"example":"The airport has tight security.","exampleZh":"機場的安檢非常嚴密。","synonyms":["safety"],"level":3,"theme":"日常與一般"},{"word":"seek","pos":"v.","phonetic":"[sik]","meaning":"尋求","definition":"to try to find or obtain something","collocations":["seek help","seek advice"],"example":"He sought help from his teacher.","exampleZh":"他向老師尋求協助。","synonyms":["search for"],"level":4,"theme":"日常與一般"},{"word":"seem","pos":"v.","phonetic":"[sim]","meaning":"似乎；看起來","definition":"to appear to be something","collocations":["seem to be","it seems that","seem likely"],"example":"The shipping delays seem to be caused by port congestion.","exampleZh":"出貨延誤似乎是港口壅塞所造成。","synonyms":["appear"],"level":1,"theme":"日常與一般"},{"word":"segment","pos":"n./v.","phonetic":"[ˈsɛgmənt]","meaning":"區隔；部分；市場區塊","definition":"one part of something, especially a market or group","collocations":["market segment","customer segment","segment the market"],"example":"The budget line targets the price-sensitive customer segment.","exampleZh":"平價產品線鎖定對價格敏感的客群。","synonyms":["section","portion"],"level":5,"theme":"行銷與銷售"},{"word":"seldom","pos":"adv.","phonetic":"[ˈsɛldəm]","meaning":"很少；不常","definition":"not often","collocations":["seldom used","seldom seen"],"example":"The manager seldom leaves the office before seven.","exampleZh":"經理很少在七點前離開辦公室。","synonyms":["rarely"],"level":4,"theme":"日常與一般"},{"word":"select","pos":"v. / adj.","phonetic":"[sɪˈlɛkt]","meaning":"挑選；精選的","definition":"to choose carefully from a group","collocations":["select a color","select group"],"example":"Please select your favorite dish.","exampleZh":"請選擇你最喜歡的菜。","synonyms":["choose"],"level":3,"theme":"日常與一般"},{"word":"selection","pos":"n.","phonetic":"[səˈlɛkʃən]","meaning":"選擇；精選品；入選","definition":"the act of choosing, or a range of things to choose from","collocations":["wide selection","selection process","selection committee"],"example":"The store carries a wide selection of office supplies.","exampleZh":"這家店販售種類豐富的辦公用品。","synonyms":["choice","assortment"],"level":3,"theme":"購物與消費"},{"word":"self-service","pos":"adj./n.","phonetic":"[ˈsɛlfˈsɝvɪs]","meaning":"自助式的；自助服務","definition":"a system where customers serve themselves","collocations":["self-service checkout","self-service kiosk","self-service station"],"example":"The cafeteria switched to a self-service checkout system.","exampleZh":"員工餐廳改採自助結帳系統。","synonyms":[],"level":4,"theme":"購物與消費"},{"word":"sell","pos":"v.","phonetic":"[sɛl]","meaning":"賣","definition":"to exchange goods or services for money","collocations":["sell goods","sell out"],"example":"The shop sells fresh vegetables.","exampleZh":"這家店賣新鮮蔬菜。","synonyms":[],"level":1,"theme":"財務與會計"},{"word":"seller","pos":"n.","phonetic":"[ˈsɛlɚ]","meaning":"賣家；銷售者；暢銷品","definition":"a person or company that sells something","collocations":["best seller","top seller","online seller"],"example":"The seller offers free returns within fourteen days.","exampleZh":"賣家提供十四天內免費退貨。","synonyms":["vendor"],"level":2,"theme":"購物與消費"},{"word":"semester","pos":"n.","phonetic":"[sɪˈmɛstɚ]","meaning":"學期","definition":"half of a school or university year","collocations":["fall semester","this semester"],"example":"She studied hard this semester.","exampleZh":"她這學期讀書很認真。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"seminar","pos":"n.","phonetic":"[ˈsɛməˌnɑr]","meaning":"研討會；講習會","definition":"a meeting for training or discussing a subject","collocations":["attend a seminar","training seminar","online seminar"],"example":"The finance seminar covers budgeting and tax planning.","exampleZh":"這場財務研討會涵蓋預算編列與稅務規劃。","synonyms":["workshop"],"level":4,"theme":"會議與簡報"},{"word":"send","pos":"v.","phonetic":"[sɛnd]","meaning":"寄送；發送；派遣","definition":"to cause something to go to another place","collocations":["send an email","send a package","send a representative"],"example":"Please send the signed contract back by express mail.","exampleZh":"請以快遞寄回簽署好的合約。","synonyms":["dispatch","mail"],"level":1,"theme":"辦公室與行政"},{"word":"senior","pos":"adj. / n.","phonetic":"[ˈsinjɚ]","meaning":"資深的；高年級生","definition":"older or higher in rank, or a final-year student","collocations":["senior citizen","senior year"],"example":"He is a senior at the university.","exampleZh":"他是大學的大四生。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"sense","pos":"n. / v.","phonetic":"[sɛns]","meaning":"感覺；意義","definition":"a feeling or the ability to perceive something","collocations":["make sense","sense of humor"],"example":"It doesn't make sense to me.","exampleZh":"這對我來說沒有道理。","synonyms":["feeling"],"level":2,"theme":"日常與一般"},{"word":"sensible","pos":"adj.","phonetic":"[ˈsɛnsəbəl]","meaning":"明智的","definition":"showing good judgment or reasoning","collocations":["sensible decision","sensible advice"],"example":"It was a sensible decision to save money.","exampleZh":"存錢是個明智的決定。","synonyms":["reasonable"],"level":4,"theme":"日常與一般"},{"word":"sensitive","pos":"adj.","phonetic":"[ˈsɛnsətɪv]","meaning":"敏感的","definition":"easily affected, hurt, or offended","collocations":["sensitive skin","sensitive topic"],"example":"She is sensitive to criticism.","exampleZh":"她對批評很敏感。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"sensor","pos":"n.","phonetic":"[ˈsɛnsɚ]","meaning":"感應器；感測器","definition":"a device that detects light, heat, movement, or other signals","collocations":["motion sensor","temperature sensor","sensor technology"],"example":"Motion sensors automatically turn off lights in empty rooms.","exampleZh":"動作感應器會自動關閉無人房間的燈。","synonyms":["detector"],"level":5,"theme":"科技與通訊"},{"word":"separate","pos":"v. / adj.","phonetic":"[ˈsɛpəˌret]","meaning":"分開的；使分開","definition":"to divide or set apart from each other","collocations":["separate rooms","separate from"],"example":"Please separate the trash from the recycling.","exampleZh":"請把垃圾和回收物分開。","synonyms":["divide"],"level":3,"theme":"日常與一般"},{"word":"sequence","pos":"n./v.","phonetic":"[ˈsikwəns]","meaning":"順序；序列；連續","definition":"the order in which things happen or should be arranged","collocations":["in sequence","a sequence of events","numerical sequence"],"example":"Complete the setup steps in the exact sequence shown.","exampleZh":"請完全按照顯示的順序完成設定步驟。","synonyms":["order","series"],"level":5,"theme":"日常與一般"},{"word":"series","pos":"n.","phonetic":"[ˈsɪriz]","meaning":"系列","definition":"a number of related things or events","collocations":["TV series","a series of events"],"example":"She is watching a new TV series.","exampleZh":"她正在看一部新的電視影集。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"serious","pos":"adj.","phonetic":"[ˈsɪriəs]","meaning":"嚴重的；認真的","definition":"important and needing careful attention","collocations":["serious problem","be serious about"],"example":"This is a serious matter that needs attention.","exampleZh":"這是一件需要關注的嚴重事情。","synonyms":["grave"],"level":2,"theme":"日常與一般"},{"word":"seriously","pos":"adv.","phonetic":"[ˈsɪrɪəslɪ]","meaning":"認真地；嚴重地","definition":"in a sincere way, or to a great degree","collocations":["take seriously","seriously injured","seriously consider"],"example":"We take every customer complaint seriously.","exampleZh":"我們認真看待每一則顧客投訴。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"serve","pos":"v.","phonetic":"[sɝv]","meaning":"服務；供應","definition":"to provide help, food, or a service","collocations":["serve customers","serve food"],"example":"The waiter served us quickly.","exampleZh":"服務生很快地為我們服務。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"server","pos":"n.","phonetic":"[ˈsɝvɚ]","meaning":"伺服器；服務生","definition":"a computer that manages network data, or a person who serves food","collocations":["web server","server maintenance","restaurant server"],"example":"The email system will be down during server maintenance tonight.","exampleZh":"今晚伺服器維護期間，電子郵件系統將暫停服務。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"service","pos":"n.","phonetic":"[ˈsɝvɪs]","meaning":"服務","definition":"the act of helping or providing for someone","collocations":["customer service","public service"],"example":"The hotel offers excellent service.","exampleZh":"這間飯店提供優質的服務。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"serving","pos":"n.","phonetic":"[ˈsɝvɪŋ]","meaning":"一份（食物）；供應","definition":"an amount of food for one person","collocations":["serving size","per serving","a serving of vegetables"],"example":"Each serving contains less than three hundred calories.","exampleZh":"每份餐點的熱量低於三百大卡。","synonyms":["portion","helping"],"level":4,"theme":"餐飲與住宿"},{"word":"session","pos":"n.","phonetic":"[ˈsɛʃən]","meaning":"會議；時段","definition":"a period of time devoted to an activity","collocations":["training session","in session"],"example":"We had a long training session today.","exampleZh":"我們今天有一場很長的訓練課程。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"set","pos":"v./n./adj.","phonetic":"[sɛt]","meaning":"設定；一套；固定的","definition":"to put something in position or decide it, or a group of things","collocations":["set a date","set up","a set of rules"],"example":"Let's set a date for the next review meeting.","exampleZh":"我們來敲定下次檢討會議的日期吧。","synonyms":["establish","fix"],"level":1,"theme":"日常與一般"},{"word":"setting","pos":"n.","phonetic":"[ˈsɛtɪŋ]","meaning":"設定；環境；場景","definition":"the position of a control, or the place where something happens","collocations":["default setting","change the settings","work setting"],"example":"You can change the language in the app's settings menu.","exampleZh":"你可以在應用程式的設定選單中變更語言。","synonyms":["environment"],"level":3,"theme":"科技與通訊"},{"word":"settle","pos":"v.","phonetic":"[ˈsɛtḷ]","meaning":"定居；解決","definition":"to resolve a matter or move somewhere permanently","collocations":["settle down","settle a dispute"],"example":"They settled in a small town after retiring.","exampleZh":"他們退休後在一個小鎮定居。","synonyms":["resolve"],"level":3,"theme":"日常與一般"},{"word":"settlement","pos":"n.","phonetic":"[ˈsɛtḷmənt]","meaning":"解決；聚落","definition":"an official agreement, or a place where people establish a community","collocations":["reach a settlement","early settlement"],"example":"The two sides reached a settlement.","exampleZh":"雙方達成了協議。","synonyms":[],"level":5,"theme":"日常與一般"},{"word":"setup","pos":"n.","phonetic":"[ˈsɛtˌʌp]","meaning":"安裝；設置；架構","definition":"the way something is arranged, or the process of installing it","collocations":["initial setup","setup fee","office setup"],"example":"The initial setup of the software takes about ten minutes.","exampleZh":"軟體的初始安裝約需十分鐘。","synonyms":["installation","arrangement"],"level":4,"theme":"科技與通訊"},{"word":"several","pos":"adj.","phonetic":"[ˈsɛvərəl]","meaning":"幾個的","definition":"more than two but not very many","collocations":["several times","several people"],"example":"I have called her several times.","exampleZh":"我打過她好幾次電話。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"severe","pos":"adj.","phonetic":"[sɪˈvɪr]","meaning":"嚴重的；嚴厲的","definition":"very bad, serious, or strict","collocations":["severe weather","severe punishment"],"example":"The area suffered severe flooding.","exampleZh":"這個地區遭受嚴重的水災。","synonyms":["harsh"],"level":4,"theme":"日常與一般"},{"word":"severely","pos":"adv.","phonetic":"[səˈvɪrlɪ]","meaning":"嚴重地；嚴厲地","definition":"very badly or strictly","collocations":["severely damaged","severely limited","severely affected"],"example":"The storm severely damaged the warehouse roof.","exampleZh":"暴風雨嚴重損壞了倉庫的屋頂。","synonyms":["seriously","badly"],"level":4,"theme":"日常與一般"},{"word":"shade","pos":"n. / v.","phonetic":"[ʃed]","meaning":"陰涼處；遮光物；使變暗","definition":"an area sheltered from direct sunlight, or to block light from something","collocations":["sit in the shade","a shade of blue","shade one's eyes"],"example":"We rested in the shade of a big tree.","exampleZh":"我們在一棵大樹的陰涼處休息。","synonyms":["shadow"],"level":2,"theme":"日常與一般"},{"word":"shape","pos":"n. / v.","phonetic":"[ʃep]","meaning":"形狀；塑造","definition":"the form or outline of something","collocations":["in good shape","take shape"],"example":"The cloud was in the shape of a heart.","exampleZh":"那朵雲的形狀像顆心。","synonyms":["form"],"level":2,"theme":"日常與一般"},{"word":"share","pos":"v. / n.","phonetic":"[ʃɛr]","meaning":"分享","definition":"to have, use, or divide something together with others","collocations":["share food","share ideas"],"example":"We shared the pizza equally.","exampleZh":"我們平均分享了披薩。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"shareholder","pos":"n.","phonetic":"[ˈʃɛrˌholdɚ]","meaning":"股東","definition":"a person who owns shares in a company","collocations":["shareholder meeting","major shareholder","shareholder value"],"example":"The annual shareholder meeting will be held in the main auditorium.","exampleZh":"年度股東大會將在大禮堂舉行。","synonyms":["stockholder"],"level":5,"theme":"財務與會計"},{"word":"sharp","pos":"adj.","phonetic":"[ʃɑrp]","meaning":"銳利的；敏銳的","definition":"having a fine cutting edge, or quick to notice things","collocations":["sharp knife","sharp mind"],"example":"Be careful, the knife is very sharp.","exampleZh":"小心，這把刀非常鋒利。","synonyms":["keen"],"level":2,"theme":"日常與一般"},{"word":"sharply","pos":"adv.","phonetic":"[ˈʃɑrplɪ]","meaning":"急遽地；尖銳地","definition":"suddenly and by a large amount","collocations":["rise sharply","fall sharply","sharply criticized"],"example":"Raw material costs rose sharply in the second quarter.","exampleZh":"原物料成本在第二季急遽上漲。","synonyms":["steeply","dramatically"],"level":4,"theme":"財務與會計"},{"word":"sheet","pos":"n.","phonetic":"[ʃit]","meaning":"床單；一張(紙)；薄片","definition":"a large piece of cloth used on a bed, or a flat piece of paper","collocations":["a sheet of paper","bed sheet","a sheet of ice"],"example":"She changed the sheets on the bed this morning.","exampleZh":"她今天早上換了床單。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"shelf","pos":"n.","phonetic":"[ʃɛlf]","meaning":"架子","definition":"a flat surface for storing or displaying objects","collocations":["bookshelf","top shelf"],"example":"She put the books on the shelf.","exampleZh":"她把書放在架子上。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"shelter","pos":"n. / v.","phonetic":"[ˈʃɛltɚ]","meaning":"庇護所；避難處；躲避","definition":"a place giving protection from weather or danger","collocations":["take shelter","a homeless shelter","shelter from the rain"],"example":"They took shelter under a bridge during the storm.","exampleZh":"暴風雨期間他們在橋下躲避。","synonyms":["refuge"],"level":3,"theme":"房產與設施"},{"word":"shift","pos":"n. / v.","phonetic":"[ʃɪft]","meaning":"轉變；輪班","definition":"a change in position or a period of work","collocations":["night shift","shift in attitude"],"example":"She works the night shift at the hospital.","exampleZh":"她在醫院上夜班。","synonyms":["change"],"level":3,"theme":"人事與職涯"},{"word":"ship","pos":"n. / v.","phonetic":"[ʃɪp]","meaning":"船；運送","definition":"a large vessel that travels on water","collocations":["board a ship","ship goods"],"example":"The ship sailed to Japan.","exampleZh":"這艘船航向日本。","synonyms":["vessel"],"level":1,"theme":"旅遊與交通"},{"word":"shipment","pos":"n.","phonetic":"[ˈʃɪpmənt]","meaning":"出貨；貨運；一批貨物","definition":"goods sent together, or the act of sending them","collocations":["track a shipment","shipment date","delayed shipment"],"example":"The shipment of office chairs is expected on Tuesday.","exampleZh":"這批辦公椅預計週二到貨。","synonyms":["consignment","delivery"],"level":4,"theme":"生產與物流"},{"word":"shipping","pos":"n.","phonetic":"[ˈʃɪpɪŋ]","meaning":"運送；運費；航運","definition":"the sending of goods, or the cost of sending them","collocations":["free shipping","shipping costs","shipping address"],"example":"Orders over one hundred dollars qualify for free shipping.","exampleZh":"訂單滿一百美元即可免運費。","synonyms":["delivery","freight"],"level":3,"theme":"生產與物流"},{"word":"shop","pos":"n./v.","phonetic":"[ʃɑp]","meaning":"商店；購物","definition":"a place where goods are sold, or to buy things","collocations":["gift shop","shop online","coffee shop"],"example":"More customers now shop online than in the physical store.","exampleZh":"現在線上購物的顧客比實體店還多。","synonyms":["store"],"level":1,"theme":"購物與消費"},{"word":"shopper","pos":"n.","phonetic":"[ˈʃɑpɚ]","meaning":"購物者；顧客","definition":"a person who is buying things in shops","collocations":["holiday shoppers","online shoppers","attract shoppers"],"example":"Holiday shoppers crowded the mall on the weekend before Christmas.","exampleZh":"耶誕節前的週末，購物人潮擠滿了購物中心。","synonyms":["customer","buyer"],"level":3,"theme":"購物與消費"},{"word":"shopping","pos":"n.","phonetic":"[ˈʃɑpɪŋ]","meaning":"購物","definition":"the activity of buying things from shops","collocations":["shopping mall","shopping cart","go shopping"],"example":"The new shopping center opens to the public next month.","exampleZh":"新的購物中心下個月對外開放。","synonyms":[],"level":1,"theme":"購物與消費"},{"word":"short","pos":"adj.","phonetic":"[ʃɔrt]","meaning":"短的；矮的","definition":"not long in length, time, or height","collocations":["short hair","short trip"],"example":"She has short black hair.","exampleZh":"她有一頭黑色短髮。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"short-term","pos":"adj.","phonetic":"[ˈʃɔrtˈtɝm]","meaning":"短期的","definition":"lasting a short time","collocations":["short-term contract","short-term goal","short-term rental"],"example":"The agency offers short-term contracts for seasonal work.","exampleZh":"該仲介提供季節性工作的短期合約。","synonyms":["temporary"],"level":4,"theme":"人事與職涯"},{"word":"shortage","pos":"n.","phonetic":"[ˈʃɔrtɪdʒ]","meaning":"短缺","definition":"a lack or insufficient amount of something needed","collocations":["water shortage","food shortage"],"example":"The drought caused a water shortage.","exampleZh":"乾旱造成了缺水問題。","synonyms":["lack"],"level":4,"theme":"日常與一般"},{"word":"shorten","pos":"v.","phonetic":"[ˈʃɔrtn]","meaning":"縮短","definition":"to make something shorter","collocations":["shorten the process","shorten the wait","shorten a meeting"],"example":"The new express lane shortens checkout times considerably.","exampleZh":"新的快速結帳通道大幅縮短了結帳時間。","synonyms":["reduce","cut"],"level":4,"theme":"日常與一般"},{"word":"shortly","pos":"adv.","phonetic":"[ˈʃɔrtlɪ]","meaning":"不久；很快","definition":"soon or a short time after","collocations":["shortly after","shortly before","arriving shortly"],"example":"A representative will be with you shortly.","exampleZh":"服務人員很快就會為您服務。","synonyms":["soon"],"level":3,"theme":"日常與一般"},{"word":"shovel","pos":"n. / v.","phonetic":"[ˈʃʌvəl]","meaning":"鏟子；鏟(雪、土)","definition":"a tool used for digging or moving material like snow or dirt","collocations":["a snow shovel","shovel snow","dig with a shovel"],"example":"They used a shovel to clear the snow from the driveway.","exampleZh":"他們用鏟子清除車道上的積雪。","synonyms":[],"level":3,"theme":"房產與設施"},{"word":"show","pos":"v. / n.","phonetic":"[ʃo]","meaning":"展示；節目","definition":"to display something, or a performance or program","collocations":["TV show","show up"],"example":"She showed me her new phone.","exampleZh":"她給我看她的新手機。","synonyms":["display"],"level":1,"theme":"媒體與活動"},{"word":"showcase","pos":"v./n.","phonetic":"[ˈʃoˌkes]","meaning":"展示；陳列櫃","definition":"to display something at its best, or a glass display case","collocations":["showcase products","showcase talent","product showcase"],"example":"The expo will showcase the latest green energy technologies.","exampleZh":"這場博覽會將展示最新的綠能科技。","synonyms":["display","exhibit"],"level":5,"theme":"行銷與銷售"},{"word":"showroom","pos":"n.","phonetic":"[ˈʃoˌrum]","meaning":"展示中心；展售間","definition":"a large room where products are displayed for sale","collocations":["car showroom","furniture showroom","visit the showroom"],"example":"Visit our showroom to see the full furniture collection.","exampleZh":"歡迎蒞臨展示中心參觀完整的家具系列。","synonyms":[],"level":4,"theme":"購物與消費"},{"word":"shrink","pos":"v.","phonetic":"[ʃrɪŋk]","meaning":"縮小","definition":"to become or make smaller","collocations":["shrink in size","shrink the budget"],"example":"My sweater shrank after washing.","exampleZh":"我的毛衣洗過後縮水了。","synonyms":["contract"],"level":4,"theme":"日常與一般"},{"word":"shrub","pos":"n.","phonetic":"[ʃrʌb]","meaning":"灌木","definition":"a small bush with several woody stems","collocations":["plant shrubs","trim the shrubs","flowering shrub"],"example":"The landscaping crew trimmed the shrubs along the entrance.","exampleZh":"園藝人員修剪了入口沿途的灌木。","synonyms":["bush"],"level":4,"theme":"房產與設施"},{"word":"shuttle","pos":"n. / v.","phonetic":"[ˈʃʌtl̩]","meaning":"接駁車；穿梭；太空梭","definition":"a vehicle that travels regularly between two places","collocations":["a shuttle bus","space shuttle","shuttle passengers"],"example":"A free shuttle bus runs between the airport and the hotel.","exampleZh":"機場與飯店之間有免費的接駁車。","synonyms":[],"level":4,"theme":"旅遊與交通"},{"word":"sick","pos":"adj.","phonetic":"[sɪk]","meaning":"生病的","definition":"unwell or affected by illness","collocations":["feel sick","sick leave"],"example":"He stayed home because he felt sick.","exampleZh":"他因為身體不舒服而待在家裡。","synonyms":["ill"],"level":1,"theme":"醫療與保險"},{"word":"side","pos":"n.","phonetic":"[saɪd]","meaning":"邊；一側","definition":"a part of something away from its center","collocations":["side by side","take sides"],"example":"They walked side by side.","exampleZh":"他們並肩走著。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"sidewalk","pos":"n.","phonetic":"[ˈsaɪdˌwɔk]","meaning":"人行道","definition":"a paved path for people to walk beside a road","collocations":["along the sidewalk","sidewalk cafe","repair the sidewalk"],"example":"The cafe added sidewalk seating for the summer months.","exampleZh":"這家咖啡館在夏季增設了人行道座位。","synonyms":["pavement"],"level":3,"theme":"旅遊與交通"},{"word":"sight","pos":"n.","phonetic":"[saɪt]","meaning":"視力；景象；視覺","definition":"the ability to see, or something that is seen","collocations":["lose sight of","a beautiful sight","at first sight"],"example":"The mountain view was a breathtaking sight.","exampleZh":"這片山景美得令人屏息。","synonyms":["vision"],"level":2,"theme":"醫療與保險"},{"word":"sightseeing","pos":"n.","phonetic":"[ˈsaɪtˌsiɪŋ]","meaning":"觀光；遊覽","definition":"the activity of visiting interesting places as a tourist","collocations":["go sightseeing","a sightseeing tour","sightseeing spots"],"example":"We spent the whole day sightseeing in the old city.","exampleZh":"我們花了一整天在舊城區觀光。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"sign","pos":"n. / v.","phonetic":"[saɪn]","meaning":"標誌；簽名","definition":"a mark or gesture that conveys meaning, or to write one's name","collocations":["sign a contract","road sign"],"example":"Please sign your name here.","exampleZh":"請在這裡簽名。","synonyms":["symbol"],"level":2,"theme":"溝通與語言"},{"word":"signage","pos":"n.","phonetic":"[ˈsaɪnɪdʒ]","meaning":"標示；招牌（總稱）","definition":"signs used to give information or directions","collocations":["clear signage","directional signage","store signage"],"example":"New signage will help visitors find the conference rooms.","exampleZh":"新的指標將幫助訪客找到會議室。","synonyms":[],"level":6,"theme":"房產與設施"},{"word":"signal","pos":"n. / v.","phonetic":"[ˈsɪgnəl]","meaning":"信號","definition":"a sign or gesture used to convey information","collocations":["traffic signal","send a signal"],"example":"The traffic signal turned red.","exampleZh":"交通號誌變成紅燈。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"signature","pos":"n.","phonetic":"[ˈsɪgnətʃɚ]","meaning":"簽名","definition":"a person's name written in their own handwriting","collocations":["a valid signature","put your signature","a signature dish"],"example":"The contract requires your signature at the end.","exampleZh":"這份合約最後需要你的簽名。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"significant","pos":"adj.","phonetic":"[sɪgˈnɪfɪkənt]","meaning":"重大的；顯著的","definition":"important enough to be noticed or to have an effect","collocations":["significant change","significant impact"],"example":"The discovery had a significant impact on science.","exampleZh":"這項發現對科學有重大的影響。","synonyms":["important"],"level":5,"theme":"日常與一般"},{"word":"significantly","pos":"adv.","phonetic":"[sɪgˈnɪfəkəntlɪ]","meaning":"顯著地；大幅地","definition":"by a large or important amount","collocations":["significantly higher","significantly reduced","improve significantly"],"example":"Delivery errors dropped significantly after the new system launched.","exampleZh":"新系統上線後，配送錯誤大幅減少。","synonyms":["considerably","substantially"],"level":4,"theme":"日常與一般"},{"word":"silverware","pos":"n.","phonetic":"[ˈsɪlvɚˌwɛr]","meaning":"（銀製）餐具","definition":"knives, forks, and spoons used for eating","collocations":["polish the silverware","set out silverware"],"example":"Please set out fresh silverware before the dinner service.","exampleZh":"晚餐服務開始前，請擺放乾淨的餐具。","synonyms":["cutlery"],"level":5,"theme":"餐飲與住宿"},{"word":"similar","pos":"adj.","phonetic":"[ˈsɪmələ]","meaning":"相似的；類似的","definition":"like something else but not exactly the same","collocations":["similar to","in a similar way","similar interests"],"example":"Her opinion is similar to mine on this issue.","exampleZh":"她對這個問題的看法和我的很相似。","synonyms":["alike"],"level":2,"theme":"日常與一般"},{"word":"similarly","pos":"adv.","phonetic":"[ˈsɪməlɚlɪ]","meaning":"同樣地；類似地","definition":"in a similar way","collocations":["similarly priced","similarly designed"],"example":"Similarly, the Osaka branch reported record sales this quarter.","exampleZh":"同樣地，大阪分公司本季也創下銷售紀錄。","synonyms":["likewise"],"level":4,"theme":"溝通與語言"},{"word":"simple","pos":"adj.","phonetic":"[ˈsɪmpl̩]","meaning":"簡單的；樸素的","definition":"easy to understand or do; not complicated","collocations":["a simple task","keep it simple","simple life"],"example":"The instructions are very simple to follow.","exampleZh":"這些說明非常簡單易懂。","synonyms":["easy"],"level":1,"theme":"日常與一般"},{"word":"simplify","pos":"v.","phonetic":"[ˈsɪmpləˌfaɪ]","meaning":"簡化","definition":"to make something easier to understand or do","collocations":["simplify a process","simplify the rules","simplify language"],"example":"The teacher simplified the lesson for younger students.","exampleZh":"老師為年幼的學生簡化了課程內容。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"simply","pos":"adv.","phonetic":"[ˈsɪmplɪ]","meaning":"只需；簡單地；僅僅","definition":"just, or in an easy way","collocations":["simply click","simply put","quite simply"],"example":"To renew your membership, simply click the link in the email.","exampleZh":"要續辦會員，只需點擊郵件中的連結。","synonyms":["just","merely"],"level":2,"theme":"日常與一般"},{"word":"simultaneously","pos":"adv.","phonetic":"[ˌsaɪmlˈtenɪəslɪ]","meaning":"同時地","definition":"at exactly the same time","collocations":["run simultaneously","launch simultaneously"],"example":"The product will launch simultaneously in ten countries.","exampleZh":"這項產品將在十個國家同步上市。","synonyms":["concurrently"],"level":6,"theme":"日常與一般"},{"word":"sincere","pos":"adj.","phonetic":"[sɪnˈsɪr]","meaning":"真誠的；誠懇的","definition":"honest and truthful in feelings or beliefs","collocations":["sincere apology","sincere thanks","a sincere person"],"example":"He gave a sincere apology for his mistake.","exampleZh":"他為自己的錯誤真誠地道歉。","synonyms":["honest","genuine"],"level":4,"theme":"日常與一般"},{"word":"sincerely","pos":"adv.","phonetic":"[sɪnˈsɪrlɪ]","meaning":"由衷地；（信末）敬上","definition":"in a true and honest way, or used to end a formal letter","collocations":["sincerely yours","sincerely apologize"],"example":"We sincerely apologize for the error in your billing statement.","exampleZh":"對於帳單上的錯誤，我們由衷致歉。","synonyms":["genuinely"],"level":3,"theme":"溝通與語言"},{"word":"single","pos":"adj. / n.","phonetic":"[ˈsɪŋgl̩]","meaning":"單一的；單身的；單曲","definition":"only one; not married","collocations":["a single room","stay single","every single day"],"example":"He has remained single for several years.","exampleZh":"他已經單身好幾年了。","synonyms":["sole"],"level":2,"theme":"日常與一般"},{"word":"sink","pos":"v. / n.","phonetic":"[sɪŋk]","meaning":"下沉；沉沒；水槽","definition":"to go down below the surface of water; a basin for washing","collocations":["sink to the bottom","kitchen sink","a sinking feeling"],"example":"The ship began to sink after hitting the rocks.","exampleZh":"這艘船撞上礁石後開始下沉。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"sit","pos":"v.","phonetic":"[sɪt]","meaning":"坐；位於","definition":"to be in a position where the body is supported on the buttocks","collocations":["sit down","sit still","sit on the fence"],"example":"Please sit down and make yourself comfortable.","exampleZh":"請坐下，不要拘束。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"site","pos":"n.","phonetic":"[saɪt]","meaning":"地點；場所；網站","definition":"a place where something is located or happens","collocations":["a construction site","a website","the site of the battle"],"example":"The company built a new factory on this site.","exampleZh":"這家公司在這個地點蓋了一座新工廠。","synonyms":["location"],"level":3,"theme":"日常與一般"},{"word":"situation","pos":"n.","phonetic":"[ˌsɪtʃuˈeʃən]","meaning":"情況；處境","definition":"the set of circumstances that a person is in at a particular time","collocations":["a difficult situation","handle the situation","the current situation"],"example":"We need to find a solution to this difficult situation.","exampleZh":"我們需要找到解決這個困境的方法。","synonyms":["circumstance"],"level":3,"theme":"日常與一般"},{"word":"size","pos":"n.","phonetic":"[saɪz]","meaning":"尺寸；大小；尺碼","definition":"the measurement or dimensions of something","collocations":["shoe size","the size of","a large size"],"example":"What size shoes do you wear?","exampleZh":"你穿幾號的鞋子？","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"sketch","pos":"n. / v.","phonetic":"[skɛtʃ]","meaning":"素描；草圖；草擬","definition":"a quick, rough drawing, or to draw one","collocations":["sketch a picture","a rough sketch","sketch out a plan"],"example":"The artist sketched the mountains in his notebook.","exampleZh":"畫家在他的筆記本上素描了山景。","synonyms":["draft"],"level":4,"theme":"媒體與活動"},{"word":"skill","pos":"n.","phonetic":"[skɪl]","meaning":"技巧；技能","definition":"the ability to do something well, gained through training or practice","collocations":["a useful skill","develop skills","communication skills"],"example":"Learning a new language requires patience and skill.","exampleZh":"學習一門新語言需要耐心和技巧。","synonyms":["ability"],"level":2,"theme":"人事與職涯"},{"word":"skilled","pos":"adj.","phonetic":"[skɪld]","meaning":"熟練的；有技術的","definition":"having the ability and experience to do something well","collocations":["a skilled worker","highly skilled","skilled labor"],"example":"They need skilled workers to build the new bridge.","exampleZh":"他們需要熟練的工人來建造這座新橋。","synonyms":["expert"],"level":3,"theme":"人事與職涯"},{"word":"slide","pos":"v. / n.","phonetic":"[slaɪd]","meaning":"滑動；滑梯；投影片","definition":"to move smoothly along a surface, or a playground structure","collocations":["slide down","a water slide","a slide show"],"example":"The kids love to slide down the playground slide.","exampleZh":"孩子們喜歡從遊樂場的滑梯上滑下來。","synonyms":[],"level":2,"theme":"媒體與活動"},{"word":"slight","pos":"adj.","phonetic":"[slaɪt]","meaning":"輕微的；些微的","definition":"small in degree or amount","collocations":["a slight problem","a slight increase","not the slightest idea"],"example":"There was only a slight difference between the two designs.","exampleZh":"這兩個設計之間只有些微的差異。","synonyms":["minor"],"level":4,"theme":"日常與一般"},{"word":"slightly","pos":"adv.","phonetic":"[ˈslaɪtli]","meaning":"稍微地；輕微地","definition":"to a small degree","collocations":["slightly different","slightly higher","slightly late"],"example":"The temperature is slightly higher than yesterday.","exampleZh":"今天的氣溫比昨天稍微高一些。","synonyms":["a little"],"level":4,"theme":"日常與一般"},{"word":"slogan","pos":"n.","phonetic":"[ˈslogən]","meaning":"標語；口號","definition":"a short, easily remembered phrase used in advertising or politics","collocations":["an advertising slogan","a political slogan","catchy slogan"],"example":"The company created a catchy slogan for its new product.","exampleZh":"這家公司為新產品創造了一句朗朗上口的標語。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"slot","pos":"n.","phonetic":"[slɑt]","meaning":"時段；投幣口；插槽","definition":"a time in a schedule, or a narrow opening","collocations":["time slot","available slot","book a slot"],"example":"The only available slot for the demo is Friday at two.","exampleZh":"產品展示唯一可預約的時段是週五兩點。","synonyms":["opening"],"level":5,"theme":"辦公室與行政"},{"word":"slow","pos":"adj. / v.","phonetic":"[slo]","meaning":"慢的；緩慢；使變慢","definition":"not fast; taking a long time","collocations":["slow down","a slow learner","slow traffic"],"example":"Please drive slowly on this narrow road.","exampleZh":"在這條狹窄的道路上請慢慢開車。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"small","pos":"adj.","phonetic":"[smɔl]","meaning":"小的；少的","definition":"not large in size or amount","collocations":["a small amount","small talk","a small business"],"example":"They live in a small apartment near the city center.","exampleZh":"他們住在市中心附近一間小公寓。","synonyms":["little"],"level":1,"theme":"日常與一般"},{"word":"smartphone","pos":"n.","phonetic":"[ˈsmɑrtˌfon]","meaning":"智慧型手機","definition":"a mobile phone that works like a small computer","collocations":["smartphone app","smartphone users","on your smartphone"],"example":"Guests can unlock their rooms with a smartphone app.","exampleZh":"房客可以用智慧型手機應用程式開啟房門。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"smooth","pos":"adj./v.","phonetic":"[smuð]","meaning":"順利的；平滑的；使順暢","definition":"happening without problems, or having an even surface","collocations":["smooth transition","smooth surface","go smoothly"],"example":"Careful planning ensured a smooth transition to the new office.","exampleZh":"周全的規劃確保了新辦公室的順利交接。","synonyms":["seamless"],"level":3,"theme":"日常與一般"},{"word":"smoothly","pos":"adv.","phonetic":"[ˈsmuðlɪ]","meaning":"順利地；平穩地","definition":"without problems or interruptions","collocations":["run smoothly","go smoothly","operate smoothly"],"example":"Thanks to the rehearsal, the launch event ran smoothly.","exampleZh":"多虧事前彩排，發表活動進行得非常順利。","synonyms":["seamlessly"],"level":4,"theme":"日常與一般"},{"word":"soar","pos":"v.","phonetic":"[sor]","meaning":"飆升；翱翔","definition":"to rise very quickly to a high level","collocations":["prices soar","sales soared","soar to record highs"],"example":"Ticket sales soared after the celebrity endorsement.","exampleZh":"名人代言後，票券銷售一路飆升。","synonyms":["surge","skyrocket"],"level":5,"theme":"財務與會計"},{"word":"social","pos":"adj.","phonetic":"[ˈsoʃəl]","meaning":"社會的；社交的","definition":"relating to society or to spending time with other people","collocations":["social media","social skills","social life"],"example":"She has a very active social life.","exampleZh":"她有非常活躍的社交生活。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"society","pos":"n.","phonetic":"[səˈsaɪəti]","meaning":"社會；社團","definition":"people living together in an organized community","collocations":["modern society","member of society"],"example":"Technology has changed modern society greatly.","exampleZh":"科技大大改變了現代社會。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"sofa","pos":"n.","phonetic":"[ˈsofə]","meaning":"沙發","definition":"a long soft seat with a back and arms for two or more people","collocations":["sit on the sofa","sofa bed"],"example":"The whole family sat on the sofa watching TV.","exampleZh":"全家人坐在沙發上看電視。","synonyms":["couch"],"level":1,"theme":"房產與設施"},{"word":"software","pos":"n.","phonetic":"[ˈsɔftˌwɛr]","meaning":"軟體","definition":"the programs and instructions used by a computer","collocations":["install software","software update"],"example":"The company develops software for schools.","exampleZh":"這家公司為學校開發軟體。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"soil","pos":"n.","phonetic":"[sɔɪl]","meaning":"土壤","definition":"the top layer of earth in which plants grow","collocations":["fertile soil","soil erosion"],"example":"The farmer checked the soil before planting seeds.","exampleZh":"農夫在播種前檢查了土壤。","synonyms":["earth","dirt"],"level":2,"theme":"日常與一般"},{"word":"solar","pos":"adj.","phonetic":"[ˈsolɚ]","meaning":"太陽的；太陽能的","definition":"relating to the sun or energy obtained from it","collocations":["solar power","solar panel","solar system"],"example":"Many houses now use solar panels for electricity.","exampleZh":"現在很多房子使用太陽能板來發電。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"sole","pos":"adj./n.","phonetic":"[sol]","meaning":"唯一的；獨家的；鞋底","definition":"only or single, or the bottom of a shoe","collocations":["sole distributor","sole purpose","sole owner"],"example":"The firm is the sole distributor of the brand in Taiwan.","exampleZh":"這家公司是該品牌在台灣的獨家代理商。","synonyms":["only","single"],"level":5,"theme":"企業經營"},{"word":"solely","pos":"adv.","phonetic":"[ˈsollɪ]","meaning":"僅僅；完全地","definition":"only and not involving anything else","collocations":["solely responsible","based solely on","rely solely on"],"example":"Hiring decisions are based solely on qualifications and experience.","exampleZh":"錄用決定完全以資格與經驗為依據。","synonyms":["only","exclusively"],"level":5,"theme":"人事與職涯"},{"word":"solicit","pos":"v.","phonetic":"[səˈlɪsɪt]","meaning":"徵求；懇求","definition":"to ask for something such as money, help, or opinions","collocations":["solicit feedback","solicit donations","solicit opinions"],"example":"The committee is soliciting feedback on the proposed policy changes.","exampleZh":"委員會正在徵求對政策修訂草案的意見。","synonyms":["request","seek"],"level":6,"theme":"溝通與語言"},{"word":"solid","pos":"adj. / n.","phonetic":"[ˈsɑlɪd]","meaning":"固體的；堅固的；固體","definition":"hard or firm; not liquid or gas","collocations":["solid ground","solid evidence","turn into a solid"],"example":"Water becomes solid when it freezes.","exampleZh":"水結凍後會變成固體。","synonyms":["firm","sturdy"],"level":2,"theme":"科技與通訊"},{"word":"solution","pos":"n.","phonetic":"[səˈluʃən]","meaning":"解決方案；答案","definition":"a way of solving a problem","collocations":["find a solution","practical solution"],"example":"We need to find a solution to this problem quickly.","exampleZh":"我們需要快點找到這個問題的解決方案。","synonyms":["answer","remedy"],"level":3,"theme":"日常與一般"},{"word":"solve","pos":"v.","phonetic":"[sɑlv]","meaning":"解決；解答","definition":"to find an answer to or a way of dealing with a problem","collocations":["solve a problem","solve a mystery"],"example":"The detective solved the mystery in a week.","exampleZh":"偵探在一週內解開了這個謎團。","synonyms":["resolve"],"level":2,"theme":"日常與一般"},{"word":"somewhat","pos":"adv.","phonetic":"[ˈsʌmˌhwʌt]","meaning":"有點；稍微","definition":"to some extent; rather","collocations":["somewhat surprised","somewhat difficult"],"example":"The test was somewhat harder than I expected.","exampleZh":"這次考試比我預期的稍微難一些。","synonyms":["rather","fairly"],"level":4,"theme":"日常與一般"},{"word":"soon","pos":"adv.","phonetic":"[sun]","meaning":"不久；很快","definition":"in a short time from now","collocations":["as soon as possible","come soon"],"example":"I hope to see you again soon.","exampleZh":"希望能很快再見到你。","synonyms":["shortly"],"level":1,"theme":"日常與一般"},{"word":"sophisticated","pos":"adj.","phonetic":"[səˈfɪstɪˌketɪd]","meaning":"精密的；老練的；世故的","definition":"highly developed and complex, or experienced in worldly matters","collocations":["sophisticated technology","sophisticated taste"],"example":"The new phone uses sophisticated technology.","exampleZh":"這款新手機採用了精密複雜的科技。","synonyms":["advanced","complex"],"level":6,"theme":"科技與通訊"},{"word":"sore","pos":"adj.","phonetic":"[sɔr]","meaning":"疼痛的；痠痛的","definition":"painful, especially from injury or overuse","collocations":["sore throat","sore muscles"],"example":"My legs are sore after the long run.","exampleZh":"長跑之後我的腿很痠痛。","synonyms":["painful","aching"],"level":3,"theme":"醫療與保險"},{"word":"sort","pos":"n. / v.","phonetic":"[sɔrt]","meaning":"種類；分類","definition":"a type or kind of thing; to arrange into groups","collocations":["sort of","sort out","sort by size"],"example":"Please sort these files by date.","exampleZh":"請依日期將這些檔案分類。","synonyms":["type","kind"],"level":2,"theme":"日常與一般"},{"word":"sound","pos":"n. / adj. / v.","phonetic":"[saʊnd]","meaning":"聲音；健全的；聽起來","definition":"something that can be heard; healthy or reasonable","collocations":["loud sound","sound asleep","sound like"],"example":"I heard a strange sound outside the window.","exampleZh":"我聽到窗外傳來奇怪的聲音。","synonyms":["noise"],"level":1,"theme":"日常與一般"},{"word":"source","pos":"n.","phonetic":"[sɔrs]","meaning":"來源；出處","definition":"the place, person, or thing from which something comes","collocations":["main source","reliable source","energy source"],"example":"The sun is the main source of energy on Earth.","exampleZh":"太陽是地球上主要的能量來源。","synonyms":["origin"],"level":3,"theme":"日常與一般"},{"word":"souvenir","pos":"n.","phonetic":"[ˌsuvəˈnɪr]","meaning":"紀念品","definition":"an item kept to remember a place, event, or person","collocations":["buy a souvenir","souvenir shop"],"example":"We bought some souvenirs to remember our trip.","exampleZh":"我們買了一些紀念品來紀念這趟旅行。","synonyms":["keepsake"],"level":4,"theme":"旅遊與交通"},{"word":"space","pos":"n.","phonetic":"[spes]","meaning":"空間；太空","definition":"an empty area; the universe beyond Earth's atmosphere","collocations":["outer space","parking space","space station"],"example":"Scientists are exploring outer space with new technology.","exampleZh":"科學家們正運用新科技探索外太空。","synonyms":["room"],"level":2,"theme":"科技與通訊"},{"word":"spacious","pos":"adj.","phonetic":"[ˈspeʃəs]","meaning":"寬敞的","definition":"having a lot of space; large in area","collocations":["spacious room","spacious apartment"],"example":"Their new house has a spacious living room.","exampleZh":"他們的新房子有一間寬敞的客廳。","synonyms":["roomy"],"level":5,"theme":"房產與設施"},{"word":"spare","pos":"adj. / v.","phonetic":"[spɛr]","meaning":"備用的；騰出(時間)","definition":"kept in reserve for use when needed; to make time or money available","collocations":["spare time","spare tire","spare a moment"],"example":"Do you have any spare time this weekend?","exampleZh":"你這個週末有空閒時間嗎?","synonyms":["extra"],"level":3,"theme":"日常與一般"},{"word":"speak","pos":"v.","phonetic":"[spik]","meaning":"說話；講","definition":"to say words aloud in order to communicate","collocations":["speak English","speak up","speak to"],"example":"Could you speak more slowly, please?","exampleZh":"可以請你說慢一點嗎?","synonyms":["talk"],"level":1,"theme":"溝通與語言"},{"word":"speaker","pos":"n.","phonetic":"[ˈspikɚ]","meaning":"說話者；喇叭；演講者","definition":"a person who speaks; a device that produces sound","collocations":["native speaker","guest speaker","loudspeaker"],"example":"The guest speaker gave an inspiring talk.","exampleZh":"這位特別來賓演講者發表了一場鼓舞人心的演說。","synonyms":[],"level":2,"theme":"溝通與語言"},{"word":"special","pos":"adj.","phonetic":"[ˈspɛʃəl]","meaning":"特別的；特殊的","definition":"different from what is usual; not ordinary","collocations":["special occasion","feel special","something special"],"example":"We had a special dinner to celebrate her birthday.","exampleZh":"我們特地準備了一頓特別的晚餐慶祝她的生日。","synonyms":["particular"],"level":1,"theme":"日常與一般"},{"word":"specialist","pos":"n.","phonetic":"[ˈspɛʃəlɪst]","meaning":"專家","definition":"a person with special knowledge or skill in a particular field","collocations":["eye specialist","financial specialist"],"example":"She saw a specialist about her back pain.","exampleZh":"她因為背痛去看了專科醫生。","synonyms":["expert"],"level":4,"theme":"人事與職涯"},{"word":"specialize","pos":"v.","phonetic":"[ˈspɛʃəˌlaɪz]","meaning":"專攻；專門從事","definition":"to focus one's work or study on a particular area","collocations":["specialize in","specialize in medicine"],"example":"This law firm specializes in international business.","exampleZh":"這家律師事務所專門處理國際商務案件。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"specialty","pos":"n.","phonetic":"[ˈspɛʃəltɪ]","meaning":"專長；招牌菜；特產","definition":"something a person or place is especially good at or known for","collocations":["house specialty","specialty store","chef's specialty"],"example":"Grilled seafood is the restaurant's specialty.","exampleZh":"碳烤海鮮是這家餐廳的招牌。","synonyms":["forte"],"level":4,"theme":"餐飲與住宿"},{"word":"specific","pos":"adj.","phonetic":"[spɪˈsɪfɪk]","meaning":"特定的；明確的","definition":"clearly defined or particular","collocations":["specific reason","specific information"],"example":"Please give me a specific date for the meeting.","exampleZh":"請給我一個明確的開會日期。","synonyms":["particular","exact"],"level":3,"theme":"日常與一般"},{"word":"specifically","pos":"adv.","phonetic":"[spɪˈsɪfɪklɪ]","meaning":"特別地；明確地","definition":"for a particular purpose, or in an exact way","collocations":["specifically designed","specifically mention","specifically for"],"example":"The training was specifically designed for new sales staff.","exampleZh":"這項訓練是專為新進業務人員設計的。","synonyms":["particularly","expressly"],"level":4,"theme":"日常與一般"},{"word":"specification","pos":"n.","phonetic":"[ˌspɛsəfəˈkeʃən]","meaning":"規格；規範","definition":"a detailed description of how something should be made or done","collocations":["technical specifications","meet specifications","product specifications"],"example":"All parts must meet the technical specifications in the contract.","exampleZh":"所有零件都必須符合合約中的技術規格。","synonyms":["requirement"],"level":5,"theme":"生產與物流"},{"word":"specify","pos":"v.","phonetic":"[ˈspɛsəˌfaɪ]","meaning":"明確指出；具體說明","definition":"to state something clearly and exactly","collocations":["specify the date","unless otherwise specified","specify requirements"],"example":"Please specify your preferred delivery date when ordering.","exampleZh":"訂購時請註明您希望的到貨日期。","synonyms":["state","indicate"],"level":5,"theme":"辦公室與行政"},{"word":"spectacular","pos":"adj.","phonetic":"[spɛkˈtækjəlɚ]","meaning":"壯觀的；驚人的","definition":"very impressive or dramatic to look at","collocations":["spectacular view","spectacular performance"],"example":"The view from the mountain top was spectacular.","exampleZh":"從山頂看到的景色非常壯觀。","synonyms":["amazing","stunning"],"level":5,"theme":"日常與一般"},{"word":"speech","pos":"n.","phonetic":"[spitʃ]","meaning":"演講；言語","definition":"a formal talk given to an audience","collocations":["give a speech","freedom of speech"],"example":"The president gave a moving speech at the ceremony.","exampleZh":"總統在典禮上發表了一場感人的演講。","synonyms":[],"level":2,"theme":"溝通與語言"},{"word":"spend","pos":"v.","phonetic":"[spɛnd]","meaning":"花費(錢、時間)","definition":"to use money or time on something","collocations":["spend money","spend time"],"example":"We spent the whole afternoon at the museum.","exampleZh":"我們整個下午都待在博物館裡。","synonyms":[],"level":1,"theme":"財務與會計"},{"word":"spending","pos":"n.","phonetic":"[ˈspɛndɪŋ]","meaning":"支出；花費","definition":"the amount of money used for something","collocations":["consumer spending","cut spending","spending habits"],"example":"Consumer spending on travel rebounded strongly this year.","exampleZh":"今年消費者的旅遊支出強勁回升。","synonyms":["expenditure"],"level":4,"theme":"財務與會計"},{"word":"spokesperson","pos":"n.","phonetic":"[ˈspoksˌpɝsn]","meaning":"發言人","definition":"a person who speaks officially for a company or group","collocations":["company spokesperson","official spokesperson"],"example":"A company spokesperson confirmed the merger talks.","exampleZh":"公司發言人證實了合併談判的消息。","synonyms":["representative"],"level":5,"theme":"媒體與活動"},{"word":"sponsor","pos":"n. / v.","phonetic":"[ˈspɑnsɚ]","meaning":"贊助者；贊助","definition":"a person or company that provides money to support an event or activity","collocations":["sponsor an event","corporate sponsor"],"example":"A local company agreed to sponsor the school marathon.","exampleZh":"一家本地公司同意贊助這場校園馬拉松。","synonyms":["support","fund"],"level":4,"theme":"財務與會計"},{"word":"spot","pos":"n. / v.","phonetic":"[spɑt]","meaning":"地點；斑點；發現","definition":"a particular place; a small mark; to notice or see something","collocations":["parking spot","spot the difference"],"example":"We found a nice spot for a picnic near the river.","exampleZh":"我們在河邊找到了一個適合野餐的好地方。","synonyms":["place","location"],"level":2,"theme":"日常與一般"},{"word":"spouse","pos":"n.","phonetic":"[spaʊs]","meaning":"配偶","definition":"a husband or wife","collocations":["spouse and children","future spouse"],"example":"Employees can bring their spouse to the company party.","exampleZh":"員工可以攜帶配偶參加公司派對。","synonyms":[],"level":5,"theme":"日常與一般"},{"word":"spread","pos":"v. / n.","phonetic":"[sprɛd]","meaning":"散布；塗抹；蔓延","definition":"to open out or extend over a wider area","collocations":["spread butter","spread the news","spread out"],"example":"News of the accident spread quickly through the town.","exampleZh":"意外的消息很快就在鎮上傳開了。","synonyms":["extend","expand"],"level":2,"theme":"日常與一般"},{"word":"spreadsheet","pos":"n.","phonetic":"[ˈsprɛdˌʃit]","meaning":"試算表","definition":"a computer program for organizing numbers and data in rows and columns","collocations":["update the spreadsheet","spreadsheet software","budget spreadsheet"],"example":"Track your monthly expenses in the shared budget spreadsheet.","exampleZh":"請在共用的預算試算表中記錄每月支出。","synonyms":[],"level":4,"theme":"辦公室與行政"},{"word":"square","pos":"n./adj.","phonetic":"[skwɛr]","meaning":"廣場；正方形；平方","definition":"an open area in a town, or a shape with four equal sides","collocations":["town square","square meter","square footage"],"example":"The office has about two hundred square meters of floor space.","exampleZh":"這間辦公室約有兩百平方公尺的使用面積。","synonyms":["plaza"],"level":2,"theme":"房產與設施"},{"word":"stability","pos":"n.","phonetic":"[stəˈbɪlətɪ]","meaning":"穩定；穩定性","definition":"the state of being steady and not likely to change","collocations":["financial stability","job stability","economic stability"],"example":"Investors value the company's long record of financial stability.","exampleZh":"投資人看重該公司長期的財務穩定紀錄。","synonyms":["steadiness"],"level":5,"theme":"財務與會計"},{"word":"stabilize","pos":"v.","phonetic":"[ˈsteblˌaɪz]","meaning":"穩定；使穩定","definition":"to become or make something steady","collocations":["prices stabilize","stabilize the market"],"example":"Fuel prices finally stabilized after months of increases.","exampleZh":"經過數月上漲後，燃料價格終於穩定下來。","synonyms":["steady"],"level":6,"theme":"財務與會計"},{"word":"stable","pos":"adj. / n.","phonetic":"[ˈstebl̩]","meaning":"穩定的；馬廄","definition":"not likely to change or fail; firm","collocations":["stable economy","stable condition","financially stable"],"example":"The patient's condition is now stable.","exampleZh":"病人的病情現在穩定了。","synonyms":["steady","firm"],"level":3,"theme":"日常與一般"},{"word":"stadium","pos":"n.","phonetic":"[ˈstedɪəm]","meaning":"體育場；運動場","definition":"a large structure with tiered seats for sports events","collocations":["football stadium","packed stadium","home stadium"],"example":"The stadium was full of cheering fans.","exampleZh":"體育場擠滿了歡呼的球迷。","synonyms":["arena"],"level":2,"theme":"媒體與活動"},{"word":"staff","pos":"n.","phonetic":"[stæf]","meaning":"職員；全體員工","definition":"the people who work for an organization","collocations":["teaching staff","staff meeting","hospital staff"],"example":"All staff must attend the meeting.","exampleZh":"所有員工都必須參加會議。","synonyms":["personnel","employees"],"level":3,"theme":"人事與職涯"},{"word":"staffing","pos":"n.","phonetic":"[ˈstæfɪŋ]","meaning":"人員配置；人力","definition":"the process of providing workers for an organization","collocations":["staffing agency","staffing levels","staffing shortage"],"example":"The hospital increased staffing levels for the holiday period.","exampleZh":"醫院為假期增加了人力配置。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"stage","pos":"n. / v.","phonetic":"[stedʒ]","meaning":"舞台；階段；舉行","definition":"a platform for performance; a period in a process","collocations":["on stage","stage a play","early stage"],"example":"She walked onto the stage confidently.","exampleZh":"她自信地走上舞台。","synonyms":["phase"],"level":2,"theme":"媒體與活動"},{"word":"stair","pos":"n.","phonetic":"[stɛr]","meaning":"樓梯（一階）","definition":"one of a set of steps leading from one floor to another","collocations":["flight of stairs","go up the stairs","stair railing"],"example":"He tripped on the bottom stair.","exampleZh":"他在樓梯最下面一階絆倒了。","synonyms":["step"],"level":1,"theme":"房產與設施"},{"word":"staircase","pos":"n.","phonetic":"[ˈstɛrˌkes]","meaning":"樓梯","definition":"a set of stairs inside a building with its supports and rails","collocations":["spiral staircase","main staircase","emergency staircase"],"example":"Use the rear staircase while the elevators are being serviced.","exampleZh":"電梯保養期間請使用後方樓梯。","synonyms":["stairway","stairs"],"level":4,"theme":"房產與設施"},{"word":"stakeholder","pos":"n.","phonetic":"[ˈstekˌholdɚ]","meaning":"利害關係人","definition":"a person or group with an interest in a business or project","collocations":["key stakeholders","stakeholder meeting","consult stakeholders"],"example":"All key stakeholders were consulted before the policy change.","exampleZh":"政策變更前已諮詢所有主要利害關係人。","synonyms":[],"level":6,"theme":"企業經營"},{"word":"stamp","pos":"n. / v.","phonetic":"[stæmp]","meaning":"郵票；蓋章；跺腳","definition":"a small piece of paper for postage; to bring the foot down heavily","collocations":["postage stamp","stamp collection","stamp your feet"],"example":"He collects rare stamps from around the world.","exampleZh":"他收集世界各地的稀有郵票。","synonyms":["seal"],"level":2,"theme":"溝通與語言"},{"word":"stand","pos":"v. / n.","phonetic":"[stænd]","meaning":"站立；忍受；攤位","definition":"to be in an upright position; to tolerate","collocations":["stand up","stand for","take a stand"],"example":"I can't stand the noise anymore.","exampleZh":"我再也無法忍受這噪音了。","synonyms":["tolerate","bear"],"level":1,"theme":"日常與一般"},{"word":"standard","pos":"n. / adj.","phonetic":"[ˈstændɚd]","meaning":"標準；水準的","definition":"a level of quality used as a basis of comparison; usual","collocations":["living standard","standard procedure","meet the standard"],"example":"The hotel maintains high standards of service.","exampleZh":"這家飯店維持高水準的服務。","synonyms":["criterion","norm"],"level":3,"theme":"日常與一般"},{"word":"standby","pos":"n./adj.","phonetic":"[ˈstændˌbaɪ]","meaning":"候補；待命；備用的","definition":"ready to be used or to act if needed","collocations":["on standby","standby passenger","standby generator"],"example":"Two technicians are on standby in case the system fails.","exampleZh":"兩名技術人員待命，以防系統故障。","synonyms":["backup"],"level":5,"theme":"旅遊與交通"},{"word":"staple","pos":"n. / adj.","phonetic":"[ˈstepl̩]","meaning":"主食；訂書針；主要的","definition":"a basic and important food item or product","collocations":["staple food","staple diet","staple gun"],"example":"Rice is a staple food in many Asian countries.","exampleZh":"米飯是許多亞洲國家的主食。","synonyms":["basic"],"level":5,"theme":"餐飲與住宿"},{"word":"stapler","pos":"n.","phonetic":"[ˈsteplɚ]","meaning":"釘書機","definition":"a device that fastens papers together with metal staples","collocations":["use a stapler","stapler refills"],"example":"There is a stapler and hole punch at the copy station.","exampleZh":"影印區備有釘書機和打孔機。","synonyms":[],"level":3,"theme":"辦公室與行政"},{"word":"start","pos":"v. / n.","phonetic":"[stɑrt]","meaning":"開始；出發","definition":"to begin an action or activity","collocations":["start over","from the start","get started"],"example":"We need to start the project today.","exampleZh":"我們今天必須開始這個專案。","synonyms":["begin","commence"],"level":1,"theme":"日常與一般"},{"word":"state","pos":"n. / v.","phonetic":"[stet]","meaning":"州；狀態；陳述","definition":"a condition of something; a country's government; to say clearly","collocations":["state of mind","state a fact","state government"],"example":"Please state your name clearly.","exampleZh":"請清楚說出你的名字。","synonyms":["condition","declare"],"level":2,"theme":"合約與法律"},{"word":"state-of-the-art","pos":"adj.","phonetic":"[ˈstetəvðɪˈɑrt]","meaning":"最先進的","definition":"using the newest and most advanced technology","collocations":["state-of-the-art facility","state-of-the-art equipment"],"example":"The gym features state-of-the-art fitness equipment.","exampleZh":"這間健身房配備最先進的健身器材。","synonyms":["cutting-edge"],"level":6,"theme":"科技與通訊"},{"word":"statement","pos":"n.","phonetic":"[ˈstetmənt]","meaning":"陳述；聲明","definition":"something said or written officially","collocations":["make a statement","official statement","bank statement"],"example":"The company issued a statement about the accident.","exampleZh":"公司針對這起意外發表了聲明。","synonyms":["declaration"],"level":3,"theme":"溝通與語言"},{"word":"station","pos":"n.","phonetic":"[ˈsteʃən]","meaning":"車站；電視台；崗位","definition":"a place where trains or buses stop regularly; a broadcasting company","collocations":["train station","gas station","radio station"],"example":"Meet me at the train station at noon.","exampleZh":"中午在火車站跟我見面。","synonyms":["depot"],"level":1,"theme":"旅遊與交通"},{"word":"stationary","pos":"adj.","phonetic":"[ˈsteʃənˌɛrɪ]","meaning":"靜止的；固定的","definition":"not moving","collocations":["remain stationary","stationary vehicle"],"example":"Keep the machine stationary while it is calibrating.","exampleZh":"機器校準期間請保持固定不動。","synonyms":["motionless"],"level":5,"theme":"生產與物流"},{"word":"statistical","pos":"adj.","phonetic":"[stəˈtɪstɪkl]","meaning":"統計的；統計學的","definition":"relating to the collection and analysis of numbers","collocations":["statistical analysis","statistical data","statistical significance"],"example":"The report includes a statistical analysis of customer trends.","exampleZh":"這份報告包含顧客趨勢的統計分析。","synonyms":[],"level":5,"theme":"科技與通訊"},{"word":"statistics","pos":"n.","phonetic":"[stəˈtɪstɪks]","meaning":"統計數據；統計學","definition":"numbers that represent facts, or the science of analyzing them","collocations":["sales statistics","official statistics","according to statistics"],"example":"The latest statistics show a rise in online purchases.","exampleZh":"最新統計數據顯示線上購物增加。","synonyms":["data","figures"],"level":4,"theme":"科技與通訊"},{"word":"statue","pos":"n.","phonetic":"[ˈstætʃu]","meaning":"雕像","definition":"a carved or cast figure of a person or animal","collocations":["bronze statue","erect a statue","Statue of Liberty"],"example":"There is a statue of the founder in the park.","exampleZh":"公園裡有一座創辦人的雕像。","synonyms":["sculpture"],"level":3,"theme":"媒體與活動"},{"word":"status","pos":"n.","phonetic":"[ˈstetəs]","meaning":"地位；身份；狀態","definition":"the relative social or professional position of someone","collocations":["social status","marital status","status symbol"],"example":"His social status changed after he became famous.","exampleZh":"他成名後社會地位改變了。","synonyms":["rank","position"],"level":4,"theme":"日常與一般"},{"word":"stay","pos":"v. / n.","phonetic":"[ste]","meaning":"停留；保持","definition":"to remain in a place or condition","collocations":["stay calm","stay overnight","stay in touch"],"example":"Please stay calm during the fire drill.","exampleZh":"消防演習時請保持冷靜。","synonyms":["remain"],"level":1,"theme":"日常與一般"},{"word":"steadily","pos":"adv.","phonetic":"[ˈstɛdɪlɪ]","meaning":"穩定地；持續地","definition":"gradually and at a constant rate","collocations":["grow steadily","increase steadily","improve steadily"],"example":"Membership has grown steadily since the club opened.","exampleZh":"自開幕以來，會員人數穩定成長。","synonyms":["consistently"],"level":4,"theme":"日常與一般"},{"word":"steady","pos":"adj. / v.","phonetic":"[ˈstɛdɪ]","meaning":"穩定的；使穩固","definition":"firmly fixed or balanced; not changing","collocations":["steady income","steady pace","hold steady"],"example":"He kept a steady pace throughout the race.","exampleZh":"他在比賽中保持穩定的步伐。","synonyms":["stable","constant"],"level":3,"theme":"日常與一般"},{"word":"steel","pos":"n.","phonetic":"[stil]","meaning":"鋼鐵","definition":"a strong alloy of iron and carbon","collocations":["stainless steel","steel industry","nerves of steel"],"example":"The bridge is made of steel.","exampleZh":"這座橋是用鋼鐵造的。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"steep","pos":"adj.","phonetic":"[stip]","meaning":"陡峭的；(價格)過高的","definition":"rising or falling sharply","collocations":["steep hill","steep price","steep decline"],"example":"The path up the mountain is very steep.","exampleZh":"上山的小路非常陡峭。","synonyms":["sheer"],"level":4,"theme":"日常與一般"},{"word":"step","pos":"n./v.","phonetic":"[stɛp]","meaning":"步驟；台階；踏出","definition":"one action in a process, or a movement of the foot","collocations":["step by step","take steps","the first step"],"example":"The company is taking steps to reduce its packaging waste.","exampleZh":"公司正採取措施減少包裝廢棄物。","synonyms":["stage","measure"],"level":1,"theme":"日常與一般"},{"word":"stimulate","pos":"v.","phonetic":"[ˈstɪmjəˌlet]","meaning":"刺激；激勵","definition":"to encourage development or increased activity","collocations":["stimulate growth","stimulate interest","stimulate the economy"],"example":"The teacher tried to stimulate students' interest in science.","exampleZh":"老師試圖激發學生對科學的興趣。","synonyms":["encourage","motivate"],"level":6,"theme":"人事與職涯"},{"word":"stipend","pos":"n.","phonetic":"[ˈstaɪpɛnd]","meaning":"津貼；補助金","definition":"a fixed regular payment, especially for training or study","collocations":["monthly stipend","travel stipend","receive a stipend"],"example":"Interns receive a monthly stipend to cover living costs.","exampleZh":"實習生每月領有生活津貼。","synonyms":["allowance"],"level":6,"theme":"財務與會計"},{"word":"stock","pos":"n. / v.","phonetic":"[stɑk]","meaning":"股票；存貨；儲備","definition":"shares in a company; goods available for sale","collocations":["stock market","out of stock","stock up on"],"example":"The store is out of stock on that item.","exampleZh":"這家店那項商品缺貨。","synonyms":["shares","inventory"],"level":4,"theme":"財務與會計"},{"word":"stopover","pos":"n.","phonetic":"[ˈstɑpˌovɚ]","meaning":"中途停留","definition":"a short stay somewhere between parts of a journey","collocations":["overnight stopover","stopover in"],"example":"The fare includes a free stopover in Bangkok.","exampleZh":"這個票價包含在曼谷免費中途停留。","synonyms":["layover"],"level":5,"theme":"旅遊與交通"},{"word":"storage","pos":"n.","phonetic":"[ˈstɔrɪdʒ]","meaning":"儲存；倉庫","definition":"the act or space of keeping goods for future use","collocations":["storage space","in storage","storage unit"],"example":"We rented a storage unit for our furniture.","exampleZh":"我們租了一個倉儲單位放家具。","synonyms":["warehouse"],"level":4,"theme":"房產與設施"},{"word":"store","pos":"n. / v.","phonetic":"[stɔr]","meaning":"商店；儲存","definition":"a shop; to keep something for future use","collocations":["grocery store","store data","department store"],"example":"She bought some bread at the store.","exampleZh":"她在商店買了一些麵包。","synonyms":["shop"],"level":1,"theme":"財務與會計"},{"word":"storefront","pos":"n.","phonetic":"[ˈstorˌfrʌnt]","meaning":"店面；門市","definition":"the front of a shop facing the street, or a small shop space","collocations":["empty storefront","storefront window","online storefront"],"example":"The bakery rented a small storefront on the main street.","exampleZh":"這家烘焙坊在大街上租了一間小店面。","synonyms":[],"level":5,"theme":"房產與設施"},{"word":"storm","pos":"n. / v.","phonetic":"[stɔrm]","meaning":"暴風雨","definition":"a violent disturbance of the atmosphere","collocations":["thunderstorm","weather the storm","storm warning"],"example":"A severe storm hit the coast last night.","exampleZh":"昨晚一場猛烈的暴風雨襲擊了海岸。","synonyms":["tempest"],"level":2,"theme":"日常與一般"},{"word":"story","pos":"n.","phonetic":"[ˈstɔrɪ]","meaning":"故事；樓層","definition":"an account of imaginary or real events","collocations":["tell a story","short story","love story"],"example":"She told her children a bedtime story.","exampleZh":"她給孩子們講了一個睡前故事。","synonyms":["tale"],"level":1,"theme":"媒體與活動"},{"word":"straightforward","pos":"adj.","phonetic":"[ˌstretˈfɔrwɚd]","meaning":"簡單明瞭的；直率的","definition":"easy to understand or do, or honest and direct","collocations":["straightforward process","straightforward instructions"],"example":"The online application process is quick and straightforward.","exampleZh":"線上申請流程既快速又簡單。","synonyms":["simple","clear"],"level":5,"theme":"日常與一般"},{"word":"strategic","pos":"adj.","phonetic":"[strəˈtidʒɪk]","meaning":"策略性的；戰略的","definition":"carefully planned to achieve an advantage","collocations":["strategic plan","strategic partnership","strategic location"],"example":"The warehouse sits in a strategic location near the port.","exampleZh":"這座倉庫位於鄰近港口的策略性位置。","synonyms":[],"level":5,"theme":"企業經營"},{"word":"strategy","pos":"n.","phonetic":"[ˈstrætədʒɪ]","meaning":"策略","definition":"a plan of action designed to achieve a goal","collocations":["marketing strategy","develop a strategy","long-term strategy"],"example":"The company changed its marketing strategy.","exampleZh":"這家公司改變了行銷策略。","synonyms":["plan","tactic"],"level":5,"theme":"財務與會計"},{"word":"stream","pos":"n. / v.","phonetic":"[strim]","meaning":"小溪；串流","definition":"a small river; to flow continuously online","collocations":["mountain stream","stream a video","stream of consciousness"],"example":"Fish swam in the clear mountain stream.","exampleZh":"魚兒在清澈的山間小溪中游動。","synonyms":["brook","creek"],"level":3,"theme":"日常與一般"},{"word":"streamline","pos":"v.","phonetic":"[ˈstrimˌlaɪn]","meaning":"簡化；使更有效率","definition":"to make a process simpler and more efficient","collocations":["streamline operations","streamline the process","streamline procedures"],"example":"The new software streamlines the entire ordering process.","exampleZh":"新軟體讓整個訂購流程更加精簡。","synonyms":["simplify"],"level":6,"theme":"企業經營"},{"word":"street","pos":"n.","phonetic":"[strit]","meaning":"街道","definition":"a public road in a city or town","collocations":["main street","cross the street","street vendor"],"example":"The street was full of shops and cafes.","exampleZh":"這條街上滿是商店和咖啡館。","synonyms":["road","avenue"],"level":1,"theme":"旅遊與交通"},{"word":"strength","pos":"n.","phonetic":"[strɛŋkθ]","meaning":"力量；優點","definition":"the quality of being physically strong","collocations":["physical strength","strength and weakness","gain strength"],"example":"It took great strength to lift the rock.","exampleZh":"需要很大的力量才能舉起那塊岩石。","synonyms":["power","force"],"level":2,"theme":"醫療與保險"},{"word":"strengthen","pos":"v.","phonetic":"[ˈstrɛŋkθən]","meaning":"加強；增強","definition":"to make or become stronger","collocations":["strengthen ties","strengthen muscles","strengthen the economy"],"example":"Exercise helps strengthen your muscles.","exampleZh":"運動有助於增強肌肉。","synonyms":["reinforce"],"level":4,"theme":"醫療與保險"},{"word":"stress","pos":"n. / v.","phonetic":"[strɛs]","meaning":"壓力；強調","definition":"mental or emotional tension; to emphasize","collocations":["under stress","stress relief","stress the importance"],"example":"Work stress can affect your health.","exampleZh":"工作壓力會影響你的健康。","synonyms":["pressure","tension"],"level":3,"theme":"日常與一般"},{"word":"stretch","pos":"v. / n.","phonetic":"[strɛtʃ]","meaning":"伸展；延伸","definition":"to extend or lengthen the body or a material","collocations":["stretch out","stretch your legs","stretch of road"],"example":"She stretched her arms after sitting all day.","exampleZh":"她坐了一整天後伸展手臂。","synonyms":["extend"],"level":3,"theme":"日常與一般"},{"word":"strict","pos":"adj.","phonetic":"[strɪkt]","meaning":"嚴格的","definition":"demanding that rules be obeyed","collocations":["strict rules","strict teacher","strict diet"],"example":"My parents are strict about homework.","exampleZh":"我爸媽對作業很嚴格。","synonyms":["rigid","stern"],"level":3,"theme":"日常與一般"},{"word":"strike","pos":"v. / n.","phonetic":"[straɪk]","meaning":"打；罷工；打擊","definition":"to hit forcefully; a refusal to work as a form of protest","collocations":["go on strike","strike a balance","lightning strike"],"example":"Workers decided to go on strike for higher wages.","exampleZh":"工人們決定為爭取更高工資而罷工。","synonyms":["hit"],"level":4,"theme":"人事與職涯"},{"word":"strive","pos":"v.","phonetic":"[straɪv]","meaning":"努力奮鬥","definition":"to make great efforts to achieve something","collocations":["strive for excellence","strive to succeed","strive hard"],"example":"We should strive for excellence in everything we do.","exampleZh":"我們做任何事都應該力求卓越。","synonyms":["struggle","endeavor"],"level":5,"theme":"日常與一般"},{"word":"stroll","pos":"v. / n.","phonetic":"[strol]","meaning":"散步；漫步","definition":"to walk in a leisurely, relaxed way","collocations":["take a stroll","stroll along the beach","evening stroll"],"example":"We strolled along the beach at sunset.","exampleZh":"我們在日落時沿著海灘散步。","synonyms":["walk","wander"],"level":4,"theme":"媒體與活動"},{"word":"strong","pos":"adj.","phonetic":"[strɔŋ]","meaning":"強壯的；濃烈的","definition":"having great physical power or force","collocations":["strong coffee","strong will","strong wind"],"example":"He is strong enough to lift heavy boxes.","exampleZh":"他強壯得足以舉起重箱子。","synonyms":["powerful","tough"],"level":1,"theme":"日常與一般"},{"word":"strongly","pos":"adv.","phonetic":"[ˈstrɔŋlɪ]","meaning":"強烈地；堅決地","definition":"in a very firm or powerful way","collocations":["strongly recommend","strongly encourage","strongly oppose"],"example":"We strongly recommend booking your seats in advance.","exampleZh":"我們強烈建議提前訂位。","synonyms":["firmly"],"level":3,"theme":"日常與一般"},{"word":"structural","pos":"adj.","phonetic":"[ˈstrʌktʃərəl]","meaning":"結構的；結構性的","definition":"relating to the way something is built or organized","collocations":["structural damage","structural changes","structural engineer"],"example":"Engineers found no structural damage after the earthquake.","exampleZh":"地震後工程師未發現任何結構性損害。","synonyms":[],"level":5,"theme":"房產與設施"},{"word":"structure","pos":"n. / v.","phonetic":"[ˈstrʌktʃɚ]","meaning":"結構；建築物","definition":"the arrangement of and relations between the parts","collocations":["social structure","sentence structure","building structure"],"example":"The novel has an unusual narrative structure.","exampleZh":"這部小說有不尋常的敘事結構。","synonyms":["framework"],"level":4,"theme":"日常與一般"},{"word":"struggle","pos":"v. / n.","phonetic":"[ˈstrʌgl̩]","meaning":"掙扎；奮鬥","definition":"to try hard to overcome a difficulty","collocations":["struggle with","power struggle","struggle to survive"],"example":"She struggled to finish the marathon.","exampleZh":"她努力掙扎完成馬拉松。","synonyms":["strive","fight"],"level":3,"theme":"日常與一般"},{"word":"studio","pos":"n.","phonetic":"[ˈstjudɪˌo]","meaning":"工作室；攝影棚","definition":"a room where an artist works or media is produced","collocations":["recording studio","art studio","studio apartment"],"example":"The band recorded their album in a studio.","exampleZh":"樂團在錄音室錄製專輯。","synonyms":["workshop"],"level":3,"theme":"媒體與活動"},{"word":"study","pos":"v. / n.","phonetic":"[ˈstʌdɪ]","meaning":"學習；研究","definition":"to learn about a subject through reading or research","collocations":["study abroad","study hard","case study"],"example":"She plans to study medicine in college.","exampleZh":"她計畫在大學攻讀醫學。","synonyms":["learn","research"],"level":1,"theme":"人事與職涯"},{"word":"stumble","pos":"v.","phonetic":"[ˈstʌmbl̩]","meaning":"絆倒；蹣跚","definition":"to trip and almost fall","collocations":["stumble upon","stumble over","stumble across"],"example":"He stumbled over a rock in the dark.","exampleZh":"他在黑暗中被石頭絆倒。","synonyms":["trip"],"level":5,"theme":"日常與一般"},{"word":"sturdy","pos":"adj.","phonetic":"[ˈstɜdɪ]","meaning":"堅固的；結實的","definition":"strongly and solidly built","collocations":["sturdy table","sturdy shoes","sturdy build"],"example":"We need a sturdy table for the workshop.","exampleZh":"我們需要一張堅固的桌子做工作坊用。","synonyms":["solid","robust"],"level":5,"theme":"日常與一般"},{"word":"style","pos":"n. / v.","phonetic":"[staɪl]","meaning":"風格；款式","definition":"a distinctive manner of doing or making something","collocations":["hair style","lifestyle","in style"],"example":"She has her own unique style of writing.","exampleZh":"她有自己獨特的寫作風格。","synonyms":["fashion","manner"],"level":2,"theme":"購物與消費"},{"word":"stylish","pos":"adj.","phonetic":"[ˈstaɪlɪʃ]","meaning":"時尚的；有型的","definition":"fashionable and attractive","collocations":["stylish design","stylish interior","stylish clothing"],"example":"The boutique hotel is known for its stylish interiors.","exampleZh":"這家精品旅館以時尚的室內設計聞名。","synonyms":["fashionable","chic"],"level":4,"theme":"購物與消費"},{"word":"subcontractor","pos":"n.","phonetic":"[sʌbˈkɑntræktɚ]","meaning":"轉包商；分包商","definition":"a company hired by a main contractor to do part of a job","collocations":["hire a subcontractor","electrical subcontractor"],"example":"The builder hired a subcontractor for the electrical work.","exampleZh":"營造商將電氣工程交由分包商施作。","synonyms":[],"level":6,"theme":"生產與物流"},{"word":"subject","pos":"n. / adj. / v.","phonetic":"[ˈsʌbdʒɪkt]","meaning":"科目；主題；使遭受","definition":"a branch of study; a topic being discussed","collocations":["subject matter","favorite subject","subject to change"],"example":"Math is my favorite subject in school.","exampleZh":"數學是我在學校最喜歡的科目。","synonyms":["topic"],"level":2,"theme":"人事與職涯"},{"word":"submission","pos":"n.","phonetic":"[səbˈmɪʃən]","meaning":"提交；投稿；提交物","definition":"the act of giving a document for consideration, or the document itself","collocations":["submission deadline","online submission","late submission"],"example":"The submission deadline for proposals is April tenth.","exampleZh":"提案的繳交期限為四月十日。","synonyms":[],"level":5,"theme":"辦公室與行政"},{"word":"submit","pos":"v.","phonetic":"[səbˈmɪt]","meaning":"提交；屈服","definition":"to hand in for consideration; to give in to authority","collocations":["submit an application","submit to","submit a report"],"example":"Please submit your homework by Friday.","exampleZh":"請在星期五前繳交作業。","synonyms":["hand in","yield"],"level":4,"theme":"人事與職涯"},{"word":"subordinate","pos":"n./adj.","phonetic":"[səˈbɔrdnɪt]","meaning":"部屬；下級的","definition":"a person with a lower position, or less important","collocations":["direct subordinate","subordinate role"],"example":"A good manager listens carefully to feedback from subordinates.","exampleZh":"好的主管會仔細聆聽部屬的意見回饋。","synonyms":[],"level":6,"theme":"人事與職涯"},{"word":"subscribe","pos":"v.","phonetic":"[səbˈskraɪb]","meaning":"訂閱；認購","definition":"to pay regularly to receive a service or publication","collocations":["subscribe to a magazine","subscribe online"],"example":"Subscribe to our channel for weekly product updates.","exampleZh":"訂閱我們的頻道，即可每週收到產品最新消息。","synonyms":[],"level":4,"theme":"媒體與活動"},{"word":"subscriber","pos":"n.","phonetic":"[səbˈskraɪbɚ]","meaning":"訂閱者；用戶","definition":"a person who pays to receive a service or publication","collocations":["newsletter subscribers","paid subscribers","subscriber base"],"example":"The streaming service added two million subscribers this year.","exampleZh":"這家串流平台今年新增了兩百萬名訂閱者。","synonyms":[],"level":5,"theme":"媒體與活動"},{"word":"subscription","pos":"n.","phonetic":"[səbˈskrɪpʃən]","meaning":"訂閱；訂閱費","definition":"an arrangement to pay regularly for a service or publication","collocations":["annual subscription","cancel a subscription","subscription fee"],"example":"Your subscription will renew automatically unless canceled.","exampleZh":"除非取消，您的訂閱將自動續期。","synonyms":[],"level":4,"theme":"購物與消費"},{"word":"subsequent","pos":"adj.","phonetic":"[ˈsʌbsɪˌkwɛnt]","meaning":"隨後的；後續的","definition":"coming after something else","collocations":["subsequent years","subsequent meetings","subsequent changes"],"example":"The first repair is free; subsequent visits incur a fee.","exampleZh":"首次維修免費，後續到府服務將酌收費用。","synonyms":["following","later"],"level":6,"theme":"日常與一般"},{"word":"subsequently","pos":"adv.","phonetic":"[ˈsʌbsɪˌkwɛntlɪ]","meaning":"隨後；接著","definition":"after something else happened","collocations":["subsequently approved","subsequently discovered"],"example":"The error was subsequently corrected in the final report.","exampleZh":"這個錯誤隨後已在最終報告中更正。","synonyms":["later","afterwards"],"level":6,"theme":"日常與一般"},{"word":"substantial","pos":"adj.","phonetic":"[səbˈstænʃəl]","meaning":"大量的；可觀的；實質的","definition":"large in amount or importance","collocations":["substantial increase","substantial savings","substantial investment"],"example":"Early registration offers a substantial discount on fees.","exampleZh":"提早報名可享可觀的費用折扣。","synonyms":["considerable","significant"],"level":5,"theme":"財務與會計"},{"word":"substantially","pos":"adv.","phonetic":"[səbˈstænʃəlɪ]","meaning":"大幅地；實質上","definition":"by a large amount","collocations":["substantially higher","substantially reduced"],"example":"Shipping times have been substantially reduced with the new carrier.","exampleZh":"改用新的貨運公司後，運送時間大幅縮短。","synonyms":["considerably","significantly"],"level":5,"theme":"日常與一般"},{"word":"substitute","pos":"n. / v.","phonetic":"[ˈsʌbstəˌtjut]","meaning":"替代品；代替","definition":"a person or thing used instead of another","collocations":["substitute teacher","sugar substitute","substitute for"],"example":"Honey can be used as a substitute for sugar.","exampleZh":"蜂蜜可以用來代替糖。","synonyms":["replacement","alternative"],"level":5,"theme":"日常與一般"},{"word":"suburb","pos":"n.","phonetic":"[ˈsʌbɜb]","meaning":"郊區","definition":"a residential area on the outskirts of a city","collocations":["live in the suburbs","quiet suburb","suburb of Taipei"],"example":"They moved to a suburb outside the city.","exampleZh":"他們搬到城外的郊區居住。","synonyms":["outskirts"],"level":4,"theme":"房產與設施"},{"word":"subway","pos":"n.","phonetic":"[ˈsʌbˌwe]","meaning":"地下鐵","definition":"an underground railway system in a city","collocations":["take the subway","subway station","subway line"],"example":"I take the subway to work every day.","exampleZh":"我每天搭地下鐵上班。","synonyms":["metro"],"level":2,"theme":"旅遊與交通"},{"word":"succeed","pos":"v.","phonetic":"[səkˈsid]","meaning":"成功；繼承","definition":"to achieve a desired aim or result","collocations":["succeed in","succeed at","succeed the throne"],"example":"She worked hard and finally succeeded.","exampleZh":"她努力工作，終於成功了。","synonyms":["prosper"],"level":3,"theme":"日常與一般"},{"word":"success","pos":"n.","phonetic":"[səkˈsɛs]","meaning":"成功","definition":"the accomplishment of an aim or purpose","collocations":["key to success","great success","achieve success"],"example":"Hard work is the key to success.","exampleZh":"努力是成功的關鍵。","synonyms":["achievement"],"level":2,"theme":"日常與一般"},{"word":"successful","pos":"adj.","phonetic":"[səkˈsɛsfəl]","meaning":"成功的","definition":"achieving the desired aim or result","collocations":["successful career","highly successful","successful attempt"],"example":"He became a successful businessman.","exampleZh":"他成為一位成功的商人。","synonyms":["prosperous"],"level":2,"theme":"日常與一般"},{"word":"successfully","pos":"adv.","phonetic":"[səkˈsɛsfəlɪ]","meaning":"成功地","definition":"in a way that achieves the intended result","collocations":["successfully completed","successfully launched"],"example":"The system upgrade was successfully completed over the weekend.","exampleZh":"系統升級已於週末順利完成。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"suffer","pos":"v.","phonetic":"[ˈsʌfɚ]","meaning":"受苦；遭受","definition":"to experience pain, illness, or difficulty","collocations":["suffer from","suffer a loss","suffer pain"],"example":"Many patients suffer from chronic pain.","exampleZh":"許多病人長期忍受慢性疼痛。","synonyms":["endure"],"level":3,"theme":"醫療與保險"},{"word":"sufficient","pos":"adj.","phonetic":"[səˈfɪʃənt]","meaning":"足夠的","definition":"enough for a particular purpose","collocations":["sufficient evidence","sufficient funds","sufficient time"],"example":"We need sufficient evidence to prove the case.","exampleZh":"我們需要足夠的證據來證明這個案子。","synonyms":["enough","adequate"],"level":5,"theme":"日常與一般"},{"word":"suggest","pos":"v.","phonetic":"[səgˈdʒɛst]","meaning":"建議；暗示","definition":"to put forward an idea or plan for consideration","collocations":["suggest an idea","suggest that","strongly suggest"],"example":"I suggest we leave early to avoid traffic.","exampleZh":"我建議我們早點出發以避開塞車。","synonyms":["recommend","propose"],"level":2,"theme":"溝通與語言"},{"word":"suggestion","pos":"n.","phonetic":"[səgˈdʒɛstʃən]","meaning":"建議；提議","definition":"an idea offered for consideration","collocations":["make a suggestion","suggestion box","helpful suggestion"],"example":"Employees may leave ideas in the suggestion box near the entrance.","exampleZh":"員工可將想法投入入口旁的意見箱。","synonyms":["proposal","recommendation"],"level":2,"theme":"溝通與語言"},{"word":"suit","pos":"n. / v.","phonetic":"[sut]","meaning":"西裝；適合","definition":"a set of matching clothes; to be convenient or suitable","collocations":["business suit","suit yourself","suit your needs"],"example":"He wore a black suit to the interview.","exampleZh":"他穿著黑色西裝去面試。","synonyms":["fit"],"level":2,"theme":"購物與消費"},{"word":"suitable","pos":"adj.","phonetic":"[ˈsutəbl̩]","meaning":"適合的","definition":"right or appropriate for a particular purpose","collocations":["suitable for","suitable candidate","suitable clothing"],"example":"This movie is not suitable for children.","exampleZh":"這部電影不適合兒童觀看。","synonyms":["appropriate","fitting"],"level":3,"theme":"日常與一般"},{"word":"summarize","pos":"v.","phonetic":"[ˈsʌməˌraɪz]","meaning":"總結；摘要","definition":"to express the main points of something briefly","collocations":["summarize the findings","briefly summarize","summarize a report"],"example":"Please summarize the key points in a one-page memo.","exampleZh":"請將重點整理成一頁的備忘錄。","synonyms":["sum up","recap"],"level":4,"theme":"會議與簡報"},{"word":"summary","pos":"n.","phonetic":"[ˈsʌmərɪ]","meaning":"摘要","definition":"a brief statement of the main points of something","collocations":["brief summary","in summary","summary of events"],"example":"Please write a summary of the article.","exampleZh":"請寫一篇這篇文章的摘要。","synonyms":["overview","outline"],"level":4,"theme":"人事與職涯"},{"word":"summit","pos":"n.","phonetic":"[ˈsʌmɪt]","meaning":"山頂；高峰會","definition":"the top of a mountain; a meeting of top leaders","collocations":["reach the summit","summit meeting","climate summit"],"example":"They finally reached the summit of the mountain.","exampleZh":"他們終於到達山頂。","synonyms":["peak","top"],"level":5,"theme":"日常與一般"},{"word":"superior","pos":"adj. / n.","phonetic":"[səˈpɪriɚ]","meaning":"較優越的；上級","definition":"better in quality, or a person of higher rank","collocations":["superior quality","feel superior","report to a superior"],"example":"This brand is known for its superior quality.","exampleZh":"這個品牌以其優越的品質聞名。","synonyms":["better","excellent"],"level":5,"theme":"日常與一般"},{"word":"supermarket","pos":"n.","phonetic":"[ˈsupɚˌmɑrkɪt]","meaning":"超級市場","definition":"a large store selling food and household goods","collocations":["go to the supermarket","shop at a supermarket","a local supermarket"],"example":"My mother buys vegetables at the supermarket every week.","exampleZh":"我媽媽每星期都在超市買菜。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"supervise","pos":"v.","phonetic":"[ˈsupɚˌvaɪz]","meaning":"監督；管理","definition":"to watch over people or work to make sure things are done correctly","collocations":["supervise staff","supervise a project","closely supervised"],"example":"She supervises a team of twelve customer service agents.","exampleZh":"她管理一支十二人的客服團隊。","synonyms":["oversee","manage"],"level":4,"theme":"人事與職涯"},{"word":"supervision","pos":"n.","phonetic":"[ˌsupɚˈvɪʒən]","meaning":"監督；指導","definition":"the act of watching over work or people","collocations":["under the supervision of","direct supervision","close supervision"],"example":"Trainees operate the equipment under close supervision.","exampleZh":"受訓人員在嚴密監督下操作設備。","synonyms":["oversight"],"level":5,"theme":"人事與職涯"},{"word":"supervisor","pos":"n.","phonetic":"[ˈsupɚˌvaɪzɚ]","meaning":"主管；督導","definition":"a person who watches over workers and their work","collocations":["immediate supervisor","shift supervisor","report to a supervisor"],"example":"Report any equipment problems to your shift supervisor.","exampleZh":"設備若有問題，請向值班主管回報。","synonyms":["manager","overseer"],"level":3,"theme":"人事與職涯"},{"word":"supervisory","pos":"adj.","phonetic":"[ˌsupɚˈvaɪzərɪ]","meaning":"監督的；管理的","definition":"relating to the job of supervising","collocations":["supervisory role","supervisory experience","supervisory position"],"example":"The posting requires two years in a supervisory role.","exampleZh":"這個職缺需要兩年的管理職經驗。","synonyms":["managerial"],"level":6,"theme":"人事與職涯"},{"word":"supplement","pos":"n./v.","phonetic":"[ˈsʌpləmənt]","meaning":"補充；補給品；增補","definition":"something added to improve or complete, or to add it","collocations":["dietary supplement","supplement income","travel supplement"],"example":"Many drivers supplement their income with weekend deliveries.","exampleZh":"許多司機靠週末送貨來補貼收入。","synonyms":["addition"],"level":5,"theme":"醫療與保險"},{"word":"supplier","pos":"n.","phonetic":"[səˈplaɪɚ]","meaning":"供應商","definition":"a company that provides goods or materials to businesses","collocations":["main supplier","parts supplier","switch suppliers"],"example":"The factory works with three suppliers to avoid shortages.","exampleZh":"工廠與三家供應商合作，以避免缺料。","synonyms":["vendor","provider"],"level":4,"theme":"生產與物流"},{"word":"supply","pos":"n. / v.","phonetic":"[səˈplaɪ]","meaning":"供應；供給","definition":"to provide something needed, or the amount provided","collocations":["supply water","food supply","supply and demand"],"example":"The factory supplies parts to car companies worldwide.","exampleZh":"這家工廠供應零件給世界各地的汽車公司。","synonyms":["provide"],"level":3,"theme":"財務與會計"},{"word":"support","pos":"v. / n.","phonetic":"[səˈport]","meaning":"支持；支撐","definition":"to help or agree with someone, or to hold something up","collocations":["support a decision","financial support","support each other"],"example":"My family always supports my dreams.","exampleZh":"我的家人總是支持我的夢想。","synonyms":["back","help"],"level":2,"theme":"日常與一般"},{"word":"suppose","pos":"v.","phonetic":"[səˈpoz]","meaning":"猜想；假定","definition":"to think something is likely true","collocations":["suppose that","be supposed to","I suppose so"],"example":"I suppose she will be late because of the traffic.","exampleZh":"我猜她會因為塞車而遲到。","synonyms":["guess","assume"],"level":3,"theme":"溝通與語言"},{"word":"surface","pos":"n.","phonetic":"[ˈsɝfɪs]","meaning":"表面","definition":"the outer or top layer of something","collocations":["the earth's surface","a smooth surface","rise to the surface"],"example":"The lake's surface was completely frozen.","exampleZh":"湖面完全結冰了。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"surgery","pos":"n.","phonetic":"[ˈsɝdʒəri]","meaning":"手術","definition":"medical treatment that involves cutting into the body","collocations":["undergo surgery","perform surgery","need surgery"],"example":"She had surgery on her knee last month.","exampleZh":"她上個月動了膝蓋手術。","synonyms":["operation"],"level":4,"theme":"醫療與保險"},{"word":"surprise","pos":"n./v.","phonetic":"[sɚˈpraɪz]","meaning":"驚喜；驚訝；使吃驚","definition":"an unexpected event, or to make someone feel amazed","collocations":["come as a surprise","surprise party","to my surprise"],"example":"The strong quarterly results came as a pleasant surprise.","exampleZh":"亮眼的季度業績令人喜出望外。","synonyms":["astonish"],"level":1,"theme":"日常與一般"},{"word":"surround","pos":"v.","phonetic":"[səˈraʊnd]","meaning":"環繞；圍繞","definition":"to be or move all around something","collocations":["surround the building","surrounded by trees","police surrounded the area"],"example":"Tall mountains surround the small village.","exampleZh":"高山環繞著這個小村莊。","synonyms":["encircle"],"level":3,"theme":"日常與一般"},{"word":"surrounding","pos":"adj./n.","phonetic":"[səˈraʊndɪŋ]","meaning":"周圍的；周遭環境","definition":"all around a place, or the area around something","collocations":["surrounding area","surrounding neighborhoods","beautiful surroundings"],"example":"The resort offers tours of the surrounding countryside.","exampleZh":"度假村提供周邊鄉野的導覽行程。","synonyms":["nearby"],"level":4,"theme":"旅遊與交通"},{"word":"survey","pos":"n. / v.","phonetic":"[ˈsɝve]","meaning":"調查；問卷","definition":"a study to collect information from people","collocations":["conduct a survey","take a survey","a survey shows that"],"example":"A recent survey shows that most students prefer online classes.","exampleZh":"一項最近的調查顯示大多數學生偏好線上課程。","synonyms":["poll"],"level":4,"theme":"人事與職涯"},{"word":"survive","pos":"v.","phonetic":"[sɚˈvaɪv]","meaning":"倖存；存活","definition":"to continue to live after a difficult event","collocations":["survive a disaster","barely survive","survive the winter"],"example":"Only a few passengers survived the crash.","exampleZh":"只有少數乘客在這場空難中倖存。","synonyms":["endure"],"level":3,"theme":"日常與一般"},{"word":"suspend","pos":"v.","phonetic":"[səˈspɛnd]","meaning":"暫停；懸掛","definition":"to stop something temporarily, or to hang something","collocations":["suspend a game","suspend a student","suspended from the ceiling"],"example":"The school suspended the student for a week.","exampleZh":"學校讓那名學生停學一週。","synonyms":["postpone"],"level":5,"theme":"人事與職涯"},{"word":"sustain","pos":"v.","phonetic":"[səˈsten]","meaning":"維持；支撐","definition":"to keep something going or in existence","collocations":["sustain life","sustain economic growth","sustain an injury"],"example":"Farmers work hard to sustain their crops during the drought.","exampleZh":"農夫在乾旱期間努力維持他們的作物。","synonyms":["maintain"],"level":5,"theme":"日常與一般"},{"word":"sustainable","pos":"adj.","phonetic":"[səˈstenəbl]","meaning":"永續的；可持續的","definition":"able to continue without harming the environment or resources","collocations":["sustainable development","sustainable growth","sustainable materials"],"example":"The brand uses sustainable materials in all its packaging.","exampleZh":"該品牌所有包裝都使用永續材料。","synonyms":["eco-friendly"],"level":5,"theme":"企業經營"},{"word":"switch","pos":"n. / v.","phonetic":"[swɪtʃ]","meaning":"開關；轉換","definition":"a device for turning something on or off, or to change","collocations":["turn on the switch","switch jobs","light switch"],"example":"He flipped the switch to turn on the lights.","exampleZh":"他扳動開關把燈打開。","synonyms":["change"],"level":3,"theme":"科技與通訊"},{"word":"symptom","pos":"n.","phonetic":"[ˈsɪmptəm]","meaning":"症狀；徵兆","definition":"a sign of illness or of a problem","collocations":["flu symptoms","common symptoms","show symptoms"],"example":"Employees with flu symptoms should stay home and rest.","exampleZh":"有流感症狀的員工應在家休息。","synonyms":["sign","indication"],"level":4,"theme":"醫療與保險"},{"word":"synthetic","pos":"adj.","phonetic":"[sɪnˈθɛtɪk]","meaning":"合成的；人造的","definition":"made from artificial materials rather than natural ones","collocations":["synthetic materials","synthetic fabric","synthetic leather"],"example":"The jacket is made of a durable synthetic fabric.","exampleZh":"這件外套採用耐用的合成布料製成。","synonyms":["artificial","man-made"],"level":5,"theme":"生產與物流"},{"word":"system","pos":"n.","phonetic":"[ˈsɪstəm]","meaning":"系統；制度","definition":"a set of connected parts or an organized way of doing things","collocations":["computer system","booking system","security system"],"example":"The new booking system handles reservations automatically.","exampleZh":"新的訂位系統會自動處理預約。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"table","pos":"n.","phonetic":"[ˈtebḷ]","meaning":"餐桌；桌子；表格","definition":"a piece of furniture with a flat top and legs","collocations":["set the table","table manners","coffee table"],"example":"We sat around the table for dinner.","exampleZh":"我們圍坐在餐桌旁吃晚餐。","synonyms":["desk"],"level":1,"theme":"房產與設施"},{"word":"tag","pos":"n. / v.","phonetic":"[tæg]","meaning":"標籤；標記；玩捉人遊戲","definition":"a small piece of paper or plastic attached to something for identification","collocations":["price tag","name tag","tag along"],"example":"Check the price tag before you buy it.","exampleZh":"買之前先看看價格標籤。","synonyms":["label"],"level":2,"theme":"財務與會計"},{"word":"tailor","pos":"n. / v.","phonetic":"[ˈtelɚ]","meaning":"裁縫師；量身打造","definition":"a person who makes clothes, or to adjust something to fit needs","collocations":["visit a tailor","tailor a plan","a tailored suit"],"example":"The tailor made a suit that fit him perfectly.","exampleZh":"裁縫師做了一套完全合身的西裝。","synonyms":["adjust","customize"],"level":4,"theme":"購物與消費"},{"word":"take","pos":"v.","phonetic":"[tek]","meaning":"拿；帶；花費(時間)","definition":"to move something from one place to another or to need an amount of time","collocations":["take a break","take place","take time"],"example":"It will take an hour to finish the report.","exampleZh":"完成這份報告需要一個小時。","synonyms":["grab","bring"],"level":1,"theme":"日常與一般"},{"word":"takeover","pos":"n.","phonetic":"[ˈtekˌovɚ]","meaning":"收購；接管","definition":"the act of gaining control of a company","collocations":["hostile takeover","takeover bid","corporate takeover"],"example":"The takeover of the airline was approved by regulators.","exampleZh":"監管機關批准了這樁航空公司收購案。","synonyms":["acquisition","buyout"],"level":6,"theme":"企業經營"},{"word":"talent","pos":"n.","phonetic":"[ˈtælənt]","meaning":"天賦；才能","definition":"a natural ability to do something well","collocations":["musical talent","natural talent","talent show"],"example":"She has a real talent for painting.","exampleZh":"她真的很有繪畫天分。","synonyms":["gift","ability"],"level":3,"theme":"人事與職涯"},{"word":"talented","pos":"adj.","phonetic":"[ˈtæləntɪd]","meaning":"有才華的；有天賦的","definition":"having a natural ability to do something well","collocations":["talented team","highly talented","talented individuals"],"example":"The design award recognizes talented young professionals.","exampleZh":"這座設計獎旨在表彰有才華的年輕專業人士。","synonyms":["gifted","skilled"],"level":3,"theme":"人事與職涯"},{"word":"talk","pos":"v. / n.","phonetic":"[tɔk]","meaning":"說話；談話","definition":"to speak to someone in order to give information or ideas","collocations":["talk about","small talk","give a talk"],"example":"Let's talk about the plan tomorrow.","exampleZh":"我們明天再談這個計畫吧。","synonyms":["speak","chat"],"level":1,"theme":"溝通與語言"},{"word":"target","pos":"n. / v.","phonetic":"[ˈtɑrgɪt]","meaning":"目標；靶子","definition":"a result that you try to achieve, or an object aimed at","collocations":["hit the target","target audience","set a target"],"example":"Our sales target for this month is high.","exampleZh":"我們這個月的銷售目標很高。","synonyms":["goal","aim"],"level":3,"theme":"財務與會計"},{"word":"tariff","pos":"n.","phonetic":"[ˈtærɪf]","meaning":"關稅；價目表","definition":"a tax charged on goods brought into a country","collocations":["impose a tariff","raise tariffs","trade tariffs"],"example":"The government raised tariffs on imported cars.","exampleZh":"政府提高了進口汽車的關稅。","synonyms":["duty","tax"],"level":5,"theme":"財務與會計"},{"word":"task","pos":"n.","phonetic":"[tæsk]","meaning":"任務；工作","definition":"a piece of work to be done","collocations":["complete a task","daily tasks","difficult task"],"example":"Finishing the project was not an easy task.","exampleZh":"完成這個專案並不是件容易的任務。","synonyms":["job","assignment"],"level":3,"theme":"人事與職涯"},{"word":"taste","pos":"n./v.","phonetic":"[test]","meaning":"味道；品味；品嚐","definition":"the flavor of food, or to try a small amount of it","collocations":["taste test","a taste of","suit every taste"],"example":"Guests can taste local specialties at the hotel's night market fair.","exampleZh":"房客可以在飯店的夜市主題活動中品嚐在地特色美食。","synonyms":["flavor","sample"],"level":2,"theme":"餐飲與住宿"},{"word":"tax","pos":"n.","phonetic":"[tæks]","meaning":"稅金","definition":"money that must be paid to the government","collocations":["pay tax","income tax","tax return"],"example":"The government raised the income tax rate.","exampleZh":"政府提高了所得稅稅率。","synonyms":[],"level":3,"theme":"財務與會計"},{"word":"taxi","pos":"n.","phonetic":"[ˈtæksɪ]","meaning":"計程車","definition":"a car that carries passengers for a fare","collocations":["take a taxi","call a taxi","taxi driver"],"example":"We took a taxi to the airport.","exampleZh":"我們搭計程車去機場。","synonyms":["cab"],"level":1,"theme":"旅遊與交通"},{"word":"taxpayer","pos":"n.","phonetic":"[ˈtæksˌpeɚ]","meaning":"納稅人","definition":"a person who pays tax","collocations":["taxpayer money","individual taxpayer"],"example":"The new e-filing system saves taxpayers time each spring.","exampleZh":"新的電子申報系統讓納稅人每年春天省下不少時間。","synonyms":[],"level":5,"theme":"財務與會計"},{"word":"teach","pos":"v.","phonetic":"[titʃ]","meaning":"教導；教書","definition":"to give lessons to someone so they learn something","collocations":["teach a class","teach English","teach by example"],"example":"She teaches math at a high school.","exampleZh":"她在高中教數學。","synonyms":["instruct","educate"],"level":1,"theme":"人事與職涯"},{"word":"teacher","pos":"n.","phonetic":"[ˈtitʃɚ]","meaning":"老師；教師","definition":"a person whose job is to teach","collocations":["English teacher","substitute teacher"],"example":"The language school is hiring certified English teachers.","exampleZh":"這家語言學校正在招聘合格的英語教師。","synonyms":["instructor","educator"],"level":1,"theme":"人事與職涯"},{"word":"team","pos":"n.","phonetic":"[tim]","meaning":"隊伍；團隊","definition":"a group of people who work or play together","collocations":["team up","team spirit","sports team"],"example":"Our team won the championship.","exampleZh":"我們的隊伍贏得了冠軍。","synonyms":["group"],"level":1,"theme":"媒體與活動"},{"word":"teamwork","pos":"n.","phonetic":"[ˈtimˌwɝk]","meaning":"團隊合作","definition":"the combined effort of a group working together","collocations":["good teamwork","promote teamwork","teamwork skills"],"example":"Strong teamwork helped the crew finish the project early.","exampleZh":"良好的團隊合作讓團隊提前完成專案。","synonyms":["collaboration","cooperation"],"level":3,"theme":"人事與職涯"},{"word":"technical","pos":"adj.","phonetic":"[ˈtɛknɪkḷ]","meaning":"技術性的","definition":"relating to the skills needed for a particular job or subject","collocations":["technical support","technical problem","technical skill"],"example":"The company offers technical support 24 hours a day.","exampleZh":"這家公司提供全天候的技術支援。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"technician","pos":"n.","phonetic":"[tɛkˈnɪʃən]","meaning":"技術人員；技師","definition":"a skilled worker who repairs or operates equipment","collocations":["lab technician","service technician","repair technician"],"example":"A technician will arrive between nine and noon to fix the copier.","exampleZh":"技術人員將於九點至中午之間到府維修影印機。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"technique","pos":"n.","phonetic":"[tɛkˈnik]","meaning":"技巧；技術","definition":"a way of doing something that requires skill","collocations":["painting technique","new technique","master a technique"],"example":"He learned a new technique for solving the problem.","exampleZh":"他學會了一種解決問題的新技巧。","synonyms":["method","skill"],"level":4,"theme":"科技與通訊"},{"word":"technology","pos":"n.","phonetic":"[tɛkˈnɑlədʒɪ]","meaning":"科技","definition":"the application of scientific knowledge for practical purposes","collocations":["modern technology","information technology","advanced technology"],"example":"Technology has changed the way we communicate.","exampleZh":"科技改變了我們溝通的方式。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"telecommunications","pos":"n.","phonetic":"[ˌtɛlɪkəˌmjunəˈkeʃənz]","meaning":"電信；電信業","definition":"the technology of sending information by phone, internet, or radio","collocations":["telecommunications company","telecommunications industry"],"example":"The telecommunications company is expanding its fiber network.","exampleZh":"這家電信公司正在擴建光纖網路。","synonyms":[],"level":5,"theme":"科技與通訊"},{"word":"teleconference","pos":"n./v.","phonetic":"[ˈtɛləˌkɑnfərəns]","meaning":"電話會議；視訊會議","definition":"a meeting held by phone or video among people in different places","collocations":["hold a teleconference","join a teleconference"],"example":"The quarterly review will be held by teleconference on Monday.","exampleZh":"季度檢討會議將於週一以視訊會議方式舉行。","synonyms":[],"level":5,"theme":"會議與簡報"},{"word":"telephone","pos":"n.","phonetic":"[ˈtɛləˏfon]","meaning":"電話","definition":"a device used to talk to someone who is far away","collocations":["answer the telephone","telephone call","telephone number"],"example":"She answered the telephone immediately.","exampleZh":"她立刻接了電話。","synonyms":["phone"],"level":1,"theme":"科技與通訊"},{"word":"television","pos":"n.","phonetic":"[ˈtɛləˏvɪʒən]","meaning":"電視","definition":"a device for receiving broadcast programs with pictures and sound","collocations":["watch television","turn on the television","television program"],"example":"The children love watching television after school.","exampleZh":"孩子們放學後喜歡看電視。","synonyms":["TV"],"level":1,"theme":"科技與通訊"},{"word":"teller","pos":"n.","phonetic":"[ˈtɛlɚ]","meaning":"銀行櫃員","definition":"a bank employee who serves customers at the counter","collocations":["bank teller","teller window"],"example":"The teller helped me set up automatic bill payments.","exampleZh":"銀行櫃員協助我設定了自動扣繳。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"temperature","pos":"n.","phonetic":"[ˈtɛmprətʃɚ]","meaning":"溫度；體溫","definition":"the degree of heat or cold measured on a scale","collocations":["room temperature","high temperature","take one's temperature"],"example":"The temperature dropped suddenly last night.","exampleZh":"昨晚氣溫突然下降。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"temporarily","pos":"adv.","phonetic":"[ˈtɛmpəˌrɛrəlɪ]","meaning":"暫時地","definition":"for a limited time only","collocations":["temporarily closed","temporarily unavailable","temporarily suspended"],"example":"The parking garage is temporarily closed for resurfacing.","exampleZh":"停車場因重鋪路面暫時關閉。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"temporary","pos":"adj.","phonetic":"[ˈtɛmpəˏrɛrɪ]","meaning":"暫時的","definition":"lasting for only a limited period of time","collocations":["temporary job","temporary solution","temporary shelter"],"example":"She took a temporary job during the summer.","exampleZh":"她暑假期間做了一份臨時工作。","synonyms":["brief","short-term"],"level":4,"theme":"日常與一般"},{"word":"tempt","pos":"v.","phonetic":"[tɛmpt]","meaning":"誘惑","definition":"to attract or entice someone to do something, often unwise","collocations":["tempt someone to","tempted to buy","resist the temptation"],"example":"The smell of cookies tempted him to eat one.","exampleZh":"餅乾的香味誘惑他吃了一個。","synonyms":["entice","lure"],"level":5,"theme":"日常與一般"},{"word":"tenant","pos":"n.","phonetic":"[ˈtɛnənt]","meaning":"房客；承租人","definition":"a person who rents land or property from a landlord","collocations":["a new tenant","evict a tenant","tenant rights"],"example":"The tenant signed a one-year lease for the apartment.","exampleZh":"房客簽了公寓一年的租約。","synonyms":["renter","lodger"],"level":4,"theme":"房產與設施"},{"word":"tend","pos":"v.","phonetic":"[tɛnd]","meaning":"傾向於；照料","definition":"to be likely to behave in a particular way, or to take care of something","collocations":["tend to","tend a garden"],"example":"People tend to eat more in winter.","exampleZh":"人們在冬天往往吃得比較多。","synonyms":["incline"],"level":4,"theme":"日常與一般"},{"word":"tendency","pos":"n.","phonetic":"[ˈtɛndənsi]","meaning":"傾向；趨勢","definition":"an inclination to behave or think in a certain way","collocations":["a natural tendency","have a tendency to","a growing tendency"],"example":"He has a tendency to arrive late for meetings.","exampleZh":"他開會總是有遲到的傾向。","synonyms":["inclination","trend"],"level":4,"theme":"日常與一般"},{"word":"tender","pos":"adj.","phonetic":"[ˈtɛndɚ]","meaning":"溫柔的；嫩的","definition":"gentle and kind, or soft and easy to chew","collocations":["tender meat","tender care","tender heart"],"example":"The steak was cooked until tender.","exampleZh":"這塊牛排煮到軟嫩。","synonyms":["gentle","soft"],"level":4,"theme":"日常與一般"},{"word":"tension","pos":"n.","phonetic":"[ˈtɛnʃən]","meaning":"緊張；張力","definition":"a feeling of worry or unfriendliness, or tightness","collocations":["ease tension","rising tension","tension between"],"example":"The mediator helped ease tension between the two departments.","exampleZh":"調解人協助緩解了兩個部門之間的緊張關係。","synonyms":["strain","stress"],"level":4,"theme":"人事與職涯"},{"word":"tentative","pos":"adj.","phonetic":"[ˈtɛntətɪv]","meaning":"暫定的；試探性的","definition":"not certain or fixed; provisional","collocations":["a tentative plan","a tentative agreement","tentative steps"],"example":"We made a tentative arrangement to meet next Friday.","exampleZh":"我們暫定下週五見面。","synonyms":["provisional","uncertain"],"level":5,"theme":"日常與一般"},{"word":"tenure","pos":"n.","phonetic":"[ˈtɛnjɚ]","meaning":"任期；任職期間；終身職","definition":"the period someone holds a job, or the right to keep it permanently","collocations":["during one's tenure","long tenure"],"example":"During her tenure as director, sales tripled.","exampleZh":"在她擔任總監期間，銷售額成長了三倍。","synonyms":["term"],"level":6,"theme":"人事與職涯"},{"word":"term","pos":"n.","phonetic":"[tɝm]","meaning":"學期；名詞；條件","definition":"a period of time such as a school semester, or a word/condition","collocations":["school term","technical term","term of contract"],"example":"The new term begins in September.","exampleZh":"新學期九月開始。","synonyms":["semester"],"level":3,"theme":"人事與職涯"},{"word":"terminal","pos":"adj. / n.","phonetic":"[ˈtɝmənl]","meaning":"終點的；末期的；航空站","definition":"situated at an end, or a building where journeys begin or end","collocations":["airport terminal","terminal illness","bus terminal"],"example":"We waited at the airport terminal for our flight.","exampleZh":"我們在機場航廈等候班機。","synonyms":["final","station"],"level":4,"theme":"旅遊與交通"},{"word":"terminate","pos":"v.","phonetic":"[ˈtɝməˌnet]","meaning":"終止；結束","definition":"to bring or come to an end","collocations":["terminate a contract","terminate employment","terminate a program"],"example":"The company decided to terminate the contract early.","exampleZh":"公司決定提前終止合約。","synonyms":["end","stop"],"level":5,"theme":"財務與會計"},{"word":"termination","pos":"n.","phonetic":"[ˌtɝməˈneʃən]","meaning":"終止；解僱","definition":"the act of ending something such as a contract or employment","collocations":["termination of contract","termination notice","early termination"],"example":"Early termination of the lease requires a two-month penalty.","exampleZh":"提前解約需支付兩個月租金的違約金。","synonyms":["ending"],"level":6,"theme":"合約與法律"},{"word":"terrace","pos":"n.","phonetic":"[ˈtɛrəs]","meaning":"露台；梯田","definition":"a flat outdoor area next to a building, or a leveled area on a hillside","collocations":["a roof terrace","rice terraces","sit on the terrace"],"example":"They had breakfast on the terrace overlooking the sea.","exampleZh":"他們在能俯瞰大海的露台上吃早餐。","synonyms":["patio","deck"],"level":4,"theme":"房產與設施"},{"word":"terrific","pos":"adj.","phonetic":"[təˈrɪfɪk]","meaning":"極好的","definition":"excellent or very good","collocations":["terrific idea","terrific performance"],"example":"You did a terrific job on the project.","exampleZh":"你這個專案做得非常出色。","synonyms":["excellent","wonderful"],"level":3,"theme":"日常與一般"},{"word":"territory","pos":"n.","phonetic":"[ˈtɛrəˏtorɪ]","meaning":"領土；領域","definition":"an area of land under the control of a country or ruler","collocations":["enemy territory","foreign territory","defend territory"],"example":"The country expanded its territory after the war.","exampleZh":"這個國家在戰後擴張了領土。","synonyms":["land","region"],"level":5,"theme":"合約與法律"},{"word":"test","pos":"n. / v.","phonetic":"[tɛst]","meaning":"測驗；測試","definition":"a set of questions or activities designed to measure ability or knowledge","collocations":["take a test","pass a test","blood test"],"example":"We have a math test tomorrow.","exampleZh":"我們明天有一場數學測驗。","synonyms":["exam","quiz"],"level":1,"theme":"人事與職涯"},{"word":"testify","pos":"v.","phonetic":"[ˈtɛstəˌfaɪ]","meaning":"作證；證明","definition":"to give evidence as a witness, in court or in a public inquiry","collocations":["testify in court","testify against someone","testify to the truth"],"example":"The witness testified that she saw the accident happen.","exampleZh":"目擊者作證說她看到了事故發生的經過。","synonyms":["witness","declare"],"level":5,"theme":"合約與法律"},{"word":"testimonial","pos":"n.","phonetic":"[ˌtɛstəˈmonɪəl]","meaning":"推薦文；使用心得","definition":"a statement praising a product, service, or person","collocations":["customer testimonials","glowing testimonial"],"example":"The website features testimonials from satisfied clients.","exampleZh":"網站上刊登了滿意客戶的推薦心得。","synonyms":["endorsement"],"level":6,"theme":"行銷與銷售"},{"word":"testimony","pos":"n.","phonetic":"[ˈtɛstəˌmoni]","meaning":"證詞；證言","definition":"a formal written or spoken statement, especially in a court of law","collocations":["give testimony","expert testimony","written testimony"],"example":"Her testimony helped convince the jury of his innocence.","exampleZh":"她的證詞幫助陪審團相信他的清白。","synonyms":["statement","evidence"],"level":5,"theme":"合約與法律"},{"word":"text","pos":"n. / v.","phonetic":"[tɛkst]","meaning":"文本；傳簡訊","definition":"written material, or to send someone a text message","collocations":["text message","send a text","read a text"],"example":"I'll text you when I arrive.","exampleZh":"我到了會傳簡訊給你。","synonyms":["message"],"level":2,"theme":"溝通與語言"},{"word":"textbook","pos":"n.","phonetic":"[ˈtɛkstˏbʊk]","meaning":"教科書","definition":"a book used for studying a particular subject","collocations":["history textbook","buy a textbook"],"example":"Please open your textbook to page ten.","exampleZh":"請翻開課本第十頁。","synonyms":[],"level":1,"theme":"人事與職涯"},{"word":"textile","pos":"n. / adj.","phonetic":"[ˈtɛkstaɪl]","meaning":"紡織品；紡織的","definition":"a type of cloth or woven fabric","collocations":["textile industry","cotton textiles","textile factory"],"example":"The city was once famous for its textile industry.","exampleZh":"這座城市曾以紡織業聞名。","synonyms":["fabric","cloth"],"level":5,"theme":"財務與會計"},{"word":"texture","pos":"n.","phonetic":"[ˈtɛkstʃɚ]","meaning":"質地；紋理","definition":"the feel, appearance, or consistency of a surface or substance","collocations":["smooth texture","rough texture","texture of the fabric"],"example":"The cake has a soft, moist texture.","exampleZh":"這個蛋糕的質地柔軟濕潤。","synonyms":[],"level":5,"theme":"日常與一般"},{"word":"thank","pos":"v.","phonetic":"[θæŋk]","meaning":"感謝","definition":"to express gratitude to someone","collocations":["thank you","thank someone for"],"example":"I want to thank you for your help.","exampleZh":"我想感謝你的幫助。","synonyms":["appreciate"],"level":1,"theme":"溝通與語言"},{"word":"theater","pos":"n.","phonetic":"[ˈθiətɚ]","meaning":"劇院；戲劇","definition":"a building where plays or films are performed or shown","collocations":["go to the theater","movie theater","theater ticket"],"example":"We watched a play at the theater last night.","exampleZh":"我們昨晚在劇院看了一場戲。","synonyms":[],"level":2,"theme":"媒體與活動"},{"word":"theft","pos":"n.","phonetic":"[θɛft]","meaning":"竊盜；偷竊","definition":"the act of stealing","collocations":["report a theft","identity theft","prevent theft"],"example":"The store installed cameras to prevent theft.","exampleZh":"這家店安裝了攝影機以防止竊盜。","synonyms":["stealing","robbery"],"level":4,"theme":"合約與法律"},{"word":"theme","pos":"n.","phonetic":"[θim]","meaning":"主題","definition":"the main subject or idea of a piece of work","collocations":["main theme","theme song","theme park"],"example":"The theme of the novel is love and loss.","exampleZh":"這本小說的主題是愛與失去。","synonyms":["subject","topic"],"level":4,"theme":"媒體與活動"},{"word":"therapy","pos":"n.","phonetic":"[ˈθɛrəpɪ]","meaning":"治療","definition":"treatment intended to relieve or heal a disorder","collocations":["physical therapy","speech therapy","undergo therapy"],"example":"She is undergoing therapy after the accident.","exampleZh":"她在事故後接受治療。","synonyms":["treatment"],"level":5,"theme":"醫療與保險"},{"word":"thereafter","pos":"adv.","phonetic":"[ðɛrˈæftɚ]","meaning":"此後；其後","definition":"after that time","collocations":["shortly thereafter","annually thereafter"],"example":"The fee is waived the first year and fifty dollars annually thereafter.","exampleZh":"首年免收費用，其後每年收取五十美元。","synonyms":["afterwards"],"level":6,"theme":"合約與法律"},{"word":"thereby","pos":"adv.","phonetic":"[ˈðɛrˈbaɪ]","meaning":"藉此；從而","definition":"as a result of that action","collocations":["thereby reducing","thereby increasing"],"example":"The plant automated its line, thereby cutting production costs.","exampleZh":"工廠將產線自動化，從而降低了生產成本。","synonyms":["thus"],"level":6,"theme":"溝通與語言"},{"word":"therefore","pos":"adv.","phonetic":"[ˈðɛrˌfor]","meaning":"因此；所以","definition":"for that reason","collocations":["and therefore","therefore, we recommend"],"example":"The flight was overbooked; therefore, we were offered compensation.","exampleZh":"班機超賣，因此我們獲得了補償。","synonyms":["thus","hence"],"level":3,"theme":"溝通與語言"},{"word":"think","pos":"v.","phonetic":"[θɪŋk]","meaning":"思考；認為","definition":"to use one's mind to consider or believe something","collocations":["think about","think of","think twice"],"example":"I need time to think about your offer.","exampleZh":"我需要時間考慮你的提議。","synonyms":["consider","believe"],"level":1,"theme":"日常與一般"},{"word":"third","pos":"num./n.","phonetic":"[θɝd]","meaning":"第三；三分之一","definition":"number three in a series, or one of three equal parts","collocations":["third quarter","a third of","third floor"],"example":"Nearly a third of our orders now come from mobile devices.","exampleZh":"我們現在近三分之一的訂單來自行動裝置。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"third-party","pos":"adj.","phonetic":"[ˈθɝdˈpɑrtɪ]","meaning":"第三方的","definition":"involving a company or person outside the main two involved","collocations":["third-party vendor","third-party logistics","third-party apps"],"example":"Deliveries are handled by a third-party logistics provider.","exampleZh":"配送作業由第三方物流業者負責。","synonyms":[],"level":6,"theme":"企業經營"},{"word":"thorough","pos":"adj.","phonetic":"[ˈθɝo]","meaning":"徹底的；仔細的","definition":"complete in every detail; careful and exact","collocations":["thorough investigation","thorough check","thorough understanding"],"example":"The police conducted a thorough investigation.","exampleZh":"警方進行了徹底的調查。","synonyms":["complete","careful"],"level":5,"theme":"日常與一般"},{"word":"thoroughly","pos":"adv.","phonetic":"[ˈθɝolɪ]","meaning":"徹底地；完全地","definition":"completely and carefully","collocations":["thoroughly inspect","thoroughly enjoy","thoroughly clean"],"example":"Each returned item is thoroughly inspected before resale.","exampleZh":"每件退回的商品在再次販售前都會徹底檢查。","synonyms":["completely","fully"],"level":4,"theme":"日常與一般"},{"word":"threat","pos":"n.","phonetic":"[θrɛt]","meaning":"威脅","definition":"a statement of intention to cause harm or damage","collocations":["pose a threat","death threat","under threat"],"example":"Pollution is a serious threat to the environment.","exampleZh":"污染是對環境的嚴重威脅。","synonyms":["danger"],"level":4,"theme":"日常與一般"},{"word":"threaten","pos":"v.","phonetic":"[ˈθrɛtn̩]","meaning":"威脅","definition":"to express an intention to harm someone","collocations":["threaten to","be threatened by"],"example":"He threatened to quit if he didn't get a raise.","exampleZh":"他威脅如果不加薪就要辭職。","synonyms":["warn","intimidate"],"level":4,"theme":"日常與一般"},{"word":"threshold","pos":"n.","phonetic":"[ˈθrɛʃhold]","meaning":"門檻；起點；界限","definition":"the entrance to a room or building, or the point at which something begins","collocations":["cross the threshold","a pain threshold","on the threshold of"],"example":"She stood on the threshold, hesitant to enter.","exampleZh":"她站在門檻上,猶豫著要不要進去。","synonyms":["doorway","entrance"],"level":5,"theme":"日常與一般"},{"word":"thrive","pos":"v.","phonetic":"[θraɪv]","meaning":"蓬勃發展；茁壯","definition":"to grow and be very successful","collocations":["businesses thrive","thrive on competition"],"example":"Local shops thrive thanks to the weekend farmers' market.","exampleZh":"拜週末農夫市集之賜，當地商家生意興隆。","synonyms":["flourish","prosper"],"level":5,"theme":"企業經營"},{"word":"through","pos":"prep.","phonetic":"[θru]","meaning":"穿過；透過","definition":"moving in one side of something and out the other","collocations":["go through","through the window","look through"],"example":"Sunlight streamed through the window.","exampleZh":"陽光透過窗戶照射進來。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"throughout","pos":"prep.","phonetic":"[θruˈaʊt]","meaning":"遍及；自始至終","definition":"during the whole period of time, or in every part of a place","collocations":["throughout the year","throughout the country"],"example":"The festival is celebrated throughout the country.","exampleZh":"這個節日在全國各地都會慶祝。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"thus","pos":"adv.","phonetic":"[ðʌs]","meaning":"因此；如此","definition":"as a result of this; in this way","collocations":["thus far","and thus"],"example":"The road was closed, thus causing heavy traffic.","exampleZh":"道路封閉，因此造成嚴重塞車。","synonyms":["therefore"],"level":4,"theme":"溝通與語言"},{"word":"ticket","pos":"n.","phonetic":"[ˈtɪkɪt]","meaning":"票；罰單","definition":"a piece of paper showing payment for entry, travel, or a fine","collocations":["buy a ticket","movie ticket","parking ticket"],"example":"I bought two tickets for the concert.","exampleZh":"我買了兩張演唱會的票。","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"tie","pos":"v. / n.","phonetic":"[taɪ]","meaning":"綁；領帶；平局","definition":"to fasten with string or rope; a piece of clothing worn around the neck; an equal result","collocations":["tie a knot","wear a tie","end in a tie"],"example":"He wore a blue tie to the interview.","exampleZh":"他穿了藍色領帶去面試。","synonyms":["fasten","bind"],"level":2,"theme":"購物與消費"},{"word":"tight","pos":"adj.","phonetic":"[taɪt]","meaning":"緊的","definition":"fitting closely; not loose","collocations":["tight schedule","tight clothes","hold tight"],"example":"These shoes feel too tight.","exampleZh":"這雙鞋感覺太緊了。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"tighten","pos":"v.","phonetic":"[ˈtaɪtn]","meaning":"收緊；加強","definition":"to make something firmer or stricter","collocations":["tighten security","tighten the budget","tighten a screw"],"example":"The airport tightened security ahead of the holiday rush.","exampleZh":"機場在假期人潮前加強了安檢。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"tile","pos":"n.","phonetic":"[taɪl]","meaning":"磁磚；瓦片","definition":"a flat piece of material used to cover floors, walls, or roofs","collocations":["floor tile","roof tile","ceramic tile"],"example":"The bathroom floor is covered with white tiles.","exampleZh":"浴室地板鋪滿了白色磁磚。","synonyms":[],"level":3,"theme":"房產與設施"},{"word":"time","pos":"n.","phonetic":"[taɪm]","meaning":"時間","definition":"the ongoing and continuous progress of events","collocations":["on time","spend time","in time"],"example":"We arrived just in time for the meeting.","exampleZh":"我們正好準時趕上會議。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"timeline","pos":"n.","phonetic":"[ˈtaɪmˌlaɪn]","meaning":"時間表；時程","definition":"a plan showing when stages of a project will happen","collocations":["project timeline","tight timeline","set a timeline"],"example":"The construction timeline calls for completion by December.","exampleZh":"工程時程規劃於十二月前完工。","synonyms":["schedule"],"level":5,"theme":"企業經營"},{"word":"timely","pos":"adj.","phonetic":"[ˈtaɪmlɪ]","meaning":"及時的；適時的","definition":"happening at exactly the right time","collocations":["timely manner","timely delivery","timely reminder"],"example":"Please respond to client emails in a timely manner.","exampleZh":"請及時回覆客戶的電子郵件。","synonyms":["prompt"],"level":5,"theme":"辦公室與行政"},{"word":"timetable","pos":"n.","phonetic":"[ˈtaɪmˌtebl]","meaning":"時刻表；時間表","definition":"a list showing when events, buses, or trains happen","collocations":["train timetable","check the timetable","revised timetable"],"example":"The revised bus timetable takes effect next Monday.","exampleZh":"新版公車時刻表下週一起生效。","synonyms":["schedule"],"level":3,"theme":"旅遊與交通"},{"word":"timing","pos":"n.","phonetic":"[ˈtaɪmɪŋ]","meaning":"時機；時間掌握","definition":"the choice of when something happens","collocations":["perfect timing","the timing of the launch","bad timing"],"example":"The timing of the product launch was planned around the trade show.","exampleZh":"產品上市的時機是配合商展規劃的。","synonyms":[],"level":4,"theme":"行銷與銷售"},{"word":"tiny","pos":"adj.","phonetic":"[ˈtaɪnɪ]","meaning":"微小的","definition":"extremely small in size","collocations":["tiny amount","tiny house","tiny bit"],"example":"The kitten is tiny and adorable.","exampleZh":"這隻小貓非常小又可愛。","synonyms":["small","little"],"level":1,"theme":"日常與一般"},{"word":"tip","pos":"n. / v.","phonetic":"[tɪp]","meaning":"尖端；小費；建議","definition":"the pointed end of something; money given for service; a piece of advice","collocations":["give a tip","tip of the iceberg","useful tips"],"example":"He gave the waiter a generous tip.","exampleZh":"他給了服務生一筆豐厚的小費。","synonyms":["gratuity","advice"],"level":2,"theme":"財務與會計"},{"word":"tire","pos":"v. / n.","phonetic":"[taɪr]","meaning":"使疲倦；輪胎","definition":"to make someone weary, or a rubber ring fitted around a wheel","collocations":["tire easily","flat tire","tire out"],"example":"The long hike tired us out.","exampleZh":"這場長途健行讓我們累壞了。","synonyms":["exhaust"],"level":2,"theme":"醫療與保險"},{"word":"tired","pos":"adj.","phonetic":"[taɪrd]","meaning":"疲倦的","definition":"feeling in need of rest or sleep","collocations":["feel tired","tired of","get tired"],"example":"I feel very tired after work.","exampleZh":"下班後我感覺非常疲倦。","synonyms":["exhausted","sleepy"],"level":1,"theme":"醫療與保險"},{"word":"tissue","pos":"n.","phonetic":"[ˈtɪʃu]","meaning":"面紙；組織(生物)","definition":"soft paper used for wiping, or a group of similar cells in a body","collocations":["tissue paper","blow one's nose with a tissue"],"example":"She wiped her tears with a tissue.","exampleZh":"她用面紙擦掉眼淚。","synonyms":[],"level":3,"theme":"醫療與保險"},{"word":"title","pos":"n.","phonetic":"[ˈtaɪtḷ]","meaning":"標題；頭銜","definition":"the name of a book, film, or a word showing a person's rank","collocations":["book title","win the title","job title"],"example":"What is the title of this novel?","exampleZh":"這本小說的書名是什麼？","synonyms":["name","heading"],"level":2,"theme":"媒體與活動"},{"word":"today","pos":"adv. / n.","phonetic":"[təˈde]","meaning":"今天","definition":"on or during this present day","collocations":["today's news","until today"],"example":"What day is it today?","exampleZh":"今天是星期幾？","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"together","pos":"adv.","phonetic":"[təˈgɛðɚ]","meaning":"一起","definition":"with or near each other; jointly","collocations":["work together","get together","live together"],"example":"We studied together for the exam.","exampleZh":"我們一起讀書準備考試。","synonyms":["jointly"],"level":1,"theme":"日常與一般"},{"word":"token","pos":"n./adj.","phonetic":"[ˈtokən]","meaning":"代幣；象徵；象徵性的","definition":"a coin substitute, or a small sign of something","collocations":["as a token of appreciation","token gesture","subway token"],"example":"Please accept this gift as a token of our appreciation.","exampleZh":"請收下這份禮物，聊表我們的謝意。","synonyms":["symbol"],"level":5,"theme":"日常與一般"},{"word":"toll","pos":"n.","phonetic":"[tol]","meaning":"通行費；傷亡人數；代價","definition":"money paid to use a road or bridge, or the damage caused","collocations":["toll road","toll booth","take a toll on"],"example":"The new highway toll can be paid electronically.","exampleZh":"新的高速公路通行費可以電子支付。","synonyms":["fee","charge"],"level":4,"theme":"旅遊與交通"},{"word":"toll-free","pos":"adj./adv.","phonetic":"[ˈtolˈfri]","meaning":"免付費的（電話）","definition":"describing a phone call that costs nothing for the caller","collocations":["toll-free number","call toll-free"],"example":"Call our toll-free number for assistance with your order.","exampleZh":"訂單如需協助，請撥打我們的免付費專線。","synonyms":[],"level":5,"theme":"科技與通訊"},{"word":"tomorrow","pos":"n. / adv.","phonetic":"[təˈmɑro]","meaning":"明天；未來","definition":"the day after today","collocations":["tomorrow morning","see you tomorrow","tomorrow's weather"],"example":"We will meet again tomorrow.","exampleZh":"我們明天再見面。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"tone","pos":"n.","phonetic":"[ton]","meaning":"語氣；音調","definition":"the quality of a sound or the way a person speaks, showing feeling","collocations":["tone of voice","polite tone","change one's tone"],"example":"She spoke in a calm tone.","exampleZh":"她用平靜的語氣說話。","synonyms":[],"level":4,"theme":"溝通與語言"},{"word":"tonight","pos":"adv. / n.","phonetic":"[təˈnaɪt]","meaning":"今晚","definition":"on the night of the present day","collocations":["tonight's dinner","see you tonight"],"example":"We are going to a movie tonight.","exampleZh":"我們今晚要去看電影。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"tool","pos":"n.","phonetic":"[tul]","meaning":"工具","definition":"a device used to carry out a particular task","collocations":["use a tool","tool box","power tool"],"example":"A hammer is a useful tool for this job.","exampleZh":"鎚子是做這項工作的實用工具。","synonyms":["instrument"],"level":1,"theme":"科技與通訊"},{"word":"top","pos":"n. / adj.","phonetic":"[tɑp]","meaning":"頂端；最高的","definition":"the highest point or part of something","collocations":["on top of","top student","reach the top"],"example":"We finally reached the top of the mountain.","exampleZh":"我們終於到達山頂。","synonyms":["peak","summit"],"level":1,"theme":"日常與一般"},{"word":"topic","pos":"n.","phonetic":"[ˈtɑpɪk]","meaning":"主題；話題","definition":"a subject discussed in a conversation, essay, or lecture","collocations":["discuss a topic","hot topic","choose a topic"],"example":"The topic of today's lecture is climate change.","exampleZh":"今天演講的主題是氣候變遷。","synonyms":["subject"],"level":3,"theme":"人事與職涯"},{"word":"total","pos":"adj. / n.","phonetic":"[ˈtotḷ]","meaning":"總共的；總數","definition":"complete, or the whole amount of something","collocations":["total amount","in total","total cost"],"example":"The total cost of the trip was quite high.","exampleZh":"這趟旅行的總花費相當高。","synonyms":["whole","entire"],"level":2,"theme":"財務與會計"},{"word":"touch","pos":"v. / n.","phonetic":"[tʌtʃ]","meaning":"觸摸；接觸","definition":"to put one's hand or fingers on something","collocations":["touch screen","keep in touch","touch base"],"example":"Please don't touch the wet paint.","exampleZh":"請不要碰觸未乾的油漆。","synonyms":["feel"],"level":1,"theme":"日常與一般"},{"word":"tough","pos":"adj.","phonetic":"[tʌf]","meaning":"堅韌的；困難的","definition":"strong and difficult to break, or difficult to deal with","collocations":["tough decision","tough meat","tough time"],"example":"It was a tough decision to make.","exampleZh":"這是一個困難的決定。","synonyms":["hard","difficult"],"level":3,"theme":"日常與一般"},{"word":"tour","pos":"n. / v.","phonetic":"[tʊr]","meaning":"旅行；巡迴","definition":"a journey for pleasure in which several places are visited","collocations":["guided tour","world tour","tour guide"],"example":"We took a guided tour of the museum.","exampleZh":"我們參加了博物館的導覽行程。","synonyms":["trip"],"level":2,"theme":"旅遊與交通"},{"word":"tourism","pos":"n.","phonetic":"[ˈtʊrɪzəm]","meaning":"觀光業；旅遊業","definition":"the business of providing services for tourists","collocations":["tourism industry","promote tourism","eco-tourism"],"example":"Tourism accounts for a large share of the island's economy.","exampleZh":"觀光業在該島經濟中占很大比重。","synonyms":[],"level":4,"theme":"旅遊與交通"},{"word":"tourist","pos":"n.","phonetic":"[ˈtʊrɪst]","meaning":"觀光客；遊客","definition":"a person who travels for pleasure","collocations":["tourist attraction","foreign tourist","tourist season"],"example":"The city is full of tourists in summer.","exampleZh":"夏天這座城市擠滿了觀光客。","synonyms":["traveler","visitor"],"level":2,"theme":"旅遊與交通"},{"word":"tournament","pos":"n.","phonetic":"[ˈtɝnəmənt]","meaning":"錦標賽；比賽","definition":"a competition with a series of games","collocations":["golf tournament","host a tournament","charity tournament"],"example":"The company sponsors an annual charity golf tournament.","exampleZh":"公司每年贊助一場慈善高爾夫錦標賽。","synonyms":["competition"],"level":3,"theme":"媒體與活動"},{"word":"tow","pos":"v./n.","phonetic":"[to]","meaning":"拖吊；拖曳","definition":"to pull a vehicle using another vehicle or a rope","collocations":["tow a car","tow truck","towed away"],"example":"Illegally parked vehicles will be towed at the owner's expense.","exampleZh":"違規停放車輛將被拖吊，費用由車主負擔。","synonyms":["haul","pull"],"level":4,"theme":"旅遊與交通"},{"word":"toward","pos":"prep.","phonetic":"[tɔrd]","meaning":"朝向；對於","definition":"in the direction of","collocations":["move toward","attitude toward","walk toward"],"example":"She walked toward the exit.","exampleZh":"她朝出口走去。","synonyms":["towards"],"level":2,"theme":"日常與一般"},{"word":"tower","pos":"n.","phonetic":"[ˈtaʊɚ]","meaning":"塔；高樓","definition":"a tall, narrow building or structure","collocations":["clock tower","control tower","tower block"],"example":"The clock tower stands in the city center.","exampleZh":"這座鐘塔矗立在市中心。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"town","pos":"n.","phonetic":"[taʊn]","meaning":"城鎮","definition":"a populated area smaller than a city","collocations":["small town","town hall","go into town"],"example":"They live in a small town near the coast.","exampleZh":"他們住在海邊的一個小鎮。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"trace","pos":"v. / n.","phonetic":"[tres]","meaning":"追蹤；痕跡","definition":"to find or discover by investigation; a mark left by something","collocations":["trace back","without a trace","trace an email"],"example":"Police traced the call to an apartment downtown.","exampleZh":"警方追蹤這通電話到市區的一間公寓。","synonyms":["track"],"level":4,"theme":"科技與通訊"},{"word":"track","pos":"n. / v.","phonetic":"[træk]","meaning":"軌道；追蹤","definition":"a rough path or road; to follow the course of something","collocations":["track record","keep track of","railroad track"],"example":"We need to keep track of our expenses.","exampleZh":"我們需要追蹤我們的開銷。","synonyms":["path","trail"],"level":2,"theme":"旅遊與交通"},{"word":"trade","pos":"n. / v.","phonetic":"[tred]","meaning":"貿易；交易","definition":"the action of buying and selling goods and services","collocations":["free trade","trade agreement","trade with"],"example":"The two countries signed a new trade agreement.","exampleZh":"這兩國簽署了一項新的貿易協定。","synonyms":["commerce"],"level":3,"theme":"財務與會計"},{"word":"trade-off","pos":"n.","phonetic":"[ˈtredˌɔf]","meaning":"取捨；權衡","definition":"a balance between two things where you give up one to gain the other","collocations":["trade-off between","make a trade-off"],"example":"There is always a trade-off between cost and quality.","exampleZh":"成本與品質之間總是需要取捨。","synonyms":["compromise"],"level":6,"theme":"企業經營"},{"word":"trademark","pos":"n./v.","phonetic":"[ˈtredˌmɑrk]","meaning":"商標；註冊商標","definition":"a name or symbol legally registered to a company","collocations":["registered trademark","trademark infringement","file a trademark"],"example":"The logo is a registered trademark and may not be copied.","exampleZh":"此標誌為註冊商標，不得複製。","synonyms":["brand"],"level":5,"theme":"合約與法律"},{"word":"tradition","pos":"n.","phonetic":"[trəˈdɪʃən]","meaning":"傳統","definition":"a custom or belief passed down through generations","collocations":["family tradition","break tradition","follow tradition"],"example":"It is a family tradition to gather for dinner every Sunday.","exampleZh":"每週日聚餐是我們家的傳統。","synonyms":["custom"],"level":3,"theme":"日常與一般"},{"word":"traditional","pos":"adj.","phonetic":"[trəˈdɪʃənl̩]","meaning":"傳統的","definition":"existing in or as part of a tradition; long-established","collocations":["traditional culture","traditional clothing","traditional festival"],"example":"They celebrated the festival in traditional costumes.","exampleZh":"他們穿著傳統服飾慶祝節日。","synonyms":["conventional"],"level":3,"theme":"日常與一般"},{"word":"traffic","pos":"n.","phonetic":"[ˈtræfɪk]","meaning":"交通；交通量","definition":"the movement of vehicles or people on roads","collocations":["traffic jam","heavy traffic","traffic light"],"example":"We were stuck in traffic for two hours.","exampleZh":"我們塞在車陣中兩個小時。","synonyms":[],"level":2,"theme":"旅遊與交通"},{"word":"trailer","pos":"n.","phonetic":"[ˈtrelɚ]","meaning":"拖車；預告片","definition":"a vehicle pulled by another, or a short film advertisement","collocations":["truck trailer","movie trailer","trailer park"],"example":"The trailer was loaded with furniture for the trade show booth.","exampleZh":"拖車上載滿了商展攤位用的家具。","synonyms":[],"level":4,"theme":"生產與物流"},{"word":"train","pos":"n. / v.","phonetic":"[tren]","meaning":"火車；訓練","definition":"a series of connected railway carriages; to teach a skill","collocations":["catch a train","train hard","train employees"],"example":"She trains every morning before school.","exampleZh":"她每天上學前都會訓練。","synonyms":["coach"],"level":1,"theme":"旅遊與交通"},{"word":"trainee","pos":"n.","phonetic":"[treˈni]","meaning":"受訓人員；實習生","definition":"a person learning the skills for a job","collocations":["management trainee","trainee program"],"example":"Each trainee spends one month in the customer service department.","exampleZh":"每位儲備人員都要在客服部門受訓一個月。","synonyms":["apprentice","intern"],"level":4,"theme":"人事與職涯"},{"word":"trainer","pos":"n.","phonetic":"[ˈtrenɚ]","meaning":"教練；訓練員","definition":"a person who trains people or animals","collocations":["personal trainer","dog trainer","fitness trainer"],"example":"Her personal trainer helped her lose weight.","exampleZh":"她的私人教練幫助她減重。","synonyms":["coach"],"level":2,"theme":"媒體與活動"},{"word":"training","pos":"n.","phonetic":"[ˈtreniŋ]","meaning":"訓練；培訓","definition":"the action of teaching a person a particular skill","collocations":["job training","training program","military training"],"example":"New employees must complete safety training.","exampleZh":"新進員工必須完成安全訓練。","synonyms":["coaching"],"level":2,"theme":"人事與職涯"},{"word":"trait","pos":"n.","phonetic":"[tret]","meaning":"特質；特徵","definition":"a distinguishing quality or characteristic","collocations":["personality trait","genetic trait","common trait"],"example":"Honesty is one of his best traits.","exampleZh":"誠實是他最好的特質之一。","synonyms":["characteristic"],"level":5,"theme":"日常與一般"},{"word":"transaction","pos":"n.","phonetic":"[trænˈzækʃən]","meaning":"交易；買賣","definition":"an act of buying or selling, or a piece of business","collocations":["cash transaction","process a transaction","transaction fee"],"example":"A small fee applies to all international transactions.","exampleZh":"所有跨國交易均酌收小額手續費。","synonyms":["deal"],"level":4,"theme":"財務與會計"},{"word":"transcript","pos":"n.","phonetic":"[ˈtrænˌskrɪpt]","meaning":"成績單；逐字稿","definition":"an official record of grades, or a written record of spoken words","collocations":["official transcript","transcript of the interview"],"example":"Applicants must submit official transcripts from their universities.","exampleZh":"應徵者必須繳交大學的正式成績單。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"transfer","pos":"v. / n.","phonetic":"[trænsˈfɝ]","meaning":"轉移；轉學；轉乘","definition":"to move from one place, position, or situation to another","collocations":["transfer money","transfer schools","train transfer"],"example":"He transferred to a new school last year.","exampleZh":"他去年轉學到一所新學校。","synonyms":["move","shift"],"level":3,"theme":"人事與職涯"},{"word":"transform","pos":"v.","phonetic":"[trænsˈfɔrm]","meaning":"轉變；使變形","definition":"to make a marked change in the form or nature of something","collocations":["transform into","completely transform","transform a room"],"example":"The internet has transformed the way we communicate.","exampleZh":"網路已經改變了我們溝通的方式。","synonyms":["change"],"level":4,"theme":"科技與通訊"},{"word":"transformation","pos":"n.","phonetic":"[ˌtrænsfɚˈmeʃən]","meaning":"轉型；蛻變","definition":"a complete change in form or character","collocations":["digital transformation","undergo a transformation"],"example":"The retailer is undergoing a major digital transformation.","exampleZh":"這家零售商正在進行大規模的數位轉型。","synonyms":["change","makeover"],"level":5,"theme":"企業經營"},{"word":"transit","pos":"n.","phonetic":"[ˈtrænsɪt]","meaning":"運輸；過境；大眾運輸","definition":"the movement of people or goods from one place to another","collocations":["in transit","public transit","transit system"],"example":"The package was damaged in transit and will be replaced.","exampleZh":"包裹在運送途中受損，將予以更換。","synonyms":["transportation"],"level":5,"theme":"旅遊與交通"},{"word":"transition","pos":"n.","phonetic":"[trænˈzɪʃən]","meaning":"轉變；過渡","definition":"the process of changing from one state to another","collocations":["transition period","smooth transition","transition into adulthood"],"example":"The transition from school to work can be difficult.","exampleZh":"從學校到職場的轉變可能很困難。","synonyms":["change"],"level":5,"theme":"日常與一般"},{"word":"translate","pos":"v.","phonetic":"[trænsˈlet]","meaning":"翻譯","definition":"to express the meaning of text or speech in another language","collocations":["translate into","translate a document","translate for someone"],"example":"Can you translate this letter into English?","exampleZh":"你能把這封信翻譯成英文嗎？","synonyms":["interpret"],"level":3,"theme":"溝通與語言"},{"word":"translation","pos":"n.","phonetic":"[trænsˈleʃən]","meaning":"翻譯；譯文","definition":"the process of translating words or text into another language","collocations":["English translation","machine translation","literal translation"],"example":"She works as a translation editor for a publisher.","exampleZh":"她在出版社擔任翻譯編輯。","synonyms":[],"level":3,"theme":"溝通與語言"},{"word":"translator","pos":"n.","phonetic":"[trænsˈletɚ]","meaning":"譯者；翻譯人員","definition":"a person who changes written words from one language to another","collocations":["professional translator","freelance translator"],"example":"The contract was reviewed by a certified legal translator.","exampleZh":"這份合約由合格的法律譯者審閱。","synonyms":["interpreter"],"level":4,"theme":"溝通與語言"},{"word":"transmission","pos":"n.","phonetic":"[trænsˈmɪʃən]","meaning":"傳輸；傳送；變速箱","definition":"the process of sending signals or the gear system of a vehicle","collocations":["data transmission","live transmission","automatic transmission"],"example":"Encrypted transmission keeps customer data safe online.","exampleZh":"加密傳輸確保顧客資料在線上的安全。","synonyms":[],"level":5,"theme":"科技與通訊"},{"word":"transmit","pos":"v.","phonetic":"[trænsˈmɪt]","meaning":"傳送；傳播","definition":"to cause something to pass from one person, place, or thing to another","collocations":["transmit a signal","transmit disease","transmit data"],"example":"The virus can be transmitted through contact.","exampleZh":"這種病毒可以透過接觸傳播。","synonyms":["send"],"level":5,"theme":"科技與通訊"},{"word":"transparent","pos":"adj.","phonetic":"[trænsˈpɛrənt]","meaning":"透明的；坦誠的","definition":"allowing light to pass through so objects can be seen clearly; open and honest","collocations":["transparent glass","transparent process","completely transparent"],"example":"The company promised a more transparent decision-making process.","exampleZh":"該公司承諾決策過程會更加透明。","synonyms":["clear"],"level":5,"theme":"日常與一般"},{"word":"transport","pos":"v. / n.","phonetic":"[trænsˈpɔrt]","meaning":"運輸；運送","definition":"to take or carry goods or people from one place to another","collocations":["public transport","transport goods","means of transport"],"example":"The goods were transported by ship.","exampleZh":"這些貨物是由船運送的。","synonyms":["carry"],"level":3,"theme":"旅遊與交通"},{"word":"transportation","pos":"n.","phonetic":"[ˌtrænspɚˈteʃən]","meaning":"運輸；交通工具","definition":"the means of transporting or conveying goods or people","collocations":["public transportation","means of transportation","transportation system"],"example":"The city has an efficient public transportation system.","exampleZh":"這座城市擁有高效率的大眾運輸系統。","synonyms":[],"level":3,"theme":"旅遊與交通"},{"word":"travel","pos":"v. / n.","phonetic":"[ˈtrævl̩]","meaning":"旅行；行進","definition":"to make a journey, typically of some length","collocations":["travel abroad","travel agency","world travel"],"example":"They love to travel around the world.","exampleZh":"他們喜歡環遊世界旅行。","synonyms":["journey"],"level":1,"theme":"旅遊與交通"},{"word":"traveler","pos":"n.","phonetic":"[ˈtrævlɚ]","meaning":"旅行者","definition":"a person who travels","collocations":["frequent traveler","world traveler","traveler's check"],"example":"The traveler stayed at a small hostel.","exampleZh":"這位旅行者住在一家小型青年旅館。","synonyms":["tourist"],"level":2,"theme":"旅遊與交通"},{"word":"treat","pos":"v. / n.","phonetic":"[trit]","meaning":"對待；治療；款待","definition":"to behave toward someone in a certain way; to give medical care","collocations":["treat kindly","treat a disease","a special treat"],"example":"The doctor treated the patient's injury.","exampleZh":"醫生治療了病人的傷口。","synonyms":["handle"],"level":2,"theme":"醫療與保險"},{"word":"treatment","pos":"n.","phonetic":"[ˈtritmənt]","meaning":"治療；待遇","definition":"medical care given to a patient; the manner of dealing with someone","collocations":["medical treatment","receive treatment","fair treatment"],"example":"He is receiving treatment for his illness.","exampleZh":"他正在接受疾病治療。","synonyms":["therapy"],"level":3,"theme":"醫療與保險"},{"word":"trend","pos":"n.","phonetic":"[trɛnd]","meaning":"趨勢；潮流","definition":"a general direction in which something is developing or changing","collocations":["latest trend","fashion trend","upward trend"],"example":"There is a growing trend toward online shopping.","exampleZh":"線上購物的趨勢正逐漸增長。","synonyms":["tendency"],"level":3,"theme":"日常與一般"},{"word":"trial","pos":"n.","phonetic":"[ˈtraɪəl]","meaning":"審判；試驗","definition":"a formal examination of evidence in court; a test of performance","collocations":["stand trial","trial period","clinical trial"],"example":"The suspect will stand trial next month.","exampleZh":"這名嫌犯下個月將出庭受審。","synonyms":["test"],"level":4,"theme":"合約與法律"},{"word":"trip","pos":"n. / v.","phonetic":"[trɪp]","meaning":"旅行；絆倒","definition":"a journey or excursion; to stumble and almost fall","collocations":["go on a trip","business trip","trip over"],"example":"We are planning a trip to Japan next summer.","exampleZh":"我們正計劃明年夏天去日本旅行。","synonyms":["journey"],"level":1,"theme":"旅遊與交通"},{"word":"trouble","pos":"n. / v.","phonetic":"[ˈtrʌbl̩]","meaning":"麻煩；困擾","definition":"difficulty or problems; to cause distress","collocations":["get into trouble","have trouble with","trouble someone"],"example":"He got into trouble for skipping class.","exampleZh":"他因為蹺課而惹上麻煩。","synonyms":["problem"],"level":2,"theme":"日常與一般"},{"word":"truck","pos":"n.","phonetic":"[trʌk]","meaning":"卡車","definition":"a large motor vehicle used for transporting goods","collocations":["delivery truck","truck driver","load a truck"],"example":"The truck delivered furniture to the new house.","exampleZh":"這輛卡車把家具送到新房子。","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"truly","pos":"adv.","phonetic":"[ˈtruli]","meaning":"真正地；確實地","definition":"in a true, accurate, or sincere manner","collocations":["truly grateful","truly amazing","yours truly"],"example":"I am truly grateful for your help.","exampleZh":"我真心感激你的幫助。","synonyms":["genuinely"],"level":2,"theme":"日常與一般"},{"word":"trust","pos":"v. / n.","phonetic":"[trʌst]","meaning":"信任","definition":"firm belief in the reliability of someone or something","collocations":["trust someone","build trust","break trust"],"example":"I trust you to make the right decision.","exampleZh":"我相信你會做出正確的決定。","synonyms":["believe","faith"],"level":2,"theme":"日常與一般"},{"word":"trustworthy","pos":"adj.","phonetic":"[ˈtrʌstˌwɝðɪ]","meaning":"值得信賴的","definition":"able to be trusted and relied on","collocations":["trustworthy source","trustworthy partner"],"example":"We only buy parts from trustworthy, certified suppliers.","exampleZh":"我們只向值得信賴且經認證的供應商採購零件。","synonyms":["reliable","dependable"],"level":5,"theme":"企業經營"},{"word":"try","pos":"v. / n.","phonetic":"[traɪ]","meaning":"嘗試；試圖","definition":"to make an attempt or effort to do something","collocations":["try hard","try one's best","give it a try"],"example":"She tried her best to solve the problem.","exampleZh":"她盡了最大努力來解決這個問題。","synonyms":["attempt"],"level":1,"theme":"日常與一般"},{"word":"tuition","pos":"n.","phonetic":"[tuˈɪʃən]","meaning":"學費；教學","definition":"the fee charged for instruction, especially at a school or college","collocations":["pay tuition","tuition fee","tuition increase"],"example":"College tuition has risen sharply this year.","exampleZh":"今年大學學費大幅上漲。","synonyms":[],"level":5,"theme":"人事與職涯"},{"word":"turn","pos":"v. / n.","phonetic":"[tɝn]","meaning":"轉動；輪流","definition":"to move in a circular direction; a chance to do something in a sequence","collocations":["turn around","take turns","turn off"],"example":"Please take turns using the computer.","exampleZh":"請輪流使用電腦。","synonyms":["rotate"],"level":1,"theme":"日常與一般"},{"word":"turnover","pos":"n.","phonetic":"[ˈtɝnˌovɚ]","meaning":"營業額；人員流動率；翻轉","definition":"the amount of business done, or the rate at which staff leave and are replaced","collocations":["staff turnover","annual turnover","high turnover"],"example":"Better benefits helped reduce staff turnover by half.","exampleZh":"更好的福利讓人員流動率降低了一半。","synonyms":[],"level":6,"theme":"人事與職涯"},{"word":"tutor","pos":"n. / v.","phonetic":"[ˈtutɚ]","meaning":"家教；輔導老師","definition":"a private teacher who teaches a single student or a small group","collocations":["private tutor","hire a tutor","tutor a student"],"example":"He hired a math tutor to help his son.","exampleZh":"他請了一位數學家教來輔導兒子。","synonyms":["instructor"],"level":3,"theme":"人事與職涯"},{"word":"tutorial","pos":"n.","phonetic":"[tuˈtorɪəl]","meaning":"教學課程；使用教學","definition":"a lesson that teaches how to do or use something","collocations":["video tutorial","online tutorial","step-by-step tutorial"],"example":"A short video tutorial explains how to submit expense reports.","exampleZh":"一段簡短的教學影片說明如何提交費用報告。","synonyms":["lesson","guide"],"level":4,"theme":"科技與通訊"},{"word":"twice","pos":"adv.","phonetic":"[twaɪs]","meaning":"兩次；兩倍","definition":"two times","collocations":["twice a week","twice as much","think twice"],"example":"I go to the gym twice a week.","exampleZh":"我一週上健身房兩次。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"type","pos":"n. / v.","phonetic":"[taɪp]","meaning":"類型；打字","definition":"a category of things having common characteristics; to write using a keyboard","collocations":["type of","type a letter","different types"],"example":"Please type your name on the form.","exampleZh":"請在表格上打上你的名字。","synonyms":["kind"],"level":1,"theme":"科技與通訊"},{"word":"typical","pos":"adj.","phonetic":"[ˈtɪpɪkl̩]","meaning":"典型的；平常的","definition":"having the distinctive qualities of a particular type of person or thing","collocations":["typical example","a typical day","typical behavior"],"example":"That's typical of him to be late.","exampleZh":"他遲到真是他的典型作風。","synonyms":["standard"],"level":3,"theme":"日常與一般"},{"word":"typically","pos":"adv.","phonetic":"[ˈtɪpɪklɪ]","meaning":"通常；典型地","definition":"usually or in most cases","collocations":["typically takes","typically used"],"example":"Refunds typically take five to seven business days to process.","exampleZh":"退款通常需要五到七個工作天處理。","synonyms":["usually","generally"],"level":3,"theme":"日常與一般"},{"word":"ultimate","pos":"adj.","phonetic":"[ˈʌltəmɪt]","meaning":"最終的；根本的","definition":"being the final or best of its kind","collocations":["ultimate goal","the ultimate decision","ultimate success"],"example":"Winning the championship is our ultimate goal.","exampleZh":"贏得冠軍是我們最終的目標。","synonyms":["final","supreme"],"level":4,"theme":"日常與一般"},{"word":"ultimately","pos":"adv.","phonetic":"[ˈʌltəmɪtlɪ]","meaning":"最終；最後","definition":"in the end; finally","collocations":["ultimately fail","ultimately succeed","ultimately decide"],"example":"Ultimately, the choice is yours to make.","exampleZh":"最終，這個選擇由你來做。","synonyms":["eventually","finally"],"level":4,"theme":"日常與一般"},{"word":"umbrella","pos":"n.","phonetic":"[ʌmˈbrɛlə]","meaning":"雨傘","definition":"a device used for protection from rain","collocations":["open an umbrella","carry an umbrella","under an umbrella"],"example":"She forgot her umbrella and got soaked in the rain.","exampleZh":"她忘了帶傘，結果被雨淋濕了。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"unable","pos":"adj.","phonetic":"[ʌnˈebl̩]","meaning":"不能的；無法的","definition":"not having the ability or means to do something","collocations":["unable to attend","unable to move","unable to sleep"],"example":"He was unable to finish the race due to an injury.","exampleZh":"他因受傷無法完成比賽。","synonyms":["incapable"],"level":2,"theme":"日常與一般"},{"word":"unavailable","pos":"adj.","phonetic":"[ˌʌnəˈveləbl]","meaning":"無法取得的；沒空的","definition":"not able to be used, bought, or met","collocations":["currently unavailable","temporarily unavailable"],"example":"The manager is unavailable until Thursday afternoon.","exampleZh":"經理週四下午之前都沒有空。","synonyms":[],"level":4,"theme":"辦公室與行政"},{"word":"uncertain","pos":"adj.","phonetic":"[ʌnˈsɝtn̩]","meaning":"不確定的；猶豫的","definition":"not known or definite; not sure","collocations":["uncertain future","feel uncertain","remain uncertain"],"example":"The future of the company remains uncertain.","exampleZh":"這家公司的未來仍不確定。","synonyms":["unsure","doubtful"],"level":3,"theme":"日常與一般"},{"word":"uncover","pos":"v.","phonetic":"[ʌnˈkʌvɚ]","meaning":"揭露；發現","definition":"to discover something hidden or secret","collocations":["uncover the truth","uncover problems","uncover evidence"],"example":"The audit uncovered several accounting irregularities.","exampleZh":"稽核揭露了幾處帳務異常。","synonyms":["reveal","discover"],"level":5,"theme":"財務與會計"},{"word":"under","pos":"prep.","phonetic":"[ˈʌndɚ]","meaning":"在……之下；少於","definition":"in or to a position below or lower than something","collocations":["under the table","under pressure","under control"],"example":"The cat is sleeping under the bed.","exampleZh":"貓正在床底下睡覺。","synonyms":["below"],"level":1,"theme":"日常與一般"},{"word":"undergo","pos":"v.","phonetic":"[ˌʌndɚˈgo]","meaning":"經歷；接受（檢查、手術等）","definition":"to experience a process, especially one that changes you","collocations":["undergo renovation","undergo training","undergo testing"],"example":"All products undergo strict quality testing before shipment.","exampleZh":"所有產品出貨前都經過嚴格的品質測試。","synonyms":["experience"],"level":5,"theme":"生產與物流"},{"word":"understand","pos":"v.","phonetic":"[ˌʌndɚˈstænd]","meaning":"了解；懂得","definition":"to grasp the meaning of something","collocations":["understand a concept","fully understand","hard to understand"],"example":"I don't fully understand the instructions.","exampleZh":"我不太懂這些指示。","synonyms":["comprehend"],"level":1,"theme":"人事與職涯"},{"word":"understanding","pos":"n. / adj.","phonetic":"[ˌʌndɚˈstændɪŋ]","meaning":"理解；諒解；體諒的","definition":"the ability to understand something, or being sympathetic","collocations":["mutual understanding","reach an understanding","an understanding friend"],"example":"They finally reached a mutual understanding.","exampleZh":"他們終於達成了共識。","synonyms":["comprehension"],"level":3,"theme":"溝通與語言"},{"word":"undertake","pos":"v.","phonetic":"[ˌʌndɚˈtek]","meaning":"承擔；著手做","definition":"to commit to and start a task","collocations":["undertake a project","undertake a task","undertake responsibility"],"example":"The team will undertake a new research project.","exampleZh":"這個團隊將著手進行一項新的研究計畫。","synonyms":["carry out"],"level":5,"theme":"人事與職涯"},{"word":"underway","pos":"adj.","phonetic":"[ˌʌndɚˈwe]","meaning":"進行中的","definition":"already started and in progress","collocations":["well underway","get underway","currently underway"],"example":"Preparations for the annual conference are already underway.","exampleZh":"年度大會的籌備工作已經展開。","synonyms":["in progress"],"level":5,"theme":"辦公室與行政"},{"word":"unemployment","pos":"n.","phonetic":"[ˌʌnɪmˈplɔɪmənt]","meaning":"失業；失業率","definition":"the state of being without a job","collocations":["unemployment rate","rising unemployment","unemployment benefits"],"example":"The unemployment rate dropped last month.","exampleZh":"失業率上個月下降了。","synonyms":[],"level":4,"theme":"財務與會計"},{"word":"unexpected","pos":"adj.","phonetic":"[ˌʌnɪkˈspɛktɪd]","meaning":"意外的；預料之外的","definition":"not expected or anticipated","collocations":["an unexpected visit","unexpected result","unexpected news"],"example":"We had an unexpected visit from our old friend.","exampleZh":"我們的老朋友意外來訪。","synonyms":["surprising"],"level":3,"theme":"日常與一般"},{"word":"unfortunately","pos":"adv.","phonetic":"[ʌnˈfɔrtʃənɪtlɪ]","meaning":"不幸地；可惜地","definition":"unluckily; regrettably","collocations":["unfortunately for us","but unfortunately","unfortunately not"],"example":"Unfortunately, the flight was canceled due to the storm.","exampleZh":"不幸的是，班機因暴風雨被取消了。","synonyms":["sadly"],"level":3,"theme":"日常與一般"},{"word":"uniform","pos":"n. / adj.","phonetic":"[ˈjunəˌfɔrm]","meaning":"制服；一致的","definition":"a distinctive set of clothes for members of a group; consistent","collocations":["school uniform","wear a uniform","uniform standard"],"example":"Students must wear their school uniform every day.","exampleZh":"學生每天都必須穿校服。","synonyms":["consistent"],"level":2,"theme":"購物與消費"},{"word":"union","pos":"n.","phonetic":"[ˈjunjən]","meaning":"聯盟；工會；結合","definition":"an act of joining or a group joined together, such as a labor union","collocations":["labor union","form a union","trade union"],"example":"Workers formed a union to protect their rights.","exampleZh":"工人們組成工會來保障自己的權益。","synonyms":["alliance"],"level":4,"theme":"日常與一般"},{"word":"unique","pos":"adj.","phonetic":"[juˈnik]","meaning":"獨特的；獨一無二的","definition":"being the only one of its kind","collocations":["unique style","unique opportunity","truly unique"],"example":"Each snowflake has a unique pattern.","exampleZh":"每片雪花都有獨特的圖案。","synonyms":["distinctive"],"level":4,"theme":"日常與一般"},{"word":"unit","pos":"n.","phonetic":"[ˈjunɪt]","meaning":"單位；單元","definition":"a single, standard, or complete part of something larger","collocations":["a unit of measurement","study unit","housing unit"],"example":"This lesson is the first unit of the textbook.","exampleZh":"這一課是課本的第一單元。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"university","pos":"n.","phonetic":"[ˌjunəˈvɝsətɪ]","meaning":"大學","definition":"an institution of higher education","collocations":["attend university","university degree","apply to university"],"example":"She is studying law at a famous university.","exampleZh":"她在一所知名大學攻讀法律。","synonyms":[],"level":1,"theme":"人事與職涯"},{"word":"unless","pos":"conj.","phonetic":"[ənˈlɛs]","meaning":"除非","definition":"except on the condition that","collocations":["unless otherwise noted","unless you agree","unless it rains"],"example":"We won't go hiking unless the weather improves.","exampleZh":"除非天氣好轉，否則我們不會去健行。","synonyms":["except if"],"level":2,"theme":"溝通與語言"},{"word":"unlike","pos":"prep. / adj.","phonetic":"[ʌnˈlaɪk]","meaning":"不像；與……不同","definition":"different from; not like","collocations":["unlike his brother","unlike before","quite unlike"],"example":"Unlike her sister, she loves spicy food.","exampleZh":"和她姊姊不同，她喜歡辣的食物。","synonyms":["different from"],"level":2,"theme":"日常與一般"},{"word":"unlikely","pos":"adj.","phonetic":"[ʌnˈlaɪklɪ]","meaning":"不太可能的","definition":"not likely to happen or be true","collocations":["unlikely event","highly unlikely","unlikely to succeed"],"example":"It is unlikely to rain this afternoon.","exampleZh":"今天下午不太可能會下雨。","synonyms":["improbable"],"level":4,"theme":"日常與一般"},{"word":"unlimited","pos":"adj.","phonetic":"[ʌnˈlɪmɪtɪd]","meaning":"無限制的；不限量的","definition":"without any limit","collocations":["unlimited access","unlimited data","unlimited refills"],"example":"Members enjoy unlimited access to all online courses.","exampleZh":"會員可無限使用所有線上課程。","synonyms":[],"level":4,"theme":"行銷與銷售"},{"word":"unload","pos":"v.","phonetic":"[ʌnˈlod]","meaning":"卸貨；卸下","definition":"to remove goods from a vehicle or container","collocations":["unload cargo","unload a truck","unload luggage"],"example":"The workers unloaded the boxes from the truck.","exampleZh":"工人們把箱子從卡車上卸下來。","synonyms":["unpack"],"level":3,"theme":"旅遊與交通"},{"word":"unrelated","pos":"adj.","phonetic":"[ˌʌnrɪˈletɪd]","meaning":"無關的","definition":"not connected with something","collocations":["unrelated to","completely unrelated"],"example":"The system outage was unrelated to yesterday's update.","exampleZh":"系統中斷與昨天的更新無關。","synonyms":[],"level":4,"theme":"日常與一般"},{"word":"until","pos":"prep. / conj.","phonetic":"[ənˈtɪl]","meaning":"直到……為止","definition":"up to the point in time or the event mentioned","collocations":["until now","wait until","until further notice"],"example":"We waited until the rain stopped.","exampleZh":"我們一直等到雨停了。","synonyms":["till"],"level":1,"theme":"日常與一般"},{"word":"unusual","pos":"adj.","phonetic":"[ʌnˈjuʒʊəl]","meaning":"不尋常的；罕見的","definition":"not common or ordinary","collocations":["unusual weather","unusual behavior","rather unusual"],"example":"It's unusual for him to be late for school.","exampleZh":"他上學遲到是很不尋常的事。","synonyms":["uncommon"],"level":2,"theme":"日常與一般"},{"word":"up-to-date","pos":"adj.","phonetic":"[ˈʌptəˈdet]","meaning":"最新的；跟上時代的","definition":"including the most recent information","collocations":["up-to-date information","keep records up-to-date"],"example":"Please keep your contact information up-to-date in the system.","exampleZh":"請在系統中隨時更新您的聯絡資料。","synonyms":["current"],"level":4,"theme":"辦公室與行政"},{"word":"upcoming","pos":"adj.","phonetic":"[ˈʌpˌkʌmɪŋ]","meaning":"即將到來的","definition":"happening soon","collocations":["upcoming events","upcoming release","upcoming meeting"],"example":"Check the calendar for upcoming training sessions.","exampleZh":"請查看行事曆了解近期的訓練課程。","synonyms":["forthcoming"],"level":4,"theme":"媒體與活動"},{"word":"update","pos":"v. / n.","phonetic":"[ˌʌpˈdet]","meaning":"更新；最新消息","definition":"to make something more modern or add the latest information","collocations":["update software","give an update","regularly update"],"example":"Please update your app to the latest version.","exampleZh":"請將你的應用程式更新到最新版本。","synonyms":["renew"],"level":3,"theme":"科技與通訊"},{"word":"upgrade","pos":"v. / n.","phonetic":"[ʌpˈgred]","meaning":"升級；提升","definition":"to improve the quality or value of something","collocations":["upgrade a computer","free upgrade","upgrade the system"],"example":"We decided to upgrade our computer system.","exampleZh":"我們決定升級我們的電腦系統。","synonyms":["improve"],"level":4,"theme":"科技與通訊"},{"word":"upon","pos":"prep.","phonetic":"[əˈpɑn]","meaning":"在……之上；一……就","definition":"on; used similarly to 'on' but more formal","collocations":["upon arrival","once upon a time","depend upon"],"example":"Once upon a time, there lived a kind old man.","exampleZh":"從前，有一位善良的老人。","synonyms":["on"],"level":3,"theme":"日常與一般"},{"word":"upper","pos":"adj.","phonetic":"[ˈʌpɚ]","meaning":"上面的；較高的","definition":"situated above another part","collocations":["upper floor","upper class","upper body"],"example":"Our office is on the upper floor of the building.","exampleZh":"我們的辦公室在這棟大樓的較高樓層。","synonyms":["higher"],"level":2,"theme":"日常與一般"},{"word":"upset","pos":"adj. / v.","phonetic":"[ʌpˈsɛt]","meaning":"心煩的；使不安；打翻","definition":"unhappy or worried; to make someone unhappy","collocations":["upset stomach","get upset","upset the balance"],"example":"She was upset after losing her favorite necklace.","exampleZh":"她弄丟了心愛的項鍊，感到很難過。","synonyms":["disturbed"],"level":3,"theme":"日常與一般"},{"word":"upstairs","pos":"adv. / adj. / n.","phonetic":"[ˈʌpˈstɛrz]","meaning":"樓上","definition":"on or to a higher floor of a building","collocations":["go upstairs","upstairs room","live upstairs"],"example":"My bedroom is upstairs on the second floor.","exampleZh":"我的臥室在樓上二樓。","synonyms":[],"level":1,"theme":"房產與設施"},{"word":"upward","pos":"adv. / adj.","phonetic":"[ˈʌpwɚd]","meaning":"向上地；向上的","definition":"moving or pointing toward a higher position","collocations":["upward trend","move upward","upward spiral"],"example":"Sales showed an upward trend this quarter.","exampleZh":"這一季的銷售呈現上升的趨勢。","synonyms":["rising"],"level":4,"theme":"日常與一般"},{"word":"urban","pos":"adj.","phonetic":"[ˈɝbən]","meaning":"都市的；城市的","definition":"relating to a city or densely populated area","collocations":["urban area","urban life","urban development"],"example":"Urban areas are growing rapidly around the world.","exampleZh":"世界各地的都市地區都在迅速發展。","synonyms":["metropolitan"],"level":5,"theme":"日常與一般"},{"word":"urge","pos":"v. / n.","phonetic":"[ɝdʒ]","meaning":"敦促；力勸；衝動","definition":"to strongly encourage someone to do something; a strong desire","collocations":["urge someone to","feel an urge","urge caution"],"example":"The doctor urged him to quit smoking.","exampleZh":"醫生力勸他戒菸。","synonyms":["encourage","push"],"level":4,"theme":"溝通與語言"},{"word":"urgent","pos":"adj.","phonetic":"[ˈɝdʒənt]","meaning":"緊急的；急迫的","definition":"requiring immediate action or attention","collocations":["urgent matter","urgent message","urgent care"],"example":"This is an urgent matter that needs your attention.","exampleZh":"這是一件需要你立刻處理的緊急事務。","synonyms":["pressing"],"level":3,"theme":"日常與一般"},{"word":"usage","pos":"n.","phonetic":"[ˈjusɪdʒ]","meaning":"使用；用法","definition":"the way in which something is used","collocations":["language usage","water usage","common usage"],"example":"This dictionary explains the correct usage of each word.","exampleZh":"這本字典解釋了每個單字的正確用法。","synonyms":["use"],"level":5,"theme":"溝通與語言"},{"word":"use","pos":"v. / n.","phonetic":"[juz]","meaning":"使用；利用","definition":"to take, employ, or apply something for a purpose","collocations":["use a tool","make use of","for personal use"],"example":"You can use my computer if you need to.","exampleZh":"如果你需要，可以用我的電腦。","synonyms":["utilize"],"level":1,"theme":"日常與一般"},{"word":"useful","pos":"adj.","phonetic":"[ˈjusfl̩]","meaning":"有用的","definition":"able to be used effectively","collocations":["useful information","useful tool","find useful"],"example":"This app provides very useful information for travelers.","exampleZh":"這個應用程式為旅客提供了非常實用的資訊。","synonyms":["helpful"],"level":1,"theme":"日常與一般"},{"word":"user","pos":"n.","phonetic":"[ˈjuzɚ]","meaning":"使用者","definition":"a person who uses something, such as a product or service","collocations":["internet user","user-friendly","daily user"],"example":"This software is designed to be simple for new users.","exampleZh":"這個軟體設計得對新使用者來說很簡單。","synonyms":[],"level":2,"theme":"科技與通訊"},{"word":"usual","pos":"adj.","phonetic":"[ˈjuʒʊəl]","meaning":"通常的；平常的","definition":"habitually or commonly occurring","collocations":["as usual","usual routine","the usual place"],"example":"He arrived late, as usual.","exampleZh":"他和往常一樣遲到了。","synonyms":["normal","typical"],"level":2,"theme":"日常與一般"},{"word":"usually","pos":"adv.","phonetic":"[ˈjuʒʊəlɪ]","meaning":"通常;一般而言","definition":"under normal conditions; generally","collocations":["usually go","usually happens","not usually"],"example":"I usually get up at seven o'clock.","exampleZh":"我通常七點起床。","synonyms":["generally"],"level":1,"theme":"日常與一般"},{"word":"utility","pos":"n.","phonetic":"[juˈtɪlətɪ]","meaning":"實用性；公用事業","definition":"the state of being useful, or public services like water and electricity","collocations":["utility bill","public utility","utility company"],"example":"The utility bill increased sharply this winter.","exampleZh":"這個冬天，公用事業費用大幅上升。","synonyms":["usefulness"],"level":6,"theme":"財務與會計"},{"word":"utilize","pos":"v.","phonetic":"[ˈjutlˌaɪz]","meaning":"利用；使用","definition":"to make practical and effective use of something","collocations":["utilize resources","utilize technology","fully utilize"],"example":"The company plans to utilize renewable energy sources.","exampleZh":"這家公司計劃利用再生能源。","synonyms":["use","employ"],"level":6,"theme":"日常與一般"},{"word":"vacancy","pos":"n.","phonetic":"[ˈvekənsɪ]","meaning":"職缺；空房","definition":"a job that is available, or an empty room in a hotel","collocations":["job vacancy","fill a vacancy","no vacancies"],"example":"The hotel has no vacancies during the festival weekend.","exampleZh":"藝術節那個週末飯店已無空房。","synonyms":["opening"],"level":5,"theme":"人事與職涯"},{"word":"vacant","pos":"adj.","phonetic":"[ˈvekənt]","meaning":"空的；未被占用的；茫然的","definition":"not occupied or filled; showing no interest or intelligence","collocations":["vacant seat","vacant position","vacant stare"],"example":"There was a vacant seat next to the window.","exampleZh":"窗邊有一個空位。","synonyms":["empty","unoccupied"],"level":3,"theme":"日常與一般"},{"word":"vacation","pos":"n.","phonetic":"[veˈkeʃən]","meaning":"假期；休假","definition":"a period of time devoted to rest or travel away from work or school","collocations":["summer vacation","go on vacation","take a vacation"],"example":"We are planning a family vacation to the beach.","exampleZh":"我們正在計畫一趟家庭海灘假期。","synonyms":["holiday","break"],"level":1,"theme":"旅遊與交通"},{"word":"vacuum","pos":"n. / v.","phonetic":"[ˈvækjuəm]","meaning":"真空；吸塵器；用吸塵器清潔","definition":"a space with no matter in it; a device that cleans by suction","collocations":["vacuum cleaner","vacuum the floor","create a vacuum"],"example":"She vacuumed the living room before the guests arrived.","exampleZh":"她在客人到來前用吸塵器清潔了客廳。","synonyms":["void"],"level":3,"theme":"房產與設施"},{"word":"valid","pos":"adj.","phonetic":"[ˈvælɪd]","meaning":"有效的；合理的","definition":"legally or officially acceptable; based on truth or reason","collocations":["valid ticket","valid reason","valid argument"],"example":"Your passport must be valid for at least six months.","exampleZh":"你的護照有效期至少要六個月。","synonyms":["legitimate","reasonable"],"level":4,"theme":"日常與一般"},{"word":"validate","pos":"v.","phonetic":"[ˈvæləˌdet]","meaning":"驗證；使有效；核准","definition":"to officially prove or confirm that something is true or acceptable","collocations":["validate parking","validate a ticket","validate the results"],"example":"Remember to validate your parking ticket at the front desk.","exampleZh":"記得到櫃檯蓋停車優惠章。","synonyms":["confirm","verify"],"level":5,"theme":"辦公室與行政"},{"word":"valuable","pos":"adj.","phonetic":"[ˈvæljəbḷ]","meaning":"珍貴的；有價值的","definition":"worth a lot of money or of great importance or usefulness","collocations":["valuable advice","valuable time","valuable resource"],"example":"She gave me some valuable advice about my career.","exampleZh":"她給了我一些關於職涯的寶貴建議。","synonyms":["precious","useful"],"level":2,"theme":"日常與一般"},{"word":"value","pos":"n. / v.","phonetic":"[ˈvælju]","meaning":"價值；重視","definition":"the importance or worth of something; to consider something important","collocations":["market value","value of life","value one's friendship"],"example":"We really value your feedback on our service.","exampleZh":"我們非常重視你對我們服務的意見。","synonyms":["worth","cherish"],"level":2,"theme":"財務與會計"},{"word":"van","pos":"n.","phonetic":"[væn]","meaning":"廂型車；貨車","definition":"a medium-sized road vehicle used for transporting goods or people","collocations":["delivery van","drive a van","load the van"],"example":"The company uses a van to deliver packages.","exampleZh":"這家公司用廂型車送貨。","synonyms":["truck"],"level":1,"theme":"旅遊與交通"},{"word":"variable","pos":"adj./n.","phonetic":"[ˈvɛrɪəbl]","meaning":"多變的；變數","definition":"likely to change, or something that can change","collocations":["variable costs","variable weather","key variable"],"example":"Variable shipping costs depend on package weight and distance.","exampleZh":"運費依包裹重量與距離而變動。","synonyms":["changeable"],"level":5,"theme":"財務與會計"},{"word":"variation","pos":"n.","phonetic":"[ˌvɛrɪˈeʃən]","meaning":"變化；差異；變體","definition":"a difference in amount or form","collocations":["seasonal variation","price variation","slight variation"],"example":"There is little variation in price among the three suppliers.","exampleZh":"三家供應商的價格差異不大。","synonyms":["difference"],"level":5,"theme":"日常與一般"},{"word":"variety","pos":"n.","phonetic":"[vəˈraɪətɪ]","meaning":"多樣性；種類","definition":"a number of different types of things or a lack of uniformity","collocations":["a variety of","variety show","add variety"],"example":"The restaurant offers a variety of dishes from around the world.","exampleZh":"這家餐廳提供來自世界各地的多種料理。","synonyms":["diversity","assortment"],"level":3,"theme":"日常與一般"},{"word":"various","pos":"adj.","phonetic":"[ˈvɛrɪəs]","meaning":"各式各樣的；多種的","definition":"more than one; of several different kinds","collocations":["various reasons","various ways","various countries"],"example":"Students learn various subjects in junior high school.","exampleZh":"國中生學習各種不同的科目。","synonyms":["diverse","several"],"level":3,"theme":"日常與一般"},{"word":"vary","pos":"v.","phonetic":"[ˈvɛrɪ]","meaning":"改變；不同","definition":"to differ or change according to circumstances","collocations":["vary in size","vary from person to person","prices vary"],"example":"Prices vary depending on the season.","exampleZh":"價格會依季節而有所不同。","synonyms":["differ","fluctuate"],"level":3,"theme":"日常與一般"},{"word":"vast","pos":"adj.","phonetic":"[væst]","meaning":"廣大的；巨大的","definition":"extremely large in area, size, or amount","collocations":["vast area","vast amount","vast desert"],"example":"The Sahara is a vast desert covering much of North Africa.","exampleZh":"撒哈拉沙漠是一片覆蓋北非大部分地區的廣闊沙漠。","synonyms":["huge","immense"],"level":4,"theme":"日常與一般"},{"word":"vegetable","pos":"n.","phonetic":"[ˈvɛdʒətəbḷ]","meaning":"蔬菜","definition":"a plant or part of a plant used as food, typically eaten with the main part of a meal","collocations":["fresh vegetables","vegetable soup","grow vegetables"],"example":"My mother grows vegetables in the backyard garden.","exampleZh":"我媽媽在後院菜園種蔬菜。","synonyms":[],"level":1,"theme":"餐飲與住宿"},{"word":"vegetarian","pos":"n. / adj.","phonetic":"[ˌvɛdʒəˈtɛrɪən]","meaning":"素食者；素食的","definition":"a person who does not eat meat or fish; relating to such a diet","collocations":["vegetarian diet","strict vegetarian","vegetarian restaurant"],"example":"She has been a vegetarian for over ten years.","exampleZh":"她已經吃素超過十年了。","synonyms":[],"level":3,"theme":"餐飲與住宿"},{"word":"vehicle","pos":"n.","phonetic":"[ˈviɪkḷ]","meaning":"車輛；交通工具","definition":"a machine, typically with wheels or engine, used for transporting people or goods","collocations":["motor vehicle","drive a vehicle","electric vehicle"],"example":"The parking lot was full of vehicles of all sizes.","exampleZh":"停車場裡停滿了各種大小的車輛。","synonyms":["car","automobile"],"level":3,"theme":"旅遊與交通"},{"word":"vendor","pos":"n.","phonetic":"[ˈvɛndɚ]","meaning":"小販；賣主","definition":"a person or company that sells goods, especially in the street or from a stall","collocations":["street vendor","food vendor","vendor stall"],"example":"A street vendor was selling roasted chestnuts on the corner.","exampleZh":"一位街頭小販在街角賣烤栗子。","synonyms":["seller"],"level":5,"theme":"財務與會計"},{"word":"venture","pos":"n. / v.","phonetic":"[ˈvɛntʃɚ]","meaning":"冒險事業；投機；冒險做","definition":"a risky or daring undertaking, especially in business; to dare to do something","collocations":["business venture","venture capital","venture out"],"example":"Starting his own restaurant was a risky business venture.","exampleZh":"開自己的餐廳是一項冒險的商業投資。","synonyms":["enterprise","dare"],"level":5,"theme":"財務與會計"},{"word":"venue","pos":"n.","phonetic":"[ˈvɛnju]","meaning":"場地；地點","definition":"the place where an event or meeting is held","collocations":["concert venue","wedding venue","change the venue"],"example":"The organizers found a perfect venue for the conference.","exampleZh":"主辦單位找到了一個完美的會議場地。","synonyms":["location","site"],"level":5,"theme":"日常與一般"},{"word":"verification","pos":"n.","phonetic":"[ˌvɛrəfəˈkeʃən]","meaning":"驗證；核實","definition":"the process of checking that something is true or correct","collocations":["identity verification","verification code","await verification"],"example":"A verification code will be sent to your registered phone number.","exampleZh":"驗證碼將發送至您登記的手機號碼。","synonyms":["confirmation"],"level":5,"theme":"科技與通訊"},{"word":"verify","pos":"v.","phonetic":"[ˈvɛrəˌfaɪ]","meaning":"證實；核實","definition":"to make sure or demonstrate that something is true, accurate, or justified","collocations":["verify information","verify identity","verify a claim"],"example":"Please verify your email address to complete registration.","exampleZh":"請驗證你的電子郵件地址以完成註冊。","synonyms":["confirm","check"],"level":4,"theme":"溝通與語言"},{"word":"versatile","pos":"adj.","phonetic":"[ˈvɝsətl]","meaning":"多才多藝的；多用途的","definition":"able to do many different things or be used in many ways","collocations":["versatile employee","versatile tool","versatile design"],"example":"The meeting room has a versatile layout for events of any size.","exampleZh":"這間會議室的配置靈活，可容納各種規模的活動。","synonyms":["adaptable","flexible"],"level":6,"theme":"人事與職涯"},{"word":"version","pos":"n.","phonetic":"[ˈvɝʒən]","meaning":"版本；說法","definition":"a particular form of something differing from other forms of the same type","collocations":["latest version","different version","movie version"],"example":"This is the updated version of the software.","exampleZh":"這是這款軟體的更新版本。","synonyms":["variant","edition"],"level":3,"theme":"科技與通訊"},{"word":"via","pos":"prep.","phonetic":"[ˈvaɪə]","meaning":"經由；透過","definition":"traveling through a place on the way to a destination; by means of","collocations":["via email","via train","travel via"],"example":"We flew to London via Dubai.","exampleZh":"我們經由杜拜飛往倫敦。","synonyms":["through","by means of"],"level":4,"theme":"旅遊與交通"},{"word":"video","pos":"n. / adj.","phonetic":"[ˈvɪdɪˌo]","meaning":"影片；視訊的","definition":"a recording of moving visual images, typically with sound","collocations":["watch a video","video game","upload a video"],"example":"She uploaded a funny video of her cat.","exampleZh":"她上傳了一段她貓咪的搞笑影片。","synonyms":["clip","recording"],"level":1,"theme":"科技與通訊"},{"word":"view","pos":"n. / v.","phonetic":"[vju]","meaning":"景色；看法；觀看","definition":"the ability to see something from a particular place; an opinion; to look at or consider","collocations":["scenic view","point of view","view the situation"],"example":"The hotel room offers a beautiful view of the sea.","exampleZh":"這間飯店房間可以欣賞美麗的海景。","synonyms":["sight","opinion"],"level":2,"theme":"日常與一般"},{"word":"violate","pos":"v.","phonetic":"[ˈvaɪəˌlet]","meaning":"違反；侵犯","definition":"to break or fail to comply with a rule, law, or agreement","collocations":["violate a law","violate rights","violate privacy"],"example":"The company was fined for violating environmental regulations.","exampleZh":"該公司因違反環保法規而被罰款。","synonyms":["break","infringe"],"level":5,"theme":"合約與法律"},{"word":"violation","pos":"n.","phonetic":"[ˌvaɪəˈleʃən]","meaning":"違規；違反","definition":"an action that breaks a law or rule","collocations":["traffic violation","in violation of","safety violation"],"example":"Parking in the fire lane is a violation of city regulations.","exampleZh":"在消防通道停車違反市府法規。","synonyms":["breach","infringement"],"level":5,"theme":"合約與法律"},{"word":"virtual","pos":"adj.","phonetic":"[ˈvɝtʃuəl]","meaning":"虛擬的；實質上的","definition":"almost or nearly as described but not completely or in name; not physically existing but made to appear so by software","collocations":["virtual reality","virtual world","virtual meeting"],"example":"The company held a virtual meeting instead of an in-person one.","exampleZh":"公司舉行了視訊會議而非實體會議。","synonyms":["simulated"],"level":5,"theme":"科技與通訊"},{"word":"virtually","pos":"adv.","phonetic":"[ˈvɝtʃʊəlɪ]","meaning":"幾乎；虛擬地","definition":"almost completely, or by using computers online","collocations":["virtually impossible","attend virtually","virtually all"],"example":"Virtually all registration is now completed online.","exampleZh":"現在幾乎所有報名都在線上完成。","synonyms":["practically","almost"],"level":5,"theme":"科技與通訊"},{"word":"virus","pos":"n.","phonetic":"[ˈvaɪrəs]","meaning":"病毒","definition":"an infective agent that causes disease; a piece of malicious computer code","collocations":["computer virus","catch a virus","spread a virus"],"example":"The doctor confirmed that he had caught a virus.","exampleZh":"醫生證實他感染了一種病毒。","synonyms":[],"level":4,"theme":"醫療與保險"},{"word":"visa","pos":"n.","phonetic":"[ˈvizə]","meaning":"簽證","definition":"an official document or stamp permitting entry into a country","collocations":["apply for a visa","student visa","visa application"],"example":"You need a valid visa to enter the country.","exampleZh":"你需要有效簽證才能入境這個國家。","synonyms":[],"level":4,"theme":"旅遊與交通"},{"word":"visible","pos":"adj.","phonetic":"[ˈvɪzəbḷ]","meaning":"看得見的；明顯的","definition":"able to be seen; noticeable or apparent","collocations":["clearly visible","visible from a distance","become visible"],"example":"The mountains were clearly visible from our hotel window.","exampleZh":"從我們飯店窗戶可以清楚看到那些山。","synonyms":["apparent","noticeable"],"level":3,"theme":"日常與一般"},{"word":"vision","pos":"n.","phonetic":"[ˈvɪʒən]","meaning":"視力；願景；想像力","definition":"the ability to see; an idea or image of the future; the ability to think or plan with imagination","collocations":["poor vision","have a vision","future vision"],"example":"The company leader has a clear vision for the future.","exampleZh":"這家公司的領導者對未來有清楚的願景。","synonyms":["eyesight","foresight"],"level":4,"theme":"日常與一般"},{"word":"visit","pos":"v. / n.","phonetic":"[ˈvɪzɪt]","meaning":"拜訪；參觀","definition":"to go to see a person or place; an occasion of going to see someone or something","collocations":["visit a museum","pay a visit","visit relatives"],"example":"We plan to visit our grandparents this weekend.","exampleZh":"我們計畫這個週末去拜訪祖父母。","synonyms":["call on"],"level":1,"theme":"旅遊與交通"},{"word":"visitor","pos":"n.","phonetic":"[ˈvɪzɪtɚ]","meaning":"訪客；遊客","definition":"a person who visits a place or another person","collocations":["welcome visitors","visitor center","frequent visitor"],"example":"The museum welcomes thousands of visitors every year.","exampleZh":"這間博物館每年都迎接數千名遊客。","synonyms":["guest","tourist"],"level":2,"theme":"旅遊與交通"},{"word":"visual","pos":"adj.","phonetic":"[ˈvɪʒuəl]","meaning":"視覺的","definition":"relating to seeing or sight","collocations":["visual aid","visual arts","visual effect"],"example":"The teacher used visual aids to explain the lesson.","exampleZh":"老師用視覺輔助教材來解釋這堂課。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"vital","pos":"adj.","phonetic":"[ˈvaɪtḷ]","meaning":"至關重要的；充滿活力的","definition":"absolutely necessary or important; full of energy","collocations":["vital role","vital importance","vital signs"],"example":"Sleep plays a vital role in maintaining good health.","exampleZh":"睡眠在維持良好健康方面扮演著至關重要的角色。","synonyms":["essential","crucial"],"level":4,"theme":"日常與一般"},{"word":"voice","pos":"n. / v.","phonetic":"[vɔɪs]","meaning":"聲音；表達","definition":"the sound produced by a person's vocal organs; to express in words","collocations":["raise one's voice","voice an opinion","lose one's voice"],"example":"He voiced his concerns about the new policy.","exampleZh":"他表達了對新政策的擔憂。","synonyms":["speak","express"],"level":1,"theme":"溝通與語言"},{"word":"volume","pos":"n.","phonetic":"[ˈvɑljəm]","meaning":"音量；體積；冊","definition":"the amount of space occupied by a substance; the loudness of sound; a book, especially one of a series","collocations":["turn up the volume","volume of water","first volume"],"example":"Could you turn down the volume on the TV?","exampleZh":"你可以把電視音量調小一點嗎？","synonyms":["loudness"],"level":3,"theme":"科技與通訊"},{"word":"voluntary","pos":"adj.","phonetic":"[ˈvɑlənˌtɛrɪ]","meaning":"自願的；志願的","definition":"done, given, or acting of one's own free will, without being forced or paid","collocations":["voluntary work","voluntary basis","voluntary donation"],"example":"Attendance at the meeting is voluntary, not required.","exampleZh":"參加這場會議是自願的，並非強制性的。","synonyms":["optional","willing"],"level":5,"theme":"日常與一般"},{"word":"volunteer","pos":"n. / v.","phonetic":"[ˌvɑlənˈtɪr]","meaning":"志工；自願做","definition":"a person who freely offers to do something; to offer to do something without being forced","collocations":["volunteer work","volunteer for a project","become a volunteer"],"example":"She volunteers at the animal shelter every weekend.","exampleZh":"她每個週末都在動物收容所當志工。","synonyms":["helper"],"level":3,"theme":"日常與一般"},{"word":"vote","pos":"n./v.","phonetic":"[vot]","meaning":"投票；表決","definition":"a formal choice made in an election or meeting","collocations":["cast a vote","vote on the proposal","unanimous vote"],"example":"The board will vote on the expansion proposal next week.","exampleZh":"董事會下週將就擴張提案進行表決。","synonyms":["ballot"],"level":2,"theme":"會議與簡報"},{"word":"voucher","pos":"n.","phonetic":"[ˈvaʊtʃɚ]","meaning":"抵用券；憑證","definition":"a printed ticket that can be used to pay for something","collocations":["gift voucher","meal voucher","travel voucher"],"example":"Delayed passengers received meal vouchers from the airline.","exampleZh":"航空公司向延誤的乘客發放了餐券。","synonyms":["coupon"],"level":5,"theme":"購物與消費"},{"word":"wage","pos":"n. / v.","phonetic":"[wedʒ]","meaning":"工資；薪水；發動（戰爭）","definition":"a fixed regular payment for work, or to carry on a conflict","collocations":["minimum wage","wage a war","hourly wage"],"example":"The factory workers demanded a higher minimum wage.","exampleZh":"工廠工人要求提高最低工資。","synonyms":["pay","salary"],"level":3,"theme":"財務與會計"},{"word":"wait","pos":"v. / n.","phonetic":"[wet]","meaning":"等待；等候","definition":"to stay in a place until someone arrives or something happens","collocations":["wait for someone","wait in line","wait a moment"],"example":"Please wait for me outside the classroom.","exampleZh":"請在教室外面等我。","synonyms":["await","stay"],"level":1,"theme":"日常與一般"},{"word":"waiter","pos":"n.","phonetic":"[ˈwetɚ]","meaning":"服務生","definition":"a person who serves food and drinks in a restaurant","collocations":["head waiter","call the waiter"],"example":"The waiter recommended the chef's seasonal tasting menu.","exampleZh":"服務生推薦了主廚的季節品嚐菜單。","synonyms":["server"],"level":1,"theme":"餐飲與住宿"},{"word":"waive","pos":"v.","phonetic":"[wev]","meaning":"免除；放棄（權利）","definition":"to choose not to demand a fee or right","collocations":["waive the fee","waive the requirement","waive one's rights"],"example":"The bank will waive the annual fee for the first year.","exampleZh":"銀行將免收第一年的年費。","synonyms":[],"level":6,"theme":"財務與會計"},{"word":"waiver","pos":"n.","phonetic":"[ˈwevɚ]","meaning":"棄權書；豁免","definition":"an official document giving up a right or excusing a rule","collocations":["sign a waiver","fee waiver","liability waiver"],"example":"Participants must sign a liability waiver before the climbing activity.","exampleZh":"參加攀岩活動前必須簽署免責同意書。","synonyms":[],"level":6,"theme":"合約與法律"},{"word":"wall","pos":"n.","phonetic":"[wɔl]","meaning":"牆壁；圍牆","definition":"a vertical structure that divides or encloses an area","collocations":["a stone wall","hang on the wall","climb over a wall"],"example":"There is a beautiful painting on the wall.","exampleZh":"牆上掛著一幅美麗的畫。","synonyms":["barrier","partition"],"level":1,"theme":"房產與設施"},{"word":"wallet","pos":"n.","phonetic":"[ˈwɑlɪt]","meaning":"皮夾；錢包","definition":"a small flat case for carrying money and cards","collocations":["lose a wallet","a leather wallet","an empty wallet"],"example":"He lost his wallet on the bus yesterday.","exampleZh":"他昨天在公車上弄丟了皮夾。","synonyms":["purse"],"level":2,"theme":"房產與設施"},{"word":"want","pos":"v. / n.","phonetic":"[wɑnt]","meaning":"想要；需要","definition":"to have a desire for something","collocations":["want to do something","in want of","want something badly"],"example":"She wants to travel around the world someday.","exampleZh":"她想要有一天環遊世界。","synonyms":["desire","wish"],"level":1,"theme":"日常與一般"},{"word":"warehouse","pos":"n.","phonetic":"[ˋwɛr͵haʊs]","meaning":"倉庫","definition":"a large building for storing goods","collocations":["a storage warehouse","warehouse workers","ship from the warehouse"],"example":"The company stores its products in a huge warehouse.","exampleZh":"這家公司把產品存放在一個巨大的倉庫裡。","synonyms":["storehouse"],"level":3,"theme":"財務與會計"},{"word":"warm","pos":"adj. / v.","phonetic":"[wɔrm]","meaning":"溫暖的；暖和的","definition":"having a comfortably high temperature","collocations":["warm weather","warm up","a warm welcome"],"example":"It's warm enough to go swimming today.","exampleZh":"今天天氣暖和到可以去游泳了。","synonyms":["mild","cozy"],"level":1,"theme":"日常與一般"},{"word":"warn","pos":"v.","phonetic":"[wɔrn]","meaning":"警告；提醒","definition":"to tell someone about a possible danger or problem in advance","collocations":["warn someone about","warn against","warn someone not to do something"],"example":"The teacher warned the students about the exam's difficulty.","exampleZh":"老師警告學生們這次考試的難度。","synonyms":["caution","alert"],"level":3,"theme":"溝通與語言"},{"word":"warning","pos":"n.","phonetic":"[ˈwɔrnɪŋ]","meaning":"警告；警報","definition":"a statement or sign telling people of a possible danger","collocations":["a warning sign","typhoon warning","give a warning"],"example":"The government issued a typhoon warning yesterday.","exampleZh":"政府昨天發布了颱風警報。","synonyms":["alert","notice"],"level":3,"theme":"日常與一般"},{"word":"warranty","pos":"n.","phonetic":"[ˈwɔrəntɪ]","meaning":"保固；保證書","definition":"a written promise to repair or replace a faulty product within a period","collocations":["under warranty","extended warranty","one-year warranty"],"example":"The repair is free because the laptop is still under warranty.","exampleZh":"筆電仍在保固期內，因此維修免費。","synonyms":["guarantee"],"level":4,"theme":"購物與消費"},{"word":"wash","pos":"v.","phonetic":"[wɑʃ]","meaning":"洗滌；洗","definition":"to clean something with water","collocations":["wash the dishes","wash one's hands","wash clothes"],"example":"Remember to wash your hands before eating.","exampleZh":"吃飯前記得要洗手。","synonyms":["clean","rinse"],"level":1,"theme":"房產與設施"},{"word":"waste","pos":"v. / n.","phonetic":"[west]","meaning":"浪費；廢棄物","definition":"to use something carelessly without a good result, or unwanted material","collocations":["waste time","waste money","food waste"],"example":"Don't waste your money on things you don't need.","exampleZh":"不要把錢浪費在你不需要的東西上。","synonyms":["squander","misuse"],"level":2,"theme":"財務與會計"},{"word":"watch","pos":"v. / n.","phonetic":"[wɑtʃ]","meaning":"觀看；手錶","definition":"to look at something for a period of time, or a small device for telling time","collocations":["watch TV","watch out for","wear a watch"],"example":"He wears a new watch on his left wrist.","exampleZh":"他左手戴著一支新手錶。","synonyms":["observe","view"],"level":1,"theme":"科技與通訊"},{"word":"water","pos":"n. / v.","phonetic":"[ˈwɔtɚ]","meaning":"水；澆水","definition":"the clear liquid that falls as rain and is essential for life","collocations":["drink water","water the plants","fresh water"],"example":"She waters the flowers in the garden every evening.","exampleZh":"她每天傍晚都會幫花園裡的花澆水。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"wave","pos":"n. / v.","phonetic":"[wev]","meaning":"波浪；揮手","definition":"a moving ridge of water, or to move a hand as a greeting","collocations":["ride a wave","wave goodbye","a heat wave"],"example":"The children waved goodbye to their grandparents.","exampleZh":"孩子們向祖父母揮手道別。","synonyms":["billow","gesture"],"level":2,"theme":"日常與一般"},{"word":"way","pos":"n.","phonetic":"[we]","meaning":"方法；道路；方式","definition":"a method of doing something, or a road or path","collocations":["find a way","by the way","on the way home"],"example":"There must be a better way to solve this problem.","exampleZh":"一定有更好的方法可以解決這個問題。","synonyms":["method","path"],"level":1,"theme":"日常與一般"},{"word":"weak","pos":"adj.","phonetic":"[wik]","meaning":"虛弱的；薄弱的","definition":"lacking physical strength or power","collocations":["a weak signal","feel weak","a weak argument"],"example":"He felt too weak to get out of bed.","exampleZh":"他覺得虛弱到無法下床。","synonyms":["feeble","fragile"],"level":2,"theme":"醫療與保險"},{"word":"wealth","pos":"n.","phonetic":"[wɛlθ]","meaning":"財富；財產","definition":"a large amount of money or valuable possessions","collocations":["great wealth","national wealth","a wealth of information"],"example":"The businessman built his wealth through hard work.","exampleZh":"這位商人靠努力工作累積了財富。","synonyms":["fortune","riches"],"level":3,"theme":"財務與會計"},{"word":"wealthy","pos":"adj.","phonetic":"[ˈwɛlθɪ]","meaning":"富有的；富裕的","definition":"having a lot of money or valuable possessions","collocations":["a wealthy family","become wealthy","wealthy nations"],"example":"She comes from a wealthy family in Taipei.","exampleZh":"她來自台北一個富裕的家庭。","synonyms":["rich","affluent"],"level":3,"theme":"財務與會計"},{"word":"wear","pos":"v.","phonetic":"[wɛr]","meaning":"穿；戴","definition":"to have clothing, jewelry, or an accessory on one's body","collocations":["wear a uniform","wear glasses","wear out"],"example":"Students must wear their uniforms to school.","exampleZh":"學生上學必須穿制服。","synonyms":["put on","dress in"],"level":1,"theme":"購物與消費"},{"word":"weather","pos":"n.","phonetic":"[ˈwɛðɚ]","meaning":"天氣","definition":"the condition of the atmosphere at a particular time and place","collocations":["bad weather","weather forecast","in this weather"],"example":"The weather forecast says it will rain tomorrow.","exampleZh":"天氣預報說明天會下雨。","synonyms":["climate"],"level":1,"theme":"日常與一般"},{"word":"website","pos":"n.","phonetic":"[ˈwɛbˌsaɪt]","meaning":"網站","definition":"a set of related pages on the internet, usually with a single address","collocations":["visit a website","create a website","an official website"],"example":"You can find more details on the school's website.","exampleZh":"你可以在學校網站上找到更多細節。","synonyms":["site"],"level":2,"theme":"科技與通訊"},{"word":"week","pos":"n.","phonetic":"[wik]","meaning":"星期；週","definition":"a period of seven days","collocations":["next week","twice a week","the school week"],"example":"I have a piano lesson twice a week.","exampleZh":"我一週上兩次鋼琴課。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"weekday","pos":"n.","phonetic":"[ˈwikˌde]","meaning":"平日；工作日","definition":"any day except Saturday and Sunday","collocations":["on weekdays","a busy weekday","weekday classes"],"example":"The library is open until nine on weekdays.","exampleZh":"圖書館平日開放到晚上九點。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"weekend","pos":"n.","phonetic":"[ˈwikˌɛnd]","meaning":"週末","definition":"Saturday and Sunday, the days when many people do not work","collocations":["on the weekend","a long weekend","weekend plans"],"example":"We are going hiking this weekend.","exampleZh":"我們這個週末要去健行。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"weekly","pos":"adj./adv./n.","phonetic":"[ˈwiklɪ]","meaning":"每週的；每週一次","definition":"happening once every week","collocations":["weekly meeting","weekly report","paid weekly"],"example":"The team holds a weekly progress meeting on Mondays.","exampleZh":"團隊每週一舉行進度會議。","synonyms":[],"level":2,"theme":"辦公室與行政"},{"word":"weigh","pos":"v.","phonetic":"[we]","meaning":"秤重；權衡","definition":"to measure how heavy someone or something is","collocations":["weigh yourself","weigh the options","weigh 50 kilograms"],"example":"The baby weighs about four kilograms.","exampleZh":"這個嬰兒大約重四公斤。","synonyms":["measure"],"level":3,"theme":"科技與通訊"},{"word":"weight","pos":"n.","phonetic":"[wet]","meaning":"重量；體重","definition":"how heavy a person or thing is","collocations":["lose weight","gain weight","the weight of a bag"],"example":"He has been trying to lose weight since last year.","exampleZh":"他從去年開始就一直努力減重。","synonyms":[],"level":2,"theme":"醫療與保險"},{"word":"welcome","pos":"v. / adj. / n.","phonetic":"[ˈwɛlkəm]","meaning":"歡迎","definition":"to greet someone in a friendly and polite way","collocations":["welcome guests","a warm welcome","you're welcome"],"example":"They welcomed us with a big smile at the door.","exampleZh":"他們在門口以燦爛的笑容歡迎我們。","synonyms":["greet"],"level":1,"theme":"溝通與語言"},{"word":"welfare","pos":"n.","phonetic":"[ˈwɛlˌfɛr]","meaning":"福利；福祉","definition":"the health, happiness, and safety of a person or group","collocations":["social welfare","public welfare","child welfare"],"example":"The government spends a lot on social welfare programs.","exampleZh":"政府在社會福利計畫上花費了大量經費。","synonyms":["well-being"],"level":5,"theme":"日常與一般"},{"word":"well","pos":"adv./adj./n.","phonetic":"[wɛl]","meaning":"好地；健康的；水井","definition":"in a good way, or in good health","collocations":["well done","as well as","well received"],"example":"The new menu has been very well received by customers.","exampleZh":"新菜單深受顧客好評。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"west","pos":"n. / adj. / adv.","phonetic":"[wɛst]","meaning":"西方；西邊","definition":"the direction in which the sun sets","collocations":["face west","the west coast","travel west"],"example":"The sun sets in the west every evening.","exampleZh":"太陽每天傍晚都在西方落下。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"western","pos":"adj.","phonetic":"[ˈwɛstɚn]","meaning":"西方的；西部的","definition":"relating to the west, especially Western countries or culture","collocations":["western culture","western countries","western food"],"example":"Many young people are interested in western culture.","exampleZh":"許多年輕人對西方文化很感興趣。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"wet","pos":"adj. / v.","phonetic":"[wɛt]","meaning":"潮濕的；濕的","definition":"covered in or soaked with liquid","collocations":["wet clothes","wet weather","get wet"],"example":"Don't go outside; your clothes will get wet in the rain.","exampleZh":"別出去了,你的衣服在雨中會弄濕的。","synonyms":["damp","moist"],"level":1,"theme":"日常與一般"},{"word":"while","pos":"conj./n.","phonetic":"[hwaɪl]","meaning":"當…時；然而；一段時間","definition":"during the time that, or although","collocations":["while you wait","for a while","worth one's while"],"example":"Shoes can be repaired while you wait.","exampleZh":"鞋子可以現場等候修理。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"wholesale","pos":"n./adj./adv.","phonetic":"[ˈholˌsel]","meaning":"批發；批發的","definition":"the sale of goods in large amounts to businesses","collocations":["wholesale price","wholesale market","buy wholesale"],"example":"Restaurants buy produce at wholesale prices from the market.","exampleZh":"餐廳以批發價向市場採購食材。","synonyms":[],"level":5,"theme":"購物與消費"},{"word":"wide","pos":"adj. / adv.","phonetic":"[waɪd]","meaning":"寬的；廣泛的","definition":"measuring a large distance from one side to the other","collocations":["a wide road","wide open","a wide range of"],"example":"The new highway is much wider than the old one.","exampleZh":"這條新高速公路比舊的寬多了。","synonyms":["broad"],"level":2,"theme":"日常與一般"},{"word":"widely","pos":"adv.","phonetic":"[ˈwaɪdlɪ]","meaning":"廣泛地；普遍地","definition":"by many people or in many places","collocations":["widely used","widely known","widely available"],"example":"The software is widely used in the hospitality industry.","exampleZh":"這套軟體在飯店業被廣泛使用。","synonyms":["broadly"],"level":3,"theme":"日常與一般"},{"word":"widen","pos":"v.","phonetic":"[ˈwaɪdn]","meaning":"加寬；擴大","definition":"to become or make something wider","collocations":["widen the road","widen the gap","widen the selection"],"example":"The city plans to widen the road near the industrial park.","exampleZh":"市府計畫拓寬工業區附近的道路。","synonyms":["broaden","expand"],"level":4,"theme":"旅遊與交通"},{"word":"widespread","pos":"adj.","phonetic":"[ˈwaɪdˈsprɛd]","meaning":"普遍的；廣泛分布的","definition":"existing or happening over a large area or among many people","collocations":["widespread use","widespread damage","become widespread"],"example":"Smartphones have become widespread among teenagers.","exampleZh":"智慧型手機在青少年之間已變得非常普遍。","synonyms":["extensive","common"],"level":5,"theme":"日常與一般"},{"word":"width","pos":"n.","phonetic":"[wɪdθ]","meaning":"寬度","definition":"the distance from one side of something to the other","collocations":["the width of a road","measure the width","in width"],"example":"Please measure the width of the table.","exampleZh":"請測量一下這張桌子的寬度。","synonyms":[],"level":4,"theme":"科技與通訊"},{"word":"wildlife","pos":"n.","phonetic":"[ˈwaɪldˌlaɪf]","meaning":"野生動物；野生生物","definition":"animals and plants living in their natural environment","collocations":["protect wildlife","wildlife conservation","local wildlife"],"example":"The national park protects a wide variety of wildlife.","exampleZh":"這座國家公園保護了各種各樣的野生動物。","synonyms":[],"level":3,"theme":"日常與一般"},{"word":"will","pos":"aux./n.","phonetic":"[wɪl]","meaning":"將要；意志；遺囑","definition":"used to talk about the future, or a legal document about property after death","collocations":["will be held","strong will","make a will"],"example":"The awards ceremony will be held in the grand ballroom.","exampleZh":"頒獎典禮將在大宴會廳舉行。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"willing","pos":"adj.","phonetic":"[ˈwɪlɪŋ]","meaning":"願意的；樂意的","definition":"ready or happy to do something without being forced","collocations":["be willing to","a willing helper","willing to try"],"example":"He is always willing to help his classmates.","exampleZh":"他總是樂意幫助同學。","synonyms":["ready","eager"],"level":3,"theme":"日常與一般"},{"word":"willingness","pos":"n.","phonetic":"[ˈwɪlɪŋnɪs]","meaning":"意願；樂意","definition":"the state of being happy to do something","collocations":["willingness to learn","show willingness","willingness to travel"],"example":"The role requires a willingness to travel internationally.","exampleZh":"這個職位需要有意願出國出差。","synonyms":["readiness"],"level":4,"theme":"人事與職涯"},{"word":"win","pos":"v. / n.","phonetic":"[wɪn]","meaning":"贏；獲勝","definition":"to achieve success or first place in a competition","collocations":["win a game","win a prize","win the race"],"example":"Our team won the basketball game last night.","exampleZh":"我們的隊伍昨晚贏得了籃球比賽。","synonyms":["triumph","succeed"],"level":1,"theme":"媒體與活動"},{"word":"window","pos":"n.","phonetic":"[ˈwɪndo]","meaning":"窗戶；窗口；時機","definition":"an opening with glass in a wall, or a period of time for doing something","collocations":["window seat","window display","delivery window"],"example":"Would you prefer a window seat or an aisle seat?","exampleZh":"您想要靠窗還是靠走道的座位？","synonyms":[],"level":1,"theme":"旅遊與交通"},{"word":"winner","pos":"n.","phonetic":"[ˈwɪnɚ]","meaning":"獲勝者；得獎者","definition":"a person or thing that wins","collocations":["award winner","prize winner","announce the winner"],"example":"The winner of the design contest will be announced Friday.","exampleZh":"設計比賽的得獎者將於週五公布。","synonyms":["victor"],"level":1,"theme":"媒體與活動"},{"word":"winter","pos":"n.","phonetic":"[ˈwɪntɚ]","meaning":"冬天；冬季","definition":"the coldest season of the year","collocations":["winter sale","winter schedule","harsh winter"],"example":"The store's winter sale starts the day after Christmas.","exampleZh":"這家店的冬季特賣從耶誕節隔天開始。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"wire","pos":"n. / v.","phonetic":"[waɪr]","meaning":"電線；金屬絲；接線","definition":"a thin piece of metal used to carry electricity or for fastening things","collocations":["electric wire","barbed wire","wire the house"],"example":"The electrician replaced the old wire behind the wall.","exampleZh":"電工更換了牆後的舊電線。","synonyms":["cable"],"level":3,"theme":"科技與通訊"},{"word":"wireless","pos":"adj./n.","phonetic":"[ˈwaɪrlɪs]","meaning":"無線的","definition":"using radio signals rather than wires","collocations":["wireless network","wireless internet","wireless headphones"],"example":"Free wireless internet is available throughout the hotel.","exampleZh":"飯店全區提供免費無線網路。","synonyms":[],"level":3,"theme":"科技與通訊"},{"word":"wise","pos":"adj.","phonetic":"[waɪz]","meaning":"明智的；有智慧的","definition":"having or showing good judgment based on knowledge and experience","collocations":["a wise decision","a wise man","it would be wise to"],"example":"It would be wise to save some money for emergencies.","exampleZh":"為緊急情況存一些錢是明智的。","synonyms":["sensible","smart"],"level":3,"theme":"日常與一般"},{"word":"wish","pos":"v. / n.","phonetic":"[wɪʃ]","meaning":"希望；願望","definition":"to want something to happen or be true, or a desire for something","collocations":["make a wish","best wishes","wish for peace"],"example":"She closed her eyes and made a wish before blowing out the candles.","exampleZh":"她閉上眼睛,在吹熄蠟燭前許了一個願望。","synonyms":["desire","hope"],"level":2,"theme":"日常與一般"},{"word":"withdraw","pos":"v.","phonetic":"[wɪðˋdrɔ]","meaning":"撤回；提款；退出","definition":"to remove or take away, or to leave a place or activity","collocations":["withdraw money","withdraw from the race","withdraw troops"],"example":"He went to the bank to withdraw some cash.","exampleZh":"他去銀行提了一些現金。","synonyms":["retreat","remove"],"level":4,"theme":"財務與會計"},{"word":"withdrawal","pos":"n.","phonetic":"[wɪðˋdrɔəl]","meaning":"撤回；提款；退出","definition":"the act of withdrawing something or someone","collocations":["cash withdrawal","troop withdrawal","withdrawal symptoms"],"example":"The bank charges a small fee for each cash withdrawal.","exampleZh":"銀行對每次提款收取一小筆手續費。","synonyms":["removal"],"level":5,"theme":"財務與會計"},{"word":"withhold","pos":"v.","phonetic":"[wɪðˈhold]","meaning":"扣留；保留；不給予","definition":"to refuse to give something, or to keep back part of a payment","collocations":["withhold payment","withhold taxes","withhold information"],"example":"Taxes are withheld automatically from each paycheck.","exampleZh":"稅款會自動從每期薪資中預扣。","synonyms":["retain","hold back"],"level":6,"theme":"財務與會計"},{"word":"within","pos":"prep./adv.","phonetic":"[wɪˈðɪn]","meaning":"在…之內","definition":"inside a limit of time, distance, or amount","collocations":["within 30 days","within walking distance","within budget"],"example":"Replies to inquiries are sent within one business day.","exampleZh":"詢問將於一個工作天內回覆。","synonyms":[],"level":2,"theme":"日常與一般"},{"word":"without","pos":"prep.","phonetic":"[wɪˈðaʊt]","meaning":"沒有；不","definition":"not having or doing something","collocations":["without notice","without permission","without delay"],"example":"Prices are subject to change without notice.","exampleZh":"價格如有變動，恕不另行通知。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"witness","pos":"n. / v.","phonetic":"[ˋwɪtnɪs]","meaning":"目擊者；證人；目擊","definition":"a person who sees an event happen, or to see something happen","collocations":["an eyewitness","witness a crime","call a witness"],"example":"Several people witnessed the accident on the highway.","exampleZh":"好幾個人目擊了高速公路上的事故。","synonyms":["observer","spectator"],"level":4,"theme":"合約與法律"},{"word":"wonder","pos":"v. / n.","phonetic":"[ˈwʌndɚ]","meaning":"想知道；感到驚奇；奇蹟","definition":"to want to know something; a feeling of surprise or admiration","collocations":["wonder if","wonder about","no wonder","wonders of nature"],"example":"I wonder why she didn't come to the party.","exampleZh":"我想知道她為什麼沒來派對。","synonyms":["ponder","marvel"],"level":2,"theme":"日常與一般"},{"word":"wonderful","pos":"adj.","phonetic":"[ˈwʌndɚfəl]","meaning":"極好的；令人驚奇的","definition":"extremely good or pleasant","collocations":["wonderful news","wonderful time","wonderful world"],"example":"We had a wonderful vacation in Japan.","exampleZh":"我們在日本度過了一個美好的假期。","synonyms":["marvelous","fantastic"],"level":1,"theme":"日常與一般"},{"word":"wood","pos":"n.","phonetic":"[wʊd]","meaning":"木頭；樹林","definition":"the hard material that forms the trunk and branches of a tree","collocations":["piece of wood","made of wood","walk in the woods"],"example":"The table is made of wood.","exampleZh":"這張桌子是木頭做的。","synonyms":["timber"],"level":1,"theme":"日常與一般"},{"word":"wooden","pos":"adj.","phonetic":"[ˈwʊdn̩]","meaning":"木製的","definition":"made of wood","collocations":["wooden chair","wooden floor","wooden box"],"example":"They live in a small wooden house.","exampleZh":"他們住在一間小木屋裡。","synonyms":[],"level":2,"theme":"房產與設施"},{"word":"word","pos":"n.","phonetic":"[wɝd]","meaning":"字；詞；話","definition":"a single unit of language that has meaning","collocations":["keep one's word","in other words","word for word"],"example":"Can you tell me the meaning of this word?","exampleZh":"你能告訴我這個字的意思嗎？","synonyms":["term"],"level":1,"theme":"溝通與語言"},{"word":"work","pos":"n. / v.","phonetic":"[wɝk]","meaning":"工作；作品；工作，運轉","definition":"to do a job or activity involving effort; a task or job","collocations":["go to work","work hard","work of art"],"example":"She works at a hospital as a nurse.","exampleZh":"她在醫院當護士工作。","synonyms":["labor","job"],"level":1,"theme":"人事與職涯"},{"word":"worker","pos":"n.","phonetic":"[ˈwɝkɚ]","meaning":"工人；工作者","definition":"a person who works, especially with their hands or in a particular job","collocations":["factory worker","social worker","hard worker"],"example":"The factory workers went on strike.","exampleZh":"工廠工人們罷工了。","synonyms":["employee"],"level":2,"theme":"人事與職涯"},{"word":"workforce","pos":"n.","phonetic":"[ˈwɝkˌfɔrs]","meaning":"勞動力；全體員工","definition":"all the people who work in a particular company, industry, or country","collocations":["skilled workforce","global workforce","join the workforce"],"example":"Women make up half of the workforce today.","exampleZh":"婦女如今占了勞動力的一半。","synonyms":["labor force"],"level":5,"theme":"財務與會計"},{"word":"workload","pos":"n.","phonetic":"[ˋwɝk͵lod]","meaning":"工作量；工作負荷","definition":"the amount of work that a person or machine has to do","collocations":["a heavy workload","reduce the workload","manage one's workload"],"example":"Teachers often complain about their heavy workload.","exampleZh":"老師們常常抱怨他們沉重的工作量。","synonyms":[],"level":4,"theme":"人事與職涯"},{"word":"workout","pos":"n.","phonetic":"[ˈwɝkˌaʊt]","meaning":"健身運動","definition":"a session of physical exercise","collocations":["daily workout","workout routine","gym workout"],"example":"He does a workout every morning before school.","exampleZh":"他每天早上上學前都會健身。","synonyms":["exercise"],"level":3,"theme":"媒體與活動"},{"word":"workplace","pos":"n.","phonetic":"[ˈwɝkˌples]","meaning":"工作場所","definition":"the place where a person works","collocations":["safe workplace","workplace environment","in the workplace"],"example":"The company improved safety in the workplace.","exampleZh":"公司改善了工作場所的安全。","synonyms":[],"level":3,"theme":"人事與職涯"},{"word":"workshop","pos":"n.","phonetic":"[ˈwɝkˌʃɑp]","meaning":"工作坊；研討會","definition":"a session for discussion or practical work; a room for manual or industrial work","collocations":["attend a workshop","writing workshop","repair workshop"],"example":"I signed up for a photography workshop.","exampleZh":"我報名參加了一個攝影工作坊。","synonyms":["seminar"],"level":3,"theme":"人事與職涯"},{"word":"world","pos":"n.","phonetic":"[wɝld]","meaning":"世界","definition":"the earth with all its countries and people","collocations":["around the world","real world","world war"],"example":"Traveling around the world is her dream.","exampleZh":"環遊世界是她的夢想。","synonyms":["globe","earth"],"level":1,"theme":"日常與一般"},{"word":"worldwide","pos":"adj. / adv.","phonetic":"[ˌwɝldˈwaɪd]","meaning":"全世界的；遍及全球地","definition":"extending or applying throughout the world","collocations":["worldwide fame","sold worldwide","worldwide web"],"example":"The disease spread worldwide within months.","exampleZh":"這種疾病在幾個月內傳遍全球。","synonyms":["global"],"level":4,"theme":"日常與一般"},{"word":"worry","pos":"v. / n.","phonetic":"[ˈwɝi]","meaning":"擔心；煩惱","definition":"to feel or cause anxiety about something","collocations":["worry about","don't worry","worry over"],"example":"Don't worry about the exam; you'll do fine.","exampleZh":"別擔心考試，你會考得不錯的。","synonyms":["fret","be anxious"],"level":2,"theme":"日常與一般"},{"word":"worth","pos":"adj. / n.","phonetic":"[wɝθ]","meaning":"值得...的；價值","definition":"having a value of; the value or usefulness of something","collocations":["worth it","worth doing","net worth"],"example":"This museum is definitely worth visiting.","exampleZh":"這座博物館絕對值得參觀。","synonyms":["value"],"level":3,"theme":"日常與一般"},{"word":"wrap","pos":"v. / n.","phonetic":"[ræp]","meaning":"包；包裹","definition":"to cover something by folding paper or cloth around it","collocations":["wrap a gift","wrap up","plastic wrap"],"example":"She wrapped the present in colorful paper.","exampleZh":"她用彩色紙包裝禮物。","synonyms":["cover","package"],"level":2,"theme":"日常與一般"},{"word":"write","pos":"v.","phonetic":"[raɪt]","meaning":"寫；書寫","definition":"to make letters, words, or numbers on a surface, especially with a pen","collocations":["write a letter","write down","write about"],"example":"He writes a diary entry every night.","exampleZh":"他每晚都寫日記。","synonyms":["compose"],"level":1,"theme":"溝通與語言"},{"word":"writer","pos":"n.","phonetic":"[ˈraɪtɚ]","meaning":"作家；作者","definition":"a person who writes books, articles, or other material","collocations":["famous writer","freelance writer","become a writer"],"example":"She dreams of becoming a famous writer.","exampleZh":"她夢想成為一位知名作家。","synonyms":["author"],"level":2,"theme":"媒體與活動"},{"word":"writing","pos":"n.","phonetic":"[ˈraɪtɪŋ]","meaning":"寫作；文字","definition":"the activity or skill of writing; something that has been written","collocations":["creative writing","in writing","writing skills"],"example":"Good writing skills are important for students.","exampleZh":"良好的寫作技巧對學生來說很重要。","synonyms":[],"level":2,"theme":"人事與職涯"},{"word":"wrong","pos":"adj. / adv. / n.","phonetic":"[rɔŋ]","meaning":"錯誤的；錯誤地；錯誤","definition":"not correct or not what is required; incorrectly","collocations":["go wrong","wrong answer","right and wrong"],"example":"I think you took the wrong turn.","exampleZh":"我覺得你轉錯彎了。","synonyms":["incorrect","mistaken"],"level":1,"theme":"日常與一般"},{"word":"year","pos":"n.","phonetic":"[jɪr]","meaning":"年；年度","definition":"the time it takes the earth to go around the sun once, about 365 days","collocations":["this year","last year","a year ago","school year"],"example":"We moved to Taipei three years ago.","exampleZh":"我們三年前搬到了台北。","synonyms":[],"level":1,"theme":"日常與一般"},{"word":"yearly","pos":"adj. / adv.","phonetic":"[ˈjɪrli]","meaning":"每年的；每年地","definition":"happening or done once every year","collocations":["a yearly event","yearly income","meet yearly"],"example":"The company holds a yearly meeting for all employees.","exampleZh":"這家公司每年為全體員工舉辦一次會議。","synonyms":["annual"],"level":3,"theme":"日常與一般"},{"word":"yet","pos":"adv. / conj.","phonetic":"[jɛt]","meaning":"尚未；然而；但是","definition":"up until now, or despite that","collocations":["not yet","yet again","small yet powerful"],"example":"He hasn't finished his homework yet.","exampleZh":"他還沒完成作業。","synonyms":["still","however"],"level":2,"theme":"溝通與語言"},{"word":"yield","pos":"v. / n.","phonetic":"[jild]","meaning":"屈服；讓步；產量；收益","definition":"to produce or provide something, or to give way to pressure or demand","collocations":["yield to pressure","crop yield","high yield","yield results"],"example":"The new farming method increased the rice yield significantly.","exampleZh":"新的耕作方法大幅提高了稻米的產量。","synonyms":["produce","surrender"],"level":4,"theme":"財務與會計"},{"word":"young","pos":"adj.","phonetic":"[jʌŋ]","meaning":"年輕的；幼小的","definition":"having lived or existed for only a short time","collocations":["young people","when I was young","look young"],"example":"My grandmother was very active when she was young.","exampleZh":"我奶奶年輕時非常活躍。","synonyms":["youthful","juvenile"],"level":1,"theme":"日常與一般"},{"word":"zone","pos":"n.","phonetic":"[zon]","meaning":"地區；地帶；區域","definition":"an area with a particular feature, purpose, or use","collocations":["a war zone","a time zone","a no-parking zone"],"example":"This part of the city is a quiet residential zone.","exampleZh":"這座城市的這個部分是安靜的住宅區。","synonyms":["area","region"],"level":3,"theme":"日常與一般"}];
